insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='SANCHEZ'and apellido2='MORENO'),'2021-11-25','-Me llama Miguel , TS del SSASB , ha estado allí el hno de Reme , quiere saber cómo vamos a pagar los gastos de alimentación. Le informo de todo lo acordado con su mujer , quedé pendiente que me pasaran un Pto. y Nº de cuenta donde abonaremos mensualmente esos gastos. Se queja de que se le haya quitado de la cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='CASARES'and apellido2='MARISCAL'),'2021-11-25','-Amalia : llamo a Victoria ,TS del SSASB para informarme sobre la situación residencia . De momento se mantiene la situación y hay más cuidadores . Me sugiere que si queremos trasladarlo solicite revisión PIA, plaza residencial en San Vicente . La tenía concedida y una prima que era su tutora renunció a ella y se lo llevó a esa residencia. Tiene primos en Alburquerque , y pueblos de alrededor además de en Puebla . De momento lo mantenemos ahí , cubre el 65% de los ingresos para copago y no lo trasladamos más . Van a enviar factura y Nº cuenta de una silla de ruedas . Me enviará luego la documentación para solicitar al SES el reembolso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2021-11-25','TERESA LA ADAPACION AL CENTRO ESTA SIENDO BUENA EN ESTA PRIMERA SEMANA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-11-24','EXITUS El óbito de produjo el 24/11/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-11-26','miguel, llega email del presidente de la comunidad de propietarios: Soy Manuel Fernández , presidente de la comunidad de propietarios del edificio La Muralla, sito en el Paseo Fluvial 1 y 2 de Badajoz. Les remito archivos donde pueden ver las denuncias y contratos de reparación, derivadas de las acciones llevadas a cabo, dentro de la comunidad de propietarios del edificio la muralla, por Alejandro Núñez Bono. Quedo a su disposición en este correo o en el número de teléfono 659 966 949, para cualquier duda.************************** Envío email a Amalia y a Maite: Buenos días ha llegado denuncias de la comunidad. Decidme si queréis que solicitemos ampliación de incapacidad y solicitud de internamiento involuntario o únicamente comunicación al juzgado.********************************** Contestación de Amalia: Buenos días , en mi opinión , hay que poner los hechos en conocimiento del juzgado para que imponga alguna sanción . Recordaros , que tiene pendiente aún la sentencia por el incendio del chalet de los Montitos . No podemos obtener información sobre eso? Con respecto al internamiento involuntario , no sé si sería más conveniente esperar a la decisión que se tome en la subcomisión de gestión de casos .Aunque Soraya indicó que se solicitase vía judicial pq lo ve más efectivo , solicitando ingreso en UME . Si os parece , se pueden ir moviendo las dos vías por si la de la subcomición no sale . En su curatela actual , incluye el tema de la salud , incluso el internamiento . Con respecto a aumentar medidas de apoyo , aunque fuesen más restrictivas estaríamos en la misma situación , los recursos de salud mental y drogas exigen su voluntariedad y él no quiere ingresar en ninguno . No veo necesario el cambio de sentencia. A ver qué opina Mayte al respecto . El lunes si queréis lo podemos concretar. ****************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-11-26','miguel, llega email del abogado Jesús Bueno: Miguel, me es muy grato adjuntarte TESTIMONIO del Auto dictado por el Juzgado de Primera Instancia nº de Logrosán por el cual se autoriza a la Comisión Tutelar de Adultos de Extremadura a realizar los gastos extraordinarios, en el importe que correspondan del tutelado D. MIGUEL SANTOS CORDERO en toda su extensión, referente al edificio Calle General Margallo 21 de Cáceres junto con las costas procesales todo a cargo de citado tutelado, debiendo justificar el órgano tutelar posteriormente los gastos efectuados. Habiendo finalizado el asunto y conforme a tus instrucciones les adjunto igualmente 1.- Mi Minuta de Honorarios sobre el asunto de referencia –factura 20/2021- a cargo de Don MIGUEL SANTOS CORDERO por su importe de cuatrocientos ochenta y cuatro euros (484 €) a fin de que procedáis a su abono mediante ingreso o transferencia en mi cuenta en CAIXBANK ES57 2100 5422 3713 0011 3197 2.- Cuenta de Derechos y gastos suplidos de la procuradora Doña Maria Victoria Hornero Rodriguez por su importe de doscientos ochenta y nueve euros con noventa (289,90 €) a fin de que procedáis a su abono mediante ingreso o transferencia a su cuenta en LIBERBANK ES23 2048 1001 95 3400032646 ****************************************** mi contestación: Buenos días, con fecha 15-11-21 se ha remitido al juzgado artículo 291 del Código Civil que establece la extinción por fallecimiento y conforme al artículo 292 del Código Civil que establece la obligatoriedad de presentación de la rendición final. Por tanto no es posible hacer frente al pago de ninguna cantidad porque ya no ejercemos cargo alguno. Os debéis de dirigir al juzgado de 1º instancia e instrucción nº2 de Plasencia, conforme al procedimiento de incapacitación nº 267/2017. *************************************************** me llama por teléfono Jesús Bueno y le explico de nuevo que deberá ponerse en contacto con el Juzgado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-11-25','miguel, remito al juzgado comunicación de que se ha solicitado abogado por cargo indebido en su cuenta de unos 48.000€ de una deuda del hno con el Ayto por ejecución de sentencia, siendo dicha cuenta titularidad de los dos hermanos. ************************************ Asimismo solicito abogado de oficio al colegio de Cáceres que la represente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-11-25','Ana: Correos de Toni de Diego, TS CR Cervantes (antonia.dediego@salud-juntaex.es): "...• ayer 24/11/2021 un residente se persona en el despacho de la coordinadora Asistencial. Quejándose que se siente acosado por la residente M.ªLuisa Montaña Aliseda, porque continuamente está llamándole a la puerta de su habitación para pedirle tabaco y dinero. Dicho residente insiste que desde la dirección se le llame la atención a M.ª luisa, pero nos puntualiza que no le hagamos conocedora de sus quejas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-11-26','Ana: Hablo con Toni, TS CR Cervantes (22270), en relación al correo de ayer: solicitaré a Futuex que intensifiquen el seguimiento para abordar esta cuestión y que si lo consideran conveniente lo comuniquen a la secc. de mayores. ··································· Envío correo a Toni, Futuex: "En relación a MARÍA LUISA MONTAÑA ALISEDA, queríamos solicitar, en la medida de lo posible, que la Educadora intensifique las visitas, y aborde con ella las conductas inapropiadas que está manteniendo con otras personas residentes: entra en habitaciones ajenas y pide constantemente y con insistencia tabaco y dinero. Hay que intentar hacerle ver, que además de no ser apropiado, desde el centro pueden determinar tomar otras medidas/sanciones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-11-25','miguel, remito al juzgado Decano de Cáceres el internamiento involuntario del curatelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-11-26','miguel, envío email al presidente de la Comunidad: Buenas tardes, procedemos a comunicar al juzgado la documentación que nos ha remitido a los efectos oportunos. De la documentación que nos ha remitido queda pendiente nos envíe este punto: 2- visionado de cámaras coste.pdf ******************************************* contesto a Amalia que me preguntaba si me había enviado todo el presidente de la Comunidad (había tenido problemas para enviarnoslo): Buenos días, tras comentarlo con Maite decidimos comunicarlo al Juzgado independientemente que en unos días solicitemos las medidas que el juzgado estime teniendo en cuenta que es una curatela (con lo que deberían revisar su capacidad antes de resolver sobre su internamiento involuntario). Debajo te dejo la contestación que hago al presidente de la Comunidad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2021-11-26','Ana: Llamada de Juan Jesús, Res. Municipal de Romangordo: Guillermo está mucho peor, la situación se ha complicado y es posible que fallezca en los próximos días. *Se ha puesto en contacto con la hermana, en relación a los deseos de Guillermo y la familia de cara al Sepelio. *La hermana dice que tiene también un seguro de decesos en que tiene incluido a Guillermo. **Llamarán a ambos, llegado el momento, para ver cuál es más beneficioso para el traslado del cuerpo. ··············· *Por otra parte, enviarán un correo con los tiques relativos a los últimos gastos en el estanco, pues el pago lo ha adelantado el ayto., habría que abonárselo mediante transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-11-26','miguel, comunico al Jzdo nº4 Badajoz por fax las denuncias que nos ha remitido hoy el presidente de la comunidad en relación a la rotura del ascensor y de la cama que tiró por la ventana el curatelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='SOLE'and apellido2='LATORRE'),'2021-11-26','Ana: Reenvío a Alberto, jefe secc. ecca., la factura y el nº de cuenta para abonar el colchón antiescaras (el presupuesto se aprobó previamente)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2021-11-29','TERESA Hola Teresa, perdona por no comunicarte los cambios.Estoy viviendo con mi hermana.Moraleja CP 10840 el banco que tengo solo hay 1.le comentado lo de alquilar un piso y me a dicho que no me llega.no ostante ya te llamo el día 1.yo si me atrevo hay ayudas de luz y agua y e visto uno por 180.tambien tengo la ayuda de alquiler De 500 e cada seis meses.trabajo e encontrado uno demedia jornada, pero todavia no e cobrado nada.puedo comer en casa de algún amigo o mi hermana , aunque me a dicho que la comida tengo que pagarla, pero bueno si voy de vez en cuando me invita. y que ella me maneja el dinero cuando cobre.le e dicho que me da igual.ella me lo da.banco de alimentos hay.Me gustaría dejar de estar tutelado como te dije . el día 18 de enero voy a la siquiatra le pediré un informe para juicio...bueno me puedes llamar cuando quieras, bueno quedamos en que te llamo el día 1 .gracias que pases buen finde','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2021-11-28','EXITUS El Dr. del Ctro. Pablo Naranjo, Juan Jesús Alonso Ríos, informa de su fallecimiento acaecido el 28/11/2021. Remite, así mismo, certificado médico de defunción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-11-29','kike, TRAS HABLAR CON JUZGADOS NOS COMUNICAN QUE NO HACE FALTA QUE ACUDAMOS AL JUICIO, PORQUE LO UNICO ES QUE LE VAN A TOMAR DECLARACION ACERCA DEL INCUMPLIMIENTO DE LA ORDEN DE ALEJAMIENTO, HECHOS QUE FUERON DENUNCIADOS Y POR LOS QUE SE CITA A LA MISMA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2021-11-29','Teresa te comunico para que tengáis conocimiento. A Natalia se la va a pasar al cobro media mensualidad de noviembre por importe de 151,05 euros (del 16 al 30 de noviembre) Para el mes de diciembre se le pasará al cobro será de 302,05 euros, el 75% de la PNC, como al resto de usuarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-11-30','TERESA ENVIO CORREO mariajesus.ramosa@salud-juntaex.es Buenos días Soy Teresa Blanco, trabajadora social de la comisión tutelar de adultos. Necesitamos se autorice un traslado en ambulancia desde la UHB de Mérida al centro asistencial hermanas hospitalarias en la Crta de Burgos, Palencia, para el próximo día dos de diciembre. El tutelado es Jose Mª Morón Hernández','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-11-30','TERESA ARCHIVO ACTA COMISION TÉCNICA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-11-30','TERESA Buenos tardes Teresa, me comenta Emi M. B que ya te informó que la semana pasada, en un momento de “ arrebato” rompió sus gafas de ver. El caso es que ahora me trae un presupuesto de una óptica de aquí de Olivenza de 305€ para unas gafas nuevas. El móvil que compró nuevo la semana pasada también lo ha vendido. Por otro lado, aún no hemos sacado los 80€ extras para ropa que se le autorizó, ya que teníamos pensado cogerlo todo el miércoles día 1. Lo comento por si veis que se ajuste con su asignación diaria o con algo de lo destinado a la ropa. Para cualquier aclaración o aspecto que querías comentar quedo a vuestra disposición. Saludos, Leonor','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2021-11-30','Buenos días: Mi teléfono está fatal, unas veces se carga otros se apaga solito…. Te mando el acta firmada por las tres. Cuanto a la situación no tenemos noticias de cambio, es decir, Pilar Rodríguez usuaria ha vuelto con su novio Jonathan, la madre sigue diciendo que quiere dejar a su actual pareja, que no lo suporta, pero todos siguen viviendo en la misma casa. A Pilar hija, se le ve bien, sin ningún signo de alerta. Es la madre quien no para de mandar whatsaaps diciendo que quiere dejar a su pareja. El teléfono de la madre: 643969847 El teléfono de Pilar usuaria: 641344869 Mañana te enviamos el informe. Un saludo y muchas gracias. Catarina Mª Ferreira Barbedo Servicio de Apoyo a Familias Aprosuba 3 Plena Inclusión Badajoz Tfno.: 610292594 www.aprosuba3.org','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2021-11-30','Amalia : envio email a la TS de Villagonzalo: Buenos días , no me aceptan el modelo de alta a terceros escaneado , por favor reenvíame el original a la siguiente dirección por correo ordinario : SEPAD A/A COMISION TUTELAR ( AMALIA TS ) AVDA. LAS AMERICAS , 4 06800 MERIDA BADAJOZ. Me indican desde dependencia que no podemos cancelar la cuenta hasta que no empiece a percibir la prestación en la nueva cuenta . Cuando llegue el original +modelo de comunicaicon de datos de expediente lo entrego en dependencia y lo comunico a Sección eco. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2021-11-30','TERESA ENVIO NO ACEPTACION PIA YA QUE LA RESIDENCIA EN LA QUE SE ENCUENTRA ACTUALMENTE EN LA CARTERA DEL SERVICIO DEL SEPAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-11-30','Ana: Tras conversación con Mariluz, Jefa de Secc. Salud Mental, envío correo a Estrella, TS CSS Plas.: "Buenos días Estrella, qué tal? Me han comunicado hoy que mañana tendrá lugar la comisión en que se valorará el acceso de Javier Agudo Cumplido a CRR. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2021-11-30','Ana: Recibimos resolución de PFHC (solicitud persona jurídica): Fecha de efectos 01/10/2020. Cuantía 598,80€/mes x 12. ··································································································································· Teresa Nogueira nos remite Informe Social por mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2021-11-30','Maite: Marta ya ha comenzado a asistir al CO de Plena Inclusión de cabeza del Buey ( 24/11/2021).He hablado con élla y está bien, se va adpatando. Hemos adordado con que va a tener una asignación de 100€ mensuales que élla adminitrará, retirará el dinero la primera semana de cada mes, acompañada por un/a profesional del centro.','2');
