insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-11-29','Ana: Correo de Toni con las últimas actuaciones, incluida la incidencia del día 26 (Guardado en el expdte. digital) ················· Llamada de Marta, TS Cilleros, mañana Julia tiene una vista por intento de agresión hacia su madre con un cuchillo (Incidente del pasado viernes 26). ······· Contacta también con los jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-11-30','Ana: Mariluz Madrigal, Jefa Secc. me informa que ayer, recibieron la solicitud de plaza en CRR (derivada desde el ESM). Tiene que pasar por Comisión de Valoración y no saben cuándo tendrá lugar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2021-11-30','Ana: Llamada de Mariví Clemente, TS CSS-Plas: En relación a la posibilidad de solicitar pensión de orfandad a Teresa, dado que no prescribe y que a día de hoy no consideramos que sea necesario, sólo solicitará a su hermana la documentación pertinente (Libro Familia, Cdo. de Defunción...) por si llegado el momento resulta necesario tramitársela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2021-12-01','TERESA Hola Teresa, te comento. Natalia ha dado positivo, para que tengáis constancia en la comisión. Ella está muy bien es asintomática totalmente. todos los trabajadores y el resto de usuarios, todos negativos. La salida de Aitor queda aplazada debido a que el viernes nos harán a todos una 2ª Pcr y el marte 7 una 3ª PCR. Estamos controlados por Salud Pública y hemos activado el protocolo de actuación del centro para estos casos. Lo ponto todo en vuestro conocimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-12-01','TERESA Buenas tardes Tersa, estoy atendiendo a Bartolome Colchon Carmona, el mismo demanda ayuda de alimentos y derivación a Caritas para tal fin. Manifiesta que con el dinero mensual que percibe no puede cubrir todas sus necesidades. Desconozco la cuantia asignada y si procede su revisión pero creo que Bartolome al tener reconocida una orfandad absoluta no procede mantenerlo en ayuda de alimentos ¿ Como lo ves Tú?, ya me vas diciendo.-','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2021-12-01','miguel, me llama por teléfono de Gestoria Arnal 932-157513 (Carmen Miñarro Monge solicitandome dicha inscripción en registro civil). La contesto al email que me remite: Buenas tardes adjunto los certificados literales de nacimiento que nos remitió el registro civil donde pueden comprobar que no se encuentra inscrito el cargo de tutor de la Comisión Tutelar de Adultos. Hemos solicitado por fax el testimonio de firmeza de la sentencia de nombramiento. Intentaremos hablar con el juzgado para recordarles ambas cuestiones: que nos remitan dicho testimonio de firmeza y que de oficio manden inscribir al registro civil dicha sentencia de incapacitación y nombramiento de tutor a la Comisión Tutelar de Adultos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2021-12-01','Se remite al CSS-Plas. CI para Tratamiento Quirúrgico de carcinoma basocelular así como la autorización de intervención anestésica y analgésica.','2');
