insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-12-01','Ana: Conversación con Anabel, TS del SSASB Miajadas ( ): dado que Esteve está ingresado en UME, van a enviar un paquete con pertenencias (ropa, calzado y 110 € que tienen guardado en el piso para gastos de bolsillo). *No saben si de momento tendrá que seguir abonado la plaza del piso. Intentará hablar dentro de un par de días con Soraya Masa. ···························· Hoy ha tenido lugar la Comisión de Salud Mental para valorar su acceso a CRR).','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2021-12-01','-Amalia : en reunión ayer entre Raquel , CRR Mérida , Mayte ; jefa sección CTAEX y yo , decidimos esperar unos meses para solicitar P. Orfandad , tras el fallecimiento de su padre . Actualmente con la PNC cubre sus gastos extras , dado que no pagan nada por la plaza . Está demandando dinero para montar un taller en su casa del pueblo , para no generar esas expectativas decidimos aplazar unos meses antes de solicitar la pensión. Si tiene el taller dejará el CRR y no lo vemos preparado para llevar una vida autónoma , sólo.','2');
