insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-11-30','Ana: correo de Estrella, TS CSS (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. Te informo que ayer tarde sobre las 18 horas, se volvió a fugar Juan Carlos Ruíz García, devolviéndolo la policía a las 20 horas. Últimamente está en proceso de duelo por desengaño amoroso y se ha autolesionado tres veces, cortándose con algún objeto punzante que encuentra por el suelo en el exterior, sin haber llegado a ser nada grave ni aparatoso...Aprovecho para insistir en la cuestión del centro, está muy cansado de estar encerrado.... A ver si se traslada pronto...." ··········· Mi respuesta: "Buenos días, Gracias por mantenernos informados. Como sabes todos los trámites están hechos y continúa , según me han informado, en lista de espera. El acceso a centros no depende la CTAEX. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2021-12-02','Ana: Correo de Ángela, directora PLACEAT, en relación a la intervención de Oclusión Tubárica, "Buenos días Ana, te remito el consentimiento para la anestesia de Maria, ya que tiene consulta de preoperatorio el viernes 10 y el lunes trece de anestesia. Parece ser que ya van a realizarle la intervención ginecológica pendiente. Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2021-12-02','Ana: Remito a Ángela, PLACEAT, escaneado, CI para Intervención Anestésica y Analgésica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-12-02','En relación con la Sentencia 59/2016, dictada por la Audiencia Provincial de Cáceres, por la que condenan a Daniel José Granados García, por un delito de agresión sexual contra Isabel Cano Blázauez, a 8 años de prisión y al pago de 20.000 euros en concepto de responsabilidad civil, puestos en contacto con el Servicio de Ejecución Penal de la Audiencia Provincial de Cáceres (927620418), nos indican que la ejecutoria es la nº 19/2017, rollo 11/2015. A fecha actual, no les consta que haya pagado nada, por lo que enviamos escrito solicitando Averiguacion Patrimonial. Está cumpliendo condena en prisión, hasta el 26/4/25.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2021-12-02','Ana: Respondo al correo de Teresa Nogueira, Novaforma, de ayer: "...En relación a Fermín García Pablos, en su expediente no tenemos constancia de dónde está empadronado… imagino que no está empadronado en Cáceres, porque desde aquí tampoco se han hecho las trámites al respecto…. Así que por nuestra parte podéis proceder. Si no os importa enviarnos el documento que tiene que firmar el representante legal."','2');
