insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2021-12-08','En relación con el tema de la pintura de la facha de una casa que, supuestamente, era de Rosa, consultado con le RP y Catastro, no aparecen propiedades inscritas a su nombre. Probablemente sea una casa perteneciente a los padres y no se haya hecho la herencia. Le he pedido a Rosario, Concejala de Valencia de Alcántara, que nos facilite datos de los padres y hermanos y averiguar a quien le perteence esa vivienda. Mientras tanto, no abonamos factura.','2');
