insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2021-12-02','Ana: A petición de Teresa Nogueira, TS Novaforma (trabajadorasocial.novaforma@gmail.com), le envío correo: "Buenas, de nuevo, Teresa, En relación a JUAN JOSÉ MASEDA DEL SOL, te remito adjunta la documentación de que disponemos: - DNI - Tarjeta Sanitaria - Certificado de Discapacidad - Dictamen Técnico - Acuerdo de Aceptación del Cargo de Tutor - Testimonio de Sentencia de Incapacitación ..."','2');
