insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-11-30','Ana: Correo Estrella Durán, TS CSS: "Hola de nuevo, Ana. Como informo en el correo anterior, Reme irá a Badajoz a ver a su madre el jueves próximo. En un principio, quisimos organizar la visita en el centro Ntra. Sra de la Luz donde está su hermana Amparo y así encontrarse las tres. Esto no va a ser posible, porque dicho centro tiene muchos casos de covid. Así, el encuentro entre madre e hija será en el Parque San Francisco, ya que en Aprosuba 3 (centro donde paga Remedios) no nos facilitan una sala para dicha visita. Seguimos..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2021-11-23','Ana: correo de Toni-Futuex: "...Según se entiende, se trata de una diligencia de embargo por una deuda que tiene el Sr. Fernando Bravo Calvo, al investigar quien es este señor, se conoce que es el jefe de la empresa de dependencia que atiende al tutelado. Parece ser que solicitan que no se le haga abono de la cuantía que corresponde y se pague directamente a hacienda, la deuda asciende a 2.931,53€." ················· Lo hablaré con Alberto, jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2021-12-03','Ana: De nuevo, llamo a la empresa RED DE SERVICIOS BRAVO (Fernando Bravo Calvo), Acreditada para SAD por el SEPADA. Tlf. 654 60 64 66: Dejo un mensaje en el buzón de voz, con mi número para que me devuelvan la llamada. ············· Localizo otro número (927 16 12 70): *Me dicen que están solucionando el problema y me llamarán a lo largo de la mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2021-11-26','Ana: Tal y como acordé con Alberto, jefe secc. ecca.: Llamo a la empresa RED DE SERVICIOS BRAVO (Fernando Bravo Calvo), Acreditada para SAD por el SEPADA. Tlf. 654 60 64 66: No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-12-03','Ana: Vuelvo a llamar al centro de salud de Coria (927 14 92 33): locución: "Todas nuestras líneas están ocupadas" ················ A través del nº de urgencias (927 14 92 35), consigo el número de Marcelo, TS Att. Primaria + COPF (70833): los informes se los tengo que solicitar a su médico, pero él ya se lo ha dicho. ·········· El MAP de Emilia es José Mª Hdez. (70809 / jose.hernandezd@salud-juntaex.es): conoce a Emilia y su hijo. Emilia presenta ha tenido tratamiento de inyecciones en el vítreo. Tiene una consulta en Oftalmología el día 13/12/21, a las 10:30h. Solicitaré que le acompañe la Ed. de Futuex. ··· Le mandaré los modelos de informes médico y de salud (ingreso en centro por decreto y valoración de dependencia) y en cuanto pueda me los enviará cumplimentados ················ Envío correo a Toni-Futuex.','2');
