insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2021-12-03','Ana: Correo de Ángela, Directora de Placeat: "Buenos dias Ana, ya tenemos fecha para la intervención de Maria. Ingresa el domingo 19 de este mes a las 5 de la tarde, y la intervienen el lunes 20. Hemos considerado el acompañamiento la tarde del domingo ( de 5 a 9) y luego que la persona acuda a las 8h de la mañana el dia de la intervención, y ya veremos como evoluciona y las necesidades de apoyo que hubiera que cubrir. Como siempre hemos pensado en personal del servicio que la conoce, concretamente en el personal de refuerzo que tenga disponibilidad. Al igual que con cristofer sería a 7€ / hora. Ella está bien, todavía no la hemos informado, hasta que pasen todos estos dias festivos, para que no se ponga nerviosa. Por lo demás nada a destacar. Te mantendré informada." ············· Paso a Alberto, jefe ecca, la propuesta económica para acompañamiento hospitalario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-12-03','TERESA El telefono de Beatriz es 641285560.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-12-03','Ana: Correo de Marisol, TS ESM Trujillo (mariasoledad.tafur@salud-juntaex.es): "A petición de la Coordinación de Salud Mental del Área de Salud de Cáceres, se les convoca para Subcomisión de Gestión de Casos sobre la paciente I.C.B. Ante la próxima externalización de la paciente se hace necesario la creación de dicha Subcomisión para el abordaje de su rehabilitación psicosocial dando continuidad a su proceso de recuperación. Lugar y fecha: Aula Clínica del HSPA. Fecha: 14/12/2021. Hora: 12.00 h. Preferentemente será asistencial."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-12-07','TERESA EMAIL DEL SOCI M DOLORES DAIMIEL me comenta es que, si no va a poder volver a su casa, para qué la sigue pagando, tanto la vivienda como los suministros (yo ignoro los gastos que le supone eso actualmente). Quizás habría que tratar eso con ella, tanto para que no tenga gastos innecesarios como para no generarle expectativas que no se puedan cumplir después. O quizás valdría la pena esperar a ver qué tal se adapta a la residencia cuando se la den. No sé a ti qué te parece. Personalmente, tengo la duda de si decirle que espere un poco por el motivo que te he comentado, esto es, generar unas expectativas de vuelta a su vivienda que bien podrían no ser posibles, o si reforzar su idea de que renuncie a la vivienda actual, puesto que en este momento su firme decisión es alquilar cuando se recupere otra vivienda por su cuenta, y sabemos las dificultades que eso puede suponer. La semana que viene consultaré a ver cómo anda su solicitud de plaza residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-12-07','TERESA ARCHIVO PIA RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2021-12-07','TERESA Estamos valorando la opción de poner una lavadora en casa de Cándido para que pueda la chica de la limpieza lavarle la ropa. PIDO A FUTUEX QUE CONTACTE CON JUAN EL ALBAÑIL PARA QUE VALORE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2021-12-09','Maite: Toni ( Futiex) envia el siguiente correo electrónico:Hola Maite, buenas tardes! Te dejo esta info por aqui al respecto de esta tutelada, con fecha martes 30 de noviembre nos comunica Marta que tiene cita ya programada en planificación familiar el miércoles 15 de diciembre a las 11:30 horas en centro de salud de Cabeza del Buey y que irá acompañada de su hermana Guadalupe. Pero tal y como indicas, intentaremos ir nosotras con ella, para poder trasladar la información y para seguir trabajando la aderencia con ella. Para confirmar dicha cita, nos ponemos en contacto, desde este equipo de apoyo social comunitario, con el servicio de Planificación familiar de la zona (corresponde al centro de salud de Castuera nº teléfono: 924 760194) y se nos confirma dicha cita: Marta Rivera Núñez, tiene programada cita en planificación familiar el miércoles 15 de diciembre de 2021 en centro de salud de Cabeza del Buey (se traslada el equipo dos veces en semana desde Castuera) a las 11:00 horas. Marta insiste en querer ir acompañada de su hermana Guadalupe, que dice también le está aconsejando en reclamar su pensión total y no recibir asignación, además de poder solicitar una tarjeta bancaria, para retirar cuando Ella crea oportuno. Desde Plena Inclusión, opinan que quizás no sea su hermana la que de estos consejos, tal como dice Marta, pues ha sido, desde siempre, la que ha puesto paz y algo de sensatez en la familia. Se le comunica que se hará acompañamiento desde el equipo de apoyo social comunitario de Badajoz, aprovechando este mismo día para modificar datos en su ficha en centro de salud y que refleje su nuevo domicilio con nuevo número de móvil. También nos comenta que tiene ya citación para consulta de revisión en endocrino para el viernes 28 de enero de 2022 en hospital de Don Benito. Ese mismo dia 30 de noviembre no acudió al centro ocupacional alegando sentirse con tos y dolor de garganta. Desde el centro se le aconsejó acudir al centro de salud en Peñalsordo, donde se le realizó un test de antígenos, dando negativo. El resto de la semana, que nos conste no han existido más ausencias. Buen puente, que la semana que viene, es un poco más cortita por los festivos!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-12-03','email de Alberto: HABLAMOS DE PAGAR BASTANTE DINERO (CERCA DE 1.000 €), PERO EL PROBLEMA ES QUE HASTA QUE AREA SOCIAL/JURIDICA CONSIGAN EL INTERNAMIENTO INVOLUNTARIO EL TUTELADO CONTINUA RESIDIENDO EN LA VIVIENDA Y GENERANDO LOS MISMOS PROBLEMAS, QUIZÁS HABRÍA QUE HABLAR CON FUTUEX PARA QUE LE EXPONGA A LA VECINA QUE NOS HAREMOS CARGO DE LOS ARREGLOS CUANDO ESTE SEÑOR SEA INGRESADO. AREA JURÍDICA: ¿OS PARECE QUE ACTUEMOS ASÍ? MAITE: SI ÁREA JURIDICA LE PARECE BIEN...HABLAS TU CON FUTUEX PARA QUE HABLEN CON VECINA. ICIAR: SI LA OPCIÓN ES PAGAR...ESCOGEMOS EL PRESUPUESTO MÁS BARATO Y ABONAMOS. ESTA ES LA ÚLTIMA OPCIÓN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-12-09','mi contestación a Alberto: Buenos días, como sabéis días atrás INSIDE no nos dejaba enviar al juzgado Decano de Cáceres dos expedientes. Finalmente la secretaria del Decanato nos ha dejado presentarlo vía email (aunque sólo ha recibido por esta vía el escrito principal, y por tanto falta porque reciban la documentación complementaria). Ahora toca que lo remitan y se asigne a un juzgado, donde deberían darnos un plazo de subsanación para la entrega de la documentación que falta. Se trata de una curatela con lo cual un internamiento involuntario es probable que tarden en concederlo (ya que deberían previamente revisar la sentencia para convertirla en lo que en la anterior ley era una tutela). Es decir, que puede tardar meses. Creo que lo más lógico es que arreglemos lo antes posible la vivienda. Además hay que tener en cuenta que los precios no paran de subir. Por tanto no hacer la obra pronto es un problema para la vecina (que puede ir a más la rotura), como para el propio curatelado por cuanto le puede costar más caro su arreglo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-12-03','email de la Abogada (Estefania): Buenos días Miguel, discúlpame pero ayer estuve preparando un juicio y me fue imposible contestar tu correo electrónico. Te explico, vuestro representante solo tendría que firmar el finiquito de Alfonsa, con el fin de cobrar la suma que aparece en el mismo (2.480€). Es un procedimiento habitual en las Compañías de Seguros para la percepción de la cantidad asegurada, se llama finiquito porque implica que se está de acuerdo con la cantidad percibida. Te recuerdo que el importe de la factura de la funeraria sin abonar son 3.100 euros, de los que corresponde pagar a Alfonsa (en proporción a su cuota hereditaria), 2.480€, mientras que a Mercedes le corresponde abonar 620€ (ella me firmará su finiquito a su vez por esa cantidad). Una vez ingresada la cantidad en los números de cuentas de ambas (la de Alfonsa la tengo porque me enviaste un certificado), se tendría que proceder a realizar una transferencia a Funerarias Siberia con carácter urgente, pues ya se ha reanudado el procedimiento monitorio de reclamación de la factura. Lo que voy a solicitar a la Compañía aseguradora es que incorpore los datos del tutor para la firma por vuestro representante de dicho finiquito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-12-07','email de Estefania: Buenos días Miguel, respecto de la firma del finiquito, me indican desde la compañía aseguradora que no es necesario modificarlo, que lo puede firmar su tutor directamente (añadiendo su nombre y su DNI encima de la firma). A ver si me lo podéis enviar el lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-12-09','mi contestación a la abogada Estefanía: Buenos días hasta hoy no he vuelto a la oficina y mañana es festivo en Mérida. Ya he puesto el documento para que lo firme el representante de la Comisión Tutelar. En cuanto lo tenga firmado te lo envío y en cuanto me confirmes que esté ingresado en cuenta avísame para hacer la transferencia que comentas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-12-09','Buenos dias Amalia! el pasado 7 de Diciembre se acompañó a Ildefonso García Rodríguez, que ha estado residiendo hasta la noche del día 6 de Diciembre en el Hostal Carmen de Zafra, a su nueva vivienda de alquiler en la Calle Espronceda, 1 de Valencia del Ventoso. En la vivienda se encontraba Rosario y su marido Enrique, los dueños de la misma, y estaba organizando la casa y haciendo reparaciones para cuando se instalara Ildefonso. Se adjuntan envían fotografías de las estancias de la vivienda, solamente no se ha hecho foto a otra habitación que había con una cama que estaba entre el salón y la cocina. Se estuvieron revisando todas las habitaciones con Rosario y con Ildefonso y se comprobó que todo estaba en muy buen estado y que incluso la dueña había comprado una colcha de invierno para la cama de matrimonio y le había dejado sábanas de verano y de invierno para que Ildefonso hiciera uso de ellas. Las bombonas de butano también las han dejado llenas casi todas para que Ildefonso no tenga que preocuparse de ese tema por ahora. Cuando se revisó todo el piso e incluso Rosario y Enrique enseñaron a Ildefonso cómo poner la lavadora y encender el brasero de butano y la catalítica, nos reunimos todos en el salón para la firma del contrato. Enrique, el dueño, leyó el contrato paso por paso y luego rellenaron los datos de Ildefonso y firmaron ambos, Enrique e Ildefonso, quedándose con una copia cada uno. Se adjunta envía una copia del contrato firmado escaneada. Tanto Rosario como Enrique confirmaron que no habían recibido la transferencia con los 500€, de los que 250€ eran para la fianza y los otros 250€ del alquiler correspondiente al mes de Diciembre. Se comentó con ellos la opción de cambiar la domiciliación bancaria de la factura de la luz y del agua y no les pareció una mala idea. Por lo que se ha quedado con Ildefonso el próximo día 14 de Diciembre, que estará en Zafra para acudir a un juicio y se le acompañará a Endesa y a Aqualia para preguntar si puede cambiar la domiciliación de esos dos recibos. Ildefonso hacía la petición de ir a cobrar su asignación al banco de manera quincenal a partir de mediados de este mes porque no hay oficina de BBVA en Valencia del Ventoso y el curatelado no quiere tener que ir a Zafra todas las semanas a retirar su asignación. La compañera dice que el piso esta bastante bien.. ojala y dure y no la lie. Seguimos, en esta semana mas rara y cortita! -- Antonia Mª Ramírez. Psicóloga Área Psicosocial areasocial3@futuex.es FUTUEX: Fundac','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-12-09','Buenos dias Amalia! el pasado 7 de Diciembre se acompañó a Ildefonso García Rodríguez, que ha estado residiendo hasta la noche del día 6 de Diciembre en el Hostal Carmen de Zafra, a su nueva vivienda de alquiler en la Calle Espronceda, 1 de Valencia del Ventoso. En la vivienda se encontraba Rosario y su marido Enrique, los dueños de la misma, y estaba organizando la casa y haciendo reparaciones para cuando se instalara Ildefonso. Se adjuntan envían fotografías de las estancias de la vivienda, solamente no se ha hecho foto a otra habitación que había con una cama que estaba entre el salón y la cocina. Se estuvieron revisando todas las habitaciones con Rosario y con Ildefonso y se comprobó que todo estaba en muy buen estado y que incluso la dueña había comprado una colcha de invierno para la cama de matrimonio y le había dejado sábanas de verano y de invierno para que Ildefonso hiciera uso de ellas. Las bombonas de butano también las han dejado llenas casi todas para que Ildefonso no tenga que preocuparse de ese tema por ahora. Cuando se revisó todo el piso e incluso Rosario y Enrique enseñaron a Ildefonso cómo poner la lavadora y encender el brasero de butano y la catalítica, nos reunimos todos en el salón para la firma del contrato. Enrique, el dueño, leyó el contrato paso por paso y luego rellenaron los datos de Ildefonso y firmaron ambos, Enrique e Ildefonso, quedándose con una copia cada uno. Se adjunta envía una copia del contrato firmado escaneada. Tanto Rosario como Enrique confirmaron que no habían recibido la transferencia con los 500€, de los que 250€ eran para la fianza y los otros 250€ del alquiler correspondiente al mes de Diciembre. Se comentó con ellos la opción de cambiar la domiciliación bancaria de la factura de la luz y del agua y no les pareció una mala idea. Por lo que se ha quedado con Ildefonso el próximo día 14 de Diciembre, que estará en Zafra para acudir a un juicio y se le acompañará a Endesa y a Aqualia para preguntar si puede cambiar la domiciliación de esos dos recibos. Ildefonso hacía la petición de ir a cobrar su asignación al banco de manera quincenal a partir de mediados de este mes porque no hay oficina de BBVA en Valencia del Ventoso y el curatelado no quiere tener que ir a Zafra todas las semanas a retirar su asignación. La compañera dice que el piso esta bastante bien.. ojala y dure y no la lie. Seguimos, en esta semana mas rara y cortita! -- Antonia Mª Ramírez. Psicóloga Área Psicosocial areasocial3@futuex.es FUTUEX: Fundac','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2021-12-09','Buenos días Amalia, te mando el escrito firmado por mi tío . Como ya hablamos por teléfono si no puede ser que le hagan el traslado a una residencia aquí en Badajoz,le alquilaremos un piso aquí porque el esta pasándolo mal y yo todos los domingos me vengo mal de verlo así. Aparte del gasto que nos supone todas las semanas el tener que desplazarnos hasta Mérida. Me ha dicho una clienta que su marido y 3 personas mas han sido trasladadas de la residencia donde el se encuentra Los olivos de Merida a la de Puente Real de aquí de Badajoz no entiendo como el no puede ser trasladado . Te pido que por favor que a la mayor brevedad posible mi tío pueda estar aquí en Badajoz ya sea en una residencia o en un piso de alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2021-12-11','miguel, pregunta su tía Amelia por la autorización para los trámites*****************Mi contestación: Buenos días Amelia, necesitaría saber cómo van los trámites de la herencia. Me comentaste que recabarías documentación que te pedía la notaria de Guadalajara. Dime si la notaria tiene todo preparado para firmar dicha herencia. Una vez que tenga el borrador de la herencia tendré que pedírselo (porque tendremos que ratificarla desde la notaria de Mérida). La Autorización que te comentaba era por si te hacía falta pero imagino que habrás podido recabar toda la documentación que te requería la notaria.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2021-12-11','miguel, pregunta su tía Amelia por la autorización para los trámites*****************Mi contestación: Buenos días Amelia, necesitaría saber cómo van los trámites de la herencia. Me comentaste que recabarías documentación que te pedía la notaria de Guadalajara. Dime si la notaria tiene todo preparado para firmar dicha herencia. Una vez que tenga el borrador de la herencia tendré que pedírselo (porque tendremos que ratificarla desde la notaria de Mérida). La Autorización que te comentaba era por si te hacía falta pero imagino que habrás podido recabar toda la documentación que te requería la notaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2021-12-13','miguel, miguel, pregunta su tía Amelia por la autorización para los trámites*****************Mi contestación: Buenos días Amelia, necesitaría saber cómo van los trámites de la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-12-13','TERESA RECIBO LLAMADA DEL CRR OLIVENZA Y ME COMENTA QUE EMILIA SIGUE CON LA IDEA DE PEDIR EL ALTA VOLUNTARIA. PARA INTERTAR QUE CAMBIE DE IDEA SE HA IDO UNOS DIAS A DON BENTIO CON MIGUEL ANGEL A PESAR DE ADVERTIRLE DE LAS CONSECUENCIAS QUE PUEDE TENER PUES TIENE ORDEN DE ALEJAMIENTO LA GUARDIA CIVIL HA DETENIDO A MIGUEL ANGEL A VERLO CON EMI POR LA CIUDAD. EMI SE ENCUENTRA ESTOS DIAS EN DON BENITO Y HOY SE LE GESTIONA TAXI CON ANSELMO PARA QUE SE VAYA DE NUEVO A OLIVENZA , finalmente contaremos con otro taxista que se llama Gabriel , este es su teléfono (608920279) y también acepta el pago por transferencia. La recogerá a las 11:00h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-12-13','TERESA Por la presente se solicita autorización para el tutelado DARIO LOPEZ GIRALTE para pasar vacaciones de navidad (del 30 de diciembre al 5 de enero) en Carbonero el Mayor (Segovia), con su tío Pedro, siendo este de las pocas referencias familiares de que dispone. TIO PEDRO C/ Las Arquetas,5 de Carbonero el Mayor (Segovia) telf.: 603 10 04 35 En esa misma fecha viajará su hermano Alejando, atendido en Vivienda Tutelada de Plasencia. Desde ese servicio trasladan a Alejando en furgoneta y se han realizado gestiones para que el traslado sea conjunto, no siendo viable. Por ese motivo Darío utilizará transporte público. Salida desde Plasencia , haciendo transbordo en Valladolid y posteriormente a lugar de destino. Desde la vivienda tutelada de Plasencia y el tío Pedro nos confirman que dicho viaje ha sido realizado en anteriores ocasiones por Darío sin mayores complicaciones. Quedamos a la espera de contestación SE AUTORIZA VIAJE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2021-12-13','TERESA Nuevamente me pongo en contacto para comunicarte que David Vita finaliza su contrato de trabajo el lunes 13 de diciembre. Te lo comento por si le gestionáis vosotros el tema del subsidio por desempleo en caso de que le tenga cuenta cobrarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-12-13','miguel, envío a la abogada Estefanía el documento firmado por el gerente, que me remitió para que la funeraria transferiera el dinero (junto con la aceptación del cargo y el dni del gerente)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-12-13','abonada a la notaria la compraventa de la vivienda de la c/ el hinojo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2021-12-13','Ana: Icíar, secc. ecca., me informa que ha hablado con Puerto, TS SSASB de Plasencia (927 60 03 28), le confirma que Ángel Félix sí está empadronado en Plasencia, pero no saben dónde está. Está en paradero desconocido. *Tardará en recopilar la documentación solicitada de oficio para el inventario para poder remitírnosla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-12-13','miguel, a petición de Ana envío nuevo email a la abogada (Mª Carmen Lucas Duran 927-226664; email: mlucasduran@icac.es para que nos informe: Buenas tardes, tal y como le remití la sentencia de incapacitación y nombramiento del tutelado Saturnino Miguel Salgado Jimenez necesitaría saber si necesita algún documento más y qué se sabe hasta ahora del procedimiento, ya que en días anteriores llamé al juzgado de 1º instancia nº6 de Cáceres en relación a las Diligencias Previas 751/20 del tutelado Saturnino Miguel Salgado Jimenez para que nos explicaran como tutores en qué situación se encontraba el procedimiento, del cual seguimos desconociendo el contenido de las actuaciones judiciales a lo cual se negaron y nos dijeron telefónicamente que se lo solicitemos a nuestra abogada. En el día de hoy su hermano Tomás se ha puesto en contacto con la Comisión Tutelar para interesarse del estado del procedimiento, al que se ha dicho que desde esta Comisión no disponemos de más información que el número de procedimiento y el juzgado. Quedamos a su disposición para cualquier aclaración e información necesaria para el caso y agradeciendo de antemano nos informe sobre dicho procedimiento.****************************Reenvío email a Ana: Ana te reenvío el email que he mandado a la abogada. Cuando tenga una respuesta de ella hablaré con el hermano del tutelado, con la información que obtenga. Tomás Salgado Jimenez (621-375898)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2021-12-13','Ana: Envío a Fátima, Ed. Asoc. Vera, autorización para pasar unos días de vacaciones durante las navidades en su domicilio familiar. ················· Envío a Toni, Futuex correo: "Buenas de nuevo Toni, En relación a ADRIÁN ORTIGOSA FUENTES, se le autoriza a pasar un par de semanas en el domicilio familiar. ¿Sería posible organizar el viaje con el apoyo de las educadoras del programa de apoyo comunitario igual que se hizo en verano? Las fechas previstas son del 23 de diciembre al 7 de enero. Pero se puede modificar en función de vuestra disponibilidad. Ya he hablado con Fátima, la educadora del centro. Si es posible que se pongan en contacto con ella para cerrarlo y me informáis después al respecto. Gracias. Seguimos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2021-12-13','Ana: Envío a Fátima, Ed. Asoc. Vera, autorización para pasar dos semanas de vacaciones durante las navidades en su domicilio familiar. ············· Solicito a Alberto, Jefe Secc. el extra de 100€ para la familia, para traslado y otros gastos (Ya se ha hecho otros años)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-12-10','Ana: Recibimos correo de la Directora del Centro de Fundación Autismo Sur, reclamando se abone ya la deuda. Costi lleva en su centro desde Noviembre de 2020 y aún no se ha abonado nada. *Reenvío correo a Alberto, jefe secc. ecca. y lo guardo tb en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-12-13','Ana: Coordinación telefónica con Toni-Futuex: Concretamos el ingreso de Antonio en la Casa de la Misericordia para el miércoles día 15 sobre 12 - 12:30 h. Gloria, Ed. Futuex, se encargará de gestionar el taxi y acudirá a Alcuéscar para darle soporte esa mañana y asegurarse de que se produce el traslado al centro. ··········· Llamo a Fernando Pecero (651 97 56 17): Todo ok. *Eso sí, sería necesaria PCR, cuestión que olvidó decirme. ··················· Llamo al centro de salud (927 38 42 10 / 52499) varias veces, pero no obtengo respuesta. En el punto de atención continuada me dicen que llame mañana a primera hora, ellas no pueden gestionar dicha cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-12-13','Ana: Correo de Juan Aª Vázquez, Res. Torres de Don Miguel (gerovida2010tsocial@hotmail.com): "Buenos días, Estamos llamando desde el sábado para comunicar el fallecimiento de Ángeles Martínez Gavilán con DNI: 08433657-V. Tutelada por ustedes y residente de nuestro centro. Se avisó a la familia de la situación pero se han desentendido de todo, por lo que ante no saber que hacer hasta que nos comuniquen los pasos a seguir se encuentra en las cámaras de la funeraria a la que avisamos. Quedamos a la espera que se pongan en contacto con nosotros para poder resolver todo cuanto antes dada la delicada situación. Informarles que la familia nos dice que no tienen intención de enterrarla en ninguna de las locidades en las que ellos reside y que tampoco tienen nicho para ello. Por lo que estamos barajando la opción de ponernos en contacto con el Ayuntamiento de esta misma localidad. Por favor, póngase en contacto con nosotros cuanto antes. Muchas gracias, un saludo" ························ Llamo a Ana, Res. (927 16 44 24): Puesto que Ángeles no tiene Seguro de Decesos, se contratará el servicio a la funeraria y nos pasarán la factura. Como tanto en la residencia como en la CTAEX desconocemos cuál era su deseo y la familia no tiene interés en enterrarla en sus localidades de residencia ni de origen, se enterrará en el cementerio municipal del pueblo. *Los familiares han reclamado sus joyas, desde el centro le han dicho que no podían darles nada sin consultárnoslo antes. ······················ Miguel, Asesor Jurídico indica que según se indica en el auto de medidas cautelares, el centro debe custodiar las joyas. Se indicará al Jdo. en la rendición final de cuentas para éste indique cómo proceder. ················· Envío correo a Ana (gerovida2010@hotmail.com) y Juan Antonio (gerovida2010tsocial@hotmail.com): "Buenas tardes Ana y Juan Antonio, Esta mañana se cortó la llamada y ya no fui capaz de volver a contactar contigo Ana. Después hablé con el Jefe de sección económica y con el Asesor Jurídico. Éste último, indica que según el Auto de Medidas Cautelares, es en vuestro centro donde se deben custodiar las joyas de Ángeles. *Desde la CTAEX, se comunicará al Juzgado en la Rendición Final de Cuentas, para que éste indique cómo proceder, mientras tanto debéis seguir custodiándolas. En cuanto a los familiares, podéis remitirles al Juzgado que incapacitó a Ángeles, para cualquier cuestión, duda o petición que os planteen. Decirles que no podéis entregarles nada mientras no lo diga el Juez. ..." ···························································································································································································· Carlos Asensio, Ayto. de Torre de Don Miguel, nos envía copia de la comunicación al SEPAD de la baja de la plaza relativa a Ángeles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-12-14','miguel, en relación a la venta de la vivienda de la c/Hinojo llega email de la compradora Ana Mª Muñoz Toro (email anamariamt99@gmail.com): Soy Ana María Muñoz Toro, la chica que compró una vivienda en Guadiana, que pertenecía a Juan Carlos Rubio Galán, he ido hoy a recoger las escrituras y sale reflejada la hipoteca anterior en las escrituras, me dicen que tenéis que ser vosotros los que os hagáis cargo de pedir un certificado como que está anulada dicha hipoteca en Ibercaja y llevar el certificado a una notaria para que cuando pida la nota simple no aparezca la vivienda con cargos.************************************************Hablo con Dolores Alvarez Moran 924-473036, a quién le doy el email para que me remita la documentación para autorizarles a tramitar la cancelación registral (en su día fue tramitada la cancelación económica con la oficina de Guadiana Emilio Mariño del Real tlfno 924-470157 quien por email de 30-9-21 indicó que para la cancelación registral nos pusieramos en contacto con la oficina origen del préstamo, que en este caso es Pueblo nuevo del guadiana)************************ Mi contestación: Buenos días, efectivamente está en trámite de hacerse la cancelación registral. Ha habido un fallo de coordinación entre oficinas de ibercaja por cuanto cuál de las dos (Guadiana/ Pueblo nuevo del Guadiana) tenía que tramitar dicha cancelación. He hablado esta misma mañana con la oficina de Pueblo nuevo y será ésta la que me remita la documentación necesaria para autorizarles a que tramiten dicha cancelación. Tardará un poco (aproximadamente 3 meses) porque para cancelar registralmente es necesario emita la entidad bancaria un certificado de cancelación total de la deuda, la firma ante notario de la escritura de cancelación de hipoteca y su posterior inscripción en el registro de la propiedad. En cuanto esté cancelada le envío un email. Disculpe las molestias. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2021-12-14','TERESA ENAIL DE ANA EDUCADORA PI ZAFRA Te escribo para informarte de que voy a mandar finalmente, y si estáis de acuerdo, documentación de Natalia a Adiser, ya que me pidieron si teníamos certificados de escolaridad y estudios y demás…y me he dado cuenta de que hay otras cosillas además del libro de escolaridad como el certificado de discapacidad original, fotocopia de vacunación infantil, solicitud y resolución de la pensión, cartilla bancaria… y cuando vayáis a verla…pues le echas vistazo in situ y si consideras oportuno pues lo guardáis allí en Mérida o que se lo queden allí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-12-14','Ana: A primera hora llamo al C.S. Alcuéscar (927 38 42 10 / 52499): el celador me informa que la Dra. Rocío Domínguez está reunida y la enfermera no está. Me pide que vuelve a llamar más tarde. ··········· Llamo más tarde: Le han hecho el volante a Antonio para hacerse la PCR a las 13 h. ············ Lo comunico a Toni-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2021-12-14','TERESA Me pongo en contacto para comunicarte que Beatriz realizará la visita a su hija el próximo martes día 14 de diciembre. Por otro lado, te quería plantear la posibilidad de que Beatriz fuera unos días a casa en Navidad. La cuidadora que la acompaña a visitar a la niña me dice que cuando han pasado a saludar a los padres, la casa se ve ordenada y que han hecho reforma en el baño y en la cocina. Bea demanda constantemente pasar unos días en su casa y los profesionales del centro lo consideramos oportuno. Como posibilidad de desplazamiento podría irse en el tren hasta Cáceres el día 23 que viaja otro usuario muy autónomo y que viaja con frecuencia hasta Plasencia y que sus padres la esperen en la estación de Caceres y cojan un autobús hasta Trujillo y al regreso podría hacerlo igual. Podría estar al menos 4 o 5 días en casa. Todo esto teniendo en cuenta, que antes de la pandemia Bea hacía salidas a casa coincidiendo con los periodos vacacionales y eran los padres los encargados de recogerla o traerla. Y por otro lado, quería plantear la posibilidad de que los días que Bea esté en casa pudiera visitar a su hija. La acompañaría el padre de Bea (La cuidadora me dice que la abuela siempre comenta que ella no tiene problema en que el abuelo vea a la niña, pero se niega a que la vea la abuela) Ya que viven tan cerca, estaría muy bien que pudieran verse. Ya me dices si es posible el planteamiento que te hago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='NOGALES'and apellido2='MUÑOZ'),'2021-12-14','-Amalia : envío a S. Social por email la opción de la PFHC , para dejar la PNC .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='NARANJO'and apellido2='LUENGO'),'2021-12-09','EXITUS El CSS de Mérida informa de su fallecimiento. El óbito tuvo lugar el día 09/12/2021, a las 15:45 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2021-12-14','Buenas tardes! Lo de el piso de alquiler ha sido después de hablar contigo y que me dijeras que podría tardar mucho tiempo en que el traslado a otra residencia fuera posible. Entonces si va a tardar mucho y hay listas de espera tan largas le alquilare un piso cerca de mi. Lo que no entiendo es lo de enviar el escrito al juez si mi tío no está incapacitado, creo que es alargarlo. Espero que no se demore mucho ya que me gustaría tenerlo aquí antes de navidades .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2021-12-09','Buenos días Cristina , planteas dos opciones; o traslado a otra residencia en Badajoz o alquilar un piso . Desde esta Comisión no nos oponemos a ninguna de ellas , tu tío tiene actualmente una sentencia de incapacitación parcial , curatela , para asistirle en actos patrimoniales. Para resolver tus dudas sobre la gestión y trámites de un cambio de residencia tienes que preguntar en la propia residencia o el el SEPAD , en el tf . 924010149. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2021-12-14','TERESA La sobrina de D. Carmelo Gracia Redondo, Mónica Gracia, nos solicita poder disfrutar de período vacacional en navidades con su tío, en concreto quiere que se ausente desde el 23/12 al 9/01/2022. Nosotros lo consideramos idóneo y adecuado para el residente, al poder establecer y reforzar vínculos familiares y afectivos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-12-14','TERESA Realizamos nota para informar de varias cuestiones surgidas con el tutelado en el último seguimiento presencial llevado a cabo el 7 de diciembre de 2021. En primer lugar, nos hemos puesto en contacto con el taxista de la localidad para pedir presupuesto, ya que el próximo 14 de diciembre (martes) tiene cita en los juzgados de Castuera en relación a las denuncias interpuesta por la agresión a los policías locales de Zalamea de la Serena. Manuel Centeno Delgado (taxista) nos indica que puede recogerlo a las 10:15 horas y que el coste del desplazamiento es de 20 euros. El pago se puede realizar por transferencia bancaria; ES15 3001 0028 1828 2000 2308. Durante la visita encontramos a Pablo con un ojo morado y una herida en la ceja, nos indica que se ha emborrachado el fin de semana y que ha sido por una caída. Se muestra con las profesionales del programa cabreado y muy insistente en que le dejemos dinero en efectivo que son fiestas y quiere salir. Cuando vamos a la compra de necesidades básicas intenta llevarse de la tienda un litro de cerveza, al prohibirle esta acción cuando vamos por la calle entra en otra tienda a coger vino. En este estado es imposible trabajar con él y conseguir que razone. Estas situaciones con el tutelado cada vez se producen con más frecuencia, aumentando la posibilidad de denuncias, conflictos vecinales incluso el propio riesgo de las profesionales a la hora de llevar a cabo los seguimientos. Por todas estas cuestiones cada vez se hace más prioritario que Pablo sea trasladado a un centro, donde se eviten riesgos y consiga llevar una vida más normalizada que en la actualidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-12-14','PRESUPUESTO FIJADO PARA ILDEFONSO . AMALIA: el número de cuenta de cargo de los SUMINISTROS ha de ser el de ABANCA, ya que es donde cobra la pensión: ES42 2080 3606 1230 4001 5416 ICIAR: TRANSFERENCIA PERMANENTE DE ABANCA A BBVA X IMPORTE DE: 250 (ALQUILER) + 650 €/MES= 900 €/MES TRANSFERENCIA PUNTUAL DESDE ABANCA X "FIANZA Y ALQUILER DICIEMBRE 2021", X IMPORTE DE 500 € TRANSFERENCIA PERMANENTE DESDE BBVA A PROPIETARIA (FOTO) X "ALQUILER PISO" X IMPORTE DE 250 €/MES (AMALIA: ESTO ES PARA QUE EL VEA QUE SE ABONA EL ALQUILER) REINTEGRO PERMANENTE BBVA X 325 €/QUINCENA EN BBVA ZAFRA A PARTIR 16/12/2021.','2');
