insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-12-14','Ana: Correo de Miguel, Asesor Jurídico CTAEX: "Hola en relación a nuestro tutelado que te preguntó su hermano ayer, comentarte que la abogada me ha trasladado este documento donde van a citar a Menores (Junta de Extremadura) como representantes de la supuesta víctima de delito de agresión sexual por si quiere personarse como acusación en el proceso penal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-12-14','miguel, recibo email de la abogada adjuntandome el último documento consistente en un ofrecimiento de acciones a la junta de extremadura (menores) como representantes de la supuesta victima de agresión sexual Antonio Javier Martin Santos','2');
