insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2021-12-14','TF DE SU HIJA ALMUDENA : 633627412 LE LLAMO PARA COMUNICARLE QUE SU MADRE VA A SER DERIVADA A LA UNIDAD DE PSIQUIATRIA . AL PARECER ELLA LE HA INDICADO QUE SE LA IBA A LLEVAR A SU CASA EN NAVIDAD . LE PIDO QUE ANTES DE GENERAR EXPECTATIVAS A SU MADRE HABLE CONMIGO PARA VER QUÉ SALIDAS SE PUEDEN HACER. ME CUENTA QUE LA RELACIÓN CON LA MADRE ES CONFLICTIVA . SU MADRE TUVO 6 HIJOS , SU HNO MAYOR TIENE MÁS DE 50 AÑOS Y ELLA 33 AÑOS . LA MADRE EJERCIÓ LA PROSTITUCIÓN , ESTUVO EN PRISIÓN POR ELLO EN LA ÉPOCA FRANQUISTA , ELLA ES SU HIJA PEQUEÑA . TIENE TAMBIÉN 4 HIJOS DE DOS PADRES DIFERENTES , LOS ATIENDE ELLA SÓLA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='NARANJO'and apellido2='LUENGO'),'2021-12-14','Buenos días, informo del fallecimiento de la paciente Josefa Naranjo Luengo, el día 09 de diciembre a las 15:45 horas. Un saludo. Manuela Domínguez Flores. Trabajadora Social. Centro Sociosanitario "Adolfo Díaz Ambrona". Ctra. Valverde, km. 2. 06800 Mérida. Tel.: 924 38 80 81. Ext.: 24012','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-12-14','miguel, hoy dejo firmada la compraventa de la c/Constitución 13, ante la notaria de Montijo (Sara de Soto). Ya hecha por la parte económica el pago de la factura de compraventa por la parte económica. Quedo pendiente que me envíen la compraventa por email.','2');
