insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-12-14','Ana: Reenvío a Toni-Futuex, el correo remitido por Pilar Martín, TS ESM, el pasado viernes 10: "Hola Ana, te comunico la nueva cita con el psiquiatra de Juan Chamorro Holguín para el próximo día 29 del mes en curso a las 12 horas. Un abrazo."','2');
