insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2021-12-13','Ana: Correo Miguel Ángel, Director CRR (crr@grupociudadjardin.com): "...le dieron de alta el viernes día 10 del 12 de 2021 sobre las 22:00 de la noche llegando en un estado de necesidad de servicios asistenciales. No se mantiene en pie y necesita silla de ruedas, utilizando pañales y llegó al recurso incluso con la vía puesta debido a un error que habían cometido por parte del Hospital y no traían ningún tipo de informe. Se lo volvieron a llevar al Hospital para que le fuese retirada la vía y lo volvieron a traer con el pijama lleno de sangre y vomitado, presentaba conductas de arcadas continuamente. Se llamo al 112 para informar que no respiraba bien y que es un Centro Comunitario y que no tenemos servicios sanitarios y lo volvieron a ingresar y nos informaron que hoy se iban a poner en contacto con la Trabajadora Social para ver que pueden hacer en este caso. La neuróloga de Urgencias refiere que Martín en el momento actual necesita cuidados específicos y que nosotros en el recurso no se los podemos ofrecer." ········· *Guardo Informe de Alta en el expdte. digital. *Diagnóstico: "Posible hematoma subdural derecho". ······················· Coordinación con Mariluz Madrigal, Jefa Secc. Salud Mental: *En el hospital le han pasado finalmente la herramienta para T3, plaza sociosanitaria, pero no da suficiente puntuación. Mañana le darán el alta y se valorará la contratación de una persona de apoyo durante una temporada de forma privada. ··········· Envío correo a Miguel Ángel Ramírez, Director CRR: "...He hablado con Mariluz, Jefa de Secc. de Salud Mental, en varias ocasiones esta mañana, me ha ido informando ella antes de leer tus correos. En cuanto a solicitar una auxiliar por la Ley de Dependencia, como ya tiene la plaza con vosotros a través de dependencia, no se puede pedir. No obstante, puesto que tiene dinero, se le puede poner de momento, al menos, de forma privada. ¿Conocéis a alguien que quiera/pueda hacer este apoyo? ¿O alguna empresa de Cáceres que conozcáis que os dé confianza? Ya me decís, pues se podría pagar durante un tiempo. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-12-15','Ana: Llamada de Ana Amor, Placeat: Christofer se irá unos días en Navidad a casa de su tía Belén (24 ó 24 de diciembre). Los familiares no pueden es ir a recogerlo por no tener vehículo. *Enviarán presupuesto de taxi y de acompañamiento de algún/a auxiliar de confianza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-12-11','EXITUS El centro comunica su fallecimiento, acaecido el 11/12/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-12-14','Ana: Correo de Julián Álvarez, COCEMFE (gerencia@cocemfecaceres.org): "Buenos días. Como todos los años solicito un extra para Tomás por los reyes, la cantidad como en años anteriores. Por otro lado informo que Tomás ya se ha puesto la vacuna de la gripe y que próximamente (sobre 22 o 23 de diciembre nos ha informado Sanidad) se le administrará la 3ª dósis de la vacuna COVID. Saludos" ······················ Paso a Alberto, jefe secc. ecca., la solicitud del extra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2021-12-15','Ana: Paso a Alberto, jefe de secc. ecca. presupuesto para obra en el patio (pared) de la casa de Mª Carmen, que me remite Pilar, Hogar San Vicente de Paúl. ············ *El muro es medianía entre la casa del vecino y la de Mª Carmen. La factura va a nombre de los dos y cada uno abonará el 50% + IVA.','2');
