insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-12-15','miguel, email de Jorge el abogado donde se suspende el procedimiento de arbitraje de desahucio porque la demandada ha solicitado abogado de oficio (puede tardar meses en que se le asigne)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-12-15','miguel, hablo con la notaria y le dejo teléfono e email para que le metan prisa a Marisa (a quién mandé la documentación en su día)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-12-15','nota de la Subcomisión de casos de Alejandro del otro dia, a través del tems, ojala sirva para que se materialice algun cambieo en este caso. Con fecha lunes 13 de diciembre de 2021, estaba planificada la subcomisión de casos, para tratar como único orden del día, la situación del curatelado Alejandro Núñez Bono. Con las siguientes profesionales presentes: Ana Delfa, (directora técnica del CRPS) como moderadora Soraya Masa (jefa de unidad de programas asistenciales del Sepad) Maite Gómez (trabajadora social, jefa sección comisión tutelar) Mª Ángeles Almena (directora CADEX) Obdulia Suarez (médica CEDEX) Pablo Calderón (psiquiatra área de salud mental Valdepasillas) Carmen Díaz (trabajadora social área de salud mental Valdepasillas) Virginia (enfermera área de salud mental Valdepasillas) Carmen Franco (UME, sociosanitario Mérida) Mª Teresa Pacheco (educadora del equipo de apoyo social comunitario de Badajoz) Antonia Mª Ramírez (psicóloga-coordinadora del área social y del programa: “la mejora del acceso a los sistemas de protección públicos de las personas tuteladas y curateladas de Extremadura”) De inicio, se expone qué argumento existe en relación al curatelado, para solicitar la convocatoria de esta subcomisión; y entre las opiniones de los presentes, se constata una realidad: la imposibilidad de cualquier abordaje con Alejandro de manera ambulatoria. Algo que se viene realizando desde el año 2019 que es valorado ya en cedex y desde noviembre de 2020, al pasar su tutela a la comisión de adultos, comprobando la nula colaboración y las diferentes situaciones de violencia y falta de habilidades mostradas, dificultando toda posibilidad de adaptación o recuperación. Dejando constancia que desde la comisión, se han intentando bastantes cosas con el que no han dado resultado por el momento,. Es por ello que, desde su equipo de referencia de salud mental, ante las continuas llamadas al 112 y sus derivaciones a urgencias hasta terminar en un ingreso en UHB, aunque ante su buena evolución, solo estuvo una semana, y ante el rechazo de posible plaza en la UDAC, han solicitado esta subcomisión, para, entre todos los presentes, poder plantear una nueva solución. Se plantea la necesidad de un dispositivo de contención, que conlleve un itinerario o recurso para modificar conducta y control de su tratamiento y a partir de ahí, la posibilidad de un dispositivo de mayor autonomía, con actividades ocupacionales, ya que ahora mismo su funcionalidad es cero. Carmen Franco (UME), destaca que el trastorno de conducta entra en la red de discapacidad intelectual y que, por tanto, un ingreso en UME, quedaría descartado, exponiendo incluso la dificultad por la que atraviesa ahora mismo el servicio, con un solo psiquiatra al día. Soraya Masa, plantea repetir de nuevo el itinerario: solicitarle valoración de dependencia, revisión de diagnóstico, tramitar de nuevo la solicitud a la UDAC, aportando estos nuevos informes más actualizados, incluso realizando su psiquiatra un CI, ante el rechazo por ser límite y como venimos exponiendo y así se ha comprobado en nuestras intervenciones con Alejandro, su funcionalidad y habilidades son escasas, y ante un nuevo diagnostico de cociente intelectual, alomejor los resultados objetivan otro grado de discapacidad más severo. (algunos profesionales, creo recordar desde el cadex, tenian alguna discrepancias al respecto) También desde la comisión, Maite Gómez, informa del proceso judicial que existe ante las diferentes denuncias ya presentadas y que. por tanto, hay que dejar que se mueva toda esta situación, pues ayudará ante la toma de decisiones o solicitud de un posible ingreso involuntario. Desde el Cedex, opinan que ingreso en una comunidad terapéutica, no es su sitio ideal, siendo un lugar que implica voluntariedad, algo que Alejandro no tiene, se puede ir en cualquier momento. Y estando expuesto al contacto con otros usuarios y otros tipos de consumo, limitaría y mucho su intervención. Y se aclara que, según los controles que se le viene haciendo y no restando importancia al hecho de consumir, hay más patología mental que consumo en sí. Desde nuestro equipo de apoyo social comunitario de Badajoz, según nuestro criterio, una vez efectuados los seguimientos, expresamos y confirmamos todo lo expuesto hasta el momento: el déficit de su estado psicopatológico, incluso físico. Permanentes conductas disruptivas, sin encontrar colaboración por parte de Alejandro. Entendiendo que en un contexto residencial que se ajuste mejor a su perfil, sería el más adecuado para que se pudiera desenvolver dentro de una normalidad en: tratamiento, revisiones médicas, organización de su vida diaria, horarios, comidas y, sobre todo, evitar las conductas delictivas que cada día van en aumento, en número y peligrosidad. No siendo su madre, ante su falta de habilidad y capacidad, figura de autoridad para Alejandro. Ni tampoco ya sus abuelos, que, por edad y enfermedad, se muestran cansados y agotados de toda esta situación. Siendo más o menos el mismo criterio de salud mental valdepasillas, y el de la comisión, que en un entorno contenedor podría funcionar bien. Como conclusión, Anda Delfa resume lo siguiente: Se confirma la situación grave de conducta, que repercute en lo personal, familiar y social inmediato. Comunidad de vecinos ya con denuncias presentadas, tema judicializado. Siendo el origen: discapacidad intelectual, déficit de atención, consumo sustancias, alteración de conducta, también sin consumo. Abordaje ambulatorio imposible. Repetir itinerario, actualizando informes: Retomar consultas revisión de psiquiatría (jueves 16 de diciembre nueva consulta) posibilidad de hacer un nuevo CI. Valoración de dependencia, necesaria para cualquier solicitud de ingreso (debe de firmarla el curatelado) Nuevo informe de la trabajadora social de salud mental de su área. Nueva revisión en CADEX (tiene pendiente la cita) pero se esperará hasta tener los informes actualizados Y nueva solicitud a la UDC, sin descartar como dice su psiquiatra, el inicio de un ingreso involuntario, no urgente. Se aclara que en la UDC no se aceptan ingresos judiciales. Pero el psiquiatra matiza que no es medida de condena, sino solo involuntario ante la negativa del curatelado. Se solicita, desde la comisión tutelar a nuestro esquipo de apoyo social comunitario de Badajoz, el retomar, si Alejandro acepta, el acompañamiento a las consultas médicas y tratamientos, en la medida de lo posible, algo que este equipo ha venido realizando desde noviembre de 2020, y ante lo que ofrecemos la total colaboración. Queda confirmado que este próximo jueves 16 de diciembre, se planifica dicho acompañamiento a consulta de psiquiatría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-12-15','nota de la Subcomisión de casos de Alejandro del otro dia, a través del tems, ojala sirva para que se materialice algun cambieo en este caso. Con fecha lunes 13 de diciembre de 2021, estaba planificada la subcomisión de casos, para tratar como único orden del día, la situación del curatelado Alejandro Núñez Bono. Con las siguientes profesionales presentes: Ana Delfa, (directora técnica del CRPS) como moderadora Soraya Masa (jefa de unidad de programas asistenciales del Sepad) Maite Gómez (trabajadora social, jefa sección comisión tutelar) Mª Ángeles Almena (directora CADEX) Obdulia Suarez (médica CEDEX) Pablo Calderón (psiquiatra área de salud mental Valdepasillas) Carmen Díaz (trabajadora social área de salud mental Valdepasillas) Virginia (enfermera área de salud mental Valdepasillas) Carmen Franco (UME, sociosanitario Mérida) Mª Teresa Pacheco (educadora del equipo de apoyo social comunitario de Badajoz) Antonia Mª Ramírez (psicóloga-coordinadora del área social y del programa: “la mejora del acceso a los sistemas de protección públicos de las personas tuteladas y curateladas de Extremadura”) De inicio, se expone qué argumento existe en relación al curatelado, para solicitar la convocatoria de esta subcomisión; y entre las opiniones de los presentes, se constata una realidad: la imposibilidad de cualquier abordaje con Alejandro de manera ambulatoria. Algo que se viene realizando desde el año 2019 que es valorado ya en cedex y desde noviembre de 2020, al pasar su tutela a la comisión de adultos, comprobando la nula colaboración y las diferentes situaciones de violencia y falta de habilidades mostradas, dificultando toda posibilidad de adaptación o recuperació