insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-12-15','Ana: Llamo al C. Salud - Alcuéscar (927 38 42 10) para preguntar por el resultado de la PCR, aún no lo tienen. La enfermera me llamará cuando lo sepan. *Al no saber nada, al final de la mañana vuelvo a llamar, no están ni la enfermera ni la Dra. ··························································································································································································· Hablo con Toni - Futuex, a Gloria, Ed. le han dicho que posiblemente hasta esta tarde no esté el resultado. ····························································································································································································· Hablo con Fernando Pecero (651 975 617), Antonio ha llegado bien. Al no tener el resultado de la PCR le han puesto en aislamiento y lo ha aceptado bien también. ··· En cuanto tengamos el resultado se lo comunicaré.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-12-15','Ana: Correo de Sara Rosa, TO del CSS-Plas. (sara.rosa@salud-juntaex.es): "Buenos días, Ana: Me pongo en contacto contigo para informarte que no va a ser posible realizar la llamada con Juan Carlos hoy. Se encuentra en aislamiento preventivo y pendiente de realizarle una PCR. En cuanto cambie esta situación, me pongo en contacto de nuevo contigo y fijamos otra fecha. Muchas gracias."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2021-12-15','Ana: Correo Miguel Ángel, Director CRR (crr@grupociudadjardin.com): "Buenos días Ana te remito el informe de Alta Hospitalaria de Martín Miguel Miranda Hernández, estamos en proceso de observación y adaptación ya que para el el recurso en el cual nos encontramos es nuevo porque ingresó antes del ingreso del mismo en el Hospital. Te comento que por parte del Equipo de Monitores/as le vamos a intentar dar los apoyos que en el momento actual necesita, si informándote que he contactado con un profesional de la rama de atención sociosanitaria que había realizado sus funciones en el recurso con anterioridad por si viésemos que fuese necesario en el peor de los casos. Te mantendré informada." ··· Guardo el informe de alta. ···················· Tras hablarlo con Alberto, jefe secc. ecca., comunico a Miguel Ángel que tiene dinero para contratar de forma temporal a Aux. privada, si fuera necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-12-14','Ana: Correo de Estrella Durán, TS CSS Plas.: "Buenos días, Ana Te escribo para comunicarte que ayer por la tarde volvió a fugarse Juan Carlos Ruíz García del centro, regresando por su propio pie a las 3 de la mañana, muy sucio, lleno de arañazos y heridas, oliendo a fuego y con mucho frío. También lo he comunicado a Soraya Masa, que precisamente ayer hablamos de otra paciente de la UHDAC a la que sus padres recientemente han pedido solo un centro de discapacidad y ya se lo van a asignar. Así que le pregunté cómo puede ser que a Juan Carlos que lleva un año esperando, que se han pedido varios para que tenga más posibilidades, no parece que se le vaya a conceder uno próximamente. La he informado de las fugas, del peligro que esto supone, de lo cansado que está de permanecer en estas unidades tan cerradas, de que pregunta a todo el mundo cuándo se va a su centro.... Seguimos...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2021-12-15','-Amalia : Hablo con Juanjo TS de la UHB donde se encuentra ingresada . Alta hospitalaria en unas horas . La Sra. quiere un traslado a otra R.M en Badajoz , se solicitará el mismo aunque no será inminente el traslado . Quiere recibir visitas de su hija Almudena ( tf. 633627412) . La llamo por tf. para concertar visita con sus 4 hijos a partir del dia 25 dic. que la madre haya cobrado . Se le pagará un taxi para que acuda . Se queda pte. que nos confirmará día .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-12-15','Ana: Correo de Paula, TO - CRR Plas (tocupacional.crrplasencia@grupo5.net) ayer a última hora: "Buenos días, nos ponemos en contacto con vosotros para comentaros la situación actual de Ceferino. • Continúa con acumulación de deudas en el CRR con personas de su entorno. • Aparecen conductas manipulativas respecto a su pareja, una persona también incapacitada, en relación a compras de objetos de interés para él, suponiendo un problema para esta persona, puesto que ella se endeuda con una amiga al no disponer del dinero para satisfacer las demandas de Ceferino. • Las presiones que ejerce sobre su pareja para que interceda económicamente están dañando la relación de ésta con una amiga y provocando situaciones en las que Ceferino se ha mostrado violento con un compañero del CRR que trataba de proteger los intereses de la compañera. • Por todo ello estamos realizando diversas intervenciones de cara a que salde la deuda y a tratar de evitar las dinámicas que establece con estas personas, así como informarnos acerca de la situación respecto a la solicitud de traslado que Ceferino realizó hace unos meses. Queríamos informaros para contar con vuestro apoyo para el abordaje de todo esto." ························· Mi respuesta: "Buenos días Paula, Ayer a última hora vino a hablar conmigo al respecto una compañera de la Sección de Salud Mental. No obstante, tengo pendiente hablarlo con la Jefa de Sección, que en este momento no está, y en cuanto podamos nos coordinamos con vosotras al respecto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-12-16','Ana: Llamo al C. Salud - Alcuéscar (927 38 42 10) para preguntar por el resultado de la PCR, la enfermera me confirma que es NEGATIVO. ····· A lo largo de la mañana me enviará el resultado por mail. ······························································································································································································· Llamo a Fernando Pecero (651 975 617), no obtengo respuesta. ········ Le envío un email para comunicárselo (aromasdecaridad@hotmail.com).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-12-16','miguel, recibo email de la abogada y le comunico a Damian lo que me indica: Buenos días Damián, en relación a su solicitud del estado del procedimiento de desahucio, le pregunté a la abogada quién me ha confirmado que el procedimiento está suspendido hasta que a los inquilinos les asignen desde el colegio de abogados uno de oficio, ya que lo habían solicitado (esos plazos suelen tardar, esperemos que lo nombren pronto). Una vez que tengan abogados el procedimiento esperemos sea rápido. Estos trámites no dependen ni de la abogada ni de la Comisión, sino del colegio de abogados que es quién nombra al abogado de oficio y del juzgado que una vez que haya abogado de oficio tendrá que dictar resolución judicial tras los trámites legales que correspondan','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PARRA'and apellido2='OCHOA'),'2021-12-16','aprobada la P. viudedad con efectos retroactivos 29/11/21','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-12-16','Ana: Respondo al correo remitido por Sandra, Técnico en Integración/Ocio y Tiempo libre de ASINDI (ocioytiempolibre.asindi@gmail.com): "Buenos días Sandra, Disculpa la demora en contestar. Desde la CTAEX se autoriza a coger el dinero estipulado del fondo de FELISA BRUNO SAAVEDRA para comprarle el regalo para el día de Reyes. ..." La cuantía estipulada oscila entorno a 15 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2021-12-16','Ana: Envío correo respuesta a Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "...Desde la CTAEX no tenemos inconveniente en que Félix Franco Jiménez viaje, como cada año, a pasar la Navidad con su familia en Madrid del 22 al 26-27 de Diciembre. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2021-12-16','Ana: En respuesta a los distintos correos correos de Aida con solicitudes varias, le respondo al correo desde el que escribe (leandro rodriguez >frayletin@hotmail.com): "Buenos días Aída, En primer lugar, decirte que sentimos mucho lo de tu perrito. En cuanto al resto de cuestiones, voy a proponer al Jefe de Sección económica lo que especifico a continuación: - Para el viaje a tu pueblo a visitar a tu familia los 100 € que planteas - Para regalos entre 80-100 € - Para el fisio, necesitamos que nos facilites presupuesto. Si es viable, entiendo que como anteriores ocasiones se aprobará. - Por último, en relación a los distintos desperfectos, solicitaré a Futuex que acudan a valorar y solicitar presupuestos para los arreglos correspondientes. Una vez se aprueben por el Jefe de sección económica se podrá proceder. Te confirmamos en cuanto sea posible de los dos primeros puntos y quedamos a la espera del presupuesto del Fisioterapeuta. Un saludo y buen día." ························· Envío correo al respecto a Toni - Futuex.','1');
