insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='SOLE'and apellido2='LATORRE'),'2021-12-16','Ana: reenvío a Estrella e Icíar, secc. ecca., el DNI escaneado que nos remiten desde el centro. ·········· Guardo el mismo en el expdte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2021-12-16','Ana: Correo de Miguel Ángel Ramirez, Director del CRR-CC (crr@grupociudadjardin.com) el día 9/12: "Buenos días Ana, te remito el informe de Feliciano de la consulta de especialista en Angiología y Cirugía Vascular que se realizó el día 2 de diciembre de 2021. Te comento que estamos observando en él un proceso degenerativo muy acusado sobre todo con respecto a perdidas de memoria y orientación. Feliciano ya ha cumplido 65 años y estamos valorando la posibilidad de realizar una solicitud de cambio de recursos ya que en el momento actual se le observa que está necesitando otro tipo de apoyos que en el CRR no se le puede ofrecer. Un cordial saludo." ·················· Mi respuesta: "... Gracias por la información. Siendo así la situación, entendemos que se solicite el cambio de recurso. Dado que tiene grado I de dependencia (vía por la que accedió a vuestro recurso), ¿qué os parece si solicitáis el Informes de Salud + Índice de Barthel a su médico de atención primaria y solicitamos revisión del grado y cambio de recurso? Ya me decís. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2021-12-17','miguel, Ana me remite de la trabajadora social Felisa presupuesto de tasación que cobraría la empresa tasadora por importe de 145,20€ . ******************************************************* Mi contestación a Ana y Alberto en el sentido de no pagar dicha tasación y aceptar el valor que propusieron en su día de 140.664,90 €, ya que a ella le pertenece el 100% del valor de usufructo que en su día se indicó en la escritura de disolución matrimonial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2021-12-17','miguel, Ana me remite de la trabajadora social Felisa presupuesto de tasación que cobraría la empresa tasadora por importe de 145,20€ . ******************************************************* Mi contestación a Ana y Alberto en el sentido de no pagar dicha tasación y aceptar el valor que propusieron en su día de 140.664,90 €, ya que a ella le pertenece el 100% del valor de usufructo que en su día se indicó en la escritura de disolución matrimonial. ********************************************* Pido a Ana que se haga con el titulo de adjudicación por divorcio','2');
