insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2021-12-17','TERESA RECIBO LLAMADA DE LA TS DE FUENLABRADA DE LO MONTES PARA INDICARME QUE ME ENVIA POR EMAIL INFORME DEL PSIQUIATRA PARA PODER INICIAR EL PROCESO DE RECUPERACION DE LA CAPACIDAD SE LO PASO A LOS JURIDICOS PARA QUE INICIEN EL PROCESO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-11-24','Ana: Correo de Toni-Futuex, con últimas incidencias: "... te envio a continuación los ultimos seguimimientos con Martin Dominguez Palencia, este lunes se le ha visto otra vez en el domicilio, está mas o menos igual, pero en una situación desde nuestro punto de vista, de absoluto abandono por parte de Salud mental, está sin seguimiento (poruqe la psiquiatara estaba de baja el dia que por fin le tocó y se habia conseguido que fuera) y no se le ha reprogramado la cita, sigue por ende, sin ningun tipo de tratamiento para su patología, que nos conste... o habiendo realizado abandono del mismo, si alguna vez lo tuvo. La compañera ha hablado en varias ocasiones con Pilar Martin,.. "que está pendiente de ser citado de nuevo" y poco mas. El hermano de Martin también ha estado en contacto con salud mental, por el momento sin exito tampco. ..." ········· *Guardo el correo completo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-12-16','Ana: Correo de Pilar Martín, ESM: "Ana, perdona, pero ahora le han cambiado la cita para el mismo día, ósea el 27 de diciembre con Juan Pedro Jimenez Cano a las 12,30. Un abrazo. ME DICE VIRGINIA QUE NO LE PUEDE ACOMPAÑAR POR VACACIONES, PERO ES MUY DIFICIL CUADRAR TAMBIÉN CON UN HUECO DEL PSIQUIATRA Y SUS VACACIONES."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2021-12-17','miguel, envío autorización al Plena Inclusión, Asociación Vera y lo remito a fiscalía','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-12-17','miguel, tras remitir las quejas de la vecina al Jzdo nº1 de Cáceres, me remiten por fax providencia indicando que el procedimiento de internamiento es de carácter no urgente. Y nos llama a Ana y a mí el secretario indicando que si consideramos que el internamiento debe de ser de carácter urgente que tendríamos que remitirnos al juzgado de guardia pero que no nos garantiza que allí se considerara su carácter urgente por lo que nos remite al protocolo habitual de actuación del 112 previo informe del médico. Le comentamos que es imposible hacernos con un informe médico pues ni acudió en el pasado ni lo hará voluntariamente y que por tanto no podemos hacer más pues tampoco somos curatela representativa (anterior tutela) y por tanto que nuestra curatela es únicamente en el ámbito patrimonial y por tanto no somos competentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2021-12-17','miguel, a petición de Teresa sobre la recuperación de capacidad del curatelado le remito email a Angel con copia a Tere: Hola Angel, he hablado con Tere porque el curatelado arriba indicado hace 3 años puso en manos de un abogado este asunto. Él quiere recuperar su capacidad completa, y tanto la Ts de su localidad como Teresa están de acuerdo en ello. La cuestión es que si lo proponemos nosotros tendríamos que enviarlo a Abogacía, mediante un informe social que sirviera de propuesta? O bien hay que buscarle un nuevo abogado, lógicamente habría previamente que cesar en la representación al abogado que él en su día designó para que se lo tramitara (que no sabemos quién es) En cuanto al informe social para solicitar dicha recuperación de su capacidad habrás de verlo esta semana próxima con Tere, pues me comenta que algo habló y yo lo desconozco. Si necesitas que vaya tramitando algo de este u otros asuntos envíame emails para que la semana del 27 los tramite.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-12-16','miguel, remito al juzgado contestación a la providencia donde nos preguntaban por el recurso que se le va a dar a la tutelada. Le contesto vía fax al jzdo nº1 Coria donde desde la Sección de Salud Mental DUE(Unidad de Programas Asistenciales) nos comunican que la tutelada ha sido derivada por el ESM de Coria para acceso a recurso Residencial de Salud Mental (CRR) por emergencia social, teniendo entrada de la derivación el el Sepad a fecha de 26-11-21, estando pendiente de valoración por al Comisión de Valoración de recursos de Salud Mental. Faltan algunos datos en el expediente para la valoración que ya están tramitando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2021-12-17','TERESA A partir de enero la asignación de Manuel hay que hacerla por transferencia bancaria a su hermana pues está viviendo con ella y se va a encargar de administrarle el dinero Hay que anular al autorización bancaria que tiene actualmente que es de 250€ DATOS ROSA DOMINGUEZ MARTIN N CUENTA: ES45 210043 7431 0100206946 CAIXABAN CANTIDAD: 250€ MENSUALES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2021-12-17','Amalia : Buenos días , según las averiguaciones que he hecho en Seguridad Social , me confirman que su Pensión de Incapacidad Absoluta Permanente sigue en alta . Efectivamente el mes de octubre y noviembre con la extra está impagado . Ha habido un cambio en el Nº de cuenta ,yo no lo he realizado , confirmarme que desde esa sección no se haya indicado otra entidad bancaria . Hay un cambio de variaciones , y está firmado por él , o pudiera ser falsificado ... Ya me decís para intentar seguir averiguando . De momento a él aunque llame no se le puede decir nada , está en trámites de separación de su mujer con la vive . Buen finde. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2021-12-17','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería informaros que estamos organizando, junto con las familias, la salida a casa. La verdad es que lo necesitan todos un poco. Se irán algunos y pocos días pero lo suficiente para recargar las pilas y sentir más cerca a la familia. Los hermanos Rodriguez Alcántara irían a ver a uno de sus hermanos a Plasencia unas horas el día 2. Nos rellenarán ellos la solicitud con el compromiso de guardar las medidas preventivas. Hace tiempo que no se ven y a penas conocen a su sobrina. Necesitan cambiar de entorno aunque sea unas horas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2021-12-17','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería informaros que estamos organizando, junto con las familias, la salida a casa. La verdad es que lo necesitan todos un poco. Se irán algunos y pocos días pero lo suficiente para recargar las pilas y sentir más cerca a la familia. Los hermanos Rodriguez Alcántara irían a ver a uno de sus hermanos a Plasencia unas horas el día 2. Nos rellenarán ellos la solicitud con el compromiso de guardar las medidas preventivas. Hace tiempo que no se ven y a penas conocen a su sobrina. Necesitan cambiar de entorno aunque sea unas horas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-12-17','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería informaros que estamos organizando, junto con las familias, la salida a casa. La verdad es que lo necesitan todos un poco. Se irán algunos y pocos días pero lo suficiente para recargar las pilas y sentir más cerca a la familia. ... Justo y Roberto Hernández Castaño se irán desde el 23 al 27 de diciembre. Han pasado de ir cada 15 días a llevar varios meses si poder ir a casa. Lo organizamos con su madre y con su hermana."','2');
