insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2021-12-17','Ana: Se acepta el presupuesto (50%) remitido a Alberto, jefe secc. ecca., María, Aux. Admvo. se encargará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2021-12-16','Ana: En respuesta a los distintos correos correos de Aida con solicitudes varias, le respondo al correo desde el que escribe (leandro rodriguez >frayletin@hotmail.com): "Buenos días Aída, En primer lugar, decirte que sentimos mucho lo de tu perrito. En cuanto al resto de cuestiones, voy a proponer al Jefe de Sección económica lo que especifico a continuación: - Para el viaje a tu pueblo a visitar a tu familia los 100 € que planteas - Para regalos entre 80-100 € - Para el fisio, necesitamos que nos facilites presupuesto. Si es viable, entiendo que como anteriores ocasiones se aprobará. - Por último, en relación a los distintos desperfectos, solicitaré a Futuex que acudan a valorar y solicitar presupuestos para los arreglos correspondientes. Una vez se aprueben por el Jefe de sección económica se podrá proceder. Te confirmamos en cuanto sea posible de los dos primeros puntos y quedamos a la espera del presupuesto del Fisioterapeuta. Un saludo y buen día." ························· Envío correo al respecto a Toni - Futuex y a Alberto, Jefe de Sección Ecca.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2021-12-20','Ana: Alberto, jefe secc. ecca., aprueba retirada de efectivo de 180 € (100€ para ir de visita al pueblo + 80€ para regalos a sus familiares). *Estrella, aux. admvo., se lo comunicará a Aída.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2021-12-16','Ana: En respuesta a los distintos correos correos de Aida con solicitudes varias, le respondo al correo desde el que escribe (leandro rodriguez: frayletin@hotmail.com): "Buenos días Aída, En primer lugar, decirte que sentimos mucho lo de tu perrito. En cuanto al resto de cuestiones, voy a proponer al Jefe de Sección económica lo que especifico a continuación: - Para el viaje a tu pueblo a visitar a tu familia los 100 € que planteas - Para regalos entre 80-100 € - Para el fisio, necesitamos que nos facilites presupuesto. Si es viable, entiendo que como anteriores ocasiones se aprobará. - Por último, en relación a los distintos desperfectos, solicitaré a Futuex que acudan a valorar y solicitar presupuestos para los arreglos correspondientes. Una vez se aprueben por el Jefe de sección económica se podrá proceder. Te confirmamos en cuanto sea posible de los dos primeros puntos y quedamos a la espera del presupuesto del Fisioterapeuta. Un saludo y buen día." ························· Envío correo al respecto a Toni - Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-12-16','Ana: Entrego a Julio, secc. soc. tanto la solicitud de Ingreso en Centro Residencial de Mayores, por emergencia social (vía decreto), como solicitud de valoración de la situación de dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-12-20','Ana: Llamada de Pedro Sánchez, TS de la Gerencia Territorial, tienen la solicitud de Emilia, me solicita que le remitamos la Cartilla de Vacunación (Cóvid) y el nº cuenta. Tenemos que solicitar que le programen ya la PCR. ···························································································································································································· Llamo al C. Salud, a José Mª Hdez., MAP de Emilia (70809 / jose.hernandezd@salud-juntaex.es): me enviará el Cdo. de Vacunación. La PCR puede ir a hacérsela cualquier día de 8.30 a 9.00 h. ···················· *Tras contactar con Toni-Futuex, me confirma por mail, que podrán acompañar mañana a Emilia a la PCR y el día 23 también podrán apoyar para el ingreso. ············· Se lo comunico a Carmen, TS SSASB. ································································································································································································· Llamo a Amparo, Res. El Cuartillo (927 00 52 80): Le enviaré los documentos necesarios y pediré a Futuex que marque la ropa que lleve puesto con un rotulador indeleble, el resto de ropa la lavarán y marcarán en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-12-20','Ana: Tras haberlo hablado el viernes con Alberto, envío correo a Estrella Durán, TS CSS Plas. (estrella.duranc@salud-juntaex.es): "Buenos días Estrella, De cara a la salida de ISABEL CANO BLÁZQUEZ el miércoles, ¿sería posible, como en la vez anterior, le facilitaseis tanto el tabaco como el dinero para llevarlo a casa? Entendemos que debe ser los 40€ habituales para que la recojan y la lleven de vuelta, unos 20-30 € para que le compre un regalo a su sobrino para reyes, como es su deseo, y otros 60€ para gastos de bolsillo. Decidme si lo veis bien y por favor, si es posible, encargaros de la gestión y confirmárnoslo. Gracias y buena mañana!" ················· *Estrella, TS CSS, confirma, que con nuestra autorización, retirarán mañana 130 € para que Isabel se lleve a casa el miércoles 22.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-12-20','TERESA ENVIO ESCRITO DE ALEGACIONES EN EL QUE NOS RECLAMAN UN COBRO INDEBIDO EL CUAL YA ESTA PAGADO','2');
