insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-12-20','Ana: Alberto aprueba presupuesto para la salida con la familia de Cristofer. ········ Se lo comunico a Ana Amor, Placeat.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-12-20','TERESA RECIBO EMAIL Eulalia Granadero Fuentes Arquitecto Técnico Tfno: 924332092 Servicio de Adjudicación y Mantenimiento Dirección General de Vivienda Consejería de Movilidad, Transporte y Vivienda JUNTA DE EXTREMADURA Buenos días Teresa, me ha facilitado su correo la compañera Anto, la trabajadora social de Almendralejo. Soy Eulalia a técnico del servicio de Adjudicación y Mantenimiento y tenemos a una inquilina (Touria Chetouani) perjudicada en C/Federico García Lorca, nº 6, 1º-A, por una fuga de la vivienda situada en la parte superior, C/Federico García Lorca, nº 6, 2º-A. Me ha comentado Anto que la inquilina de la vivienda que provoca la fuga de agua es una persona incapacitada y que al día de hoy no se encuentra viviendo en la vivienda, que se le ha cambiado la cerradura de la puerta principal y que se os facilitará a vosotros las llaves. Comentaros si existe alguna posibilidad de entrar en la vivienda junto con personal de la Comisión Tutelar para poder llevar a cabo la reparación. Espero su respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2021-12-20','Ana: correo de Paula, TO CRR, Plas (tocupacional.crrplasencia@grupo5.net): "Buenos días, quería informaros de que Mª Angeles tiene previsto ir a casa por Navidad del 23 al 27. Hemos visto y entrenado medidas generales para la prevención de Covid (mascarillas, distancia de seguridad, gel hidroalcoholico, etc.). Y nos hemos coordinado con su padre para que realice los apoyos pertinentes durante esos días. Si necesitáis alguna información complementaria o pensáis que debemos hacer algún cambio no dudéis en llamarnos. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2021-12-17','Ana: Correo de Teresa, TS Novaforma (trabajadorasocial.novaforma@gmail.com): "Buenas tardes, os informo de que Fermín García esta de nuevo ingresado en psiquiatría, os voy contando como va la evolución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-12-20','Ana: Conversación con Clara, TS C. Salud (53107): Juan solicita un extra de 200€ para la navidades (Nochebuena, Nochevieja, su cumpleaños y Reyes), además no quiere ir el día 29 a la consulta de Psiquiatría, ESM. ················ Envío un mail a Alberto, Secc. Ecca., consultando si autoriza el extra. ·············· Llamo a Pilar Martín, TS ESM (54612) varias veces, pero no obtengo respuesta. ············· Llamo a centralita ESM (54698): varias veces, tampoco obtengo respuesta. ······························································································································ Envío correo-e a Pilar Martín: "Buenas tardes Pilar, No sé si estarás ya de vacaciones, pues he intentado contactar contigo por teléfono y no obtengo respuesta. En relación a Juan Chamorro Holguín, dice que no va a acudir a su cita de Psiquiatría programada para el día 29 a las 12, pues dice que “no está para viajar”… pide que se le haga mediante video conferencia o telefónicamente. He llamado también a centralita para que me pasen con el Dr. Jiménez Cano, pero tampoco obtengo respuesta, si está trabajando por favor, trasládale la consulta al doctor o facilítame su contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-12-16','Ana: Correo de Clara, TS C.S.: "Hoy ha venido Juan, refiere que ha recibido la cita el día 29 a las 12, pero que no va a ir, no está para viajar, que por video conferencia o telefónicamente, que se lo comunique a la T.S de la CTA." ······· Lo hablaré con el ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-12-21','kike ,llega Providencia del Juzgado indicando que dicho Juzgado han remitido oficio al Instituto de Medicina Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-12-21','Ana: Se aprueba un extra de 100€ para Navidad, tendrá la visita de su hijo. ·········· Lo comunico a Felisi, y le reitero, tal y como pide Alberto, Jefe secc. ecca., que no pidan más extras en los próximos meses porque no se les va a conceder.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2021-12-21','Comentarte que Antonio F. M el viernes de madrugada no estaba en el centro y no contestaba al teléfono. Javier, Director, interpuso denuncia. Finalmente llegó al CRR el sábado sobre las 20h, acompañado de un amigo suyo que refería haberle encontrado en la calle sin calzado y con algunas heridas en la cara; Antonio refirió haber caído por un cañaveral y perder la consciencia. Se le llevó al Hospital y, en estos momentos, está ingresado en UHB. La Policía ha pedido que los partes de lesiones se aporten en Comisaría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2021-12-21','TERESA Adjunto parte de incidencia ocurrido esta madrugada y foto. Actualmente está ingresado en la Unidad de de Hospitalización Breve del Hospital de Psiquiatría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2021-12-20','TERESA Hemos visto en la cuenta de Ramón se están cargando recibos de Legalitas, Jazztel y Orange. A mí en ningún momento me ha comunicado que quería contratar nada de esto. Vamos a devolver todos lo recibos ya que son nulos los contratos que haya formalizado, a ver que puede averiguar Susana al respecto si esto es cosa de él o está otra persona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2021-12-20','TERESA Hemos estado hablando con Agustín, para organizar una salida de un día para visitar a su madre en su localidad. Su madre está residiendo en los pisos tutelados, y recibe visitas allí, ya no pasa día en su domicilio. Habíamos pensado, que Agustín fuera un día a visitarla a los pisos, ya que se aproxima Navidad, acompañado con un cuidador externo. Sería irse por la mañana, realizar la visita y regresar al centro. Si lo veis bien, me decís, y pregunto por el precio del taxi y cuanto costaría el acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2021-12-21','-Amalia , envio a Miguel , juridico , toda la información para solicitar RAE. Cuando me envie copia de la solicitud judicial + I. social de Ap3 + Acta de la reuníon ,haré la solitud RAE a Manuela. Buenos días , te envío informe social de la TS de Aprosuba 3 y el acta de la reunión en la que yo también estuve para solicitar plaza residencial para Pilar . Te anoto unos breves apuntes para añadir a tu petición , para que puedas justificar la misma : Pilar reside junto a su madre y a la pareja de ésta , Manuel , en una vivienda propiedad de éste en la pedanía de Balboa . Desde allí , acude de lunes a viernes , al Centro Ocupacional de Aprosuba 3 en Badajoz , en un transporte de la entidad . Se va sobre las 8.00 de la mañana y acude al domicilio por la tarde , pasando en éste las tardes y fines de semana. Ella está contenta y es bien atendida en sus necesidades básicas tanto por la madre como por Manuel . Sin embargo , la pareja pasa por malos momentos en su relación matrimonial . Manuel las ha echado de la casa , y quieren separarse . Su madre , también con discapacidad , no tiene otra vivienda donde poder irse a vivir las dos , ni las capacidades parentales necesarias para ejercer sóla los cuidados de Pilar. Es por ello , que se hace necesario , solicitar autorización judicial para que Pilar pueda ingresar en un centro residencial de discapacidad donde pueda ser atendida y se garantice un sitio dónde poder vivir y en el que se atiendan todas sus necesidades . Ella preferiría seguir como está actualmente en Centro Ocupacional y regresando a la casa por las tardes . Sin embargo , cuando la pareja haga efectiva la separación no tendría casa dónde poder vivir . Desconocemos qué alternativas tendría la madre , por el momento , ni ella sabe dónde podría ir a vivir . Tiene una prestación de baja cuantía que difícilmente le daría para alquilar una vivienda y poder llevar una vida independiente y autónoma . Tiene otro hijo , que está viviendo fuera de Extremadura , en la casa de un familiar y está empezando a trabajar allí . Ella no ha planteado la posibilidad de ir a vivir con él. Pilar presenta una discapacidad con un grado del 72% por discapacidad intelectual . Al llevar años acudiendo a Centro Ocupacional , creemos que su adaptación al mismo tipo de centros pero pernoctando en él sería positiva . Una vez que su madre estabilizara su situación , podría pasar con ella los fines de semana y periodos vacacionales. Cuando ya tengas hecha esta solicitud judicial , me das una copia para que yo pueda ir solicitando plaza residencial de discapacidad en el SEPAD . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-12-21','Ana: Tras llamar a la Jefa de Sala del 112 (924 31 02 04), remito por mail (112@juntaex.es) el "fax" y resto de documentación pertinente, con las aclaraciones oportunas en el texto del correo. ···················································································································································································································································································································· Llamada de Rebeca Gallego, sobrina de Emilia (606 205 733): *Preparará una bolsa con ropa de su madre que pueda servirle a Emilia (Camisones, bata y demás...) y se la entregará a Gloria, Ed. Futuex. *Por otra parte, me informa que le ha facilitado mi número a Jesús, otro hijo de Emilia. ·············· Facilito su contacto a Futuex ·············································································································································································································· Llamada de Jesús Gallego Gutiérrez, el otro hijo de Emilia (643 063 690), en la CTAEX desconocíamos su existencia. No tiene relación con su hermano y por evitar problemas también ha pedido contacto con su madre. **Solicita, que a ser posible, una vez cubiertas las necesidades de su madre, se mantenga los suministros de su vivienda para que su hermano pueda seguir residiendo en ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-12-21','Ana: Alberto aprueba el extra de 200€ para Navidades + cumpleaños. ············································································ Llamo a centralita ESM (54698), me pasan con el Dr. Juan Pedro Jiménez Cano: ante la negativa de Juan de acudir a su cita el próximo día 29, dice que las únicas opciones que ve es negociar con él nueva fecha y pedirle nueva cita y hablar con su MAP en relación al control de la medicación, sobre todo inyectable. En el caso de que no se ponga alguna dosis, tendrían que activar el 112 desde el centro de salud para ingreso. *Según afirma no es necesario que él anote nada en la historia clínica. *"Lo importante es la inyección" asegura, y añade "psiquiátricamente poco más se puede hacer". ·································································································································· Llamo a Clara, TS C. Salud (hoy en Berzocana: 52705): no entiende que la poca coordinación entre los médicos de atención primaria y los especialistas... ········································································ Hablo con Toni Futuex, le informo del extra autorizado y de la conversación con el Psiquiatra. ···························································································································································································· Llamo a Juan (633 391 891) en varias ocasiones, pero no atiende las llamadas. Le dejo un mensaje en el buzón de voz y pido que me devuelva la llamada. ······· Vuelvo a intentarlo más tarde múltiples veces y no coge la llamada. ················································································ Envío correo a Toni-Futuex, y Clara, TS C.S. (isabel.garcial@salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2021-12-22','TERESA Los padres de los hermanos de Carmen, solicitan autorización para llevársela a sus domicilios durante el periodo 23 de diciembre – 3 de Enero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2021-12-20','TERESA Solicitamos autorización para estancia en domicilio familiar durante el periodo 23 diciembre-7 enero 2022. MªAntonia Fernández Salguero pide estar esa temporada en casa de su tía en Zafra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2021-12-20','TERESA Antonio Jesús va a pasar la Nochebuena con la familia colaboradora de Malpartida de Plasencia del día 24 al 28. Es la familia con la que suele pasar tiempo en vacaciones. Nosotros le acercamos a Mérida y allí le recogerá Elisa. Necesita ropa nueva, que vaya mono.jiji Si os parece bien se la compramos y os pasamos la factura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2021-12-21','Comentarte, de Alonso Ortiz Germán, ingresado desde el 01 de diciembre de 2021 en el hospital Universitario de Badajoz, como sabes. Fue intervenido de obstrucción de asas intestinales, de la que se está recuperando satisfactoriamente. Pero, durante su evolución ha sufrido una complicación respiratoria leve, así como detectada anemia, para la cual han tenido que realizarle transfusión de dos bolsas de sangre. En el momento actual, se encuentra estable, con dieta normalizada, con sonda vesical de nuevo puesta, ya que por parte del equipo médico, recomiendan que sea intervenido, lo antes posible de su problema de hiperplasia de próstata, pues está afectando al funcionamiento renal. Está prevista posible alta entre mañana miércoles 22 de diciembre o el jueves 23, a la espera de ser citado para la intervención. Su auxiliar (Esther) ya ha informado que los trámites de autorización para consentimiento ya fueron entregados en su momento y que incluso, han recibido una llamada la semana pasada del servicio de cirugía para saber si no habría inconveniente en ser derivado para la intervención, en el hospital Quirón Salud (Clideba) ante la lista de espera que hay en el Universitario. --','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-12-01','Ana: Mayte y yo visitamos el C.R. Cervantes: La directora del centro solicita con vehemencia el cambio de centro de Mª Luisa, ya han agotado toda posible intervención con ella y consideran que sólo provoca perjuicios a otros residentes, incluso los familiares están ya formulando quejas al respecto. ·········· Nos facilitan el informe que remitieron en su día a la Gerencia Territorial, Mayores. ································ **Hablamos con Mª Luisa sobre la necesidad de cambiar su actitud y comportamiento y le explicamos también la necesidad de cambiar de centro. *Ella dice que no quiere irse, a no ser que el traslado sea a Don Benito o a Plasencia (Sabemos que actualmente su hija reside en esta localidad, por lo que sería contraproducente). ································ Toni, TS, dice que intentarán hablar con ella sobre otras alternativas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-12-21','Ana: Llamo a Toni, TS CR Cervantes (22270), pero está de vacaciones y me atiende Minerva: Mañana intentará, junto a la Psicóloga, hablar con Mª Luisa sobre otras opciones de recursos. Le propondrán centros de la provincia de Badajoz, por si le resulta más atractivo al ser ella de Don Benito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-12-20','Ana: Recibimos resolución aprobatoria de PNC con complemento a 3ª persona (402,80 + 201,40) = 604,20 € ··········· Líquido a percibir en el primer pago: 1010,60 €','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-12-22','TERESA 2021/12/22: TERE/ALBERTO: VISITA HERMANO TAXI: 238 € IDA/VUELTA. CENTRO PREGUNTA CUANTAS VECES PUEDE REALIZAR ESTE VIAJE: - AL CENTRO SE LE TRASLADA QUE COMO MÁXIMO 1 VEZ AL MES (TERE) - EN 6 MESES REVISAMOS GASTOS PARA VER SI PUEDE SEGUIR CON ESE NIVEL DE GASTOS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-12-22','Ana: José María Hdez, MAP, me remite el resultado NEGATIVO de la PCR, realizada ayer a Emilia. ···················· Se lo remito a Amparo, Directora de la Res. El Cuartillo (rm.elcuartillo@salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2021-12-22','Concretado con el centro que entre hoy y mañana puede retirar los 60€. la TS va a realizar averiguaciones tanto del copago de la plaza , y si están incluyendo las P. extras ,como el tema del trabajo . Me dice que no me lo han comunicado porque ha sido breve .. increíble . Y obviamente no han comunicado nada a PNC . He pedido a la Dtra. contratos , cuantía .. y el resto de documentación , me encargo yo de las gestiones de comunicación a PNC . Nos lo pasarán en unos días , hay bastante desorganización. Cuando tenga toda la información , te lo paso organizado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2022-10-31','-Amalia , escribo a Laura de Aexpainba : Te comento por aquí un par de cosas : Tengo que aclarar cuales son sus ingresos por PNC actualmente . Los tiene suspendidos por completo por el contrato laboral que tenía anteriormente ? en su extracto bancario aparece el cargo de TGSS de 721,70€ , a qué corresponden estos ingresos ? a rendimiento laboral ? cuales van a ser los ingresos con el nuevo contrato laboral ? para poder calcular otro presupuesto . Hablamos también sobre ésto , no puedo contactar con vosotros , igual has cogido puente . El nuevo contrato laboral tiene que reenviarlo Juan José a PNC , no está curatelado en esa esfera. Si no lo veis posible lo hacemos desde la CTAEX , pero no es lo correcto y nos pueden poner pegas . un saludo','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-12-22','TERESA ENVIO ACEPTACION PIA A Dependencia III ZAFRA SEPAD A11030430','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2021-12-22','TERESA 643846445','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2021-12-22','Ana: En relación a la venta del usufructo de la vivienda, tras hablar con Felisa Custodio, TS CAMF, envío el siguiente correo a Alberto, secc. ecca., y Miguel, Asesor Jurídico: "Buenas Alberto y Miguel, Tras haber hablado con Felisa, TS CAMF-Alcuéscar, rescato y os envío este presupuesto de para tasación de la vivienda por una inmobiliaria de Alcuéscar. Yo lo veo razonable, si se puede asumir, por mi parte ok, para no demorar mucho más este asunto. En cuanto a lo que pedía Miguel, dice que ya lo envió hace mucho tiempo, a petición de los jurídicos también, no obstante, me lo reenviará de nuevo para que os lo vuelva a pasar. Por último, en relación a la deuda, no me saben decir, como ella ve la cartilla con la curatelada, también se ha extrañado de que no le hayan vuelto a pasar nada desde agosto, pues cree recordar que aún debía más de 2.000 €, llamaré yo a la Seguridad Social, a ver si puedo averiguar algo. Ya me decís lo de la tasación. Seguimos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-12-22','Ana: Juan Carlos ha protagonizado recientemente varias "fugas" del centro. A su regreso una de las veces, dice que se va porque no le sacan... se plantea, también con mediación de Soraya Masa con el CSS, la posibilidad de contratar un servicio de acompañamiento para pasear por Plasencia, mínimo 1 día/semana, hasta que le concedan plaza en C. Discapacidad. ·················· Llamo a Estrella Durán, TS del CSS, con este planteamiento. Ella misma llamará a una empresa que conoce de Plasencia. ······························································································································································································ Llamada de Juan Carlos, hoy está muy contento, han tenido la visita en el centro de "Papá Noel" y le ha regalado una colonia. Además había mucha decoración y luces que le han gustado. Su cumpleaños fue el día 20 y le compraron una tarta. En Nochebuena y Navidad tendrán comidas especiales y dulces navideños sin azúcar. *Vuelve a preguntar cuándo se irá a un centro. ································································································································································································· Estrella Durán me facilita un contacto de una empresa con la que acaba de hablar. Le envío un correo a Álvaro, Empresa EUEXIA (ameuexia@gmail.com): "Buenos días Álvaro, Me ha facilitado Estrella Duran, Trabajadora Social del Centro Sociosanitario de Plasencia, que acaba de hablar con usted, su contacto. Queríamos solicitar un presupuesto para un acompañamiento para salir a pasear al Centro de Plasencia a D. Juan Carlos Ruíz García, tutelado por la Comisión Tutelar de Adultos de Extremadura y residente en el Centro Sociosanitario. La idea sería que le recogieran en el propio Centro Sociosanitario y fueran con él al centro a pasear/tomar un café, al menos una vez a la semana con una duración de 2 horas. En función del presupuesto y de sus posibilidades económicas se podría ampliar a algunos días más, si fuera viable. El presupuesto debe ir a nombre del propio tutelado, al igual que las facturas si finalmente se contratara el servicio. Ante cualquier cuestión, no dude en contactar. Gracias por su atención y un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-12-22','Ana: Llamo a Juan (633 391 891) varias veces, pero siempre salta el buzón de voz. Le dejo un mensaje la primera vez y sigo intentándolo sin éxito. ············· Lo comunico a Toni-Futuez y Clara, TS C.Salud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-12-17','Ana: Correo de Toni Futuex: "Buenas tardes, al respecto de Martin, adjuntamos novedades de Martín de esta semana y te paso tb el video que paso la vecina apenas se ve pero se escucha perfectamente como cae agua ventana abajo (no se si son estas las imagenes de las que hablabas) , lo de la cita a ver si accede a que se le acompañe hemos pensado decirle el lunes que se le va a presentar a mi compañera por si necesita algo durante el periodo de vacaciones de Virginia y entrarle por ahí porque con el hay q ir con pies de plomo que tiene poca paciencia y empieza a estar harto de tanto seguimiento. (es complicadisimo llegar a el) y lo de localizar al hermano tambien lo podemos tantear. ..." el correo está guardado en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-12-22','Ana: Coordinación con Minerva, TS CR Cervantes: han hablado c con Mª Luisa y le han entregado un listado de centros de BA, le han informado que desde la CTAEX queremos tener en cuenta su opinión a la hora de solicitar nuevo centro. Dice que se lo va a pensar y mañana me enviarán un correo con la respuesta que dé.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2021-12-22','TERE: OK A LA CANCELACIÓN DEL REINTEGRO PERMANENTE Y ALTA DE LA TRANSFERENCIA MANUTENCIÓN A HERMANA TUTELADO A PARTIR 01/01/2022','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2021-12-22','Buenos días, hablado con Laura (educadora social), me indica que el dinero se lo paga el tutelado en mano a la autoescuela, que hay que mandarle 260€ de atrasos, más 40€ por mes de autoescuela, Entonces ahora se le va a hacer un reintegro extra de 300€ para pueda pagar atrasos y el mes de diciembre. Y posteriormente 40 € para sacar entre los días 1 y 5 de cada mes, siempre hablando antes con Laura, para saber si continua en autoescuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2021-12-22','Buenos días, hablado con Laura (educadora social), me indica que el dinero se lo paga el tutelado en mano a la autoescuela, que hay que mandarle 260€ de atrasos, más 40€ por mes de autoescuela, Entonces ahora se le va a hacer un reintegro extra de 300€ para pueda pagar atrasos y el mes de diciembre. Y posteriormente 40 € para sacar entre los días 1 y 5 de cada mes, siempre hablando antes con Laura, para saber si continua en autoescuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-12-22','Amalia : Hablo con Jackeline , va a enviar un email a ctutelar indicando su Nº Cuenta para abonarle los 100€ por la limpieza de la vivienda . Le pregunto por su situación con Mercedes , hace mucho tiempo que no va a limpiar su casa . No habla con ella . Dejó de ir hace mucho tiempo pq había días que iba y no le abría la puerta , otras veces la llamaba solo para una hora... Trabaja en casa de su amiga Ñeña , el otro día se presentó allí y le dijo que no se iba de la casa . La ven mal .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2021-12-23','TERESA 1. CONTRATO TELEFONICOS Y LEGALITAS ayer se llamó por teléfono a Ramón González Hernández para preguntarle si él había contratado a Jazztel para que le pusiera internet en casa, porque le estaban cobrando facturas en su cuenta. Ramón contesta que no, que él no tiene ni idea y tampoco ha hablado con ellos. Se le pregunta también por Legalitas, ya que también están intentando pasarle facturas en su cuenta, y la respuesta de Ramón es la misma, que él no ha hecho nada al respecto ni ha hablado con ellos. Sobre el caso de Orange, se recuerda que en el mes de Julio del presente año, se conversó con Ramón sobre la empresa Orange, porque él les llamó para que le pusieran internet en casa, aunque a los dos días se arrepintió y ya no quería contratarlos. El tutelado cuenta que ha llamado a Orange el miércoles 14 de Julio y ha contratado internet con fijo para su casa y una línea móvil por 68€ al mes, aunque ahora hay una promoción de tres meses al 50% por valor de 34€ al mes. . El contrato se ha hecho efectivo porque Ramón realizó una grabación de voz para formalizarlo, no fue necesario firmar nada en papel. El agente confirma que la cuota asciende a 68€ al mes, con una promoción de tres meses a 34€, y está domiciliada en la cuenta de Ramón Se explica, por encima, la situación del tutelado al agente y éste comenta que dadas las circunstancias de Ramón, se podría llamar al 656 00 14 70 y pedir una desestimación del contrato ya que Ramón es una persona incapacitada y no puede contratar internet sin consultar con sus tutores Se ha hablado con Ramón y se le ha explicado que él no puede gestionar este tipo de contratos de manera unilateral, ya que él no puede disponer de su dinero libremente. Ramón comenta que él pensaba que podía pagar los 30€ de su dinero de la asignación y alega que le han engañado por lo que pide que se cancele el contrato. 2. EMBARGO OAR Ramón recibe una carta de Ibercaja, en uno de los documentos de la carta, explica que se le va a embargar la cantidad de 140€ por el OAR. Se habla con un agente del OAR y se pregunta por este embargo de 140€ en la cuenta de Ramón y comentan que está pendiente el pago de un impuesto de rodaje de una moto Derbi Variant y además el tutelado tiene una multa por no llevar mascarilla. Cuando se le explica todo esto a Ramón, él entiende que son cosas ciertas y que hay que pagarlas y no vuelve a hablar del tema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2021-12-23','TERESA EMAIL DE P.I. ALEXANDRA Te comunico que el lunes día 20 no vino al centro, el motivo según ella fue porque estaba muy cansada. Hoy ha venido para recoger las gafas de la óptica y para retirar del banco su asignación extra de navidad (100€), para realizar esas dos gestiones se le ha prestado apoyo desde el centro. Cuando ha llegado, nos ha comunicado que se tenía que ir y que venían a recogerla unos amigos. Primero nos ha contado que tenía cita en el médico en Peñalsordo, tras comprobar que eso no era cierto y ofrecerle apoyo para acompañarla al médico, nos ha dicho que tenía que irse a realizar compras, finalmente hablando con la psicóloga le ha contado que en realidad es su novio, que no quiere que comparta el transporte con otro chico usuario de nuestro servicio, ya que por lo que ella cuenta su novio es muy celoso. También le ha comentado que no va a venir más. Conclusión: A las 13:15h aproximadamente, aprovechando el cambio de actividad (ya que a esa hora suben todos los usuarios al comedor), ha desaparecido. Se ha ido, no sabemos con quién ni cómo. Te lo comunico para que quede constancia, valoréis la situación y toméis las medidas que creáis oportunas. Por cierto, ya he solicitado al médico de Marta la PCR para que se la hagan el lunes día 3 de enero en Peñalsordo, para que pueda incorporarse el día 5 tras las vacaciones de navidad. Ella ya lo sabe, ya te contaré finalmente si va hacérsela o no.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='CABEZAS'and apellido2='MAZON'),'2021-12-23','TERESA RECIBO LLAMADA DE CONCHI TS DEL CENTRO PENITENCIARO DE MALLORCA 971224229 DONDE RESIDE EL HIJO DE ROSARIO MANIFIESTA EL INTERES DE SU HIJO PARA HABLAR CON SU MADRE Y NOS PIDE AUTORIZACION PARA ELLO Tras conversación con Sor Arlis que es la persona que se encarga de Rosario, acordamos probar con una llamada para valorar cómo reacciona la madre. Las llamadas están autorizas siempre y cuando transcurran con normalidad y no generen en Rosario ningún perjuicio para su salud mental y emocional. En el caso que lo genere o que ella manifieste que no desea hablar con su hijo se nos comunicaría a la comisión por este medio para desautorizar dichas llamadas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2021-12-27','miguel, recibimos por email ctutelar preguntando por liberbank si les autorizamos a facilitar información (movimientos de cuenta) al que dice ser su abogado. Le contesto: Buenos días, en referencia a la consulta que nos realizan de entregar documentación al que dice ser abogado de la curatelada arriba indicada, entendemos que no debe facilitársele esa documentación por las siguientes razones: 1) Sus poderes de representación no han sido acreditados, y por tanto no demuestra representarla 2) Conforme a Auto referido en el testimonio judicial adjunto, desde esta Comisión Tutelar de Adultos se ejerce la curatela patrimonial de esta curatelada. 3) Que el solicitante deberá solicitar cualquier información a través del Juzgado, no pudiendo facilitarse información al mismo en base a la Ley orgánica de Protección de Datos 3/2018 de 5 de diciembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-12-27','miguel, no pudo firmarse la renuncia de la herencia de la madre ya que había que haber aportado los originales de los certificados de defunción y a la notaria de Don Benito se le olvidó decirnoslo. Remito email a dicha notaria adjuntando la renuncia de herencia de su padre, certificado de nacimiento de Juan Carlos para acreditar la Curatela de la Ctaex, testimonio de incapacitación y nombramiento, testimonio de aceptación del cargo, últimas voluntades de su madre Rosa. La indico que no tengo el original del certificado de defunción de la madre Rosa Galan Merino, porque en su día lo remitimos al juzgado nº1 de Mérida para la rendición final de cuentas. ********************************************************* He solicitado hoy por email al registro civil de Mérida dicho certificado original de defunción, en cuanto lo tenga pido a la notaria día y hora para firmar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-12-28','Ana: Envío correo-e a Paloma Castellano, TS Res. El Cuartillo (paloma.castellano@salud-juntaex.es) en respuesta a su correo: "Buenos días Paloma, Te facilito los informes de que disponemos, pensaba que os los facilitaban para el ingreso, son los mismos que remitimos a la Gerencia Territorial con la Solicitud de Ingreso Involuntario: - Informe Social – Modelo Solicitud de Ingreso (Decreto) - Informe de la Policía Local - Informe Médico – Anexo solicitud de Ingreso (Decreto) La sentencia de Incapacitación y la autorización judicial de internamiento involuntario, se la remití a la directora en los días previos. Aprovecho para preguntarte qué tal está Emilia y qué tal está yendo la adaptación al centro. ..."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2021-12-28','Email de Alberto del día 21: ANA: TAREA ASIGNADA X MIGUEL: Ana a través del centro preguntes a la curatelada donde está la escritura notarial o sentencia judicial de adjudicación por divorcio (que podéis ver en la nota simple). • TAMBIÉN SOBRE SI TUTELADA SABE QUIEN ABONA CONSUMOS O/Y IMPUESTOS VIVIENDA. MARIA: HABLA CON CENTRO Y PREGUNTA SI TENEMOS ALGUNA DEUDA PENDIENTE. TEN EN CUENTA QUE: • NO CARGAN EMBARGOS DESDE 08/2021. MIGUEL: NO ABONAMOS EMBARGOS DESDE AGOSTO 2021 Y MARIA AVERIGUARÁ SI AUN QUEDA DEUDA X SALDAR...SI YA NO HAY DEUDA PODEMOS ABONAR TASACIÓN!!! ****************************************************** miguel, mi contestación: Hola, como intenté explicar en el anterior email es titular del 100% del usufructo y para averiguar el cálculo del mismo (el valor aproximado que tenía la vivienda en el momento de constituirse el usufructo y compararlo con el valor de compra que han ofrecido, necesito el título (notarial o judicial por el que se constituyó, es decir, el que viene en nota simple…Disolución conyugal. Por tanto, si Ana logra que le remitan escritura notarial o sentencia judicial de adjudicación por divorcio podremos localizarlo y si nos cuadra por precio con lo que proponen vender, entonces no haría falta pedir ninguna tasación. ********************************************** email de Ana de 22-12-21: Buenas Alberto y Miguel, Tras haber hablado con Felisa, TS CAMF-Alcuéscar, rescato y os envío este presupuesto de para tasación de la vivienda por una inmobiliaria de Alcuéscar. Yo lo veo razonable, si se puede asumir, por mi parte ok, para no demorar mucho más este asunto. En cuanto a lo que pedía Miguel, dice que ya lo envió hace mucho tiempo, a petición de los jurídicos también, no obstante, me lo reenviará de nuevo para que os lo vuelva a pasar. Por último, en relación a la deuda, no me saben decir, como ella ve la cartilla con la curatelada, también se ha extrañado de que no le hayan vuelto a pasar nada desde agosto, pues cree recordar que aún debía más de 2.000 €, llamaré yo a la Seguridad Social, a ver si puedo averiguar algo. Ya me decís lo de la tasación. ********************************************** miguel, mi contestación: Hola este email en relación con el anterior. No va a hacer falta seguramente como os he comentado pagar esta tasación (pensando en la falta de liquidez de la curatelada) y que podemos intentar calcular el usufructo (valor que va a adquirir la curatelada con la venta de la vivienda)','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2021-12-27','Email de Alberto del día 21: ANA: TAREA ASIGNADA X MIGUEL: Ana a través del centro preguntes a la curatelada donde está la escritura notarial o sentencia judicial de adjudicación por divorcio (que podéis ver en la nota simple). • TAMBIÉN SOBRE SI TUTELADA SABE QUIEN ABONA CONSUMOS O/Y IMPUESTOS VIVIENDA. MARIA: HABLA CON CENTRO Y PREGUNTA SI TENEMOS ALGUNA DEUDA PENDIENTE. TEN EN CUENTA QUE: • NO CARGAN EMBARGOS DESDE 08/2021. MIGUEL: NO ABONAMOS EMBARGOS DESDE AGOSTO 2021 Y MARIA AVERIGUARÁ SI AUN QUEDA DEUDA X SALDAR...SI YA NO HAY DEUDA PODEMOS ABONAR TASACIÓN!!! ****************************************************** miguel, mi contestación: Hola, como intenté explicar en el anterior email es titular del 100% del usufructo y para averiguar el cálculo del mismo (el valor aproximado que tenía la vivienda en el momento de constituirse el usufructo y compararlo con el valor de compra que han ofrecido, necesito el título (notarial o judicial por el que se constituyó, es decir, el que viene en nota simple…Disolución conyugal. Por tanto, si Ana logra que le remitan escritura notarial o sentencia judicial de adjudicación por divorcio podremos localizarlo y si nos cuadra por precio con lo que proponen vender, entonces no haría falta pedir ninguna tasación. ********************************************** email de Ana de 22-12-21: Buenas Alberto y Miguel, Tras haber hablado con Felisa, TS CAMF-Alcuéscar, rescato y os envío este presupuesto de para tasación de la vivienda por una inmobiliaria de Alcuéscar. Yo lo veo razonable, si se puede asumir, por mi parte ok, para no demorar mucho más este asunto. En cuanto a lo que pedía Miguel, dice que ya lo envió hace mucho tiempo, a petición de los jurídicos también, no obstante, me lo reenviará de nuevo para que os lo vuelva a pasar. Por último, en relación a la deuda, no me saben decir, como ella ve la cartilla con la curatelada, también se ha extrañado de que no le hayan vuelto a pasar nada desde agosto, pues cree recordar que aún debía más de 2.000 €, llamaré yo a la Seguridad Social, a ver si puedo averiguar algo. Ya me decís lo de la tasación. ********************************************** miguel, mi contestación: Hola este email en relación con el anterior. No va a hacer falta seguramente como os he comentado pagar esta tasación (pensando en la falta de liquidez de la curatelada) y que podemos intentar calcular el usufructo (valor que va a adquirir la curatelada con la venta de la vivienda)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2021-12-28','miguel, tras recibir la sentencia de divorcio y el borrador del contrato de compraventa remito email a Ana y Alberto: Buenos días, tras leer la documentación que me reenvía Ana (sentencia de divorcio y borrador de contrato privado de compraventa donde no se indica importe de venta y tampoco propuesta de cantidad del usufructo). Veo los siguientes inconvenientes para vender: Cuando uno se divorcia, tras el divorcio hay un procedimiento de liquidación de la sociedad de gananciales, entiendo viendo el borrador de la compraventa que dicho procedimiento de liquidación de la sociedad de gananciales nunca se hizo y por tanto no se dio valor a la casa y por tanto al usufructo, es decir, que yo no tengo forma de saber el valor de la casa ni del usufructo. Eso supone que la única forma de saber el valor de la casa y por ende del usufructo tendrá que dictaminarla un tasador. Por tanto el presupuesto que tenéis deberías aprobarlo Alberto para que sea tasada no solo la nuda propiedad de las sobrinas del exmarido, sino el usufructo cuyo 100% era del matrimonio. Al fallecer el exmarido y no haber liquidado dicha sociedad de gananciales (como he dicho no se hizo procedimiento judicial de liquidación de la sociedad de gananciales), supone que la parte del exmarido pasa a su heredera, y que según veo es la madre del exmarido. Por tanto la venta deberá hacerla tanto nuestra tutelada como la madre del exmarido (que entre las dos tendrían el 100% del usufructo) y las dos sobrinas que tendrían la nuda propiedad. En conclusión que Alberto autorice dicha tasación y a dicho tasador se le diga que ha de incluir la valoración de la vivienda y de cuánto puede ser el valor del usufructo. Una vez lo cual, dividiremos entre dos el valor de dicho usufructo y ese será el importe que se asigne nuestra tutelada. Decidle al centro que en cuanto esté la tasación (que no debería tardar) se puede completar con cifras de compra y valoración dicho borrador de contrato privado y firmar en notaria la notaria que más cercana esté a Alcuescar que creo es la de Montanchez, y nosotros ratificaríamos desde la notaria de Mérida en la misma mañana, ya que entre ambas notarias se enviarían telemáticamente la compraventa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-12-28','Ana: Correo de Minerva, TS CR Cervantes: "Buenos días Ana, he estado hablando con Mª Luisa como hemos concretado, de los posibles destinos que le he ofrecido me comenta que prefiere la residencia de La Serena en Castuera. Espero respuesta con vuestra decisión, a ver si os parece acertada. Nos ponemos en contacto a la vuelta de tus vacaciones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-12-28','Ana: Envío correo-e a Paloma Castellano, TS Res. El Cuartillo (paloma.castellano@salud-juntaex.es) en respuesta a su correo: "Buenos días Paloma, Te facilito los informes de que disponemos, pensaba que os los facilitaban para el ingreso, son los mismos que remitimos a la Gerencia Territorial con la Solicitud de Ingreso Involuntario: - Informe Social – Modelo Solicitud de Ingreso (Decreto) - Informe de la Policía Local - Informe Médico – Anexo solicitud de Ingreso (Decreto) La sentencia de Incapacitación y la autorización judicial de internamiento involuntario, se la remití a la directora en los días previos. Aprovecho para preguntarte qué tal está Emilia y qué tal está yendo la adaptación al centro. ..." ································································································································································································ A petición de remito a Amparo, Directora de la Res. El Cuartillo (rm.elcuartillo@salud-juntaex.es) información sobre las pensiones que percibe Emilia: "La tarjeta sanitaria, si no la llevaba, habrá que gestionarle una nueva… decidme si podéis solicitarla en el centro de salud o sino veré qué puedo hacer desde aquí. En cuanto a las pensiones, percibe 2: - Pensión de Jubilación: 509,87 € x 14 pagas - Pensión de Viudedad: 322,31 € x 14 pagas Los certificados no los tenemos, aunque los solicitamos al INSS cuando se aceptó el cargo, no nos los han remitido. Sabemos las cantidades por los movimientos bancarios." ································································································································································································· Respuesta de Paloma Castellano, TS Res. El Cuartillo (paloma.castellano@salud-juntaex.es): "Buenas mi teléfono es 927005308 La adaptación de Emilia en planta es complicada porque tiende a trastear mucho tanto de día como de noche. Se ira valorando la situación y si es necesario se baja a otra planta donde esté más controlada!! Sinceramente nada que sea imposible de resolver!!! Gracias y buen dia!!!!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-12-27','miguel, me llega físicamente el sobre que dejó la madre a Amalia en Badajoz que contiene un archivo de expediente de la subdelegación del gobierno en Badajoz, en base a su minusvalía. Y otra infracción por actividades molestas por importe con reducción del 40%. ********************************************** Las remito por email al Oar Badajoz para que me indiquen si hay otras cartas de pago pendientes de abonar y si la que tengo es vigente para su abono hasta final del 2021','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2021-12-28','Ana: Tras hablar con Miguel Ángel, Director del CRR (927 83 02 10), llamo a Juan José, en relación a la petición que realiza de irse por fin de año 3 noches a un hotel, tal y como hacía cuando estaba en Badajoz. *Le explico, que tal y como está la situación de pandemia actual, por prevención, quizá sería mejor aplazar esa salida para más adelante cuando esté todo más tranquilo y haya menos riesgo de contagio. Lo acepta bien. ············ *Hablará entonces con Miguel Ángel sobre la posibilidad de ir en Nochevieja a cenar con su familia. ································································································································································································ Envío a las compañeras de la secc. ecca. presupuesto del Decathlon para unas mancuernas que pidió Juan José por su cumpleaños y que me ha remitido Toni-Futuex. *Como no están Alberto ni Maite, lo autorizo yo. Juan José lo está pasando mal dado el cambio temporal al CRR por las cirscustancia de la entidad y considero será positivo para él (además se lo puede permitir).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2021-12-28','Ana: Remito a Miguel Ángel Ramirez, Director del CRR-CC (crr@grupociudadjardin.com) los C.I. para Sedación y Colonoscopia, firmados digitalmente por el representante legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-12-28','Ana: A petición de Miguel, Asesor Jurídico, le remito el siguiente correo: "Te adjunto todo lo que he podido recabar en el expediente digital y papel. - Certificado Discapacidad CADEX - Dictamen Técnico CADEX - Informe Clínico de Salud Mental (25/11/19) - Informe de Salud Mental relativo a su capacidad de Conducir (31/08/2020) - Comunicación Ingreso Centro Penitenciario - Notas Seguimiento FUTUEX de junio a diciembre de 2020 Es todo lo que tenemos. No obstante tenía cita programada en el Servicio de Psiquiatría para el 23 de enero de 2020, por lo que solicitaré a Salud Mental informe de dicha cita y si tuvo alguna más a posteriori también. En cuanto me la remitan te lo hago llegar, pero no sé lo que tardarán dadas las fechas en las que estamos." ······························· *Envío fax, a Julia Gía White, Coordinadora de Área de Salud Mental, solicitando informe de psiquiatría de la consulta programada para el día 23/01/20 y sucesivas del año 2020 (hasta antes de ingresar en C. Penitenciario).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-12-23','Ana: Correo de Julia Gía White, Coord. de Salud Mental, adjuntando el ACTA DE LA SUBCOMISIÓN DE CASOS CLÍNICOS. *Guardo en el expdte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-12-23','Ana: Correo de Clara, TS C.S. Guadalupe: "Buenos días Ana. Ha venido Juan, me ha dicho que ahora no quiere ir a la cita, que para después del 20 enero. Yo me voy de vacaciones, vuelvo el 20 de enero. No he podido hablar con Pilar para que se programe la nueva cita. Le voy a poner un correo y cuando vuelvas de tus vacaciones habla tú con ella, a la vuelta de mis vacaciones te llamo para coordinarnos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-12-28','Ana: Envío correo a Pilar Martín, TS ESM (pilar.martinp@salud-juntaex.es), le informo de la conversación con el Dr. Jiménez Cano y Clara, así como el correo que me remite. Propongo hablar tras las respectivas vacaciones. Intentaré gestionar nueva cita para Juan, para después del 20/01/22. ··················· Llamo a Salud Mental (927 21 37 30 // 54698): Ya le han programado nueva cita para el día 17 a las 12:30 h. *Se lo comunico a Toni-Futuex por mail y a posteriori a Clara y Pilar Martín.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2021-12-29','Ana: Recibo correo de Toni con los últimos contactos con Aída, ésta pone muchos impedimentos para que la Educadora acuda a la vivienda a valorar, con el seguro de hogar los problemas de las tuberías y otros supuestos desperfectos. No accede a quedar con ella, y el día que supuestamente iban a quedar no respondió a sus llamadas. ················· *Envío correo a Aída (aidamartindepinol@gmail.com) pidiendo que nos envíe los justificantes del viaje a su pueblo. (*Según informa Toni-Futuex, la vez anterior no consiguieron que les enseñara ningún ticket, billete ni similar).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2021-12-29','Ana: Llamo a Juan José (667 958 878): le comunico que se autoriza la compra las mancuernas por su cumpleaños. Icíar le ha solicitado cita en su banco para mañana a las 10:15 h. *Le recuerdo que debe pedir y enviarnos la factura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2021-12-29','Ana: Juan José llama a María, secc. ecca., para solicitar que se le autorice a retirar 100€. *Aún no está el inventario hecho. No tenemos informe social. *Percibe PNC, y José Vicente ya está en la cuenta. *Se le autorizarán los 100€. ············ Presenta 65% de Discapacidad reconocido por el CADEX, con diagnóstico de TRASTORNO MENTAL POR TRASTORNO BIPOLAR. ············ Reconocido GRADO II de DEPENDENCIA. ···················· Telf. de contacto: 643 641 375','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2021-12-29','Ana: Juan José llama a María, secc. ecca., para solicitar que se le autorice a retirar 100€. *Aún no está el inventario hecho. No tenemos informe social, no lo han remitido del IMAS-CC. *Percibe PNC, y José Vicente ya está en la cuenta. *Se le autorizarán los 100€. ············ Presenta 65% de Discapacidad reconocido por el CADEX, con diagnóstico de TRASTORNO MENTAL POR TRASTORNO BIPOLAR. ············ Reconocido GRADO II de DEPENDENCIA. ···················· Telf. de contacto: 643 641 375 ················· **En el expdte. digital hay guardados CORREOS previos a la aceptación del caso en que se indica la GRAVEDAD DEL CASO. ································································································································································································· *Envío fax, a Julia Gía. White, Coordinadora de Área de Salud Mental, solicitando Informe de Seguimiento de Psiquiatría. ······················· Paso a Kike, CTAEX, 2 oficios-solicitud de Informe Social, uno para remitirlo al IMAS-CC, y otro para Pilar Martín, TS del ESM a través de registro (SIREX). ································································································································································································· *Conversación con Miguel, Asesor Jurídico, cuando recibamos los informes solicitados realizarán comunicación al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-12-29','Ana: envío correo a Toni-Futuex: "Buenas tardes Toni, ¿qué tal vais? Aquí, para variar, esto es un no parar… ¿Podríais confirmarme si Martín finalmente acudió a la cita de Psiquiatría el pasado lunes 27? Si al final pudo acompañarle alguna compañera o si hablasteis con el hermano? Gracias. Seguimos!" ····························· Respuesta de Toni-Futuex: "Buenas Ana, confirmamos a través del hmo q si que acudió a esta consulta, lo que ya es un gran logro q inicie tratamiento, después de tanto tiempo, si bien no tenemos datos de la pauta o las consideraciones de la consulta, a la vuelta la compañera tratará de recabar mas información, si puede ser hablando con Jiménez Cano directamente, aq este psiquiatra ya veremos que novedades instaura con este caso.... Conociéndolo creemos q pocas,, pero a ver q pasa de cara a la intervención"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-12-29','Ana: puesto que no he obtenido respuesta a mi correo de la empresa EUEXIA, llamo a la empresa (651 63 97 17) y hablo con Álvaro: No nos han dado respuesta porque ha estado de vacaciones, intentará enviar presupuesto esta misma tarde. Le facilito la dirección de correo de Maite, Jefa de Secc. para que nos lo envíe a ambas (yo no estaré los próximos días)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-12-29','Ana: Llamo a la Gerencia Territorial de CC (927 00 42 39), Pedro no está. Hablo con Plácido Alejandre, en principio cuando una persona ha ingresado por emergencia social no se puede solicitar cambio de centro... Explico un poco la situación y hago mención al informe social que les remitieron desde C.R. Cervantes a fecha de 30 de junio de 2021. Acordamos que les enviaré de nuevo dicho informe y volveremos a hablar en enero, con él o con Pedro. ··········· Escaneo y envío el informe que nos entregaron e mano.','2');
