insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2022-01-03','Remedios Lozano Baquero >reme_lb@hotmail.com> Lun 27/12/2021 12:17 Buenos días, Alonso ya está en casa. No viene en muy buenas condiciones para mantenerlo en el domicilio, necesita una persona 24 horas. Creo que deberíais valorar ingreso en centro. Cuando puedas, hablamos de este caso. saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2022-01-03','una cosa que se me ha olvidado, en la Residencia el Chalet de Puebla que es privada, creo que le han concedido plazas sociosanitarias, por si fuera esa una opcion.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2022-01-03','Amalia Diaz Gonzalez Lun 03/01/2022 13:23 Hola , sí te he llamado y me lo he imaginado . He hablado con la Sección que gestiona estas plazas sociosanitarias en el SEPAD . En Puebla lo que hay son plazas para dependientes , no hay plazas sociosanitarias . Para poder acceder a una de esas plazas habría que solicitar una revisión PIA , para que subiera en la lista . Ésto se puede alargar en el tiempo . Otra opción es solicitarle plaza sociosanitaria . La parte sanitaria para ver qué puntos obtendría en la herramienta la tiene que hacer el enfermero o el médico de su centro de salud . Y la Trabajadora social del centro de salud o del SSASB la parte social . El expediente me lo tenéis que reenviar a mí para que añada la parte de la tutela y la firma de su rpte. legal . Y me encargaría de registrarlo a la sección encargada para que le dieran plaza. En estas plazas no se elige destino , podemos pedir lo más cercano al domicilio . Cuál de las opciones consideras más apropiado ?? El estado de salud de Alonso permite demorarse en el tiempo ?? Otra opción ,por coger lo más rápido , es solicitar plaza T2 o T3 según baremo y luego solicitar un traslado cuando estuviese valorado por dependencia . Enviaré a la delegada tutelar a visitarlo para ver cómo se encuentra. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2022-01-03','Amalia : Hablo con Victoria , TS del H.P.S . donde ha vuelto a ingresar el dia 28 . El médico ha pasado herramienta y da 17 puntos , no llega a los puntos necesarios para solicitar plaza sociosanitaria. Mañana le dará el alta . Llamo a Reme para decírselo . Va a intentar que las auxiliares SAD alarguen su horario para estar el máx. de horas atendidos . La semana q viene q se incorpora vamos a mover las dos vias , dependencia y sociosanitaria ( con la valoración del medico de familia )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='SANCHEZ'and apellido2='MORENO'),'2022-01-03','Amalia Diaz Gonzalez Lun 03/01/2022 14:44 Buenas , Los 310€ se les ingresa por transferencia a la cuenta del hermano . Ellos se encargan de abonar todo y de darle a ella los 60€ de gastos de bolsillo. En el documento que envía la señora se indica el Nº de Cuenta. Ya se le deben 3 meses . Se podría hacer una primera transferencia con los 3 meses pendientes y luego indicar una permanente . Le doy prioridad a este pago , la familia está ya impaciente con el dinero que ellos están adelantando','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2022-01-04','Amalia Diaz Gonzalez Mar 04/01/2022 12:52 Buenos días , he hablado con Beni . El contrato inicial de alquiler que se hizo fue en fecha 1/12/2018 por 3 años de validez . Quieren saber si hay que hacer otro contrato . Y actualizar IPC , no han subido la cuota durante estos años . Ángel , he visto que ese contrato lo gestionaste tú . En el email anterior aparece el tf. de la propietaria para que puedas contactar con ellos. Un saludo. Amalia Diaz Gonzalez Mar 04/01/2022 12:28 Buenos días , la llamo y me informo . Seguimos.. Maria Teresa Gomez Martin Mar 04/01/2022 10:39 ¡Buenos días! Ha llamado la dueña del piso donde vive Catalina Miranda Rosado ( Beni). Dice que el contrato de alquiler finalizó en Octubre, aunque seguimos pagando. También nos pide que vayamos a ver el piso pq no tiene buenas condiciones de habitabilidad y que por favor nos pongamos en contacto con élla: 650169824.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2022-01-04','Buenos días , solicito un servicio de 3horas al día de lunes a domingo para los hermanos Ortiz Germán. Quedo pendiente de recibir presupuesto y cuadramos el servicio. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2022-01-04','-Amalia : Alonso ha recibido alta hospitalaria , no viene en buenas condiciones de salud , se va a solicitar revisión PIA ( los informes médicos los va a pedir Reme ) y tambien se va a solicitar plaza sociosanitaria , necesita plaza residencial . Mientras tanto se amplia el servicio de ayuda a domicilio que tienen contratado en la casa para los 3 hermanos 3 horas más de L a D para dejarlo acostado y cubrir todo el día . Actualmente tienen con la AOEX y con la PVS de dependencia a 3 auxiliares : Esther va 8 h al día , mañana y tarde . otra auxiliar va 3 h de L a V para ayudar a Esther con baños , y tareas domesticas por la mañana. Bañan a los 3 hermanos . Rufina va 3 h los fines de semana y festivos . He pedido a la AOEX ( Jaime ) que busque otra persona , las que están no lo pueden cuadrar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2022-01-04','-Amalia : Alonso ha recibido alta hospitalaria , no viene en buenas condiciones de salud , se va a solicitar revisión PIA ( los informes médicos los va a pedir Reme ) y tambien se va a solicitar plaza sociosanitaria , necesita plaza residencial . Mientras tanto se amplia el servicio de ayuda a domicilio que tienen contratado en la casa para los 3 hermanos 3 horas más de L a D para dejarlo acostado y cubrir todo el día . Actualmente tienen con la AOEX y con la PVS de dependencia a 3 auxiliares : Esther va 8 h al día , mañana y tarde . otra auxiliar va 3 h de L a V para ayudar a Esther con baños , y tareas domesticas por la mañana. Bañan a los 3 hermanos . Rufina va 3 h los fines de semana y festivos . He pedido a la AOEX ( Jaime -673925159) que busque otra persona , las que están no lo pueden cuadrar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-01-04','Amalia : email de Carmen TS del ESM : He conectado con una ordenanza del SEPAD (Gerencia Territorial de Badajoz) y, te voy a enviar la Solicitud de Valoración de Dependencia de Alejandro allí, ya que tu jefa decía que tenía que estar firmada por el, y por vosotros, supongo. Si ves que algo no cuadra, lo corriges y la entregas. Hago esto porque no puedo escanearla y porque cuando tú te incorpores, me voy yo de días de L.Disposc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-01-04','De: Flavio Escribano >fescribano@gmail.com> Enviado el: miércoles, 29 de diciembre de 2021 9:18 Para: ICIAR ROSA REYES >iciar.rosa@salud-juntaex.es>; Carmen Márquez Valdelacalzada >carmen.marquez@valdelacalzada.es> Asunto: Asunto compras Rosa Serrano García Muy buenas Iciar y Carmen, espero que estéis bien y que estéis aprovechando estos días para disfrutar de vuestros seres queridos. Os escribo porque me he dado cuenta de que mi madre sigue haciendo compras por Internet, la casa vuelve a estar llena de cosas que podrían ser peligrosas, especialmente en invierno con calefactores y demás. Ella está comprando con los 45€ semanales que se le deja sacar del banco. Es muy probable que los 100€ que le habéis concedido de más para esta semana también se los gaste en compras de Internet. Pongo un ejemplo: ella ha comprado un tapacubos del coche (sin ni siquiera pasar la ITV), ha contactado con la persona por Internet y lo ha pagado contra-reembolso. Digo esto porque el asunto es muy serio, es decir, mi madre no es una persona con la que se pueda razonar, es una adicta con una enfermedad mental, es necesario cortar Internet en su caso y dejarle exclusivamente una línea de teléfono. Mi madre es capaz de provocar una situación en la que a Blas o a ella le falten cosas esenciales con tal de comprar, está totalmente fuera de control. Yo ya estoy en Montijo viviendo, me ofrezco a ir a Mérida o a donde haga falta para discutir sobre este punto y ver cómo proceder. Si no obtengo respuesta o no se cancela la línea de internet que tiene mi madre ahora mismo en uso (+34 634 48 99 51) durante el mes de Febrero tramitaré directamente esta petición con el fiscal que lleva el tema para que agilice la gestión. Quedo a vuestra disposición a través de este medio o en mi móvil: 625538303 Un saludo y muchas gracias por el buen trabajo que estáis realizando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-01-05','Buenas compi , ya estoy de vuelta , me quedan días , pero los iré intercalando durante las semanas . Esta pregunta tienes que planteársela a Ángel , desconozco a nivel jurídico los requisitos. Lo que se ha hecho en otras ocasiones , es que la persona ya se había trasladado a otra comunidad , por su cuenta , y pasado unos meses allí Ángel comunicaba al juzgado esta situación y el juzgado hacía la remoción del cargo a la entidad competente de esa comunidad . Si Damián quiere irse y dado que es curatela económica que busque ya un alquiler o un sitio donde irse a vivir y deje voluntariamente el CRR . Lo hablamos primero con Ángel que nos aclare y decidimos , te parece ? Seguimos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-01-05','Amalia : hablo con su hijo por tf de toda la situación . Propone que anulemos su cuenta de internet y tf ( nos ha enviado un email de la compañia para proceder ) he solicitado autorización a parte eco y jurídica , quedo pte. de su respuesta para gestionarlo. Envio email a seccion eco , se podría bajar de 45 a 30€ al mes para evitar compras compulsivas: Buenas de nuevo , siguiendo con este caso , que té parece si le echamos un vistazo a sus cuentas ??? Cúanto se le da a la semana ??? el hijo propone que se le baje , al parecer todo el dinero que coge se lo gasta en artículos de todo tipo, ha mandado fotos con la casa llena de paquetes . Está comprando cosas para el coche que no va a poder utilizar , no tiene dinero para su mantenimiento , gasolina ... y creo que es un peligro que lo conduzca. Cuando tengas un hueco lo vemos y si te parece actualizamos sus cuentas . Y vemos también la opción de dar de baja a internet . Ahora tenemos la tranquilidad que para comida no le va a faltar , el hijo se compromete a que ésto lo tendrá siempre cubierto al regresar él al pueblo . Seguimos...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-01-05','Amalia : hablo con su hijo por tf de toda la situación . Propone que anulemos su cuenta de internet y tf ( nos ha enviado un email de la compañia para proceder ) he solicitado autorización a parte eco y jurídica , quedo pte. de su respuesta para gestionarlo. Envio email a seccion eco , se podría bajar de 45 a 30€ al mes para evitar compras compulsivas: Buenas de nuevo , siguiendo con este caso , que té parece si le echamos un vistazo a sus cuentas ??? Cúanto se le da a la semana ??? el hijo propone que se le baje , al parecer todo el dinero que coge se lo gasta en artículos de todo tipo, ha mandado fotos con la casa llena de paquetes . Está comprando cosas para el coche que no va a poder utilizar , no tiene dinero para su mantenimiento , gasolina ... y creo que es un peligro que lo conduzca. Cuando tengas un hueco lo vemos y si te parece actualizamos sus cuentas . Y vemos también la opción de dar de baja a internet . Ahora tenemos la tranquilidad que para comida no le va a faltar , el hijo se compromete a que ésto lo tendrá siempre cubierto al regresar él al pueblo . Seguimos...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2022-01-05','Amalia : llamo a la Dtra. para preguntar por Maria . Tuvo otro intento autolítico y volvió a ingresar en la UHB , ya está de nuevo en la residencia. La hija no la ha llamado en las ultimas semanas . Quedé pendiente con ella que me avisara para gestionar un taxi para poder llevarla con sus hijos a ver a la madre , pero no ha llamado ,ni a la residencia ni a la CTAEX . Por el momento y con la alta incidencia covid tampoco es muy conveniente la visita . Con respecto a la solicitud de traslado de su plaza T4 de San Vicente a Badajoz , me indican que no hay plaza en Badajoz . LLamo a Maria y junto con la DTRA . y la médico le explico la situación , lo más cercano es la Albuera . Le planteo la opción de pedir traslado ahí pero no quiere . Le indico que de momento no se solicita ningun traslado a la espera de que existan plazas t4 en Badajoz. ---------------------------------------------------- Hablo con M.Angeles ,la Dtra. me enviará a mi email las facturas de podologia y peluqueria cada 3 meses para q se hagan transferencias. El modelo 50 tambien me lo enviará , se envia cada mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-01-05','Amalia : Me llama Maria , psicóloga del CRR Olivenza. Han expulsado a J.M. tras sus últimos incidentes , con altercados tanto con usuarios como con personal . Le permiten quedarse unos días , pero él se niega , se quiere ir hoy . Me pide que la asignación que tiene que retirar de 132€ el día 17 la pueda hacer en Cáceres , en Liberbank de la Avda. de la Hispanidad . Lo indico a la sección eco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-01-05','Amalia : envío email a la sección eco Buenos días , Me ha llamado María , psicóloga del CRR Olivenza. El brote de coronavirus que ha habido está remitiendo. Han expulsado a J.M. tras sus últimos incidentes , con altercados tanto con usuarios como con personal . Quedo pendiente recibir toda la documento referente a la expulsión. Le permiten quedarse unos días , pero él se niega , se quiere ir hoy , firmará el alta voluntaria. Me pide que la asignación que tiene que retirar de 132€ el día 17 la pueda hacer en Cáceres , en Liberbank de la Avda. de la Hispanidad . Con ese dinero tendría que tener hasta final de mes . Para febrero se establecerá un nuevo presupuesto , él solicita que se le ponga de nuevo el catering que tenía en Cáceres . Prefiero esperar y lo hablamos con Ana , a la vuelta de sus vacaciones , que nos de su opinión sobre este tema . Ella tiene más información de sus gastos en domicilio . Ya no tiene que pasar asignación a sus hijos . Los suministros de la vivienda se le abonan a su hermano . Seguimos..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-01-05','Buenas tardes Informar que Jose Manuel Romero Mediavilla ha tenido una salida definitiva del centro por presentar de manera reiterada comportamientos conflictivos-disruptivos y agresivos con profesionales y compañeros. Pese a ofrecerle poder tener la salida el viernes ha decidido irse en este momento. Se niega a firmar la ficha de salida pero se lleva copia de ella. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-01-05','M. Luz Madrigal : Buenas tardes, con respecto a esta salida entiendo que no ha sido voluntaria, por tanto no podemos darle de baja como usuario por el momento. Debéis enviar Informe con los hechos que motivan la Propuesta de perdida de plaza y una vez estudiados en la Comisión de Acceso a Recursos Residenciales C.de SM, se resolverá lo que proceda y se os enviará la comunicación, al igual que a la CTA. Quedamos a la espera del Informe. Saludos,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2022-01-05','Buenos días Jaime , la situación de Alonso no es muy buena y vamos a esperar hasta la semana que viene para tomar una decisión más definitiva . Necesitamos que nos cubras de momento , el servicio desde mañana durante 3 horas al día , de momento hasta el jueves día 13 que volveré a hablar contigo . Se le ha dejado una grúa a las auxiliares y queremos ver también cuál es la evolución en los cuidados. Muchas gracias por tu ayuda . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-12-29','remito email a Amalia: Hola compi, imagino que estarás de vacas. Para cuando vuelvas a ver si puedes ver este asunto donde Damian quiere volver a Málaga y no sabe qué requisitos necesita para que la curatela la asuma la Junta de Andalucía','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-01-07','miguel, remito email a Amalia: Buenos días, tras hablar con Angel, vemos que no pide un traslado de expediente sino un traslado a un centro de Málaga. Según me comenta Angel en otros expedientes los traslados de expedientes a otras Comunidades Autónomas seguían los siguientes trámites: Llevaban no meses sino años viviendo en algún centro de esa Comunidad, ejemplo: Margarita Antich. Una vez eso se solicitaba la remoción del cargo a través de abogacía general al Juzgado. Damian lo que quiere es irse a vivir allí y que le tramitemos con la junta de Andalucía un centro en Málaga, un CRR o su equivalente. La posibilidad de irse a un piso no sería viable (entiendo) porque no está capacitado para ello, (además que depende de la decisión de la parte económica)aunque eso es una cuestión que habría que hablar con Gisela, y que él aprovecha cada vez que se va ella para hablar de estos asuntos. También está claro que no podemos impedirle que se vaya a ir a vivir a otra parte por su propia voluntad. Por tanto y en conclusión entiendo que no es una cuestión jurídica puesto que no se trata de un traslado de expediente y que es una cuestión a social imagino que a tratar con Gisela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2022-01-07','ICIAR: HABLO CON FERNANDO DE LA CASA DE LA MISERICORDIA. COMO INDICA MAITE EN SU CORREO SE LE AUTORIZA 50 €/SEMANA. AL NO HABER BANCA PUEYO EN LA LOCALIDAD SE EL HARÁ TRANSFERNCIA PERMANENTE AL CENTRO POR 200 €/MES Y ELLOS SE LO ADMINISTRAN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-01-07','miguel, llama por telefono interesado en firmar contrato de arrendamiento nuevo de rústica: arrendatario Fco Jesús Mariñas Perez Nif 33977466A, Tfno:618634763 y email: chiquimarina@hotmail.es Tras revisar la rendición final veo que hay que revisar el expte físico ya que por error está escaneado en vez el certificado de últimas voluntades, el certificado de seguros, y por tanto hay que comprobar que efectivamente no hizo testamento. Por otro lado tras comprobar en catastro aparece en algunas fincas arrendadas un 3º titular Dolores Lara Lay con nif 4477778136B, dirección en c/ Valle 32, 06200, Almendralejo (Badajoz); tlfno: 625030078, donde le dejo recado en email para que nos llame explicandole que es titular y que hay interesado en arrendar. Angel coge el expte porque no estaré por vacas los próximos dias. ******************************************** Tras revisar el expte físico seguramente habrá que hacer declaración de herederos+ pedir autorización judicial de aceptación de la herencia+ adjudicación de herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTIN'and edp.apellido1='POZO'and apellido2='CANSECO'),'2022-01-10','TERESA RECIBO RESOLUCION SOBRE SOLICITUD DE INCLUSION DEL PROGRAMA PARA PACIENTES CON NECESIDADES ASISTENCIALES EN LA CUAL NOS INDICAN QEU LA SOLICITUD ESTA INCOMPLETA POR NO APORTAR INFORMES CLINICOS QUE JUSTIFIQUEN LA SITUACION SE LO COMENTO A TONI TS DEL CAMP Y ME DICE QUE SE LOS PEDIRA AL MEDICO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-01-10','Ana: Correo de Amalia del día 5 para Alberto, nos pone en copia a Maite y a mí: "Me ha llamado María , psicóloga del CRR Olivenza. El brote de coronavirus que ha habido está remitiendo. Han expulsado a J.M. tras sus últimos incidentes , con altercados tanto con usuarios como con personal . Quedo pendiente recibir toda la documento referente a la expulsión. Le permiten quedarse unos días , pero él se niega , se quiere ir hoy , firmará el alta voluntaria. Me pide que la asignación que tiene que retirar de 132€ el día 17 la pueda hacer en Cáceres , en Liberbank de la Avda. de la Hispanidad . Con ese dinero tendría que tener hasta final de mes . Para febrero se establecerá un nuevo presupuesto , él solicita que se le ponga de nuevo el catering que tenía en Cáceres . Prefiero esperar y lo hablamos con Ana , a la vuelta de sus vacaciones , que nos de su opinión sobre este tema . Ella tiene más información de sus gastos en domicilio . Ya no tiene que pasar asignación a sus hijos . Los suministros de la vivienda se le abonan a su hermano . Seguimos.." ··················· Mi respuesta: Buenos días, Esta mañana he hablado tanto con José Manuel como con su hermano José Luis. José Manuel pide volver al centro, dice que fue un impulso y que él no puede vivir sólo, no quiere quedarse en Cáceres. No he hablado con las compañeras de Salud Mental, pero supongo que la decisión de expulsión es definitiva… Lo que no entiendo es que tenga que firmar “el alta voluntaria”, pues es una expulsión. De todas formas, por lo que me dice, él no ha firmado nada. Con respecto a la asignación, puesto que no tiene dinero y que hoy y mañana no estáis trabajando ninguno de los tres, he hablado con Icíar e intentará enviar la autorización a la sucursal para pueda retirar el efectivo el jueves. Si finalmente se queda en Cáceres, tampoco tengo claro lo de volver a contratar ese cáterin, pues por su parte todo eran quejas y pedía que se lo cambiáramos pues no le gustaba y tiraba la comida. ..." ····················································································································································································································································································································· Tras hablarlo con Icíar, secc. ecca., informo a José Manuel que el jueves podrá ir a retirar el dinero a la oficina de la Avda. de la Hispanidad. **Vuelve a insistir en que no firmó nada y que él quiere volver. ························································································································································································································································································································· Hablo con Eva, Psicóloga Secc. Salud Mental, me informa de que desde el CRR no han llevado a cabo adecuadamente el procedimiento de expulsión. La Psicóloga del CRR elaborará un informe detallado con las incidencias y posiblemente se proceda a la expulsión definitiva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='BLAZQUEZ'and apellido2='SANDOVAL'),'2022-01-10','Ana: Teresa Nogueira, TS Novaforma (trabajadorasocial.novaforma@gmail.com), comunica que hay un brote de COVID en el centro. Manuel ha dado positivo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-01-10','Ana: Ceferino ha sido expulsado de forma temporal del CRR, Amalia le ha gestionado un Hostal en Plasencia del 10 al 13 (lunes - jueves). *La sección económica ya está en contacto con el hostal para el abono de la factura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-01-10','Ana: Llamada de Isabel: hoy vuelve al CSS. Dice que ha pasado bien estos días en su casa, a excepción de unos días que tuvo una obstrucción intestinal y tuvo que ir al hospital, pero ya está mejor. *Pregunta por la asignación de este mes. Entiendo que se lo darán en el CSS, como habitualmente. *Y me recuerda que en 15 días volverá a su casa, por lo que necesitará más dinero. ···· En cuanto al CRR, pregunta cuando podrá acudir al mismo, le indico que debe de tener paciencia, aún no sabemos fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO RODRIGO'and edp.apellido1='RIVERA'and apellido2='TORIO'),'2022-01-10','Ana: Envío a Alberto, factura de gafas que me remite Teresa Nogueira, TS Novaforma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2022-01-10','Ana: Correo del jueves 6 de Alfredo Moreno Cebrián (residenciaplasenzuela21@gmail.com): "Buenos días. Les informo que ayer sobre las 12:00 horas de la noche se procedió a realizar el traslado de Doña Antonia Serrano Suárez (Tutelada por su Comisión) a Urgencias del Hospital San Pedro de Alcántara de Cáceres. Según el médico que la derivó a urgencias tenía un posible encharcamiento de pulmones y una infección de orina. También le informo que ha dado positivo en COVID 19. Le informaremos cuando tengamos nuevas noticias de ella, de todos modos si quieren saber más sobre ella, pueden ponerse en contacto con Urgencias del Hospital San Pedro de Alcántara de Cáceres." ························· Llamo a la Residencia (927 31 37 45), Alfredo no está, hablo con Rosa Robledo, me informan que cuando ingresó estaba muy afectada, pero el viernes por la mañana les informaron de que, dentro de la gravedad, está evolucionando bien. Hoy aún no les han llamado del hospital, me mantendrán informada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2022-01-10','Ana: Correo del viernes 7 de Maite, Jefa Secc.: "Te pongo al corriente sobre Isabel Muñoz Melchor. Como te dije le van a dar plaza en la resi de Torrecilla de la Tiesa. Me dijo Mai que el ingreso será para el dia 12. He hablado con la residencia de Jaraicejo para que le hagan PCR el lunes. Le dije a Maria la directora que el Lunes te pones en contacto con ella para gestionar el traslado." ···························································································································································································· Hablo con María, TS de Jaraicejo (664 598 967), ya le han hecho la PCR a Isabel. No cree que ponga impedimento el miércoles, por lo que acordamos que el traslado se realice en taxi, ella lo gestionará. ··························· Llamo a la Res. de Torrecillas de la Tiesa (927 33 80 76), la TS está de vacaciones hasta febrero. Hablo con Ana Sánchez, le informo que Isabel ingresará en su centro el miércoles 12. *No han recibido la resolución (no la envían hasta que tienen el resultado de la PCR). *Acordamos que el ingreso tendrá lugar sobre las 12 h. *Tiene que llevar: DNI, Tarjeta Sanitaria, Informe Médico, Pauta de medicación actualizada y copia de la primera hoja de la cartilla bancaria. ················· *Lo comunico a María, TS Jaraicejo. **Ha hablado ella con Gloria, Ed. Futuex, le indicará también la hora por si puede estar presente el día del ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2022-01-10','Ana: Rosa Bravo, CSS, me remite CI para ENDOSCOPIA DIGESTIVA BAJA Y SEDACIÓN ENDOSCÓPICA DIGESTIVA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2022-01-11','Ana: Remito a Rosa Bravo, CSS, los CI debidamente firmados y sellados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-01-11','Llama una sobrina, María del Pilar Rodríguez Rosado (927212138-645909526), preguntando el estado en el que se encuentra el procedimento, al ser administradores provisionales de bienes y no haberse resuelto hasta la fecha el procedimiento de incapacitación, que le informo. Comenta que siempre fue ella quien se hizo cargo de su tía y siempre ha estado pendiente de ella, sin embargo no fue llamada para el ofrecimiento del cargo de tutor o curador, en el procedimiento de incapacitación. Cree que llamaron a otra prima que lo ha rechazado. Hay que hablar con el Juzgado para preguntar si se resolvió el procedimiento de incapacitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2022-01-11','Ana: Conversación con Anabel, TS del SSASB Miajadas (Tfno.: 927 347 000 Ext.: 3401): dado que Esteve ya no va a volver al piso, firmaremos la RENUNCIA a la plaza para que se tramite la baja de la misma.','2');
