insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2022-01-11','Ana: Correo de Teresa Nogueira, TS Novaforma (trabajadorasocial.novaforma@gmail.com): "Buenos días De los tutelados , nos confirman hoy los siguientes residentes positivos covid: Felipe Blanco Fermín Garcia Juanjo Panadero Álvaro González Manuel Blazquez"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-01-10','Ana: Correo del día 3/01/22, de Estrella Durán, TS CSS: "Buenos días, Ana y Feliz Año! Tengo que comunicarte que el día 24 de diciembre sobre las 18 horas, se volvió a fugar del Centro Juan Carlos Ruíz, regresando acompañado por el 112 al día siguiente por la mañana. Venía sucio, mojado y tiritando de frío, lo encontraron andando por la autovía. Leo en Base de Datos del Centro, que la Psicóloga Coordinadora de la unidad de Juan Carlos ya lo ha comunicado a la Jefa de Unidad, Soraya Masa. Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-01-11','Ana: Llamada de Juan Carlos: sigue deseando irse a otro centro. *Ahora sale de L-V 1h a pasear con otros compañeros y un monitor, Fernando. ··································································································································································································· Conversación con Soraya Masa: el acompañamiento a pasear se replantea para los fines de semana. ····················· *Realizo consulta a Álvaro, Empresa EUEXIA (ameuexia@gmail.com). El presupuesto inicial remitido es de 70€ las dos horas, incluye traslado de ida y vuelta al CSS, coordinación con los profesionales del CSS y paseo/café por el centro de Plasencia. Duración total: 2h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2022-01-11','Ana: Llamada de Ana Benavente: Guadalupe estuvo ayer en consulta y manifiesta no estar a gusto en la residencia, no es la primera vez que lo dice y solicita el poder cambiar a piso tutelado. *Desde el CRR nunca plantearon la posibilidad de pasar a PP.SS., por no reunir suficiente autonomía, por tanto a priori descartamos esta opción, pero sí se puede plantear el traslado a otro centro residencial de otra localidad. ··················','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2022-01-11','Ana: Correo del día 5 de Pilar Martín, TS del ESM-CC (pilar.martinp@salud-juntaex.es): "Francisco Cacho Garrido, con alta voluntaria en PS de Mérida, ahora parece ser se encuentra en una pensión, pero según conversación telefónica mantenida con el paciente se quiere ir a Plasencia para alejarse del entorno de consumo, pero no acepta CRR ni PS . Su intención es ir al albergue de allí y luego buscar un piso compartido con alguien. Le digo que caso de tener plaza en el albergue que se ponga en contacto con la compañera del ESM Ana Benavente. El teléfono actual de Francisco es-641-56-94-90. Un abrazo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2022-01-11','Ana: Conversación con Anabel, TS del SSASB Miajadas (Tfno.: 927 347 000 Ext.: 3401): dado que Esteve ya no va a volver al piso, firmaremos la RENUNCIA a la plaza para que se tramite la baja de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-01-11','Ana: Conversación con Lucía Ávila, Res. El Conquistador (660963767): hay que poner al día las deudas generadas en el centro el año pasado (2021), nos enviará un documento con todo detallado y declaraciones juradas de los acompañamientos a citas médicas. ··········· Lucía también informa "el mes de abril tendremos plazas públicas por si os parece que pueda optar a ella".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2022-01-12','Ana: Entrego a Maribel Ramos, TS Secc. Disc., con NOTA INTERIOR, la RENUNCIA A LA PLAZA DE VIVIENDA TUTELADA, con fecha de 31/12/21. ············ Le envío escaneado a Anabel, TS del SSASB y VT, el documento de Renuncia. ································································································································································································ Envío a Alberto, Jefe secc. ecca., el Suplemento de Actualización de Sumas del Seguro de Decesos relativo a Esteve, que me remite Anabel, TS VT.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-01-12','Ana: Correo-respuesta de Estrella Durán, TS CSS: "...Con respecto al dinero, lo hacemos así por ahora, le sacamos para comprar tabaco solo. Sí, lo del CRR de Plasencia, parece que puede ser que sea pronto, me llamó Mariluz Madrigal hace unas semanas, y estaban pendiente de que quedase una plaza libre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-01-11','Ana: Correo de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es): "Os escribo porque los gastos de bolsillos mensuales que acordamos para Isabel Cano Blázquez se han ampliado este mes, ya que se extrajeron a principios de mes los 150 euros previstos y antes de irse con su madre en Navidad, se sacaron otros 130 euros. Ha vuelto del pase, aquí solo le quedan 13 euros y está demandando comprar tabaco. Entonces tendréis que ver la posibilidad de ampliar esos gastos de bolsillo, ya que va a domicilio muy a menudo..." ······················· Mi respuesta: "Alberto está de vacaciones. ... Yo entiendo que dada la nueva situación, con visitas más frecuentes al domicilio, habrá que reajustar el presupuesto… no obstante, bajo mi responsabilidad (pues tampoco está la jefa de la sección social), autorizo a que retiréis efectivo suficiente para comprarle el tabaco que necesite para estas semanas y el próximo miércoles intentaré reunirme con él para valorar la nueva situación. ¿Por cierto, con respecto al acceso al CRR de Plasencia, que me comentó la propia Isabel en llamada telefónica, qué hay de cierto? ¿se plantea finalmente esta opción? Ya me dices cuando puedas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-01-12','Ana: Correo de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es): "Juan Carlos se volvió a fugar del centro socio-sanitario, sobre las 18 horas aproximadamente. Se informó a la Policía, que lo trajo sobre las 23 horas, protagonizando graves alteraciones de conducta con heteroagresividad física que obligaron al personal de seguridad y a la Policía a intervenir en su contención mecánica. Presentaba claros signos de intoxicación etílica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2022-01-12','TELEFONOS DE INTERES 646970766(Javier) - 639503536(Carmen) - 643669625(María Jesús) - 691795544(Lourdes). Son todos sobrinos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2022-01-12','Ana: Traslado de Isabel a la Res. de Torrecillas de la Tiesa. ············· Llamo a la Res. de Torrecillas de la Tiesa (927 33 80 76): Ana, la Directora, no está. Pero hablo con Ana, Enfermera: me informa que Isabel está un poco nerviosa, pero nada alarmante. Está en su habitación colocando sus cosas. Ya ha estado dando una vuelta por el centro para conocerlo. Realiza muchas preguntas a todo el personal que ve. Dice que va a pedir cambio de centro en cuanto pueda. ··· Ana añade que los primeros días en un cambio suelen ser difíciles, pero espera que se adapte bien. ····························································································································································································Toni-Futuex, informa que Gloria no ha podido acudir a acompañar a Isabel en el traslado, pues está con síntomas y pendiente de PCR. ················ Correo de María, Directora de la Res. Jaraicejo (mariagarciarecio97@gmail.com): "Buenas tardes Ana, sólo comentarte que he acompañado a Isabel Muñoz al ingreso, puesto que iba sola. El ingreso ha ido bien, la veo conforme dentro de lo que cabe. Un abrazo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2022-01-13','-Amalia , envio email a Alberto y Mayte : Buenos días , cuando puedas hablamos de este presupuesto , en principio lo acepto a espera de tu vuelta de vacaciones . Es urgente porque Alonso se encuentra muy mal , mientras nos dan una respuesta de posible ingreso en plaza residencial ,hay que atenderlos en domicilio . Son 3 hermanos , pero el que más cuidados personales necesita es Alonso . Tienen dinero ahorrado . Habría que valorar a nombre de cuál de ellos ponemos este presupuesto pq Alonso ya tiene dos presupuestos a su nombre . De momento lo voy a aceptar y quedo pendiente con la empresa el tema de la facturación. Un saludo . De: Remedios Lozano Baquero >reme_lb@hotmail.com> Enviado: lunes, 10 de enero de 2022 14:52 Para: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es> Asunto: RV: PRESUPUSTO DE ALONSO ORTIZ GERMAN. 45 HORAS. buenas tardes Amalia, creo que te cogías días, pero en principio, te lo envío por aquí. hablando con las auxiliares que están ahora mismo dadas de alta con los hermanos, hemos pensado ampliar el contrato a la que hace los fines de semana y festivos a 45 horas al mes. Asi estarian mas cubiertos y a ella le daría tiempo a dejarlo bien cuidado. Te adjunto el presupuesto de Jaime, que me he adelantado en pedirlo. Considero que esto de momento podemos hacerlo hasta que se valore de dependencia o se solicite ingreso en plaza sociosanitaria. Ya me comentas tu. saludos Reme De: Jaime Sanchez >jaime.sanchez@aoex.es> Enviado: lunes, 10 de enero de 2022 12:44 Para: reme_lb@hotmail.com >reme_lb@hotmail.com> Asunto: PRESUPUSTO DE ALONSO ORTIZ GERMAN. 45 HORAS. Buenas tardes, adjunto presupuesto de Alonso Ortiz German, de 45 horasm , para dar el Servicio en Fines de Semanas y Festivos, el horario sale a 5 horas los sabados y domingos y festivos... El coste hora del Servicio, lo he puesto a precio de lunes a viernes, como ya sabes, el precio es más caro lo Fines de Semana, pero todos tenemos que arrimar el hombre de una manera u otra. Un abrazo -- Jaime Sánchez González Coordinador Servicio Atención a la Dependencia. Asociación Oncológica Extremeña ( AOEx) Telfs: 924207713-673925159.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2022-01-13','-Amalia : envio email a Reme y Jaime ( OAEX) Buenos días , el jefe de la sección económica está de vacaciones , pero dada la urgencia , se acepta el presupuesto de 45 h para ampliar el servicio los fines de semana y festivos. Jaime , si te parece bien , quedamos pendiente para la semana que viene y te confirmo a nombre de cuál de los hermanos ponemos este servicio . Por no facturar todo a nombre de Alonso . Muchas gracias por vuestra implicación , así da gusto trabajar . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-01-13','Ángel. Hablo con Gema (642137837), hermana de Miguel, en relación con la vivienda que su padre le vendió a una pareja que tuvo, Basilia, con la que no estaba casada, ni eran pareja de hecho. El motivo de la llamada es porque han impugnado la venta judicialmente, porque entienden que Basilia se aprovechó de la enfermedad en la que se encontraba el padre de los hermanos. De esta venta supone que Basilia tiene un 83,33% de propiedad y Miguel un 16,33%. Al mismo tiempo, nos indica Gema que esa casa se ha alquilado, con lo que Miguel debe percibir su parte proporcional. Intengo hablar con Gema para que me facilite el teléfono de Basilia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2022-01-13','-Amalia , envio email a Alberto y Mayte : Buenos días , cuando puedas hablamos de este presupuesto , en principio lo acepto a espera de tu vuelta de vacaciones . Es urgente porque Alonso se encuentra muy mal , mientras nos dan una respuesta de posible ingreso en plaza residencial ,hay que atenderlos en domicilio . Son 3 hermanos , pero el que más cuidados personales necesita es Alonso . Tienen dinero ahorrado . Habría que valorar a nombre de cuál de ellos ponemos este presupuesto pq Alonso ya tiene dos presupuestos a su nombre . De momento lo voy a aceptar y quedo pendiente con la empresa el tema de la facturación. Un saludo . De: Remedios Lozano Baquero >reme_lb@hotmail.com> Enviado: lunes, 10 de enero de 2022 14:52 Para: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es> Asunto: RV: PRESUPUSTO DE ALONSO ORTIZ GERMAN. 45 HORAS. buenas tardes Amalia, creo que te cogías días, pero en principio, te lo envío por aquí. hablando con las auxiliares que están ahora mismo dadas de alta con los hermanos, hemos pensado ampliar el contrato a la que hace los fines de semana y festivos a 45 horas al mes. Asi estarian mas cubiertos y a ella le daría tiempo a dejarlo bien cuidado. Te adjunto el presupuesto de Jaime, que me he adelantado en pedirlo. Considero que esto de momento podemos hacerlo hasta que se valore de dependencia o se solicite ingreso en plaza sociosanitaria. Ya me comentas tu. saludos Reme De: Jaime Sanchez >jaime.sanchez@aoex.es> Enviado: lunes, 10 de enero de 2022 12:44 Para: reme_lb@hotmail.com >reme_lb@hotmail.com> Asunto: PRESUPUSTO DE ALONSO ORTIZ GERMAN. 45 HORAS. Buenas tardes, adjunto presupuesto de Alonso Ortiz German, de 45 horasm , para dar el Servicio en Fines de Semanas y Festivos, el horario sale a 5 horas los sabados y domingos y festivos... El coste hora del Servicio, lo he puesto a precio de lunes a viernes, como ya sabes, el precio es más caro lo Fines de Semana, pero todos tenemos que arrimar el hombre de una manera u otra. Un abrazo -- Jaime Sánchez González Coordinador Servicio Atención a la Dependencia. Asociación Oncológica Extremeña ( AOEx) Telfs: 924207713-673925159.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-01-13','-AMALIA Confirmo con Seguridad Social que percibe P. Orfandad de clases pasivas por 672,30€ x 14 pagas . No tiene PFHC , la tuvo antes de percibir la de orfandad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2021-11-27','SALIDAS El 27/11/2021. Salida al mercado navideño de Cáceres y encendido de navidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2021-11-27','SALIDAS El 27/11/2021. Salida al mercado navideño de Cáceres y encendido de navidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='LOPEZ'and apellido2='THOMAS'),'2022-01-13','Ana: Llamada de Esther, TS Serradilla (927 450 036), fue quién promovió el procedimiento de incapacitación y el ingreso residencial. Puesto que la tienen de referencia la siguen llamando a ella. *Me comunica que Antonia ha dado positivo en Covid, está en aislamiento pero asintomática. ········ *Ya está valorada por Dependencia, Grado III. Lo que no sabe es si se llegó a negociar el PIA. La Técnico que le valoró fue Carmen (EVD Plas.). **Ella considera que el mejor centro para Antonia sería LOS PINOS, por ser especializado, ha sufrido un grave deterioro desde que ingresara en el Centro Ntra. Sra. de la Luz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-01-13','-AMALIA Confirmo con Seguridad Social que percibe P. Orfandad de clases pasivas por 672,30€ x 14 pagas . No tiene PFHC , la tuvo antes de percibir la de orfandad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-01-13','Amalia : Copio el email de la psicóloga del CRR , ante la urgente necesidad , hablo con Mayte y se autoriza el pago de las gafas . Adjunto presupuesto de gafas de ver de Emilia Morales Botello. Las necesita, lleva un mes sin ellas con lo que supone para una persona con problemas de visión realizar sus actividades cotidianas y salir a la calle con inseguridad por no poder ver. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-01-13','-Amalia : envio email a su hijo y a la TS : Buenos días , estoy a la espera de que se reincorpore de vacaciones el jefe de sección para valorar ,como te indiqué en el anterior email , bajar esa cantía a 30€ y cancelar los pagos de internet . Cuando se valore el caso te comentaré las decisiones a adoptar Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-01-13','Ana: Paso a Julio, CTAEX, para que de registro de Salida a la Comunicación de Variación de datos (domicilio) para la valoración de dependencia. ············· Una vez registrado se lo remito a Claudia, TS C.R. El Cuartillo (claudia.alonso@salud-juntaex.es) ··················································································· Claudia me informa: "Le está costando un poco adaptarse, suele deambular constantemente, pero por la noche bien. Estamos buscando alternativas con actividades que para poder tenerla entretenida. Estoy segura que al final se va a adaptar bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2022-01-13','De: Remedios Lozano Baquero >reme_lb@hotmail.com> Enviado: jueves, 13 de enero de 2022 11:04 Para: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es> Asunto: BARTOLOME ALBA GRAGERA Buenos días Amalia, qué tal? como ya tengo medio arreglado el tema de Alonso, empezamos con Barto. Nada grave ni grave. tengo tres cosas que comentarte: (igual son más de Alberto, pero ya lo decides tu) -. Entiendo que vosotros sabéis que Barto tiene dos cuentas bancarias. Te lo comento porque yo siempre le he visto una cartilla y ayer me viene con otra distinta. Te adjunto la copia de la cuenta. -. A Barto se le había reducido la cuantía mensual que cobraba, ya lleva más de un mes con la cuantía reducida. Creo recordar de un correo anterior que yo os avisara cuando subir otra vez la cuantía, una vez pasadas unas cuatro semanas. Si podéis, incrementarle la cuantía a los 108 que cobraba antes. -. También quiere solicitar un abogado de oficio para que le quiten la tutela. Se la tengo rellena, pero no sé si puede firmarla el o no. (aunque no le van a dar abogado de oficio con lo que cobra, pero se pone mu pesadito). Ya me dices tu que hago','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-01-13','Ana: Llamo a Sonia Bernabé, ASINDI (669 602 920): valorará con la psicóloga y el resto del equipo si procede que a día de hoy Aarón ingrese en UHDAC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-01-12','Ana: Soraya Masa, jefa de Ud. de PP.AA., me comunica que Aaron es el siguiente en la lista de espera para UHDAC, hay que valorar si a día de hoy es necesario o contraproducente el ingreso de Aarón en la misma. ············ Lo hablo con Maite, Jefa sección CTAEX. ········ Llamaré a Sonia Bernabé para que nos informen de la situación actual y de la valoración que hacen al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2022-01-13','Ana: Llamo a la Res. de Torrecillas de la Tiesa (927 33 80 76): Ana, la directora, no está. Pero me informan que Isabel está bien, tranquila y come bien. Habla mucho y hace muchas preguntas pero bien. ············· Le facilito mi nº telf. y correo directos por si necesitasen contactar. ················································································· **Guardo Resolución de traslado a la Res. de Torrecilla de la Tiesa en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='SERRANO'and apellido2='TRANCON'),'2022-01-12','Ana: Llamada de Fátima, Ed. Asociación Vera: Agustín ha estado ingresado en el hptal. de Plasencia desde la noche del domingo 2 al viernes 7 con INSUFICIENCIA RESPIRATORIA, ya está bien y de vuelta en el centro. *NO ha tenido covid. *Tampoco se le ha puesto acompañamiento, pues dada la incidencia de contagios no se permitía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-01-13','Ana: Llamada de Fátima, Ed. Asociación Vera: tras el periodo de estancia con su familia, Adrián no quería volver al centro el día de Reyes. Pero le llamó Fátima, Ed. y le convenció. ············ Adrián pide que solicitemos un cambio de centro más cercano al domicilio familiar. ········ Lo valoraré con Maite.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-01-12','Ana: Estrella Durán, me informa que mañana día 12 Isabel tiene entrevista en el CRR - Plas. de cara al posible ingreso en el mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2022-01-13','-Amalia : en su expediente he archivado informe del psiquiatra con respecto al carnet de conducir. Escribo al CRR : según la respuesta que da el psiquiatra , será el centro de reconocimiento el que debe determinar si tiene capacidad y en su caso si necesitan un informe complementario , ha de ser Trafico el que se lo pida . En otro caso similar que se nos dió el informe fue previo y el usuario se ahorró entre otras cosas ,el coste económico del mismo. Si Rubén insiste en el tema , tendrá que llevar este informe al centro y estaremos pendientes de la respuesta que le den .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-01-14','-Amalia : recibo email de Paula : Buenas tardes Amalia, comentarte que José Vicente Vicente está de nuevo en el CP de Badajoz.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-01-14','-Amalia : recibo email de Paula : Buenas tardes Amalia, comentarte que José Vicente Vicente está de nuevo en el CP de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2022-01-13','SALIDA La Providencia dixit: "Se encuentra en Villafranca con uno de sus hermanos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2022-01-13','SALIDA La Providencia dixit: "Mañana se irá al domicilio de su tía en Zafra. Estará hasta el viernes próximo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-01-14','-AMALIA : Me llama M.Jesús ( tf. 699993177) me dice que quiere tratar varios temas : -Se le ha pasado la cita del CADEX del 31 dic. solicitaré una nueva. -El lunes le hacen contrato laboral con ACNUR , con un salario de 910€/ mes , captando persoanal que colabore con la ONG en la calle . Le pido que me envíe contrato por email para comunicarlo a PNC. -Quiere solicitar alta voluntaria en pisos supervisados y buscarse una habitación compartida en un piso en Mérida . Va a esperar a que se incorpore la nueva psicóloga al piso y empieza a buscar alquiler . -Quiere anular su tutela , esperará a que el juzgado la llame de oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-01-14','-AMALIA : Me llama M.Jesús ( tf. 699993177) me dice que quiere tratar varios temas : -Se le ha pasado la cita del CADEX del 31 dic. solicitaré una nueva. -El lunes le hacen contrato laboral con ACNUR , con un salario de 910€/ mes , captando persoanal que colabore con la ONG en la calle . Le pido que me envíe contrato por email para comunicarlo a PNC. -Quiere solicitar alta voluntaria en pisos supervisados y buscarse una habitación compartida en un piso en Mérida . Va a esperar a que se incorpore la nueva psicóloga al piso y empieza a buscar alquiler . -Quiere anular su tutela , esperará a que el juzgado la llame de oficio.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2022-01-14','Angel envía email al abogado Angel Calle para que nos envíe el testimonio de firmeza','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-01-14','llega email de la trabajadora social del centro penitenciario: Buenos días Miguel! Decirte que he estado de vacaciones y por eso no te he podido contestar antes. Te he llamado en varias ocasiones durante esta semana. Te informo de que para que yo pueda realizar un informe social me lo tiene que pedir de oficio el Juzgado. De todas maneras creo que el informe social no sería lo más adecuado dado que yo en mi informe no haría constar las patologías que presenta el interno y ,que por otra parte desconozco, debido a que no soy la profesional indicada para eso y sí un médico, psiquiátra/psicólogo. Gracias y saludos!!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-01-17','miguel, remito email a Carmen Lucas la abogada: Buenos días Carmen, he estado de vacaciones por lo que acabo de ver los emails. Como puedes ver en el email de más abajo, la trabajadora social del Centro Penitenciario no nos remitirá informe alguno. Lo único que ha podido obtener la Comisión Tutelar es este informe médico que te adjunto, y que junto con la sentencia de incapacitación no sé si servirá para tu escrito de defensa. No disponemos de más información','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2022-01-17','-Amalia : se pone en REgistro CADEX solicitud H.Funcional','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-01-17','Maite: José Maria ingreso en Hermanas Hospitalarias el 2 de diciembre, de Palencia. Durante su estancia allí ha estado tranquilo. Tb ha pasado el Covid. El 12 de enero de 2022 ha sido trasladado a un centro en Avila, Mentalia Arévalo. De momento la adaptación es buena. El contacto en el centro es la trabjadora social, Modesta ( 920 30 14 00).tsocialpsiquiatria.arevalo@mentaliasalud.es','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-01-10','Ana del Sch me confirma que necesita la firma del gerente y del curatelado en la misma mañana','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-01-17','miguel, cierro la fecha de 27-1-22 para las 9h ir con el gerente a una oficina del Sch de Mérida para desbloqueo y transferencia del fondo de inversiones. Una vez esto iré a Badajoz donde a las 12,40h quedaremos en la puerta del Edificio Sara donde Amalia (va a citar a la familia y curatelado) reservará la sala para que la directora del Sch vaya con la documentación y firmemos. Intentare que asista el abogado de la otra parte además de Amalia y yo y la familia con el curatelado. ********************************************************** Envío email a Ana del Sch : Buenos días Ana, ya estoy incorporado al trabajo. Me han dado cita con el Gerente para poder firmar el jueves día 27-1-22 a las 9,15h en la oficina del Santander de Mérida. Por favor organiza oficina y persona de contacto a la que dirigirnos para que ese día esté todo preparado. El documento que firme el Gerente yo me lo llevaré a Badajoz esa mismo día y quedamos contigo (en el edificio Sara a partir de las 12,40h) para que firme la documentación que tu lleves el curatelado. Yo asistiré acompañado de la trabajadora social, el abogado de la otra parte Carlos Jurado e intentaremos que al curatelado le acompañe su familia. Cualquier duda ponme un email o llámame ******************************************************* Envío email al abogado de la otra parte Carlos Jurado: Buenos días Carlos, ya estoy reincorporado al trabajo. Hablé con la directora Ana del Sch y necesita que en la misma mañana firmen el Gerente y el curatelado el desbloqueo y la orden de transferencia. Intentaremos que sea todo el día 27-1-22, mira el email de más abajo y si tienes duda dimelo. Necesitaría que asistieras a las 12,40h del jueves 27 para explicar todo sobre la marcha al curatelado y firmarlo. Por otra parte aunque no nos lo exigen sería conveniente liquidar el impuesto de sucesiones para evitar problemas (por posible donación) con lo que si puedes llevar preparado el modelo relleno yo podría llevarte una autorización del gerente para que hagas la gestión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-01-18','Amalia : respondo a su email : Buenos días Mª Jesús , veo que ya has iniciado la búsqueda de piso , parece que tienes varias opciones . Ya se ha incorporado la psicóloga ?? tienes que esperar un poco para que ella informe de tu situación actual , te parece bien ? Qué tal va lo del trabajo ?? te han hecho contrato ?? acuérdate de enviarme una copia para comunicarlo a PNC. Cómo te encuentras ?? qué tal vas en el piso ?? Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-01-18','Amalia : respondo a su email : Buenos días Mª Jesús , veo que ya has iniciado la búsqueda de piso , parece que tienes varias opciones . Ya se ha incorporado la psicóloga ?? tienes que esperar un poco para que ella informe de tu situación actual , te parece bien ? Qué tal va lo del trabajo ?? te han hecho contrato ?? acuérdate de enviarme una copia para comunicarlo a PNC. Cómo te encuentras ?? qué tal vas en el piso ?? Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='GONZALEZ'and apellido2='SILVA'),'2022-01-18','miguel, me comunica Iciar que de Caixabank han embargado al menos 1.000€ a la tutelada. Me reenvía lo que le han mandado del centro y abro una carpeta virtual para reclamar (igual que hice con su hermano Fco a TGSS y Prestaciones de la Junta). Iciar me remite informe social del centro y fotocopia de movimientos de las cartillas ya que Caixabank no le facilita datos. ***************************************************** Envío email a Ana solicitandola los certificados médicos anteriores y posteriores a nuestro nombramiento para demostrar que no estaba capacitada para personarse en el procedimiento incluso antes de nuestro nombramiento. Asimismo le solicito que se haga con cartas o notificaciones que le hayan enviado en relación al embargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-01-18','Hola Amalia, José Vicente finaliza medida de seguridad el 30 de Marzo, pero le quedan por cumplir 2 años más. Tenéis que cambiar la cuenta de peculio a Badajoz. Muchas gracias por tu información. Un saludo PAULA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-01-18','Hola Amalia, José Vicente finaliza medida de seguridad el 30 de Marzo, pero le quedan por cumplir 2 años más. Tenéis que cambiar la cuenta de peculio a Badajoz. Muchas gracias por tu información. Un saludo PAULA Buenas , ha sido trasladado al Ctro. penitenciario de Badajoz , hay que cambiar la cuenta peculio . Mantenemos la misma cantidad estipulada . Un saludo . Pido cambio en lista de domicilios a JUlio Envio email a Seccion eco:','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-01-18','miguel, remito al nuevo arrendador (Fco Jesús Mariñas Perez; email: chiquimarina@hotmail.es) por email el nuevo contrato para que lo complete y me lo envíe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-01-18','recibo email de Damian: No he querido reunirme con futuex ya que el centro la reunión que tuvo la administrativa Raquel con la parte económica se me pautó 5 euros diarios y se sacaba 500 euros al mes a ver si usted puede hablar con la parte económica para que le transmita al centro mi deseo de cobrar 7 euros diarios me puede ayudar por favor? Ya sé que se me dan extras pautados pero para mi cumpleaños que es el próximo 5 de febrero quiero recibir un extra.y una cosilla en la carpeta tengo ahorrado unos 600 euros y me hacen falta 5 camisetas más para el gimnasio ya que ayer me gasté 100 euros en ropa de decatlón 7 pantalones cortos 5 camisetas y 3 pares de calcetines y me haría falta un bolso grande para la ropa del gimnasio y 5 camisetas más por favor ayúdeme por lo menos que me suban la asignación diaria a 7 euros por favor.espero su contestación porque ha venido hoy futuex pero no he querido hablar con ellos porque no se me solucionan mis peticiones y en la carpeta se sigue acumulando dinero se lo pido por favor que me suban la asignación a 7 euros diarios hay compañeros que cobran de asignación mucho más que yo y ahora con la subida de la pensión cobraré 1500 euros aparte que ya no tengo deudas como tenía antes con entidades privadas estoy limpio de deudas ayúdeme por favor señor Miguel que hable la parte económica con el centro*************Intente me ayudar por favor que me sobra mucho dinero todos los meses*************No he querido hablar con ellos porque ellos no me van a ayudar en mis temas económicos transmitaselo a la parte económica y que ya hay 600 euros ahorrado hay en la carpeta*****************************Me gustaría porque no estoy contento que me den una cita para yo hablar personalmente con la parte económica ya que el dinero es mío y yo también quiero que me ayude en mis derechos a cobrar 7 euros diarios se lo pido por favor********************************* Los remito a ctutelar a la A/A parte Económica************** Contesto a Damian:Buenos días Damian, como ya sabe todas las peticiones debe realizarlas a través de Gisela que a su vez hablará con la trabajadora social Amalia de la Comisión Tutelar. Este tipo de email debe enviarlo a ctutelar@salud-juntaex.es ya que desconozco estos asuntos económicos como bien sabe. Cualquier otra cuestión debe tratarla por los cauces habituales que le he comentado la trabajadora social Amalia en otras ocasiones, es decir a través de Gisela. Desde la parte jurídica no podemos atender otras cuestiones que no sean estrictamente jurídicas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO'and edp.apellido1='CUEVAS'and apellido2='MOYANO'),'2022-01-18','miguel, email de Ana Lucas (abogada): Buenas tardes Miguel Angel, voy a pedir la libertad provisional, y que os hagáis cargo vosotros puesto que está bajo vuestra tutela de él ¿Qué medios tenéis para evitar fuga, centros etc…? y además caso de que lo estimen oportuno una medida cautelar menor gravosa para este Sr. y te repito ¿Qué Centros tiene la junta para cumplir este tipo de medidas personas de estas características? El hermano de este Sr (que creo no es el indicado, sería la Junta) sigue insistiendo, así que a ver cómo lo enfoco, te ruego me des la informacion que te pido, saludos.************************************************** Envío email a Ana Ts:Buenas tardes, para cuando vuelvas, me pregunta la abogada qué centros y medios tenemos porque va a pedir prisión provisional…Necesitaré un informe desde vuestra parte social para remitírselo.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-01-18','miguel, envío email a Ana Ts: Ana, ha llegado una nueva notificación de la AEAT, sé que Angel estaba viendo algo, incluso que iba a hablar con la pensión porque se le había embargado alguna cantidad, para no pagarles algún mes… La cuestión está en que hay que sacarle de esa pensión y llevarlo a otro sitio antes de que acabe el mes porque si se lo descontamos a la pensión le van a echar seguramente. Una vez que lo tengas (antes de que acabe el mes) necesitaría un justificante que acredite su nueva residencia y un certificado de empadronamiento de su nueva residencia para comunicarlo a hacienda. Ya lo he visto con Estrella y estaba sin cancelar la orden de domiciliación mensual a la pensión de 600€. Esta mañana ya por fin (no sabemos porque no se ha hecho antes)se ha cancelado la orden mensual de transferencia a la pensión. La cuestión será ver si AEAT no le reclama con carácter retroactivo alguna cantidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='MINERO'and apellido2='PEGUERO'),'2022-01-18','EXITUS Fallecido el 18/01/2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-01-19','Ana: María, Aux. secc. ecca.: me informa que el día de ayer habló con Anabel, de la Empresa de SAD. Aún no han solucionado el problema con Hacienda. Hasta ahora se ha seguido abonando el servicio a la empresa. **Hoy le comunicará que en febrero se pagará ya a Hacienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-01-19','Ana: Solicito por mail a Toni-Futuex, que ayuden a José a buscar una nueva pensión y se traslade, a ser posible, antes de que acabe el mes.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-01-19','Ana: Solicito por mail a Toni-Futuex, que ayuden a José a buscar una nueva pensión y se traslade, a ser posible, antes de que acabe el mes. Pido también que le acompañen a empadronarse y nos remitan tanto el certificado de empadronamiento como un justificante de la pensión en que se indique que reside allí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-01-19','Ana: Correo de Miguel: "me pregunta la abogada qué centros y medios tenemos porque va a pedir prisión provisional…Necesitaré un informe desde vuestra parte social para remitírselo." ············· Mi respuesta: "Buena Miguel, Para empezar, puedes explicarle, que la CTAEX NO dispone de centros ni recursos propios. Si va a solicitar que salga de prisión, habría que solicitar centro por la misma vía que el resto de ciudadanos/as extremeños/as. En este caso tendría que ser de la Red de Salud Mental, y no sé si dado el perfil y la medida judicial, si le van a aceptarle en un CRR (Centro Residencial de Rehabilitación), al que por otra parte tendrían que derivarle desde el Salud Mental (el Psiquiatra que firma el último informe), nosotros no podemos solicitar dicha plaza. Por otra parte, sé que en la actualidad, hay lista de espera por no haber plazas libres en ninguno de ello. Dicho todo esto, supongo que la única alternativa que queda, y podría solicitar la abogada, sería Centro Sociosanitario. En Extremadura hay 2 (uno en Plasencia, que sería el que correspondiera por domicilio y otro en Mérida). *En estos centros nosotros tampoco podemos solicitar plaza, se ingresa por orden de Psiquiatras o para cumplimiento de medidas judiciales si así se indica en resolución judicial. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-01-13','Ana: Una vez me facilita Icíar el nuevo número de cuenta, llevo a Registro la Comunicación al INSS de Variaciones de Datos Bancarios. ··········· Guardado documento en el exdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-01-19','Ana: Envío a Pilar, ESM CC, las páginas pertinentes de la solicitud de dependencia para la Revisión PIA y solicitud de ACCESO A CRR. *Julio le da registro de salida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-01-19','Ana: Correo de ayer de Estrella, TS CSS: "Te escribo para comunicarte que Alfonso Marín se va de alta a su domicilio el viernes próximo día 21. Se le comunica también a Gloria de Futuex, Cáceres." ····················· Mi respuesta: " Buenas, de nuevo, Estrella, En relación a Alfonso, ¿no hay posibilidad de que pasara primero por CRR o incluso por Piso Supervisado? Como ya te planteé en su día? Desde la CTAEX no vemos claro que vuelva al domicilio, donde llevaba una vida desordenada, sin hábitos alimenticios, horarios, ni de higiene mínimamente adecuados y en aislamiento social. Ni siquiera Gloria, que como sabes es la Educadora que hacía el seguimiento en su domicilio, podía tener acceso al mismo, pues durante el día dormía o se encerraba en su cuarto… la compañera sólo podía contactar y visitar a su madre. Agradeceríamos se valorara esta posibilidad. Pongo en copia a Maite, Jefa de sección."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-01-19','Ana: Tras conversaciones, tanto con Estrella, TS CSS, como con Francisca, madre de Isabel, remito correo a Alberto y Julio, CTAEX: "Comunicaros que desde hoy, ISABEL CANO BLÁZQUEZ, está residiendo en el CRR de Plasencia - Julio: ¿Podrías actualizarlo en la base de datos? - Alberto: Como sabes este centro es gratuito, pero habrá que adaptar presupuesto de gastos de bolsillo (ella pide 200€) y, supongo, habrá que acordar con el centro “extra anual”. No sé qué propuesta harán desde el CRR. Supongo que Paula se pondrá en contacto al respecto. - Alberto: Por otra parte, su madre, solicita los 20€ habituales, pera acudir a visitarla la semana que viene. Lo necesitaría para el 24-25, se le puede hacer mediante transferencia, como siempre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2022-01-19','Ana: Correo de ayer de Alfredo Moreno Cebrián (residenciaplasenzuela21@gmail.com): "Buenos días, Ana. Antonia Serrano Suárez sigue ingresada en Cáceres, su estado de Salud, según el Médico Internista, es estable "dentro de la gravedad" el viernes tuvo fiebre. De momento es lo único que te puedo decir, te seguiré informando según me lleguen noticias."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2022-01-19','Ana: llamada de Jairo: comienza diciendo que necesita los 100€ semestrales para ropa. Por otra parte, necesita unas gafas graduadas nuevas, las que tenía se le rompieron hace 5 meses, dice. ····· A partir de aquí, comienza a decir que quiere renunciar a su pensión, pues no quieres ser dependiente, y a hilar un discurso totalmente inconexo y sin mucho sentido. ······················· Envío correo a Alberto, jefe secc. ecca. con las demandas económicas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-01-19','miguel, tras hablar con Ana Ts, remito este email a la abogada Ana Lucas: Buenas tardes, me comenta la compañera trabajadora social de la Comisión que la CTAEX NO dispone de centros ni recursos propios. Tampoco tienen prioridad sobre otros ciudadanos externos a la Comisión a la hora de asignarles centro. El tipo de Centro depende de la decisión del Psiquiatra (Guendolina Andrés Pereira, del Equipo de Salud Mental de Cáceres, tlfno 927-213730). Lo único que ha remitido la psiquiatra es ese informe donde no especifica si recomienda o no que vaya a un centro, ni a cual, para que sea el juez quién en la resolución así lo acuerde. La otra vía, es cuando hay una descompensación, el psiquiatra activa el 112 y pueden internarlo en un centro hospitalario. Y esta es la opinión de nuestra trabajadora social: “Si va a solicitar que salga de prisión, habría que solicitar centro por la misma vía que el resto de ciudadanos/as extremeños/as En este caso tendría que ser de la Red de Salud Mental, y no sé si dado el perfil y la medida judicial, si le van a aceptarle en un CRR (Centro Residencial de Rehabilitación), al que por otra parte tendrían que derivarle desde el Salud Mental (el Psiquiatra que firma el último informe), nosotros no podemos solicitar dicha plaza. Por otra parte, sé que en la actualidad, hay lista de espera por no haber plazas libres en ninguno de ello. Dicho todo esto, supongo que la única alternativa que queda, y podría solicitar la abogada, sería Centro Sociosanitario. En estos centros nosotros tampoco podemos solicitar plaza, se ingresa por orden de Psiquiatras o para cumplimiento de medidas judiciales si así se indica en resolución judicial”. En conclusión, la única opción pasaría porque hablara con la psiquiatra que ha tratado a Saturnino (Guendolina Andrés Pereira, del Equipo de Salud Mental de Cáceres, tlfno 927-213730) y le hiciera un informe con el contenido que menciona en su email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-01-19','Ana: Correo del lunes de Estrella Durán, TS CSS: "Hemos mantenido esta mañana reunión con Soraya Masa y Maite, tu Jefa de Sección. Éstas nos han manifestado que, vais a hacer una visita a Juan Carlos próximamente, con objeto de ponerle de manifiesto que se está buscando centro para él y vea que, tanto vosotras como nosotras, les damos el mismo mensaje. Por nuestra parte, esa visita la podéis hacer cuando queráis y os rogaríamos que a la mayor brevedad posible."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-01-19','Ana: En relación a la llamada de Julia y Julia, madre (644 876 893), envío correo a Toni-Futuex: "Me dice Julia que le entregó a Gloria unas facturas pendientes de abono. Ya le he recordado en modo de proceder, pures no ha solicitado autorización previa… No obstante, se las pasaré a Alberto y veremos. Así que pasárnosla cuando podáis."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2022-01-19','Ana: Conversación con Javier: plantea las demandas habituales. *Le explico que ha de tener paciencia, pues aunque se ha aceptado su acceso a CRR aún no hay plazas disponibles. ··············· *En cuanto a la posibilidad de pasar a URH, se niega, dice que está bien donde está y no quiere cambiar. Sólo acepta el paso a CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-01-20','Maite: Sonia ha enviado correo electrónico:Hola Maite, te comunico en relación a la solicitud de Aaron a la UDAC, que tras valorar su comportamiento actual, tras varios meses de intervención, seguimiento y de adaptación del entorno, va evolucionando favorablemente y no es tan grave como cuando se solicitaba el recurso, por lo tanto, seguiremos en la misma línea en su programación individual aquí en ASINDI. Esperemos que no precise del recurso en un futuro. Un saludo,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-01-21','Ana: Tras hablar con Estrella y Maite (CTAEX): envío correo a Toni-Futuex: "Buenas tardes Toni, En relación a MARTÍN DOMINGUEZ PALENCIA, añadimos al trabajo habitual más cuestiones de “investigación”, gracias a la carta de pago del OAR que os adjunto, vemos que tienen varios vehículos, dos motos y un tercero con esta matrícula 6315KMP que no tenemos claro si se trata de un coche o moto. De vez en cuando le pasan también multas, como la que aparece en la carta. Necesitamos saber qué uso da a estos vehículos, si tiene garaje propio (lo suponemos por el VADO que también le cobran) . Además tendremos que ver, si quiere vender alguno de los vehículos y en la próxima revisión en ESM (si es que asiste) valoren si está en condiciones de conducir… más que nada para comunicarlo al Juzgado y a Tráfico en tal caso, porque a día de hoy sigue siento CURATELA ECONÓMICA…. Y de las anteriores comunicaciones al Juzgado aún no hemos obtenido respuesta… En fin, seguimos en contacto!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2022-01-21','Ana: Estrella CSS, me comunica que ha fallecido la abuela de Carlos Alberto, consideramos que tiene que ir al funeral. **Solicitarán taxi para acudir a la localidad de Villar del Ciervo (Salamanca). *Como no está Albero, Jefe de secc. ecca. autorizo yo. *A posteriori enviarán la factura. ················· Más tarde Estrella, TS, envía el siguiente correo: "Os comunico que, mañana a las 9 de la mañana, irá Carlos Alberto Vicente Calderero al funeral de su abuela, a la localidad de Villar del Ciervo provincia de Salamanca, acompañado de dos Auxiliares de Enfermería, Ana Iglesias y Milagros Garrido, regresando al centro, aproximadamente, sobre las 14 horas, cuando finalice dicho funeral. Para ello hemos pedido dos presupuestos a taxistas de Plasencia: José María Gil 190 euros Néstor Alcón 240 euros. Pedimos el servicio a José María Gil."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2022-01-21','Ana: Entrego a Julio, CTAEX, oficio y todos los documentos remitidos por la residencia de Torrecilla, excepto el del banco, debidamente firmados y sellado para que dé registro de salida y los remita también por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-01-21','Ana: Adelanto por mail a Estrella Duran, TS CSS, y a Paula, TO CRR, el documento relativo al ingreso, debidamente firmado y sellado. *Se lo entrego también a Julio, CTAEX, para que lo registre y remita por correo certificado. ······························································································································ Envío a Alberto la propuesta económica del gasto que remiten desde el CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2022-01-24','Ana: Correo del viernes por la tarde de Alfredo Moreno Cebrián (residenciaplasenzuela21@gmail.com): "Buenas tardes, Ana. Nos Informan del Hospital que Antonia Serrano está un poquito mejor, pero que sigue dando positivo en Covid. Le van a hacer un ciclado y si todo va bien probablemente el lunes le darán el alta. En el momento que se produzca el alta, o si hubiera alguna incidencia te informo. Un Saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-01-24','miguel, envío nuevo email a la directora del Sch Ana Perez: Buenos días Ana, necesito me indiques oficina y persona de contacto ir el jueves 27-1-22 a las 9h, para el desbloqueo del fondo de inversiones. Una vez firmado traeré en mano el documento original para entregártelo a la 12,45h en el edificio Sara donde ya tenemos reservada la sala. Llevaré el original de la orden de transferencia que te comenté. Si a parte del documento adjunto hace falta algo más por favor dimelo. Estará la familia y el abogado de la otra parte. **************************************************** Envío email a Carlos Jurado (abogado de las hermanastras del curatelado): Buenos días Carlos, te reenvío email que he enviado a la directora del Sch Ana Perez. Si no te importa pasa por allí el miércoles para que te confirme que todo está ok. Queda porque nos diga en qué oficina de Mérida tiene que firmar nuestro gerente (representante de la Comisión Tutelar de Adultos) Cualquier duda dimelo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='LOPEZ'and apellido2='THOMAS'),'2022-01-24','Ana: Tras recibir correo Carmen Martín, TO EVD-Plas. (carmen.martinmon@salud-juntaex.es): subo al portafirmas las Aceptaciones PIA para plaza pública en centro especializado (CR Los Pinos de Plasencia) y para Prestación vinculada al SAR. *El Alta de Terceros, tras recabar la firma del D.Gerente, se lo entrego a Icíar para que lo lleven al banco cuando vayan. ······························································································································································································ Una vez firmados los documentos, envío correo-e a Carmen Martín: "...Te envío la ACEPTACIÓN PIA para plaza en C.R. Los Pinos de Plasencia firmado digitalmente por su Curador Representativo. Ya le he pasado a las compañeras de la sección económica el Alta de Terceros firmado también por el Representante para que lo lleven al banco. Posiblemente puedan ir la semana que viene al banco. Cuando me lo devuelvan te lo envío también junto a la ACEPTACIÓN de la prestación vinculada al SAR. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2022-01-24','Ana: Una vez me devuelven las compañeras de la secc. ecca el Anexo I – "Impreso de Domiciliación Bancaria de Recibos Periódicos", se lo entrego a Julio, Aux. Admvo. CTAEX, junto con el oficio, para que le dé registro de salida y lo envíe por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-01-24','miguel, llega carta ordinaria del Defensor del Pueblo para que le informemos de la petición de ingreso en centro que hace su hermano Tomás (y que ya pidieron en noviembre de 2021), contestación: Buenos días, con fecha de hoy 24-1-2022 ha llegado a esta Comisión Tutelar de Adultos por vía carta ordinaria el escrito adjunto del Defensor del Pueblo en relación al tutelado D. Saturnino Salgado Jimenez. Actualmente este tutelado (curatela representativa conforme la nueva ley 8/2021, 2 junio por la que se reforma la legislación civil y procesal para el apoyo a las personas con discapacidad en el ejercicio de su capacidad jurídica), se encuentra cumpliendo condena por el procedimiento arriba indicado y que se adjunta. El estado actual del procedimiento es el escrito de defensa que ha realizado su abogada y que también adjuntamos. En él se ha incorporado los informes médicos que ha logrado obtener esta Comisión Tutelar. Por otra parte se ha intentado obtener informe social del equipo de trabajadores sociales del Centro Penitenciario, ya que esta Comisión Tutelar no dispone de información para realizar el mismo, siendo la contestación de la trabajadora social del centro penitenciario “Te informo de que para que yo pueda realizar un informe social me lo tiene que pedir de oficio el Juzgado. De todas maneras creo que el informe social no sería lo más adecuado dado que yo en mi informe no haría constar las patologías que presenta el interno y ,que por otra parte desconozco, debido a que no soy la profesional indicada para eso y sí un médico, psiquiátra/psicólogo”. Se adjunta informes médicos que se remitieron a la abogada defensora Doña Carmen Lucas (mlucasduran@icac.es> c/ San Antón, 6 1º B, 10003 Cáceres Teléfonos y Fax: 927 226664 y 927226673, 627597037) , junto con la respuesta de la trabajadora social del Centro Penitenciario que obra en el email de debajo, y junto con los 3 escritos recibidos por la abogada, en el cual podrán comprobar que la supuesta víctima (hoy fallecida) dejó un hijo menor cuya protección quieren desde el juzgado la asuma la junta de Extremadura. Se adjunta también sentencia judicial y nombramiento a la Comisión Tutelar de Adultos. Entendemos que el equipo de salud mental de la Gerencia del Area de Salud de Cáceres, y en concreto la Dra Guendolina Andres Pereira, es quién tiene que dictaminar si ve necesario o no el traslado del tutelado a un centro adecuado para el cumplimiento del resto de la pena, tal como pide su hermano Tomás. No obstante, es necesario para el tratamiento de cualquier enfermo y por ende para su ingreso en un centro, que se encuentre desintoxicado. Desde esta Comisión Tutelar de Adultos no consta más información con lo que deberán ponerse en contacto con el Juzgado para cualquier otra cuestión, ya que desde esta Comisión se cumplirá, como no puede ser de otra manera, con la resolución judicial que se dicte. Quedamos a su disposición para cualquier otra aclaración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-01-24','Ana: Llamo de José Luis, hermano de José Manuel (687 581 061): en cuanto a la avería del baño, se está encargando él de lo que puede. Nos pasará factura de los sanitarios que hay que cambiar. ··········· Comunica que el calentador sigue averiado, pediré a Futuex que soliciten presupuestos para un termo eléctrico de 50 litros. ·········· Me comunica también que su hermano ha dejado de acudir al comedor social y que además el hijo ha vuelto a casa con él... ································································································································································································ **Llamo a Toni de Futuex: Volverán a asignarle el seguimiento a Virginia, Ed. ········ Nos facilitarán un par de presupuestos de otros 2 cáterin distintos, el anterior, "Qué bueno", ha dicho que no quiere tenerlo como cliente. ····· Por últimos, solicitarán también presupuesto para un termo.','1');
