insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2022-01-25','TERESA Mª ANTONIA FERNÁNDEZ SALGUERO, demanda desde hace tiempo ponerse implantes en la boca. Se le ha llevado al especialista y le han realizado un tac para comprobar si su boca es apta para los implantes. Los resultados han sido favorables por lo que os mandamos los presupuestos que nos ha dado el dentista para ver se dispone de saldo suficiente. PRESUPUESTO 1: 13.200€ PRESUPUESTO 2: 18.008,50€ SE ACEPTA PRESUPUESTO MAS ELEVADO NO ES NECESARIA PEDIR LA AUTORIZACION JUDICILA CON LA NUEVA LEGISLACION YA QUE TENEMOS EL DESEO EXPRESO DE LA CURATELADA DE QUERER LA PROTESIS Y ADEMAS ES UNA NECESIDAD','2');
