insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2022-01-26','miguel, recibo llamada del hermano del tutelado, (Lorenzo 678-731543 e email lorenzogarcia1950@hotmail.com) e intercambiamos nuestros datos de contacto porque comenta que en notaria tienen la documentación para la firma de la herencia de su madre (su padre falleció también hace años). Comenta que el Impuesto de Sucesiones ya lo liquidaron y que necesitaran la firma de la herencia y la autorización judicial de venta. Le comento que necesitaremos abogado, tasar las fincas y toda la documentación por lo que le pido que la notaria se ponga en contacto conmigo para ver todo lo que tiene y lo que pueda faltar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2022-01-20','miguel, recibo email de Maite Ts: He hablado con Beni, la casera del piso alquilado para Catalina Miranda. Hace varias demandas: • Por un lado, plantea qué se va a hacer con el contrato pq caducó en el mes de Octubre de 2021. • También pide subir algo el aquiler , con arreglo a la subida del IPC. Se paga lo mismo desde hace tres años. • Manifiesta las malas condiciones en las que vive Catalina. Hay mucha suciedad en la casa, huele todo a tabaco y está todo amarillo pq no limpia, no ventila….. pide que alguien vaya a ver la casa para ver en las condiciones que está.','2');
