insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2022-01-25','miguel, Buenos días Amalia, en relación al email que me mandó Maite y que dejo debajo, he preguntado a la parte económica. Estrella me comenta que en la conversación de la arrendadora de Catalina Miranda Rosado habla que quiere que alguien entre en la vivienda y compruebe el estado de todo y las condiciones que está. Ya que ella no quiere que entre nadie y sólo pone excusas. Una vez que me confirmes (que te hagan un informe del estado de la vivienda), procederemos a hablar con la dueña para que nos diga qué modificaciones quiere en la actualización del contrato de alquiler (subida de la cuantía y el IPC me indica Maite en su conversación del jueves 20-1-22), y tras verificar con la parte económica que esté de acuerdo procederemos a actualizarle el contrato de alquiler. Por tanto, manda, imagino que a Futuex para que te haga un informe de cómo está la vivienda y a partir de ahí hacemos lo demás.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2022-01-26','Ana: Envío correo a Toni-Futuex: "Buenas tardes Toni, Te llamé, pero estarías conduciendo o algo. En relación a SANDRA SANDIN HERNÁNDEZ, nos han escrito del banco porque ha acudido a la sucursal acompañada de la educadora para retirar la asignación y no tenían el escrito. Es normal que no lo tuvieran porque desde aquí no se ha enviado nada… La cuestión es que en inicio Sandra, si recordáis, el padre de Sandra era el que se hacía cargo de todos los gastos y no pedían autorización de retirada de efectivo, en ningún concepto. Entendemos que ahora lo que quiere es para gastos de bolsillo, por favor, ¿podríais hacer un presupuesto aproximado mesual para que se pueda autorizar y enviar el escrito al banco? Gracias. Seguimos en contacto."','2');
