insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2022-01-28','Ana: Recibimos escrito de PNC-Andalucía, "Con motivo de la devolución de los importes mensuales de la pensión..." le citan en la delegación de Málaga. ····· Icíar me informa que le han bloqueado la cuenta bancaria, la que tenía en el banco Santander, además de seguir sin añadir a Representante Legal en al misma. ····························································································································································································· Llamo a David Barea - PNC Andalucía (679 773 137): para solucionar el problema podemos hacer un escrito solicitando le ingresen las mensualidades impagadas en nuevo CCC por haber tenido problemas con la entidad bancaria indicada en la solicitud. *El ingreso se lo harán junto a la mensualidad de marzo, pues la nómina de febrero ya está cerrada. *Acordamos que una vez registrado en ORVE el escrito, se lo adelantaré por mail (david.barea@juntadeandalucia.es)','2');
