insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2022-01-28','miguel, vuelve a llamar Coro para saber si ya nos ha enviado la firmeza judicial el abogado(todavía no)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-01-28','miguel, me llama su hijo Jesús, que actualmente dice ser el único heredero de su madre porque su hermano ha fallecido hace pocos días. Quiere ocupara la vivienda que en su día fue domicilio familiar. Le doy el correo electronico de ctutelar para que nos lo solicite y lo hable con Alberto, aunque no veo problema ya que su madre reside ya en centro, y él se haría cargo de sus gastos de luz y agua','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FERNANDA'and edp.apellido1='MARQUEZ'and apellido2='GARCIA'),'2022-01-28','miguel, tras el aviso por email y hablar con la oficina del Sch de Santos de Maimona acordamos la firma del reparto por su asesoría jurídica de un fondo de inversiones de su fallecida hermana Rosa. En el día de hoy voy con el gerente a la firma de apertura de un fondo de inversiones de la parte que corresponde a la tutelada y le doy a Iciar dicha apertura y sus claves','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-01-28','miguel, voy con el gerente por la mañana a la oficina de Mérida para firmar la autorización para desbloquear y poder transfererir los importes del fondo de inversiones conforme acuerdo de las dos partes (hermanastras, madre del curatelado y de Alejandro) Firma en Badajoz tanto Ana Perez (directora del Sch) y el curatelado dicho desembolso Remito email de la comisión al curatelado con los datos a donde debe llamar o enviar sus emails. Me deja sus datos que son móvil 722189774 e email alexnbp25@gmail.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-01-28','miguel, voy con el gerente por la mañana a la oficina de Mérida para firmar la autorización para desbloquear y poder transfererir los importes del fondo de inversiones conforme acuerdo de las dos partes (hermanastras, madre del curatelado y de Alejandro) Firma en Badajoz tanto Ana Perez (directora del Sch) y el curatelado dicho desembolso Remito email de la comisión al curatelado con los datos a donde debe llamar o enviar sus emails. Me deja sus datos que son móvil 722189774 e email alexnbp25@gmail.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2022-01-28','TERESA RECIBO EMAIL DE VIVIENDA nuria.morenor@juntaex.es Buenos días Teresa, en el día de hoy se han puesto en contacto con nuestro Servicio de adjudicación la Trabajadora social de los SSASB de Almendralejo (Anto) en relación a la vpp que tiene adjudicada Antonia Engracia Lavado del Hoyo, debido a que le han remitido a ella las llaves de la vivienda de la Calle Federico Garcia Lorca Portal 6 - 2ºB. De ella teníamos conocimiento que había sido ingresada en un Centro sociosanitario pero desconocemos si se trata de un ingreso temporal o permanente. Necesitamos ponernos en contacto con vosotros para determinar si va a volver a la vivienda en un breve espacio de tiempo y mantener el uso de la misma, o si está previsto que continúe en el Centro en el que se encuentra o ingresará en otro centro de forma permanente, en cuyo caso tendríamos que recuperar la posesión de la vivienda que tiene adjudicada a día de hoy. También necesitamos vuestra autorización para entrar en la vpp de Antonia y hacer una reparación a la vecina del 1ºB por una avería que existe en la vpp de Antonia. Esperamos vuestra respuesta, un saludo. MAIL DE VIVIENDA COMUNICO SITUACION ACTUAL Y LE INDICO QUE PUEDEN RETOMAR LA POSESION DELA VIVIENDA AUTORIZO ENTRADA PARA REPARACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='REBOLLO'and apellido2='HERNANDEZ'),'2022-01-28','TERESA TERESA ENVIO A PETICION DE SU HIJA ANTONIA LA CARTILLA DEL BANCO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='DE LA MORENA'and apellido2='MARTINEZ'),'2022-01-28','TERESA FORMA DE PAGO DE LA DENTADURA Revisando el presupuesto y con las indicaciones que nos dice, lo haríamos de la siguiente forma: 1ª factura de 3 implantes…………….2.565,00€ 2ª factura con un mes de diferencia, otros tres implantes………….2.565,00€ 3ª factura a los tres meses de haber puesto los últimos implantes, sobre dentadura superior……………………2.500,00€ 4ª factura al terminar (mínimo mes , mes y medio de la 3ª factura) sobre dentadura inferior……………………..2.300,00€ El tc habría que hacerlo en cuanto nos digan cuando empezamos , pero el precio 104,00€ con las condiciones que nos ponen podría ser en el mismo mes de la primera cirugía puesto que la suma es inferior a 3.000,00€ Dígame si es factible de esta forma y si están de acuerdo empezamos a organizar las citas. Estamos en contacto. Un saludo. SE APRUEBA PRESUPUESTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-01-28','Ana: correo de Sara Pozo, TS del HUC (sara.pozo@salud-juntaex.es / 927 256 322): "Buenos días Ana. Tenemos un paciente ingresado llamado Feliciano Borreguero Cambero que está tutelado y me indican desde FEAFES que probablemente al alta vaya a necesitar un recurso residencial. He hablado con los médicos de medicina interna y aún no tiene diagnóstico ni se puede saber qué necesidades de atención va a precisar al alta. Me gustaría saber cuál es vuestra preferencia. No sé si dará puntuación para plaza sociosanitaria, y en ese caso en qué residencia podría ingresar. También me gustaría saber si dispone de recursos económicos para ingresar de forma privada y en ese caso si él podría decidir dónde. Quisiera tener esa información para poder afinar la búsqueda de recursos. Gracias por tu atención. Saludos y feliz día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-01-31','Ana: Llamada de Claudia, TS CR El Cuartillo (22162): me comunica que Emilia ha dado positivo en Covid. ········ Aviso a Toni-Futuex, para anular la visita de Gloria, Ed, el jueves.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-01-31','Ana: Llamo a Cristina, Psicóloga del CRR (927 83 02 10): Feliciano lleva tiempo mal, se desorienta con facilidad, se ha perdido en varias ocasiones, necesita apoyo para casi todo e incluso han tenido que ducharlo en el CRR los días previos al ingreso por falta de autonomía. *Al CRR NO puede volver. ··· En cuanto a la elección de centros, mientras no vuelva a residir en su pueblo natal (Aliseda), que no le vendría nada bien, puede ir a cualquiera que no esté demasiado lejos y pueda seguir visitando periódicamente el cementerio, donde están enterrados sus padres y hermana. ································································································································································································ Llamo a Sara Pozo, TS del HUC (927 256 322): como no está hoy hablo con Mª Carmen, TS. Pasarán la herramienta para plaza Sociosanitaria. En caso de que dé puntuación para la misma, plantean la Residencia de Casas de Don Antonio, por proximidad a su pueblo (Aliseda) y porque tienen plazas privadas también, por si no hubiera ninguna pública disponible. *Finalmente acordamos que soliciten también plaza pública en las residencias de Cáceres. *Los ingresos no son altos, pero cuenta con buenos ahorros que le permitirían acceder a la privada de forma temporal hasta que quedara alguna pública libre. ··················· Pte. remitir a Mª Carmen, TS HUC: Copia de DNI, Tarjeta Sanitaria, Cdo. Empadronamiento y Cdo. de pensiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-01-31','Ana: Llamo a Toni-Futuex, en relación a la búsqueda de nueva pensión para José. Me informa de que están en ello, pero aún no tienen nada. Hoy es la última noche que está abonada en el alojamiento habitual. Para mañana le ayudarán a buscar algún alojamiento, aunque sea temporal, hasta que encuentren algo permanente a pensión completa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2019-10-31','Ana: El lunes en la reunión Toni-Futuex me pasó nota de José con Presupuesto para viaje en el Puente de Diciembre. **Se lo paso a Alberto, Jefe de Secc. Ecca. para valorar si se le puede autorizar un extra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-01-31','miguel, recibo emails de Damian que remito a Maite y Amalia porque le han atropellado (también contesto a su abogada Rocio Gracian que se lo comunico a la parte social, ya que me ha enviado un email para avisarme): Buenos días Miguel, Me ha llamado Damián desde el hospital. Está ingresado por haber sido atropellado por un coche. Me dice que tiene lesión en la pierna y cadera. Me pide que me ponga en contacto contigo y te informe de ello porque, según dice, " no le atienden al teléfono porque llama mucho y están enfadados con el". Por favor, confírmame la recepción de este correo Gracias. *************************************** Hola señor Miguel me tienen que hacer pruebas porque pasando por el paso de peatones me ha atropellado un coche el tema judicial es que la policía cuando termine del hospital me pase por los daños por si el conductor hay que hacer un atestado para indemnizar me por daños cuando pueda llámeme por favor ************************************ Nuevo email de Damian indicando el nº de atestado: El número de diligencia del atropello es 40/22 gracias me lo ha dado la policía para que usted lo tenga cuando salga el juicio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-01-31','Ana: Acude Martín en persona, sin cita previa, al SEPAD solicitando hablar con la secc. ecca. ··· *Bajamos Maite y yo a para atenderle. *Aprovechamos para explicarle que la CTAEX no atiende sin cita, por lo que si vuelve a hacerlo así no se le podrá atender. *Se lleva anotado los teléfonos de la secc. soc. **Al preguntarle por su problemas de salud, dice que el tratamiento lo toma, pero que no se quiere hacer el cateterismo, que en su cuerpo no va a entrar nada. ···· En cuanto a sus solicitudes eccas. envío correo a Alberto con copia a los Asesores Jurídicos: "Buenas tardes Alberto, En relación a MARTÍN DOMÍNGUEZ PALENCIA, solicita: - 150 € para ropa - 500 € para irse de viaje al Algarve con unas amistades Si es viable económicamente, por mi parte OK a ambas cosas. *Eso sí, también le hemos explicado que hasta que no se solucione los problemas que tiene en el banco (embargos OAR) no se podrá valorar por la sección económica y darle respuesta. Le llamarán en cuanto puedan. Su teléfono es: 644 21 34 59 *Pongo en copia a Miguel y Ángel, porque dice que ya no tiene ninguno de los vehículos que aparecen en el listado del OAR (impuestos), cree que deben estar en el desguace, por lo que entiendo que habría que darlos de baja en tráfico. Los documentos que necesitéis y no haya en su expdte. podéis solicitarlos a Futuex, aunque no estoy segura de que en esa casa lleguen a encontrar algo…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2022-01-31','Ana: Remito a Rosa Bravo, CSS, CI para extracción dentaria debidamente firmado y sellado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-01-31','Ana: correo de Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. Supuse que te alegraría saber que Juan Carlos está muy contento con la salida del sábado con Euexia. Me ha dicho que lo llevaron una chica y un chico, que no se acuerda cómo se llaman, al parque de Los Pinos, donde vio patos, cisnes, pavos. También me dijo que volverán "el domingo" a sacarlo por ahí... Te lo pongo entrecomillado porque él no controla bien los días de la semana.... No obstante espero que sigáis insistiendo respecto al centro"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2022-01-27','miguel, email de CSS a Soraya por posible delito de violación del tutelado a usuaria del centro: Buenos días: Recibido oficio desde el juzgado, remitido al Director del SEPAD, entendemos que va dirigido a la dirección del sociosanitario, os lo comunico para vuestra información. En relación a los hechos que se describen en el auto y ante la reiteración de los hechos (P.A. 261/21 con juicio señalado para el 24/02/2021 en las que están citadas a declarar una monitora ocupacional, la coordinadora de terapia y la Comisión Tutelar de Adultos), el equipo terapéutico se reitera e insiste en el traslado de centro de C.M.B tutelado por la CTA, ya que las medidas de vigilancia impuestas no resultan efectivas. Se informa así mismo a la Comisión Tutelar de estos hechos, ya que es la tercera vez que la residente lo verbaliza. En este caso la denuncia es interpuesta por Juan Ignacio Gonzalez Pulido como tutor de M.T.G.P.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2022-01-31','miguel, recibí el viernes 27-1-22 email de Soraya: Buenos días Miguel, la Directora del CSS de Plasencia, envía información de un procedimiento que está en marcha sobre un tutelado. Podemos saber en qué punto está el procedimiento???. No adjunta ninguna información . Como pide traslado, no quiero gestionar nada hasta saber por vuestra parte como está el caso. Ya me dices cuando puedas. ***************************************** Envío email a Soraya: Buenos días, he hablado con el juzgado de 1º instancia nº3 de Plasencia, me confirma que el procedimiento está casi recién iniciado y que hasta ahora sólo se ha tomado declaración a nuestro tutelado Cipriano Miguel Bazaga y que se ha remitido al Sepad (al centro CSS Plasencia) requerimiento para que emitan informe social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2022-01-31','miguel, contesto email a Soraya: Buenos días, he hablado con el juzgado de 1º instancia nº3 de Plasencia, me confirma que el procedimiento está casi recién iniciado y que hasta ahora sólo se ha tomado declaración a nuestro tutelado Cipriano Miguel Bazaga y que se ha remitido al Sepad (al centro CSS Plasencia) requerimiento para que emitan informe social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2022-01-28','miguel, recibo email de Soraya: Buenos días Miguel, la Directora del CSS de Plasencia, envía información de un procedimiento que está en marcha sobre un tutelado. Podemos saber en qué punto está el procedimiento???. No adjunta ninguna información . Como pide traslado, no quiero gestionar nada hasta saber por vuestra parte como está el caso. Ya me dices cuando puedas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='SOLE'and apellido2='LATORRE'),'2022-01-31','Ana: Reclaman el abono de la factura del colchón antiescaras. Se lo reenvío a Alberto, jefe de sección ecca. La factura ya se la remití a fecha de 26/11/21.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='VAZQUEZ'and apellido2='CORRALES'),'2022-01-31','Ana: Llamada de María, Directora de la Res. de Casar de Palomero, me indica que Juan está delicado, en su última fase de la vida. *No tiene seguro de deceso. ········ Su localidad natal es Los Santos de Maimona y María cree que él quería ser enterrado allí. Acordamos que llegado el momento contactarán con la Funeraria y se solicitará el traslado y entierro en dicha localidad. *Según última rendición puede asumirlo económicamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-01-28','Ana: correo de Toni-Futuex: "Buenas tardes Ana, que tal? Se envia a continuación la autorización para realizar punción, a Julia Morón de un bulto que tiene en la espalda. El otro dia acude a la consulta de cirugía general para recoger los resultados de la resonancia realizada, en el mes de septiembre, del bulto que tiene Julia en el costado. El cirujano comenta que, en principio, no aparenta ser nada maligno, por lo que meterse a operar algo tan sumamente grande, mide unos 27cmx15cm, es muy complicado, puede ser más perjudicial que beneficioso, además, no se asegura que se fuese a eliminar completamente debido al tamaño. EN principio parece una masa de grasa, pero se puede hacer una punción del lipoma, para extraer un poco de la materia que lo compone y hacer una biopsia para terminar de descartar. Se le explica a la tutelada y acepta, la educadora lo estima oportuno para descartar todas las opciones posibles, para realizar dicha punción se precisa autorización firmada por sus tutores legales, a entregar el día de la realización de la prueba, se adjunta en documento a parte. Podemmos hacer como otras veces que se firme y lo podeis enviar escaneado, para que la compañera lo lleve el dia de la prueba. Saludos y buen finde si no hablamos!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-02-01','miguel, recibo email de la tía del tutelado Amelia:AMELIA RODRIGO SANZ >MELITONARODRIGO@hotmail.es> Buenas tardes, Miguel Soy Amelia Rodrigo, familiar de Raúl y Sergio Gil Sanz, te recuerdo que estamos gestionando la escritura de aceptación de herencia Me he puesto en contacto con la notaría y desde septiembre del año pasado que empecé a enviarles documentación, no se ha realizado nada, me comentan que ha cambiado todo el personal de la notaría y hay que volver a retomar el asunto. Voy a intentar recuperar yo o pedir el certificado de últimas voluntades de Teresa que falta ya que la notaría me dice que ellos pueden tardar meses en conseguirlo. Por vuestra parte, necesitan: _Sentencia de declaración de incapacidad _Nombramiento de tutor o curetaje _copia autorizada de los testamentos de los padres. Te mando el nuevo email del contacto de la notaría, se llama Marían: magperez@despacho.notariado.org Te mandé el tfno de contacto y correo de la notaría donde testaron los padres, a mí no me dejan solicitar copia de los testamentos. Vamos a intentar volver a retomar las gestiones para que recuperen su herencia.','2');
