insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-02-01','miguel, llamo al juzgado y les indico que ya he pedido la suspensión de la ejecución. Me piden se lo pase por fax 924-304534 porque el registro tardará horas en darle nuestra solicitud de suspensión de ejecución. El teléfono de la hermana que el otro día vino a traer el requerimiento es Rosa 674-765-757. Me comenta Amalia que ella no nos coge el teléfono y no podremos hacer nada, además que ya tendrá ella previsto donde se va a ir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='VAZQUEZ'and apellido2='CORRALES'),'2022-01-30','EXITUS El centro comunica su fallecimiento, acaecido el 30/01/2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-01-31','miguel, remito al juzgado solicitud de suspensión de la ejecución hipotecaria 207/2012 del jzdo nº1 de Mérida que nos trajo en mano la hermana de la tutelada (Rosa)y cuyo lanzamiento está previsto para el día 2-2-2022','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-02-01','kike: Indicar que llega de los Juzgados la Providencia por la que D. Martín Domínguez Palencia ha sido citado para el próximo 16 de marzo de 2022 en la sala 1 de los Juzgados de Cáceres a las 9:20 horas. Igualmente, el mismo día debe acudir a las 9:30 horas en el Instituto de Medicina Legal, en el mismo edificio. Tras consulta con el área jurídica, no hace falta la asistencia por parte de dicha área.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-02-01','miguel, envío email a Amelia: Buenas tardes, he remitido a Marian de la notaria de Jimena del Castillo Rodriguez, magperez@despacho.notariado.org, la documentación que me indicas en tu email. Imagino que será compañera de Ana Sepulveda (en su día era el contacto que me indicastes de esa notaria) Asimismo he solicitado a Mónica de la notaria de Brihuega de Doña Ana Isabel Barriga Gozalo, al email que indicastes en tu email documentación@notariabrihuega.es pero me da error, no tendrás otro email? Mañana llamaré a dicha notaria de Brihuega para que agilicen la copia autorizadas de los dos testamentos. En cuanto al certificado de últimas voluntades que indicas en tu email deberían pedirlo electrónicamente desde la notaria, que a ellos se lo suelen remitir en días. Cualquier duda vamos hablando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-01-31','miguel, recibo email de Amelia: Buenas tardes, Miguel Soy Amelia Rodrigo, familiar de Raúl y Sergio Gil Sanz, te recuerdo que estamos gestionando la escritura de aceptación de herencia Me he puesto en contacto con la notaría y desde septiembre del año pasado que empecé a enviarles documentación, no se ha realizado nada, me comentan que ha cambiado todo el personal de la notaría y hay que volver a retomar el asunto. Voy a intentar recuperar yo o pedir el certificado de últimas voluntades de Teresa que falta ya que la notaría me dice que ellos pueden tardar meses en conseguirlo. Por vuestra parte, necesitan: _Sentencia de declaración de incapacidad _Nombramiento de tutor o curetaje _copia autorizada de los testamentos de los padres. Te mando el nuevo email del contacto de la notaría, se llama Marían: magperez@despacho.notariado.org Te mandé el tfno de contacto y correo de la notaría donde testaron los padres, a mí no me dejan solicitar copia de los testamentos. Vamos a intentar volver a retomar las gestiones para que recuperen su herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-02-01','miguel, remito a la notaria email (que me da error y llamaré mañana a la notaria) a Mónica de la notaria de Brihuega de Ana Isabel Barriga Gozalo, tlfno 949-280270: Buenas tardes Mónica. Conforme nos indica Doña Amelia Rodrigo Sanz, le escribo para solicitar las copias autorizadas de los testamentos de los padres fallecidos de dos personas tuteladas por la Junta de Extremadura (Comisión Tutelar de Adultos), Raúl y Sergio Gil Sanz, cuyos testimonios judiciales de incapacitación y nombramiento a esta Comisión Tutelar de Adultos le adjunto, junto con copia de los dos testamentos de sus padres fallecidos Don Máximo Gil Garcia y Doña Teresa Sanz Carrascosa, emitidos por la notaria de Brihuega, Doña Alicia Velarde Valiente con nº de protocolo 229 y 230 de fecha 14-4-1998. Adjunto también libro de familia y dni de los tutelados. La llamaré para confirmar que está todo correcto. Si necesita algo más dígamelo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2022-02-01','Ana: Correo de María Glez. - Autismo Sur: "...necesitamos un certificado de ingresos... una declaración jurada, que pese a que tiene resolución no ha recibido ni un euro... Costi esta estupendo... ya le dije a sara que es mi compañera que está en hogares que te vaya comentando.... pero supongo que entre unas cosas y otras... se lo recuerdo nuevamente hoy"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2022-02-02','Ana: Envío a María Glez. Palomo, TS Autismo Sur, la Declaración Responsable de PNC para este 2022 firmado digitalmente por el Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-02-02','Ana: Traslado a Alberto, Jefe secc. ecca., nueva solicitud de extra de Saturnino. ············· Remito también a Miguel, Asesor Jurídico, respuesta de Maite, TS del C. Penitenciario, en relación a la solicitud de informe: "... le trasladas a la abogada que para cualquier informe sobre el interno debe ser solcitado a través del Juzgado de quién depende, tal y como os comenté"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2022-02-02','miguel, recibo email de Jorge Calvo (abogado):Buenos días, Tras vuestra llamada al TSJ han tenido a bien llamarme para decirme que el señalamiento que nos han hecho es una citación de abogados para hablar con el letrado de la Administración. No obstante, les he indicado que eso no es lo que nos han mandado. Por lo que estoy a la espera de que me manden un email para aclarar las pretensiones de dicho día 10. Entiendo que irán en el mismo sentido que te han dicho. Quedo a la espera de vuestras noticias el viernes para aclarar la situación, dado que es muy rara la causa. Hay que recordar que todo empezó porque la tutelada me llamó al despacho porque no le pagaban el alquiler. Por lo que, una cosa es que os pueda ocultar datos, pero otra muy distinta es que ella misma me haya llamado para eso mismo. ***************************************************** mi contestación: Buenas tardes, independientemente de que el viernes aclaremos de quién es la firma que aparece en los recibí, te adjunto los recibí que en su día ella entregó a Futuex (la fundación que realiza funciones de apoyo a la Comisión Tutelar) y donde como verás es algo inverosímil ya que hay fechas seguidas en el mismo mes, en algunos casos. Por otro lado en el juzgado nos han dicho que más adelante sí nos avisarán para que vaya la tutelada y nosotros a una vista. En cualquier caso ya nos avisaréis vosotros. Gracias y el viernes te avisaré con lo que ella nos diga. **************************************recibo otro email del abogado Jorge: efectivamente hay cosas que no cuadran. Y la firma de la documentación que han presentado cambia en exceso de una a otra. Con trazos dudosos en unos casos y cambiantes en otros figuras de la firma que no deberían cambiar por ser muy significativos y personales. Yo pongo la duda en la autenticidad de lo que han presentado, pero me temo que eso me lo tenéis que confirmar y gestionar. Gracias y quedo a tu disposición. ************************************************* recibo email del abogado Jorge Calvo Onsurbe (reuniomabogados@gmail.com; tlfno 644 34 04 48): Adjunto le remito el último trámite procesal en el asunto arriba referenciado. 01/02/2022CONTESTACION ALA DEMANDA Y dior señalamiento 10-2-22 A LAS 12.30 HORAS - **APORTAN JUSTIFICANTES FIRMADOS DE RECIBÓ DE MENSUALIDAD** (¿SON VERDADEROS O FALSIFICADOS?) Del asunto referenciado. Han presentado oposición y nos han señalado para vista para el próximo 10 de febrero. A la vista de todo lo que adviernten en oposición, creo que es necesario que alguien en representaicón de Carmen y la propia Carmen puedan asistir. Asi, se ha adjuntado documentación en donde ellos refieren que se han realizado todos y cada uno de los pagos en mano, y aportan recibos firmados, PRESUNTAMENTE, por María Carmen. Advierto que las firmas diferen mucho y pongo en duda que TODAS sean originales. URGE que pongais este tema en común con Carmen antes de la vista puesto que, de ser así, habrá que negarlo y que se abra pieza penal por falsificación documental. RUEGO SE ME LLAME AL 644 34 04 48 para ver cómo actuar en el asunto. **************************************************** Reenvío el email del abogado a Maite, Amalia y Alberto y les envío email: Buenos días, adjunto más abajo el email que me envía el abogado por el procedimiento de desahucio que está tramitando para expulsar a la inquilina de nuestra tutelada Carmen Leal Benito. Alberto-comprueba si Carmen Leal no ha recibido nada en estos años por el alquiler-En su día Belen me dijo que no había constancia de que pagaran desde el inicio del contrato por lo que debían todos estos años. A espaldas de la Comisión se firmó dicho contrato de alquiler (año 2011), aunque ejercemos el cargo de tutores desde finales del año 2009. A raíz de todo ello se envió un burofax a los inquilinos para lo cual alguien acompañó a Carmen Leal (futuex creo), pero tiempo después Belén y yo nos dimos cuenta que lo dirigieron al Sepad no a la dirección de la casa alquilada, por lo que lo puse en manos del abogado que viene más abajo, el cual me explicó que había que tramitarlo conforme la Ley de Arbitraje ya que en el contrato de alquiler no se sometían a los tribunales ordinarios (le hubiera correspondido de 1º instancia de Badajoz por ser donde está el inmueble). Tras iniciar el procedimiento, los inquilinos se han opuesto y mandan muchos recibos supuestamente cobrados en efectivo por la tutelada. Nos remite citación para la vista fecha de 10/2/2022 en el Tribunal Superior de Justicia de Cáceres (porque se sometieron a la Ley de arbitraje en el contrato de arrendamiento en vez de a los tribunales de 1º instancia de Badajoz que es lo habitual…) Amalia-Por la documentación que adjunta y lo que comenta hay que hablar con Carmen Leal para que confirme si estos recibos que aportan están o no firmados por ella y para que Amalia-organiza que Carmen vaya al Tribunal Superior de Justicia sala de lo civil el 10-2-22 (que la acompañe alguien)- En caso de que te diga que ella no ha firmado esos recibos dimelo para que se lo diga al abogado y éste pueda solicitar un perito “calígrafo” para que identifique la autoría de la firma de los jusitificantes-recibí. Sé que el contrato es nulo por cuanto fue firmado sin consentimiento de la Comisión, pero han pasado 11 años sin que hayamos intervenido lo cual puede volvérsenos en contra. A ver si entre viernes y lunes me podéis confirmar todo esto. **************************************** Me llama la procuradora Cristina Soto (tlfno 660-404923)para pedirme que agilicemos los trámites por si tienen que pedir perito y por tanto posible pieza separada penal por posible delito ************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2022-02-02','miguel, recibo email del abogado Jorge Calvo Onsurbe (reuniomabogados@gmail.com; tlfno 644 34 04 48): Adjunto le remito el último trámite procesal en el asunto arriba referenciado. 01/02/2022CONTESTACION ALA DEMANDA Y dior señalamiento 10-2-22 A LAS 12.30 HORAS - **APORTAN JUSTIFICANTES FIRMADOS DE RECIBÓ DE MENSUALIDAD** (¿SON VERDADEROS O FALSIFICADOS?) Del asunto referenciado. Han presentado oposición y nos han señalado para vista para el próximo 10 de febrero. A la vista de todo lo que adviernten en oposición, creo que es necesario que alguien en representaicón de Carmen y la propia Carmen puedan asistir. Asi, se ha adjuntado documentación en donde ellos refieren que se han realizado todos y cada uno de los pagos en mano, y aportan recibos firmados, PRESUNTAMENTE, por María Carmen. Advierto que las firmas diferen mucho y pongo en duda que TODAS sean originales. URGE que pongais este tema en común con Carmen antes de la vista puesto que, de ser así, habrá que negarlo y que se abra pieza penal por falsificación documental. RUEGO SE ME LLAME AL 644 34 04 48 para ver cómo actuar en el asunto. **************************************************** Reenvío el email del abogado a Maite, Amalia y Alberto y les envío email: Buenos días, adjunto más abajo el email que me envía el abogado por el procedimiento de desahucio que está tramitando para expulsar a la inquilina de nuestra tutelada Carmen Leal Benito. Alberto-comprueba si Carmen Leal no ha recibido nada en estos años por el alquiler-En su día Belen me dijo que no había constancia de que pagaran desde el inicio del contrato por lo que debían todos estos años. A espaldas de la Comisión se firmó dicho contrato de alquiler (año 2011), aunque ejercemos el cargo de tutores desde finales del año 2009. A raíz de todo ello se envió un burofax a los inquilinos para lo cual alguien acompañó a Carmen Leal (futuex creo), pero tiempo después Belén y yo nos dimos cuenta que lo dirigieron al Sepad no a la dirección de la casa alquilada, por lo que lo puse en manos del abogado que viene más abajo, el cual me explicó que había que tramitarlo conforme la Ley de Arbitraje ya que en el contrato de alquiler no se sometían a los tribunales ordinarios (le hubiera correspondido de 1º instancia de Badajoz por ser donde está el inmueble). Tras iniciar el procedimiento, los inquilinos se han opuesto y mandan muchos recibos supuestamente cobrados en efectivo por la tutelada. Nos remite citación para la vista fecha de 10/2/2022 en el Tribunal Superior de Justicia de Cáceres (porque se sometieron a la Ley de arbitraje en el contrato de arrendamiento en vez de a los tribunales de 1º instancia de Badajoz que es lo habitual…) Amalia-Por la documentación que adjunta y lo que comenta hay que hablar con Carmen Leal para que confirme si estos recibos que aportan están o no firmados por ella y para que Amalia-organiza que Carmen vaya al Tribunal Superior de Justicia sala de lo civil el 10-2-22 (que la acompañe alguien)- En caso de que te diga que ella no ha firmado esos recibos dimelo para que se lo diga al abogado y éste pueda solicitar un perito “calígrafo” para que identifique la autoría de la firma de los jusitificantes-recibí. Sé que el contrato es nulo por cuanto fue firmado sin consentimiento de la Comisión, pero han pasado 11 años sin que hayamos intervenido lo cual puede volvérsenos en contra. A ver si entre viernes y lunes me podéis confirmar todo esto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-02-02','Ana: Remito correo con documentación a Mª Carmen, TS del HUC (mariac.rodriguez@salud-juntaex.es): "Buenos días Mª Carmen, Tal y como acordamos mediante conversación telefónica, te remito adjunta la siguiente documentación escaneada: - DNI - Tarjeta Sanitaria - Certificado de Pensión de Jubilación por Incapacidad Permanente - Certificado de residencia en centro (*Dado que no tenemos Certificado de Empadronamiento, te remito adjunto éste por si os sirviera, en algún caso me lo han admitido, si necesitáis el de empadronamiento sí o sí, dímelo, pero tardará unos días más, pues se requiere autorización tanto del Representante Legal como del Representanta de la Entidad en que reside y realizar las gestiones oportunas en el Ayto. de Cáceres. Ya me dices)..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2022-02-02','Ana: Envío a Cristina Molano, Psicóloga CRR, CI para anestesia loco-regional debidamente firmado por el Representante Legal. ·················· La intervención quirúrgica es para: "retirar y cambiar los tornillos del tobillo que le pusieron con anterioridad por intolerancia al material y los problemas ocasionados de ello."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-02-02','Ana: Traslado a Toni-Futuex, la comunicación de la cita en tanto en el Jdo. como en Instituto de Medicina Legal el día 16 de marzo, para que se aseguren de que Martín lo sabe y si él aceptase, le acompañen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-01-21','miguel, recibo email de la abogada Ana Lucas: Buenos días, me remite nuestra trabajadora social (Ana Matamoros) lo que le traslada Maite (trabajadora social del centro penitenciario): - “El interno solicita hablar por teléfono con su abogada Dª.Carmen, para ello te informo de que la abogada tiene que remitir un documento por fax al 927181150 y que ponga para entregar al interno Saturnino Miguel Salgado en el que se haga constar que ella es la abogada que le representa en la causa tal, su número de teléfono y que autoriza a que el interno Salgado Jiménez pueda llamarle”. Por otra parte, mi compañera Ana Matamoros ha vuelto a solicitar a la trabajadora social del centro un informe: “. Dada la patología que presenta Saturnino Miguel, la abogada quieres solicitar un cambio de centro y nos pide informe para poder defender esta postura. Nosotros le hemos facilitado los certificados de discapacidad y dependencia, dictamen técnico y los informes del servicio de Psiquiatría de las últimas consultas (últimos años). No sé, una vez habéis conocido el perfil, si tú como Trabajadora Social de referencia en la actualidad y/o el personal de Enfermería que le atiende, consideráis si Saturnino Miguel podría cumplir esta medida de forma menos gravosa para él, quiero decir, en algún otro centro (Centro Sociosanitario, pues no hay ningún otro en la región en que pudiera cumplir una medida judicial de estas características). Si esto fuera así, ¿podríais ponerlo por escrito?.” Estamos a la espera de una respuesta por parte de la trabajadora social del Centro Penitenciario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-01-21','miguel, me remite este email la abogada: Miguel Angel te estoy llamando, no sé como localizarte y prefiero hablar contigo por teléfono, he hecho la petición de libertad provisional y subsidiariamente complimiento en un centro ya, yo con el interno no tengo que hablar de momento nada más, además, cuando he intentado hablar con él ha sido imposible. Saludos ****************************************** La llamo y me dice que recibe presiones y llamadas constantes del hermano del tutelado. Me comenta que ya ha contestado al escrito y que por tanto ya no necesita el informe social y me lo adjunta vía email para el expediente. También me dice que no va a llamar a Saturnino pues nada tiene que hablar con el ya que está en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-01-21','miguel, me remite este email la abogada: Miguel Angel te estoy llamando, no sé como localizarte y prefiero hablar contigo por teléfono, he hecho la petición de libertad provisional y subsidiariamente complimiento en un centro ya, yo con el interno no tengo que hablar de momento nada más, además, cuando he intentado hablar con él ha sido imposible. Saludos ****************************************** La llamo y me dice que recibe presiones y llamadas constantes del hermano del tutelado. Me comenta que ya ha contestado al escrito y que por tanto ya no necesita el informe social y me lo adjunta vía email para el expediente. También me dice que no va a llamar a Saturnino pues nada tiene que hablar con el ya que está en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-02-02','miguel, contesto a Ana y Alberto: la abogada ya contestó al juzgado con lo cual no necesita ya no necesita el informe social. He subido a la intranet sus emails y conversaciones. Me comentaba que tampoco tiene que hablar nada ni con el tutelado ni con su hermano (que no para de llamarla) pues lo que tenga que informar lo hará a través mía. He dejado en el expediente el escrito que ha hecho ella al juzgado por si queréis verlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-02-02','miguel,envío email a Amelia: Buenos días Amelia, si te hiciera falta certificado de saldo a fecha de fallecimiento de sus padres entonces sí tendrías que hablar con Caixabank, caso contrario no atenderán tu petición, por lo que te recomiendo que o bien lo solicites mirando en Google donde te dirigirán a la página del Ministerio de Justicia o bien dile a la notaria que aunque te cobren lo hagan ellos. Acabo de mandar a los dos emails que indicas (para Mónica) el email de ayer para solicitar escrituras autorizadas de los dos testamentos (efectivamente había puesto por error la tilde). Ya me ha contestado Marian que ha recibido el email que le envié con los documentos que me indicastes (incapacitación y nombramiento de cargo)para que vaya preparando la adjudicación de herencia. ****************************************************** remito email a la notaria para pedir las copias autorizadas de testamento a los emails que me indica Amelia (info@notariabrihuega.es; documentacion@notariabrihuega.es): Buenas tardes Mónica. Conforme nos indica Doña Amelia Rodrigo Sanz, le escribo para solicitar las copias autorizadas de los testamentos de los padres fallecidos de dos personas tuteladas por la Junta de Extremadura (Comisión Tutelar de Adultos), Raúl y Sergio Gil Sanz, cuyos testimonios judiciales de incapacitación y nombramiento a esta Comisión Tutelar de Adultos le adjunto, junto con copia de los dos testamentos de sus padres fallecidos Don Máximo Gil Garcia y Doña Teresa Sanz Carrascosa, emitidos por la notaria de Brihuega, Doña Alicia Velarde Valiente con nº de protocolo 229 y 230 de fecha 14-4-1998. Adjunto también libro de familia y dni de los tutelados. La llamaré para confirmar que está todo correcto. Si necesita algo más dígamelo. ****************************************************** recibo email de Marian de la notaria donde se está preparando la herencia de los padres de los tutelados Sergio y Raúl: Miguel, así un poco por encima, mientras que imprimía la documentación, he visto que con respecto a SERGIO GIL SANZ, me envías la Sentencia en la que se rehabilita la patria potestad, pero necesitaría el Auto en que se nombra a la Comisión Tutelar de Adultos de Extremadura como tutor de Sergio. Y, aprovechando, otra cuestión de la que tendremos que hablar con calma, tras la Ley 8/2021 que ha suprimido la figura del tutor, cómo estáis procediendo??? Lo digo porque mi notaría pide el documento judicial que declara al tutor en curador y que determina en que actos (o si son todos) y en qué forma intervendrá el curador. Ya te digo que de este tema tenemos que hablar, … En todo caso y para cualquier cuestión, si necesitas hablar conmigo, mi extensión directa es la 21. **************************************** mi contestación: Buenos días Marian, te remito los testimonios de nombramiento y aceptación de cargo correctos. Cuando quieras avísame y te llamo para comenta lo de la nueva Ley. Según reunión que tuve con la presidenta del TSJ y fiscales de Extremadura, la idea es revisar todas las sentencias anteriores a la entrada en vigor de la nueva y ley, y por tanto hasta que sean revisadas siguen aplicándose tal como están, es decir como tutelas o curatelas. En otro orden, voy a intentar contactar con la otra notaria esta mañana para pedir las dos copias autorizadas del testamento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-02-02','miguel, recibo email de Amelia dirigido a Caixabank (CAIXABANK OFICINA 8771 CIFUENTES. PLAZA MAYOR >8771@caixabank.com>): Buenos días, soy Amelia Rodrigo, con DNI 03091440X, he estado hablando con varios empleados de la oficina de Cifuentes y desde hace mucho tiempo, para gestionar la testamentaría de mis tios Teresa Sanz y Maximo Gil fallecidos en enero y septiembre del 2020. Les reenvío un correo que les hice llegar al buzón de la oficina en julio del año pasado, no ha habido respuesta al mismo y tampoco puedo contactar con ustedes por teléfono. He dejado varios mensajes para que se pongan en contacto conmigo sin resultado. Como he comunicado a la oficina, los herederos de los mismos son sus hijos, Raul y Sergio Gil Sanz pero ambos son incapacitados y tutelados por la Junta de Extremadura. Estoy intentando ultimar, lo antes posible, la escritura de aceptación de herencia de los mismos y para ello necesito de su colaboración. La notaria me pide: -certificado de últimas voluntades de Teresa Sanz, por algún motivo, no obra en mi poder, probablemente no me quedé con copia y se haya entregado original en la confección del IS, necesito que revisen en su testamentaria, como tenía una renta vitalicia aparecerá información también de sus seguros. -Ultimo recibo de contribución cobrado en su cuenta, corresponde a la casa en Calle la Fuente, 14 con ref catastral 8417037WL3181N0001RL, se habrá cobrado en cuenta en el periodo estival del año pasado. -copia de los certificados de saldo de las cuentas de Maximo Gil Garcia, fallecido el 15 de septiembre de 2020. Pueden ponerse en contacto conmigo para recoger ésta documentación, o bien enviarla a mi correo o les voy a facilitar el correo de la persona de contacto en la notaría donde se está gestionando la escritura, Notaria Jimena del Castillo Rodriguez. Tfno 949 248079 y correo de Marian: mgperez@despacho.notariado.org Pongo en copia de éste correo a D. Miguel Fernández de la Comisión Tutelar de Adultos de Extremadura por si consideran oportuno contactar con él o necesitan alguna documentación para facilitarnos la documentación necesaria. Esperando sea atendida rápidamente la colaboración requerida, les saludo atentamente. Mi teléfono de contacto es 628 581 997','2');
