insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-02-02','Ana: Traslado a Alberto, jefe de secc. ecca., los presupuestos de cáterin. ············· *Toni-Futuex, me confirma que el hijo ya está instalado en la casa con José Manuel y que pretende comer también del mismo menú.','2');
