insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2022-02-02','Ana: Envío a Rosa Bravo, admvo. del CSS-Plas correo-e (rosamaria.bravop@salud-juntaex.es): "...Te adjunto el Consentimiento Informado para resonancia magnética relativa a Remedios Chaves Masero, firmado digitalmente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-02-02','Ana: Envío a Toni-Futuex, CI para la "PUNCIÓN-ASPIRACIÓN" firmado digitalmente por el Representante Legal. ················································································ De las facturas que remite Julia por registro a la CTAEX, Alberto, jefe de secc. ecca., de entrada autoriza el abono del taxi. Las otras dos, puesto que no pidió presupuesto previo ni autorización a la CTAEX, de momento no se abonarán. Más adelante veremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-02-02','Ana: Tras comunicarme Icíar, secc. ecca. que Juan Félix ha aparecido pues se lo ha comunicado Puerto Ramos, TS SSASB Plas. (600 44 92 38 / 927 60 03 28): Ángel Félix ha acudido a su despacho porque no puede retirar efectivo del banco. Sabe que percibe una PNC. Me facilita sus datos de contacto: "Domicilio: C/Galisteo, nº 17 – Plasencia Tlf. 643 622 174. ··········· Tiene una hermana, Eva, que reside en el CRR de Plasencia y quién presenta Grados de Discapacidad y Dependencia reconocidos. ···························································· Llamo a Ángel Félix, le parece bien que le ayudemos a gestionar su dinero, pues él mismo admite que no se le da muy bien. Se muestra accesible y coherente. Le he dicho también que iba a derivarlo al programa de apoyo comunitario y que una compañera, Educadora, le visitará periódicamente y que le ayudará a elabora una propuesta de presupuesto de gasto semanal. **Dice que no tiene domicilio propio, vive con un amigo, al cual le abona algo, pero no lo aclara mucho. Hemos acordado que las autorizaciones de retirada de efectivo serán semanales. De momento el viernes podrá retirar 50€, pues dice que no tiene nada, pero que cuando se apruebe un presupuesto podrá retirar lo que se acuerde todas las semanas. ··································································································································································································································································· Realizo derivación a Futuex. ··············································································································································································································· Icíar, secc. ecca., realizará la autorización bancaria puntual para el viernes (50€)','2');
