insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-12-03','Ana: Correo de Estrella, TS CSS: "...Muy bien, está bastante bien, así que se irá de alta después del puente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2022-02-03','miguel, recibo email de Tere donde me adjunta informe de incidencia de los servicios sociales de base del Ayto de Almendralejo: Que hacemos con esto? Ya es la segunda vez que mete gente en su causa y tiene problemas…***************mi contestación:Buenos días, lo voy a comunicar al juzgado pero al dejarle entrar voluntariamente es un problema y sólo se me ocurre que o bien le denuncie (como la otra vez) cuando ocurra algún hecho ilícito o bien intentes buscarle algún centro… Lo comunicamos al juzgado?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2022-02-03','Ana: Correo-e de Fernándo Pecero, Casa de la Misericordia: "Buenos días Ana Quería informarte sobre Antonio y hablarte de algunas cuestiones. Lo primero es que está bien, bueno, en estos momentos tiene COVID pero asintomático como la mayoría de los residentes. Está tranquilo y estable. Hasta el día de hoy su comportamiento es muy bueno y esperemos que siga así. Hablé con una compañera tuya para el tabaco y la asignación económica para sus gastos personales. De lo cual él está conforme con su paquete de tabaco y los 2.5 € diarios. Pero quería comentarte que sobre la mensualidad para el mantenimiento de la plaza no estamos recibiendo aún nada. No sé si hay algún problema. Ya me dirás cuando puedas. No hay prisas. Muchas gracias y recibe un cordial saludo" ······························································································································································································ Recuerdo a Alberto, Jefe de Secc. Ecca. que hay que realizar una aportación al centro, en función de las posibilidades de Aº sin renunciar a su asignación semanal para gastos de bolsillo. ····························· Alberto me comunica que propondrá aportar 200€/mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2022-02-03','miguel, me llama Evelyn 622-253-784,y me confirma que ya firmaron la Declaración de Herederos y que el motivo de su llamada es porque la oficina de Ibercaja de San Francisco en Badajoz le pide para el desbloqueo que habrá de acudir el representante de la Ctaex y que le remita los certificados de titularidad. Le pido que me envíe la declaración de herederos y datos de contacto email y tlfno de persona de Ibercaja para quedar con ellos para firmar en oficina de Mérida ******************************************** Envío email a la parte económica para que me remitan certificado de titularidad de cuenta para su desembolso.','2');
