insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-02-03','miguel, a petición de Estrella mando email al Sabadell (7840@bancsabadell.com; SAC@bancsabadell.com; info@bancsabadell.com)que no atiende las peticiones de cargo en cuenta que se le han hecho: Buenos días, del cliente D. Martin Dominguez Palencia con Nif 6.998.750B, curatelado por la Comisión Tutelar de Adultos de la Junta de Extremadura, cuyo testimonio de aceptación de cargo se adjunta, y en nombre por tanto del mismo, les requerimos para que en un plazo no superior a 5 días, procedan a cargar en su cuenta (que actualmente está bloqueada, sin que se nos haya notificado el motivo), los siguientes recibos que se adjuntan de nuevo: 1)OAR de Cáceres, varios cargos por importe total de 689,82€ 2)Seguro de Mapfre de Deceso por importe total de 77,30€ 3)Factura a proveedores por importe de 756,25€ Hemos comprobado vía online que siguen sin cargar dichos recibos. Tras reiterados emails y llamadas telefónicas sin éxito (siempre están los operadores ocupados según su contestador automático), es por ello que les solicitamos un teléfono directo y un email de contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-02-03','miguel, Tere me devuelve el email que le mandé porque Eulalia está en el plena inclusión de Mérida. Le envío email a Amalia: Buenos días, en su día por error envié email a Tere. Eulalia se encuentra en Plena Inclusión de Montijo, y su hermando Francisco que fue tutelado nuestro falleció en la Cam de Don Benito Tiempo atrás se puso en contacto un nuevo arrendador de las rústicas que tenían Francisco y Eulalia (por error entiendo en el antiguo contrato de arrendamiento se metieron otras rústicas también, donde aparecía otra persona también de titular) El nuevo arrendador quiere le hagamos un contrato de arrendamiento rústico y nos encontramos que no sé si Francisco dejó herederos (la rendición final de cuentas se hizo mal y se adjuntaron documentos diferentes al certificado de últimas voluntades, con lo que necesito verificar este dato y saber si la única heredera es ella antes de volver a arrendarlo (no vaya a ser que haya otros herederos) Dime algo lo antes posible. También habría que liquidar el impuesto de sucesiones…(necesitaré originales de certificado de defunción y últimas voluntades)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-02-03','miguel, envío email a Amelia: Buenos días de nuevo Amelia, acabo de hablar por teléfono con Marian y me confirma que por el tema de la legitimación de firma del representante de la Comisión Tutelar de Adultos hay que hacer la solicitud de las copias de testamento desde nuestra notaria habitual en Mérida. Por tanto para poderlo solicitar necesito que me envíes por mensajería o correo certificado los certificados de defunción y de últimas voluntades originales de los padres de Sergio y Raúl, a la dirección: SEPAD-Comisión Tutelar de Adultos (A/A Miguel) Avda de las Américas 4, 06800, Mérida (Badajoz)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-02-03','miguel, envío email a Amelia: Buenos días de nuevo Amelia, acabo de hablar por teléfono con Marian y me confirma que por el tema de la legitimación de firma del representante de la Comisión Tutelar de Adultos hay que hacer la solicitud de las copias de testamento desde nuestra notaria habitual en Mérida. Por tanto para poderlo solicitar necesito que me envíes por mensajería o correo certificado los certificados de defunción y de últimas voluntades originales de los padres de Sergio y Raúl, a la dirección: SEPAD-Comisión Tutelar de Adultos (A/A Miguel) Avda de las Américas 4, 06800, Mérida (Badajoz)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-01-18','Ana: Correo de Paula, TO CRR-Plas: "Buenos días, nos ponemos en contacto con vosotros para comentar una situación acerca de Ceferino Mariscal. Lo ocurrido es que, en el transcurso de su expulsión por consumo de marihuana, solicita a una compañera del CRR que le compre una nintendo para hacer más llevadera su estancia, así como algún dinero extra para la misma. Esta compañera, con la que de forma intermitente mantiene una relación (actual pareja), no posee dinero en ese momento, por lo que adquiere una importante deuda con otra persona para poder dar respuesta a las solicitudes de Ceferino (hasta el momento el mantenimiento de dicha relación está ligado a la recepción de "regalos" por parte de Ceferino). Por lo que adeudan a su compañera 1150 Euros. Realizando los cálculos del dinero del que Ceferino sería directamente responsable serían 410 Euros. Y de los 740 restantes se ha beneficiado de forma conjunta. Realizando una intervención con ambos por parte de la Directora y yo como terapeuta, identifican estas deudas y se barajan diferentes opciones para dar respuesta a ellas. Así aparece la posibilidad de que pueda facilitarse el pago completo de la deuda de 1150 Euros a la compañera por parte de Ceferino, él pagaría los 410 que ha generado y su pareja le iría devolviendo a él, a razón de unos 100 Euros mensuales, los 750 Euros restantes. Esta opción colocaría a Ceferino y su actual pareja en una posición diferente, ayudaría a poder trabajar los roles de pareja; que asumieran de forma conjunta (sobre todo Ceferino) la responsabilidad respecto a la obtención de objetos de su interés a través de las relaciones con mujeres y no a través de los canales apropiados (solicitar a través de la comisión lo que necesita o es relevante para su desarrollo personal y/o para su disfrute para el ocio). Además permitiría que devolvieran el total de lo que deben a su compañera. Os ruego que valoreis esta opción y que en la medida de lo posible contactéis con nosotras para poder aclarar cualquier cuestión." ·········· Se lo reenvío a Alberto, Jefe de secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-01-19','Ana: Respuesta de Alberto en relación al correo de Alberto: "Hola Ana. En la ecuación que propone el centro me falta una cuestión importante. Ceferino se ha gastado, según el centro y sin molestarse en solicitarnos autorización, 410 €...Teniendo en cuenta que se le ha tratado bastante bien últimamente con la publicación del libro y otras cuestiones, esos 410 € debe reembolsarlos a través de la reducción de su asignación o similar...actualmente cobra 325 €/mes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-02-02','Ana: Nuevo correo de Paula, TO - CRR Plas (tocupacional.crrplasencia@grupo5.net): "Buenos días, quería preguntaros acerca de Ceferino Mariscal y la deuda pendiente con una compañera. Realizamos una propuesta que se basaba en una intervención orientada a un cambio de rol en la que Ceferino adelantara el dinero de la deuda de su compañera además de saldar la propia, pero finalmente ésta no va a ser posible porque la otra persona ha abonado su deuda a través de distintos apoyos para cumplir con su parte. Por lo que en la actualidad el único deudor es Ceferino. Ceferino debe 410 Euros y es importante que pueda devolver dicho dinero. Es importante para la intervención con Ceferino que podamos coordinarnos respecto a este tema, puesto que hasta ahora no ha resultado efectivo que pague con estas deudas con el dinero de asignación mensual, puesto que adquiere otras nuevas y cada vez es más complicado apoyarle. Por ello os emplazo a que se pueda autorizar el pago de esta deuda de forma completa de sus ahorros (no del dinero mensual) y poder tener una coordinación en la que valorar y repensar estrategias utilizadas hasta el momento y otras nuevas a incorporar, para tratar de producir cambios, puesto que en otras áreas de su vida (ocupaciones significativas) ha logrado realizar proyectos que han requerido esfuerzo por su parte, poniendo de manifiesto así otras competencias personales. Esperamos vuestra respuesta respecto al pago de la deuda, así como de una posible entrevista para coordinarnos (telefónica o virtual). Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-02-03','Ana: Llamo a Paula, TO del CRR-Plas (682 704 401): pero no obtengo respuesta.','2');
