insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2022-02-03','Ana: Subo al portafirmas digital la Solicitud de Inclusión en Lista de Espera y los 4 CI: Anestesia Gral. y Local, Colecistectomía, Intervención Quirúgica en contexto de Pandemia, remitidos desde el CRR-CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-02-03','miguel, recibo llamada de la tutelada (tlfno 677407893)comentando que quiere que le pida un abogado de oficio para recuperar su capacidad. Envío email a la parte económica y a Ana Ts con cómo hay que proceder en estos casos: Buenas tardes, me ha llamado la tutelada para que la solicitemos abogado de oficio para recuperar su capacidad, lo cual como sabéis no es posible, salvo que sea la propia Comisión quien solicite la recuperación de su capacidad( aunque ella sí puede solicitar la remoción del cargo). Además en caso de que fuera la Ctaex la que lo solicitara lo haría a través de abogacía general (que nos representan en nombramientos y ceses) Hemos quedado que os comunicaría a la parte económica que en cuanto podáis remitáis al juzgado la rendición anual de cuentas junto con el informe social. Ana, en caso que desde la parte social se estime que algún tutelado deben cambiar sus capacidades (curatela representativa a asistencial o viceversa) el informe social habrá de hacer mención en ese sentido, ya que las rendiciones de cuenta será lo que tendrán en cuenta los juzgados para revisar la incapacidad de cada persona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-02-03','miguel, recibo email de Ana: Buenas compi, Te he escaneado a tu carpeta de escáner el Informe de evolución de José Manuel Romero Mediavilla en Recursos Residenciases de la Red de Salud Mental de Extremadura, firmado por la Jefa de Sección de Salud Mental. En el mismo, tras una exposición detallada de su recorrido por los distintos recursos, desde 7 años antes de aceptar la CTAEX el cargo de tutor, en el apartado de “CONSIDERACIONES FINALES”, especifican que José Manuel “… no es un perfil adecuado para estos recursos, concluyendo que su funcionamiento no está determinado por desestabilización clínica de su trastorno mental, sino que es comportamental y con rasgos antisociales.”, “…consideramos que los recursos residenciales comunitarios no son el tipo de recursos que se adaptan a su funcionamiento.” Este documento, junto con los dos que te remito adjunto: - Propuesta de expulsión del CRR de Olivenza (antiguo CRR de Badajoz) - Resolución de Baja del mismo Son los que tendría que remitir al Juzgado para: 1- Comunicar su vuelta al domicilio 2- “Solicitar” que revisen su tutela, pues de acuerdo con los informes aportados, no sé hasta que punto tiene sentido que siga tutelado por la CTAEX. Ante cualquier duda, hablamos. Seguimos con el jueves. *********************************************** Mi contestación a Ana y Alberto (parte económica): Buenas tardes Alberto, urge que se remita la rendición de cuentas anual de este expediente para la revisión de su capacidad y que desde el juzgado se adapten a la nueva ley, donde dicten las medidas de apoyo que consideren. Para ello, al igual que en cualquier rendición de cuentas anuales que hagáis, remitídmela para que previo a verlo con la trabajadora social que corresponda (en este caso Ana) acordemos qué indicar al Juzgado, además lógicamente de aportar el informe de evolución que han remitido firmado por la Jefa de Sección de Salud Mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-01-18','miguel, email de Ana Lucas (abogada): Buenas tardes Miguel Angel, voy a pedir la libertad provisional, y que os hagáis cargo vosotros puesto que está bajo vuestra tutela de él ¿Qué medios tenéis para evitar fuga, centros etc…? y además caso de que lo estimen oportuno una medida cautelar menor gravosa para este Sr. y te repito ¿Qué Centros tiene la junta para cumplir este tipo de medidas personas de estas características? El hermano de este Sr (que creo no es el indicado, sería la Junta) sigue insistiendo, así que a ver cómo lo enfoco, te ruego me des la informacion que te pido, saludos.************************************************** Envío email a Ana Ts:Buenas tardes, para cuando vuelvas, me pregunta la abogada qué centros y medios tenemos porque va a pedir prisión provisional…Necesitaré un informe desde vuestra parte social para remitírselo.','2');
