insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2022-02-04','Ana: Llevo a REGISTRO el Escrito-solicitud abono mensualidades impagadas. ····················· Envío mail a David Barea (david.barea@juntadeandalucia.es): "Buenos días David, Tal y como hablamos la semana pasada, te remito adjunto el escrito-solicitud de abono de mensualidades impagadas de la PNC relativo a D. Costi Alexandru Rizea, tutelado por la CTAEX, ya registrado. Ante cualquier cuestión, no dudes en ponerte en contacto conmigo. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2022-02-04','-Amalia : en respuesta al correo de Rubén enviado desde el CRR para que accedamos a que le den el permiso de conducir : Buenos días , lo que Rubén nos pide es que accedamos a que le den el permiso de conducir para poder desarrollar su proyecto laboral . Como sabéis la Comisión Tutelar no tiene potestad en este tema, tiene que pasar el reconocimiento médico que exige la DGT . Cuando pida cita para ello , tiene que llevar el informe médico que le dió su psiquiatra en la última cita . Por favor , mostrarle a Rubén este escrito para que él pueda leerlo . Un saludo .','2');
