insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-02-04','Buenas Manuel , qué tal ? cuanto tiempo sin saber de tí . Ayer hablé con Mª Jesús , el alquiler asciende a 280€/ mes que sumado a gastos de suministros y demás es inviable económicamente con la PNC que percibe de 402€. Estaba pendiente de un contrato de trabajo que me comentó que finalmente no ha salido . Le comenté que ha salido un bono para alquiler joven , pero obviamente hay que cumplir todos los requisitos para acceder a él y que el contrato sea formalizado. Este bono , aunque se lo den , tardan meses en resolver y tendría que tener dinero ahorrado para ir tirando unos meses . Tiene dinero ahorrado para eso ?? ha comprobado que cumple todos los requisitos para el bono de alquiler ?? le comenté que fuese a preguntar a vivienda , en la zona del Peri de Mérida y se informe de todo antes bien . Tú la ves ya para alta ?? esta chica sabría mantenerse sóla ? Un saludo .','1');
