insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2022-02-07','Ana: Remito a Rosa Bravo, Admvo. CSS-Plas., Autorización de Tratamiento de Datos según Política de Privacidad de la Clínica San Miguel para las pruebas médicas.','2');
