insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-02-03','Ana: Correo de Mª Carmen Rguez., TS HUC (mariac.rodriguez@externos.salud-juntaex.es): "Buenos días de nuevo, he hablado con el médico que lleva a Feliciano Borreguero, me comenta que el paciente está en estudio y que alguna de las pruebas no se la han podido realizar por la no colaboración del paciente. Nos ha dado una puntuación muy baja (23 puntos) para solicitar plaza T3. Tenemos que ir viendo otro recurso al alta."','2');
