insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GIL'and apellido2='RIVAS'),'2022-02-07','-Amalia : fallecido . Hablo con Ocaso , funeraria José Tomás 682196583 y un familiar Angel Picazo 664100133 para que sea enterrado en su pueblo Villarta de los Montes . Me confirman que lo tiene recogido en los servicios de su póliza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-02-07','Ana: Llamo a Mª Carmen, TS UHC (56823): El médico le ha dicho que, como está en estudio, de momento dejemos en "stand-by", la solicitud de recursos. *El médico no quiere dar informe alguno hasta que no tenga un diagnóstico claro. *No obstante, como la puntuación en la herramienta para T3 es bajita, dejaremos abierta la solicitud, cuando la tramitemos, a toda Extremadura. Y cuando el alta sea inminente, si no tiene plaza aún, puede ingresar en plaza privada en Casas de Don Antonio. ····· *Por la Ley de Dependencia, sólo tiene reconocido Grado I, por lo que habría que solicitar revisión de grado y esto va muy lento. *Lo pediremos cuando esté en centro. ··································································································································· Llamada de Mª Carmen, TS HUC (56823): el médico que está hoy le han informado de que Feliciano tiene un TUMOR CEREBRAL. Está pendiente o de que le hagan una biopsia por parte de Neurocirugía o de derivarle a Oncología.','2');
