insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-02-07','Ana: Llamo a Mª Carmen, TS UHC (56823): El médico le ha dicho que, como está en estudio, de momento dejemos en "stand-by", la solicitud de recursos. *No obstante, como la puntuación en la herramienta para T3 es bajita, dejaremos abierta la solicitud, cuando la echemos, a toda Extremadura. Y cuando el alta sea inminente, si no hay recurso, puede ingresar en plaza privada en Casas de Don Antonio. *Por la Ley de Dependencia, sólo tiene reconocido Grado I, por lo que habría que solicitar revisión de grado y esto va muy lento. *Lo pediremos cuando esté en centro.','2');
