insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-02-07','Amalia : hablo con su hna Rosa por tf. 674765757 , no sabe nada de ella , desconoce si se ha producido el deshaucio . A ellos tampoco les coge tf ni les abre la puerta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2022-02-04','miguel, recibo email de Ibercaja (Remedios Naranjo Perez email rnaranjo@ibercaja.es) Buenos días, Para finalizar la testamentaría de José Martínez, falta aún alguna documentación, que a continuación se detalla: - Testimonio de la sentencia de incapacitación de Juan José y Antonio Martínez Pérez. - Nombramiento y aceptación del cargo de tutor de ambos. - Documento de aceptación y partición de la herencia a beneficio de inventario firmado por los herederos, indicando el porcentaje que corresponde a cada uno. Aprovecho para adjuntarle la declaración de herederos, que me ha comentado Evelin que la necesita. Cualquier duda o aclaración, estoy a su entera disposición. ********************************** mi contestación: Buenos días, adjunto la documentación que nos solicitáis. En cuanto al reparto entendemos que debería ser en partes iguales. Reenvío email a Evelyn para que firme algún modelo que tengáis en Ibercaja y luego nos lo haga llegar para que lo firme el representante de la Comisión Tutelar y enviároslo. Gracias, un saludo ******************************************** reenvío email a Evelyn evelinmrzahinos@gmail.com: Buenos días, adjunto email enviado a Ibercaja. Ya les he enviado las sentencias que solicitaban, con lo que faltaría firmar el modo de reparto. Les he puesto que te den un modelo y que lo firmemos las 3 partes. Tendría que firmarlo primero tu padre y después puedes enviárnoslo por correo certificado a la siguiente dirección: Comisión Tutelar de Adultos (SEPAD) Avda de las Américas nº4 06800, Mérida Nos lo tienes que hacer llegar para firmarlo el representante de la Comisión. El reparto entendemos que debe ser en 3 partes iguales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-02-07','Ana: Se ha recibido factura del Hostal para el mes de febrero. *Se lo paso a Estrella, secc. ecca. ················· Envío correo a Toni, Futuex: "Buenos días Toni, A ver si podemos hablar luego. De todas formas, en relación a José Moreno Moyano, hemos pensado en que se le valore por Dependencia, pero para ello necesitamos: - Informe de Salud (Anexo. II, lo adjunto) ¿Podríais apoyarlo para pedir cita en el médico de atención primaria y acompañarle a la misma para solicitar dicho informe? Por otra parte, ¿la compañera ha hablado con él en relación a la contratación de un Cáterin? De momento sabemos que está en el Hostal Alameda Palacete, pero aquí no estaba incluida las comidas ni había posibilidad para ello, ¿no? ¿Habéis acordado algo con él con respecto a las comidas? A Estrella, compañera de la secc. ecca. le ha solicitado un extra de 150€, pero no sé con qué finalidad exactamente. Ya me dices. Gracias y buena semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2022-02-07','-AMALIA: le envio a Eva , TS , la opcion por PNC ya firmada por el Gerente para que lo registre a PNC una vez firmada por Fco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2022-02-07','-AMALIA : HA LLEGADO UNA CARTA DEL INSS QUE SUSPENDIAN SU PENSION LO HE ACLARADO CON JUAN DE PENSIONES Y ESTÁ TODO CUADRADO . YA LE HAN ENVIADO TODOS LOS PAGOS A LA CUENTA ANTERIOR DEL LIBERBANK.','2');
