insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2022-02-07','Ana: Correo de Estrella Durán, TS CSS-Plas.: "Me han llamado del CRR de Cáceres para hacer entrevista previa a ingreso, a Esteve Pascual Ramos el día 8 a las 11 horas...para ingresar la semana del 14 al 18..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2022-02-04','Ana: Correo de Cristina Carrón, T.O. del EVD Coria (cristina.carron@salud-juntaex.es): "Buenos días Ana, soy Cristina del equipo de valoración de dependencia de la zona de Coria. ¿Te acuerdas que hablamos de la señora Emiliana Sánchez Bermejo? Esta mujer que se encuentra en los pisos tutelados de Calzadilla y ha pasado a tener reconocido un Grado II, y por lo tanto hemos de buscar un Servicio de Atención Residencial para ella. Yo le he propuesto solicitar plaza pública de SAR en Calzadilla, y evidentemente os he de enviar la ficha de propuesta PIA a vosotros. La consulta es, ¿solicitamos plaza en algún centro más? Puede solicitar hasta en cuatro centros residenciales que dispongan de plazas públicas para personas con dependencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2022-02-04','Ana: Correo de la residencia FEMAR (residenciafemar2019@gmail.com): "el día 21 de Febrero tenemos cita para la renovación del DNI de Valentina Fernández Trejo, necesitamos que ingresen antes de esa fecha la cantidad de 20 euros para fotografías y pago del DNI." ············ Informo de la cuestión económica a Estrella, secc. ecca., para que se ocupen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2022-02-07','TERESA RECIBO LLAMADA DE ELI DE CARITAS A PARTIR DE AHORA SERA ELLA QUIEN LLEVE EL EXPEDIENTE ME COMENTA QUE TOMAS QUIZAS TENGA QUE DEJAR EL PISO EN EL QUE SENCUENTRA ACTUALMENTE PUES LE HAN SUBIDO EL PRECIO Y TIENE SOSPECHAS DE QUE LOS COMPAÑEROS SE ESTAN APROVECHADO DE EL TELEFONO DE ELI 607580199','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2022-02-07','Ana: Llamada de Clara, TS C.S. Guadalupe (53107): Ha consultado en Jara y Juan no acudió a la consulta del día 17 en ESM. ··············· Envío correo a Toni-Futuex: "En relación a JUAN CHAMORRO HOLGUÍN, supongo que sabréis que Juan finalmente no asistió a la consulta de Salud Mental para la que estaba citado el día 17. Voy a solicitar informe al respecto para comunicarlo al juzgado. A parte de esto ¿Teresa ha vuelto a visitarlo? Si es así, por favor, enviarme cuando podías nota informativa de dicha visita de seguimiento. Si no, por favor, cuando podáis le visitáis de nuevo y me enviáis la nota a posteriori." ···································································································································· Envío al ESM, a la Att. del Dr. Jiménez Cano, fax solicitando informe de la última consulta programada a fecha de 17/01.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2022-02-07','Ana: Envío por mail a Paula, TO, escaneada y debidamente firmada, la Autorización para la Inclusión en el PAI (Proceso Asistencial Integrado) de TMG (Trastorno Mental Grave) y para el intercambio de información entre los distintos dispositivos y programas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2022-02-07','-Amalia : La estoy llamando por tf. , no la localizo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-02-07','Ana: Correo de Alberto, jefe secc. ecca. a Miguel, Amalia y a mí. "AMALIA/ANA/ALBERTO/MIGUEL: VISTA SITUACIÓN ECO DE TUTELADA SE LLEGA A CONCLUSIÓN (PENDIENTE DE QUE LO VEA MIGUEL) DE QUE SERÍA POSITIVO PROCEDER A LA VENTA DE SU PROPIEDAD EN CÁCERES. TIENE CIERTA URGENCIA PROPIEDAD: 100 % PROPIEDAD EN ISABEL DE MOCTEZUMA CÁCERES. IMPORTANTE: CREO QUE SIGUE SIENDO UNA ADMINISTRACIÓN DE BIENES...PERO BASTANTE CUALIFICADA." ············· Comunico conformidad con la venta desde la sección social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2022-02-07','Ana: Tras varios intentos sin éxito, de contactar con la Res. Santa Catalina de Calzadilla (927 146 458), envío correo a Cristina Carrón, TO del EVD: "Buenas tardes Cristina, Yo creo que con el tiempo que lleva en la localidad y estando bien allí lo más adecuado es que permanezca en al misma. No obstante e intentado llamar al centro en distintas ocasiones desde que vi tu correo esta mañana y no consigo contactar, pues quisiera saber si su deseo es seguir allí o si está dispuesta a cambiar de localidad. Vuelvo a intentarlo mañana y ya te confirmo." ············· *Envío también correo a la residencia (administracion@calzadilla.es) pidiendo que cuando puedan se pongan en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2022-02-07','TERESA OK A SUBIR LA PARTE DE APORTACIÓN A PISO TUTULADO X CONCEPTO "OCIO": PASA A 190 € (PREVIAMENTE ERA DE 150 €)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2022-02-07','EMAIL ALBERTO AMALIA: SI TE PARECE, ESTAS FACTURAS LAS ABONAMOS EN ESTA OCASION - PERO TEN EN CUENTA QUE NI CENTRO NI HERMANAS HAN PEDIDO AUTORIZACIÓN PREVIA Y X TANTO NO SE CONTROLA LO QUE TIENE O NO TIENE QUE GASTAR DESDE EL PUNTO DE VISTA SOCIAL NI ECONÓMICO...NO PUEDE SER QUE SEAN LAS HERMANAS LAS QUE GASTEN LO QUE CONSIDEREN Y CUANDO LO CONSIDEREN...ESO LES DEBE QUEDAR MUY CLARO A LAS HERMANAS Y AL CENTRO, ASÍ COMO QUE NO SE ABONARÁ NADA QUE NO HAYAMOS AUTORIZADO PREVIAMENTE. HABLAMOS DE 850,14 € ESTRELLA: ABONAMOS LOS 850 € (LOS PDF ADJUNTOS Y EL CORREO SOCIAL JUSTIFICA TODO) QUE NOS INDICA AMALIA + HABLA CON CRR PARA QUE NOS DIGAN COMO LE HACEMOS LLEGAR ESTE DINERO A LAS HERMANAS + Y LES REITEREAS LO QUE AMALIA HABLARÁ CON ELLOS...NO SE ABONARÁN FACTURAS SIN APROBACIÓN PREVIA CTAEX. DETALLE GASTO: GAS 85,50 € COLCHÓN: 410 € VARIOS: 15,45 € MEDIAMARKT TV: 284,99 € TABACO: 54,2 € TOTAL: 850,14 € AMALIA : HABLO CON EL CENTRO SOBRE ESTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-02-08','EMAIL FUTUEX : Buenas Amalia! como estas?? espero que totalmente recuperada (en la reunión del fondo social me comentaron tus compis, que estabas de baja por este dichoso virus) Según ella estas al tanto, pero por contrastar la situación contigo, que nos trasmiten de la tutelada Mª Jesús Cruz Esperilla residente en los pisos supervisados de Mérida. Quiere irse a un piso de alquiler de forma independiente. Según nos comenta, ha encontrado un piso en la calle John Lennon en Mérida pero la forma de pago es en efectivo, no aceptan transferencias. Nos transmite que se ha puesto en contacto con la comisión, en este caso dice haber hablado contigo y se le ha indicado que debe solicitar la ayuda al alquiler para menores de 35 años. Por otro lado, Manuel, coordinador de los pisos, nos contacta también para saber sobre dichas gestiones. Desde el programa tras lo trabajado con la tutelada, actualmente, no creemos recomendable que se independice ya que se observan ciertas carencias para el correcto desarrollo de actividades de la vida diaria. El recurso en el que está se considera un buen apoyo para la adquisición de autonomía y habilidades para su desenvolvimiento personal. Sabemos que esto es algo voluntario y que si dice irse poco se podra hacer, pero es que realmente sola y sin apoyo no puede estar. Para terminar, también nos transmite su preocupación referente a la revisión en el CADEX ya que su grado de discapacidad es de carácter provisional 31 de diciembre de 2021 y no ha recibido ninguna citación. Cualquier cosa, estamos en contacto gracias, Saludos!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-02-08','Ana: Tras recibir correo de Toni con información sobre nueva hospitalización y acerca del único vehículo que utiliza Martín en la actualidad (Motocicleta matrícula: C6394BWC), envío correo a Miguel y a Alberto, secc. jurídicas y ecca.: "Con respecto a los vehículos de MARTÍN DOMÍNGUEZ PALENCIA, tal y como indiqué con anterioridad, hay que dar de baja todos los que aparecen en el documento que remitieron a Estrella desde el OAR, excepto el que se indica en el correo de a continuación (subrayo en amarillo) Miguel, aparte de lo de los vehículos, ya sé que estamos pendientes de cita con el Forense. Como puedes leer está de nuevo hospitalizado, no sé cómo evolucionará la cosa, pues a Maite y a mí, nos manifestó verbalmente la semana pasada, que no quiere someterse a las pruebas médicas que le habían indicado en anteriores ingresos. Veremos si no vuelve a solicitar el alta voluntaria." ················································································ En cuanto a la citación en el Instituto de Medicina Legal, Gloria, Ed. Futuex, se lo comunica y él manifiesta que acudirá, e incluso acepta el apoyo de la educadora. *El hermano "se muestra disponible a colaborar en caso de ser necesario llevarlo en coche o acompañarlo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-02-08','Ana: Tras recibir llamada de Maite, TS del C. Penitenciario (927 181 407), envío correo a Alberto, jefe secc. ecca., con copia a Maite, Jefa Secc. CTAEX: "He recibido nueva llamada de la Trabajadora Social del C. Penitenciario, en relación a la DEUDA que tiene con otros internos y que cada día es mayor. Saturnino está cada día más nervioso y acude a diario a su despacho con la misma demanda. Quiere un EXTRA y sabe que tiene dinero en la cuenta peculio. La solicitud de la TS es que se le autorice un EXTRA de 100€ (de los 200 € que tiene en cuenta) para amortizar dichas deudas. Yo creo que en esta ocasión se le puede conceder, indicando de nuevo que no se le van a dar más extras en X periodo de tiempo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-02-08','EMAIL FUTUEX : Buenas Amalia! como estas?? Según ella estas al tanto, pero por contrastar la situación contigo, que nos trasmiten de la tutelada Mª Jesús Cruz Esperilla residente en los pisos supervisados de Mérida. Quiere irse a un piso de alquiler de forma independiente. Según nos comenta, ha encontrado un piso en la calle John Lennon en Mérida pero la forma de pago es en efectivo, no aceptan transferencias. Nos transmite que se ha puesto en contacto con la comisión, en este caso dice haber hablado contigo y se le ha indicado que debe solicitar la ayuda al alquiler para menores de 35 años. Por otro lado, Manuel, coordinador de los pisos, nos contacta también para saber sobre dichas gestiones. Desde el programa tras lo trabajado con la tutelada, actualmente, no creemos recomendable que se independice ya que se observan ciertas carencias para el correcto desarrollo de actividades de la vida diaria. El recurso en el que está se considera un buen apoyo para la adquisición de autonomía y habilidades para su desenvolvimiento personal. Sabemos que esto es algo voluntario y que si dice irse poco se podra hacer, pero es que realmente sola y sin apoyo no puede estar. Para terminar, también nos transmite su preocupación referente a la revisión en el CADEX ya que su grado de discapacidad es de carácter provisional 31 de diciembre de 2021 y no ha recibido ninguna citación. Cualquier cosa, estamos en contacto gracias, Saludos!','2');
