insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2022-02-08','Ana: Llamo a la Res. Santa Catalina de Calzadilla (927 146 458), hablo con Loli, Admvo., hablarán con Emilia a lo largo de la mañana y me darán una respuesta. *Aprovecha para informar que ahora mismo no hay plaza pública libre, pero hay vinculadas, que le resultarían más económicas que la plaza de Pisos Tutelados que está abonando. ··· Podríamos solicitar la vinculada y la pública, para que ingrese en la primera y hasta que quede una libre de las públicas. / No obstante, me informarán sobre si quiere irse a alguna otra localidad. ······························································································································· Correo de Loli, Residencia Santa Catalina (residenciasantacatalina@gmail.com): "BUENOS DIAS ANA, HE HABLADO CON EMILIANA Y ELLA PREFIERE QUEDARSE AQUÍ, COMO TE COMENTÉ ESTA MAÑANA, EN LA RESIDENCIA CONTAMOS CON UNA PLAZA PRIVADA VINCULADA AL SERVICIO. ELLA AHORA MISMO POR LA PLAZA EN LOS PISOS ESTÁ ABONANDO 941.04 Y EL IMPORTE DE LA PLAZA PRIVADA SERIAN 950€. CUALQUIER DUDA ME PUEDES LLAMAR O ESCRIBIRME A ESTA DIRECCIÓN DE CORREO. UN SALUDO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2022-02-08','Amalia , envio email a Miguel : Buenos días, después de muchos intentos telefónicos para contactar con Carmen , hoy me ha cogido el tf. Me asegura que ella no ha recibido ningún dinero por el alquiler y que no ha firmado los recibís . Un saludo .','2');
