insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2022-02-08','miguel, email de Amalia, confirmando que Carmen Leal no ha firmado los recibí: Buenos días, después de muchos intentos telefónicos para contactar con Carmen , hoy me ha cogido el tf. Me asegura que ella no ha recibido ningún dinero por el alquiler y que no ha firmado los recibís . Un saludo . Reenvío email de Amalia al abogado Jorge: Buenos días, ya ha logrado mi compañera hablar con Carmen Leal y ésta ha confirmado que no ha firmado ningún recibo. Quedo pendiente tras la cita del jueves 10, me digas cómo queda todo esto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2022-02-08','miguel, me llega email de Alberto: MIGUEL/TERE: EL TUTELADO HA SACADO SI AUTORIZACIÓN LOS SIGUIENTES IMPORTES: 2022-01-25 RGO. MANUEL -250 2022-01-13 RGO. MANUEL -250 2022-01-03 RGO. MANUEL -250 LA CUESTIÓN ES QUE EN CUENTA HA DEJADO UN SALDO APROXIMADO DE 58 €....NO HA TENIDO EN CUENTA NI LA PENSIÓN QUE LE PASA A SU HIJA NI EL IMPORTE QUE LE ABONAMOS A SU HERMANA (LA DEL TUTELADO) X SU MANUTENCIÓN. QUIZÁS DEBIERA COMUNICARSE ESTO AL JUZGADO. TERE: YA ME DICES QUE HACEMOS CON SU HERMANA, SI ES QUE SIGUE CONVIVIENDO CON ELLA. OSCAR: REMITIMOS DE NUEVO ESCRITO CANCELACIÓN A OFICINA DE MORALEJA...SI ES POSIBLE INTENTA HABLAR CON OFICINA, ÚNICAMENTE X SABER SI NOS PUEDEN APORTAR ALGUNA INFORMACIÓN. ***************************************** Mi contestación:Buenos días, necesito para comunicarlo al juzgado: 1.-Extracto de movimientos donde figure esa retirada de dinero 2.-Me desgloses los gastos que tiene que tendría que asumir lo que queda de mes. En cuanto me lo mandes lo comunicamos al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-02-08','miguel, contesto al email de Ana y a Alberto: Buenos días, como sabéis estamos pendiente de cita en el juzgado nº 1 de Cáceres que le vea el forense para el procedimiento de internamiento involuntario. Por otra vía, Estrella y yo remitimos nuevo email a varias direcciones del Sabadell para que carguen las cantidades que desde la parte económica llevan tiempo remitiendo. Por último Ana, no puedo dar de baja en tráfico por varias razones: 1) porque se trata de una Curatela y en la sentencia no especifica nada, por lo que deberás solicitarlo cuando hagamos la rendición anual de cuentas y con ello podamos solicitar que le retiren el carnet y dar de baja o vender los vehículos que tenga. 2) No hay documentación de dichos vehículos. Veo en la intranet que el 21-1-22 hablaste con Toni de Futuex para que te averigue qué vehículos tiene.','2');
