insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2022-02-08','Amalia : envío email a la parte eco : Buenas , necesito que comprobéis si en la cuenta de AGUSTIN CASTAÑO TORNAVACAS , está como autorizada la hija . Está haciendo gestiones para retirar 10.000€ de la cuenta del padre . Ha conseguido el DNI y un duplicado de la cartilla bancaria. No estaría de más avisar al banco de las intenciones , por si en unas de las visitas al padre en la residencia de mayores de San Vicente de Alcántara en el tiempo del paseo lo lleva . La hija es de Villar del Rey , quizás la gestión la intente hacer en la Caja Rural de esa localidad. Seguimos..','2');
