insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2022-02-09','-Amalia . TF. de Tomas 643502640 Actualmente en piso de alquiler en Avda. Damián Téllez La Fuente , Nº 4 , 2º B de Badajoz . Está buscando otro piso para el mes que viene con un compañero , algo más barato que el actual . Presenta retraso mental + hipoacusia. Sin grado de dependencia , he solicitado valoración , para esta semana me llamarán para darme cita . Tengo que pedir que esté presente alguien de Cáritas . He hablado con Inés , educadora social 924260175-664437600 de Caritas, se necesita que alguna de ellas esté presente pq no se le entiende al hablar . Desde Caritas le hacen un seguimiento Tiene 38 años y bastante autonomia para AVD. Solicito a seccion eco dinero ahorrado para el cambio del alquiler . Una vez que esté en la nueva dirección , avisaré a Futuex para incorporarlo en seguimientos.','2');
