insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-02-09','miguel, me confirma Iciar que ya están hechas las transferencias y Alejandro le corresponden unos 25.000€. Me pide Carlos Jurado (abogado) que está tramitando la liquidación del impuesto de sucesiones que le enviemos el justificante de transferencia de la madre. Remito email a Iciar y Alberto par que me manden dicho justificante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-02-09','miguel, llama su hijo Jesús Valle Gutierrez (movil 643063690) e email jesusgallego@gmail.com, para decir que ya se ha ido a vivir a la vivienda de la que es titualr junto a su madre en plaza de la paz nº3, 4ºA, Coria (Cáceres). Y para pedir que le demos de baja al gas natural, ya que él ya está pagando la luz y el agua. Me pide los emails de la ctaex. Envío email a Ana y Alberto para dar de baja el gas natural','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-02-09','Ana: Llamada de José Manuel (627788797), se ha caído y tiene el tobillo hinchado, no ha ido al médico porque le da vergüenza como tiene las uñas de los pies. Pide un extra para acudir al podólogo, le digo que le pida un presupuesto al podólogo y nos lo envíen. Una vez dado el ok por la secc. ecca. podrán atenderle y pasarnos la factura para abonarla mediante transferencia. ················ Se queja también porque en el menú del cáterin no le entra postre ni pan. Le digo que puede pagarlo con la asignación quincenal. Debería de reducir el consumo de tabaco, por salud y por su economía. ················ Por último me explica que ha tendido una buena bronca con su hijo, que este se ha puesto a darle voces y decirle barbaridades. Y que quiere irse a un centro. Le recuerdo que ya no tiene posibilidad de ingresar en ningún recurso de la red de Salud Mental. **Entonces pide irse a vivir a Olivenza, a una casita barata de alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2022-02-09','-Amalia : doy conformidad para tto. dental , 780€ a abonar . se lo paso a sección eco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2022-02-08','Ana: Correo de la Residencia Santa Catalina (residenciasantacatalina@gmail.com): "BUENOS DIAS ANA, HE HABLADO CON EMILIANA Y ELLA PREFIERE QUEDARSE AQUÍ, COMO TE COMENTÉ ESTA MAÑANA, EN LA RESIDENCIA CONTAMOS CON UNA PLAZA PRIVADA VINCULADA AL SERVICIO. ELLA AHORA MISMO POR LA PLAZA EN LOS PISOS ESTÁ ABONANDO 941.04 Y EL IMPORTE DE LA PLAZA PRIVADA SERIAN 950€. CUALQUIER DUDA ME PUEDES LLAMAR O ESCRIBIRME A ESTA DIRECCIÓN DE CORREO. UN SALUDO','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ESTEVEZ'and apellido2='RODRIGUEZ'),'2022-02-09','Amalia : se recibe email de la TS , se gestiona el pago . Adjunto remito resolución sobre reintegro de pago indebido por parte del SEPAD, en relación con la prestación económica vinculada al SAD que recibe Antonio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2022-02-09','Ana: Envío correo a Cristina Carrón, T.O. del EVD Coria (cristina.carron@salud-juntaex.es): "Buenos días Cristina, Infórmate de que el deseo de Emiliana es quedarse en Calzadilla. Me informan en la misma que la plaza libre que tienen es privada vinculada, por lo que si te parece podemos solicitar la vinculada (cuyo coste le saldría poco más de lo que paga en la actualidad) y solicitar también la plaza pública para que pueda pasar a ésta cuando quede una libre. ¿Te parece bien? ¿Por cierto, la resolución del grado me la podíais hacer llegar, aunque sea escaneada? Cuando puedas nos remites la propuesta de PIA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2022-02-04','Ana: Maite, Jefa de Secc. CTAEX, entrega a la sección de discapacidad la Renuncia de la Plaza de Remedios en "Aprosuba 3 - Plena Inclusión, pues no regresará a este recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-02-09','Ana: Tras hablar con Belén, TS Secc. Discapacidad, envío correo-e a Sonia Bernabé ASINDI (trabajosocial@asindi.e.telefonica.net): "En relación a Roberto y Justo Hdez. Castaño, me piden desde la Secc. de Discapacidad, que elaboréis una propuesta-programación de viajes al domicilio, pues van a intentar que tengan de nuevo el servicio de trasporte de Cruz Roja, lo único que sólo podrán cubrir una viaje al mes. Así sólo habría que abonar el taxi el resto de ocasiones. Cuando podáis, por favor, enviarme dicha programación de 1 viaje al mes, me indican que lo ideal es que nos lo enviéis cada 3 meses"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-02-09','Ana: Tras hablar con Belén, TS Secc. Discapacidad, envío correo-e a Sonia Bernabé ASINDI (trabajosocial@asindi.e.telefonica.net): "En relación a Roberto y Justo Hdez. Castaño, me piden desde la Secc. de Discapacidad, que elaboréis una propuesta-programación de viajes al domicilio, pues van a intentar que tengan de nuevo el servicio de trasporte de Cruz Roja, lo único que sólo podrán cubrir una viaje al mes. Así sólo habría que abonar el taxi el resto de ocasiones. Cuando podáis, por favor, enviarme dicha programación de 1 viaje al mes, me indican que lo ideal es que nos lo enviéis cada 3 meses"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2022-02-09','Ana: Tras facilitarme Toni-Futuex, el contacto del hijo de Jesús, Rubén (640 165 123) le llamo en distintas ocasiones, pero salta el buzón de voz. En el último intento dejo mensaje en el buzón de voz pidiendo se ponga en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2022-02-09','-Respuesta con respecto a los suministros . Procedo a Buenos días Amalia, esperarán como siempre a última hora. Los suministros de agua y luz son privados y es el inquilino quien tiene que darles de baja. Te doy los teléfonos de aqualia de Mérida con quien puedes hablar: Elvira o Eva: 924.315634 En Sevillana endesa no tenemos ningún contacto. Si necesitas cualquier cosa me dices Un saludola baja con Aqualia y Endesa , he pedido a EStrella las facturas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2022-02-09','-Respuesta con respecto a los suministros . Procedo a Buenos días Amalia, esperarán como siempre a última hora. Los suministros de agua y luz son privados y es el inquilino quien tiene que darles de baja. Te doy los teléfonos de aqualia de Mérida con quien puedes hablar: Elvira o Eva: 924.315634 En Sevillana endesa no tenemos ningún contacto. Si necesitas cualquier cosa me dices Un saludola baja con Aqualia y Endesa , he pedido a EStrella las facturas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-02-09','Ana: Tras conversaciones, tanto con Maite, TS del C. Penitenciario, como con Alberto, Jefe de secc. ecca., remito a Maite (trabajosocialcpcaceres@dgip.mir.es) el siguiente correo: "Buenas tardes Maite, Tal y como hemos acordado, comunico por escrito la AUTORIZACIÓN, desde este Gabinete Técnico de la Comisión Tutelar de Agultos, para que JESÚS MANUEL RAMOS BARGÓN pueda retirar 100 € de la cuantía que tiene en su cuenta peculio además de su asignación periódica habitual. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2022-02-09','Ana: Llamo a Mari, Directora Residencia Ntra. La Luz de Malpartida de Plasencia (927 459 100, ext. 1): En relación a la comunicación de Ana Benavente, de que Guadalupe no se encuentra a gusto en el centro, me informa que el problema cree que viene porque no es capaz de ajustarse al dinero que le queda para gastos de bolsillo. Semanalmente le entregan entre 5 - 6 € para cafés y el resto se invierte en tabaco. al que presenta una gran dependencia. Han conseguido que reduzca considerablemente el consumo, de 1 paquete diario a 6 cigarrillos. Pero así y todo, ha habido temporadas en que pedía dinero y tabaco a profesionales y residentes. ············ En cuanto a la cuestión ecca. me pasa con Esther, Admvo., quien me aclara la duda planteada por Alberto, Jefe secc.: Guadalupe abona el 65% de su pensión incluidas pagas extras (este año: 319,56 €). Se lo comunico a Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-02-09','miguel, recibo email del curatelado: Buenas tardes señor Miguel estoy perdido he entregado la documentación en el registro de la gerencia de salud del área de Mérida y me ha dicho la policía local que para la indemnización me tengo que buscar un abogado el número de registro de presentación es 202273300008072 según el cuestionario que he rellenado de la carta que me llegó el DNI del conductor es 08632716 letraB la compañía aseguradora es compañía Reale seguros matrícula del vehículo 1959GTM marca del vehículo Citroën C4 si con estos datos usted puede ayudarme a gestionar el tema de la indemnización gracias y buenas tardes ********************************************************** le respondo: Buenos días Damian, el nombramiento de abogado (si llega el momento en que hiciera falta) depende de, como le dije en el otro email, de cuándo el juzgado le escriba a usted y/o a la Comisión Tutelar de Adultos, en el que nos dará un plazo por si quiere seguir adelante con la denuncia. Hasta que no se resuelva ese procedimiento judicial no habrá sentencia condenatoria (o absolución) que le conceda la indemnización por daños. Tenga en cuenta que el atestado de la policía lo tienen que enviar al juzgado y tienen que indicar qué juzgado va a conocer el caso y qué número de procedimiento se le va a dar. Y como digo, hasta que no haya resolución de ese procedimiento (que nadie sabe cuánto tardará en tramitarse) no sabremos si saldrá a pagar o no.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2022-02-09','Ana: Correo de Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es): "Te comunico que la entrevista de Esteve ayer con CRR fue bien. Ingresa el lunes a partir de las 12."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2022-02-02','Ana: Correo de Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es): "Os informo, Remedios Chaves irá a Badajoz al Centro Ntra Sra de la Luz a visitar a su hermana y a su madre, el jueves día 10 de febrero, con el taxi habitual."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-01-20','Ana: Correo de Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es): "...Con respecto a Alfonso, no tiene conciencia de enfermedad, por lo que la voluntariedad necesaria para ir a CRR tampoco la tiene. Desde el Equipo se valora como conveniente, que a lo mejor Futuex tiene que trabajar este tema con la madre, que al final es la que permite que esté en su domicilio y de la manera en la que está...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-02-10','-Amalia : Emi sale del CRR , ha firmado alta voluntaria , le van a dar una semana de margen . email de Raquel , Sección Sepad Salud mental : Buenos días Mar! Desde el Sepad nos parece adecuado darles ese margen para poder seguir trabajando con ella y ver si conseguimos que vuelva al recurso para poder continuar con las actividades que viene realizando desde su ingreso. Ya nos vais informando al respecto. Saludos, Raquel Gómez Aparicio 924 00 92 63 - 68510 Sección Salud Mental-DUE Unidad de Programas Asistenciales MARIA MAR BARROSO GOMEZ >MBARROSO@caseresidencial.es> Mié 09/02/2022 18:10 Buenas tardes. Emilia Morales Botello ha firmado finalmente esta medio día el alta voluntaria pese a las recomendaciones terapéuticas de su permanencia en el centro tanto por parte del equipo técnico como de Amalia, su persona de referencia en la CTAEX. Esperamos que recapacite de su decisión y que en una semana pueda volver al centro , por lo que vemos adecuado darle ese margen para poder trabajar vía telefónica con ella su vuelta al recurso. Pero entendemos que esta salida puede ser terapéutica para ella y estar fuera del centro unos días puede ayudarle a ver todo lo que el CRR le reporta en su bienestar diario. Os mantenemos informados de sus pasos. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-02-10','-Amalia , envío respuesta en contestación al email anterior : Buenos días , desde la Comisión Tutelar , apoyamos la medida terapéutica adoptada , esperamos que recapacite y vuelva al recurso . Un saludo .','2');
