insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2022-02-10','miguel, remito a Evelin por email borrador del acuerdo de reparto para que lo complete y me lo devuelva firmado. Le recuerdo que hay una cuenta en bbva que tendrá que hacer lo mismo ya que está a medias del abuelo y de Juan José','2');
