insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-02-10','Buenas Amalia, el interno está valorado por Ley Dependencia en Andalucía. Te adjunto la resolución en este email, para que la tengáis por si la necesitarais. Creo que te comenté que tiene una causa que cumplir nueva, saldrá excarcelado el 22/03/24. Estamos en contacto. Un saludo Beatriz Trabajadora Social Secretaría General de Instituciones Penitenciarias Centro Penitenciario de Badajoz. C/Ctra. Olivenza, Km 7.3; 06011, Badajoz. Telf. 924 28 91 17 Fax: 924 28 91 07 beatriz.TS.12742@dgip.mir.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-02-10','Buenos días , perfecto , lo archivo todo en su expediente . Me comentan desde la sección económica que el banco por error ha pasado por dos veces su asignación económica mensual , con lo que en los dos últimos meses ha recibido 700€ de asignación , el doble de lo que tiene presupuestado . Por lo tanto en febrero no se le va a pasar nada más y en marzo se regulariza la asignación como la venía percibiendo. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2022-02-10','TERESA Te contesto a este email puesto que es donde te explicaba la situación de David Vita. Actualmente sigue en su casa y estamos trabajando para que se incorpore al Centro Ocupacional y a Residencia, pero hasta que no comience el Programa de Empleo personalizado creo que va a ser complicado. De momento como te comenté en el email anterior solo está asistiendo los jueves a la sesión de tratamiento psicológico y se vuelve a su casa. Me pongo en contacto para comentarte que el padre me envía emails presionandome para que os pida más dinero, pues me dice que tienen deudas y que su hijo tiene que ayudarle. Te voy a copiar los emails que me ha enviado: "Mercedes, tu con 100 € cuanto dias le daría de comer a tu familia, Espero respuesta, Mi hijo David tiene un poco más, no lo se, pero como se suele decir el qué maneja el dinero de otro algo se queda en el camino. Es un decir antiguo, de mis abuelos " "Dice el qué maneja el dinero del vecino,, algo se queda en el camino. No lo intrepetes mal, solo es un dicho" "Mercedes perdona que te moleste, solo es para pedirte una ayuda económica para mi familia en tema de comida, ya que este mes nos ha surgido un problema, haber si la comisión aprueba la ayuda, lo necesitamos, si no hiciera falta sabe que no lo pediría, yo con mi sueldo y pagar todo no me llega, David podría dejarno algo para poder aguantar el mes, gracias por todo. Saludos" "Según me notifica algún colaborador de Ibercaja, siendo confidente, me notifica que David poseen en su cuenta entre 12,000 y 13.000 euros, y tu solo das al familia 100 €, yo solo te he pedido una ayuda, para soportar el mes, recuerda el artículo 155 del código civil, que ya te lo recordé en su día, Y si ignora este correo electrónico, nos veremos en otro lado, no te amenazó solo es llegar a un acuerdo" Estos son los emails que me ha enviado la semana pasada. Yo te pedí que le autorizasen 150€ para que David colaborase con los gastos de la casa pero parece ser que su padre quiere que David le pague deudas que al parecer tiene. El padre piensa que soy yo la encargada de gestionar su dinero por tanto creo necesario que desde la Comisión se le aclare ese tema. Te paso el teléfono del padre, al cual tuve que bloquear en mi teléfono personal hace ya varios meses.por si os parece conveniente hacerle una llamada y explicarle el asunto del dinero de David. Se llama Angel Vita: 651 62 88 31 ACORDMOS TRAS CONVERSACION CON MERCEDES DARLE ESTE MES 150€ A LA ESPERA DE QUE EN MARZO COMIENCE A IR AL CENTRO PARA VALORAR SI LE DAMOS MAS DINERO HABLAMOS CON ANGEL VITA PARA COMERNTARLE LA DECISION,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2022-02-10','-Amalia , envío respuesta a Miguel , se ha recibido de Hacienda comunicación para regularizar sus declaraciones de hacienda . Buenas , se ha pedido por dos veces información a la seguridad social de Alemania , desde el INSS con escritos míos para asegurar que llegaban correctamente a la entidad . Pero nos siguen respondiendo lo mismo , que revisemos en su cuenta porque no tienen devolución de la pensión y se le sigue enviando . Les reiteré que por favor nos indicasen al menos entidad bancaria en la que la están ingresando pero no nos facilitan ese dato . Quizás desde hacienda puedan cruzar datos y aclarar todo ésto . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-02-10','-Amalia : envío email a Miguel , para liquidación impuesto de sucesión : Buenas , te adjunto cdo. CADEX , pero era provisional hasta 31/12/2021. El CADEX de oficio lo volverá a citar para próxima valoración . Seguimos...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2022-02-10','miguel, email de Amalia: Buenas , se ha pedido por dos veces información a la seguridad social de Alemania , desde el INSS con escritos míos para asegurar que llegaban correctamente a la entidad . Pero nos siguen respondiendo lo mismo , que revisemos en sus cuentas porque no tienen devolución de la pensión y se le sigue enviando . Les reiteré que por favor nos indicasen al menos entidad bancaria en la que la están ingresando pero no nos facilitan ese dato . Quizás desde hacienda puedan cruzar datos y aclarar todo ésto .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-02-10','TERESA buenos dias !! hace un tiempo hablamos de la posibilidad de vender la vienda de este tutelado , habia una persona interesada, pues bien, ahora hay dos personas interesadas, necesitábamos el certificado de defuncion de su madre Aurora Chaves Caballero, pero no falleció aquí en calera , falleció en Llerena el 23 de noviembre de 1997 (¡¡¡¡¡el dato me lo ha dado el tutelado, que memoria !!!!!), a traves de este registro civil hemos pedido un duplicado del certificado de convivencia que os lo mandan del registro de llerena directamente a vosotros, con eso podeis pedir las ultimas voluntades y hacer la herencia .... un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-02-10','miguel, Carlos Jurado me pide le diga si tiene o no minusvalía. Consulto a Amalia y me indica que está pendiente de nueva revisión, hasta ahora tiene un 63%. Por otra parte pongo un email a Alberto para que mañana estemos pendientes de si hay que hacer o no finalmente una transferencia a la oficina liquidadora por el impuesto de sucesiones del padre fallecido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-02-10','kike,Nos ponemos en contacto con TONI de Futuex, y le comento que tiene una citación para el día de mañana 11 DE FEBRERO DE 2022 PARA EL DENUNCIADO ALFONSO MARIN DE CACERES, indicando que debe de ir a dichos Juzgados. Como hemos acordado en conversación telefónica, rogaría que se pusieran en contacto con nosotros, si por lo que sea, no fuera posible contactar con Alfonso, para que pudiera avisar con la suficiente antelación a los Juzgados. Para cualquier aclaración, no dude en ponerse en contacto con nosotros, por esta vía o por teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-02-10','-Amalia : envío email a Futuex : Buenas , con respecto a la citación CADEX a la que no acudió le acabo de pedir una nueva , seguramente por Marzo , me avisarán con la nueva cita . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-02-10','-Amalia : envío email a Futuex : Buenas , con respecto a la citación CADEX a la que no acudió le acabo de pedir una nueva , seguramente por Marzo , me avisarán con la nueva cita . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2022-02-10','miguel, recibo llamada del que dice ser abogado (Fernando Agorreta con email fernandoagorreta@hotmail.com, y con móvil 631-171-918 que quiere impugnar una póliza de préstamo personal que considera nula ya que nunca fue firmada por nuestra tutelada. Le remito nuestros datos y le pido informe, así como sus honorarios para informar al juzgado: Buenas tardes, adjunto mi email, siendo el corporativo de la Comisión Tutelar ctutelar@salud-juntaex.es Cuando pueda remítame un informe explicando los motivos de la necesidad de anular la póliza del préstamo, para trasladarlo al juzgado. Junto al mismo necesitamos un presupuesto de sus honorarios. Ignoramos si estuvo casada o no en régimen de gananciales a efectos de que puedan impugnarlo, con lo que sería necesario aportar certificado de matrimonio del registro civil junto con la sentencia de divorcio-liquidación del régimen conyugal. Saludos cordiales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-02-10','miguel, llamo a Encarni (hija de Basilia) tlfno 692687110 y a Basilia tlfno 692687229 para que me expliquen conforme el informe de la policia local de Fuente del Maestre, porqué han alquilado la vivienda de Calle Buensuceso, nº 45 de Fuente del Maestre sin informar a la Ctaex. Llamo sin éxito (no logro hablar con ninguna de las dos)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2022-02-10','-Se recibe email de aprosuba 3 , estamos a la espera que se le asigne una plaza en centro . Se ha registrado hoy la petición de revisión PIA solicitando plaza residencial por emergencia social adjuntando toda la documentación . La guardo en archivo. Buenos días: Os comunicamos que la madre de María del Pilar Rodríguez Escalera, está continuamente enviando mensajes de audio diciendo que: No aguanta a su hija, que no se hace caso, que le busquemos un sitio para que se vaya su hija, que la pongamos en un centro (y demás mensajes pero con el mismo contenido). Observamos a Pilar hija y le cuestionamos sobre su situación en casa, sobre su madre, y nos comenta que todo bien, además en su lenguaje corporal tampoco se observa que esté a vivir una situación complicada. Aún así, os queremos trasladar lo que nos está diciendo madre, porque los mensajes son reiterativos y muy focalizados. Nos gustaría saber como están las gestiones para la derivación residencia y saber si podemos aportar algo, para que se haga efectiva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2022-02-16','-Se recibe email de aprosuba 3 , estamos a la espera que se le asigne una plaza en centro . Se ha registrado hoy la petición de revisión PIA solicitando plaza residencial por emergencia social adjuntando toda la documentación . La guardo en archivo. Buenos días: Os comunicamos que la madre de María del Pilar Rodríguez Escalera, está continuamente enviando mensajes de audio diciendo que: No aguanta a su hija, que no se hace caso, que le busquemos un sitio para que se vaya su hija, que la pongamos en un centro (y demás mensajes pero con el mismo contenido). Observamos a Pilar hija y le cuestionamos sobre su situación en casa, sobre su madre, y nos comenta que todo bien, además en su lenguaje corporal tampoco se observa que esté a vivir una situación complicada. Aún así, os queremos trasladar lo que nos está diciendo madre, porque los mensajes son reiterativos y muy focalizados. Nos gustaría saber como están las gestiones para la derivación residencia y saber si podemos aportar algo, para que se haga efectiva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2022-02-10','Buenas Cris , como bien dices es mucho dinero , se necesitaría una autorización judicial . Por otro lado , si decides ir hacia delante en el caso de que tuvieras ese dinero ahorrado lo tienes que tener muy claro , tus cuentas se quedarían a 0 . Piénsalo bien ... Se van a revisar todas las sentencias incluidas la tuya , tendremos que plantear todo ésto . No hemos recibido respuesta respecto al DNI','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-02-10','Ana: Tras hablar con el Dr. Joaquín Antón, HUC (660 916 133), envío correo a Cristina, Psicóloga del CRR (crr@grupociudadjardin.com): "Buenas tardes Cristina, Ya he hablado con el Dr. Joaquín Antón, el pronóstico de FELICIANO BORREGUERO CAMBERO es muy malo. El tumor cerebral que presenta es profundo y de difícil solución. De ayer a hoy ha empeorado mucho. Se encuentra en estado semicomatoso, con un nivel de conciencia bajísimo, apenas responde. Tampoco come prácticamente ya. Consideran que las pruebas son muy invasivas en el estado en que se encuentra. Cree que no servirá de nada el hacer biopsia y en este caso el posible tratamiento sería muy agresivo. Le han retirado ya prácticamente toda la medicación. Excepto la de la epilepsia y poco más. Y cree que lo mejor dadas las circustancias es aplicar tratamiento paliativo. Posiblemente el traslado de al recurso residencial no tendría lugar hasta el lunes. Por favor, si os envían al centro algún documento para la firma, hacérmelo llegar. Auqnue también les he dicho que la vía más rápida y sencilla para ellos es hacerlo a través de la Trabajadora Social del Hospital." ······························································································································· Envío a Sara Pozo, TS HUC (sara.pozo@salud-juntaex.es): "Buenas tardes Sara, Aquí tienes la solicitud firmada y sellada por el Representante Legal junto con el resto de documentación pertinente. He hablado también con el Dr. Joaquín Antón, me informa que el pronóstico de FELICIANO BORREGUERO CAMBERO es muy malo. De ayer a hoy ha empeorado mucho. Se encuentra en estado semicomatoso, con un nivel de conciencia bajísimo, apenas responde. Tampoco come prácticamente ya. Consideran que las pruebas son muy invasivas en el estado en que se encuentra. Cree que no servirá de nada el hacer biopsia y en este caso el posible tratamiento sería muy agresivo. Le han retirado ya prácticamente toda la medicación. Excepto la de la epilepsia y poco más. Y cree que lo mejor dadas las circunstancias es aplicar tratamiento paliativo. Si hay que firmar algo, supongo que te lo entregarán a ti para que me lo envíes. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2022-02-11','Ana: Envío correo a María Glez., TS Autismo Sur: "Buenos días María, Te remito adjunta la siguiente documentación relativa a Costi Alexandru Rizea: - Informa sobre Ingresos, firmado digitalmente por el Representante Legal - Resolución de Concesión de Pensión no contributiva - Doc. 2 – Extracto bancario con saldo de cuenta del Banco Santander - Doc. 3 – Certificado bancario de Unicaja con saldo actualizado Con respecto a las necesidades económicas y las deudas de Costi con vuestro centro, mis compañeras de la sección económica se pondrán en contacto con vosotros para regularizar ya el abono de la plaza y resto de gastos habituales, pues los ingresos ya serán periódicos. Pero hasta que no le ingresen las nóminas y atrasos de 2021 no se podrá proceder a abonar la deuda contraída. Confío en que lo ingresen junto a la nómina de febrero o marzo como muy tarde. Un saludo y buen día." ······················ Envío correo a Alberto, Jefe Secc. Ecca., en relación al abono periódico de la plaza y los gastos mensuales. *La deuda se afrontará una vez le ingresen las nóminas de 2021 y atrasos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-02-11','Ana: Correo de Miguel, Asesor Jurídico: "Buenos días Ana, adjunto mantenimiento de medidas cautelares que remiten desde el juzgado (continúa por tanto en prisión provisional sin fianza)…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2022-02-11','miguel, asisto videoconferencia a juicio por delitos leves 48/2021 del jzdo nº4 de Plasencia, porque el tutelado agredió al guardia jurado del centro médico. Pese a indicar nuestro tutelado que se debió a que el guardia jurado le había dado en las rodillas y le había dejado cojo. Pendiente de sentecia que se resolverá, con multa de 3000€ y obligación de seguimiento médico al menos 3 meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-02-10','Ana: Llamo a Mª Ángeles, Aux. de SAD (675 264 255): comunico que se autoriza la compra del microondas. *La factura la remitirán a través de Isabel Pino, TS SSASB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSE'and edp.apellido1='MOLINA'and apellido2='SALAZAR'),'2022-02-11','TERESA RECIBO LLAMADA DE LA TS DE C.E. DE VILLANUEVA 83231/ DON BENITO 85553 Y ME COMENTA QUE M JOSE ESTA EN LA UHB Y TIENEN PREVISTO QUE PASE A UME. LE HAN COMENTADO DERVIVARLA A CRR PERO ELLA NO QUIERE VAMOS A SOLICITARLO PARA QUE SE PONGA EN LISTA DE ESPERA PARA INTENTAR QUE PASE A CRR UNA VEZ TENGA EL ALTA EN LA UME ME MANDARA LA DOCUEMENTACION PARA QUE LA FIRME POR CORREO ORDINARIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2022-02-11','TERESA EMAIL MERCEDES PI Me pongo en contacto para comunicarte que el Programa de Intervención que se está llevando a cabo con Libertad está dando resultados positivos. Accedió a asistir a la consulta de Salud Mental y está tomando una medicación que hace que esté más abordable y más tranquila en general. Y por otro lado, después de Navidad ha comenzado a trabajar en uno de los trabajos que ya abandonó hace algún tiempo. No te comenté nada cuando empezó porque siempre que empieza un trabajo lo abandona a los pocos días pero de momento lleva ya un mes y las previsiones son de continuidad. Está contratada por el centro especial de empleo dependiente de PLena Inclusión Llerena y son 9 horas semanales como limpiadora de un portal y el sueldo son 196,95€ Esperemos que todo siga así por mucho tiempo. Por otro lado, te quería comentar que no pedí dinero extra para su cumpleaños que fue a mediados del mes de enero y quería plantearte la posibilidad de que le autoriceis si puede ser 100€ o lo que pueda ser porque quiere comprarse una tablet.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-02-11','-Amalia , he hablado telefónicamente con Rosa ( tf. 611650311) , envío email a sección eco : Buenos días , he estado hablando largo y tendido con Rosa sobre todo lo relacionado con su situación jurídica ,económica y social . Os paso a detallar la respuesta que le he dado a sus peticiones para que todos estemos al tanto y no trate de manipularnos . Quiere dinero para productos sanitarios no recetados por su médico de cabecera y que ha de abonar a parte . NO SE LE DARÁ MÁS DINERO EXTRA , HA DE ABONARLO DE LOS 45€ SEMANALES QUE SE LE DAN . Quiere subir la asignación económica mensual de 240€/ mes para compras . SE LE EXPLICA TODA LA SITUACIÓN ECONÓMICA , SUS INGRESOS Y DEUDAS PENDIENTES , ELLA MISMA ES CONSCIENTE DE QUE SU PETICIÓN NO SE LE PUEDE AUTORIZAR . Pide dinero para abonar temas relacionados con el coche , para pasar la ITV , duplicado de papeles del coche ... CONSIGUIÓ EL PERMISO DE CONDUCIR POR 5 AÑOS ENGAÑANDO SOBRE LA ENTIDAD DONDE PASARÍA EL RECONOCIMENTO MÉDICO . ANTE LA DUDA DE SI ESPECIFICÓ SU PATOLOGIA MENTAL Y SU MEDICACIÓN , NO CREO QUE SEA CONVENITEN FACILIAR QUE CONDUZCA . EN UN PUEBLO , CON DISTANCIAS CORTAS CREO QUE NO ES UNA NECESIDAD URGENTE . VAMOS A ESPERAR A LA REVISIÓN DE SU SENTENCIA Y QUE SEA EL JUZGADO EL QUE ORIENTE SOBRE ESTA SITUACIÓN . POR LO TANTO QUEDA DENEGADA SU PETICIÓN HASTA RESPUESTA JUDICIAL . Le he comentado su opinión sobre dar de baja los recibos de móvil . Controla muchísimo sobre ofertas de llamadas + internet. Tiene 2 líneas , una para ella y otra par Blas , dice que cuando sale , el marido se queda un tf. por si la necesita . Insiste en que necesita internet para wasap y correos . Se le ha llegado a dar de baja a estos recibos ?? tengo dudas al respecto , por un lado el hijo pide que se le quite ,incluso él cubriría un móvil sólo con llamadas ilimitadas . Pero habría que tener un compromiso por su parte , porque no podemos quedarlos sin comunicación. Qué opináis al respecto ?? Quiere información sobre los embargos pendientes que se están cubriendo . Desde Wizink la llaman a diario , la amenazan con subirle intereses , ésto se está abonando en la medida de las posibilidades ?? Si me pasáis esta información yo se la trasladaré . Recabo información sobre sus familiares directos ,pensando en la revisión judicial de su sentencia , en su momento creo que es conveniente solicitar que sean sus hijos los que ejerzan el cargo . ( esta información es sólo para mi expediente ) Tiene 3 hijos : Flavio Escribano Serrano , vive actualmente en Montijo , trabaja para una empresa catalana , teletrabaja. Tenemos tf. de contacto e email . Nos ha enviado múltiples mensajes para orientar nuestra actuación. Desconforme con nuestra gestión. Dulce Nombre de Maria Escribano Serrano , vive en la ciudad de Badajoz . Al parecer de baja médica , posible patología mental . Mª Rosa Ródena Serrano . Es hermana de los otros dos , pero su actual marido la adoptó. Vive en Sevilla y trabaja en un despacho de abogados ayudando a su pareja . Creo que le he quedado todo bastante aclarado , otra cosa es que no comparta nuestro criterio . Seguimos...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2022-02-11','Ana: Llevo a registrar de ENTRADA la DECLARACIÓN ANUAL DE PNC, a la Dirección Gral. de Personas Mayores y PNC (Delegación Territorial de Málaga)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-02-11','Ana: Miguel, Asesor Jurídico, llama a Carmen, empresa FERNANDO BRAVO CALVO (622 72 41 78), en relación a la Reclamación de la Agencia Tributaria que ha recibido Felipe Rguez. Solís. **Miguel enviará escrito a la Agencia Tributaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2022-02-11','Ana: Vuelvo a llamar a Rubén, hijo de Jesús (640 165 123), no obtengo respuesta. Vuelvo a dejar mensaje en el buzón de voz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-02-11','miguel, remito email a Ana, Estrella, Alberto: Buenos días, tal como hemos hablado, reclaman a nuestro tutelado que las cantidades que viene abonando a la empresa Fernando Bravo hagamos los ingresos a AEAT. ***************************************** Hablo con Carmen de la empresa Fernando Bravo y la aviso de que desde Marzo no se le va a abonar a AEAT (Tlfno 622724178; email gestoresfbc.carmen@hotmail.com)************************** Voy a contestar a AEAT rellenando los importes, pero es necesario que Estrella me remitas justificantes de ingreso mensual desde Octubre de 2021 hasta la fecha de hoy. Tienes que dar orden al banco para no ingresar ninguna cantidad a la empresa desde Marzo. Por mi parte solicito a AEAT que nos envíe carta de pago actualizada, indicándole que mensualmente estamos pagando 805€. ************************************ Recibo email de Ana (que me reenvia email de Toni de Futuex): URGENTE diligencia Agencia Tributaria: El tutelado entrega una carta que recibió de hacienda el día anterior, al leerla se comprueba que ya se hizo intento de hacer otra entrega y no se produjo, Felipe comenta que cree que le llegó una notificación para que fuese a recogerla y nunca fue… Se le dice que las notificaciones de la Agencia Tributaria son muy importantes, se cierra diciendo que no debe dinero a nadie, se le intenta explicar que no tiene porqué deber dinero, sino que le pidan información de algún tipo. Según se entiende, se trata de una diligencia de embargo por una deuda que tiene el Sr. Fernando Bravo Calvo, al investigar quien es este señor, se conoce que es el jefe de la empresa de dependencia que atiende al tutelado. Parece ser que solicitan que no se le haga abono de la cuantía que corresponde y se pague directamente a hacienda, la deuda asciende a 2.931,53€. Junto a la diligencia se adjunta un anexo que el tutelado debe rellenar y enviar para aclarar la relación comercial que tiene con el deudor, indicando el pago que le hace, cuándo, cantidad y la temporalidad del mismo, esto debe hacerlo llegar antes del 22 de noviembre pues tiene un plazo de 10 días hábiles desde el día siguiente a la entrega de la notificación. Se adjunta, en documento a parte, la carta recibida con toda la información. El tutelado se encuentra muy nervioso, establece que no debe dinero a la empresa de dependencia, se le dice que se quede tranquilo pues no tiene problema alguno, se va a comprobar y se solucionará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-02-11','-Amalia , envio email a Beatriz del Ctro. Penitenciario Buenos días , hay que solicitar traslado de expediente , pero se especifica en el modelo que tiene que tener un domicilio de forma permanente en la Comunidad de traslado. En este caso José no tiene domicilio fijo , está en Ctro. Penitenciario , habría que esperar , está empadronado en algún domicilio de Extremadura ? Con respecto al dinero , la compañera de cuentas ya se lo ha explicado pero sigue llamando exigiendo dinero . Como no puedo hablar con él te lo comunico a tí por si se lo puedas indicar y para que sepas cuál es su situación. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-02-11','-Amalia , envio email a Beatriz del Ctro. Penitenciario Buenos días , hay que solicitar traslado de expediente , pero se especifica en el modelo que tiene que tener un domicilio de forma permanente en la Comunidad de traslado. En este caso José no tiene domicilio fijo , está en Ctro. Penitenciario , habría que esperar , está empadronado en algún domicilio de Extremadura ? Con respecto al dinero , la compañera de cuentas ya se lo ha explicado pero sigue llamando exigiendo dinero . Como no puedo hablar con él te lo comunico a tí por si se lo puedas indicar y para que sepas cuál es su situación. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-02-11','-Amalia : me llama la TS del CSS , está ingresada en la UHB y esta tarde la subirán a medicina interna . Me pide q llame a la madre . Se llama Mª Dolores tf 605977520.Queda informada . Dice que le costó ceder su tutela y que no está conforme con las respuestas sanitarias que le han dado a su hija . Que no deberia haber salido de alta a los pisos . Que su hija no puede vivir sóla y que discrepa del actual psicolo que lleva a su hija , Manuel Picado , que la anima a llevar una vida aútoma . Le indico que es su hija la que quiere irse del piso , que me ha llamado en varias ocasiones con esta idea y que incluso está buscando piso y trabajo . Le explico que para pisos se exige su voluntariedad y que puede pedir el alta voluntaria. Dice que eso no es posible y que lo tiene puesto todo en manos de abogados que pondrán la situación en conocimiento del Fiscal . El lunes hablaré con Manuel sobre este caso más en profundidad para ver su evolución en piso . Todo dependerá de su evolución hospitalaria actual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2022-02-14','Ana: Correos de ayer domingo de Alfredo Moreno Febrián (residenciaplasenzuela21@gmail.com): "Buenos días. Me ha comunicado la Residencia que Doña Antonia Serrano Suárez acaba de fallecer y han llamado al médico de urgencias para que certifique el fallecimiento. En cuanto lo tenga que lo envió, junto con el informe de alta hospitalaria (ya que como te indicó Natalia el viernes le habían dado el alta hospitalaria y estaba en la Residencia). Solo tenemos el teléfono de contacto de un hermano hermano en una residencia de la Vera (esta vez que ha estado ingresado no hemos podido contactar con él). La otra vez que estuvo ingresada si se habló con su hermano y se le preguntó cómo proceder en caso de fallecimiento y nos dijo que él no sabía y que lo hiciéramos nosotros (por lo tanto se la va a enterrar aquí en Plasenzuela e intentaremos localizar al hermano para informarle). A continuación te indico cómo se va a proceder: 1.- He llamado al Ayuntamiento para localizar un nicho libre. 2.- En cuanto certifique el médico, llamaré a la funeraria para que realice el servicio en el Tanatorio de Plasenzuela). 3.- Como no tiene seguro de decesos, la funeraria procederá a hacer una factura por el coste del servicio (también incluirán en la factura el importe del nicho, que previamente ellos pagan al Ayuntamiento). 4.- Esta factura os la enviaré para que procedáis a realizar el pago a la funeraria." ············ "Ya está todo preparado, es posible que la funeraria se ponga en contacto con vosotros. Le he facilitado tú correo electrónico y el de la comisión tutela, también le he facilitado los teléfonos de la Comisión Tutelar. También te indico que ya hemos informado su hermano que está en la Residencia de Madrigal de la Vera y no ha dicho que nos encarguemos nosotros, que él no puede venir. Mañana a primera hora te envió el informe hospitalario de Alta (08/02/2022) y el Certificado Médico de Defunción. Para cualquier duda me puedes llamar." ·················· "Me comentan en la funeraria si mañana a primera hora os podéis poner en contacto con ellos. Teléfono: 609 965 572 (Fran)." ······································································································································ *Finalmente, las compañeras de la secc. ecca., comprueban que sí tenía seguro de decesos. ············· *Llamo a la Funeraria (609 965 572) y facilito a Fran el nº de póliza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2022-02-11','Ana: Correo de las Res. Plasenzuela (residenciaplasenzuela21@gmail.com): "Buenas tardes, comunicarles que Antonia Serrano ya ha sido dada de alta. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2022-02-13','EXITUS El centro informa de su fallecimiento, acaecido el 13/02/2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-02-14','Ana: Solicito a Toni-Futuex, por mail, nos remita Certificado de Empadronamiento de José en el hostal y en su defecto un certificado del hotel indicando la fecha desde la que se aloja en el mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2022-02-14','-Email Amalia : Buenos días Oscar , tenéis que hacer transferencia al Nº cuenta del padre ( lo tenéis de otras ocasiones ) con un total de 2005€ . La factura del dentista son 1455 € ( la tenéis adjunta ) Factura del ordenador , le restan 550€ . ( también se adjunta ) Ya he hablado con la familia , no se abonará nada más que no esté previamente aceptado por nosotros . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-02-14','miguel, tras llamada hace unos días, me dijo Inmaculada de Cid y Villafaina que el expte estaba encima de la mesa de su jefe y que le preguntaría que le falta para que se pueda desbloquear la cuenta. *********************************************** Envío nuevo email a Inmaculada de Cid y Villafaina: Buenos días Inmaculada, por favor recuerdale a tu jefe que revise el expediente de José Antonio, hay que ir agilizando el desbloqueo de la cuenta. Cualquier cosa que necesite dile se ponga en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-02-14','miguel, envío email a Ana TS: Buenos días Ana, veo en la intranet esta anotación de hoy tuya “Envío a Miguel, Asesor Jurídico, los documentos completos de la Agencia Tributaria remitidos por Toni-Futuex. ·············· Solicito a Toni nos remita Certificado de Empadronamiento de José en el hostal y en su defecto un certificado de hotel indicando la fecha desde la que se aloja en el mismo.” Mira a ver si me has enviado algo de este expte pues no me ha llegado nada nuevo. En cuanto tengas algún justificante de donde reside actualmente (certificado de empadronamiento o comunicación del hostal de que reside desde tal fecha…)podré enviar contestación al requerimiento del juzgado. Por favor intenta agilizarlo que ya nos han requerido varias veces y no se ha retenido ni pagado nada a AEAT.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-02-14','Buenas tardes. Tenemos que encontrar una solución al caso de Mª Jesús Cruz. Ha entrado en una fase en la cual: no cumple ninguna norma de convivencia ni terapéutica. No ayuda a las tareas comunes, no arregla su habitación, descontrol de horario de levantarse y acostarse, provoca discusiones, faltas de respeto a los monitores y usuarios, etc. No quiero verme en la situación de tener que expulsarla de los PS. Ella sabe que es un Recurso voluntario. Creo que es una buena opción el alquiler de 280 que había encontrado. Tendría supervisión externa. Tiene opciones laborales. Su familia ayudaría, siempre y cuando ella cambie la actitud con ellos. Ya me dirás porque al piso no quiere volver y los monitores le tienen miedo. Buen domingo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2022-02-14','Ana: Tras conversación con Alberto, Jefe de Secc. Ecca., la pasada semana, envía correo-e a Iciar, con copia para mí: "ICIAR: HABLAS DIRECTAMENTE CON DIRECTORA DEL CENTRO Y CIERRAS: • PAGO PLAZA: CONFIRMA LOS 450 €/MES...DOMICILIACIÓN O TRANSFERENCIA • PRESUPUESTO MES: - APORTACIÓN VEHÍCULO PASEO: 100 €/MES - SOCIO PROTECTOR: 15 €/MES - MEDICINAS: 30 €/MES (MEDIA) • CONFIRMAS IMPORTE APROX. Y FORMA DE PAGO. IMPORTANTE: SEGURO DECESO: SI NO TIENE HAY QUE FORMALIZAR...ICIAR: SE LO PASAS A ESTRELLA. DEUDA: EN CUANTO ENTREN EN CCC LOS ATRASOS DE LA PENSIÓN SE DEDICAN EN SU PRÁCTICA TOTALIDAD A LA CANCELACIÓN DE LA DEUDA Y EL RESTO, SI EL CENTRO ESTA DE ACUERDO, A MEDIDA QUE COBRE PAGAS EXTRAS."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-02-14','Buenas tardes. Tenemos que encontrar una solución al caso de Mª Jesús Cruz. Ha entrado en una fase en la cual: no cumple ninguna norma de convivencia ni terapéutica. No ayuda a las tareas comunes, no arregla su habitación, descontrol de horario de levantarse y acostarse, provoca discusiones, faltas de respeto a los monitores y usuarios, etc. No quiero verme en la situación de tener que expulsarla de los PS. Ella sabe que es un Recurso voluntario. Creo que es una buena opción el alquiler de 280 que había encontrado. Tendría supervisión externa. Tiene opciones laborales. Su familia ayudaría, siempre y cuando ella cambie la actitud con ellos. Ya me dirás porque al piso no quiere volver y los monitores le tienen miedo. Buen domingo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2022-02-14','-Amalia : He hablado con Rubén por tf. Solicita un extra , le he pedido que hable con Raquel y que suba la asignación y de ahí ahorre y se compre lo que quiera. Quiere montar una empresa , ser autónomo , que le demos 7500€ para iniciar y que luego pedirá una subvención... Le indico que todo eso se lo tiene que autorizar un juez , que lo comente en su revisión de sentencia . Quiere irse a vivir al pueblo , la madre le dice que no .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2022-02-14','Ana: Preparo oficio y entrego a Julio, CTAEX, los informes recibidos por la residencia Casa Familiar Virgen de la Montaña, ya firmados por el D. Gerente, para que se los devuelva al centro por correo certificado. ············· De los informes extraemos: Antonio es totalmente autónomo para las ABVD. También realiza varias actividades instrumentales ( *Participa en las actividades (aunque cada vez con menor motivación) y se comporta de manera adecuada. *Sólo muestra una mínima alteración cuando le molestan o increpan. // Come dieta diabética no estricta. // En septiembre de 2021 tuvo un altercado con un compañero, por lo que tuvo que acudir a urgencias por una herida en el párpado inferior del ojo izquierdo. // Según la Fisioterapeuta Antonio lleva una vida muy sedentaria y a raíz de la pandemia, las salidas se han visto reducidas. "Ha perdido agilidad y destreza para realizar los ejercicios que antes hacía bien." A pesar de ello, *"sigue siendo un residente funcional e independiente, mantiene su capacidad física para realizar las actividades de la vida diaria" ············ En la esfera afectiva, manifiesta eutimia, aunque permanecen quejas puntuales relativos al grupo primario, familiares de laos que demanda atención, pero éstos no pueden cubrir dichas necesidades" *Aunque este año ha recibido llamadas y visitas de ambas primas. *No sintomatología de carácter ansioso, ni preocupaciones excesivas ni temores, ni trastornos susceptibles de ser tratados. Sueño y apetito conservado. *Solicitud recurrente de hacerse un tatuaje. ············· A nivel cognitivo se mantiene estable, leve deterioro, pero sin cambios significativos.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2022-02-14','Ana: Preparo oficio y entrego a Julio, CTAEX, los informes recibidos por la residencia Casa Familiar Virgen de la Montaña, ya firmados por el D. Gerente, para que se los devuelva al centro por correo certificado. ············· De los informes extraemos: Antonio es totalmente autónomo para las ABVD. También realiza varias actividades instrumentales ( *Participa en las actividades (aunque cada vez con menor motivación) y se comporta de manera adecuada. *Sólo muestra una mínima alteración cuando le molestan o increpan. // Come dieta diabética no estricta. // En septiembre de 2021 tuvo un altercado con un compañero, por lo que tuvo que acudir a urgencias por una herida en el párpado inferior del ojo izquierdo. // Según la Fisioterapeuta Antonio lleva una vida muy sedentaria y a raíz de la pandemia, las salidas se han visto reducidas. "Ha perdido agilidad y destreza para realizar los ejercicios que antes hacía bien." A pesar de ello, *"sigue siendo un residente funcional e independiente, mantiene su capacidad física para realizar las actividades de la vida diaria" ············ En la esfera afectiva, manifiesta eutimia, aunque permanecen quejas puntuales relativos al grupo primario, familiares de laos que demanda atención, pero éstos no pueden cubrir dichas necesidades" *Aunque este año ha recibido llamadas y visitas de ambas primas. *No sintomatología de carácter ansioso, ni preocupaciones excesivas ni temores, ni trastornos susceptibles de ser tratados. Sueño y apetito conservado. *Solicitud recurrente de hacerse un tatuaje. ············· A nivel cognitivo se mantiene estable, leve deterioro, pero sin cambios significativos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-02-14','TERESA HABLO CON SU PRIMA MARICARMEN 657042224 Y LE COMUNICO QUE A PARTIR DE MARZO PUEDE SACAR 100€ SEMANALES QUE LOS SUMINTROS ESTAN DOMICILIADOS QUE EL DESBLOQUEO DE LA CUENTA ESTA EN MANOS DEL CID Y VILLAFANIA QUE LAS FACTURA DE TELEFONO VIENE POR IMPORTE DE 200€, ENIO A FUTUEX PARA QUE GESTIONE ALGO MAS ECONOMICO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-02-14','Ana: Llamada de Rebeca, sobrina de Emilia, le ha llamado Montaña, Médica de la Residencia El Cuartillo, le ha comunicado que Emilia ha estado 8 días ingresada en el hospital. Está indignada porque nadie le había informado al respecto. Le informo, 1º, que ni el personal del la Resid. ni el de la CTAEX está obligado a informar a los familiares. *No obstante desde la CTAEX tenemos en cuenta a la familia cuando se muestra colaboradora y no hay otro tipo de intereses. 2º nosotros tampoco sabíamos que ha estado ingresada. ······················································································· Llamada de Claudia, TS CR El Cuartillo (22162): no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-02-14','Ana: Llamo a Sara Pozo, TS del HUC (927 256 322 / 56781): no ha conseguido contactar con el médico, en cuanto sepa algo me informa. ······················· más tarde contacta conmigo, ha visto a Feliciano, hoy estaba mucho más espabilado. *Le han confirmado que ayer le hicieron PCR, ha dado negativo y hoy mismo le darán el alta y le trasladarán a la Res. de Casas de Don Antonio, plaza privada T3.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2022-02-14','Maite: desde la sección de salud Mental nos han pasado la resolcuión de adjudiación de plaza por situación de emergencia social en el Centro Residencial de Rehabilitación de Salud Mental de Cáceres. Está escaneada , en su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2022-02-14','Ana: Recabo la firma del D.Gerente y pongo para registro de ENTRADA la Comunicación de cambio de datos del expediente de Dependencia.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2022-02-14','va Álvarez >trabajadorasocialco@plenainclusionmontijo.org> Lun 14/02/2022 13:39 Sí, leí tu correo. Yo estoy intentando hacerle ver que el tema vaginoplastia va a ser más complicado que se lo aprueben, porque yo estimo que no tiene mucho dinero ahorrado como para no necesitar un préstamo y, es obvio que un banco no le va a dar un dinero teniendo una pensión tan pequeña, la cual necesita para abonar la cuota de la vivienda tutelada. Con respecto a lo de ponerse a dieta, está en ello, pero es verdad que le está costando, además de por la ansiedad que tiene por la comida, porque está muy pasada de peso y tiene mucha tripa. De todas formas sólo sería informarnos en un principio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2022-02-14','Buenos días , autorizo para que se le suba la asignación mensual de 250€ al mes a 350€ al mes . Está en CRR de Mérida . Os paso email del centro solicitándolo . Sería para iniciar en marzo . Administracion CRR Merida >administracion.crrmerida@grupo5.net> Lun 14/02/2022 13:37 Buenos días Amalia, Según conversación telefónica, confirmamos con equipo técnico la posibilidad de pasar a cobrar Ruben Montero el próximo 1 de marzo 350€, de los cuales pueda sufragar extras fuera del alcance de su planificación y conseguir ahorros para sucesivas peticiones. Quedamos pendiente hablar cuando puedas con respecto a la llamada mantenida con él. Gracias de antemano,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2022-02-14','Buenos días , autorizo para que se le suba la asignación mensual de 250€ al mes a 350€ al mes . Está en CRR de Mérida . Os paso email del centro solicitándolo . Sería para iniciar en marzo . Administracion CRR Merida >administracion.crrmerida@grupo5.net> Lun 14/02/2022 13:37 Buenos días Amalia, Según conversación telefónica, confirmamos con equipo técnico la posibilidad de pasar a cobrar Ruben Montero el próximo 1 de marzo 350€, de los cuales pueda sufragar extras fuera del alcance de su planificación y conseguir ahorros para sucesivas peticiones. Quedamos pendiente hablar cuando puedas con respecto a la llamada mantenida con él. Gracias de antemano,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-02-14','-email FUTUEX : Gracias por avisar. Te cuento lo que sabiamos nosotras a finales de la semana pasada: Desde el miercoles por la tarde noche nos está insistiendo de una forma más intensa que quiere irse del piso supervisado, porque no aguanta más. Según expresa ella, Manuel le habría indicado que el jueves se podría ir e instalarse en otro piso de forma independiente, pero ayer a última hora le indicaba que no será posible ya que la comisión no lo aprueba. Ella se refiere a esta situación como "un cachondeo" ya que por un lado recibe la expectativa e ilusiones de irse de forma independiente a un piso de alquiler y por otro, solo son trabas para llevarlo a cabo. Desde el equipo de apoyo social comunitario tratamos de trabajar con ella la posibilidad de mantenerse en dicho recurso y para entretenerla, siguiendo en la línea de intervención que previamente consesuamos contigo, le marcamos buscar alternativas y solicitud de ayudas ya que solo con su pensión no podría asumir los gastos. Amenaza con escaparse del piso como hizo recientemente, suceso que ocurrió durante una noche de la semana pasada. La semana pasada se hizo una visita a los pisos, pero no pudimos ver a Mª Jesús pues no estaba, la monitora expresaba que no ven a la tutelada para alta terapéutica e incluso, bajo su criterio, debería volver al sociosanitario pues en los pisos no está consiguiendo adaptarse y no está cumpliendo ni las normas ni los objetivos, además, refleja que existen problemas de conducta y está siendo compleja la convivencia. Y si ahora está ingresada pues parece estar todo en la linea de esos problemas de conducta ... cualquier cosa estamos en contacto. Saludos.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-02-14','-email FUTUEX : Gracias por avisar. Te cuento lo que sabiamos nosotras a finales de la semana pasada: Desde el miercoles por la tarde noche nos está insistiendo de una forma más intensa que quiere irse del piso supervisado, porque no aguanta más. Según expresa ella, Manuel le habría indicado que el jueves se podría ir e instalarse en otro piso de forma independiente, pero ayer a última hora le indicaba que no será posible ya que la comisión no lo aprueba. Ella se refiere a esta situación como "un cachondeo" ya que por un lado recibe la expectativa e ilusiones de irse de forma independiente a un piso de alquiler y por otro, solo son trabas para llevarlo a cabo. Desde el equipo de apoyo social comunitario tratamos de trabajar con ella la posibilidad de mantenerse en dicho recurso y para entretenerla, siguiendo en la línea de intervención que previamente consesuamos contigo, le marcamos buscar alternativas y solicitud de ayudas ya que solo con su pensión no podría asumir los gastos. Amenaza con escaparse del piso como hizo recientemente, suceso que ocurrió durante una noche de la semana pasada. La semana pasada se hizo una visita a los pisos, pero no pudimos ver a Mª Jesús pues no estaba, la monitora expresaba que no ven a la tutelada para alta terapéutica e incluso, bajo su criterio, debería volver al sociosanitario pues en los pisos no está consiguiendo adaptarse y no está cumpliendo ni las normas ni los objetivos, además, refleja que existen problemas de conducta y está siendo compleja la convivencia. Y si ahora está ingresada pues parece estar todo en la linea de esos problemas de conducta ... cualquier cosa estamos en contacto. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-02-14','Buenas , con respecto a Emi he vuelto a hablar con los terapeutas del CRR , para el día 16 hay que enviarle un extra de 140€ . Se ha ido del centro una semana como medida terapéutica y tiene que cubrir gastos de manutención y regreso al centro . Con respecto a la subida de su asignación mensual , con esta descripción de gastos que me muestras ( el caso lo ha llevado hasta ahora Teresa ) no se le puede subir a 400€ , para poder asumir algunos extras que van a surgir . Calculad vosotros cuánto sería lo máximo que se le podría dar al mes . Lo que sí se nos pide es que la asignación la perciba en dos quincenas . Indicadme en qué entidad bancaria podría ir a retirar los 140€ , no sabemos su dirección exacta , pero creo que está en Don Benito . Dónde hacía los reintegros cuando ha estado viviendo allí ? Seguimos ...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2022-02-15','Ana: Recabo la firma del D.Gerente y pongo para registro de ENTRADA la Comunicación de cambio de datos del expediente de Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-01-12','TERESA INGRESA EN CENTRO DE SALUD MENTAL Y AREVALO EN PALENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-02-14','Ana: Llamo a Amor López, TS ASPACE (690 79 16 38), para solicitar informe para la solicitud de traslado por cambio de PIA (Dependencia): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MIRANDA'and apellido2='GODOY'),'2022-02-14','TERESA SE ACUERDA ENTRA LAS PARTE ECO, JURIDICA Y SOCIAL QUE AL SER UNA CURATELA DE SALUD VAMOS A SOLICITAR QUE QUITEN AL REPRESENTANTE LEGAL TANTO DEL BANCO COMO DE LA PRESTACION LA FAMILIA DEMANDA CAMBIAR LA PRESETACION DEL BBVA A IBERCAJA Y NO PUEDEN PORQUE PIDEN LA FIRMA DEL REPRESENTANTE LEGAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2022-02-14','TERESA Tras reunión parte eco, social y jurídica acordamos aumentar la asignación 50€ este mes para contribuir con los gastos de manutención en la familia. Queda pendiente valoración para el mes de marzo en función de si vuelve al centro Gracias¡¡','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-02-15','Ana: Recibimos informe social solicitado para la rendición de 2022. En el mismo se detalla la trayectoria de Felisa desde que ingresara en ASINDI en diciembre de 2021, sus continuas llamadas de atención, incidencias, episodios de heteroagresividad, intentos de fuga... y qué técnicas y estrategias están llevando a cabo desde el equipo profesional para intentar minimizar y reconducir estas conductas. Así como para aumentar su motivación y promover la mejora y estabilidad de su estado emocional. ············ En cuanto a las relaciones familiares, ningún miembro de su familia se ha interesado por ella desde que está en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-02-15','OSCAR: TRAMITAR REINTEGRO PUNTUAL DE 140 € A TUTELADA ENTRE LOS DÍAS 16 Y 25 DE FEBRERO DE 2022. IMPORTANTE: ESTE REINTEGRO PUNTUAL TIENE QUE SER EN DON BENITO...CREO QUE YA HEMOS HECHO ALGUNOS REINTEGROS EN ESA POBLACIÓN...LE COMUNICAS A TUTELADA LA OFICINA CUANDO YA ESTE HECHA LA AUTORIZACIÓN. AMALIA: SE AUTORIZA REINTEGRO PERMANENTE X 175 €/QUINCENA (350 €/MES) ...AMALIA: ENTIENDO QUE ESTE REINTEGRO PERMANENTE ES EN OLIVENZA: CONFÍRMANOSLO XFA... AMALIA: TAMBIEN ENTENDEMOS QUE VA SIN ACOMPAÑAMIENTO??? OSCAR: CUANDO AMALIA NOS CONFIRME LA LOCALIDAD EN LA QUE SE REALIZARÁ EL REINTEGRO PERMANENTE LO TRAMITAS: 175 €/QUINCENA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2022-02-14','Ana: Recibimos Informe Social emitido Emilia, TS del CSS solicitado previamente por la CTAEX para la Rendición Anual 2022. En el mismo hace constar que "El paciente se mantiene estable, sin alteraciones ni enfrentamientos notables con otros pacientes ni con el personal profesional, con notable estado de desánimo y desinterés. De forma continuada plantea ser trasladado al Centro Sociosanitario de Mérida...", "El médico Psiquiatra no encuentra un motivo médico-clínico para realizar un informe clínico motivado para un traslado, pues el paciente se encuentra psicopatológicamente estable y no presenta causas clínicas motivadoras a tal petición, aunque considera que en caso de solicitud del paciente y de la comisión tutelar de adultos de cambio de centro, por motivos psico-sociales y motivación del paciente, no encuentra negativa al cambio..." A continuación propone dicho cambio, que considera puede ser beneficioso, pues Jairo presenta conductas desorganizadas, exigentes hacia personal, con una necesidad de solicitar cuestiones a organismos judiciales fuera de la norma legal... y con una actitud manipuladora al no ver cumplidas sus expectativas." ··················· Envían también Informe de la Psicóloga Clínica Ana Rosa Glez.: actualmente "...no existe descompensación psicopatológica, ni alteración sobre su funcionamiento basal; mantiene estabilidad y buena adherencia al tratamiento farmacológica.", "Desde el punto de vista psicológico, por tanto, no existe impedimentos para cursar la solicitud del interesado"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-02-15','miguel, Patricia Bono (>patibo@hotmail.com>)me remite citación del Jzdo nº3 Badajoz: Hola Miguel, Te envío la citación que le ha llegado a Alejandro para que tengáis constancia y para que por favor a ver si podéis informaros de que procedimiento se trata y porqué está citado en calidad de investigado. ********************************************* Llamo al Jzdo nº3 sin éxito, por lo que les remito el siguiente email (instruccion3.badajoz@justicia.es.) Buenos días, tras el intento sin éxito para comunicar con su juzgado vía telefónica, le adjunto citación a una persona curatelada por la Junta de Extremadura (se adjunta sentencia de incapacitación y nombramiento a la Comisión Tutelar de Adultos). Necesitamos que por favor nos aclaren el motivo de la citación y si es o no necesario la asistencia de esta Comisión Tutelar de Adultos. El curatelado no dispone de abogado por lo que necesitaría que de oficio el juzgado solicitara uno de oficio. Si fuera necesaria la asistencia de esta Comisión Tutelar de Adultos, ruego nuestra asistencia vía videoconferencia de la web video.justicia.es, para lo que necesitaríamos que nos indicaran la ID y el código de acceso.********************************************** Reenvío email a Amalia: Buenos días, me ha remitido Patricia Bono una citación judicial en claidad de investigado de Alejandro. No sé de que puede ser, he mirado emails y la intranet y no logro hablar con el juzgado nº3 de Badajoz. Les he enviado un email a ver si me dan respuestas. Lo he subido a la intranet por si quieres verlo. Si me entero de algo te diré…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-02-15','TERESA FUTUEX:el 8 de febrero de 2022. Nos indican que desde la Comisión tutelar les han informado que, en el plazo de esta semana o la próxima semana, Pablo será trasladado al centro sociosanitario. Manifiestan que como se va a proceder con los animales que tiene en el domicilio (gallinas y un perro). La agente indica que debe ser gestionado por comisión tutelar ya que desde el ayuntamiento no existe un recurso de recogida de animales, que la única solución sería entregar las gallinas algún vecino de la localidad y en relación al perro localizar una perrera que pueda hacerse cargo del animal. El traslado es involuntario, están evitando que el tutelado conozca el proceso ya que se realiza en contra de su voluntad y el rechaza irse de su domicilio. Por este motivo es difícil que pueda llevar preparado ese día todos sus objetos personales. En relación a su domicilio nos dice que se solicitaría a la auxiliar de ayuda a domicilio que una vez realizado el traslado fuese al domicilio para dejar la casa lo mejor posible ya que se quedaría sin habitar. No sabemos si la casa es exclusivamente del tutelado, o es vivienda familiar, ya que según dice la agente de policia,... ha oido comentarios de que un hermano de Pablo que está divorciado, en cuanto este la casa vacia, la va a ocupar. Pablo, alguna vez ha comentado algo de este hermano, y parece que tiene mala relación. Ya me comentas tambien de cara a la duración del traslado (por si no fuera permanente y fuera solamente para la rehabilitacion alcoholica) de cara a todo esto, y a los sumunistros y el mantenimiento de la cassa. Tambien, si tenemos que star el dia del traslado o colaborar de alguna forma, para poder organizarnos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='QUINTIN'and edp.apellido1='SANCHEZ'and apellido2='ALAMILLO'),'2022-02-15','EXITUS La familia informa de su fallecimiento. El óbito tuvo lugar el 19/09/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='QUINTIN'and edp.apellido1='SANCHEZ'and apellido2='ALAMILLO'),'2022-02-15','TERESA RECIBO LLAMDADE ROSA POVEDA 679241004 SOBRINA POLITICA DE QUINTIN PARA PEDIR INFORMACION DE DONDE SE ENCUNTRA DOMICILIADA LA PENSION DE SU TIO PUES EN LA CUENTA DEL SANTANDER NO APARECE NOS INFORMA QUE HA FALLECIDO EL 19 DE SEPTIEMBRE DE 2021, NO TENIAMOS CONOCIMIENTO DE LA DEFUNCION LE FACILITO INFORMACION DE LA CUENTA ABIERTA EN LIBERBANK QUE ES DONDE COBRA LA PENSION COMENTA QUE HOY VAN A FIRMAR LA HERENCIA CON LA GESTORIA GEAPOLIS CONSULTING 924221964','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-02-15','Ana: Envío correo a Modesto, Res. Casas de Don Antonio (administracion@centrodemayoressierradesanpedro.es): "Buenos días Modesto, Tal y como acabamos de acordar, mediante conversación telefónica, os remito adjunta la siguiente documentación escaneada relativa a FELICIANO BORREGUERO CAMBERO: - DNI - Tarjeta Sanitaria Adjunto remito también la Ley 8/2021 En cuanto al contrato, una vez lo hayamos recibido y recabemos la firma del Representante Legal, os lo haremos llegar. Recordar que deben ser dos copias para que podamos quedarnos uno firmado por ambas partes. En relación a las pertenencias que Feliciano tiene en el CRR, acabo de hablar con Cristina, Psicóloga y actualmente Directora en funciones del centro. Le he facilitado tu número y te llamará para organizaros. En principio no tiene inconveniente alguno en tener todo abajo alguna tarde a la hora que acordéis. *Quedo a la espera del presupuesto aproximado de gastos mensuales y, el precio de la plaza, que no te lo he preguntado. Con todo esto, una vez tengamos el visto bueno de Alberto, Jefe de sección económica, mis compañeras de la sección económica se pondrán en contacto contigo. Un saludo y buen día." ················· Envío nuevo correo a Modesto: "Hola de nuevo Modesto, Olvidé decirte que Feliciano, sólo cuenta con una prima, de la cual no tengo el contacto, y con su cuñado Antolín 600 818 400, pero con este mantiene una relación conflictiva (es mutuo…). Su hermana y sus padres fallecieron y están enterrados en Aliseda, su localidad natal y lugar en que también le gustaría ser enterrado. Mientras ha podido, ha visitado el cementerio de vez en cuanto. Lo digo por si, su salud en un momento dado lo permitiera y él quisiera, se podría contratar un taxi y poner un acompañamiento."','2');
