insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2022-02-15','Ana: Envío correo de Estrella Durán, TS del CSS Plas. (estrella.duranc@salud-juntaex.es): "En relación a Carlos Alberto Vicente Calderero, podéis proceder a cumplimentar la solicitud de plaza en centro residencial PLACEAT por Dependencia, cuando la tengáis me la hacéis llegar para recabar la firma del Representante Legal e incluso, por agilizar, darle registro de entrada desde aquí."','2');
