insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2022-02-15','Buenas Cris , como bien dices es mucho dinero , se necesitaría una autorización judicial . Por otro lado , si decides ir hacia delante en el caso de que tuvieras ese dinero ahorrado lo tienes que tener muy claro , tus cuentas se quedarían a 0 . Piénsalo bien ... Se van a revisar todas las sentencias incluidas la tuya , tendremos que plantear todo ésto . No hemos recibido respuesta con respecto a la solicitud del DNI Un saludo .','1');
