insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2022-02-15','Esperanza Grao >pitugrao@gmail.com> Vie 11/02/2022 10:45 Buenos días Amalia, soy Esperanza Grao, la madre de Macarena Otano Grao, he intentado hablar contigo por teléfono pero no ha sido posible, es por ello que te escribo este correo. Macarena está aquí en Badajoz con nosotros, también está Eduard, su novio, está muy bien, dentro de su linea, han decidido vivir aquí con nosotros, están haciendo un curso en el Call Center de Elvas para trabajar, están ilusionados. Decirte que tendrás que volver a notificar su cambio de residencia a Badajoz, necesita sus médicos aquí, ya sabes que los necesita, ya está empadronada aquí. Otra cosa el mes de febrero no se lo han pagado, hemos llamado y dicen que ya tienen sus datos, pero la nómina no llegará hasta este mes, que hacemos? , Esta rebotadisima, ya le hemos dado/prestado dinero, pero le supo fatal, podemos reclamarlo? Gracias, espero tu respuesta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2022-02-15','Esperanza Grao >pitugrao@gmail.com> Vie 11/02/2022 10:45 Buenos días Amalia, soy Esperanza Grao, la madre de Macarena Otano Grao, he intentado hablar contigo por teléfono pero no ha sido posible, es por ello que te escribo este correo. Macarena está aquí en Badajoz con nosotros, también está Eduard, su novio, está muy bien, dentro de su linea, han decidido vivir aquí con nosotros, están haciendo un curso en el Call Center de Elvas para trabajar, están ilusionados. Decirte que tendrás que volver a notificar su cambio de residencia a Badajoz, necesita sus médicos aquí, ya sabes que los necesita, ya está empadronada aquí. Otra cosa el mes de febrero no se lo han pagado, hemos llamado y dicen que ya tienen sus datos, pero la nómina no llegará hasta este mes, que hacemos? , Esta rebotadisima, ya le hemos dado/prestado dinero, pero le supo fatal, podemos reclamarlo? Gracias, espero tu respuesta ----------------------------------- Amalia : respuesta : Buenos días , necesitamos que nos envíes cdo. de empadronamiento para enviarlo a Pensiones no contributivas y volver a solicitar el traslado de expediente . He hablado por tf. con ese servicio y hasta que el expediente no esté tramitado en Extremadura no podrá percibir la pensión. El traslado de médicos puede gestionarlo ella directamente en su centro de salud. Vamos a incluirla de nuevo en los seguimientos de esta Comisión , le pediré a la delegada tutelar que la llame y quede con ella para visitarla . Indicadnos su Nº de tf. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2022-02-15','Ana: Julio REGISTRA en SIREX el oficio junto con la Aceptación PIA para SAR y el Alta de Terceros a la Secc. de Dependencia V - Plasencia (a la que pertenece el EVD-Coria). Buzón de SIREX: A11030404 (Indicado por Cristina Carrón) ·········· Se lo remito a Cristina Carrón por mail (cristina.carron@salud-juntaex.es) y lo comunico a Loli, Residencia de Calzadilla (RESIDENCIA SANTA CATALINA CALZADILLA >residenciasantacatalina@gmail.com>) ·········· Acuerdo con Loli que la Aceptación PIA para la prestación vinculada aún no la registraremos, pues le ha quedado libre una pública y dependerá de si puede ingresar ella u otra persona y si ésta última fuera hombre o mujer, el que ella puede incluso acceder a la vinculada... hablará con Mai, Jefa secc. mayores, y me informará en cuanto le confirmen algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='LOPEZ'and apellido2='THOMAS'),'2022-02-15','Ana: envío correo-e a Carmen Martín, TO EVD-Plas. (carmen.martinmon@salud-juntaex.es): "Buenas tardes Carmen, En relación a ANTONIA LOPEZ THOMAS, cuyo cargo de Curador Representativo ostenta la CTAEX, adjunto remito la documentación que teníamos pendiente: - ACEPTACIÓN PIA de la prestación vinculada al SAR, firmada digitalmente - Alta de Terceros Ante cualquier otra cuestión, no dudes en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-02-15','Ana: Tras hablar con Felisa Custodio, TS CAMF, vuelvo a reenviar a Alberto, jefe secc.ecca, varios correos anteriores con el presupuesto de la Tasación pendiente de aprobar y que Miguel, Asesor Jurídico, indicó que habría que aprobar y realizar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2022-02-15','-Amalia : llamo a su madre para obtener informacion sobre la VPP . No se la han dado todavía a nadie . Me confirma que el hijo le dió de alta a los suministros de agua y luz.Pongo a firma el documento para dar de baja el agua . Me comenta que no va a ver al hijo y que de vez en cuando la llama . Que habla los domingos con su hermana . Que una orden judicial les prohíbe ver a su nieta .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2022-02-15','TERESA Me pongo en contacto para comunicarte que el Programa de Intervención que se está llevando a cabo con Libertad está dando resultados positivos. Accedió a asistir a la consulta de Salud Mental y está tomando una medicación que hace que esté más abordable y más tranquila en general. Y por otro lado, después de Navidad ha comenzado a trabajar en uno de los trabajos que ya abandonó hace algún tiempo. No te comenté nada cuando empezó porque siempre que empieza un trabajo lo abandona a los pocos días pero de momento lleva ya un mes y las previsiones son de continuidad. Está contratada por el centro especial de empleo dependiente de PLena Inclusión Llerena y son 9 horas semanales como limpiadora de un portal y el sueldo son 196,95€ Esperemos que todo siga así por mucho tiempo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2022-02-16','Ana: Correo-Respuesta de Estrella Durán: "Buenos días, Ana. Puse de manifiesto ayer en reunión de Equipo, tu correo sobre la nueva solicitud de plaza residencial en Placeat de Carlos Alberto y, se concluyó que, por ahora es mejor que no se tramite, ya que el paciente está adaptado y estable en la UHDAC...." ·········· Se lo comunico a Maite, Jefa de Secc. CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-02-16','miguel, envío email a Patricia Bono: Buenos días Patricia, desconocía por completo este procedimiento. He intentado hablar a la mañana de ayer con el juzgado e incluso les he mandado un email pero no les llega. He remitido esta mañana un fax solicitando que le nombren abogado de oficio, y que nos informen del motivo de dicho procedimiento. Asi mismo les he indicado que se trata de una persona curatelada y que en caso de que sea necesario nuestra asistencia nos lo digan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-02-16','-Se recibe email de Futuex , voy a plantear a Miguel solicitar al fiscal ingreso en UMe . Buenas tardes Amalia, que tal? El viernes 11 de febrero de 2022, Mercedes Pérez Pinna, tenía programada consulta de revisión de psiquiatría en área de salud mental de ciudad Jardín con su psiquiatra Fernando Galán a las 13.30 horas. Comentarte que no acudió. Te desarrolló la sitaución: Desde este equipo de apoyo social comunitario de Badajoz, hemos estado intentando contactar con ella, para planificar acompañamiento a dicha consulta, pero o bien no atendía nuestras llamadas, o colgaba en otras ocasiones. Por lo tanto se decide acudir a su domicilio, donde tampoco se obtiene respuesta a través de portero electrónico. Pasado unos minutos, recibimos una llamada de Mercedes donde nos quiere comunicar lo siguiente: que “su hermano está en Badajoz con unas conductas molestas y alterando el orden público. Que Ella no tiene problemas con su comunidad de vecinos y no quiere que esta situación de su hermano le afecte”. Le decimos que su hermano, según nuestra información, reside en Córdoba no aquí en Badajoz. Mercedes insiste en que su hermano está en Badajoz, provocando escándalos, que solo nos lo comunica por si sucede algo más. Le recordamos que los intentos de contactar con ella son por la consulta de revisión que tiene programada en esta mañana en psiquiatría, algo que ella nos niega rotundamente una y otra vez, diciendo que estamos equivocadas y nos cuelga. Se ha contactado con el equipo de salud mental de ciudad jardín, con la ts concretamente, para comunicar la negativa de Mercedes a acudir a su cita, negando que tuviera nada programado y que solo nos ha llamado para contar una situación no real sobre su hermano. Desde salud mental no han podido contactar con ella y nos comunicaran que realizaran reprogramación de cita y seguirán trabajando e intentando su adherencia a tratamiento y consultas de revisión. Poquito más nos plantean de cara a esta situación. Si nos consta, que el inyectable se lo puso, el 1 de Febrero en salud mental, a pesar de no tener cita, se presentó alli. Cualquier cosa en la podamos intervenir, quedamos a disposción. SEguimos!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2022-02-16','TERESA Buenos días Teresa, me pongo en contacto contigo para preguntarte si sabes como va el proceso para retirar la curatela de Carmelo. Hoy me estaba esperando para decirme que SE PONE EN HUELGA DE HAMBRE PORQUE YA NO AGUANTA MAS ESTAR CURATELADO. Él ha llamado a Teresa Pacheco pero no le coge el teléfono y se ha cansado. No sabes cuanto tiempo puede demorar esto?. A Carmelo no le he podido quitar la idea de la huelga de hambre, ya le he dicho a Teresa Pacheco que le llame y hable con él. Está cansado y es normal. Va a ser dificil hacerle cambiar de idea, ya lleva tiempo amenazando con la huelga de hambre o con encadenarse en la plaza. Y como siempre le decimos que tenga paciencia pues ya no surte efecto el diálogo. A mi realmente me preocupa, no se si vosotras quizás podais explicarle mejor y hacer que cambie de opinión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2022-02-16','TERESA ME COMUNICA MARIA TS DEL CENTRO LA PROVIVENCIA traslado a otro servicio de la tutelada, informarte que ella misma nos ha comunicado que ha gestionada plaza en el centro de día de Sierra Pinar. Sabe el coste y demás. Si conoces algún dato más nos dices. El contacto que ha tenido ella ha sido una trabajadora llamada MªCarmen. Es lo que sabemos. DESDE LA CTAEX NO TENEMOS CONOCIMIENTO DE ESTA SOLICITUD ENVIO EMAL A LA RESIDENCIA PREGUNTANDO POR ESTA SOLICITUD','2');
