insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-02-16','-Amalia : comunico al ESM la situación actual . Buenas , la delegada me ha informado de la situación de Mercedes , que al parecer tiene delirios con su hermano y que no ha consentido ir a la cita prevista . Me ha informado que ya te lo había comentado a tí . Los vecinos también han contactado con nosotros , están preocupados por su estado de salud . A ver cómo valora el psiquiatra su situación. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2022-02-16','-Amalia , envio email a Miguel : Cómo se puede proceder para pasar el expediente de tutela a Cataluña ?? No soy capaz de contactar con la señora ha puesto mal su tf. De: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Enviado: viernes, 11 de febrero de 2022 9:58 Para: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es> Asunto: JUAN ANGEL CHAVARRÍAS VIZUETE Buenos Días, ha llegado éste correo.saludo De: Salud Extremadura >inf.saludextremadura@salud-juntaex.es> Enviado el: jueves, 10 de febrero de 2022 12:40 Asunto: Contacto Comisión Tutelar de Adultos Nombre: Lourdes Apellidos: Chavarrías Vizuete Asunto: Traslado a otro centro Sociosanitario Mensaje: Buenos días, soy Lourdes y tengo un hermano que está en el socio sanitario Adolfo Díaz Ambrona de Merida. Comentarles que por temas familiares lo queremos trasladar a otro socio sanitario de la comunidad de Cataluña, la tutela la tiene la comunidad extremeña. Como tenemos que proceder? Para contactar conmigo mi teléfono es 655484322. Espero su respuesta. Gracias','2');
