insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-02-16','Ana: Envío por correo-e a Modesto, Res. Casas de Don Antonio (administracion@centrodemayoressierradesanpedro.es): el contrato de la residencia firmado por ambas partes. ······· Y a Alberto, jefe secc. ecca.: la información del coste de la plaza residencial así como la del resto de gastos de periodicidad mensual/bimensual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2022-02-16','TERESA realizamos nota para dar a conocer el rechazo que lleva manifestando para ser visitada desde el mes de noviembre. Al aproximarse las fiestas navideñas y el ingreso de la paga extra, nos indica que si desde comisión tutelar no le dan los 733 euros de paga extra ella rechaza cualquier visita desde la Fundación Tutelar, dicha negativa la sigue manifestando hasta la fecha utilizando el dinero como alternativa a aceptar o no los seguimientos presenciales. Insiste continuamente que su asignación no le llega para todos sus gastos semanales, sin embargo, se comprueba que estos gastos son exclusivamente para actividades de ocio (salir a tomarse algo con amigos o cenar). Ella se excusa que este dinero también tiene que gastarlo en comida porque sus hermanos le obligan a aportar algo más de sus gastos de bolsillo para la compra de la unidad familiar. Cuando se intenta trabajar con ella la gestión económica, para determinar qué gastos precisa que sean prioritarios para cubrir necesidades básicas o extras que se le presenten, rechaza cualquier ayuda indicando que lo quiere y punto, que no quiere dar explicaciones a ningún profesional de lo que hace con su dinero. Es decir, su objetivo es tener más dinero para salir con los amigos y que no le pidan explicaciones de cómo lo administra. No se si esto te orienta de cara a la posible subida de asignacion que ella plantea.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2022-02-16','TERESA EMAIL ISABEL PUERTO PSICOLO PI ZAFRA Te informamos que en el día de ayer Josefa Domínguez Blanco tuvo una importante alteración conductual que requirió la intervención de los servicios médicos. Tuvo que ser trasladada a Llerena a una consulta de urgencia, donde la doctora Mª Luisa Álvarez, tras hablar conmigo como una de las psicólogas de referencia del caso, decidió, a pesar de mi insistencia en que la dejara ingresada, dar el alta esa misma tarde. Ella mostró un cuadro de agitación y agresividad grave hacia varios profesionales. Del mismo modo tiró una piedra contra una puerta de cristal rompiendo la misma. Se pasaron serios momentos de tensión y el riesgo de haber experimentado daño hacia sí mismo y hacia los demás fue elevado. Te adjuntamos los informes médicos que nos facilitaron. En cuanto tengamos desarrollados con detalle los hechos ocurridos os lo mandaremos igualmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2022-02-17','Ana: llamo a Marili, Directora del C.O. de Miajadas (927029632 y 21959): Le harán llegar la cartilla bancaria al CRR a través de un trabajador del centro que vive en Cáceres. ················· *Le enviaré la renuncia a la plaza de C.O.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-02-17','Maite: el 9 de febrero fuimos a Plena Inclusión Cabeza del Buey, para visitar a Marta y hablar con ella, ya que está faltando mucho a centro ocupacional sin causa justificada, y también pq no admninistra bien su asignación mensual. Incialmete hablamos con Alexandra, trabajadora social del CO y la psicóloga.Nos confirmaron que una de las razones por las que no acude es pq la condicionan su novio y su suegra, ya que ellos no ven necesario que Marta acuda al centro. Además el novio se pone celoso pq va en el transporte con dos compañeros, habiendo increpado a uno de ellos. Concidimos en que la forma de hacer que Marta vaya al CO es controlar su dinero desde la entidad. Dándole 5 € el dia que vaya, y no dándoselo cuando se ausente sin motivo justificado, asícomo gratificándola cada cierto tiempo si consigue continuidad. Por otro lado, hemos decidido darle una asignación a la suegra de 100€, para gastos de manutención, que estará condicionado también a que Marta vaya al centro. Preguntamos a Alexandra si MArta ha tenido contacto con su madre, nos ha dicho que no.Hablamos sobre la posibilidad de trabajar en un futiro la relación con su madre. Tras la reunión, hablamos con Marta. Le preguntamos como está en el CO, nos dijo que bien pero que le da pereza ir pq tiene que madrugar.... Le comentamos cómo íbamos a gestionar el dinero, a través del centro, pq élla no se organiza bien. Hablamos tb sobre la posibilidad de cambiar de método anticonceptivo ( usa parches semanales). Le da miedo cambiar. El 25 de febrero tiene cita con el ginecólogo. La acompañarán Teresa de futuex, le hemos pedido que se lo comente al ginecólogo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-02-17','Ana: Correo de Manuel Andrés Casado, TO, EVD CC (manuel.casado@salud-juntaex.es): "Buenos días, Adjunto Aceptacion PIA de Doroteo Diaz Cerro, tutelado por la Comision Tutelar de Adultos, con el fin de ser firmada por el Director Gerente. Como en otras ocasiones, entiendo que tras ser firmada, daréis registro de entrada, y salida cuando proceda. A continuación, expongo texto modelo de aceptación. Confirmad si recibís correctamente el mail y el archivo adjunto. Muchas gracias y feliz día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSE'and edp.apellido1='MOLINA'and apellido2='SALAZAR'),'2022-02-17','TERESA RECIBO LLAMADA DE TACIANA PARA COMENTARME QUE M JOSE ESTA INGRESADA EN LA UHB, SE LE HA TRAMITADO RECURSO POR EMERGENCIA SOCIAL ESTA PENDIENTE DE LA FIRMA DEL TUTOR TACIANA.VALVERDE@SALUD-JUNTAEX.ES TELF 81620','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-02-17','miguel, llama el abuelo del curatelado, Pedro Bono para quejarse que hay que revisar la situación económica del curatelado (quiere subida de la asignación), y que cómo queda su situación sanitaria, si se le va a ingresar, o cómo controlar que va al médico. Me pide le justifique los ingresos que se han hecho en las hermanastras y de cuánto dinero queda. Le digo que por la ley de datos no se puede dar esa información pero que paso nota a la parte económica y social quienes les contestarán.************************* Remito email a Alberto y Amalia: Buenos días, ha llamado el abuelo para quejarse que no le atendemos y que quiere que se le informe de: -Alberto: Nueva situación de cuánto dinero le queda a su nieto y cuánto va a cobrar al mes. En definitiva que se le suba la asignación -Amalia: Dice que allí no puede seguir viviendo Alejandro (quejas habituales de descontrol con su persona y sus horarios y que las sigue liando. Que ahora no sale por miedo que le hagan algo) Quiere que se le busque algo a Alejandro pero a parte que a su madre. Ya le he explicado que salvo que vosotros digáis lo contrario por la ley de protección de datos sólo se puede dar información al juzgado y a Alejandro, pero se empeña en que desde la junta nadie les comunica nada. Le he explicado que las medidas a adoptar serán revisadas por un juez, puesto que se van a revisar, conforme a la nueva ley de discapacidad, todas las sentencias. Le he vuelto a recordar que tienen un email para solicitar lo que necesiten, y que una vez haya una respuesta por la Comisión Tutelar, se le contestará. Por favor, revisad su expediente y si depende de su revisión judicial, preparadlo para que la solicitemos cuanto antes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2022-02-17','Ana: Envío correo a Alberto, jefe secc. ecca. con copia a Maite, Jefa CTAEX: "Buenas tardes Alberto, En relación a JUAN JOSÉ MASEDA DEL SOL, hay que establecer presupuesto de gastos. Percibe PFHC y Orfandad en la cuenta antigua. Ya están comunicadas las variaciones de datos bancarios al INSS, pero se ha comunicado en enero. Entiendo que la Orfandad ya la ingresarán en la nueva cuenta el mes que viene, pero la PFHC hasta abril no la ingresarán en la misma, por el carácter trimestral. *Tiene seguro de decesos propio (lo gestionó Icíar) *Tienen también una deuda (después te explicamos Maite y yo) de 8.800€ *A parte tiene otro préstamo bancario La propuesta de gastos por parte de la Sección Social es la siguiente: - Hacer una transferencia periódica mensual a su hermano (convive con éste y con su cuañada): 305 € = 250€ en concepto de manutención + 100€ para el abono de la deuda) - Autorización de retirada de efectivo: 30 € /quincena = 10 € para la tarjeta del móvil + 20 € para gastos de bolsillo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2022-02-17','TERESA HABLO CON EL PADRE DE MANUEL, MANUEL DOMINGUEZ 623247979, LE COMENTO QUE SU HIJO HA SACADO VARIOS REINTEGROS SIN NUESTRA AUTORIZACION POR IMPORTE DE 1000€, EL PADRE DESCONOCE LOS HECHOS Y ME FACILITA EL TELFF DE SU HIJA CON LA CUAL YO HABIA ACORDADO PASARLE POR TRANSFERENCIA 200€ PARA QUE LE ADMINISTRE EL DINERO A MANUEL LLAMO A ROSA HERMANA DE MANUEL 665302945, LE COMENTO LO MISMO QUE A SU PADRE Y LE INDICO QUE ESTE MES NO LE PODEMOS PASAR LOS 200€ POR ESTE MOTIVO Y QUE TAMPOCO HA DEJADO DINERO PARA PASAR LA MANUTENCION DE SU HIJA. ELLA COMENTA QUE NO SABE NADA AL RESPECTO QUE EL SIGUE VIVIENDO CON ELLA Y QUE HOY HAN IDO AL CONTROL AL CEDEX. ACORDAMOS SEGUIR CON LAS MISMAS CONDICIONES EN CUANTO HAYA DE NUEVO DINERO EN LA CUENTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2022-02-18','miguel, me remite Ana Ts el informe de hechos del CSS que le solicitó el Jzso de Plasencia nº1 sobre procedimiento DPA 490/21','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-02-18','miguel, posición de la parte económica Alberto: En mi opinión, a su ABUELO, no deberíamos informarle de ninguna cuestión, al menos ECO, que afecte al tutelado. TODOS: saldo hoy, tras haber recuperado depósito y repartido, previa acuerdo con familiares: 29.409,53 €...esto NO ES DINERO...el último año hemos abonado 1.000 € aprox .en multas y similares. PENSIÓN: ha subido de 672,30 a 853,30 €/mes ASIGNACIÓN: es de 666 €/mes a través transferencia a madre...podríamos subirla hasta 847 €/mes. YO NO LE DARÍA NI UN € MÁS...DISTRIBUIDLO COMO QUERÁIS PERO ESE DEBERÍA SER EL LÍMITE. Ejemplo: podemos mantener los 666 €/mes de asignación y volver "AYUDAR AL ALQUILER" x 181 €/mes (que es lo que le ha subido la pensión. ******************************************** contestación de Amalia: Buenas tardes , con respecto a parte eco , yo subiría su asignación al máximo que indica Alberto 847€ y que ellos la administren como consideren oportuno . Con respecto a la búsqueda de recursos , ya hemos hablado este asunto en varias ocasiones . Como sabéis si estableció una Subcomisión de Gestión de Casos y se está gestionando según lo acordado . El recurso tiene que ser solicitado por su Equipo de Salud Mental , que así lo hizo , pero de momento no cumple requisitos . En los próximos días tiene revisión en el CADEX y dependerá de la resolución del mismo . Voy a esperar a este resultado para valorar las posibles medidas de apoyo a establecer en su revisión de sentencia . Comparto la opinión de Alberto con respecto a dar información a su abuelo . ****************************************** mi contestación: Buenos días, a parte de la asignación, él solicita que Alejandro se vaya a vivir a otro sitio. Evidentemente le dije que la información por la ley de protección de datos no se le puede dar a ellos. En mi opinión este es uno de esos casos que deberíamos agilizar la rendición de cuentas y la revisión de las medidas de apoyo. Hace tiempo que no hablaba con él pero ante su insistencia y teniendo en cuenta que tiene una citación judicial que ignoramos tanto ellos como nosotros (y me remitió vía email su hija Patricia), me vi en la obligación de coger la llamada…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-02-17','Ana: Correo de Claudia, TS El Cuartillo (claudia.alonso@salud-juntaex.es): "Informarte que la Dra. Román ha derivado a Emilia al hospital para que valoren patología de su pierna. Según me indica ya está informada Gloria (educadora)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-02-17','Ana: Modesto, Res. de Casas de Don Antonio, informa acerca del estado de Feliciano mediante email: "Feliciano la verdad es que está muy bien, nos comentan desde enfermería que las noches las pasa muy bien, que está muy tranquilo y bastante adaptado al centro. Come bien y demás pero aún le cuesta un poco a la terapeuta hacer que colabore. Aún es pronto pero en términos generales está muy bien. Confiemos que siga así e incluso mejor."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-02-17','Ana: Correo de Toni-Futuex, remitiendo Certificado del Hotel Palacete, en que indican que José reside en el mismo. ·········· Informa también de que han realizado los trámites oportunos junto con José para empadronarle en el Hotel. *Aún están pendiente del Certificado como tal. ··········· Así mismo, comunican que han recibido llamada de Cristina, dueña de la anterior pensión, diciendo que ya han abonado la deuda pendiente con Hacienda. ·············· *Indico a Toni que no me han remitido ninguno de los dos justificantes (ni el el padrón ni el del abono de la deuda). ·························································································· Envío a Miguel, Asesor Jurídico, el Cdo. del Hotel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2022-02-21','Ana: Envío correo a Miguel, Asesor Jurídico, y Alberto, jefe secc. ecca.: "Buenos días Alberto y Miguel, Os reenvío el correo del CRR de Cáceres con multa de Juan José Bergantiño Glez. Se la pusieron cuando residía en Badajoz por beber en un parque. Supongo que habrá que pagarla." ····································· Respuesta de Miguel, Asesor Jurídico: "..., no está finalizado el procedimiento (mandan acuerdo de inicio de procedimiento) En cuanto le llegue el definitivo que se pague…" ·········· Se lo comunico a Cristina, Psicóloga CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-02-21','Ana: Envío a Belén Gutiérrez, TS Secc. Acceso a RR. Discapacidad, propuesta de viajes para que los dos hermanos vayan a visitar a la familia, remitido por Sonia-Asindi.','2');
