insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-02-21','Ana: Llamada de Doroteo (609 928 621), pregunta si ya le han abierto su cuenta propia. *Le informo de que está abierta y que ya se ha pedido que le ingresen la pensión en la misma. Es probable que este mes ya se la ingresen en la misma. ····························································································································· Envío correo a Alberto, jefe secc. ecca., con información aprox. de los gastos mensuales y propuesta de presupuesto. *Se propone transferencia a su madre de 300€/mes en concepto de manutención y 50€ semanales para gastos de bolsillo. ······························································································································································································· Envío a Manuel Casado, TO EVD (manuel.casado@salud-juntaex.es): "Comunicarte que ya tengo la ACEPTACION PIA de DOROTEO DIAZ CERRO firmada digitalmente por el Representante Legal, pensaba registrarla aquí, pero falta tu firma. Te la mando adjunta para que puedas firmarla y tú me dices si lo registras ahí o si me la devuelves para que le demos registro desde aquí, como tú prefieras. Ya me dices."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-02-21','Buenas tardes , con respecto a parte eco , yo subiría su asignación al máximo que indica Alberto 847€ y que ellos la administren como consideren oportuno . Con respecto a la búsqueda de recursos , ya hemos hablado este asunto en varias ocasiones . Como sabéis si estableció una Subcomisión de Gestión de Casos y se está gestionando según lo acordado . El recurso tiene que ser solicitado por su Equipo de Salud Mental , que así lo hizo , pero de momento no cumple requisitos . En los próximos días tiene revisión en el CADEX y dependerá de la resolución del mismo . Voy a esperar a este resultado para valorar las posibles medidas de apoyo a establecer en su revisión de sentencia . Comparto la opinión de Alberto con respecto a dar información a su abuelo . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2022-02-21','TERESA ayer Nerea tuvo dos crisis acompañadas de agresividad, una por la mañana en la que fue necesario la presencia del 112 (le inyectaron calmante) y la guardia civil para contenerla por el estado de alteración. Y por la tarde noche tuvo otra crisis en la que fue necesaria nuevamente la presencia del 112, guardia civil y policía por el estado de agresividad en el que se encontraba. Se activó el traslado al hospital de Mérida a las 11.00 de la noche; al ser esta hora, en nuestro centro contamos solo con una cuidadora de noche por lo que no pudo acompañar a Nerea. Nos pusimos en contacto con el hospital y con la psiquiatra de guardia para informarla de todo lo ocurrido y de las características y medicación de Nerea. Sobre la 01.00 de la madruga se ponen en contacto con nosotros desde el servicio de psiquiatría para informarnos que le dan el alta y que era nuestra responsabilidad el acompañamiento porque esta paciente no puede volver sola en la ambulancia al centro; por lo que desde nuestro centro decide que vayan a por ella la educadora social y la cuidadora. Somos conscientes que esta desestabilización de Nerea ha sido provocada por la presencia de una nueva usuaria al centro, por las amenazas, insultos y tocamientos. Esperemos que esta situación no vuelva a ocurrir. Como siempre te lo comunico para que tengas constancia de ello. Dime si es necesario que te remita parte de incidencias y alta de psiquiatría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-02-21','Asunto: CITA ALEJANDRO NUÑEZ CADEX Amalia : he avisado a Futuex para que lo acompañen a la cita . Al abuelo lo han avisado desde CADEX . Me he reunido con Carmen , TS del ESM esta mañana , simplemente por saber cual será el procedimiento a seguir después . Tendrán que volver a solicitar otra vez la UDAC . Buenos días Maite como hemos hablado te remito para vuestro conocimiento y por si fuera necesario la cita de Alejandro Núñez. De todas formas me pongo en contacto con su abuelo para comentarle el día y la hora Un saludo Susana Hernández Espada Administrativo CADEX C/ Agustina de Aragón,16 06004 Badajoz Teléfono 924009529','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-02-21','Asunto: CITA ALEJANDRO NUÑEZ CADEX Amalia : he avisado a Futuex para que lo acompañen a la cita . Al abuelo lo han avisado desde CADEX . Me he reunido con Carmen , TS del ESM esta mañana , simplemente por saber cual será el procedimiento a seguir después . Tendrán que volver a solicitar otra vez la UDAC . Buenos días Maite como hemos hablado te remito para vuestro conocimiento y por si fuera necesario la cita de Alejandro Núñez. De todas formas me pongo en contacto con su abuelo para comentarle el día y la hora Un saludo Susana Hernández Espada Administrativo CADEX C/ Agustina de Aragón,16 06004 Badajoz Teléfono 924009529','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2022-02-21','-Email del ESM : Se encuentra ingresada Concha en HUB en la planta de Neumología. Se encuentra baja de ánimo decaída, le están haciendo pruebas. Me pide que os envíe un correo para contactar con ella','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2022-02-21','-Email del ESM : Se encuentra ingresada Concha en HUB en la planta de Neumología. Se encuentra baja de ánimo decaída, le están haciendo pruebas. Me pide que os envíe un correo para contactar con ella. Buenas , sí , ya sabíamos que iba a ingresar . Su solicitud es siempre la misma , dinero , y se le da su asignación íntegra . Nos llama Manuel y nos la pasa para que pida dinero . No se le puede dar más de lo que ingresa . Con respecto a Mercedes P.P. , acudió a la nueva cita programada ? se ha puesto inyectable ?? Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2022-02-21','-Email del ESM : Se encuentra ingresada Concha en HUB en la planta de Neumología. Se encuentra baja de ánimo decaída, le están haciendo pruebas. Me pide que os envíe un correo para contactar con ella. Buenas , sí , ya sabíamos que iba a ingresar . Su solicitud es siempre la misma , dinero , y se le da su asignación íntegra . Nos llama Manuel y nos la pasa para que pida dinero . No se le puede dar más de lo que ingresa . Con respecto a Mercedes P.P. , acudió a la nueva cita programada ? se ha puesto inyectable ?? Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2021-11-09','Ana: Correo de Toni con cuestiones varias, entre ella: "22/10/2021 Se realiza acompañamiento a consulta en psiquiatría del equipo de salud mental de Cáceres, con su psiquiatra de referencia, Dra.: Isabel Rubio. Se contacta con el tutelado a primera hora de la mañana para recordarle la cita y comprobar que mantiene accesibilidad para que se realiza el acompañamiento, se queda con él en la puerta del centro de salud mental 15 min. Antes de la consulta, acude acompañado de su madre y nada más llegar ésta saluda y levantando la voz transmite a la educadora que será ella quien acompañe a su hijo a la consulta, no se lo pone impedimento alguno y se la reconoce el derecho a acompañarlo como madre y conviviente que es del tutelado, la comunicación con la educadora es tensa y con connotaciones agresivas. La consulta se retrasa y durante la espera el tutelado se muestra muy nervioso e intranquilo, síntoma de escasa paciencia y nula capacidad de espera, se levanta constantemente y manifiesta quejas constantes por la espera, el comportamiento del tutelado y en menor rasgo el de su madre demuestra que son personas muy exigentes. Entre ellos están discutiendo constantemente y se faltan al respeto mutuamente en todo momento, mediante ataques verbales e incluso insultos. Una vez en la consulta se realizan las presentaciones pertinentes y se muestra accesible a que se pase a la consulta por lo que se realiza en presencia de Doroteo, su madre y la educadora. La consulta se desarrolla entre discusiones y ataquen entre madre e hijo, con faltas de respeto constantes entre ellos, la psiquiatra comunica que es la tónica habitual de comunicación entre ellos, informa que siempre ha habido problemas de convivencia y una relación bastante conflictiva entre ellos, confirma que no son síntomas clínicos del paciente si no problemas de convivencia y relacionales en el ámbito familiar y doméstico. La relación del tutelado con sus hermanos según el mismo manifiesta es nula y la psiquiatra confirma que nunca los ha visto ni los conoce, no están implicados en la vida de Doroteo. Carmen, la madre del tutelado transmite que no se toma bien la medicación y que a veces llega a casa bebiendo a alcohol, la doctora le transmite que debido a la tipología del tratamiento de Doroteo (Trecvita, inyectable cada 3 meses), el resto de medicación es complementaria y si un día no lo toma bien no es peligroso y aumentará los síntomas de su trastorno, intenta calmar los ánimos entre ellos ofreciendo soluciones. Se comenta también en la consulta que ha sido usuario de CRPS y fue dado de alta, también ha participado de forma activa en el club de ocio de FEAFES con aprovechamiento, el por su parte solicita poder hacer un curso de informática y se le ofrece ayuda por parte del equipo en la búsqueda de recursos formativos. Carmen por su parte comunica que lo quiere tener en casa y solicita que se le derive a un centro residencial, se le explican en la consulta los protocolos de acceso a los centros para que comprenda que no es tan sencillo y que debe haber disponibilidad por parte del tutelado. Tras la consulta la Dra.: pide que se quede la educadora en el despacho para transmitir impresiones e intercambiar criterios, informa q es un perfil muy complicado sobre todo por las relaciones familiares que siempre han sido conflictivas, informa del ultimo ingreso en UHB que fue en 2017. Explica que tras aquel ingreso no se han observado síntomas psicóticos en el paciente, pero si bastantes problemas a nivel conductual, achaca los problemas de convivencia al carácter de ambos y no a síntomas clínicos de Doroteo, datos que se confirman a lo largo de la mañana tras observar la relación entre ellos. El próximo 21 de diciembre tiene cita para el inyectable a las 9:40 h con Montse del equipo de salud mental. Se recibe llamada de Pilar Martín TS del equipo de salud mental de Cáceres, explicando que han estado en su despacho la madre y la hermana de Doroteo para confirmar si la educadora del equipo de apoyo es realmente educadora de este equipo y trabaja para la CTAEX, explica también que han verbalizado en la consulta que no desean que el tutelado viva en casa de su madre y exigen que se le derive a un centro residencial. Por otro lado, insisten sobre un dato que ya se trató en la consulta con la Psiquiatra, el hecho de que según su madre conduce el coche de un conocido, en la misma consulta el tutelado mostró que tiene el carnet de conducir en vigor y renovado recientemente por la DGT por lo que la doctora no vio inconveniente en que conduzca y se les explicó a ambos que si comete alguna infracción deberá asumir las consecuencias legales como cualquier ciudadano, pero que si tiene el permiso en vigor no se puede impedir que conduzca. Se envía esta nota junto con el resto de seguimientos y documentación aportada (por él y su madre) en la primera visita al domicilio, para exponer el contexto general de este nuevo tutelado al cual tan sólo se le ha visitado en dos ocasiones, pero sé que pretende realizar seguimiento la próxima semana. En esta semana, es en la que se ha constado la NEGATIVA POR PARTE DE LA HERMANA Y LA MADRE A QUE CONTINUE RESIDENCIA EN EL DOMILICIO, por los multiples conflictos.. Doroteo no se responsabiliza de nada y la convivencia es horrible todo el día a gritos y faltas de respeto constantes la madre no lo quiere en casa segú dice porque hay muchos problemas y es muy mayor pero el tampoco plantea alternativa así no sabemos q se puede hacer, segun la compañera indica no parece presentar muchas habilidades para vivir de forma a autónoma en un piso de alquiler, ante la pregunta de si estaría dispuesto a estar en un centro no creemos que en caso de aceptar fuera viable porque tiene una ausencia total de normas y de responsabilidades."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTA'and edp.apellido1='CABRERA'and apellido2='MORA'),'2022-02-16','EXITUS El centro nos informa de su fallecimiento. Acaecido el 16/02/2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-02-21','Ana: Habiendo comunicado Alberto, jefe secc. ecca.: "A DÍA DE HOY SE PODRÍA ABONAR UNA TASACIÓN...SIEMPRE QUE NO APAREZCAN EMBARGOS QUE DESCUADREN LA CCC...repito, desde 08/2021 no ha venido ninguno." ···· Envío correo-e a Felisa Custodio, TS CAMF Alcuéscar (trabajadora_social_alcuescar@imserso.es): "En relación a la TASACIÓN de la vivienda de CARMEN GÓMEZ MUÑOZ, por fin puedo comunicarte la AUTORIZACIÓN de la SECCIÓN ECONÓMICA para llevarla a cabo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2022-02-21','Ana: Llamo a Loli, Res. Santa Catalina de Calzadilla (927 146 458), me dice que aún no le han confirmado lo que la plaza, así que aún no me puede enviar el contrato. De momento Emiliana seguirá ocupando la plaza de Piso y quedamos a la espera de que le confirmen en la Secc. Mayores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-02-21','miguel, hablo con Basilia y su hija Encarni (encarnigarcia2014@gmail.com) quienes me comentan que está en 3º instancia pendiente la impugnación de venta que han hecho las hermanas del tutelado. El caso lo lleva un abogado Horacio (tlfno 645-79-47-64). Envio un email a la hija para que se quede nuestro contacto a efectos de los gastos e ingresos que conlleve la propiedad común. Basilia está dispuesta a vender su parte a Miguel, si estuviera interesado o a comprarla. Aunque no hemos hablado del valor de la misma, me comenta su hija Encarni que es una casa muy vieja con que necesita reforma y que la idea era alquilarla a los que aparecen en el informe policial que mandaron la policía local del Ayto de Fuente del Maestre, quienes si harían cargo a cambio de no pagar de ir reparando sus desperfectos, pero que debido a los problemas que les está ocasionando con las hermanas han decidido cerrarla sin más. Y una vez que sea firme la resolución judicial de la impugnación de la venta del padre del tutelado a Basilia, en ese momento nos pondremos de acuerdo para alquilar, vender, etc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2022-02-21','-Amalia : lo intervienen quirugicamente del higado el dia 25 . Las hermanas vendrán para quedarse con él . Hablo con la Secretaria de hepático viliar para confirmar que el consentimiento esté firmado , me indican que ya lo tienen . ------------------------------------- Me llama Juani auxiliar ( 666863893) Julio plantea la necesidad de irse los dos , junto con Isabel su mujer a un centro . Isa ya es dependiente , no puede apenas levantarse y necesita cuidados permanentes. He quedado con Juani que hablaremos después de la operación sobre este tema , yo haría su revisión PIA y Mayte del SSASB el de Isabel .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2022-02-21','-Amalia : lo intervienen quirugicamente del higado el dia 25 . Las hermanas vendrán para quedarse con él . Hablo con la Secretaria de hepático viliar para confirmar que el consentimiento esté firmado , me indican que ya lo tienen . ------------------------------------- Me llama Juani auxiliar ( 666863893) Julio plantea la necesidad de irse los dos , junto con Isabel su mujer a un centro . Isa ya es dependiente , no puede apenas levantarse y necesita cuidados permanentes. He quedado con Juani que hablaremos después de la operación sobre este tema , yo haría su revisión PIA y Mayte del SSASB el de Isabel .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2022-02-17','-Amalia : consulto el tema de su PNC con Adela. Tenemos que enviarles a Mérida un cdo. empadronamiento de Macarena para solicitar de nuevo el cambio de expediente. Se lo he pedido a la madre .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2022-02-21','Ana: Correo de Toni, TS CR Cervantes (antonia.dediego@salud-juntaex.es): "María Luisa sigue con los mismos problemas de conductas con sus compañeros. Sí podéis hacer algo para adelantar su traslado sería muy conveniente para ella. Además, ella sigue demandando el traslado casi a diario." ·································· Mi respuesta: "Buenos días Toni, Vaya, siento que Mª Luisa siga actuando de la misma manera. En principio no está en nuestra mano adelantar el traslado, no obstante, lo comunico a Maite, Jefa de Sección por si puede hablar con la Jefa de la Sección de Mayores al respecto."','2');
