insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL MARIA'and edp.apellido1='SANTOS'and apellido2='GOMEZ'),'2022-02-21','Amalia : nos remueven del cargo : 1º: Dejar sin efecto la designación de la Comisión Tutelar de Adultos de Extremadura como curador y que fue acordada en sentencia aludida anteriormente. 2º.- La constitución de una curatela designándose como curador a D. FRANCISCO ESCUDERO ALMENA, el cual asistirá al demandado en el ejercicio de la capacidad jurídica en el ámbito puesto de manifiesto anteriormente. 3º.- Las medidas de apoyo establecidas serán revisadas en el plazo de 3 años.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-02-21','Ana: Tras hablar con Belén Gutiérrez, TS de la Secc. Discapac, envío correo a Sonia Bernabé, TS Asindi: "Buenas tardes Sonia, En relación a la posibilidad de transporte para las salidas de Aarón Rosado Alarcón a su domicilio, he consultado a la compañera de la Secc. de acceso a recursos de discapacidad que lo gestiona. Me dice que a priori no es posible, ya han hecho un esfuerzo para que entren los usuarios que ya lo recibían antes con el “apaño” de 1 vez al mes, pero resulta que no han incrementado este año el presupuesto a Cruz Roja, ... No obstante, haremos la solicitud formal desde aquí para que entre en lista de espera para cuando vayan surgiendo bajas en el servicio y puedan acceder usuarios nuevos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2022-02-21','Ana: Alberto da ok al presupuesto. ········· Llamo a Sara (675 50 07 12), cuñada de David, hermano de Juan José, con el que convive: el teléfono está ocupado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2022-02-21','-Amalia : priorizo el caso para revisión : Buenos días , os comento cómo he gestionado yo el primero de los casos que voy a priorizar para revisión de sentencia . He mantenido reunión de coordinación con el centro , para estudiar las medidas de apoyo que vemos necesaria para Cris . El informe social que envía el centro , contiene mis propias opiniones , son compartidas tanto por el centro como por mí y también por Joaquín. Se solicita cambio de la tutela actual ( muy desproporcionada para la realidad que presenta la persona , aunque entiendo en que su día el juez lo consideró así por factores sociales. ) por una curatela asistencial , sólo para la esfera económica , para gastos de extraordinaria cuantía. Para todo lo demás tiene capacidad plena para llevar una vida totalmente autónoma . Con este informe social , queda justificada esta esfera. La sección eco entiendo que tendrá que presentar rendición de cuentas . Y todo ello Miguel / Ángel lo presentará al juzgado. Es correcto el proceso a seguir ?? Un saludo','2');
