insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-02-21','-Hablo con Carmen , le he pasado el email enviado a la parte eco y a su hijo para coordinarnos con las acciones. Buenos días Amalia. Soy Carmen, la Trabajadora Social de Valdelacalzada. Llamame cuando tengas un hueco para hablar de Rosa Serrano Garcia Mi teléfono es el 627051020 Gracias, un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2022-02-21','-Amalia : email de seccion eco enviado tb a Reme , la TS del SSASBuenos días. Analizada la situación económica con Alberto, por ahora no da el visto bueno a la subida de la asignación semanal. Me comenta que habría que controlarle los gastos en supermercado y fruta. La previsión que teníamos realizada era de una media de 320€ al mes, pero en los últimos meses ha subido a 405€ de media, por lo que habría que vigilar esta circunstancia. Además, en el último año ha comprado sillones por valor de 1029€ y ha realizado reformas en la vivienda por 2269€. Un saludo.B.','2');
