insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2022-02-22','Buenos días, mira la intranet, con fecha 11-11-21 te puse: llega por carta testamentaria de la madre fallecida de la tutelada consistente en dni, certificado de defunción, últimas voluntades y cartillas de la cuenta del Sch con saldo de unos 3.000€ (único bien a declarar y repartir). Compruebo que en catastro no existen más bienes. Hay que hacer la declaración de herederos ya que fallece sin hacer testamento, el cual hay que hacerlo en la notaria de Azuaga, lugar de fallecimiento ya que falleció en la Residencia Socio Sanitaria Hogar San José. Hablo con Teresa para que localice dos testigos para dicha declaración de herederos. No hay hecho nada, hay que hacer la declaración de herederos, para lo cual tienes que confirmarme que puedan firmar en la notaria de Azuaga (para mandar a dicha notaria la información). Una vez hecha hay que presentarla a liquidar el impuesto de sucesiones con los bienes que haya. Si como parece no tienen bienes inmuebles, bastaría para repartir el dinero en el banco un posterior escrito de acuerdo de reparto','2');
