insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2022-02-22','miguel, mi respuesta a Amalia: Buenos días, pide a la parte económica que elaboren la rendición anual de cuentas y me la remitan. Una vez yo la tenga añado lo acordado para las revisiones y te lo paso para que la parte social añadáis lo que entendáis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-02-22','Ana: Llamada de Claudia, TS C.R. El Cuartillo (22162): La semana pasada, cuando llevaron a Emilia al hptal. en relación a la pierna, sólo la dejaron ingresada un día. Finalmente la trombosis no es tan grave como pensaban. ·········· Por otra parte la sobrina fue a visitarle una tarde, y en principio todo bien. Por el momento no ha vuelto a solicitar cita para visita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-02-22','miguel, me remite el abogado Jesús Bueno del Jzdo 1ºinstancia nº4 Plasencia,del X15 AUTORIZ JUD DISPOSICION BS MENORES/DISCAPAC 0000392 /2020, por el que se autorizó a la venta de bienes, que le remitamos escrituras de compraventa y justificante de pago. Remito a Jesús (abogado) para que lo haga llegar al juzgado las escrituras de compraventa y ratificación junto con justificantes bancarios (titularidad y movimientos de cuenta)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-02-22','Ana: Cumplimento la solicitud de transporte de Cruz Roja y la pongo para la firma del D. Gerente. ················· Pido a Sonia Bernabé, Asindi, que nos remitan informe al repecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-02-22','miguel, recibo email de Patricia Bono: Hola Miguel, ¿Te informó el juzgado de que procedimiento se trata?,¿ Va necesitar acudir con abogado de oficio?. Y otro tema que también te quería comentar y del que ya mi padre te habló en conversación telefonica el otro día, son los gastos de Alejandro, el recibe su pensión todos los meses pero parece ser según me cuentan, que no las pagas extraordinarias ni la cuantía actualizada de su pensión. El tiene una serie de gastos en su día a día que muchas veces se ve incrementados por su condición y hay que pagar desperfectos que ocasiona en la vivienda o comprarle un móvil nuevo cada dos por tres porque rompe el que tiene o simplemente ropa y no es justo que sea mi padres los que con su pensión tengan que asumir los gastos extra porque su madre tampoco puede, cuando él tiene su dinero y las pagas extras tendrán que ser para asumir sus gastos extras. Queremos saber como proceder para solucionar este tema a quien hay que dirigirse y de que manera porque con llamaros y comentarlo hasta la fecha no hemos conseguido nada. ******************************************************* mi contestación: Buenos días, estos temas debe tratarlos directamente el curatelado con la Comisión a través de su trabajadora social Amalia. No obstante, te confirmo ambas cuestiones: comunicamos por fax al jzdo de Badajoz nº3 que se trata de una persona incapacitada y que solicitamos abogado de oficio, y si entiende que es necesario la asistencia de la Comisión, nos citen(que no lo han hecho). Y por último les pedíamos que nos indicaran los motivos de dicho procedimiento. En cuanto a la solicitud de aumento del importe que tiene asignado, es competencia de la parte económica y ya les comuniqué la petición que hizo su padre. Me comentan que lo están estudiando y ya responderán al respecto. Por la ley de protección de datos no se puede dar información a nadie salvo al juzgado y al propio curatelado. Desde la parte jurídica no puedo atender más cuestiones que las estrictamente jurídicas. **************************************** Remito email a Amalia y Alberto: Adjunto email que he contestado a la tía de Nuñez Bono. Desde la parte jurídica únicamente atenderemos a cuestiones estrictamente jurídicas…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2022-02-22','-Respuesta del CSS tras la ultima escapada . Buenas tardes, ha llegado esta mañana a las 07:30 horas. Según los compañeros dice que se lo ha pasado genial. De vez en cuando, sobre 2 o 3 meses, se da una escapada. Ya te llamo y te doy más detalles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-02-22','Ana: Envío correo a Estrella, TS del CSS (estrella.duranc@salud-juntaex.es), y a Paula, TO CRR (tocupacional.crrplasencia@grupo5.net): "Buenos días a las dos, Espero que estéis bien. En relación a ISABEL CANO BLÁZQUEZ, quería preguntaros cómo está y cuál es la previsión de intervención. Me enteré la semana pasada, por su madre, que está ingresada en Media Estancia. Agradecería que nos organizásemos a la hora de coordinarnos con estas cuestiones, pues no hemos recibido noticias al respecto de ninguno de los dos recursos. Espero que evolucione bien y pueda regresar pronto al CRR. Un saludo y buena mañana." ·········································································· Respuesta de Estrella, TS: "Ay, Ana, lo siento, tengo muchísimo lío en UME y se me ha pasado... Se va mañana de alta, hizo una ingesta sin aparente motivación...Ha empezado a salir con un chico que también vive en CRR, al que conoció en UME. Él también está ingresado, lo hizo antes que ella, no sabemos si fue esto lo que provocó la alteración...." ····················································································· Respuesta de Paula, TO del CRR-Plas.: "Hola Ana, disculpa si esperabais información puntual a este respecto, estábamos pendientes de poder coordinarnos con el centro sociosanitario para hacer una valoración del impacto y posibles siguientes pasos con Isabel, puesto que como se puso en evidencia desde el principio es un caso especialmente delicado. Isabel tiene dos gestos autolesivos en un periodo corto de tiempo, aparentemente motivados, según nos refieren, por dificultades de manejo de la ansiedad/incertidumbre. Uno de estos gestos es por ingestión de objetos, por lo que tras valoración psiquiátrica, deciden su ingreso para evaluar más exhaustivamente. Estos gestos, pese a que son previsibles, puesto que forman parte de su historia de vida, no dejan de ser importantes e impactantes y por este motivo era imprescindible la información de los profesionales que conocen a Isabel desde hace años. En la coordinación que hasta hace unos minutos no hemos logrado mantener(desde hace días se lleva intentando mantener este contacto puesto que nos informaban de que se iba a proceder al alta y desde el CRR se solicitaba un intercambio de información y una estrategia conjunta) se ha establecido el alta del ingreso y regreso de Isabel al CRR, con la idea de generar estrategias para el manejo de la espera en cuestiones de atención sanitaria, vías de información directas al Equipo del CRR sobre el caso de Isabel, así como por parte del CRR y junto con Isabel, establecer los criterios que determinarán la posibilidad de que se continúe la intervención o no en nuestro recurso a medio-largo plazo (riesgos, estrategias, alternativas...). Gracias Ana por vuestro interés, os iremos informando si surgen nuevas cuestiones por nuestra parte." ······································································ Envío nuevo correo a Estrella, TS CSS: "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2022-02-22','Fugado del CSS el dia 21/02/2022.Se avisa a la policia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2022-02-22','Fugado del CSS el dia 21/02/2022.Se avisa a la policia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2022-02-22','miguel, remito de nuevo email a Marisa de la notaria de Don Benito solicitando cita: Buenos días Marisa, dime qué necesito llevar a la notaria para dejar firmada la renuncia a la herencia de la madre de Juan Carlos Rubio Galán. Ya tengo el certificado original de defunción de Rosa Galán Merino. Dime también qué día puedes darnos para ir a firmar sobre las 10h. ************************************ Y se lo reenvío a Tere','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-02-22','miguel, remito email a Encarni (hija de Basilia) para que tengan los emails de la Ctaex para comunicarse con respecto a la vivienda que tiene Miguel en común con Basilia: Buenos días, conforme hablamos ayer adjunto nuestros 3 emails para que contacten con nosotros en cuanto se conozca la resolución en 3º instancia de las hermanas para decidir el destino de la vivienda. Recordarles que cualquier disposición del bien tiene que venir autorizada por Miguel Ortíz Gordillo (la Comisión Tutelar de Adultos en su nombre). Asimismo si hay gastos que tenga que asumir nuestro representado ruego nos lo remitan a ctutelar@salud-juntaex.es (A/A de la Parte Económica). El email de mi compañero Angel es angel.marinm@salud-juntaex.es. En cuanto esté desocupada la vivienda por quienes nos ha indicado en un informe la policía local del Ayuntamiento de Fuente del Maestre, esto es Juan Gabriel Guerrero Corchero, Cristina Lopez Lopez y un menor de edad, ruego nos lo comuniquen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2022-02-22','Ana: Tras hablar con Alberto, jefe secc. ecca., pues no le están cobrando la plaza a Florencia, *llamo a la Residencia El Pendere, de Santiago de Alcántara (927 59 21 35): . Me indican que llame a Rebeca o Aurora al Ayto (927 59 20 29). Llamo y hablo con Aurora, secretaria del Ayto.: Efectivamente no se le está pasando ningún cobro por la plaza. *Yo no tengo la resolución y ella en el Ayto. tampoco. Se acercará a la residencia para ver si está en su expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2022-02-22','Ana: Tras hablar con Alberto, jefe secc. ecca., pues no le están cobrando la plaza a Florencia, *llamo a la Residencia El Pendere, de Santiago de Alcántara (927 59 21 35): . Me indican que llame a Rebeca o Aurora al Ayto (927 59 20 29). Llamo y hablo con Aurora, secretaria del Ayto.: Efectivamente no se le está pasando ningún cobro por la plaza. *Yo no tengo la resolución y ella en el Ayto. tampoco. Se acercará a la residencia para ver si está en su expte.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-02-22','Ana: llamada de José Manuel (627 788 797): dice que esta mañana ha vuelto a tener problemas con su hijo, le ha ido a despertar esta mañana porque tenía que ir a un curso y éste se ha alterado mucho, le ha gritado, insultado y amenazado. Expresa que ya no puede más y que se quiere ir a un centro. ············ *Ha hablado con el cura de su barrio y ahora quiere irse a vivir a la Casa de la Misericordia de Pinofranqueado. *Le digo que él nunca ha querido ir allí y que lo piense bien, pues como gestionemos todo desde la CTAEX y luego no quiera ir desde aquí no se le podrán gestionar más recursos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MILAGROS'and edp.apellido1='CORDERO'and apellido2='DIEGUEZ'),'2022-02-22','Ana: Llamada de Emilia Almodóvar, TS CSS: plantean la posibilidad de ir, como ya se hiciera anteriormente, a visitar su domicilio, sito en la localidad de Casas del Monte, acompañada de un profesional del centro. En esta ocasión, además del profesional que ya venía haciéndole, le acompañará también Emilia. *La directora del recurso pide que lo autoricemos desde la CTAEX por escrito, aunque sea en un email. ·························· Envío un email autorizando la salida. **No obstante, le indico que en el CSS cuentan con una AUTORIZACIÓN GENERAL DE SALIDAS para todos los residentes a cargo de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MILAGROS'and edp.apellido1='CORDERO'and apellido2='DIEGUEZ'),'2022-02-22','Ana: Envío correo a Emilia, TS del CSS-Plas (emilia.almodovar@salud-juntaex.es): "Buenos días Emilia, De acuerdo a la conversación telefónica mantenida hace unos minutos: Desde este Gabinete Técnico de la Comisión Tutelar de Adultos de la Junta de Extremadura, se AUTORIZA a Dña. MILAGROS CORDERO DIÉGUEZ, a visitar su domicilio sito en la localidad de Casas del Monte, acompañada por un profesional del Centro Sociosanitario. Tanto la ida y la vuelta tendrán lugar en el mismo día. **No obstante, tras corroborarlo con los compañeros, deciros que en el Centro contáis con una AUTORIZACIÓN GENERAL DE SALIDAS, desde hace años, que autoriza todas las salidas de todas las personas residentes a cargo de la CTAEX siempre que desde el equipo técnico lo consideréis oportuno. Lo único que se pide desde aquí es que nos mantengáis informadas al respecto. Ante cualquier cuestión, no dudes en volver a contactar. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-02-22','KIKE, LLEGA AUTO INDICANDO QUE SE MANTIENE LA MEDIDA CAUTELAR DE PRISION PROVISIONAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-02-23','Ana: Puesto que había un error en la Aceptación PIA, Manuel Casado me lo envía de nuevo y vuelvo a ponerlo para la firma del Representante Legal. ·················································· *Pongo para REGISTRO DE ENTRADA la Aceptación PIA para acceso a CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2022-02-23','Amalia : Se registra de entrada a dependencia la revisión PIA para plaza residencial de mayores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-02-23','Ana: En relación al correo remitido ayer por Sonia, TS de Asindi: "quería comentarte que ha habido otro incidente de alteración de conducta de Aaron. Va ser derivado a Salud Mental de Cáceres. Ha agredido a un compañero y el médico ha hecho parte de lesiones. No hace tanto te decía que le veíamos mejor e incluso se relacionaba con los compañeros de la planta en la que está ahora. Por lo que estamos viendo es importante que volvamos a solicitar la UDAC. Hemos hablado con su Psiquiatra y nos dice que para poder entregarnos informes para el trámite de solicitud necesita vuestra autorización. Estamos intentando averiguar cuáles son los trámites que hay que hacer, la Psiquiatra, por lo visto no lo sabe qué trámites hay que hacer." ························ Envío hoy correo-respuesta: "es una pena que Aarón vuelva a la misma dinámica, con lo bien que parecía que estaba evolucionando. Sé que hablaste ayer con Maite, Jefa de sección de la CTAEX, al respecto. Sólo recalcar que las derivaciones a UHDAC las realizan desde el Equipo de Salud Mental, los trámites los llevan a cabo la trabajadora social de y el psiquiatra de referencia" ············································································· Correo de Sonia Bernabé: "Hola Ana, las mañanas en ASINDI están siendo muy tensas desde primera hora. Hoy Aaron nada mas levantarse ha tenido la misma conducta que ayer, incluso con más agresividad hacia los profesionales. Ha sido derivado a Cáceres a Salud Mental, pero por lo que nos han dicho regresará en unas horas. Antes de ir a Cáceres le han inyectado un tranquilizante por lo que allí está ahora mismo tranquilo y al no tener disponibilidad de camas,... La compañera que lleva temas médicos ha conseguido hablar con la Psiquiatra del Equipo de Salud Mental que habitualmente trata a Aarón y va a informarse sobre los trámites para solicitar el ingreso en UHDAC. Ahora tardarán un tiempo pero estaremos pendientes por si necesitan datos para que, por lo menos la solicitud se pueda agilizar lo antes posible. Por lo visto el cambio de estación que empieza a notarse en las temperaturas,... a ellos les afecta mucho y, están viendo un aumento de casos con alteración de conducta. Tenemos previsto que se vaya a casa el viernes, pero tendrá que estar tranquilo para que no relacione que presenta conducta agresiva y se marcha. Si mañana se levanta y está tranquilo toda el día podríamos valorar la posibilidad de irse a casa el jueves por la tarde a última hora. Ya te iré comentando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-02-21','miguel, recibo email de Alberto: AMALIA: HAY QUE DECIDIR SI LES DAMOS MÁS DINERO...HAST LOS 800 €/MES APROX. (PERO SIN NINGÚN EXTRA MÁS DURANTE TODO EL AÑO) Y A PARTIR DE QUE FECHA (MARZO 2022). LO QUE NO SE ES SI ESTO VA A SERVIR DE ALGO...CREO QUE EL ABUELO NO VA A DEJAR DE PRESIONAR Y EL TUTELADO NO VA A DEJAR DE GENERAR PROBLEMAS...POR TANTO...MERECE LA PENA SUBIR ASIGNACIÓN???...PORQUE EN CASO CONTRARIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-02-22','miguel, recibo contestación de Amalia al email de Alberto de ayer: Buenas , mi opinión es subir la asignación a los 847€/mes que indicó Alberto , sin extras , a partir de marzo . Esta cantidad se le seguirá ingresando a la madre en su cuenta , para que la administre según proceda . La familia va a seguir discrepando de nuestra gestión , en este punto , yo enviaré un email a la familia para que conozcan la subida ( si así se acuerda ) y punto y final... si quieren gestionarlo ellos que asuman la curatela. Y si tienen quejas que acudan al juzgado , no daré más explicaciones a la familia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-02-23','Ana: Tras recibir llamada del CADEX (21992), remito correo a Paula, TO del CRR-Plas: "Quería comunicarte que me han llamada del CADEX para dar cita para nuevo reconocimiento a Mª Antonia Bernardo Piris por haber vencido la validez de la anterior valoración. La fecha y hora son las siguientes: 10/03/2022 a las 11:30 h. *No obstante, van a enviarme la citación en papel, en cuanto la reciba te la remito también por mail. Confirmarme, por favor, que se lo comunicáis y si va a acompañarle algún profesional del piso o del CRR." ·············· Respuesta de Paula, TO: "Gracias Ana, se lo transmitimos. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2022-02-16','TERESA RECIBO LLAMADA DE PILAR LAVADIÑO 924805077, ME COMENTA QUE FELICIANO ANDA ULTIMAMENTE CON MUCHOS DESPISTE Y SE DESORIETA Y QUE ADEMAS SOSPECHAN QEU SUFRA APENA. ESTA PENDIENTE DE CITA DE NEUMOLOGIA PARA HACERLE PRUEBAS PERO LA LISTA DE ESPERA LLEVA MUCHO RETRASO EL MEDICO DE ATECION TEMPRANA LO ACHACA A LA POSIBLE APNEA NOS SOLICITAN ACUDIR A CONSULTA PRIVADA DE NEUROLOGIA PARA DESCARTAR QUE LOS DESPISTES QUE VIENE SUFRIENDO SEAN DE OTRA CAUSA DISTINTA AL PROBLEMA DE APNEA SE AUTORIZA ASISITR A CONSULTA DE NEUROLOGIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2022-02-17','miguel, se recibe por el email de ctutelar de la madre Teresa: : El pasado sábado 12 de Febrero falleció el padre de mi hijo RICARDO ROCHA BARCO que está tutelado por ustedes y reside en el Centro sociosanitario de Mérida antiguo siquiátrico Yo mantengo contacto diario con él y con los profesionales del Centro pero jamás consigo contactar con ustedes en ninguno de los teléfonos Pero ahora es necesario porque son los responsables legales de Ricardo Ayer la trabajadora social del Centro me dijo les pondría un email y ustedes me llamarían He recurrido a este medio porque ahora hay decisiones con plazos y tengo que contactar ASUNTO: Su padre ha fallecido son 4 hermanos Me dicen que nos avisaran en 15 días a partir del 12 de que ya se puede leer el testamento Seguro que algo hay aunque no sabemos aún la forma ni cuánto Ricardo no sabe aún que ha fallecido porque se va a descolocar más aún de lo que está El día que me pregunte se lo diré En todo caso para gestionar lo que reciba la abogada amiga de la familia necesita un teléfono ,email o algo para ponerse en contacto con ustedes cuando se pueda abrir el testamento y saber qué hacer Yo desde hace años nunca he conseguido hacerlo Sólo cuando les dí la tutela que fui en persona a llevar toda la documentación de mi hijo Me las arreglo bien con el personal del Centro y viéndole todos los sábados hasta que llegó el COVID Me piden COMO CONTACTAR CON EL TUTOR LEGAL DE RICARDO Tengo el nombre de los que ha ido teniendo El último que me dijo mi jijo es Amalia Pero ncomo ningún teléfono contesta desearía que me llamen para saber COMO CONTACTAR CON SU TUTOR LEGAL mI TELEFONO ES 659064628 correo: teresa.barco@hotmail.com Direccion Avda de Colón 14 ,6º,B 06005 Badajoz Gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2022-02-22','miguel, recibimos en ctutelar email de la abogada que está tramitando la herencia: Contacto con Vds. para informarles que tenemos encargado la gestión de la tramitación de la herencia con causa en el fallecimiento de Don Ricardo VICTOR ROCHA CAMACHO en la que resultará heredero uno de sus tutelados concretamente DON RICARDO ROCHA BARCO, hermano de nuestros clientes Doña Teresa y Don Miguel Rocha Barco e hijo del difunto. En la actualidad estamos recopilando documentación necesaria para tal trámite (certificados de defunción, de nacimiento, matrimonio, últimas voluntades y seguros, testamento) en cuanto logremos el testamento se lo haremos llegar y contactaremos de nuevo con Vds. para tratar el asunto ya con algo mas de información sobre los posibles derechos de los hijos del causante (su tutelado y mis clientes). Sin otro particular, quedo a su entera disposición para cualquier duda o cuestión que pudieran necesitar al respecto,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2022-02-23','miguel, remito email a la madre Teresa, teresa.barco@hotmail.com y a la abogada Rus, rusmg@eliasymunozabogados.onmicrosoft.com: Buenos días, conforme a los emails que nos han remitido, desde la Comisión Tutelar de Adultos quedamos a la espera que nos remitan tanto la testamentaria como el borrador de la escritura de adjudicación de herencia que se quiera firmar para que poder cumplir a lo estipulado en la Ley 15/15 de 2 de Julio de Jurisdicción Voluntaria, artículo 93.1 b), conforme a lo cual tendremos que pedir las correspondientes autorizaciones judiciales de aceptación de herencia, y una vez firmada la aprobación de la misma. Dichos trámites habrán de tratarlo con Angel Marín (angel.marinm@salud-juntaex.es; tfno 924-003190), o conmigo que representamos a la parte jurídica de la Comisión','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2022-02-23','miguel, remito email a Carmen Miñarro Monge de AMSTRO Buenos días, como sabéis hemos solicitado el testimonio en reiteradísimas ocasiones. Pues bien, tras conversación telefónica con el juzgado de 1º instancia e instrucción nº2 Cáceres esta misma mañana, nos confirman que hay una nueva persona a la que se ha entregado la documentación. Así mismo nos han pedido que lo solicitásemos vía email, lo cual se ha hecho y además lo hemos remitido vía fax. Adjunto dicho fax. *************************************** email que me remite kike: Buenos días Miguel, Acabo de hablar con la chica de contacto( Guadalupe, tfno: 927620325). Me comenta que el pasado 03/02/22 ya dio la documentación a la persona indicada. También me dice que ahora hay otra persona, y que le enviemos la documentación pertinente vía email. Se ha enviado toda la documentación por enésima vez al email indicado y se vuelve a enviar por FAX para que se acelere el proceso. Te he puesto en COPIA en el envío, para ver si tenemos más suerte con el procedimiento. ************************************* Kike remite email a SCOP Sección1 Cáceres >scop.seccion1.caceres@justicia.es>: Tras conversación telefónica con el personal del Juzgado 1ª Inst. e Instr. N.º 2 de Cáceres, nos indica que la forma de presentar los escritos es a través de este correo que nos facilita. Igualmente para la agilización del proceso, dicho OFICIO se ha adelanto el mismo día de hoy por FAX, con el reporte ACEPTADO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='VEGA'and apellido2='FUENTES'),'2022-02-23','-Amalia : envío firmada solicitud revisión del grado de dependencia por empeoramiento al Ctro. Residencial El Valle . Desde allí la TS se encarga de gestionarlo , la valoración se hace desde el propio centro . Guardo en su expediente la copia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2022-02-23','Buenas tardes me dirijo a ustedes para informales de que se encuentra ingresada en el Hospital Universitario de Badajoz, unidad de Neumologia ,Doña Concepcion Alejandro Diez . La consulta que la paciente ha realizado a este servicio está dirigida a la información de su ingreso ante la Comisión de adultos y la compra de objetos personales para su estancia hospitalaria,( ropa interior y productos de aseo...). Amalia: hablo con la TS y le envio email , no se le va a enviar ningún extra para su estancia en el hospital .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-02-23','AMALIA: DAMOS DE BAJA EL TELÉFONO LOWI A NOMBRE DE TUTELADA----(SU HIJO FLAVIO DEBERÍA ASEGURARNOS QUE YA HA FORMALIZADO CONTRATO QUE EL PAGARÁ). AMALIA: COMUNICAR A FLAVIO QUE NOSOTROS NO PODEMOS DAR DE BAJA CUALQUIER LÍNEA QUE VENGA A NOMBRE DE BLAS...HA DE SER EL PROPIO INTERESADO. ICIAR: DAMOS DE BAJA TODO LO CONTRATADO X TUTELADA CON EFECTO INMEDIATO COMPROBAR EN ABRIL Y DEVOLEVER CUALQUIER RECIBO POSTERIOR A 01/04/2022. ICIAR: PRESTAMO CAIXABANK: HABLAR CON DIRECTOR Y VER SI ACEPTA QUE SE HAGA UNA AMORTIZACIÓN PARCIAL...Y COMPROMETERNOS A PAGAR MÁS CON LA EXTRA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISMAEL'and edp.apellido1='LOPEZ'and apellido2='IGLESIAS'),'2022-02-23','-Amalia: Realizado su plan de intervención. Actualmente en Ctro. penitenciario . Perceptor de PNC , he preguntado a la TS cúanto dinero considera necesario enviarle a cuenta peculio . Tiene embargos en su cuenta , lo he pasado a la sección eco para valoración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2022-02-23','Maite: Ana y yo , hemos hablado con Sara para comentarle como se va a gestionar el dinero a partir de ahora. La aportación para la manutención era de 250 € pero nos ha pedido una pequeña subida , si es posible;en cuanto al préstamo de 109 € nos dice, como está a nombre de Juan JOsé y su hermano David,´que tendría que pagar la mitad; en cuanto al préstamo que tiene con un gitano, Sara nos dice que no hay nada por escrito ( el gitano no quiere pero le ha dado su palabra de que no le cobrara mas y que se irá descontando)élla tiene un registro en un libreta y va anotando los pagos mensuales, el primer pago fué con fecha 25 de febrero de 2021, la cuantia mensual es de 100 €. El total de este dinero se pasará por transferencia a la cuenta del hermano. Hemos acordado que el reintegro quincenal lo retire él en el banco. Inicialmenre eran 30 € quincenales, lo vamos a subir a 40 con el fin de que no pida dinero a su hermano y/o a Sara. Vamos a derivar a la educadora de FUTUEX, para que realice el seguimiento y realice a través de élla las peticiones que considere en cuanto a gastos extraordinarios... ( se lo hemos dicho a Sara). Pasaremos correo a la sección económica para que autoricen todos los gastos:465 € de los cuales 310 serían para manutención; 100 € para pagar la deuda con el gitano y 50 para el préstamo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-02-23','buenas tardes Amalia. Por aquí seguimos, de momento. Tema: Mª Jesús Cruz Esperilla. El contrato de trabajo no ha salido, también es cierto que ella no ha mostrado mucha disposición. No tiene ahorros para poderse independizar. No ha comprobado lo del bono para alquiler joven. Tampoco ha ido a la zona de Peri para informarse. Estaba pendiente de tu respuesta. Ahora le diré que vaya actuando. No tengo ninguna duda sobre su situación clínica: no está preparada para un alta, le falta bastante, pero, ya sabes que me frustra bastante el hecho de que puedan voluntariamente abandonar un Recurso como el PS. Creo que eso, sobre todo, tutelados, se debería modificar. SALUDOSSSS Amalia Diaz Gonzalez Vie 04/02/2022 13:59 Buenas Manuel , qué tal ? cuanto tiempo sin saber de tí . Ayer hablé con Mª Jesús , el alquiler asciende a 280€/ mes que sumado a gastos de suministros y demás es inviable económicamente con la PNC que percibe de 402€. Estaba pendiente de un contrato de trabajo que me comentó que finalmente no ha salido . Le comenté que ha salido un bono para alquiler joven , pero obviamente hay que cumplir todos los requisitos para acceder a él y que el contrato sea formalizado. Este bono , aunque se lo den , tardan meses en resolver y tendría que tener dinero ahorrado para ir tirando unos meses . Tiene dinero ahorrado para eso ?? ha comprobado que cumple todos los requisitos para el bono de alquiler ?? le comenté que fuese a preguntar a vivienda , en la zona del Peri de Mérida y se informe de todo antes bien . Tú la ves ya para alta ?? esta chica sabría mantenerse sóla ? Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-02-23','miguel, email que reenvía Tere del trabajador social del pueblo José: buenos dias !!! mira los abogados tienen que ser de monesterio porque en calera no hay ninguno te paso dos: castro y torrado (sobre todo a esto de herencias se dedica Rosa) tlf. 924516874 Antonio bautista Romero 658838197 notarias en monesterio solo hay una: Notaria Monesterio tlf. 924516203 si necesitas otra te puede servir la de fuente de cantos que es la mas cercana, Tlf. 924500029. de la documentación que me dices, no tenemos ninguna porque la casa de paco estaba en ruinas cuando yo lo conoci y no tenia ni DNI que tuvimos que hacérselo, creo que la madre no dejo testamento y si lo dejo en las ultimas voluntades pone donde lo otrogo , tenéis que pedirlas vosotros y ahí viene si hay testamento o no , en cuento a la nota simple nuestro registro de la propiedad, esta en fuente de cantos, los conozco y voy a preguntarles a ver como es ese procedimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-02-23','Muy buenas Amalia, muchísimas gracias por vuestra labor y vuestra implicación. Esperemos que esto resuelva la situación. Yo voy a contratar esta nueva SIM de llamadas ilimitadas para Blas y la voy a domiciliar en mi cuenta personal, por lo que el pago está garantizado. La otra línea está a nombre de mi madre y es probable que intente pagar a través de ahí un nuevo servicio de Internet. Debemos estar atent@s de esa cuota, mi recomendación (ya que yo no puedo entrar en esa cuenta corriente) es revisar esos recibos y si es necesario, cancelarlos también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-02-23','miguel, recibo email de Amalia: Buenas , Miguel me llama Fco. Jesús Mariñas Perez ( tf 618634763) de Almendralejo. Este señor está pendiente que se regularice el contrato de alquiler de las tierras de Eulalia Rangel Porro y su hermano. Ya hay un contrato de alquiler anterior , pero el señor se ha jubilado y este otro se ha quedado con ellas . Me dice que ya hablaste con él , pero había gestiones por hacer y que está esperando ese contrato para firmarlo , pq hay trabajos agrícolas que ya los está haciendo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-02-23','Ana: Recibo correo-e de Modesto, Res. Casas de Don Antonio (administracion@centrodemayoressierradesanpedro.es): "Buenos días Ana. Ya tenemos la concesión de la plaza pública de Feliciano la cual adjuntamos. También te adjunto la factura de los días que ha estado de privado que pasaremos en los próximos días por el número de cuenta que nos habéis facilitado." ··············· Envío a Alberto, jefe de secc. ecca., ambos documentos. ········· Archivo en su expte. la Resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-02-23','buenas tardes Amalia. Por aquí seguimos, de momento. Tema: Mª Jesús Cruz Esperilla. El contrato de trabajo no ha salido, también es cierto que ella no ha mostrado mucha disposición. No tiene ahorros para poderse independizar. No ha comprobado lo del bono para alquiler joven. Tampoco ha ido a la zona de Peri para informarse. Estaba pendiente de tu respuesta. Ahora le diré que vaya actuando. No tengo ninguna duda sobre su situación clínica: no está preparada para un alta, le falta bastante, pero, ya sabes que me frustra bastante el hecho de que puedan voluntariamente abandonar un Recurso como el PS. Creo que eso, sobre todo, tutelados, se debería modificar. SALUDOSSSS Amalia Diaz Gonzalez Vie 04/02/2022 13:59 Buenas Manuel , qué tal ? cuanto tiempo sin saber de tí . Ayer hablé con Mª Jesús , el alquiler asciende a 280€/ mes que sumado a gastos de suministros y demás es inviable económicamente con la PNC que percibe de 402€. Estaba pendiente de un contrato de trabajo que me comentó que finalmente no ha salido . Le comenté que ha salido un bono para alquiler joven , pero obviamente hay que cumplir todos los requisitos para acceder a él y que el contrato sea formalizado. Este bono , aunque se lo den , tardan meses en resolver y tendría que tener dinero ahorrado para ir tirando unos meses . Tiene dinero ahorrado para eso ?? ha comprobado que cumple todos los requisitos para el bono de alquiler ?? le comenté que fuese a preguntar a vivienda , en la zona del Peri de Mérida y se informe de todo antes bien . Tú la ves ya para alta ?? esta chica sabría mantenerse sóla ? Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2022-02-23','miguel, recibo llamada y después email del abogado del curatelado josemariadelgado@icaba.com: Buenos días, Miguel: Según conversación mantenida hace un momento, te remito solicitud de embargo a un tutelado vuestro, por lo que, a fin de evitar que le embarguen su pensión, al menos, de aqui en adelante, os agradecería que me informaras, e incluso, que me facilitaras algún documento donde se haga constar la cuenta en la que percibe los ingresos. JOSE MARIA DELGADO TEMPRANO ABOGADO ICABA 2507 C/ LOS MAESTROS Nº 7. 06800 MERIDA Tlfno. 607924597 *********************************************** mi contestación: Buenos días José Maria, conforme a tus indicaciones te adjunto el saldo a fecha actual de la cuenta del curatelado, que a fecha de hoy es de 2.443,18€. Te adjunto los movimientos de cuenta para que veas como hay más embargos y que únicamente percibe una pensión No contributiva de invalidez de la TGSS de 421,40€. La cuenta de Banca Pueyo está cancelada. Cualquier otra duda quedo a tu disposición. *************************************************** contestación del abogado José Mª Delgado: Muchas gracias, Miguel. Creo que con la información que me facilitas, tengo suficiente. No obstante, si necesito alguna cosa más, te lo diré.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-02-23','miguel, recibo email de Amalia: Buenas , Miguel me llama Fco. Jesús Mariñas Perez ( tf 618634763) de Almendralejo. Este señor está pendiente que se regularice el contrato de alquiler de las tierras de Eulalia Rangel Porro y su hermano. Ya hay un contrato de alquiler anterior , pero el señor se ha jubilado y este otro se ha quedado con ellas . Me dice que ya hablaste con él , pero había gestiones por hacer y que está esperando ese contrato para firmarlo , pq hay trabajos agrícolas que ya los está haciendo','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-02-23','miguel, recibo email de Amalia: Buenas , Miguel me llama Fco. Jesús Mariñas Perez ( tf 618634763) de Almendralejo. Este señor está pendiente que se regularice el contrato de alquiler de las tierras de Eulalia Rangel Porro y su hermano. Ya hay un contrato de alquiler anterior , pero el señor se ha jubilado y este otro se ha quedado con ellas . Me dice que ya hablaste con él , pero había gestiones por hacer y que está esperando ese contrato para firmarlo , pq hay trabajos agrícolas que ya los está haciendo','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-02-23','miguel, envío borrador de contrato de alquiler al nuevo arrendatario y envío email a Alberto y Amalia: Hola, ya he remitido al interesado en continuar el arrendamiento de las tierras de Eulalia Rangel el nuevo contrato de arrendamiento, con las condiciones del anterior para que lo firme y nos lo envíe para su firma por José Vicente. También hablé con el marido de Dolores Lay que es titular de algunas tierras en común con Eulalia Rangel, y al igual que a nuestro nuevo arrendatario le he indicado que si en algún momento tienen interés en comprar las tierras nos acrediten la oferta de compra con una tasación para pedir la correspondiente autorización judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-02-23','Ana: Correo de Paula, TO del CRR (tocupacional.crrplasencia@grupo5.net): "Hola Ana, como te dije hoy ha vuelto Isabel Cano, desde antes de su ingreso tenía prevista una salida con su madre y, según nos dice, desde el sociosanitario estaban de acuerdo también, por lo que si no hay ninguna otra circunstancia se irá a casa del 25 de febrero al 1 de Marzo. Ella conoce las medidas de prevención respecto al Covid y se compromete a respetarlas." ····························· Mi respuesta: "Ok. Precisamente he hablado con ella por teléfono hoy y me lo ha comentado. Puesto que en el C. Sociosanitario no ven inconveniente en que realice la visita al domicilio, por nuestra parte tampoco hay problema en que se vaya estos días."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2022-02-23','Ana: Aurora, secretaria del Ayto (927 59 20 29 / secretaria@santiagodealcantara.com) me remite la RESOLUCIÓN DE LA PLAZA. La guardo en el expte. digital. ······ Le facilito el nº de cuenta en que le cobrarán todos los atrasos y el nuevo, para cuando comiencen a ingresarle la pensión en la nueva cuenta bancaria. ················ Cumplimento la comunicación de cambio de datos bancarios y la pongo para firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2022-02-23','Ha llamado la trabajadora social de Oliva de Mérida, Magdalena, para hablar de Francisco Casillas García. Está muy preocupada por la situación ,propone el ingreso en centro. Le he explicado que acaba de llegar y todavía no hemos intervenido. Me ha dado su teléfono para que nos pongamos en contacto con élla para lo que necesitemos: 669501741.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2022-02-24','Ana: Correo de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es): "Me llamó el otro día, Maite para el tema de solicitar la plaza en Placeat para Carlos, para que reconsideráramos la idea. Lo puse de manifiesto ayer en reunión de UHDAC y estamos de acuerdo en solicitarla. Solicito revisión PIA para ello." ··············· Respondo: "De acuerdo, me parece perfecto. Cuando tengas la solicitud me la pasas para que la ponga a la firma del Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2022-02-24','Ana: Correo de ayer de Yolanda, Técnico Valoración Dependencia (yolanda.garciar@salud-juntaex.es): "SOY YOLANDA TECNICO DE VALORACIÓN DEL SEPAD. LE HEMOS REALIZADO LA VALORACIÓN DE LA DEPENDENCIA A D. FELIX FRANCO JIMENEZ Y HA OBTENIDO UN GRADO I. NECESITO ENVIARTE UNA DOCUMENTACIÓN DE ACEPTACIÓN O NO ACEPTACION DEL PIA ASIGNADO Y TE AGRADECERIA QUE CONTACTES CONMIGO EN EL TELEFONO 927638012 PARA ACORDAR DONDE PUEDO REMITIRLA ASI COMO PARA QUE ME FACILIES LOS DATOS PERSONALES DEL REPRESENTANTE LEGAL PARA LA FIRMA DE DICHA DOCUMENTACIÓN. ESPERO TU RESPUESTA. GRACIAS" ························ Llamo a Yolanda (927 638 012 / 24112): Félix ha dado grado I en la valoración de Dependencia. *No puede optar a plaza residencial. **Él quiere ir a PISO TUTELADO, pero el SEPAD no cuenta con plazas públicas ni vinculadas de estas características. **Habrá que solicitar plaza privada. Los PISOS más cercanos son: El de la Residencia María de Luna de Pasarón de la Vera y el de Malpartida de Plasencia (927 459 245). En éste además sabe que va a quedar una plaza libre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-02-24','-Amalia : Como Entidad que presta medidas de apoyo para el ejercicio de la capacidad jurídica de D. DAVID ESTEVEZ DE FELIPE , con DNI 8090174B , se adjunta comunicación de variaciones de PNC.( registrado )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-02-22','Ana: Tras conversación telefónica con Álvaro, EUEXIA, Envío correo a Estrella, TS CSS: "Buenos días Estrella, He recibido llamada de Álvaro de la empresa EUEXIA, me pregunta si vemos apropiado el que lleven a Juan Carlos a la piscina alguno de los días de salida, dice que él quiere ir, pero no queríamos tomar la decisión desde aquí sin contar con la opinión del equipo técnico de la UHDAC. Ya me decís si lo valoráis factible y adecuado. Quedo a la espera de respuesta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-02-23','Ana: Respuesta de Estrella, TS CSS, a mi correo de ayer: "Nos parece fenomenal que lo lleven a la piscina. Esta semana le compramos bañador, gorro, chanclas y toalla."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-02-24','Ana: Llamo a Álvaro, empresa EUEXIA (651 639 717): confirmo que pueden llevar a Juan Carlos a la piscina el sábado. Le recogerán a la hora de siempre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2022-02-24','miguel, asisto por videoconferencia al jucio por abusos sexuales del tutelado. La Comisión damos nuestra conformidad con el acuerdo expuesto por nuestro abogado Jose Luis Martin y la Fiscal para la absolución del delito y medida de internamiento en el mismo CSS por 2 años.','2');
