insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2022-02-24','Ana: Pongo para la firma del Representante Legal la Solicitud de Material Ortoprotésico para par de baterías para silla de ruedas eléctrica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='SANCHEZ'and apellido2='MORENO'),'2022-02-24','miguel, email de Oscar (parte económica): Buenas tardes. Una vez hechas las averiguaciones del embargo por importe de 704,38 € que se adjunta, nos comunican que se debe a una multa de tráfico por radar para el vehículo Volkswagen Jetta matrícula 2547FHC. Aún le restan por pagar a día de hoy 1.137,22 €. El embargo se ha producido porque el coche está a su nombre y, después de que la DGT solicitara identificación del conductor, no se realizó ni se pagó la multa por exceso de velocidad. Se adjunta también póliza de seguros Mapfre Auto por importe de 225,67 €, que vence el próximo 1 de septiembre, domiciliada en su cuenta, pero que está a nombre de su hermano Manuel Sánchez Moreno, aunque esta póliza no corresponde con el vehículo multado, sin que asegura a la matrícula 0310JJG. Igualmente, hay otra póliza de seguros de Zurich Auto por importe de 190,87 €, con vencimiento del 22 de diciembre, también domiciliada en su cuenta y a nombre de su hermano, para el vehículo 5639HRN, que tampoco es el vehículo multado. El 9 de noviembre se solicitó la devolución de estos recibos, además de otros, pero Ibercaja no lo ha realizado y ha vuelto a cargar el de Zurich Auto en diciembre. Habría que averiguar si el vehículo multado está realmente a su nombre y decidir qué hacer con el vehículo, u otros vehículos que pudiera tener a su nombre, y con los seguros. Desde la sección social habría que averiguar si la tutelada tiene carné de conducir y, en este caso, decidir si suspender su vigencia. *************************************************** mi contestación: Buenos días, os pongo en rojo lo que entiendo que debe proceder: Una vez hechas las averiguaciones del embargo por importe de 704,38 € que se adjunta, nos comunican que se debe a una multa de tráfico por radar para el vehículo Volkswagen Jetta matrícula 2547FHC.Aquí, es imposible que dé de baja un vehículo sin documentación, por tanto si no ha acreditado quién es el conductor tendrá que pagarlo. Aún le restan por pagar a día de hoy 1.137,22 €. El embargo se ha producido porque el coche está a su nombre y, después de que la DGT solicitara identificación del conductor, no se realizó ni se pagó la multa por exceso de velocidad. Se adjunta también póliza de seguros Mapfre Auto por importe de 225,67 €, que vence el próximo 1 de septiembre, domiciliada en su cuenta, pero que está a nombre de su hermano Manuel Sánchez Moreno, aunque esta póliza no corresponde con el vehículo multado, sin que asegura a la matrícula 0310JJG. Aquí entiendo que hay que devolver el recibo (si es posible que se avise al hermano…), salvo que la cuenta en la que se ha cargado sea también titular el hermano. Igualmente, hay otra póliza de seguros de Zurich Auto por importe de 190,87 €, con vencimiento del 22 de diciembre, también domiciliada en su cuenta y a nombre de su hermano, para el vehículo 5639HRN, que tampoco es el vehículo multado. Aquí entiendo que hay que devolver el recibo (si es posible que se avise al hermano…), salvo que la cuenta en la que se ha cargado sea también titular el hermano El 9 de noviembre se solicitó la devolución de estos recibos, además de otros, pero Ibercaja no lo ha realizado y ha vuelto a cargar el de Zurich Auto en diciembre. Si Ibercaja no devuelve estos recibos haced un nuevo requerimiento indicando que se procederá a reclamar vía Banco de España…Y si pasado dos meses no lo hacen ese requerimiento lo enviaremos al Banco de España. PD: Este tipo de casos son los que debemos de agilizar la rendición de cuentas con revisión de sentencia indicando que solicitamos insten a la Dirección General de Tráfico a que den de baja definitiva cualquier vehículo, ya que debido a la falta de documentación no es posible lo haga la Comisión Tutelar de Adultos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2022-02-24','miguel, hablo por telefono con el notario de los Santos de Maimona, D. Carlos Duro y le transmito al abogado Angel Garcia Calle lo que necesita: Buenas tardes, tras conversación con el notario de los Santos de Maimona D. Carlos Duro, me comenta que para poder tramitar la Adjudicación de la Herencia y la Venta tenéis que solicitar al Juzgado: 1.- Testimonio firme del Auto dictado donde se Autorizó la Herencia, con los documentos que deban acompañarlos y que en su día se aportaron (tasaciones, testamentaria, etc) 2.-El testimonio firme que me remitistes ayer está incompleto ya que hace referencia a los contratos que no se trascriben por el juzgado (y por tanto no se saben las condiciones de la venta), por lo que tienes que solicitar nuevo testimonio donde se adjunten las copias de esos contratos (donde figuran las condiciones de la venta, entre ello el precio de venta).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-01-27','Maite: he hablado con la farmacia de Peñalsordo para que Marta retire los parches anticonceptivos y nos envié las facturas, y cualuiqer cosa que pueda necesitar, mensualmente. El farmaceútico es Antonio Pozuelo:924 614362. Es muy colaborador.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2022-02-25','-RGTO VARIACIONES PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-02-01','Mercedes no acude al ESM a las citas. Insistimos en localización telefónica y no nos coge teléfono. Ante la situación hable con su primo Jesús para ver que sabe de ella. Me dice que la acompañó a ponerse el inyectable a la clínica, que desde el ingreso está suspicaz con nosotros, que ha perdido la confianza, nos rechaza, etc... le comenté que intentará acercamiento de nuevo con el equipo y la necesidad de ponerse en contacto con nosotros. Esa misma mañana me llamo Mercedes por teléfono tras hablar con el primo. Me dijo que por ahora necesitaba tiempo, que lo había pasado muy mal durante el ingreso hospitalario y que no iba a venir a las citas en el ESM-CJ. Seguiremos trabajando en la adherencia al equipo, como te comenté desde el ingreso la vimos mal con los profesionales de ESM, callada, triste y poco comunicativa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2022-02-28','Ana: Envío correo a Alberto, jefe secc. ecca.: "Buenos días Alberto, He recibido llamada de Marili, Directora del Centro Ocupacional de Miajadas (927029632 y 21959). Me dice que ha ido al banco para quitarse de autorizada de la cuenta bancaria de Esteve Pascual Ramos, pero la persona que le ha atendido le ha dicho que no puede quitarse, que la tienen que quitar desde aquí, con la autorización del Representante Legal de Esteve. Me ha resultado raro, pero bueno. *La cuenta que tiene Esteve se la abrieron desde ahí antes de estar tutelado por la CTAEX para el cobro de la beca que le daban, por eso aparece ella como autorizada. Por favor, intentad que la quiten o hablar con ella sobre cómo puede hacerlo." ····························· *Por otra parte, Marili dice que independientemente, enviará hoy la cartilla al CRR con el conductor del centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-02-01','Email de ESM : Tiene abierta la agenda al día que desee acudir, ya se lo he traslado tanto a Teresa como a su primo, él que también trabajará para buscar adherencia de nuevo. Cuando no acude el paciente, se insiste con su localización telefónica para buscar de nuevo el vínculo, si persiste el no acudir, se contacta con familiares, centros de atención primaria e instituciones vinculadas al paciente para informar de que no acude. Saludos,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-02-28','-Envío email a sección eco y jurídica y pido I.Social a Futuex. Buenos días , a ver , este escrito ha sido enviado por su hijo al Juzgado. Este señor se ha trasladado a vivir a Montijo desde Cataluña , para entre otras cosas poder atender a su madre , es por ello que solicito que se proceda a la revisión de la sentencia de D. ROSA SERRANO GARCIA , instando al juzgado para que sea su hijo el que asuma las medidas de apoyo necesarias , manteniéndo las mismas para la esfera económica . Este señor discrepa de las decisiones que se adoptan desde la Comisión Tutelar . Con respecto a las líneas de tf. que utiliza Rosa , pedía suprimir todas , y bloquear el acceso a internet. Una de las líneas está a la titularidad de su pareja , Blas Ródena , con lo que no podemos solicitar la baja de una línea de una persona que no está tutelada por esta entidad. Hemos mantenido conversaciones con su hijo , la TS de la localidad y se ha tomado la decisión que a partir de marzo vamos a proceder a la baja de la línea de la que es titular Rosa , pero para no dejarla incomunicada , se ha acordado con su hijo que él se encargará de dar una línea y del pago de la misma , sólo con llamadas ilimitadas, sin datos. ( para evitar las compras por internet ) La persona curatelada , no está de acuerdo en esa decisión. Cuando se revise su sentencia , y las acciones tengan que tener en cuenta su voluntariedad no sabemos cómo quedaría este hecho. Así mismo , habría que pedir al juez que se pronuncia sobre : -suprimir su permiso de circulación , se lo ha renovado sin informar sobre su patología mental y dudo que haya presentado en el centro de reconocimiento, información sobre la medicación pautada. -Tiene un coche, pero no tiene dinero para mantenimiento , ni para pasar la itv ... que ella utiliza a pesar de todo para ir de Valdelacalzada a Montijo a recoger paquetes que sigue comprando. Voy a solicitar informe social a la delegada tutelar para acompañar este escrito . Desde la parte económica tendrían que pedir rendición de cuentas. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-02-28','-Envío email a sección eco y jurídica y pido I.Social a Futuex. Buenos días , a ver , este escrito ha sido enviado por su hijo al Juzgado. Este señor se ha trasladado a vivir a Montijo desde Cataluña , para entre otras cosas poder atender a su madre , es por ello que solicito que se proceda a la revisión de la sentencia de D. ROSA SERRANO GARCIA , instando al juzgado para que sea su hijo el que asuma las medidas de apoyo necesarias , manteniéndo las mismas para la esfera económica . Este señor discrepa de las decisiones que se adoptan desde la Comisión Tutelar . Con respecto a las líneas de tf. que utiliza Rosa , pedía suprimir todas , y bloquear el acceso a internet. Una de las líneas está a la titularidad de su pareja , Blas Ródena , con lo que no podemos solicitar la baja de una línea de una persona que no está tutelada por esta entidad. Hemos mantenido conversaciones con su hijo , la TS de la localidad y se ha tomado la decisión que a partir de marzo vamos a proceder a la baja de la línea de la que es titular Rosa , pero para no dejarla incomunicada , se ha acordado con su hijo que él se encargará de dar una línea y del pago de la misma , sólo con llamadas ilimitadas, sin datos. ( para evitar las compras por internet ) La persona curatelada , no está de acuerdo en esa decisión. Cuando se revise su sentencia , y las acciones tengan que tener en cuenta su voluntariedad no sabemos cómo quedaría este hecho. Así mismo , habría que pedir al juez que se pronuncia sobre : -suprimir su permiso de circulación , se lo ha renovado sin informar sobre su patología mental y dudo que haya presentado en el centro de reconocimiento, información sobre la medicación pautada. -Tiene un coche, pero no tiene dinero para mantenimiento , ni para pasar la itv ... que ella utiliza a pesar de todo para ir de Valdelacalzada a Montijo a recoger paquetes que sigue comprando. Voy a solicitar informe social a la delegada tutelar para acompañar este escrito . Desde la parte económica tendrían que pedir rendición de cuentas. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2022-02-28','Antonio Fernández Merchán ingresó en psiquiatría por desestabilización el día 23 de febrero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2022-02-28','Ana: Correo de Minerva, TS del C.R. Cervantes: "Desde el Centro se os comunica que nuevamente se retoman las salidas de los residentes, en este caso Mª Luisa Montaña podrá salir 3 días a la semana con una duración de una hora, a parte de la salida semanal al banco. Mª Luisa saldrá sola a estas salidas, como venía haciendo anteriormente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='CAMARA'and apellido2='MORENO'),'2022-02-28','Ana: Correo de Estrella Durán, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Ha ingresado en UME Alfonso Cámara Moreno, me ha comunicado alguna compañera de Cáceres que está incapacitado y tutelado por la CTA. Confírmamelo." ·························· Mi respuesta: "Tras haberlo comprobado y corroborado con mis compañeros de la sección jurídica, te informo que de Alfonso Cámara Moreno sólo ha llegado la Defensa Judicial y en la misma no indica ningún tipo de medida por parte de la CTAEX. Hasta que no se resuelva el procedimiento y nos nombren como Curadores Representativos o Asistenciales no podemos intervenir."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-02-22','Ana: Una vez me devuelven de firma la SOLICITUD DE REVISIÓN PIA, la pongo para REGISTRO de ENTRADA junto con los informes facilitados por ASPACE Jaraíz.','2');
