insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISMAEL'and edp.apellido1='LOPEZ'and apellido2='IGLESIAS'),'2022-02-28','Buenos días, compruebo que sí tiene cuenta peculio, según los movimientos que me has enviado. saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-02-28','Ana: Remito a Manuela, jefa de secc. de acceso a RR. de Discapacidad, la SOLICITUD de Revisión PIA REGISTRADA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2022-02-28','Buenos días: Os comunicamos que la madre de María del Pilar Rodríguez Escalera, está continuamente enviando mensajes de audio diciendo que: No aguanta a su hija, que no se hace caso, que le busquemos un sitio para que se vaya su hija, que la pongamos en un centro (y demás mensajes pero con el mismo contenido). Observamos a Pilar hija y le cuestionamos sobre su situación en casa, sobre su madre, y nos comenta que todo bien, además en su lenguaje corporal tampoco se observa que esté a vivir una situación complicada. Aún así, os queremos trasladar lo que nos está diciendo madre, porque los mensajes son reiterativos y muy focalizados. Nos gustaría saber como están las gestiones para la derivación residencia y saber si podemos aportar algo, para que se haga efectiva. Aprosuba 3 , Catarina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-02-17','Ana: Llamada de Juan Carlos, pide "perdón" por las voces y su comportamiento el día de la última llamada. Se alteró mucho y tuvieron que intervenir los vigilantes de seguridad. Hoy está más tranquilo. Pero sigue preguntando cuando podrá irse a otro centro. ···················· *La llamada en esta ocasión la realiza acompañado de Mª Paz, Psicóloga y Coordinadora de la UHDAC, quién pregunta también por su acceso a centro. Se le explica que por parte de la CTAEX están todas las gestiones realizadas, que no depende de nosotros y que en cualquier caso estamos pendiente y volveremos a preguntar en la U.PP.AA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2022-03-02','-Amalia : Le han informado a la hna. sobre el traslado . Tendría que llevárselo a Cataluña y empadronarlo allí y que un ESM lo derivase a UME , pero les han dicho que allí hay una lista de espera de 8 años. Preguntará en servicios centrales de esa comunidad.','2');
