insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2022-03-02','Ana: Pongo para la firma del D.Gerente, la Aceptación PIA para MANTENIMIENTO DE PLAZA T3 en la Residencia Sierra de San Pedro. ······················· Una vez firmado digitalmente lo pongo para REGISTRO DE ENTRADA a la Gerencia Territorial del SEPAD, Sección de centros II.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO MANUEL'and edp.apellido1='TERRON'and apellido2='SALGADO'),'2022-03-02','-Amalia : Ingresado en R.M. San Vicente de Alcantara , la TS ( 633842707) me ha llamado para revisar dependencia , la avisaré cuando tengamos sentencia y procederemos igual que para Mª Baez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2022-03-02','TERESA David Vita ha sido seleccionado para realizar la misma formación sobre COCINA que Libertad en Plena Inclusión Zafra. Ya te comenté que está resultando muy difícil que regrese el Centro, así que de momento va a asistir al curso desde su casa en Fuente de Cantos hasta que consigamos que pase algunos días en el centro. Ha comenzado hoy y se desplaza en el autobús de línea. Al igual que te comenté de Libertad, va a recibir una beca de transporte que se la ingresarán a finales del mes pero de momento necesita disponer de al menos 4€ diarios para el autobús. Esta mañana ha pasado por el banco en Fuente de Cantos y le han dado 50€. Quiero recordar que tenía autorizada una cantidad más elevada pero no estoy segura y como de momento este mes también va a seguir en casa tal y como acordamos el mes pasado debemos valorar nuevamente la posibilidad de que David colabore económicamente con los gastos comunes. Necesitaría 80€ para el transporte y además lo que vosotros consideréis oportuno para colaborar en casa. Ya me dices cuando lo trates con la sección económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2022-03-02','-Amalia : Hablo con Reme ( 672633885), Alonso ha mejorado , las úlceras se han curado y ya empieza a andar .Pte. de otra operación. Se mantiene SAD como estaba antes de su ingreso hospitalario , subiendo 5h. los fines de semana. Preguntar a la parte eco para ver a quién lo está cargando la empresa. Se deja la solicitud de plaza sociosanitaria . Todos los hermanos tienen G.3 , se va a solicitar revisión PIA para Alonso para plaza residencial . Me enviará todo por email y yo lo firmo y registro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-03-02','Maite:ha preguntado Alexandra si ya habiamos hecho la transferencia de 150 a la cuenta de la entidad parair dándole a MArta sus 5 € diarios. Todavia no se ha relaizado pq no le han ingresado la pensión. Desde el centro le han adelantado los 5 € de ayer 1 de marzo. Les he enviado la cita del CADEX para que jusitifique la no aistencia y para que sela den a élla. Hablé el dia 22 con Felisa, suegra de MArta , para pedirle su número de cuenta y decirle que vamos a tranferir 100 € mesuales en concepto de manutención. He enviado correo a la parte eco, Lourdes, reiterando los números de cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-03-02','Maite: he enviado correo al centro para que compren algo para su cumpleaños que es el 5 de marzo: Buenos días Araceli! ¿ cómo está José Maria?. El próximo 5 de marzo es su cumpleaños. NO sé si soleis hacer algo especial. Nos gustaría que con su asignación , si es suficiente, le comprarais algo que él quiera. Nos ha llamado la madre para decirnos que quiere ir a verlo. No sé si os ha comunicado algo. Tendriamos que pagar el taxi con el dinero de José María. Tendremos que ver si se puede. No seria para su cumpleaños. Buena mañana','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2022-03-02','Ana: Pongo para REGISTRO de ENTRADA la solicitud de Modificación de Datos Bancarios a la Dirección Provincial del INSS de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2022-03-02','Ana: Correo de Toni de Diego, TS CR Cervantes: "Buenos días Ana te informo que Eugenia tras asistir a consulta de neumología, le han prescrito un tratamiento para dejar de fumar. te adjunto el escrito de la doctora Camino iglesia, medica de Eugenia en la Residencia. solicitando el pago de los parches" ························ Guardo informe del Serv. de Neumología en el expte. digital y envío correo a Alberto, jefe secc. ecca.: "Buenos días Alberto, Cuando puedas tienes que valorar el presupuesto de tratamiento para dejar de fumar prescrito. Es necesario para ella, pero tenéis que valorar si puede costeárselo."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2022-03-02','Ana: Correo de Loli, Residencia Santa Catalina (residenciasantacatalina@gmail.com), con copia a Cristina Carrón, EVD: "BUENOS DÍAS, ACABO DE HABLAR CON MAY, Y LA PLAZA PÚBLICA SE LA HAN CONCEDIDO A EMILIANA SÁNCHEZ, A LO LARGO DEL DIA NOS HARAN LLEGAR LA RESOLUCION DE INGRESO. UN SALUDO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-03-02','miguel, contesto a Amalia con copia a Alberto: Buenos días Amalia, tras leer tu email no aclaras si hay o no inconveniente a que el cargo de curador pueda realizarlo su hijo que es lo que están planteando desde el Jzdo nº4 de Badajoz, donde actualmente han ofrecido al hijo se pronuncie sobre una posible remoción del cargo mediante su solicitud a través de abogado y procurador…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-03-02','Ana: Correo de ayer de Paula, TO CRR (tocupacional.crrplasencia@grupo5.net): "Buenas Ana, en relación a la revisión del CADEX de Antonia Bernardo Piris, comentarte varias cosillas que nos preocupan: • En primer lugar la posibilidad de que se reduzca el grado de discapacidad tras la valoración con la consiguiente pérdida de su única fuente de ingresos que es la Pensión. • Y el posible impacto que esta pérdida pueda tener tanto de cara a su recuperación (influencia en su salud y su desempeño) como a las posibilidades futuras de continuar con el plan de aumento de la autonomía; es cierto que esto podría motivar una posible búsqueda de empleo, aunque tal y como está el mercado laboral esta situación es compleja. Intentaré contactar el miércoles día 2 para poder pensar y recoger de forma conjunta acerca de estas circunstancias." ···················· Mi respuesta: "Buenos días Paula, Entiendo vuestra preocupación, no obstante, decirte que el Certificado que tiene a día de hoy ha perdido validez… está caducado. La revisión es obligatoria, si quieres lo hablamos pero debe asistir a la cita sí o sí, pues a día de hoy es como si no lo tuviera. Por otra parte, teniendo a día de hoy la “incapacitación” y ostentando el cargo la CTAEX, yo creo que como mínimo se lo mantendrán tal cual, pero claro, no tenemos nada seguro al 100%. No obstante, si quieres, hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-03-01','miguel, llega de Cid y Villafaina email: Buenos dias, es necesario que la COMISIÓN TUTELAR DE ADULTOS DE EXTREMADURA, como curador de D. Jose Antonio Delgado Rodríguez, otorgue un apoderamiento a favor de un Procurador para iniciar procedimiento de jurisdicción voluntaria de solicitud de aceptación de herencia de persona con discapacidad en el Juzgado de Primera Instancia de Fregenal de la Sierra. El apoderamiento puede ser “apud acta”, que deberá otorgarse: - de forma telemática en: https://sedejudicial.justicia.es/-/apoderamiento-apud-acta. Una vez en esta aplicación se pincha en “Acceder al servicio clave” y se rellenan los campos. Hay que identificar al Procurador al que se hace el poder. Puede ROSA MARÍA ANDRINO DELGADO, con DNI 08.823.385-X, colegiada nº 280 del Colegio de Procuradores de Badajoz. Si tienes algún problema dímelo y me pongo en contacto con ella. ******************************************** mi contestación: Buenos días, tendríamos que solicitar cita y que el representante de la Comisión Tutelar de Adultos (actual gerente del Sepad) firmara en los juzgados de Mérida dicho poder para lo cual tendréis que indicarme: -Juzgado de primera instancia que conocera del caso (la localidad…) -Presupuesto de abogado y procurador (aproximado…)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2022-03-02','TERESALa sobrina de D. Carmelo Gracia Redondo, Mónica Gracia, nos solicita poder disfrutar del fin de semana del viernes 11 al domingo 13 de marzo Nosotros lo consideramos idóneo y adecuado para el residente, al poder establecer y reforzar vínculos familiares y afectivos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-03-02','miguel, a raiz de la incomparecencia del curatelado, el jzdo solicitó se localizara su domicilio para notificarle. Llega consulta del domicilio del Juzgado nº1 de Cáceres, Procedimiento ITR 764/21 a su punto neutro judicial donde les aparecen dos direcciones: c/ Huaina Capac nº1, Portal 1, 3º E, Cáceres y C/Garcia Marquez. Los Olivos 10, Cáceres','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2022-03-02','TERESA RECIBO LLAMADA DE M ANTONIA PARA PEDIR AUTORIZACION PARA SALIR TODOS LSO FIENES DE SEMANA A CASA DE SU PRIMA HABLO CON MARIA TS DE LA PROVIDENCIA Y ME COMENTA QUE NO ES VIABLE ESTA SALIDA PUES TIENE QUE HACER CAMBIO DE BUS Y ENTRE UNO Y OTRO TARDA DOS HORAS LE PROPONGO HACERLO EN TAXI, ME COMENTA QUE SON UNOS 25 EUROS HABLO CON SU PRIMA CARMEN 606044448) LE PLANTEO QUE VAYA A SU CASA A CADA QUINCE DIAS, IRA EN TAXI Y SU PRIMA LA TRAERA EL LUNES AL CENTRO. LA PRIMA LE PARECE BIEN LE COMUNICO A MARIA LA DECISION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2022-03-02','Ana: Pongo para la firma del D.Gerente, la SOLICITUD de REVISIÓN DEL GRADO DE DEPENDECIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-03-02','Ana: Llamada de Felipe, Ed. CAM Fco. Pizarro - Trujillo (61091), está sustituyendo temporalmente a Juan Pedro, Director. Recientemente, el día 22/2/22, se aceptó el cargo de Tutor por parte de la CTAEX. Juan José presenta 65% de discapacidad, reconocida por el CADEX. Desde el centro le han solicitado C. Discapacidad (Novaforma y Placeat). *Actualmente está cursando una FP Básica de Administración en Trujillo, gracias a la implicación de los educadores del CAM así como del propio IES, va bastante bien y seguramente aprobará el curso. **Mantiene buena relación con familiares, dos hermanas y su padre. Se va a casa todos los fines de semana. El padre ya es mayor y está delicado de salud. **Educadores de referencia: Gema y Felipe (61081), del hogar 2. ················ *Me remitirán desde el CAM la documentación de su expediente. Correo del centro: cam.franciscopizarro@salud-juntaex.es ············· *Piden una autorización de salidas. Ya tienen la AUTORIZACIÓN GENERAL, de cuanto residía allí otro tutelado por la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-03-02','Ana: Nos confirman desde la Secc. Discapacidad que a Juan Carlos se le va a conceder plaza RAE en Plena Inclusión Cabeza del Buey. En el plazo máximo de 15 días se producirá el ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2022-02-17','TERESA ANOTNIA ES TRASLADA A LA RESIDENCIA DE MAYORES JUAN CARLOS IBARA DE VILLAFRANCA HACER PRESUPUESTO DE GASTOS Y AUTORIZACION PARA SACAR DINERO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2022-03-01','-Amalia : Ingresada en la UHB por ingesta de medicamentos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2022-03-03','Ana: Envío correo a Emilia Almodóvar, TS CSS (emilia.almodovar@salud-juntaex.es): "En relación a la propuesta que no habéis realizado, tanto en el Informe Social como en de la Psicóloga, de cambio de centro relativa a Jairo Puertas Martín, tras haberlo valorado con Maite, Jefa de sección del Gabinete Técnico de la CTAEX, nos surgen dudas al respecto: - Si el psiquiatra no encuentra criterios clínicos para ese traslado ¿cómo se realizaría?. Entendemos que el procedimiento es interno entre ambos centros , ¿no sería a través de propuesta en subcomisión de casos? - Si se trasladara al sociosanitario de Mérida, ¿cuánto tiempo sería y cómo se gestionaría el regreso? Por otro lado, comentar que: - En la visita realizada al Centro Sociosanitario el pasado día 25 de enero de 2022, mantuvimos una “reunión” con Jairo, y en la misma no manifestó en ningún momento querer trasladarse al Centro Sociosanitario de Mérida. Es más, su planteamiento era el de irse a vivir a Cáceres de forma independiente a un piso de alquiler, dejar de percibir su prestación económica y trabajar. - En las dos últimas conversaciones telefónicas mantenidas con él (fechas: 19/01/2022 y 23/02/22), el discurso ha sido el mismo que en el día de la visita. Por nuestra parte no habría problema para que se realizara el cambio, si el criterio de los profesionales del equipo así lo aconseja, pero puesto que Jairo no manifiesta esa demanda, consideramos valorar la posibilidad de esperar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-03-03','Ana: En relación al último correo de Estrella, TS CSS, y la solicitud de Fca., madre de Isabel, para que ésta le deje dinero para pagar la fianza de un piso de alquiler en Plasencia, donde quiere trasladarse a vivir, llamo a Estrella (24146): Dicen que el Psiquiatra está de baja y que de todas formas, no le va a hacer más caso por que se lo diga él. Que se lo digamos nosotras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2022-03-03','miguel, llega del CSS-Pilar email a Soraya, Ana y yo: Buenos días. Recibida notificación del Juzgado de 1ª Instancia e instrucción nº3 sobre P.A 490/2021, el Fiscal interesa el traslado de C.M.B a otro Centro, por lo que se comunica afín de dar cumplimiento a lo interesado. ************************************************* mi contestación: Buenos días, la sentencia de este procedimiento todavía no ha sido dictada. Hasta que no se dicte y veamos su contenido, y la misma sea firme (no quepa recurso contra la misma) no habrá de ser cumplida. Esto significa que no hay que cambiarle por ahora de centro. Según asistí por videoconferencia a la vista el día 24-2-22, se llegó a un acuerdo entre el abogado defensor (con el visto bueno nuestro) con el Ministerio Fiscal por el que se le absolvió del delito de abusos sexuales, aunque si habrá multa pecuniaria y una orden de alejamiento a cumplir en el Centro durante 2 años, pero no se comentó que haya de trasladársele a otro centro. Por lo tanto hay que esperar a que llegue la mencionada sentencia antes de actuar. ************************************** responde Pilar del CSS: Buenos días Miguel. El residente tiene varios procedimientos abiertos. Son 2 procedimientos distintos. Al que tú te refieres es el que el centro notificó, al que tú asististe por videoconferencia el 24/02/2022 (P.A 261/2021) Juzgado de lo penal nª1 y que está pendiente se dicte sentencia. El que se envía ahora es la resolución del juzgado sobre la denuncia que puso el tutor de M.T.G.P con fecha de 2/12/2021 (P.A. 490/2021) en el Juzgado de 1ª instancia e instrucción nº 3, en el cual el juez ha sobreseído la causa pero Fiscalía en dicho procedimiento interesa el traslado de C.M.B. Espero haber aclarado la situación en el sentido de que a pesar de que en el PA 261/2021 estemos a la espera de que se dicte orden de alejamiento y medida de seguridad, en este que nos ocupa (P.A 490/2021) fiscalía interesa el traslado igualmente. ************************************************* mi contestación: Correcto Pilar, efectivamente este procedimiento del Juzgado de 1º instancia nº3 de Plasencia, procedimiento DPA 490/21 resuelve por Auto de 24-2-22 el sobreseimiento y archivo, pero interesa el Ministerio Fiscal su traslado a otro centro por reiteración. Por tanto tal como dice Pilar hay que trasladar a Cipriano a otro Centro donde deberá de cumplir además la pena de internamiento que llegará por el otro procedimiento mencionado PA 261/2021 del que resolverá en pocos días el Juzgado de lo Penal nº1 de Plasencia. Tras confirmarlo con el juzgado nº3 de Plasencia, me confirman que efectivamente hay que trasladarlo de Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2022-02-23','Ana: Llamada de Jairo: Solicitó 2 presupuestos para gafas y ha elegido el más barato, pues además eran las gafas que más le gustaban (70 € apróx.). *A parte dice que va a comenzar un tratamiento para dejar de fumar, por lo que pide poder disponer del dinero que no se gaste en tabaco para otros gastos de bolsillo. **Dice que debe 7€ en un bulevar. ··········· A partir de aquí su discurso comienza a desvariar: quiere poner un "veto sanitario a la sanidad pública" y "contratar un seguro de salud privado", "dejar la medicina a través del proceso de abstinencia de fármacos". Después cambia de tema diciendo "en mi día a día mi madre manifiesta que quiere mi custodia", "como sabes mis padres se han separado, peros se llevan bien y quieren la custodia compartida". *Rosa Bravo, Adtvo. CSS, que escucha de fondo el discurso de Jairo, interviene diciéndole que él sabe que eso que dice no es verdad. Lo que provoca el enfado de Jairo, respondiéndole que no se meta, que es una conversación privada y que le deje en paz...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-03-03','miguel contesto a email de Alberto (con copia a parte economica/social): Buenos días, no hay sentencia definitiva en el expediente, por favor Kike comprueba con el juzgado si ya hay testimonio de firmeza, en caso contrario somos administración de bienes provisional y no podríamos hacer nada. Por otra parte una vez firme hay que solicitar autorización de venta de bien inmueble (si no hay otros problemas como otros propietarios, deudas, etc) para lo cual hará falta seguramente nombrar abogado y entablar un procedimiento judicial de autorización de venta una vez que se tenga un precio de la vivienda y un comprador.. Por tanto la solución más rápida pasa por cambiarla de centro… **************************************** Email de Alberto: Hola...ya hemos hablado de esta "administración de bienes" hace muy poco...la situación sigue empeorando...como indica Oscar, el precio de la plaza ha subido 300 €/mes aprox. (ver correo anterior de Oscar)...la situación no se puede mantener...hay que hacer algo ya. Previamente habíamos hablado de la venta...deberíamos reunirnos urgentemente la semana que viene para tratar esta cuestión "YA". ******************************************** email de Oscar: Buenos días. Ya estuvimos comentando su situación para ver si se cambiaba de residencia. Le han subido el importe a 1.706,60 € (antes pagaba 1.428,18€). Teniendo en cuenta que cobra en total 1.593,08 € y que tiene más gastos fijos (Orange, Iberdrola y Comunidad de Propietarios), se va a quedar sin ahorros en 6 meses. Lo vemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2022-03-03','Ana: Correo de Ángela, Directora Placeat (directora@placeat.org): "Buenos dias Ana Adjunto te remito una nota informativa sobre la situación covid en el servicio residencial de Placeat, que se ha distribuido a todas las familias de los residentes Mª Rosa se le ha realizado hoy un test de antígenos y ha dado un resultado negativo.."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-03-03','kike, llega diligencia de notificación para la comparecencia el próximo 16/03/22 a las 9:20 y a las 9:30 en la Sala 1 y Instituto de Medicina Legal respectivamente, para que el mismo, sea reconocido por el médico forense. Se entrega al hermano, que es el que se compromete a entregárselo a Martín.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-03-03','Ana: Envío correo a Toni-Futuex, con la Diligencia recibida: "Buenos días Toni, ¿Qué tal estáis? En relación a Martín Domínguez Palencia, te reenvío el documento que hemos recibido del Juzgado. Como podéis leer, su hermano se ha compromete a comunicárselo. Os lo envío para vuestro conocimiento y para que estéis pendiente, por favor. Gracias y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2022-03-03','Ana: Envío correo a Teresa Nogueira, Novaforma: "... En relación a JUAN JOSÉ MASEDA DEL SOL, Icíar, compañera de sección económica, me ha confirmado hace un momento que ya ha realizado la transferencia a la cuenta de su hermano y la autorización para la retirada de efectivo para gastos de bolsillo de Juan José. Queríamos preguntaros si desde el CO sería posible que le acompañaseis una vez cada quince días a la oficina de la C/ Liberbank de la C/ San Pedro a retirar su asignación. ¿Podrías también avisar a Sara de que la transferencia ya está hecha? Las cuantías, finalmente, son las siguientes: - Autorización de retirada de efectivo: 40€/quincena (10 € para teléfono y el resto para gastos de bolsillo) - Transferencia mensual en concepto de “manutención” a la cuenta del hermano de 460 € mensuales (de los cuáles 55 € son para abonar la mitad de un préstamo a nombre de los dos hermanos y 100 para abonar la otra deuda que tiene contraída. El resto para manutención) Informaros también que la semana pasada ya hicimos la derivación al Programa de Apoyo Comunitario gestionado por FUTUEX, para que puedan hacer su seguimiento y prestarle apoyo en cuestiones necesarias. Les visitarán en el domicilio y también se coordinaran con vosotras. Les facilité tu contacto, pero no sé si ya le han asignado una Educadora ni si, en ese caso, se habrá puesto en contacto contigo. ····································· Respuesta de Teresa: "Buenas tardes, desde Novaforma no es posible realizar ese acompñamiento, ya que no tenemos personal disponible y que el centro ocupacional esta a las afueras de Caceres. Contacto con nosotras la delegada tutelar y mantuvimos una reunion con ella, quedo en que ella iria con Juanjo a retirara el dinero y si ella no puede pues ira algún otro miembro de la familia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-03-03','miguel, remito email al nuevo arrendador Francisco Jesús Mariñas Perez (chiqui):Hola Francisco, te adjunto el borrador, donde he incluido la finca que indicas y que deberás comentarla antes de firmar con la otra titular, Dolores Lara Lay (tlfno 625030078) ya que el 25% era de Francisco, otro 25% de Eulalia y el 50% restante de Dolores Lara Lay, según consulta que he realizado a Catastro y cuya certificación me han remitido y te adjunto. Tendrás por tanto que acordar la incorporación al contrato de dicha parcela con la otra parte. Adjunto también la renovación del contrato en Word para la revises. Remítemelo firmado por duplicado. Una vez me lo envíes lo firma el representante y te lo remito a la dirección que indiques. La dirección a la que tienes que enviármelo es: Comisión Tutelar de Adultos (SEPAD) Avda de las Americas 4 06800, Mérida (Badajoz) Recuerda rellenar los datos de tu dirección. En cuanto envíes el documento avísame.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-02-23','llega email de Francisco Mariñas (chiqui), el nuevo arrendador: Buenas tardes Miguel, le he echado un vistazo al contrato y veo dos incidencias la primera que falta un parcela en la descripción parcelaria que es la siguiente: el pilón ,polígono 28 parcela 193 con una superficie de 0ha65a72ca. Está parcela estaba incluida en el otro arrendamiento y la cédula catastral está a nombre de Francisco. Haber si te puedo pasar la cédula para que la veas.y luego en el capítulo segundo se en cabeza con el nombre del antiguo arrendatario.por lo demás lo veo correcto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-03-03','Ana: Llamada de Juan Carlos, le comunico que ya le han asignado plaza en un centro y en el plazo de 2-3 semanas se irá. ···· Pregunta si se puede llevar su TV y le digo que sí. ····· En cuanto al paseo de hoy no han podido salir porque llovía mucho. ········ Y el sábado pasado fue a la piscina y dice que se lo pasó muy bien, pero que no le dejaron meterse en la zona profunda, pero que él sabe nadar. ··········· A Sara y Estrella les preocupa que se retrase el ingreso en el centro y se ponga más nervioso, pero a nosotros nos han dicho que en 2 semanas debe producirse el ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2022-03-03','miguel, remito firmado por el gerente y corregido el acuerdo de reparto de la cuenta de Ibercaja. Conforme a instrucciones de Carlos Mora se lo remito a su email','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2022-03-03','miguel, remito firmado por el gerente y corregido el acuerdo de reparto de la cuenta de Ibercaja. Conforme a instrucciones de Carlos Mora se lo remito a su email','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2022-03-03','Buenas, Paso a comunicaros lo acontecido en el fin de semana/puente de carnaval. Juanjo pidió marcharse a su pueblo. Allí sacó el dinero mensual establecido. Al llegar al servicio de vivienda nos dice que ya no dispone de los 100 euros porque se los ha dado a su abuela (hecho que no nos convence porque es precisamente la abuela la que en ocasiones le presta dinero). Llamamos a la abuela para corroborar esta información pero nos cuelga la llamada constantemente. Decir que su hermano está viviendo también en el hogar familiar. Además, nos damos cuenta que posee cannabis y que no ha tomado la medicación, a pesar de haberle hecho seguimiento telefónico. Se le ha explicad que no dispondrá de dinero durante este mes a no ser que la comisión tutelar opine lo contrario. También comunicaros que se ha abierto parte de incidencia grave con las medidas sancionadoras recogidas en el Reglamento de Régimen Interno del Servicio de Vivienda Tutelada de Aexpainba. Consideramos oportuno revisar las medidas de apoyo del usuario ( no sabemos quiénes deberían solicitar el proceso). Si consideráis podemos mantener una reunión para tratar el caso. Saludos. ------------------------------------------ Amalia . respuesta : Buenas Laura , según lo que expones desde la Comisión y siguiendo vuestra intervención terapéutica no se le va a conceder otra asignación económica. Con respecto a la revisión de su sentencia , se van a ir realizando conforme a su rendición anual . Cuando llegue la suya contactaré con vosotros para conocer vuestra opinión. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2022-03-03','miguel, me llama el curatelado y le comento que la notaria (Marisa) ni contesta a los emails, ni cogen el tfno. Le digo que cuando pase por allí cierre día/hora y voy a firmar con él la Renuncia de Herencia de su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2022-03-03','Buenas, Paso a comunicaros lo acontecido en el fin de semana/puente de carnaval. Juanjo pidió marcharse a su pueblo. Allí sacó el dinero mensual establecido. Al llegar al servicio de vivienda nos dice que ya no dispone de los 100 euros porque se los ha dado a su abuela (hecho que no nos convence porque es precisamente la abuela la que en ocasiones le presta dinero). Llamamos a la abuela para corroborar esta información pero nos cuelga la llamada constantemente. Decir que su hermano está viviendo también en el hogar familiar. Además, nos damos cuenta que posee cannabis y que no ha tomado la medicación, a pesar de haberle hecho seguimiento telefónico. Se le ha explicad que no dispondrá de dinero durante este mes a no ser que la comisión tutelar opine lo contrario. También comunicaros que se ha abierto parte de incidencia grave con las medidas sancionadoras recogidas en el Reglamento de Régimen Interno del Servicio de Vivienda Tutelada de Aexpainba. Consideramos oportuno revisar las medidas de apoyo del usuario ( no sabemos quiénes deberían solicitar el proceso). Si consideráis podemos mantener una reunión para tratar el caso. Saludos. ------------------------------------------ Amalia . respuesta : Buenas Laura , según lo que expones desde la Comisión y siguiendo vuestra intervención terapéutica no se le va a conceder otra asignación económica. Con respecto a la revisión de su sentencia , se van a ir realizando conforme a su rendición anual . Cuando llegue la suya contactaré con vosotros para conocer vuestra opinión. Un saludo .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-03-03','De: manuel f.m. >xiliana06@yahoo.es> Enviado el: miércoles, 19 de enero de 2022 18:08 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: Alejandro Núñez Bono Vuelvo a ponerme en contacto con ustedes, para poner en su conocimiento que la actitud del inquilino del portal 1-piso 4º C, Alejandro Núñez Bono, no ha cambiado desde la última vez que les mandé información sobre él. Como presidente de la comunidad y por insistencia de los vecinos de la misma, vuelvo a verme obligado a informarles que no solo sigue la misma línea de comportamiento, poniendo música a gran volumen a cualquier hora, voces, ruidos y golpes, sino que además se dedica, con "sus amigos", a sentarse en las escaleras de acceso al portal y en la zona posterior del edificio a fumar porros, hablando a voces, reírse en alto y hacer comentarios desagradables, provocando las molestias pertinentes en las viviendas mas cercanas a esos lugares por los olores y humos así como por el ruido. Por todo esto, algunas vecinas que les han instado, tanto a él como a "sus amigos", a que se marchen, han recibido insultos y comentarios fuera de tono hacia sus personas. Además, últimamente, según los vecinos que viven mas próximos a él, su vivienda recibe un trasiego anormal de personas que entran y salen de ella. Por otra parte , informarles que la madre de este chico es consentidora de todo esto y además no hace nada por evitar que ocurra. Quedo a su disposición para aclararles cualquier duda que pueda surgirles. Un saludo.','2');
