insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2022-03-07','Ana: Pongo para REGISTRO DE ENTRADA, la SOLICITUD de REVISIÓN DEL GRADO DE DEPENDECIA, ya firmada y sellada, junto con el Informe de Salud y la Historia clínica resumido. ·························· Mai, Jefa de Secc. Mayores, me confirma que la plaza que ocupa Valentina es Municipal, de "válidos", por Promoción de la Autonomía (Grado I) no se le puede asignar ninguna plaza residencial. **En el SIDEX, aparece el expte. activo con plaza por PROMOCIÓN DE LA AUTONOMÍA (Confirmado con Chelo, Dependencia, previamente) ····························· Registrada de ENTRADA hoy mismo. Guardado en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-03-07','miguel, llega físicamente la denegación de abogado de oficio del Colegio de Abogados de Cáceres','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-03-15','TERESA SE LLEVA A CABO EL INGRESO NO VOLUNTARIO DE PABLO EN COORDINACION CON FUTUEX Y LA POLICIA LOCA. HA ESTADO UNOS DIAS EN LA UHB Y EL JUEVES HA PASADO A UME. HABLO CON LOLA TS CSMERIDA 24005 ME INFORMA QUE ESTA BIEN, LE FACILITO NUMERO DE CUENTA. FUTUEX LE HA ACERCADO UNA MALETA CON LO QUE NECESITA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2022-03-02','Ana: correo de Paula, TO: "Buenos días Ana, comunicarte que ayer Conchi Fernández hizo una ingesta de medicación importante que tuvo que ser atendida por el servicio de urgencias en el CRR y posteriormente en el Hospital Virgen del Puerto para poner los medios necesarios y asegurarse de que no existieran consecuencias negativas para su salud. Este gesto, como aparece en el informe, no se considera con intencionalidad autolítica, sino una forma de afrontamiento ante varias circunstancias que confluyen (información respecto a lo hablado con CTA en cuanto a demorar el arreglo de su casa, proceso de salida del CRR más largo de lo que ella quiere, frustración ante la posibilidad de hacer un regalo a su hija por su comunión que familiares de la niña hacen sin contar con ella...). Ayer regresa al CRR y se realizan los apoyos pertinentes. Os iremos informando de los posibles ajustes de las intervenciones planteadas." ·························· Guardo Informe Médico en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-03-07','miguel, envío por carta contestación a diligencia de embargo de AEAT indicando que se ha estado pagando a la pensión mensualmente 600€ y que ha cambiado de residencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2022-03-07','Ana: Correo de Cristina Molano, Psicóloga CRR (crr@grupociudadjardin.com): "Buenos días: Comentamos el estado de Antonia Canelada del Río: - El viernes en la mañana se aprecia un empeoramiento de su estado físico, motivo por el cual se procede a comunicar con su MAP quien tras valoración realiza orden de traslado para valoración en servicio de urgencias. Tras valoración, en servicio de urgencias y pautada medicación y terapia de oxigenoterapia se da el alta el sábado tras pasar la noche en observación. - El domingo tras presentar sintomatología de empeoramiento se acude de nuevo al servicio de urgencias donde se ajusta tratamiento y se valora estado por servicio de psiquiatría para dicho momento. - En estos momentos Antonia se encuentra con una ligera mejoría física con respecto al fin de semana, sin embargo tenemos dificultades para asegurar el uso de la terapia de oxígeno manifestando en repetidas ocasiones no querer usarla, así como dificultades para mantener su uso en la habitación. Solo manteneros informados de su situación actual. Seguiremos informando. Un saludo." ······················ Guardo informes en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSE'and edp.apellido1='MOLINA'and apellido2='SALAZAR'),'2022-03-07','TERESA RECIBO LLAMADA DE TACIANA PIDIENFO INFRAMACION SOBRE LA SITUACION DE M JOSE. LE COMENTO QUE HEMOS FIRMADO DERIVACION PARA CRR ME COMENTA QUE NO HAY PSIQUIATRA EN LA URH Y NO ACEPTAN INGRESOS Y QUE LA UHB NO ES LUGAR PARA QUE ESTÉ HABLO CON M LUZ DE SALUD MENTAL Y ME COMENTA QUE AÚN NO HAN RECIBIDO LA DERIVACION Y QUE HAY UNA LARGA LISTA DE ESPERA PARA EMERGENCIA SOCIAL SE LO COMUNICO A TACIANA Y ACORDAMOS DERIVAR A FUTUEX PARA QUE LA VISITE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2022-03-07','Buenos días , he estado hablando con Sonia , me indica que en Madrid tienen un piso que era propiedad de sus padres fallecidos y que son 4 las herederas . Sin embargo , su hermana Concha ( tf. 669483690) lo tiene alquilado , no sabemos exactamente por cuánto dinero pero se queda ella con ese dinero . Me cuenta que tb tenían un piso en la playa que su hna. vendió y se quedó con todo el dinero . He mirado en su inventario y no aparece esta propiedad , imagino que no se habrá hecho partición de herencia . Habría que averiguar en registro si hay alguna información sobre ésto. Voy a llamar a la hermana por si rescato alguna información más que os pueda facilitar la gestión. Si esto es así , habría que exigir a su hermana la parte que le corresponda a Sonia. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-03-04','Ana: Correo de Sonia Bernabé - Asindi: "Hola Ana, quería informaros que Aaron ha quedado ingresado en Salud Mental del hospital en Cáceres. Lleva varios días diciendo que oye voces en su cabeza, en concreto, la voz de la residente a la que agredió y hace referencia a cuchillos, hachas,..Dice que ella quiere pegarle. El martes tiene la citación online con el Juzgado, no sabemos si estará ya de alta. Voy a mandar también correo a Angel (asesor jurídico) para que esté informado por si no estuviera para la cita el martes. Yo el lunes no estoy en el centro. He informado a mi compañera Amparo y le he facilitado vuestros teléfonos por si hubiera cambios, pero por si acaso, creo que podéis llamar vosotros y preguntar por si hay que avisar en el Juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2022-03-07','Buenos días , he estado hablando con Sonia , me indica que en Madrid tienen un piso que era propiedad de sus padres fallecidos y que son 4 las herederas . Sin embargo , su hermana Concha ( tf. 669483690) lo tiene alquilado , no sabemos exactamente por cuánto dinero pero se queda ella con ese dinero . Me cuenta que tb tenían un piso en la playa que su hna. vendió y se quedó con todo el dinero . He mirado en su inventario y no aparece esta propiedad , imagino que no se habrá hecho partición de herencia . Habría que averiguar en registro si hay alguna información sobre ésto. Voy a llamar a la hermana por si rescato alguna información más que os pueda facilitar la gestión. Si esto es así , habría que exigir a su hermana la parte que le corresponda a Sonia. Un saludo.','2');
