insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-03-07','-Amalia : Ingresado en plaza T3 en Caser residencial Olivenza . Percibe PNC , he enviado cambio de Nº cta. Curatela para esfera personal y patrimonial para gastos de extraordinaria cuantía. Especifica la sentencia incapt. que si solicita el alta voluntaria tenemos que comunicarlo al Jgdo. que dictará lo que proceda. Intento hablar con Gloria ( TS del centro ) para cuadrar pto y otras necesidades que precise. Volveré a llamar.','2');
