insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2022-03-03','Ana: subo a hablar con Mai, jefa de sección de acceso a recursos de mayores. Le han concedido la plaza pública a Emilia, la Aceptación PIA ya se registró. *Pero necesita PCR, pues aunque gestionado por la misma entienda, el Piso es un recurso diferente a la residencia. *Llama a la residencia, gestionarán ellos la cita. ··········· En cuanto a sus ingresos, yo les enviaré el Certificado de Revalorización de la Pensión. ··············· Ingresará en la residencia la semana que viene. ·········································· Remito a Mai el cdo. pensión (mayores.sscc@salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2022-03-03','Ana: Envío a Toni de Diego, TS CR Cervantes el correo remitido por Alberto: "Hola Presupuesto...18 semanas (4,5 meses) x 100 €/mes son 450 € aprox. Asumir este coste implica que, en cómputo anual, este año va a tener unos GASTOS superiores a los INGRESOS. ANA: si tú ves que es necesario asumimos el coste del tratamiento. 2 cosas: • El centro debería asegurar que dicho presupuesto es fijo y que no se va a incrementar • El centro debe tener claro que los gastos extras NO deberían producirse durante todo este año. OSCAR: si ANA da OK...ABONAMOS TRATAMIENTO...HABLAS CON QUIEN NOS INDIQUE ANA" ···················································· Respuesta de Toni: "Buenas Ana nuevamente Referente al presupuesto de tratamiento para dejar de fumar prescrito de Eugenia, lo vamos a valorar. seguimos en contacto"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-03-07','TERESA SE ACUERDA VISITA A CENTRO DE SU MADRE POR SER SU CUMPLEAÑOS SE ACEPTA PRESUPUESTO TAXI SE PAGRA POR TRANSFERENCIA 330€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2022-03-02','Ana: Correos de Toni de Diego, TS CR Cervantes (antonia.dediego@salud-juntaex.es): "Buenos días Ana te informo que Eugenia tras asistir a consulta de neumología, le han prescrito un tratamiento para dejar de fumar. te adjunto el escrito de la doctora Camino iglesia, medica de Eugenia en la Residencia. solicitando el pago de los parches un saludo" ·································································································································································································· Guardo informe del Serv. de Neumología en el expte. digital y envío correo a Alberto, jefe secc. ecca.: "Buenos días Alberto, Cuando puedas tienes que valorar el presupuesto de tratamiento para dejar de fumar prescrito. Es necesario para ella, pero tenéis que valorar si puede costeárselo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-03-07','miguel, en relación al procedimiento monitorio por el que ya le están embargando y que consulté, ha llegado tasación del juzgado aceptada de los honorarios de abogado y procurador (no firme, cabe impugnación en 10 días). No alegaremos. Reenvío email a Alberto para que en cuanto sea firme lo abonen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2022-03-03','Ana: Correo de Margarita, TS Mancomunidad Sierra de Montánchez (tsocial4@mancomunidadsierrademontanchez.es): "quería comunicaros que ha fallecido el hermano de DÑA. ISABEL PULIDO CARAVACA, tutelada, y con domicilio actual en la Residencia "Balcon de Extremadura" de Montánchez, por si tenéis que realizar gestiones de algún tipo, o simplemente para vuestro conocimiento y/o efectos oportunos, mi telefono es el nº 637 099 759 estoy en el despacho de Montanchez los martes, miercoles y jueves" ················· Lo pasaré al Asesor Jurídico, por si hubiera que hacer algo relativo a la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2022-03-07','Retomando este tema , he hablado con su hermana Concha, he pedido que nos envíe a ctutelar toda la documentación al respecto de esta propiedad. Efectivamente es así , ella dice que ese dinero del alquiler lo administra ella entre las hermanas en función de sus necesidades . Le he explicado nuestra función y que tenemos que velar por sus cuentas y que pondremos toda la situación en regla. Un saludo','2');
