insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='DIAZ'and apellido2='ROMERO'),'2022-03-07','-Amalia : Realizo Plan de Intervención. Actualmente está pasando unos dias con su tia Loli en Badajoz recuperandose de la operación de espalda. Para la revisión de sentencia proponer que sea su tia la que realice la provisión de medidas de apoyo . Seguirá en RAL de P. Inclusión . Percibe PNC , el 75% para copago plaza y 90€ al mes para gastos de bolsillo . De momento lo sacan sin problemas pq fueron defensa judicial y aparecen en la cuenta como autorizado.','2');
