insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2022-03-08','-AMALIA : he hablado con su hija y me enviará por escrito la petición. Es la señora que intentó ir al banco a sacar este dinero . Insiste en que su padre quiere dárselo , y que es hija única . En estos casos que lo enviamos al juzgado para que compruebe si es una decisión y voluntad de Agustín','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2022-03-08','-AMALIA : he hablado con su hija y me enviará por escrito la petición. Es la señora que intentó ir al banco a sacar este dinero . Insiste en que su padre quiere dárselo , y que es hija única . En estos casos que lo enviamos al juzgado para que compruebe si es una decisión y voluntad de Agustín ---------------------------------------------------------- AMALIA: LA HIJA DEL TUTELADO (AZUCENA: TFONO.: 638583263), HABLA CON LOURDES Y NOS SOLICITA 10.000 € DE SU PADRE PARA ARREGLARSE (LA DE ELLA) LA BOCA + ELLA VERBALIZA QUE CUENTA CON EL PERMISO DE SU PADRE. LOURDES VA A LLAMARLA PARA QUE DICHA SOLICITUD LA HAGA CONSTAR A TRAVÉS DE CORREO ELECTRÓNICO...LA LLAMAS TU ANTES??? SITUACIÓN ECO: PNC: 421,70 X 14 CENTRO: 320 €/MES + GASTOS VARIABLES (ACTUALMENTE DE POCO IMPORTE) SEGURO DECESO: 22,5 €/MES SALDO 07/03/2022: 26.476,72 € MIGUEL: SIMPLEMENTE QUE LO TENGAS EN CUENTA...CUANDO AMALIA HABLE CON ESTA CHICA, DECIDIMOS SI SE AUTORIZA O NO...Y SI HAY QUE SOLICITAR AUTORIZACIÓN JUDICIAL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-03-08','miguel, recibo email de la abogada (Rocio Gracian): Buenos días Miguel, En relación al procedimiento de desahucio sobre la vivienda en Málaga de Damián, te informo que han señalado la fecha del juicio el próximo día 29 de Abril, a las 9.15 horas. Se celebrará en la Ciudad de la Justicia, Juzgado de Primera Instancia nº 15. Te ruego me llames cuando puedas al objeto de preparar el asunto. Gracias Saludos Rocío Gracián Fernández ABOGADA C/ Alameda de Colón, 34, 2º-6 29001 Málaga Tlfs: 607650498 - 952600772','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2022-03-08','Buenos días , ya me ha contado Mª Luz , que se ha caído y va a necesitar de cuidados continuados durante unos días . Como tiene dinero , se autoriza para que pase a una plaza en Rosalva durante unos días . Pasarnos el presupuesto para saber a cuánto ascendería . La sección eco de esta Comisión hará el abono al Nº de cuenta que se nos facilite . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2022-03-08','Buenos días , ya me ha contado Mª Luz , que se ha caído y va a necesitar de cuidados continuados durante unos días . Como tiene dinero , se autoriza para que pase a una plaza en Rosalva durante unos días . Pasarnos el presupuesto para saber a cuánto ascendería . La sección eco de esta Comisión hará el abono al Nº de cuenta que se nos facilite . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2022-03-08','-Amalia : la hija nos envía el email con la petición. Miguel , este escrito es para derivarlo al juzgado y que se manifieste en la autorización o no sobre esta petición . El señor está residiendo en la R. M. San Vicente de Alcántara. Su sentencia aún no se ha revisado , es de los casos nuevos . Un saludo','2');
