insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-03-08','-Email de Manuel Picado : Buenos días. Sin cobertura vodafone. Te informo: viernes, ayer lunes y hoy he estado en UHB atendiendo a Mª Jesús y gestionando todo. Está todo preparado para que mañana vaya al CADEX a las 11 h. También coordinado con Sonia (futuex). Irá desde el hospital con ambulancia y celador. He acordado con psiquiatra, Alfredo de la Rubia que vendrá a UME con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-03-08','-Email de Manuel Picado : Buenos días. Sin cobertura vodafone. Te informo: viernes, ayer lunes y hoy he estado en UHB atendiendo a Mª Jesús y gestionando todo. Está todo preparado para que mañana vaya al CADEX a las 11 h. También coordinado con Sonia (futuex). Irá desde el hospital con ambulancia y celador. He acordado con psiquiatra, Alfredo de la Rubia que vendrá a UME con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2022-03-08','Ana: Correo de Sara Gía, Psicóloga de Autismo Sur (sara@autismosur.es): "Buenas tardes Ana, Mi nombre es Sara, soy la psicóloga de Hogares la Virreina donde vive Alexandru. Disculpa por no haberos enviado antes el correo. Alex, desde que está con nosotros, se ha adaptado perfectamente a las rutinas del hogar, participa con el apoyo necesario de los técnicos a realizar las actividades del día a día, como su aseo, preparar el desayuno, coger su ropa, realizar las actividades y talleres diarios como taller de relajación, de cocina, etc. Todas las semanas hacemos actividades de ocio inclusivo como ir a la cafetería, hacer salidas con la furgoneta a lugares de ocio, senderismo a diario, ir a la piscina una vez a la semana, las cuales disfruta mucho, sobre todo ir en furgoneta. Las grandes necesidades de apoyo de Alex en la comunicación hace que en ocasiones pueda presentar conductas no adaptativas, conductas que nos quieren decir algo, algún malestar, algún deseo no cumplido, nuestro trabajo es conocerlo en profundidad y observarlo y registrar estas situaciones para comprender la conducta y poder ayudarle a decirnos lo que le ocurre o necesita. Lleva una alimentación basal, su comida favorita es la fruta, y eso nos facilita a poder ofrecerle como reforzador las manzanas que son sus preferidas cuando queremos conseguir cosas de él, como que participe en algún taller que no muestra tanto interés. De forma esporádica recibe la visita de María, su madre colaboradora, la cual le trae regalos y ropa, es ella quién paga la factura de la piscina de Alex. Él disfruta mucho de estas visitas, sale contento y los reconoce perfectamente. A nivel de salud, Alex goza de buena salud, tiene un peso adecuado a su edad y altura, toma su medicación diaria, se le va a realizar una analítica de seguimiento, que solemos hacer anualmente. Os mantendremos informados. No sé si queréis saber algo más concreto de Alex, estoy a vuestra disposición, más abajo tenéis mi número de teléfono donde también podéis contactar conmigo."','2');
