insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-03-08','Ana: Remito a Elsa Corrales, TO EVD Plasencia (elsa.corrales@salud-juntaex.es), ACEPTACIÓN PIA para TRASLADO ya REGISTRADA DE ENTRADA el día de ayer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2022-03-08','Ana: Correo de Loli, Residencia Santa Catalina (residenciasantacatalina@gmail.com): "BUENOS DÍAS ANA, INFORMARTE QUE EL INGRESO DE EMILIANA SE REALIZARÁ ESTA SEMANA, HOY HEMOS REALIZADO PCR Y LO MAS SEGURO QUE MAÑANA TENGAMOS LOS RESULTADOS, SI TODO ES NORMAL, MANDARE EL RESULTADO A MAY PARA QUE MANDEN LA RESOLUCIÓN. TE MANDARÉ LA DOCUMENTACIÓN RELLENA PARA QUE LA FIRMÉIS Y ME LA DEVUELVAS FIRMADA, SI TE PARECE BIEN. ESTAMOS EN CONTACTO. UN SALUDO"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-03-08','Ana: Envío correo a Oscar y Alberto, Secc. Ecca: "Comunicaros que a través de la Ley de Dependencia se le solicitó, el pasado mes de agosto, revisión para acceso plaza residencial (puede ser plaza pública o prestación vinculada al servicio). He mirado en SIDEX y actualmente está pendiente de Negociación PIA (Programa Individual de Atención), esto quiere decir, que me tienen que enviar el documento para que aceptemos alguna de las dos propuestas; plaza o prestación, o ambas en su caso, y una vez se acepte le concederán una de las dos. He intentado contratar varias veces esta mañana con ella, sin éxito, a ver si lo consigo. Y en cualquier caso, espero nos remitan pronto el documento para registrar la aceptación y comience a mejorar su situación económica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2022-03-08','Ana: Correo en el ctutelar@ a través de la dirección de contacto: inf.saludextremadura@salud-juntaex.es: "Buenos días! mi nombre es Mamen Sánchez, trabajadora social del centro de Personas sin Hogar de caritas en Cáceres, en estos momentos tengo acogido a Francisco Cacho Garrido, llevo dos semanas llamando a los diversos teléfonos de la comisión tutelar para poder hablar con Ana Matamoro, y no lo consigo, por eso me pongo en contacto por este medio. Me refiere Francisco (que esta cobrando una pensión no contributiva de invalide) que la declaración anual de dicho pensión la realizan ustedes, quería saber si esto es así, sino no fuera para realizarlo desde nuestro recurso. Gracias un saludo MAMEN SANCHEZ RODRIGUEZ EMAIL: mcsanchez.cdcoriacaceres@caritas.es teléfono: 927 23 50 82 ········································································· Llamo a Mamen, TS del Centro de personas sin hogar (927 23 50 82), me dicen que no se encuentra. ············· Le envío un correo (mcsanchez.cdcoriacaceres@caritas.es): "Buenas tardes Mamen, Acabo de llamarte pero ahora soy yo la que no te pillo a ti, jeje. En relación a Francisco Cacho, decirte que efectivamente, está tutelado y le teníamos perdida la pista. La Declaración Anual de PNC la hacemos desde aquí, sí, la tiene que firmar su REPRESANTE LEGAL (Presidente de la Comisión Tutelar de Adultos). No obstante me gustaría hablar contigo al respecto de Francisco. Mañana intento llamarte de nuevo. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-03-08','Ana: Conversación con Ceferino, se le explica como se va a proceder con respecto a las deudas que ha adquirido con una compañera del CRR. *Deberá, como él mismo propuso, devolverle el dinero con su "extra anual". *Se queja porque dice que la consola que compró (1ª deuda) ya no la tiene él. Esta cuestión deberá abordarla con las profesionales del centro. Además la decisión de desprenderse de ella también ha sido suya y la deuda como tal tiene que pagarla. ························· Correo de Lourdes, secc. ecca., al CRR: "...CEFERINO MARISCAL CRESPO, se le va cambiar la asignación mensual de 350€ a 450€, y en cuanto a la extra anual solicitado, que pedís 1200€ y se le va a dar 1000€, dinero del que tendrá que pagar la deuda pendiente. Así mismo, necesitamos saber como se va a actuar en caso de que vuelva a endeudarse( como es posible que pueda volver a pasar), que consecuencias a va a tener Ceferino, castigo,…."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-03-07','Ana: Llamo a Paula, TO CRR: Abordamos las cuestiones monetarias, deudas, asignación mensual y "extra anual" y la forma en que intervendrán con él. *Van a probar una nueva estrategia tras haber comprobado reiteradamente que la del "castigo" no funciona con él. Quieren colocarlo en otra posición y ayudarle a gestionarse, teniendo él mayor capacidad adquisitiva. ·················· Tendrá que abonar su deuda con el extra mensual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2022-03-08','Ana: Correo de Lourdes, secc. ecca., al CRR: "MARIA CONCEPCION FERNANDEZ MUÑOZ, respecto a la cuota mensual se acepta los 360€, pero NO se acepta el extra anual solicitado por importe de 1000€, el motivo es que se compensará porque solicitáis unas cantidades mensuales de 150-200€ como parte de la intervención para su autonomía y esta si se acepta."','2');
