insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2022-03-09','miguel, recibo email de Amalia (con copia a Alberto y Angel):Buenos días , este piso es de los padres de SONIA VALCACER VIDAL . No aparece en su inventario ni en las D. anuales , me acabo de enterar que existía y he pedido la documentación a su hermana. ( tenéis tf. de contacto en la intranet ) . Es un piso que está en Madrid y que lo tienen alquilado. Son 4 hermanas , 3 con patología mental asociada a consumo de drogas . La hermana mayor que vive en Cáceres ,y que no tiene discapacidad es la que gestiona todo . De los alquileres va pagando cosas de las hermanas pero sin ningún control . Le he explicado que nosotros tenemos que velar por los bienes de Sonia y que todo ésto hay que regularizarlo y ella tiene que coger su parte de los ingresos y obviamente también de los gastos . Tiene una cuenta a nombre de todas las hermanas y ahí va ingresando el dinero . Os envío la documentación que me ha enviado para regularizar la situación. Habría que hacer partición de herencia ?? No me ha pasado documentación sobre el alquiler , contrato , cuantía .. se lo voy a volver a pedir . Pido también información sobre esa cuenta en común que tienen? Seguimos.. **************************************** mi contestación: Buenos días, mandas una escritura de compraventa ilegible. En el expediente no hay nada ni de bienes inmuebles, ni de cuentas, ni certificados de defunciones, etc. Tampoco veo si la tutelada tiene marido, hijos, etc… Lo digo porque si no tiene futuros herederos y viendo que no tiene necesidad de que se tramite herencia, ya que en su inventario tiene más de 15.000€, habría que dejar en manos de un abogado o gestoría que acuerden sus hermanas en común con ella la tramitación de todo…','2');
