insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2022-03-09','TERESA En relación al tutelado Darío López Giralte tenemos una duda que espero que nos aclares. Como sabes está matriculado en un módulo de informática en el Instituto “Luis Chamizo” está siendo una experiencia muy positiva para él. Los profesores están muy implicados, mantenemos un contacto estrecho con ellos y nos comentan que tienen dudas de que el curso lo finalice satisfactoriamente a nivel académico, pero que le está viniendo muy bien a nivel de integración social. Tiene un grupo de amigos con los que se relaciona de forma positiva en el instituto y fuera del instituto. Esto es un logro importante para Darío, teniendo un diagnóstico de autismo. Con este grupo de compañeros queda para salir con ellos y de vez en cuando para cenar en Villanueva. El problema es que son chicos de diversas localidades y sabemos que van a quedar para cenar en las localidades de cada uno de ellos, estamos hablando de Don Benito, Quintana, etc, pueblos de nuestros alrededores. La forma de ir es que le recogerían en la Vivienda Tutelada y posteriormente le traerían en el coche de los amigos. Esta situación que es totalmente normal, en chicos de su edad, y que estamos convencidos de que a Darío le vendría muy bien por su integración social y en la comunidad, creando lazos de amistad significativos, nos da un poco de miedo que lo pueda hacer sin el visto bueno vuestro. Por este motivo, ruego valoréis este tema y nos deis una respuesta. Comprendiendo que los riesgos siempre existen, pero sopesando los pros y contra de la situación SE AUTORIZAN LAS SALIDAD APOYANDONOS EN LA NUEVA NORMATIVA ESTAREMOS PENDIENTE DE COMO INFLUYEN ESTAS SALIDAS EN DARIO','2');
