insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='SANCHEZ'and apellido2='MORENO'),'2022-03-10','REUNIDOS 10/03/2022: AMALIA, MIGUEL, OSCAR Y ALBERTO...SE DECIDE: EMBARGO: EMBARGO X 704,38 €.......le abonaríamos 845,62 € y esa deuda quedaría SALDADA EMBARGO: OSCAR HA COMPROBADO QUE X LA MISMA MULTA FALTAN POR PAGAR 1.137,22 € (INFORMACIÓN OAR): SE UTILIZARÁ EL MISMO SISTEMA...SE MINORARÁN LOS PAGOS X MANUTENCIÓN EN LA PROPORCIÓN NECESARIA (OSCAR) PRESTAMO PSA: OSCAR: HABLAS CON PSA FINANCE PARA AMORTIZAR DEUDA X IMPAGOS Y RETOMAR EL PAGO MENSUAL. SEGUROS AUTO: SON 2 Y AMALIA, EN SU MOMENTO YA AVISÓ A FAMILIA QUE DEBIAN DOMICILIARLOS A SU NOMBRE O SE PROCEDERÍA A SU DEVOLUCIÓN - OSCAR REITERO LA MISMA CUESTIÓN A LA CUÑADA. LOS 2 SEGUROS X IMPORTE DE 225,67 € Y 190,87 €= 416,54 €----ACORDAMOS RESTAR ESTE IMPORTE DE LOS 845,62 RESTANTES (ATRASOS X MANUTENCIÓN: SE ABONARIA X "ATRASOS MANUTENCIÓN": 429,08 € OSCAR: TRANSFERENCIA PUNTUAL X 429,08 € "ATRASOS MANUTENCIÓN" OSCAR: TRANSFERENCIA PERMANENTE X 310 € "MANUTENCIÓN".','2');
