insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-03-10','Ana: Llamada de Sonia Bernabé - Asindi (927 390 193): Sigue ingresado en la UHB, el fin de semana se había levantado de noche y estuvo autoagrediéndose, tuvieron que ponerle un inyectable para tranquilizarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-03-10','Ana: Envío correo a Toni-Futuex: "Buenos días Toni, He recibido llamada de Ángel Félix Maillo, me dice que el otro día fue a visitarla una chica pero que estaba muy nervioso y no estaba para atender a nadie. Me pide que os traslade sus disculpas y que os diga que podéis volver a ir. Que él no suele comportarse así. Veremos. A parte de esto, dice que necesita ropa y calzado, le he vuelto a explicar el modo de proceder, que tiene que remitir presupuestos previos para que el jefe de sección dé el visto bueno a los mismos y que posteriormente se abonará a la tienda mediante transferencia. También quiere unas “simientes” que comprará en el mercadillo, para el patio de una casa de un amigo en Malpartida que van a preparar. Le he preguntado si se trata de algo ilegal, afirma con rotundidad que no…. En cuanto a su enfado de la otra semana con respecto a la asignación bancaria, por si hiciera alusión a ello, me informa Icíar que fue un error del banco. Pues desde aquí se envió autorización para un extra de 20€ y especificaron que era independiente de su asignación periódica, que también debían darle, pero no debieron entenderlo o no lo leyeron directamente o no sé qué ocurrió, pues sólo le dieron los 20… Ya me vais diciendo si consiguen visitarlo y cómo funciona en tal caso. Gracias y buen día." ······································ Correo-respuesta de Toni, con información de la primera visita realizada (04/03/22). Guardo en el expte. digital. A reseñar: "Pues el primer seguimiento, fue fracamente mal... como te comente se hace muy complejo la intervencion con un perfil asi, que está en situación (muy pobrablemente de consumo). En el crr, nos comentan ya que como sabes tenemos alli a su hermana (aunque el no debe saber de esta vinculacion) que está consumiendo bastante.. (ya que ha concertado alguna cita con la hermana y no se ha presentado)." ... "Su humor cambia durante la conversación puesto que exige que se solucione en esa misma mañana la posibilidad de retirar más dinero, su leguaje es agresivo y exigente, verbalizando de forma literal que se le “está jodiendo la vida” y boicoteando cualquier intento de conversación o dialogo por lo que la visita se acorta bastante al no acceder a la realización del citado presupuesto, lo que si manifiesta claramente que con la cantidad autorizada de 50 € semanales no tiene suficiente para vivir. Explica también que necesita comprarse ropa y calzado, se observa que las zapatillas que lleva puestas están rotas y en caso de lluvia se le mojarían los pies, a nivel global se le observa con una higiene adecuada. Se sospecha de habitos de consumo, sin poder contrastarlo." ··· *No consiguen su colaboración para establecer un presupuesto de gastos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-03-10','Ana: Pongo para REGISTRO DE ENTRADA la Aceptación PIA de Mantenimiento del Servicio que me remite Claudia, TS del C.R. El Cuartillo. ················· Registrada el mismo día. ·········· Se lo envío escaneado a Claudia, TS CR El Cuartillo (Técnica que a su vez firmó el PIA)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2022-03-10','Ana: Envío correo-respuesta a Minerva, TS del CR Cervantes (minerva.salvador@salud-juntaex.es): "DESDE ESTE GABINETE TÉCNICO DE LA COMISIÓN TUTELAR DE ADULTOS DE EXTREMADURA SE AUTORIZA EL ABONO DEL TRATAMIENTO PARA DEJAR DE FUMAR PARA EUGNIA PACHECHO VICENTE CUYO COSTE HABÉIS DETALLADO. Desde la sección económica piden que os recuerde que este presupuesto no puede incrementarse y que no deberán producirse otros gastos extraordinarios en lo que queda de año. Pongo en copia a Oscar, el compañero de la sección económica que se encargará de esta cuestión. Supongo que se pondrá en contacto contigo."','2');
