insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-03-11','Ana: Correo de Sonia Bernabé - Asindi: "Hola Ana, quería informarte que seguramente a lo largo de esta tarde dan el alta a Aaron. Están pendientes de resultado de un TAC que le han realizado para descartar cualquier lesión que sea el origen de las voces. Como por la tarde no estaré, el lunes os confirmo si ha regresado. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2022-03-14','Ana: envío correo a Rosa Bravo, Admvo. CSS-Plas: "Buenos días Rosa, Aquí tienes el consentimiento informado para extracción dentaria relativo a Cipriano Miguel Bazaga. Un saludo y buena semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2022-03-11','miguel, llega email del abogado Luis Fernando Agorreta Blázquez >fernandoagorreta@hotmail.com> : Muy señor mio:le adjunto embargo efectuado a Doña Pilar Garcia Moreno por importe de 11.453 euros con fecha 24 de Noviembre de 2021, en los autos de ejecucion de titulos judiciales seguidos en el Juzgado de Primera Instancia nº 4 de Cáceres, y Auto despachando ejecucion con fecha 5 de Septiembre de 2008.En el siguiente email le adjunto poliza de préstamo que ha dado lugar a la ejecucion y le explicito motivos de oposicion. Doña Pilar estuvoi casada en régimen de gananciales.El presupuesto del pleito para honorarios de Letrado y Derechos de Procurador ascenderia a unos 975 euros. Atentamente FERNANDO AGORRETA BLAZQUEZ - Abogado- 631 171 918 ******************************************* reenvio email a Alberto: Buenos días, hay un abogado que se ha puesto en contacto en relación a la tutelada, que pretende impugnar un embargo cuyo origen es un ptmo del que no teníamos conocimiento. El procedimiento origen es del 2008… El embargo como verás en el email de más abajo es de 11.453 euros. Este abogado nos propone tramitarlo, siendo sus honorarios unos 975 euros. Mi pregunta es, hay dinero para asumir el gasto de abogado? Mira las cuentas a ver si le han cargado algo los últimos meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-03-14','Amalia, no recuerdo si te mandé el informe de Mª Jesús Cruz Esperilla. De momento sigue en UHB en espera de su derivación e ingreso en el CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-03-14','Ana: A petición de Miguel, Asesor Jurídico, envío correo a Sonia Bernabé, Asindi: "Buenos días Sonia, En relación al asunto de FELISA BRUNO, pedirte por favor, que en cuanto sea posible: - Solicitéis el Certificado de Empadronamiento de Felisa. Eso sí, como tú bien planteabas lo tendrá que firmar el representante legal. - No enviéis también Certificado de Ingreso en vuestro centro - Por último, que Felisa firme la DECLARACIÓN JURADA adjunta y nos la enviéis junto con los otros documentos Si el certificado del Ayto. tárdese mucho (no sé cuánto tardan en esta gestión) enviarnos primero los otros dos, que puede que con eso sirva. No obstante es importante que se empadrone para futuras cuestiones que puedan surgir. Gracias y buena semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-03-14','-Email de Mar , TS del ESM : Buenas tardes; Mercedes continua sin acudir al ESM, suponemos que no cumple tratamiento farmacológico con el riego que lleva consigo. Como bien sabes, los profesionales del equipo no se desplazan al domicilio. Saludos,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-03-17','miguel, remito a AEAT contestación a la notificación de la diligencia de embargo de créditos acreditando lo que pagamos al mes, 805€ solicitando que nos remitan carta de pago por este importe o una cuenta al que ingresarlo.Hemos unido los justificantes de los pagos realizados de los últimos meses por este importe, y junto a la orden al banco de eliminar la orden de domiciliación','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-03-11','miguel, llega email de la empresa a ctutelar: Buenos días, le agradecería me hiciera llegar copia del ingreso que han hecho a Hacienda en nombre de Fernando Bravo Calvo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-03-14','miguel, contesto a Carmen de la empresa: Buenos días Carmen, te adjunto justificante de contestación a la notificación de la diligencia de embargo de créditos, de la cual AEAT no nos ha contestado. Si quieres preguntar a Aeat porque si ves nuestro escrito y documentación que adjuntamos como justificantes, solicitamos nos remitan cartas de pago por los importes de 805€ y no la cantidad total que indican.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-03-14','Amalia, no recuerdo si te mandé el informe de Mª Jesús Cruz Esperilla. De momento sigue en UHB en espera de su derivación e ingreso en el CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-03-14','-Amalia , respondo al ESM : Buenos días , desde la Comisión Tutelar no podemos obligarla a ir , la delegada le insiste y motiva para que acuda a consulta pero sin éxito . Ante esta situación , y dado que los profesionales del ESM no se desplazan a domicilio , os habéis planteado solicitar internamiento involuntario a través del 112 ?? Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-03-14','-Amalia : escribo email a Miguel ( jurídico y Jefa de sección ) . Buenas , he llamado a Mercedes pero no tiene intención de ir , le he dicho que en ese caso lo tendremos que informar al juzgado , a ver si la hacía reaccionar ,pero nada . El ESM me dice que ellos no se desplazan . He preguntado si desde el ESM se han planteado activar el 112? pero te puedes imaginar la respuesta , si estando descompensada no lo han hecho . Ante esta situación , no sé si tenemos que comunicarlo al juzgado . Mañana si quieres lo hablamos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2022-02-24','miguel, envío email a Carmen Miñarro Monge, con copia a CC: Mónica Lázaro Andreu >mlazaro@amstro.es>; defectos_inscripciones@servihabitat.com, donde remito el testimonio firme solicitado de nombramiento. ******************************************** contestación de ella: Buenos días, gracias por lo remitido pero en realidad lo que el registro necesita es que se acredite que la sentencia de incapacitación consta inscrita en el registro civil, que es lo que se os pidió debiendo constar la aceptación de cargo de tutor, por eso os pedíamos certificado literal de nacimiento donde constara la inscripción de la sentencia de incapacitación y la aceptación de cargo de tutor ******************************************* mi contestacion: Buenos días, entiendo que si la sentencia no consta todavía inscrita en el registro civil, vosotros como parte interesada podéis gestionar dicha inscripción, con la aceptación de cargo. Quedo pendiente de vuestras noticias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2022-03-04','Ana: Correo de Emilia, TS CSS (emilia.almodovar@salud-juntaex.es): "Respecto al cambio de Centro por motivos psicosociales del paciente, fueron considerados por el equipo, tras tener en cuenta sus peticiones y solicitudes del paciente, y nuestro deber es comunicarlo a sus tutores y así tomar alguna decisión. Desde entonces, Jairo fue cambiado de Unidad dentro del centro (URA) en estos momentos ha vuelto a la Unidad de Larga Estancia. Teniendo en cuenta que sus peticiones nos son sostenidas en largos periodos de tiempo, desde la visita, nos manifiesta lo que refieres en el correo de irse a Cáceres, trabajar y ser independiente, de echo está esperando a la compañera de Futuex para ir a la Oficina de Desempleo. Muchas Gracias por la atención Ana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-02-15','Ana: Correo de Fátima, Ed. Soc. Asociación Vera: "Buenos días Con motivo de la incidencia-agresión que tuvo lugar la semana anterior, en la que Adrián agredió físicamente a un compañero y de la cuál se informó a Comisión Tutelar. Adjunto factura de gafas nuevas, ya que rompió las de su compañero, para que Adrián Ortigosa reembolse al afectado. Pongo en copia a Ana, ya que aunque es un tema económico, creo que debe ser consciente de esta medida. El usuario agredido ha pagado por adelantado el precio de las gafas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2022-03-14','miguel, envío email a Amalia y Maite: Buenos días, acaba de llamarme Jose Manuel Escalona (de abogacía general, tlfno 924-003931) en relación con lo que comentaba en el curso del viernes Tony (abogada) que como extrabajadora de Futuex, y con la cual finalmente no tuve oportunidad de hablar de este asunto. Al tratarse de la petición que hace la familia para que asumamos la curatela representativa, necesita le remitamos un borrador de informe social aclarando las siguientes cuestiones: Tal y como le pide la contraparte y al venir recogido en nuestro Decreto constitutivo, la obligación de la Ctaex de contratar con cualquier organismo público o privado para ejercer nuestro cargo, sería posible el apoyo de Futuex, Centro de Plena Inclusión, etc. Esto le lleva a preguntarnos: 1.-Sobre la Ctaex: de qué medios de apoyo contamos para con nuestros representados (curatela representativa/ asistencial), y cuándo no disponemos de medios cómo actuamos…ya que tenemos obligación de aportar medidas de apoyo. 2.-Sobre Futuex: qué funciones desarrollan para nosotros, de cuántos delegados de apoyo dispone para cada provincia. 3.-Sobre Plena Inclusión: qué ayudas y para qué fines sirven, únicamente para sus residentes o también para los que van a centro de día. Dice que en algunos casos han asumido cargos y para otros se niegan a aceptar el cargo (sin justificar los motivos) 4.-En relación al curatelado: cuál es su trato con la ctaex (describirlo lo más posible), y cómo actuamos nosotros con él, qué recursos disponemos con él, y cuáles necesitaría. Me ha comentado que le gustaría que le informáramos de cómo haremos para adaptarnos a la nueva ley (básicamente de qué medios y recursos dispondremos). En definitiva que hablará más adelante con Maite. Si quieres Amalia cuando vengas a la oficina presencial llamamos a Tony para que nos comente su posición antes de hacer este informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-03-10','Ana: Correo de Fátima, Ed. Soc., Asociación Vera (educadorasocial@asociacionvera.com): "Buenos días Adjunto informe sobre la evolución conductual de Adrián Ortigosa Fuentes, como su actitud ha ido en detrimento en los últimos meses." ········· Guardo el informe en el expte. digital. ··········· Según el informe, entre otras cuestiones: Adrián no cumple los horarios de regreso al centro cuanto sale, sale del centro sin autorización y sin comunicarlo, incumple las sanciones que le imponen en el centro, se enfrenta a trabajadores del centro, golpea a varios usuario del centro (hay partes de lesiones), cogió las llaves de la furgoneta del centro e intentó irse con la misma, pero se le calaba y no consiguió arrancarla, se niega a acudir a los talleres e incumple los horarios y se levanta al medio día, sólo quiere ir a las actividades lúdicas y de ocio, miente de forma reiterada, la habitación la tiene desordenada y sucia, "guardando" la ropa sucia debajo de la cama, faltas de respeto reiteradas y amenazas a compañeros y profesionales...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-03-14','miguel, recibo email de la abogada Carmen Lucas Duran >mlucasduran@icac.es> c/ San Antón, 6 1º B, 10003 Cáceres Teléfonos y Fax: 927 226664 y 927226673, 627597037 www.bufetelucasabogados.com: Miguel, recibo esto del hermano de Miguel Salgado, sólo preguntarte ¿Sabe él algo de las consultas que realizaste y de las que me diste traslado a los tecnicos? No sé, me está resultando el tema cargado de presión, yo he solicitado la libertad provisional, os pedí informes… ________________________________________ ************************************************** Reenvío email a Ana Ts: Buenos días Ana, conforme los emails de más abajo, el hermano ha requerido vía Defensor del pueblo y al que ya contesté en su día. Nos hace llegar la contestación del defensor del pueblo donde se preguntan si se ha solicitado o no informe de psiquiatría… Al final te mandaron algún informe social o de psiquiatra de Saturnino? Te he llamado sin éxito… Si miras los emails de debajo de enero y febrero ya le comenté que la Trabajadora social del Centro Penitenciario no haría informe sin que se lo requiera al juzgado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-03-14','-Email de Miguel : Buenos días, lo que haya que comunicar al juzgado hay que acreditarlo por escrito, por lo que desde el ESM, equipo médico, etc deberíamos tener algo por escrito… Lo vemos cuando vengas. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2022-03-10','Ana: Correo de Fátima, Ed. Soc., Asociación Vera (educadorasocial@asociacionvera.com): "Los usuarios tutelados que han dado positivo y de los que su estado de salud es bueno, ya que son asintomáticos son: - ANTONIA BRAVO PATILLA..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2022-03-10','Ana: Correo de Fátima, Ed. Soc., Asociación Vera (educadorasocial@asociacionvera.com): "Los usuarios tutelados que han dado positivo y de los que su estado de salud es bueno, ya que son asintomáticos son: - JOAQUÍN HERRERO GARCÍA"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-03-14','Ana: Envío correo a Paloma, TS del CR El Cuartillo (paloma.castellano@salud-juntaex.es): "Buenos días Paloma, ¿Qué tal estás? En relación a EMILIA GUTIÉRREZ SERRADILLA, me comenta el jefe de la sección económica, que puede que haya habido algún error en la cuota de Emilia, pues cree que quizá deberían estar cargándole una cuantía más alta. Copio textualmente: • “COSTE CENTRO EL CUARTILLO...SÓLO LE PASAN 211,36 € X LA PLAZA...ESE IMPORTE NO SE SI ES CORRECTO (DEBERÍA SER SUPERIOR)...SUS INGRESOS SON: o JUBILACION 530,91 14,00 7.432,74 VIUDEDAD 335,61 14,00 4.698,54 o • NO HAY ESTABLECIDO UN PRESUPUESTO MENSUAL DE GASTOS CON CENTRO” La información sobre las pensiones se la pasé yo a Amparo, Directora, a fecha de 28 de diciembre. En cuanto a los gastos de bolsillo, como ves, también pregunta si no tiene gastos y sino habría que establecer un presupuesto para los mismos (si toma café, peluquería…) Ya nos dices cuando puedas. Gracias y buena semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2022-03-14','-Amalia : respondo a Miguel con respecto de la revisión de sentencia que ha presentado nuevamente la familia . Si os viene bien , mañana nos reunimos y hablamos de este caso . Es la segunda vez que se emite informe sobre la misma problemática , puedes verlo en su expediente . Y nuestra postura es la misma , puesto que su situación no ha cambiado . Desde la CTAEX no podemos garantizar la adherencia a tratamiento de aquellas personas que viven solas en su domicilio , aceptando su deseo y preferencia. Y éste es uno de los casos. Desde Plena Inclusión , recurso de discapacidad , no pueden atenderle ( a pesar de que lo están apoyando sin tener plaza ) porque el CADEX no le ha dado perfil de discapacidad para este tipo de centros . La entidad insiste en que sí se le podría atender en plaza de Centro Ocupacional , pero no ha obtenido pérfil administrativo necesario para ello , debido a su patología mental y problemas de conducta. Es un usuario cuya patología principal es de salud mental , por lo que es su ESM el que tendría que proporcionarle atención sanitaria . Pero él no la facilita , no tiene conciencia de enfermedad , ni correcta adherencia a tratamiento . Sin embargo , su estado es basal , no suele tener descompensaciones a nivel psiquiátrico . Podría acceder a los recursos residenciales del SEPAD : Centro residencial de rehabilitación para usuarios con enfermedad mental ó Pisos supervisados cuya derivación es desde el ESM . Pero se exige la voluntariedad ,al ser un recurso de rehabilitación y él se niega a ingresar en ningún centro. Por lo tanto , no se le puede ingresar en ningún recurso como solicitan los padres . Actualmente reside en un chalet en el campo cuyo copropietario es el padre . Suele tener varios perros con él , y no quiere desprenderse de ellos . Cría perros que luego vende . Los padres no quieren que esté allí porque la familia y sus tíos no pueden disfrutar del chalet e insisten en que se le busque una alternativa residencial desde la administración. Alternativa inexistente puesto que su hijo no quiere acceder a centro . Con respecto al control de la medicación, y entendiendo las dificultades que pueda tener la familia para garantizar la asistencia a citas médicas y la toma de la medicación, creemos que deben ser ellos los que velen por la salud de su hijo. Estas funciones no pueden garantizarse desde la Comisión Tutelar, que ejerce funciones de tutela administrativa, no convivimos con el curatelado y no se puede facilitar que diariamente siga el tratamiento de ninguna de las maneras. Y es imposible sí él no quiere tomársela. No está actualmente en seguimiento con FUTUEX porque para el control económico que es de lo que somos curadores no es necesario . Para la adherencia a tratamiento , aunque lo visitasen una vez a la semana si él no quiere acudir a citas ni tomarse la medicación , nada puedan hacer. La madre tiene una relación de apoyo y protección , la relación es más tensa con el padre , que trata de imponer sus opiniones. A pesar de esta mala relación, tanto los padres , como su hermano y resto de familia , viven en la misma localidad y aunque sea indirectamente , saben y conocen de la situación del hijo . En la práctica siguen ejerciciendo medidas de apoyo con su HIJO . Incluso le apoyan económicamente cuando le hace falta algo ( por ej. han abonado la mitad del colchón que se le ha comprado el mes pasado ) Si por lo tanto , en la práctica están ayudando a su hijo , cual es el fin de que a nivel jurídico se les exima del cargo ??? La alternativa residencial a nivel técnico, que garantizaría que las necesidades básicas de alimentación, higiene, vivienda e integración social y laboral sería que D. Francisco. Javier aceptase voluntariamente el ingreso en plaza residencial en un centro específico pero no se cuenta , como explicaba , con su voluntariedad . En el ejercicio del cargo de curador, para el aspecto económico que nos encomienda su sentencia, de modificación de capacidad, nos estamos encontrando con la oposición por parte de D. Francisco. Javier para la administración económica. No acepta la situación de control económico que ejercemos sobre él. Nos ha amenazado en varias ocasiones , se ha presentado en las oficinas del SEPAD sin cita y ha dejado una hoja de reclameaciones... no acepta nuestra ayuda , no quiere que nadie controle su vida ni su dinero . OJO !! si en la revisión de sentencia él decide cómo administrar su PNC no sé cómo se tendrá que intervenir desde la Comisión .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2022-03-14','Ana: Envío correo a Loli, RRMM Santa Catalina de Calzadilla (residenciasantacatalina@gmail.com): "Buenos días Loli, Adjunto remito los siguiente documentos relativos a EMILIANA SÁNCHEZ BERMEJO, debidamente firmados por su representante legal: - Contrato de Residencia - Cláusula Informativa para residentes - Autorización de cinturón bajo indicación médica - Autorización Domiciliación Bancaria Ante cualquier cuestión no dudes en ponerte en contacto de nuevo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2022-03-14','-Amalia : respondo a Miguel con respecto de la revisión de sentencia que ha presentado nuevamente la familia . Si os viene bien , mañana nos reunimos y hablamos de este caso . Es la segunda vez que se emite informe sobre la misma problemática , puedes verlo en su expediente . Y nuestra postura es la misma , puesto que su situación no ha cambiado . Desde la CTAEX no podemos garantizar la adherencia a tratamiento de aquellas personas que viven solas en su domicilio , aceptando su deseo y preferencia. Y éste es uno de los casos. Desde Plena Inclusión , recurso de discapacidad , no pueden atenderle ( a pesar de que lo están apoyando sin tener plaza ) porque el CADEX no le ha dado perfil de discapacidad para este tipo de centros . La entidad insiste en que sí se le podría atender en plaza de Centro Ocupacional , pero no ha obtenido pérfil administrativo necesario para ello , debido a su patología mental y problemas de conducta. Es un usuario cuya patología principal es de salud mental , por lo que es su ESM el que tendría que proporcionarle atención sanitaria . Pero él no la facilita , no tiene conciencia de enfermedad , ni correcta adherencia a tratamiento . Sin embargo , su estado es basal , no suele tener descompensaciones a nivel psiquiátrico . Podría acceder a los recursos residenciales del SEPAD : Centro residencial de rehabilitación para usuarios con enfermedad mental ó Pisos supervisados cuya derivación es desde el ESM . Pero se exige la voluntariedad ,al ser un recurso de rehabilitación y él se niega a ingresar en ningún centro. Por lo tanto , no se le puede ingresar en ningún recurso como solicitan los padres . Actualmente reside en un chalet en el campo cuyo copropietario es el padre . Suele tener varios perros con él , y no quiere desprenderse de ellos . Cría perros que luego vende . Los padres no quieren que esté allí porque la familia y sus tíos no pueden disfrutar del chalet e insisten en que se le busque una alternativa residencial desde la administración. Alternativa inexistente puesto que su hijo no quiere acceder a centro . Con respecto al control de la medicación, y entendiendo las dificultades que pueda tener la familia para garantizar la asistencia a citas médicas y la toma de la medicación, creemos que deben ser ellos los que velen por la salud de su hijo. Estas funciones no pueden garantizarse desde la Comisión Tutelar, que ejerce funciones de tutela administrativa, no convivimos con el curatelado y no se puede facilitar que diariamente siga el tratamiento de ninguna de las maneras. Y es imposible sí él no quiere tomársela. No está actualmente en seguimiento con FUTUEX porque para el control económico que es de lo que somos curadores no es necesario . Para la adherencia a tratamiento , aunque lo visitasen una vez a la semana si él no quiere acudir a citas ni tomarse la medicación , nada puedan hacer. La madre tiene una relación de apoyo y protección , la relación es más tensa con el padre , que trata de imponer sus opiniones. A pesar de esta mala relación, tanto los padres , como su hermano y resto de familia , viven en la misma localidad y aunque sea indirectamente , saben y conocen de la situación del hijo . En la práctica siguen ejerciciendo medidas de apoyo con su HIJO . Incluso le apoyan económicamente cuando le hace falta algo ( por ej. han abonado la mitad del colchón que se le ha comprado el mes pasado ) Si por lo tanto , en la práctica están ayudando a su hijo , cual es el fin de que a nivel jurídico se les exima del cargo ??? La alternativa residencial a nivel técnico, que garantizaría que las necesidades básicas de alimentación, higiene, vivienda e integración social y laboral sería que D. Francisco. Javier aceptase voluntariamente el ingreso en plaza residencial en un centro específico pero no se cuenta , como explicaba , con su voluntariedad . En el ejercicio del cargo de curador, para el aspecto económico que nos encomienda su sentencia, de modificación de capacidad, nos estamos encontrando con la oposición por parte de D. Francisco. Javier para la administración económica. No acepta la situación de control económico que ejercemos sobre él. Nos ha amenazado en varias ocasiones , se ha presentado en las oficinas del SEPAD sin cita y ha dejado una hoja de reclameaciones... no acepta nuestra ayuda , no quiere que nadie controle su vida ni su dinero . OJO !! si en la revisión de sentencia él decide cómo administrar su PNC no sé cómo se tendrá que intervenir desde la Comisión .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-03-14','-email de Mar , TS ESM : Buenos días Amalia! Estamos en contacto con el primo, Jesús, es nuestro referente. Hemos hablado con Mercedes por teléfono, en la conversación, sí que la noto distante y que no quiere hablar, es lo que más detecto. En cuanto al 112, por protocolo se activa desde el Médico de AP, siempre se necesita una valoración clínica. Ya sabemos que no la podéis obligar. Estamos en contacto. Saludos,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-03-14','-email de Mar , TS ESM : Buenos días Amalia! Estamos en contacto con el primo, Jesús, es nuestro referente. Hemos hablado con Mercedes por teléfono, en la conversación, sí que la noto distante y que no quiere hablar, es lo que más detecto. En cuanto al 112, por protocolo se activa desde el Médico de AP, siempre se necesita una valoración clínica. Ya sabemos que no la podéis obligar. Estamos en contacto. Saludos,','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2022-03-14','_Amalia : el informe de seguimiento que hizo el psiquiatra ( guardado en su expediente ) para sacar o no el carnet de conducir instaba a que fuese el centro de reconocimiento médico el que justificase su aceptación o no . Le han dado el carnet y la madre , sin preguntarnos, le ha comprado un coche y se lo ha traído a Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2022-03-14','_Amalia : el informe de seguimiento que hizo el psiquiatra ( guardado en su expediente ) para sacar o no el carnet de conducir instaba a que fuese el centro de reconocimiento médico el que justificase su aceptación o no . Le han dado el carnet y la madre , sin preguntarnos, le ha comprado un coche y se lo ha traído a Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2022-03-14','-Actualizacion contrato , email de Angel : En relación con este correo os comento. El contrato de alquiler, se firmó el 30/11/2018, con una vigencia de tres años. Llegado el vencimiento, 30/11/21, al no haberse denunciado, entra en tácita reconducción y se va renovando por años, en este caso, hasta el 30/11/22 y así sucesivamente. En cuanto a la actualización de la renta, estas han sido las variaciones del ipc, durante la vigencia del contrato: Noviembre del 18 á noviembre del 19: 0,4% Noviembre del 19 á noviembre del 20: -0,8% Noviembre del 20 á noviembre del 21: 5,5% Total: 5,9%. La renta se fijó en 350 euros y la cantidad que corresponde subir por el ipc del 5,9%, es de 20,65 euros, quedando actualizada en la cantidad de 370,65 euros. En cuanto a la limpieza de la vivienda, entiendo que debería acudir alguien de Futuex y que nos vaya diciendo. Saludos.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2022-03-14','-Actualizacion contrato , email de Angel : En relación con este correo os comento. El contrato de alquiler, se firmó el 30/11/2018, con una vigencia de tres años. Llegado el vencimiento, 30/11/21, al no haberse denunciado, entra en tácita reconducción y se va renovando por años, en este caso, hasta el 30/11/22 y así sucesivamente. En cuanto a la actualización de la renta, estas han sido las variaciones del ipc, durante la vigencia del contrato: Noviembre del 18 á noviembre del 19: 0,4% Noviembre del 19 á noviembre del 20: -0,8% Noviembre del 20 á noviembre del 21: 5,5% Total: 5,9%. La renta se fijó en 350 euros y la cantidad que corresponde subir por el ipc del 5,9%, es de 20,65 euros, quedando actualizada en la cantidad de 370,65 euros. En cuanto a la limpieza de la vivienda, entiendo que debería acudir alguien de Futuex y que nos vaya diciendo. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2022-03-14','emal de su hermana: Buenas tardes Amalia, Comentarle que Alberto ha tenido una recaída desde carnavales. Ahora está en el hospital universitario en la unidad de psiquiatría. Está bien, no tiene brote como otras veces, pero le hemos convencido para que esté allí unos días. Reciba un cordial saludo. Ana Ramos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='GARCIA'and apellido2='PEREZ'),'2022-03-14','TERESA María 5/T/21 está tutelada por esta comisión desde febrero de 2021. Ingreso en la residencia Juan Carlos Ibarra de manera involuntaria. Anteriormente vivía en una vivienda social en régimen de alquiler. Me han llamado de vivienda para que firmemos la renuncia de la vivienda social ya que María no va a volver a esta casa pues sus circunstancias mentales y su edad no se lo permiten. Si ves la sentencia el forense indica que padece demencia senil la cual la incapacita parta prestar de forma consciente cualquier consentimiento. Ella se niega a renunciar a la vivienda social pero al ser en régimen de alquiler y estar ya en residencia de mayores debemos renunciar a ella pues hay lista de espera en el ayuntamiento de Villafranca pendiente de que le asignen una vivienda de estas características. Es necesario pedir autorización para firma dicha renuncia? Maria no dispone de parientes cercanos, hecho que se refleja en la sentencia de incapacitación, que hacemos con los muebles y sus enseres personales? VIVIENDA MARISA: luisa.cortes@juntaex.es Soy Marisa, Trabajadora Social de la Dirección General de Vivienda Me facilita tu email Marisa del Ayuntamiento de Villafranca de los Barros, he intentado llamarte pero no te localizo. Mi consulta es referente a María García Pérez, DNI 08671849-k, adjudicataria de la vivienda de promoción pública sita en Plaza América, nº 22 y que lleva años sin habitar. Me comentan en el Ayuntamiento que esta señora ha pasado a estar tutelada por la Comisión Tutelar de Mayores y que tú eres la persona de referencia. Necesito que se firme la renuncia a la vivienda para poder recuperarla y por ello quería hablar contigo. Mi teléfono es 924 33 24 56 o si quieres me respondes por email y me dices cuando puedo yo llamarte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-03-15','Ana: Pongo para REGISTRO DE ENTRADA la Comunicación de Variación de Domicilio del INSS. *Especifico que a efectos de comunicaciones hagan constar la dirección de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-03-14','Ana: paso a Julio, Aux. Admvo. de CTAEX, para que registre de SALIDA, oficio solicitando los Certificados con Revalorización de las Pensiones (Jubilación y Viudedad) de Emilia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-03-15','Ana: Subo al portafirmas digital la Solicitud de Cdo. de Empadronamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-03-14','Ana: Correo de Sonia Bernabé, ASINDI: "Aaron ha sido derivado a Salud Mental esta mañana muy temprano. El fin de semana ha estado más o menos tranquilo pero las compañeras dicen que no está estable como otras veces. Esta mañana sobre las 6 se ha levantado y se ha bajado a la zona de despachos, dando golpes a las puertas, tirando mobiliario y queriendo agredir a las compañeras que estaban en turno. Varias veces decía que oía voces y que veía un perro. Seguramente regrese a lo largo del día cuando le hagan ajuste de medicación,... Ya os informaremos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-03-15','Ana: Remito a Miguel el Informe del ESM que nos remitieron tras solicitarlo. ································································································································································································ Ana: Remito correo a Paula, Progr. de Intervención en C. Penitenciarios de Plena Inclusión (paula@plenainclusionextremadura.org): Tal y como hablamos ayer, te facilito información relativa a SATURNINO MIGUEL SALGADO JIMÉNEZ, interno del Centro Penitenciario de Cáceres. • Diagnóstico según valoración del CADEX: Trastorno Mental por Esquizofrenia Paranoide, etiología Idiopática. Grado Reconocido: 65% • Procedimiento Abreviado 751/2020 (Diligencias Previas) por Agresiones Sexuales • Se ha solicitado, mediante presentación de escrito de fecha 19 de Enero de 2021, la libertad provisional • Mediante Auto de 9 de febrero de 2022, del Juzgado de Instrucción nº 6 de Cáceres, se acuerda mantener la medida cautelar de prisión provisional comunicada y sin fianza. • Con anterioridad a su ingreso en prisión, residía solo en un domicilio familiar, con bastante autonomía y los apoyos por parte de la CTAEX, que ostenta el cargo de Tutor según Sentencia vigente y pendiente de revisión acorde a la nueva legislación. Si necesitas más información no dudes en decírmelo." ··············· Respuesta de Paula: "Buenos días Ana, voy a ver que Maite es la trabajadora social y el viernes me entrevisto con él. Y el próximo miércoles te llamo y te cuento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-03-15','Ana: ante el correo de Paula, TO CRR (tocupacional.crrplasencia@grupo5.net): "Hola Ana, en relación a lo que hablamos de una deuda de teléfono de Ceferino por una línea de contrato, confirmarte que actualmente y desde hace mucho tiempo (no sé especificarte) tiene un teléfono de tarjeta y destina 20 euros del presupuesto mensual a su recarga." ··········· Envío correo-respuesta a Paula: "Ok, gracias. Pues, según me informan mis compañeras de la sección económica, todos los meses, desde al menos julio del pasado 2021, le cargan un recibo de Vodafone de 76,98 €… desde aquí, como te comenté se devolverán los recibos. Agradecería que lo habláis también con él cuando tengáis ocasión, pues no puede seguir haciendo contratos sin estar autorizado desde aquí. Al menos no mientras no se revise su sentencia actual." ··················· Respuesta de Paula, TO: "seguimos trabajando con él en este aspecto, con la necesidad de consultar y recibir vuestro apoyo para la realización de contratos. Esto por lo que vemos es de hace bastante tiempo. Esperemos que con las intervenciones y nuevos enfoques podamos apoyarle a producir cambios."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-03-15','miguel, contesto a la abogada Carmen y le adjunto informe médico que me remite Ana Ts: Buenos días, el único informe que teníamos y no recuerdo si lo remitimos a tiempo. No hay informe social, porque tal y como te comente en un email que nos remitió la trabajadora social del centro penitenciario, ésta no emitiría ningún informe sino se lo solicitaba de oficio el juzgado. A nosotros también nos pidieron información el Defensor del pueblo y no hemos recibido nueva contestación a la nuestra. Entiendo que no hay más que aportar y que tanto el hermano como el defensor del pueblo tienen que esperar a la sentencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-03-15','miguel, me llama Inma de asesoría Cid y Villafaina, remito email de lo que me comenta a Alberto: Buenos días, de este expte la asesoría del Cid y Villafaina están tramitando la herencia de su madre. El viernes acompañaré al gerente a firmar en el juzgado el poder apud acta para que el procurador pueda aceptar la herencia que no tenía nada que ver con nosotros. He dado el visto bueno a contratar el abogado y procurador porque dispone de ahorros. La cuestión es que se han enterado por la Caixa de una cuenta que tenía la mujer allí y de la que el tutelado ha estado sacando dinero. Según me dicen es el único heredero y por tanto no afecta a otras personas. La asesoría va a hacer una adicción a la herencia (pagar el impuesto de sucesiones de esa cuenta), ignoramos el importe, y cuando la tenga me la remitirá. Apuntadlo la parte económica','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2022-03-15','miguel, subo a su expte el email del procedimiento de Remoción de tutores que han solicitado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-03-15','miguel, remití ayer a Carmen Tello el escrito que remití a Hacienda y que no han contestado. Me pide que la llame 620267748, y me comenta: el emisor SERVICIOS ASISTENCIALES FBC, no es Fernando Bravo, por lo que no deberíamos haber aceptado la diligencia de embargo de crédito. Ha habido un fallo puesto que la empresa tampoco nos lo aclaró, ya que dice que las facturas viene a nombre de esa empresa y no de Fernando Bravo. Parece ser que todo esto viene de los cambios de nombre de la empresa de Fernando Bravo y que a día de hoy ya está la deuda saldada. El lunes día 21 irá a hacienda y o bien me manda un justificante de que está al día de la deuda o bien tendré que mandar un nuevo escrito a AEAT indicando que no tenemos vinculación actual con Fernando Bravo sino con SERVICIOS ASISTENCIALES FBC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-03-15','Ana: Correo de Claudia, TS de CR El Cuartillo (claudia.alonso@salud-juntaex.es): "A Emilia la llevo yo, para cualquier asunto referente a ella me lo haces saber, por favor. En respuesta al email, los compañeros de administración me comentan los siguiente: La cantidad indicada de 211,36 euros, corresponde a los 9 días del mes de ingreso, los meses posteriores y al ser ya meses completos, se le pasará la cuantía total correspondiente. En cuanto a presupuesto mensual de gastos, debido a las características de la residente, no precisa gastos de tipo cafetería. Se le ha proporcionado el servicio de peluquería en dos ocasiones desde su ingreso. Si precisa de otro tipo de gastos (ropa, calzado...) os lo informaremos con antelación." ····················· Reenvío correo con las aclaraciones Alberto, jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-03-15','Ana: Correo de Sonia Bernabé, TS Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, Aaron quedó ingresado, luego intentaremos contactar con la psiquiatra que le atiende para ver cómo está y qué van a decidir, si se queda unos días y revisan tratamiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-03-15','miguel, hablo con la abogada Rocio Gracian en relación al judicio del 29-4-22 del desahucio en Málaga donde seguramente tengamos que asistir Damian y nosotros para lo cual me pide que le mande el siguiente email para asistir todos por videoconferencia para que se lo pueda presentar al juzgado: Buenos días, conforme hemos hablado comentarte que necesitamos que solicites al juzgado que si fuera requisito la asistencia nuestra se haga vía videoconferencia, a través de la página https://videojusticia.es la cual nos remite a una página de la Subdirección General de nuevas tecnologías de la Justicia de la App Cisco Meeting. Los datos que solicitamos a los Juzgados son el ID de la reunión y el código de acceso a la misma. El teléfono para el día de la citación desde el que accederíamos sería el 616552977 (del gabinete técnico jurídico de la Comisión Tutelar de Adultos). De igual forma, en caso que sea requisito la asistencia de Damian, tendría que ser por videoconferencia desde el Centro en el que reside (CRR Grupo 5-Mérida) tflno 924-304538, dirección c/Arturo Barea Ogazón sn 06800, Mérida (Badajoz) Los datos de contacto de esta Comisión Tutelar de Adultos son (aparte de mi email y tlfno que aquí te dejo): Email ctutelar@salud-juntaex.es Avda de las Americas 4, 06800, Mérida Nuestro fax 924003194 Como te he comentado el perfil de Damian es de una persona muy sensible que le supondría una gran alteración tanto antes como después del juicio, por lo que ruego que en la medida de lo posible no sea necesario se le cite. El juzgado puede consultar la enfermedad que sufre a efectos de tomar esta decisión. Por último y en caso que no pueda citarnos vía videoconferencia, comentar que en otros casos hemos asistido (durante años) vía videoconferencia desde los Servicios del SCACE de Mérida (servicio común de actos de comunicación y embargos) del Ministerio de Justicia, cuyos datos de contacto son los siguientes: 924317882; 924387427; 924387271 y fax 924315103. Cualquier duda quedo a tu disposición.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2022-03-15','Ana: Envío correo a Estrella, TS del CSS-Plas. (estrella.duranc@salud-juntaex.es): "En relación a REMEDIOS CHAVES MASERO, Alberto, jefe de sección económica, tras revisar su situación económica actual, nos confirma lo siguente: Desde el Centro podéis “DISPONER DE UN MÁXIMO DE 500 €/MES, QUE DISTRIBUIRÁN A SU ELECCIÓN (TAXI, GASTOS PERSONALES, REINTEGROS...)”, es decir, tenéis libertada para destinar, como máximo esa cuantía, a aquellas cuestiones que consideréis necesarias/importantes para ella, din necesidad de solicitar autorización al Gabinete Técnico de la CTAEX. *Eso sí, esta situación se podrá mantener siempre y cuándo Reme no tenga que abonar plaza residencial. Si hubiera algún cambio, incluso dentro de vuestro recurso, que implique una cuota mensual, hacédnoslo saber pues tendrán que volver a recalcular la cuantía. Las facturas de taxis y demás, podréis abonarlas desde ahí y enviarlas periódicamente, si queréis cada varios meses, a mis compañeras de la sección económica para control y, en su caso, justificación al juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2022-03-15','TERESA TAL Y COMO QUEDAMOS LE VAMOS A HACER UN REINTEGRO PERMANENTE DE 170 €/MES A PARTIR DE 04/2022, CON LA SIGUIENTE DISTRIBUCIÓN: 100 € PARA TUTELADO Y 70 € DE MANUTENCIÓN PARA SU PADRE. DISPONE DE SALDO SUFICIENTE, PERO ESOS 70 € EXTRAS AL MES HACEN QUE LOS INGRESOS SEAN IGUALES QUE LOS GASTOS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2022-03-15','Ana: Envío correo respuesta a Felisa Custodio, TS del CAMF-Alcuéscar: "Tras haberlo valorado en equipo, desde este Gabinete Técnico de la Comisión Tutelar de Adultos de Extremadura, no encontramos argumentos para denegar la solicitud de ISABEL DEBÓN CHENIQUE de salir con su “novio” por la localidad de Alcuéscar. Por tanto, siempre que no surjan incidencias y/o desde el centro valoréis que estas salidas producen algún tipo de malestar o perjuicio a Isabel, en cuyo caso agradeceríamos que nos lo comunicaseis, SE AUTORIZAN LAS SALIDAS DIARIAS de 2 horas de duración."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2022-03-11','Ana: Correo de Felisa Custodio, TS CAMF-Alcuéscar (trabajadora_social_alcuescar@imserso.es): "...un año casi después, la residente sigue insistiendo en salir al exterior con este señor. Llora por no poder hacerlo, le he propuesto salir a las excursiones que está organizando el centro, ir los viernes al mercadillo con el grupo que sale pero no quiere nada de ésto, con lo cual lleva un año sin salir del centro. Me plantea mi Directora (pongo copia del correo para ella) la posibilidad de dejarla salir con su "novio", dos horas u hora y media todos los días para que os de traslado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2022-03-15','TERESA A PETICION DE JOSE FLORENCIO ME PONGO EN CONTACTO CON MARI CARMEN LA TRABAJADORA SOCIAL DE BARCARRROTA 653887728 PARA AMPLIAR LA ZONFICACION PARA CENTRO SOLICITANDO ZAFRA Y LLERENA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-03-15','Ana: Llamo a Paula, Programa en C. Penitenciarios de Plena Inclusión (686 76 53 47), le enviaré un correo con respecto a Saturnino Miguel para valorar la derivación a su programa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-03-15','TERESA ARCHIVO RESOLUCON PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2022-03-15','TERESA ARCHIVO RESOLUCON PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-03-16','miguel, tras conversación con el jzdo nº1 Villanueva de la Serena, remito vía fax solicitud de abogado y procurador y suspensión del procedimiento hasta que sean nombrados dichos abogado y procurador.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-03-16','-email de ESM Ciudad Jardín Buenos días Amalia! Estamos en contacto con el primo, Jesús, es nuestro referente. Hemos hablado con Mercedes por teléfono, en la conversación, sí que la noto distante y que no quiere hablar, es lo que más detecto. En cuanto al 112, por protocolo se activa desde el Médico de AP, siempre se necesita una valoración clínica. Ya sabemos que no la podéis obligar. Estamos en contacto. Saludos,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-03-16','Ana: Solicito a Toni-Futuex y ésta me remite un correo con las notas de los seguimientos que hayan tenido lugar en los dos últimos meses, pues no nos han vuelto a remitir nada y el juicio es esta misma mañana. ······· En las mismas se detallan las últimas incidencias: el día 7 de marzo arrojó vajilla y otros objetos por la ventana del tercer piso en el que vive. Tuvo que intervenir la policía local. ······· Informan también de que Pilar Martín ha llamado a la educadora porque a su vez, ha recibido llamada del ayto. comunicando que ha arrojado ropa ardiendo por la ventana. *Desde el equipo lo único que hacen al respecto es solicitarle cita en el Serv. de Psiquiatría. ················· *Llamo a la Policía Local de CC (927629 055) y, tal y como me piden, solicito por fax (927 24 01 41) Informes de Actuaciones Policiales en el domicilio de Martín a fecha de 7/03/22 y cuantas otras intervenciones hayan llevado a cabo por incidencias similares.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-03-15','Ana: Llamada de José Manuel (627 788 797): expresa que el dinero del extra que se autorizó para ropa, se lo ha gastado en otra cosa y ahora sigue sin ropa y necesita ropa. *De momento no se le va a autorizar más dinero para ropa. Y la próxima vez, tendrán que enviar presupuesto previo de una tienda específica a la que se le abonará a posterior mediante transferencia bancaria. ····················· *A parte, ahora dice que quiere ingresar en la residencia de mayores de su barrio. *Le explico que aún no tiene edad para ello, que a partir de los 55 sería de forma excepcional, pero que él es muy joven para este tipo de recursos y que se sentiría fuera de lugar. Le recuerdo además que lo último que pidió era irse a la Casa de Misericordia de Alcuéscar. Sigue cambiando de parecer y eso no puede ser al a hora de solicitar los RR. ······· Dice que lo va a pensar bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-03-15','miguel, remito a la abogada el informe que me remite Ana Ts, y la abogada Carmen Lucas contesta: No tenía este informe, el Juzgado aún no va a pedir informes, ni siquiera he calificado. El tema me resulta un poco agobiante, porque no sé qué más puedo hacer por este Sr. la verdad. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-03-16','miguel, remito a la abogada escrito de Defensor del Pueblo solicitandonos información si en las diligencias se ha pedido a la letrada que solicite informe psiquiatrico de oficio Si se ha solicitado su traslado del centro a uno específico de carácter psiquiatrico. Le contesto a la abogada de cómo contestaremos: Buenos días Carmen, a nosotros también nos llegó un escrito pidiendo información y ahora este. Nuestra contestación irá en el siguiente sentido: 1.-El informe psiquiatrico que te remití ayer por favor aportalo en cuanto puedas. En dicho informe verás que el psiquiatra no hace mención de ingresarlo en otro lugar. 2.-En cuanto a lo que indica de si la Ctaex ha solicitado su traslado a un centro socio sanitario, le indicaremos que nosotros no somos quienes tomamos esas decisiones y que si leen el informe psiquiatrico que se aportará de enero, el psiquiatra no lo indica. Y por último que si quieren conocer el día a día de Saturnino tendrán que solicitar de oficio al juzgado informe de la trabajadora social del centro penitenciario, pues ésta se ha negado en mandarlo salvo que se lo soliciten de oficio. Como digo, la decisión de si hay o no que ingresar a una persona en centro corresponde en última instancia al juez, basándose en los informes periciales, en este caso del psiquiatra, que repito, no menciona que se ingrese en otro centro. Si llegada la sentencia el juez dictara una sentencia en ese sentido de ingresarlo en centro, tendría que verse en otro departamento del SEPAD como otro ciudadano más (listas de espera, comprobar si cumple el perfil adecuado de ingreso en el centro concreto que soliciten). Quedo a tu disposición para aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-03-16','miguel, inma de asesoria Cid y Villafaina me envía modelo 600 e indicaciones para hacer la transferencia para el pago del impuesto de sucesiones de la cuenta de la Caixa que apareció hace poco y estaba a nombre de la madre.Se lo envío a Alberto y Oscar para que hagan la transferencia y me envíen justificante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-03-16','miguel, hablo por telefono con la abogada y le reenvío el email que en enero envié al defensor del pueblo vía email cuando nos solicitaron información del procedimiento: Buenos días, con fecha de hoy 24-1-2022 ha llegado a esta Comisión Tutelar de Adultos por vía carta ordinaria el escrito adjunto del Defensor del Pueblo en relación al tutelado D. Saturnino Salgado Jimenez. Actualmente este tutelado (curatela representativa conforme la nueva ley 8/2021, 2 junio por la que se reforma la legislación civil y procesal para el apoyo a las personas con discapacidad en el ejercicio de su capacidad jurídica), se encuentra cumpliendo condena por el procedimiento arriba indicado y que se adjunta. El estado actual del procedimiento es el escrito de defensa que ha realizado su abogada y que también adjuntamos. En él se ha incorporado los informes médicos que ha logrado obtener esta Comisión Tutelar. Por otra parte se ha intentado obtener informe social del equipo de trabajadores sociales del Centro Penitenciario, ya que esta Comisión Tutelar no dispone de información para realizar el mismo, siendo la contestación de la trabajadora social del centro penitenciario “Te informo de que para que yo pueda realizar un informe social me lo tiene que pedir de oficio el Juzgado. De todas maneras creo que el informe social no sería lo más adecuado dado que yo en mi informe no haría constar las patologías que presenta el interno y ,que por otra parte desconozco, debido a que no soy la profesional indicada para eso y sí un médico, psiquiátra/psicólogo”. Se adjunta informes médicos que se remitieron a la abogada defensora Doña Carmen Lucas (mlucasduran@icac.es> c/ San Antón, 6 1º B, 10003 Cáceres Teléfonos y Fax: 927 226664 y 927226673, 627597037) , junto con la respuesta de la trabajadora social del Centro Penitenciario que obra en el email de debajo, y junto con los 3 escritos recibidos por la abogada, en el cual podrán comprobar que la supuesta víctima (hoy fallecida) dejó un hijo menor cuya protección quieren desde el juzgado la asuma la junta de Extremadura. Se adjunta también sentencia judicial y nombramiento a la Comisión Tutelar de Adultos. Entendemos que el equipo de salud mental de la Gerencia del Area de Salud de Cáceres, y en concreto la Dra Guendolina Andres Pereira, es quién tiene que dictaminar si ve necesario o no el traslado del tutelado a un centro adecuado para el cumplimiento del resto de la pena, tal como pide su hermano Tomás. No obstante, es necesario para el tratamiento de cualquier enfermo y por ende para su ingreso en un centro, que se encuentre desintoxicado. Desde esta Comisión Tutelar de Adultos no consta más información con lo que deberán ponerse en contacto con el Juzgado para cualquier otra cuestión, ya que desde esta Comisión se cumplirá, como no puede ser de otra manera, con la resolución judicial que se dicte. Quedamos a su disposición para cualquier otra aclaración. ********************************************* Preparo contestación a la nueva petición de información que nos vuelve a hacer el defensor del pueblo: donde se nos pide les informemos sobre dos cuestiones: 1.- Si, en las diligencias penales donde es imputado Don Saturnino Salgado Jiménez se ha pedido a la letrada que le asiste, que solicite informe psiquiátrico de oficio 2.-Si, en su caso, se ha solicitado su traslado del centro donde se halla preventivamente privado de libertad a uno específico de carácter psiquiátrico, más acorde con las enfermedades que parecen aquejarle. Y quedo con la abogada en que en cuanto lo tenga se lo enviaré. La abogada me insiste que en su escrito de defensa indicó que le dieran libertad provisional y que se le ingresara en centro adecuado (este segundo punto no lo veo en su escrito)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-03-10','Ana: Correo de Toni-Futuex con incidencias varias: José Manuel se ha gastado en tabaco y un reloj el dinero destinado a ropa. ······ El 9 de marzo no acudió al centro de salud para la analítica que tenía programada. *Se la reprogramaron para el 15 de marzo. ········ A posteriori se encontraba muy acatarrado y congestionado y no quería ir al centro de salud. Llamó al 112 y le dijeron que debía acudir al C. Salud para que le valoraran e hicieran PCR, pero también lo rechazó. ······ La educadora le explica: "... que no ha cumplido nada de lo acordado, otra vez, y que ahora se queda sin dinero para lo realmente necesario. Su respuesta es que no se lo demos a él y que se encuentra cansado y aburrido de todos los días igual. Que desea ingresar en una residencia de mayores ya que este mes de octubre cumple 55 años y con esa edad se puede solicitar, pues no quiere seguir en su casa solo. Que lo expongamos así a la comisión." ·············· En cuanto a la consulta de salud mental la educadora informa: "hemos podido contactar con trabajadora social de salud mental en Cáceres para solicitar que esta consulta fuera presencial, pero nos comentan que es imposible) Que se le ha comunicado a él, que, de seguir con las continuas llamadas y demandas, además de solicitar ingreso, terminaran por hacer derivación a sociosanitario, algo que José Manuel rechaza totalmente." ······*Guardo nota en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-03-14','Ana: Al correo de día 10 de la Maite, TS del C. Penitenciario - CC (trabajosocialcpcaceres@dgip.mir.es): "Buenos días, el interno de este Centro Penitenciario, Saturnino Miguel, solicita se le autorice la compra de un juego de cuerdas para la guitarra que valen, según refiere, unos 10 €. También solicita se le autorice la compra de un bloc de dibujo. Refiere que él tiene dinero en su cuenta de peculio para ello." ··············· *Desde la secc. ecca. se autoriza esta petición, comunicándoselo a la TS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-03-15','Ana: Correo de Fátima, Ed. Soc., Asociación Vera (educadorasocial@asociacionvera.com): "Buenas tardes. Adjunto informe de nueva incidencia de Adrián Ortigosa Fuentes ocurrida este fin de semana. Informar también de que hoy hemos acudido con el a revisión de Salud Mental con su psiquiatra, ésta a modificado medicación y tenemos nueva cita la semana que viene para seguir valorando. Estamos a la espera de informe de psiquiatría, ya que valora que los hechos ocurridos en los últimos meses son graves. Se adjunto también factura para reponer la ventana que ha roto Adrián. Una de las medidas es que éste pague, la ventana; para que valore el dinero se le descontará el 50 % de su paga semanal hasta saldar la deuda. Valoramos que en relación a las gafas que tuvo que pagar al compañero, no ha sufrido ningún tipo de consecuencia pues él al no ver el dinero considera que no le falta. Ana comentarte también que se va a informar a Maribel de todos los hechos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2022-03-16','Comunicar que la tutelada MªTeresa González Naranjo, es positivo en Covid 19. Se encuentra bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-03-16','Ana: Correo-respuesta al correo de ayer de Fátima, Asoc. Vera: "...Muchas gracias por informar de nuevo. A ver cómo pasa esta semana y qué estima la Psiquiatra la semana que viene. Cuando tengáis el informe, por favor, hacédnoslo llegar. En cuanto a la medida para que abone él la ventana, me parece muy bien el modo de proceder. Y estoy totalmente de acuerdo en que cada vez que haga algo, se “responsabilice” de alguna manera de lo ocurrido. También se le podría haber descontado semanalmente de su asignación, hasta abonar las gafas, sino la totalidad, al menos un buen tanto por cierto de la misma. Tenéis razón, podéis explicarle que a partir de ahora se procederá así. Ya me dirás también qué te dicen desde la sección de discapacidad." ··· "Por cierto, el resto de medidas indicadas en el informe también nos parecen muy bien" : Limpiar y arreglar los desperfectos de su habitación y "trabajos en beneficio del centro": pintar dos salas con el personal de mantenimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='CRESPO'and apellido2='PEREZ'),'2022-03-17','Ana: Ante el correo de ayer de Emilia, TS del CSS, : "Adjunto, el documento enviado por Eulogio. telf 619907231. la vivienda que tienen en común en la localidad de Castuera, la tienen alquilada, Eulogio refiere que Ángel Crespo esta empadronado en esta vivienda, con lo cual la persona que esta allí viviendo actualmente no puede acceder a la ayuda, propone Elogio cambiar el domicilio de empadronamiento de Ángel Crespo.", respondo: "Buenos días Emilia, ¿Qué tal? En principio, entiendo que no habría problema para empadronar a Ángel en el CSS. No obstante, antes de nada quería preguntarte cómo sigue Ángel y si el pronóstico es que continúe residiendo en vuestro centro. En cuanto al poder notarial que nos remites, no sé muy bien para qué nos lo envías, si es por algo en concreto, porfa, especifícanoslo. De todas formas, ya no tiene validez. Decae con la firmeza de la sentencia de incapacitación y nombramiento y con la aceptación del cargo de la CTAEX en este caso. De todas formas, pongo en copia a mi compañero Miguel y, junto con tu respuesta, determinamos lo oportuno de empadronarlo en vuestro centro. Por cierto, en tal caso, ya podréis enviarnos el modelo de solicitud de empadronamiento para ponerlo a la firma del D. Gerente. Un saludo y buena mañana. PD: Miguel, el poder está en el correo ayer de Emilia en el ctutelar@"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='CRESPO'and apellido2='PEREZ'),'2022-03-17','miguel, mi contestacion a Ana y Lourdes: Buenos días, no hay problema que cambie su empadronamiento. Los trámites de cambio entiendo que lo hará el centro (supongo que como con otros usuarios). ************************************* recibo email también de Lourdes: Buenos días compi, ayer llamaron explicando que el tutelado ANGEL CRESPO PEREZ, tiene un piso común con otras dos personas, el tutelado tiene el 50% y las otras dos personas el 25% cada uno de ellos, el nombre de uno es Eulogio, y el del otro no me lo dijeron. La cuestión es que quieren alquilar el piso, y para que a las personas alquiladas le den una ayuda, no se exactamente que, necesitan que el tutelado no esté empadronado en la vivienda, no sé si me puedes informar acerca de esto, El teléfono de contacto es 624634689. En cuanto al poder y aunque el mismo indica su validez es hasta que se pronuncie sobre el mismo la sentencia judicial, donde no se indica nada, por lo que debemos entender que no tiene validez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-03-16','Ana: REGISTRADA DE ENTRADA la Comunicación de Variación de Domicilio al INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-03-17','miguel, tras ver el expte con Tere, buscamos una asesoría que al tiempo tiene abogado en Monesterio que es el municipio más cercano a Calera de León Asesoria Rogalex-Abogados; Pablo Garrote, email 4179@icaba.com, teléfono 673-163200','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-03-17','miguel, envío email a Inma de del Cid y Villafaina: Buenos días, la transferencia nos ha confirmado el Santander que ya la ha hecho, pero les da problemas el enviarnos la justificación por lo que no puedo aportartela… ************************************** su respuesta:Buenos días, no hay problema he llamado a la oficina liquidadora de Fregenal y le sale ya el ingreso, así que hoy lo presento. No sé si podrás ir a liquidar el impuesto de esta forma…la Cuenta desde la que se ha abonado los 51.60€ es ES92 0049 0502 81 2490061018 que está a nombre de Jose Antonio Delgado Rodriguez. Mañana en cuanto tenga hecho el poder te lo envío.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-03-17','TERESA CONTACTA MIGUEL CON UNA ASESORIA DE MONESTERIO PARA QUE LE DEN PRESUPUSTO PARA LA GESTION DE LA HERENCIA Y LA VENTA DE LA VIVIENDA DE SU MADRE YA QUE HAY DOS PERSONAS INTERESADAS EN LA COMPRA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-03-17','Ana: Correo de Paula, TO CRR-Plas: "Buenos días Ana, te adjunto el documento que hemos firmado con Ceferino en relación al abono de la deuda y de su compromiso de cambio." ····· Guardo el documento en el expdte. digital y reenvío el correo a Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-03-17','Ana: Recibimos de la Secc. de apoyo y RR para la infancia y la familia de la Gerencia Territorial de CC, resolución de REVOCACIÓN de la declaración de desamparo y asunción de la tutela de Juan Carlos, así como el cierre y archivo del expte. de protección de menores, por haber alcanzado la mayoría de edad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-03-11','Ana: desde la Secc. de Acceso a RR. Discapacidad, me entregan la RESOLUCIÓN de plaza en Resid. de Apoyo Extenso (RAE) en el CAM Mª Jesús López Herrero de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-02-09','Ana: Correo de Fátima, Asociación Vera: "Adjunto informe social relativo a las dos incidencias de esta semana con ADRIAN ORTIGOSA FUENTES. Pongo en copia a la Educadora Social de nuestra entidad." ··········· Adrián ha agredido y roto las gafas a otro residente del centro. *Guardo documentos en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='NOGALES'and apellido2='MUÑOZ'),'2022-03-17','-Amalia : envio email a Alberto Buenas , he hablado con PNC , no se ha dado de baja la prestación (registrada correctamente mi opción por la PFHC) Van a pasar un cobro indebido de unos 2000€. Como no tiene dinero ahorrado para ese pago he pedido indicaciones para poder fraccionarlo . Para ello , cuando nos envíen ese pago no lo hacemos. Lo pasarán a S. Social y desde ahí nos pedirán que fraccionemos el pago. Has podido calcular el % que se hace de copago en el centro ?? Debe ser más del 75% , porque si no , no me cuadra que no haya ahorros y su cuenta esté en negativo. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MIRANDA'and apellido2='GODOY'),'2022-03-17','TERESA ENVIO A LA TESORERIA ESCRITO PARA QUE QUITEN A JOSE VICENTE COMO REPRESENTANTE LEGAL EN LA PRESTACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-03-17','TERESA Ha sido reconocida en consulta de psicología, donde confirman la necesidad y el visto bueno a dicho tratamiento en centro de Plena Inclusión de Cabeza del Buey. Siendo también valorada en consulta de terapia ocupacional, que observando la autonomía que Marta tiene, no ven quizás la necesidad de este tratamiento o apoyo específico, pero que ya se decidiría en reunión con el equipo. Por tanto, está a la espera de recibir la resolución en su domicilio, aunque podemos confirmar que tratamiento psicológico si tendrá. Demanda una cantidad de dinero extra para comprar ropa, pero por internet (tienda SHEIN) en torno a 70 euros, ya que envía por wasap fotos de la ropa que desea comprar. Le comentamos que compra por internet requiere uso de tarjeta, de la que no dispone. Pero insiste en la idea de querer comprar por este medio, ropa que dice necesita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-03-17','Ana: Conversación con manos libres entre Maite, jefa CTAEX, Maripaz - Psicóloga UHDAC, Dr. Daniel- Psiquiatra y yo. *A Juan Carlos han tenido que administrarle una medicación de rescate, está muy nervioso ante la incertidumbre de cuándo se va al centro. Necesitan que le digamos que que en una o dos semanas o a antes de que acabe el mes se marchará. *Le explicamos que no podemos decirle eso, pues no sabemos con seguridad cuándo podrá marcharse, la otra vez se le dijo así y como surgieron complicaciones no se ha cumplido, lo cuál le ha afectado negativamente. *Dado que no podemos decirle lo que nos piden, estiman que es mejor que no hablemos con él hoy. **Llamaremos cuando sepamos cuándo y a qué centro se irá.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-03-17','TERESA Acompañamiento a consulta de revisión de ginecología en centro de especialidades de Villanueva de la Serena programada presencial a las 12:20 Hr. La especialista, Romero Lozano, no da alta definitiva, pero no entrega ya cita de revisión, solo SI PRECISA NUEVA VALORACIÓN, remitir de nuevo a consulta desde su MAP, que debe llevar control. Se le realiza una ECO de control, todo dentro de la normalidad, recomendando continuar con EVRA sus parches mensuales recetados por planificación familiar en diciembre 2021. También en la consulta de revisión de endocrinología, 03 de febrero 2022, se le ha dado el alta por parte del especialista, encontrando sus valores de analítica en rango normal. Tiene cita programada para valorar tratamiento en CADEX el viernes 04 de marzo 2022 a las 11:15 HORAS, acompañamiento ya planificado por este equipo de apoyo social comunitario de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2022-03-14','Ana: Pongo para la firma del D. Gerente la solicitud de REVISIÓN PIA para solicitar plaza en PLACEAT.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-03-17','Ana: Al correo enviado a Toni-Futuex: "Buenas tardes Toni, ¿sabéis si acudió ayer a la analítica?? Ya me confirmas." ················ Toni responde: "Si, confirmamos que fue. Hoy ha ido otra vez, porque tiene mucha tos.. hasta ahora no se ha querido hacer prueba de covid. Demanda ultimamente que está muy aburrido, seria factible alomejor que le mandaran al crps?? no sabemos si ha estado anteriormente, desde luego desde que salió de la carcel y antes de irse a Badajoz no, el 29 tiene cita telefonica con psiquiatra, le insisteremos que lo plantee."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-03-18','Ana: Envío correo-respuesta a Toni: "Yo también lo desconozco, desde que estoy aquí trabajando al menos no y en el expte. tampoco hay nada al respecto. He consultado a las compañeras de las sección de salud mental y cuando puedan lo mirarán. Ya os diré cuando sepa algo. Lo que sí reitera, es lo que ya sabíamos, que debe derivarle el Psiquiatra, por lo que volver a recordárselo cuando habléis con él, porfa. Yo la semana que viene intentaré llamar a Pilar Martín, ESM y se lo comento también."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-03-16','Ana: Correo de Sonia, TS y Directora de Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, te escribo para informarte que Aaron sigue ingresado. Desde Salud Mental inician los trámites para solicitar la plaza en la UHDAC. Nos han solicitado informe social y psicológico, por lo que si no nos decís lo contrario los elaboramos y se los remitimos en estos días. Por otro lado, he estoy valorando si informar a su padre también de los trámites porque necesito hablar con él para poder actualizar datos y redactar el informe, qué te parece?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2022-03-18','Ana: Envío correo a Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net), "En relación al interés de FÉLIX FRANCO JIMÉNEZ en poder optar a una plaza de piso supervisado de mayores en lugar de un recurso residencial, a priori, dado los ingresos que tiene (las dos prestaciones) y los buenos ahorros, entiendo que no habría ningún problema de solicitar ingreso de forma privada en el piso de estas características que él mismo elija. Eso sí, en función del precio de éste, tendrá para más o menos años. Llegado el momento, y una vez elegido el recurso, haremos los trámites oportunos y si hay plaza en el mismo el traslado sería rápido."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-03-18','miguel, llega de Futuex email a Ana que me remite: 15/03/2022 Área Jurídica URGENTE (nueva notificación de sanción por denuncia): Durante la espera para la consulta de salud mental, tal y como se le había indicado el día anterior, la tutelada hace entrega de una carta sobre una notificación en referencia a una denuncia. La tutelada indica que le llegó la semana pasada, lo comunicó el lunes día 14, pero resulta extraño porque la fecha de salida marca el 28 de febrero. En dicha carta se le vuelve a notificar la sanción que debe pagar, asciende a 200€, por la denuncia que le interpuso la guardia civil de Cilleros el día de la discusión en el bar la Caña, por falta de respeto y desacato. En la misma, se especifica la posibilidad de reclamar, se tiene plazo de un mes para interponer recurso. Se adjunta, en documento a parte, toda la documentación facilitada por la tutelada. En cuanto a la conducta,está completamente cambiada, no presentandose las mismas queprecisamente le han llevado a acumular estas denuncias. Estatranquila, y bien. Se adjunta al email, ladocumentacion facilitada. Tambien la revision de grado dedependencia, denegado. *********************************** Reenvío a Alberto con copia a Ana para que lo abonen','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2022-03-18','miguel, llega email de Ana que me reenvía de Paula del CRR: Buenas tardes, me pongo en contacto con vosotros en relación a Felix Franco, tutelado vuestro y residente del Piso supervisado de Plasencia. Éste nos comunica que, deseando poder realizar la venta de su casa ha recibido a través de su familia la comunicación de que hay una persona interesada en ella. Así, informamos a Félix de la necesidad de trasladaros esta información y creemos que puede ser interesante facilitar a su familia vuestro correo para que contacten con vosotros y podáis valorar esta situación (tanto su pertinencia como los pasos en caso de que consideréis que es posible). Félix ha intentado contactar telefónicamente con vosotros, pero no lo ha logrado, por lo que intermedio para que os llegue la información y podáis devolverle la llamada cuando sea posible (Telf. de contacto Felix: 722363257). Así mismo, está interesado en poder optar a una plaza de piso supervisado de mayores en lugar de un recurso residencial cuando llegue el momento (su valoración de dependencia anticipaba un máximo de grado I). Le gustaría que valoráramos la posibilidad de buscar recursos privados, por las dificultades que ha observado de solicitar este tipo de recursos de forma pública. Esperamos vuestra respuesta y agradecemos vuestra intervención, un saludo. ****************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2022-03-18','Buenas , os comunico cambio: Fco. Javier Pinilla Baena , es baja de PFHC y causa alta en PNC Invalidez , misma cuantía pero con 14 pagas . Fecha efectos 01/04/2022. Seguimos..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2022-03-18','miguel, recibo email de Tere: Necesito que me digas el día que hay que ir a la notaria porque en función del día irán unos testigos u otros para poder facilitarte los nombres ***************************************************** mi contestacion: Buenos días, acabo de hablar con la notaria y para que pueda firmarse además de la documentación que enviaron, necesitamos se hagan con el original de lo siguiente: -Libro de Familia y si no lo tienen Certificado original del registro civil de Matrimonio de los padres -Certificado original de nacimiento de cada heredero emitido por el registro civil. Una vez lo tengamos podremos remitir todo a la notaria para que nos den cita de firma de la declaración de herederos. ***Datos de la notaria de Azuaga: Notaria de Jose Luis Perez Cardesa, (oficial Fran 924-890159; email: notariaazuaga@hotmail.com)***Tere intentará pedirlo directamente porque no tienen a nadie para facilitar esta documentacion','2');
