insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-03-18','-Amalia , email a TS de Conser en Olivenza Buenas , te he llamado varias veces pero tampoco consigo hablar contigo , hoy me dicen que estás de descanso , mejor por email . Acabo de solicitar traslado de la plaza sociosanitaria T3 a la R.M. Encinar de las Cruces en Don Benito porque es donde hay plazas . No tiene capacidad económica para quedarse en la actual , una pena. Ya he leído tu informe social . Un saludo . ------------------------------------------------------ GLORIA CABANILLAS VIÑUELA >GCABANILLAS@caseresidencial.es> Mié 16/03/2022 13:01 Buenos días Amalia En el centro de Olivenza, como ya sabrás, el dia 31 ya no tenemos plazas T3. David al estar tutelado por la Comisión no se si hay que solicitarle traslado a otro centro con su plaza T3 o solicitar piso tutelado. El manifiesta que no le gustaría irse, pero claro, no puede hacer frente al pago de forma privada. Ya me dices.','2');
