insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2022-03-21','De: CARMEN FRANCO ALVAREZ >carmen.franco@salud-juntaex.es> Enviado el: lunes, 14 de marzo de 2022 14:40 Para: Soraya Masa Moreno >soraya.masa@salud-juntaex.es>; Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: sobre Miguel Gamero Buenos días: Os pongo al día de un tema que me preocupa, últimamente tengo muchas informaciones sobre Miguel Gamero y su estado (antes era más notable su autoagresividad pero la tendencia a la heteroagresividad va en incremento). Esta observación la realiza también la médica somática que tiene una visión objetiva del tema porque lo conoce y lo trata en profundidad. Estamos reflejando en el libro de incidencias de la unidad todos estos incidentes por tener certeza escrita y hemos retomado la valoración a nivel intelectual y deterioro cognitivo que se acordó en la última subcomisión. (durante la pandemia las alteraciones conductuales de Miguel han sido menores, pero en el momento actual están disparadas) Hoy lo hemos traslado a UHB para valoración por agitación en psiquiatría, ya que como sabéis tampoco tenemos psiquiatra muchos días en la semana. Creo que sería buena idea ir programando alguna subcomisión como planteamos en la última. Intentaré comprobar cómo van los psicólogos con las pruebas y retomamos el tema. Solo deseaba que estuvierais al tanto de este tema. Un abrazo y buena semana','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2022-03-21','miguel, a la documentación que me entregó Tere(fotocopias), se lo reenvié el viernes a la notaria de Azuaga (Fran) ******************************************* Contestación de la notaria de Azuaga: Confírmame por favor que tienes los originales de los documentos que me has enviado. Yo voy a pedir la defunción del marido. Pásame, los datos de la persona que va a venir a firmar el requerimiento, y los dni de las herederas. ************************************************ Mi email a Tere: Buenos días, la notaria de azuaga me pide le remitamos los originales de lo que me envías…A ver cuáles puedes conseguir para decírselo a la notaria A ver si puedes conseguir los dni de los herederos.','1');
