insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-03-18','miguel, remito a Inma de Cid y Villafaina el poder para el procurador','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-03-21','miguel, me escribe la abogada de la familia pues tiene en la notaria de Don Benito preparada para que se firme la venta del inmueble en calle Malavé Nº 47 de Valle de la Serena (Badajoz). Tras hablar con Rafael de Notaría de Carlos Varela Donoso en Don Benito (C/ Groizard Nº 10- 1ºIzda. 06400.Don Benito), me comenta que tendremos que ir presencialmente porque hay una hipoteca de la vivienda que hay que dejar cancelada. Envío email a Pilar del Santander indicandole el número de cuenta al que hacer la transferencia. Remito email a Alberto y Oscar para su conocimiento ***************************************** Contestación de Pilar del Sch: Buenos dias estamos en contacto y le voy informando una vez tenga fecha de firma que posiblemente sea esta semana mi teléfono para cualquier cosa 669233009 . ***************************************************** envío email con la documentación a Rafael de la notaria: Buenos días Rafael, te adjunto los testimonios de incapacitación, nombramiento a la Comisión Tutelar de Adultos, junto a la Autorización para firmar la compraventa del tutelado por la Comisión, Don José Luis Murillo Horrillo. Dime si el notario lo veo correcto y cuándo sería la firma. Ya he remitido el número de cuenta a Pilar del Santander. *********************************** Contesto a Ana de Pablo sobre los trámites realizados. **************************************************** Me escribe Ana de Pablo: Muy bien, para esta operación los tres hermanos que residen en Gipuzkoa van a otorgar un poder para la firma de la venta a Dña. Mª del Pilar Fernández Carrasco (agente del Santander) y enviarlo a la Notaría de Don Benito. Lo ha exigido la entidad bancaria Santander. ************************************************* mi contestación: Perfecto. Quedo pendiente que me avise la notaria de si está todo correcto en cuyo caso se firmaría el día que nos indiquen. Un único asunto a tratar es el dinero del contrato de arras de 6.000€, entendemos que hasta que no terminen los trámites de plusvalía y demás gastos no se repartirá la parte que a cada uno corresponda, es así? ********************************************** Contestación de Ana de Pablo: Efectivamente, haré la liquidación definitiva cuando todo termine. Después de esta operación se va a vender la finca de la viña (la número 3 del inventario de la herencia) por 59.000€, a otro comprador. Cuando se escriture esa venta, los tres hermanos proponen vender su parte de las fincas números 4,5,6 y 7 (que son fincas rústicas sin edificación) a su hermano José Luis, si les parece bien aprobarlo así a la Comisión Tutelar. En la Notaría de Azkoitia la Sra. Notaria nos dijo que era posible mediante escritura de compraventa por el hermano tutelado del porcentaje de titularidad de sus tres hermanos. Ya me dirá si están dispuestos a realizar esta última propuesta; se haría la venta desde la Notaría de Azkoitia, con la aprobación de la Junta y firma por ustedes desde la Notaría de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-03-21','miguel, email de Ana de Pablo: le comunico que se va a proceder a la escrituración de la venta de la finca sita en calle Malavé Nº 47 de Valle de la Serena (Badajoz) en la Notaría de Carlos Varela Donoso en Don Benito (C/ Groizard Nº 10- 1ºIzda. 06400.Don Benito) el contacto es: RAFAEL Tf: 924810202. Dirección de correo electrónico: rafael@notariadonbenito.com D. Rafael necesita que usted contacte con él para el envío de la documentación que acredite la tutela por parte de la Comisión Tutelar de Adultos de la Junta de Extremadura y del representante que vaya a firmar la venta, así como el auto de autorización de la venta por el precio de 45.000€. No nos han dado fecha de firma, pero, teniendo en cuenta que el banco Santander subió los datos a la plataforma el pasado jueves, día 17, son diez días para hacerlo. Le agradecería que se ponga en contacto con D. Rafael. Esta venta se ha demorado porque el comprador D. Julio Rodríguez Godoy (y su esposa Dña. Isabel María González Godoy) no conseguían el préstamo bancario que finalmente el banco Santander les ha concedido (escrituran el préstamo y la compraventa). Por otra parte, la gestora del banco Santander, me pide que usted facilite el número de cuenta a donde hacer la transferencia de la parte correspondiente a José Luis Murillo Horrillo: precio de venta = 45.000€ entrega a la firma del contrato de arras = 6.000€ entrega a la firma de escritura =39.000€ : 4 hermanos = 9.750€ a cada uno. Los datos de la gestora son: Maria del Pilar Fernández Carrasco, NIF 34769737Q y domicilio en Alonso Martín Nº 7-2C, Don Benito (06400. Badajoz) Teléfono: 669233009. Dirección de correo electrónico:mariapilfernandez@agentes.bancosantander.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-03-21','Ana: Registrada de ENTRADA la Comunicación a Dependencia para recordar el DOMICILIO A EFECTOS DE COMUNICACIONES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-03-21','Ana: Envío correo a Toni-Futuex: "Procedo a realizaros una nueva DERIVACIÓN: JUAN JOSÉ GONZÁLEZ CARRERO Es una tutela, aceptada por la CTAEX a finales del año pasado. Juan José es paciente de Salud Mental. Su psiquiatra de referencia es el Dr. Jiménez Cano. La última vez que acudió a consulta fue el 15/11. A las tres citas anteriores no se presentó. En el informe solicitado sólo refiere que acudió sólo y el tratamiento que hace. Según el dictamen técnico del CADEX presente Trastorno Mental por Trastorno Bipolar (Grado de Discapacidad reconocido: 65%). Según informe de Psiquiatría está diagnosticado desde la adolescencia con múltiples ingresos desde entonces tanto en UHB y UME. Perceptor de PNC. Percibe otro ingreso del SEPAD, creemos que por la “Ayuda en entorno familiar”, que no se pasa a la madre (pendiente de confirmar). **Lo ideal sería cambiarlo por la ayuda a domicilio. Según conversación mantenida el pasado viernes con la Trabajadora Social del IMAS, Laura Domínguez, actualmente Juan José está estable. Anteriormente no tenía expediente en abierto en los SSASB. Hasta el momento. Ha rechazado el Servicio de Ayuda a Domicilio. Reside sólo en Cáceres, en domicilio familiar, en una vivienda de protección social propiedad de su madre, Josefa Carreras, con la que convivía hasta hace unos meses, cuando se vio obligada a abandonar a marcharse del domicilio por graves conflictos con Juan José y una orden de alejamiento que él tiene hacia ella. *La madre, a pesar de ello, se sigue preocupando por él e intenta ayudar en las medidas de sus posibilidades. *Juan José no abona nada por los suministros ni por la vivienda en sí. Su madre corre con todos los gastos, pero su situación económica también es delicada, por lo que necesitaríamos que se estimara un presupuesto aproximado para hacer una transferencia a Josefa y que él lo sepa. También será necesario establecer una asignación semanal, pues se gasta toda la pensión. Según su madre necesitaría acudir al podólogo y al dentista. Es necesario comenzar con los seguimientos, además de para establecer el presupuesto, para intentar adherencia a las consultas de seguimiento en ESM y para los otros tratamientos que pueda necesitar, como los que indica la madre. *Importante trabajar también con él su situación ocupacional (asiste puntualmente a la Universidad, no tengo muy claro a qué. Mantener esto y buscar alguna otra actividad) y la aceptación del SAD. *Valorar también la opción de catering o asistencia al comedor social. Considero conveniente, que al menos en las primeras visitas, vayan dos compañeras, Educadora asignada y Trabajadora Social." ········ Envío otro correo a Toni con los datos de contacto de Juan José y el teléfono de su madre. Y añado: "Aprovecho también para confirmarte que está valorado con Grado II de Dependencia y tiene aprobado PRESTACION ECONOMICA PARA CUIDADOS EN EL ENTORNO FAMILIAR Y APOYO A CUIDADORES NO PROFESIONALES. *Me encargo de esta cuestión, voy a comunicarlo a Dependencia, para que se la den de baja por no reunir los requisitos en la actualidad." ·································································································································································································· Cumplimento, pongo para firma y después para REGISTRO de ENTRADA, la Comunicación de Variaciones en la circunstancias: Ya no reúne requisitos para percibir la prestación económica por cuidados en el entorno familiar. *Comunico también la dirección a efectos de comunicaciones. ································································································································································································· Tras hablar con Pilar Martín, TS ESM (54612), me remite correo: "te informo de la próxima cita con enfermería para el día 25 del mes en curso a las 9,40. Enfermera- K. Elisabeth Viljanen." ························· Escribo de nuevo a Toni-Futuex: "Te reenvío correo de Pilar Martín con la próxima cita de enfermería de Juan José Glez. Carrero. En este caso no creo que podáis acompañar ni hacer nada al respecto por l precitado, pero sí hacer seguimiento de las citas unas vez comencéis a visitarle. Pediros también que le solicitéis nueva cita de seguimiento de Psiquiatría, pues me comenta Pilar Martín que no hay ninguna nueva programada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='NOGALES'and apellido2='MUÑOZ'),'2022-03-21','REUNIÓN 2022/03/21 AMALIA/ALBERTO X ERROR DE LA SEGURIDAD SOCIAL HAY UN COBRO INDEBIDO DE PNC X IMPORTE APROX. DE 2.400 €. SALVO ERROR EL CALCULO DERIVA DE LO SIGUIENTE: COBRA PFHC DESDE 01/10/21 SIENDO EL PRIMER PAGO X 399,20 €/MES (417,70 € PARA AÑOS 2022) EL 28/10/2021 COBRA PN ORFANDAD DESDE 02/11/201 X IMPORTE DE 2018,80 € X 14. SIENDO PRIMER PAGO 04/04/2021 DE 632,40 (CON ATRASOS) PERIODO INCOMPATIBILIDAD DE PNC CON PN ORFANDAD: DESDE OCTUBRE 2021 HASTA FEBRERO 2022 (AMALIA CONFIRMA QUE A PARTIR DE MARZO 2022 NO LE VOLVERAN A PASAR): IMPORTE 2.454 € QUE LE RECLAMARAN DE PNC. OSCAR: HAY QUE HABLAR CON CENTRO Y SOLICITAR DEVOLUCIÓN 2.454 € QUE HAN COBRADO X LA PLAZA DE FORMA INDEBIDA (YA QUE DERIVA DE INGRESOS INDEBIDOS QUE VAMOS A DEVOLVER A PNC) X OTRA PARTE NOS ENCONTRAMOS CON QUE CENTRO "INSTITUTO SECULAR HOGAR DE NAZARET" O CENTRO Nª SRA DE LA LUZ DE BADAJOZ: ESTÁ COBRANDO DE FORMA IRREGULAR LA PLAZA...BÁSICAMENTE SE APROPIA DEL 100 % DE TODOS LOS INGRESOS (INCLUIDOS LOS COBRADOS INDEBIDOS DE PNC): ACTUACIONES PENDIENTES DE OK AREA SOCIAL Y ECO: SOLICITAR AL CENTRO "AMISTOSAMENTE" DEVOLUCIÓN 2.454 € (CUANDO RESOLUCIÓN LE LLEGUE A AMALIA) SOMOS CONSCIENTES DE QUE ADEMÁS HAN COBRADO EL 100 % DEL IMPORTE DE LAS PENSIONES, CUANDO AMALIA LES INDICÓ QUE ÚNICAMENTE PODIAN COBRAR EL 75 %: ESTE PERIODO NO SE VA A RECLAMAR. OJO: ESE 25 % QUE NO VAMOS A RECLAMAR, HAY QUE TENERLO EN CUENTA EN EL MOMENTO EN QUE SE TOMEN DECISIONES SOBRE LA DEUDA DE 11.000 € QUE SE TIENE CON ESTE CENTRO EN RELACIÓN CON ACTUACIÓN MENORES. A PARTIR DE MARZO/ABRIL 2022: TENEMOS QUE ASEGURAR QUE ÚNICAMENTE SE ABONA EL 75 % DE LAS PENSIONES EXCLUIDAS LAS PAGAS EXTRAS: PFHC: 417,4 PNORF: 220,7 TOTAL: 638,4 X 75%= 478,80 €/MES. OSCAR: HABLAMOS "AMISTOSAMENTE" CON CENTRO Y LE INDICAMOS QUE A PARTIR DE MARZO/ABRIL ÚNICAMENTE PASARÁN 478,80 €/MES O, SI LO PREFIEREN ABONAMOS A TRAVÉS DE TRANSFERENCIA PERMANENTE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2022-03-21','-Amalia : llama por tf. él y la mujer . Ha robado 70€ de un gimnasio y quiere que le hagamos un extra para devolverlo. Denegado , lo hablo con Oscar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2022-03-21','miguel, recibo llamada del notario de los Santos de Maimona Don Carlos Duro quién me insiste que cree que habrá diferencia entre lo indicado en la aceptación de la herencia y la autorización de venta judicial en cuanto a las cuotas de participación. ****************************************************** localizo dicha aceptación de venta judicial y se la remito por email a la notaria para que el notario la vea: Buenos días, este email es para el notario Don Carlos. Si tras ver esta aceptación de herencia le quedan dudas sobre la cuota de participación, entonces tendríamos que ponerle en contacto con el abogado de ambos procedimientos: aceptación de herencia y autorización de venta. Quedo pendiente de vuestra respuesta al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-03-21','Ana: Me comunica Pilar Martín, ESM (54612) que hoy mismo han registrado de ENTRADA (Nº Registro: 202270400010448) a la Derivación a CRR. *Sólo han solicitado el de CC. ·············· Doroteo también tiene concedida la Prestación Ecca. para cuidados en el entorno familiar, pero lo percibe la madre en su cuenta.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2022-03-21','-Amalia : llama por tf. él y la mujer . Ha robado 70€ de un gimnasio y quiere que le hagamos un extra para devolverlo. Denegado , lo hablo con Oscar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='NOGALES'and apellido2='MUÑOZ'),'2022-03-21','-Oscar_ He hablado con el Centro. Van a cargar en cuenta el 75% de las pensiones que le corresponden. En cuanto a la deuda que va a tener, entiende que ha sido un cobro indebido por su parte y que volveremos a hablar cuando llegue la resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-03-21','Ana: Me comunica Pilar Martín, ESM (54612) que hoy mismo han registrado de ENTRADA (Nº Registro: 202270400010448) a la Derivación a CRR. *Sólo han solicitado CC. ··············· Percibe 173,80 € de Prestación Ecca. por cuidados en el Entorno Familiar por Dependencia, se lo ingresan en la cuenta de la madre (la misma en que venía percibiendo ella la pensión de Doroteo).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2022-03-21','Ana: Envío correo a Carmen Gía. Martín - EVD Plas. (carmen.garciamarti@salud-juntaex.es) y Sara, TS de la Res. Banium Residencial (TrabajadoraSocialBanium@hotmail.com) : "Buenos días Carmen y Sara, Disculpad la demora. Por fin he podido reunirme con Alberto, Jefe sección económica y con Maite, Jefa Secc. Social. Confirmaros que se ha decidido que CONCEPCIÓN BARBERO SÁNCHEZ, se quede en la Residencia en la que está y solicitar la Prestación Ecca. Vinculada al Servicio. Consideramos que es la mejor opción para ella, así que mientras pueda permitírselo así se hará. Si fuera necesario llegado el momento se solicitaría el cambio de recurso. Carmen, cuando puedas, envíame la nueva Aceptación PIA. Ante cualquier otra cuestión, no dudéis en poneros en contacto. Un saludo y buena tarde a las dos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2022-03-22','miguel, en relación a la petición de la hija de que se le entreguen 10.000€, preparo borrador para el juzgado y remito email a Amalia, Alberto y Oscar: Buenos días, en relación al tutelado arriba indicado he preparado este borrador del que necesito varias cosas: 1.-Amalia: centro en el que actualmente reside, centro puente real? Lo trasladaron desde el CRR de Cáceres? No tenemos un informe más actual? 2.-Parte económica: Necesito saber exactamente qué ingresos y gastos mensuales tiene. También necesitaré un pantallazo del saldo de la cuenta a fecha actual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2022-03-22','Ana: Subo al portafirmas digital la Autorización de sujeción mecánica por indicación médica (barandilla de cama), remitida por la Residencia Balcón de Extremadura (balconextremadura@grupociudadjardin.com) al ctutelar@. ····························· Remito la Autorización firmada digitalmente a la Res. Balcón de Extremadura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2022-03-22','miguel, envío email a Alberto y Oscar: Buenos días, se va a proceder a la venta de un inmueble de esta tutelada, por lo que necesitaría me dijerais si desde la parte económica tenéis algo en contra de que se le abone al otro titular (su hermano Pedro...está al 50%) los gastos que justifica con las facturas que se adjuntan. Dichos gastos se descontarían del precio de venta. Decidmelo lo antes posible ya que se quiere firmar ya.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2022-03-21','Ana: Correo de Cristina, Psicóloga CRR (crr@grupociudadjardin.com): "Informar sobre el estado de Antonia Canelada del Río. Estos últimos días comienza a manifestar dificultades a lo hora de cumplimentar el tratamiento de oxigenoterapia pautado. No siguiendo las indicaciones médicas ni del equipo de profesionales del CRR. Seguiremos interviniendo para su uso y mantenimiento de su estado médico. Iremos informando de la situación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-03-21','Ana: Correo de Toni-Futuex: "...aunque estamos para ampliar la informacion, ya que la compañera iba a ir a Navas..al parecer Felisi (Felipe Teomiro) ha tenido problemas, se intuyen que graves con Jesus, no sabemos si ha existido violencia, (pero no seria de extrañar, psicologica seguro) un sobrino estaba asesorandola, para cambiar la cerradura, y no sabemos si incluso ha denunciado, hasta que vayamos para allá y ampliemos la info. En cuanto tengamos la nota te lo paso, a ver si conseguimos ordenar un poco la situacion."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2022-03-22','-Amalia : Registro solicitud de traslado de la RM. Puente Real a Domus Vi en Badajoz pq dejan de tener plazas T2.','2');
