insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-03-22','TERESA HABLO CON TONI ADISER PUES ME COMENTA QUE JESUS HA REÑIDO CON LA MADRE Y YA NO VIVE CON ELLA. AITOR PREGUNTA QUE SI VA A PODER IR AL DOMICLIO YA QUE ES JESUS QUIEN FIRMA COMO RESPONSABLE EN LA ULTIMA VISITA HA VENIDO SIN TOMAR LA MEDICACION,ALTERADO CON LA MISMA ROPA.... VAMOS A AUTIRZAR LA SALIDA EN SEMANA SANTA DE JUEVES A DOMINGO Y EN FUNICON A COMO VUELVA VALORAREMOS LAS SIGUENTES SALIDAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2022-03-22','TERESA TELEFONOS FAMILIARES Jesús (685 031 479) ANTONIA MANUELA 643 790 946','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2022-03-22','Ana: Cumplimento la Comunicación de Modificación de Datos Bancarios al INSS y la pongo para la firma del D. Gerente. ··············· Lo pongo para REGISTRO DE ENTRADA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-03-22','miguel, recibo email de Carmen Tello: Buenos días Miguel, adjunto te envio documento emitido por la Agencia Tributaria en el que figura que la deuda que te están reclamando está pagada, de todas formas, como ya te comenté, desde diciembre Felipe no tiene relación con Fernando Bravo ya que es la empresa la que factura, dime cómo realizaríais el pago de la factura de Febrero En espera de tu respuesta, recibe un atento saludo ************************************************ Remito email a Alberto y Oscar: En relación al tutelado Felipe Rodriguez Solis hay que reactivar el pago permanente de ayuda a domicilio. Paso a comunicar a AEAT la reactivación del pago debido a que justifica le empresa que ya está al día de la deuda, además de que no deberíamos haberlo interrumpido porque la deuda es con otra sociedad perteneciente a la misma empresa (nuestras facturas no son a nombre de Fernando Bravo, quitando las facturas de octubre y noviembre, que se adjuntaron a la contestación a AEAT. Por tanto el deudor de AEAT no tiene relación con la empresa a la que nosotros pagamos, es decir a la beneficiaria de nuestros pagos, que es Servicios Asistenciales FBC SLU, y a la que hay que hacer los abonos que se venían haciendo con carácter permanente, y cuya reactivación deberá incluir este mes de marzo (puesto que AEAT no nos llegó a contestar y por tanto a AEAT no llegamos a abonarles nada…) Cualquier duda me decis. Procedo a comunicarlo a AEAT.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-03-22','Ana: Toni-Futuex, me comunica que Doroteo ayer, en consulta con Pilar Martín - ESM, en la que estuvo Gloria, Ed., acompañándole, se negó rotundamente a acudir a ningún otro centro que no sea el de Cáceres. ··································································································································· Envío correo a Miguel, Asesor Jurídico: "Te paso el número de Carmen, hermana de Doroteo Díaz Cerro: 669 86 41 67 , por si te puede facilitar información sobre el fallecimiento del tío para ver si te puede aclarar algo con respecto a la herencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-03-21','Ana: Maite, Jefa secc. CTAEX, me comunica que desde la Secc. de Acceso a RR de Discapacidad, le informan que Brahim, aún no ha ingresado en el CAMP-Plas. porque hay un brote de Covid.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2022-03-22','Ana: Envío correo a David Barea - PNC Delegación Provincial de Málaga (david.barea@juntadeandalucia.es): "Buenos días David, En relación a COSTI ALEXANDRU RIZEA, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura, me pongo en contacto contigo para preguntar cuándo le van a ingresar las mensualidades impagadas ya reclamadas a fecha de 4/02/2022, pues tiene una deuda contraída con el centro en que reside por no poder abonar el coste de la plaza y desde dicho centro vuelven a preguntarme al respecto. Agradecería me informes cuando puedas. Gracias y un saludo." ···························· Respuesta de David: "En relación a la consulta efectuada sobre el abono de atrasos del beneficiario de PNC D. COSTI ALEXANDRU RIZEA, NIE. Y1090272V, le comunico que el abono esta previsto para la presente nomina de marzo 2022." ················ Se lo comunico por mail a María, TS Autismo Sur. ································································································································· Llamo a la Oficina de Extranjería de Ba, para hacer una consulta (924 97 95 03 / 924 97 94 06), pero no obtengo respuesta. ····················· Llamo a la oficina de extranjería de Málaga (952 98 04 60): me informan que Costi podría solicitar el Certificado de Residencia Permanente de Ciudadano de la UE, este trámite se realiza en la Policía Nacional. ·············· En cuanto a los trámites para la adquisición de la Nacionalidad Española, se realizan ya todos online, siendo el responsable el Registro Civil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2022-03-22','miguel, llega desde Gerencia (Alicia) complementaria del 2018 que remito a Alberto, Oscar y Amalia para que la abonen','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2022-03-22','miguel, recibo email de la empresa que presta servicio a domicilio(Carmen Tello):Buenos días Miguel, adjunto te envio documento emitido por la Agencia Tributaria en el que figura que la deuda que te están reclamando está pagada, de todas formas, como ya te comenté, desde diciembre Felipe no tiene relación con Fernando Bravo ya que es la empresa la que factura, dime cómo realizaríais el pago de la factura de Febrero En espera de tu respuesta ************************************************** Remito email a Alberto y Oscar: En relación al tutelado Felipe Rodriguez Solis hay que reactivar el pago permanente de ayuda a domicilio. Paso a comunicar a AEAT la reactivación del pago debido a que justifica le empresa que ya está al día de la deuda, además de que no deberíamos haberlo interrumpido porque la deuda es con otra sociedad perteneciente a la misma empresa (nuestras facturas no son a nombre de Fernando Bravo, quitando las facturas de octubre y noviembre, que se adjuntaron a la contestación a AEAT. Por tanto el deudor de AEAT no tiene relación con la empresa a la que nosotros pagamos, es decir a la beneficiaria de nuestros pagos, que es Servicios Asistenciales FBC SLU, y a la que hay que hacer los abonos que se venían haciendo con carácter permanente, y cuya reactivación deberá incluir este mes de marzo (puesto que AEAT no nos llegó a contestar y por tanto a AEAT no llegamos a abonarles nada…) Cualquier duda me decis. Procedo a comunicarlo a AEAT.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2022-03-23','miguel, envío contestación a Carmen Tello: Buenos días, ya hemos procedido a comunicar a AEAT la reanudación de los pagos. Mi compañero Oscar (de la parte económica) se pondrá contigo en contacto para el abono de lo pendiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-03-22','Ana: correo de Emilia Almodóvar, CSS-Pla.: "Informar que Murillo Horrillo José Luis, paciente de sociosanitario de Plasencia, unidad de larga estancia en la unidad de cronicos. será ingresado en el día de hoy en el hospital Virgen del Puerto de Plasencia a causa de una hemorragia nasal continuada. Cualquier modificación será informada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-03-11','citación para el 3-5-22 DPA 230/21 del Jzdo nº6 de Cáceres','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2022-03-23','Ana: Correo de ayer de Gema Sánchez, Coordinadora de la RR.MM. Malpartida de Cáceres - Grupo Nexus, al ctutelar@: "El motivo de mi correo es en relación a nuestro residente León Leal Perez Olague tutorizado por ustedes. En reunión mantenida esta mañana con fiscalía de Cáceres nos ha pedido una copia de la sentencia de León. Actualmente no disponemos de copia en su expediente. Por favor, nos pueden facilitar ustedes una copia?" ·················· Llamo a Gema (670 381 292) en relación a dicha solicitud. Me informa que desde Fiscalía les están haciendo visitas informativas en los centros, en relación a los derechos de las personas mayores (control de medidas de sujeción mecánica, etc). Le preguntaron cuantas personas "tuteladas" tenía y le pidieron la sentencia. *Le informaron también a groso modo de los cambios que supone la Ley 8/21. ····················· Envío a Gema (gsanchez@nexusintegral.com) el Testimonio del Auto de remoción, nombramiento y aceptación del cargo de Tutor. ·························· *Gema me informa que León está bien, ha estado una temporada un poco más nervioso porque su compañero de habitación comenzó con deterioro degenerativo y a él le afectan muchos los cambios, pero ya lo lleva mejor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2022-03-23','Ana: REGISTRADA DE ENTRADA la Comunicación de Modificación de Datos Bancarios al INSS.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2022-03-23','Ana: REGISTRADA DE ENTRADA la Comunicación de Modificación de Datos Bancarios al INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2022-03-23','-Amalia : email de centro penitenciario y mi respuesta. Buenas tardes Amalia, informaros que Rafael Cacho García, con DNI Nº: 09191860W, ha reingresado en centro penitenciario de Badajoz, el pasado 11/03/2022. Un saludo Trabajadora Social Secretaría General de Instituciones Penitenciarias Centro Penitenciario de Badajoz. C/Ctra. Olivenza, Km 7.3; 06011, Badajoz. Telf. 924 28 91 17 Fax: 924 28 91 07 emilia.TS.39570@dgip.mir.es _______________________________________ Buenas , madre mía , estaba en paradero desconocido . Podéis informarnos de la sentencia condenatoria ?? cuánto tiempo pasará en ese centro ? este chico no tiene ningún tipo de prestación porque tampoco tiene reconocido grado discapacidad. Se lo he pedido en varias ocasiones , pero en el CADEX hay lista de espera de dos años y cuando lo llaman para la cita ya ha salido de centro penitenciario o lo han trasladado a otra comunidad y no hay forma de que acuda a la cita . Lo intentamos de nuevo?? Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2022-03-23','Ana: Llamada del Padre de Consuelo (643 653 824), me comunica que su hija le ha verbalizado varias veces que un compañero del CRR, Juan Mario, le ofrece porros y ha fumado varias veces. ················· Llamo a Cristina, CRR (927 83 02 10): confirma el problema que tienen con Juan Mario, con el que Consuelo mantiene una relación sentimental. **Habitualmente suelen reconducirla bien. ·········· *Por otra parte, me comunica que Consuelo de nuevo quiere irse del CRR, se plantean a un C.D. cercano a su localidad para estar más cerca de su familia, pues da perfil de Discapacidad, pero por otra parte ella en este tipo de centros se siente fuera de lugar. ················ Nos seguirán informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2022-03-23','Ana: Conversación telefónica con Amor, TS ASPACE, Santi sigue bien, sin cambios significativos. *Han encontrado un tapicero de una localidad cercana, que va a hacerle unos chalecos de piel, esperan conseguir que deje de comerse la camisetas y otras prendas de vestir al llevar este encima.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-03-24','Ana: Llamo a Amor, TS ASPACE, en relación a los trámites de Extranjería que dejamos pendientes. (*Brahim cumple requisitos para solicitar la RESIDENCIA DE LARGA DURACIÓN, dado el cambio en la normativa del pasado 2021: >>Residentes que al llegar a la mayoría de edad hayan estado bajo la tutela de una entidad pública española durante los 5 años inmediatamente anteriores). Dice que no ha obtenido respuesta a la consulta que realizó en la oficina de extranjería. Puesto que pronto se producirá el traslado de centro, considera que lo mejor es que lo retome la compañera del CAMP. *Se lo comunicará llegado el momento. ······································································································································ Llamo a la oficina de extranjería de CC ( Cita previa: 927 749 083 // 927 749 151 // Consultas: 927 74 90 88): Brahim tiene concedida la Larga Duración (Efectos desde 2018 a 2023), pero existe un problema al no tener en vigor su Documento de Identidad. *Hay una RESOLUCIÓN DENEGATORIA del expediente solicitado a fecha de 25/06/21, que en la CTAEX no hemos recibido. En principio "debe recogerla o descargarla con su Cdo. Digital José Vicente Granado". Al explicarle que es un cargo político y cómo funciona la CTAEX, me da la opción de solicitar por escrito una copia de dicha resolución alegando motivos por no haberla recibido. Hay que enviarlo a la Oficina de Extranjería, nº Registro: EA0040566.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-03-23','1 - Ana: Llamo a Amor, TS ASPACE, en relación a los trámites de Extranjería que dejamos pendientes. (*Brahim cumple requisitos para solicitar la RESIDENCIA DE LARGA DURACIÓN, dado el cambio en la normativa del pasado 2021: "Residentes que al llegar a la mayoría de edad hayan estado bajo la tutela de una entidad pública española durante los 5 años inmediatamente anteriores"). Dice que no ha obtenido respuesta a la consulta que realizó en la oficina de extranjería. Puesto que pronto se producirá el traslado de centro, considera que lo mejor es que lo retome la compañera del CAMP. *Se lo comunicará llegado el momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-03-23','Ana: Llamo a Cristina, CRR (927 83 02 10 / 678 37 87 33): Nos confirma la información sobre consumo comunicada por el padre de Consuelo Nevado. Juan Mario consume a diario alcohol además del consumo de porros. Hace tiempo aceptó acudir al CEDEX, pero después dejó de acudir. *No tiene conciencia real de su adicción ni de la consecuencias que tiene el consumo sobre su salud. *En cuanto al a Psiquiatra de Referencia es la Dra. Rubio. Ésta no le da demasiada importancia al consumo, pues no está presentando otras alteraciones de conducta. *Posiblemente, debido al cambio de dirección del RR. les cambien también la Psiquiatra. ········ Puesto que ya no saben qué más hacer, pues la sanción de expulsión una temporada en este caso no es viable, están redactando un informe que remitirán a la Secc. de Acceso a RR de Salud Mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-02-23','Ana: Llamo a Amor, TS ASPACE, en relación a los trámites de Extranjería que dejamos pendientes. (*Brahim cumple requisitos para solicitar la RESIDENCIA DE LARGA DURACIÓN, dado el cambio en la normativa del pasado 2021: >>Residentes que al llegar a la mayoría de edad hayan estado bajo la tutela de una entidad pública española durante los 5 años inmediatamente anteriores). Dice que no ha obtenido respuesta a la consulta que realizó en la oficina de extranjería. Puesto que pronto se producirá el traslado de centro, considera que lo mejor es que lo retome la compañera del CAMP. *Se lo comunicará llegado el momento. ······································································································································ Llamo a la oficina de extranjería de CC ( Cita previa: 927 749 083 // 927 749 151 // Consultas: 927 74 90 88): Brahim tiene concedida la Larga Duración (Efectos desde 2018 a 2023), pero existe un problema al no tener en vigor su Documento de Identidad. *Hay una RESOLUCIÓN DENEGATORIA del expediente solicitado a fecha de 25/06/21, que en la CTAEX no hemos recibido. En principio "debe recogerla o descargarla con su Certificado Digital José Vicente Granado". Al explicarle que es un cargo político y cómo funciona la CTAEX, me da la opción de solicitar por escrito una copia de dicha resolución alegando motivos por no haberla recibido. Hay que enviarlo a la Oficina de Extranjería, nº Registro: EA0040566.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2022-03-23','Maite. He hablado con la trabajadora social de la residencia de Deleitosa ( Guadalupe) para aclarar el tema de la póliza de deceso. Le he explicado que debido a su edad no se hace, que llegado el momento tienen que enviarnos un presupuesto y desde aquí se autoriza. Respecto a la visita que nos habian solicitado, me dice que de momento no es necesario, ya que han conseguido contactar con una sobrina de Sofia, con la que habla periodicamente y esto la mantiene tranqnuila. Guadalupe me comtenta que les resulta complicado que se tome la medicacón y quizá haya posibilidad de que pueda desastibilizarse. Hemos quedado de en que si necesitan que vayamos nos lo dirán desde el centro.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-03-23','Ana: Llamo a Amor, TS ASPACE, en relación a los trámites de Extranjería que dejamos pendientes. (*Brahim cumple requisitos para solicitar la RESIDENCIA DE LARGA DURACIÓN, dado el cambio en la normativa del pasado 2021: >>Residentes que al llegar a la mayoría de edad hayan estado bajo la tutela de una entidad pública española durante los 5 años inmediatamente anteriores). Dice que no ha obtenido respuesta a la consulta que realizó en la oficina de extranjería. Puesto que pronto se producirá el traslado de centro, considera que lo mejor es que lo retome la compañera del CAMP. *Se lo comunicará llegado el momento.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2022-03-23','TERESA Es cierto que Natalia demanda el contacto telefónico con su madre y que está siempre diciendo que su madre ha solicitado su tutela y que se la habéis denegado. Que su madre está rehabilitada y que cuando se lo aprobéis se irá con su madre porque ha arreglado ya los papeles en varias ocasiones, y que es la comisión la que se lo deniega. Si finalmente vosotros dais la autorización para que hable con su madre, por nosotros no hay problema, se llevaría en el mismo formato que con su abuelo, llamadas supervisadas, fijando día y hora. En estos momentos, como te he comentado esta mañana, Natalia continúa en su plan amenazador, está fuera del centro y amenaza con escaparse y pegarle a cualquiera que intente impedirlo. No sabemos cómo acabará esta situación, ya te iré contando. Los niveles de exigencia de Natalia son impresionantes, consiguió el encuentro con su abuelo para traerse su dinero y ahora está con lo del tatuaje. SE HA PEDIDO AUTORIZACION JUDICIAL PARA EL TATUAJE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-03-23','2 - Ana: Tras hablar con Amor - ASAPCE, **llamo a la oficina de extranjería de CC ( Cita previa: 927 749 083 // 927 749 151 // Consultas: 927 74 90 88): Brahim tiene concedida la Larga Duración (Efectos desde 2018 a 2023), pero existe un problema al no tener en vigor su Documento de Identidad. *Hay una RESOLUCIÓN DENEGATORIA del expediente solicitado a fecha de 25/06/21, que en la CTAEX no hemos recibido. En principio "debe recogerla o descargarla con su Cdo. Digital José Vicente Granado". Al explicarle que es un cargo político y cómo funciona la CTAEX, me da la opción de solicitar por escrito una copia de dicha resolución alegando motivos por no haberla recibido. Hay que enviarlo a la Oficina de Extranjería, nº Registro: EA0040566. ········································································································· Redacto escrito para solicitar a Extranjería RESOLUCIÓN DESESTIMATORIA del expte. presentado a fecha de 25/06/2022 y lo subo al portafirmas digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2022-03-17','TERESA Te comunico que Beatriz realizará una visita a su hija el día 1 de abril. Ya nos ponemos en contacto con la abuela. Solo para que tengáis constancia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='MORENO'and apellido2='REY'),'2022-03-24','-email de Sole : Buenas tardes, Amalia. También lo pensé. Estoy de acuerdo. Solicitaré para Mª Carmen el reconocimiento de su situación de dependencia pero es que no doy a basto con el trabajo que tengo. Cuando la tenga cumplimentada , os la envío para que la firméis. Ayer te envié por correo ordinario la documentación original de Mª CARMEN MORENO REY relativa a la petición de cambio de perfil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='MORENO'and apellido2='REY'),'2022-03-24','-email de Sole : Buenas tardes, Amalia. También lo pensé. Estoy de acuerdo. Solicitaré para Mª Carmen el reconocimiento de su situación de dependencia pero es que no doy a basto con el trabajo que tengo. Cuando la tenga cumplimentada , os la envío para que la firméis. Ayer te envié por correo ordinario la documentación original de Mª CARMEN MORENO REY relativa a la petición de cambio de perfil.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2022-03-24','Ana: Envío correo a Pilar Martín, TS ESM (pilar.martinp@salud-juntaex.es): "Buenos días Pilar, Tal y cómo hemos acordado mediante conversación telefónica, te facilito la información que pedías relativa a Francisco Cacho Garrido: - Francisco tiene una autorización mensual de retirada de efectivo de 340 €. - A su hija, a día de hoy, no le pasa nada en concepto de manutención, tampoco nos consta resolución judicial al respecto en su expediente. Ante cualquier otra cuestión, hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2022-03-24','Ana: Envío correo a Carmen Gía. Martín - EVD Plas. (carmen.garciamarti@salud-juntaex.es) y Sara, TS de la Res. Banium Residencial (TrabajadoraSocialBanium@hotmail.com): "Buenos días Carmen, Te remito adjunta la ACEPTACIÓN PIA para Prestación Económica vinculada a SAR relativa a CONCEPCIÓN BARBERO SANCHEZ, ya registrada. Pongo en copia a Sara, de la RR.MM. Banium, para que esté informada y pueda adjuntarlo al expediente." ················· En relación al nuevo correo de Carmen, EVD, solicitando otros documentos, envío nuevo correo a las dos (Carmen y Sara): "- El alta de terceros, ya lo he cumplimentado y entregado a mis compis de la sección económica, pero hasta que éstas no vayan al banco no te lo podré enviar. - En cuanto al contrato residencial, Sara, cuando podías, enviármelo para que pueda ponerlo a la firma y os lo pueda enviar a las dos ya firmados por ambas partes. - El anexo informativo lo tengo ya también. Dime si te lo envío con lo demás o si te lo envío ya. Dime también si es suficiente si te envío los documentos por correo electrónico o si necesitas que le demos registro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-03-24','Ana: paso a Julio, CTAEX, el escrito para solicitar a Extranjería RESOLUCIÓN DESESTIMATORIA del expte. presentado a fecha de 25/06/2022, para que le dé REGISTRO DE SALIDA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-03-24','Ana: correo de Sonia Bernabé, Asindi: "Hola Ana, quería informarte que seguramente Aaron reciba el alta hoy. Ayer nos comunicaron que estaban pendientes del resultado de una analítica y una vez que lo tuvieran recibiría el alta. También nos han dicho que en pocos días ingresará en la UHDAC. A él ya se lo han comunicado. En un rato hablaré con su padre para informarle, aunque sabiendo que llama seguramente a diario ya lo sabrá. Iremos organizando todo en cuanto a ropa, ya que teníamos previsto irle comprando porque tiene poca y alguna deteriorada"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2022-03-24','Ana: Correo-e de Fernándo Pecero, Casa de la Misericordia (aromasdecaridad@hotmail.com): "Buenos días. Espero que estés bien. Lo primero que quiero decirte es que Antonio está muy bien. En todos los aspectos, comportamiento y relaciones sociales. Esperemos que siga así. La otra cuestión que quería comentarte es que a fecha de hoy seguimos sin percibir nada por su ingreso en el Centro, sólo sus gastos de bolsillos. Espero que se pueda hacer." ·············· Hablo con Alberto, jefe secc. económica. Lo solucionarán, estaba ya hablado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-03-25','miguel, me llegó ayer email de Rocio Gracian: Buenas tardes, Miguel En el Juzgado me dicen que el Juez no acepta las intervenciones por video conferencia ni nada parecido, exige la comparecencia personal de las partes. Esto es inexplicable pero es así, algunos jueces están por encima del bien y del mal. Voy a intentar que no tengáis que comparecer ni vosotros ni Damián alegando el articulo de la LEC que establece el plazo de 5 dias desde el señalamiento del juicio para que las partes pidan como prueba el interrogatorio de la otra parte. La parte contraria no la ha pedido así que me agarraré a ese argumento para dispensaros de comparecer. Lo que ocurre es que algunos Juzgados admiten que la declaración de la otra parte se pida en el mismo momento del juicio aunque no se haya solicitando en esos 5 dias, así que no se como reaccionará este Juzgado. Como voy a presentar ya un escrito alegando lo de los 5 días, sería importante aportar un pequeño informe vuestro que exponga la afectación negativa a Damián si tuviera que declarar en juicio. Es lo mismo que me pusiste en el correo pero de modo más formal. TE rogaría que me lo enviases lo antes posible para que podamos solucionar esto lo antes posible. Sería conveniente finiquitarlo la semana que viene. Espero tus noticias. ************************************************************ mi contestación: Buenos días, si es preciso haz un borrador de videoconferencia aunque sea por exhorto al juzgado de Mérida (al SCACE) para que lo firme nuestro representante que es un político…(el Gerente del SEPAD) y que evidentemente actuaría autorizándome a mi seguramente. Nosotros no podemos asistir, justifica en el escrito que representamos a más de 800 personas y que es habitual y diario los trámites judiciales y todos los hacemos por videoconferencia pues el equipo técnico que asisten a los mismos sólo lo forman 2 personas. Gracias, quedo a la espera de tu contestación. ******************************************************* Envío email a Rocío: Buenos días Rocío, aunque te llame sobre las 11:30h, echa un vistazo al borrador que he preparado, al que si así lo entiendes puedes unir testimonio judicial de incapacitación y nombramiento a la Comisión Tutelar de Adultos. También te adjunto las delegaciones de competencia del presidente de la Comisión Tutelar de Adultos (el presidente, que es el Consejero de la actual Consejería de Sanidad y Servicios Sociales). Es importante que recuerdes que hay que completar el escrito con los datos del procedimiento y el juzgado, e incluyas en el mismo la normativa en la que te basas (LEC imagino…)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2022-03-25','TERESA RECIBO LLAMADA DE BELEN TS DE LA RESIDENCAI DE TALARRUBIA 824903047, ME COMENTA QUE HAY UNA CHICA QUE ESTA CUIDANDO LOS PERROS DE ALFONSA QUE TENIA EN SU VIVIENDA. LA CHICA COBRABA ALGO DE DINERO PARA HACERSE CARGO DE LOS PERROS Y CUBRIR EL GASTO DE PIENSO PERO POR LA SITUAICON ECONOMICA DE ALFONSA HUBO QUE DEJAR DE DARLE ESE DINERO ACTUALMENTE LA SITUACION ECOMOICA DE ALFONSA ES MEJOR Y POR ESO CONSIDERAN QUE SE LE PODIA VOLVER A DAR ESA CANTIDAD SIMBOLICA DE DINERO QUEDO CON BELEN EN QUE ME MANDE PRESUPUESTO DE GASTO PARA QUE LO VALOREN EN LA SECCION ECONOMICA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-03-25','TERESA ME COMUNICA LA TS DEL ENCINAR DE LAS CRUCES QUE SE VA A HACER LE TRALADO EL 1/04/22. ME ENVIARA DOCUEMNTACION PARA LA FIRMA DE JOSE VICENTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-03-25','Ana: Envío correo a Alberto, jefe secc. ecca, con copia a Toni-Futuex: "Buenos días Alberto, En relación a FELISA FELIPE TEOMIRO, han cerrado la oficina de Liberbank de Navas del Madroño, localidad de residencia, por lo que en la actualidad no existe ninguna entidad bancaria en el pueblo. Van a dejar el cajero automático (por si en futuro hubiera opción de la tarjeta monedero. Y en tal caso se podría intentar dar apoyo desde el Programa de Familia y desde Futuex, para las retiradas periódicas, al menos hasta que aprendiera a utilizarla correctamente). Puesto que también ha dejado la relación que mantenía con Jesús, ya no dispone de vehículo para acudir a ARROYO DE LA LUZ, localidad más cercana en la que podría retirar su dinero y a la que puede ir en autobús. Y considerando que ella sola puede administrarse más o menos bien (con apoyo de su hermana y sobrino), acepto propuesta de Futuex de retirar el dinero de forma quincenal, en lugar de semanal, para reducir el número de desplazamientos. Alberto, por favor, confirma si te parece bien y cuándo estarías las gestiones bancarias pertinentes. Seguimos con el viernes."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-03-25','Ana: Envío correo a Alberto, jefe secc. ecca, con copia a Toni-Futuex: "Buenos días Alberto, En relación a FELISA FELIPE TEOMIRO, han cerrado la oficina de Liberbank de Navas del Madroño, localidad de residencia, por lo que en la actualidad no existe ninguna entidad bancaria en el pueblo. Van a dejar el cajero automático (por si en futuro hubiera opción de la tarjeta monedero. Y en tal caso se podría intentar dar apoyo desde el Programa de Familia y desde Futuex, para las retiradas periódicas, al menos hasta que aprendiera a utilizarla correctamente). Puesto que también ha dejado la relación que mantenía con Jesús, ya no dispone de vehículo para acudir a ARROYO DE LA LUZ, localidad más cercana en la que podría retirar su dinero y a la que puede ir en autobús. Y considerando que ella sola puede administrarse más o menos bien (con apoyo de su hermana y sobrino), acepto propuesta de Futuex de retirar el dinero de forma quincenal, en lugar de semanal, para reducir el número de desplazamientos. Alberto, por favor, confirma si te parece bien y cuándo estarías las gestiones bancarias pertinentes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL MARIA'and edp.apellido1='SANTOS'and apellido2='GOMEZ'),'2022-03-25','ARCHIVO DE EXPEDIENTE Se recibe DIOR de f/ 22/03/2022 del Jzdo. de 1.ª Inst. e Inst.n.º 4 de Badajoz, por la que se declara firme el Auto n.º 81/22, de 14 de febrero, por el que se deja sin E/ el nombramiento de la CTAEx y se procede a nombrar, a D. Fco. Escudero Almena, curador.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-03-25','-Amalia : Hablo por tf con la TS del Encinar . El traslado se hará el 1/4/22 en ambulancia , cuadrado con la RM de Caser . Percibe 421€ de PNC , abona por la plaza T2 432€ , no le','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2022-03-25','Ana: La MEDIDA JUDICIAL DE APOYO aceptada por la CTAEX es una CURATELA ASISTENCIAL en la esfera personal para "supervisión en el aseo, en la alimentación, para sus actividades de subsistencia, toma de medicación, citas y revisiones médicas, utilización de transporte público y similares", y en la espera patrimonial incluirán: "supervisión para el manejo del dinero, para la realización de compras, administración de sus bienes y disposición inter vivos" ·································································································································································································· Llamo a la Res. Ciudad Jardín Parque del Príncipe. Maribel Álvarez está siendo sustituida temporalmente por Pilar Cerrillo. De la conversación de ella y del informe emitido por Maribel, se desprende que tanto María, como su hermana Isabel, residen en el mismo centro. Ambas presentan dependencia y necesitan apoyo para las las ABVD e importantes problemas de salud. Vivían juntas. No tienen descendencia. María ocupa plaza privada y percibe Prestación Vinculada a Plaza Residencial. Su hermana María ocupa una T3. Ésta presentaba síndrome de Diógenes. Pero de ella no hay ningún cargo asumido ni pendiente de aceptación desde la CTAEX. ······························· ········································································· Llamo a Carmen, sobrina de ambas hermanas (646 970 766), su padre fallecido era el hermano de sus tías. Expresa que ella ha intentado ayudar todo lo que ha podido, se ha encargado de muchas gestiones y de coordinarse con la TS, pero sus tías siempre han rechazado su ayuda y en sus última visitas sólo ha recibido gritos e improperios. ············ El resto de sus hermanos no se ha implicado en nada. ······ Pregunto por la vivienda y teniendo en cuenta la información facilitada envío correo a Pilar Cerrillo, TS Res.: "En relación a la vivienda de María, nos consta que tiene el 50% de la propiedad. Y, puesto que en el Informe Social, Maribel indica que la casa no reúne condiciones de salubridad e higiene, he llamado a Carmen, sobrina, quien me informa que la vivienda sigue igual, nadie ha entrado a limpiar y el patio está lleno de malas hiervas muy altas ya y sería conveniente hacer limpieza también en el mismo. También me dice que la otra propietaria de la vivienda es su otra tía, Isabel, y que ésta no consiente en que nadie entre en el domicilio, ni a limpiar ni a nada. Yo entiendo que sería conveniente realizar una limpieza para prevenir problemas de posibles infecciones en el vecindario, pero si la otra propietaria, de quién la CTAEX no ostenta ningún cargo, no quiere, no vamos a poder hacer nada. Así mismo, desde el Gabinete Técnico de la CTAEX, entendemos que sería conveniente proceder a dar de baja la telefonía fija y suministros, puesto que en la vivienda no reside nadie en la actualidad y suponemos que ninguna de ellas volverá al mismo. Pero Carmen, sobrina, dice que Isabel tampoco quiere. ¿Podrías confirmarnos esta información, y si es así, abordar con ellas tanto la conveniencia de darlos de baja así como de hacer las citadas limpiezas? En caso de que se aceptara por parte de Isabel estas cuestiones, ponerlo en nuestro conocimiento para que podamos proceder. Por cierto, suponemos que, aunque ambas hermanas están en la misma cuenta en que María percibe su pensión, Isabel tiene distinta donde cobra la suya y desde la que abona su plaza, no? A María se le ha abierto una nueva cuenta, sólo a su nombre y el de Representante Legal, y ya he pedio el cambio de la pensión a INSS, pero la intención también es pasar la mitad del dinero de la cuenta compartida a la nueva de María, pues con la pensión y la prestación vinculada no llega para abonar la plaza y en dicha cuenta tienen buenos ahorros. Nos gustaría saber si vosotras veis algún inconveniente en ello. Ya nos dices."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-03-24','Ana: Toni - Futuex nos remite nota informativa de la situación actual de Felisi. Ha dejado la relación con Jesús, aunque está triste parece decidida muy segura con la decisión tomada. Hace razonamientos muy coherentes con respecto de la actitud de Jesús y lo insano de la relación. Jesús ya ha abandonado la vivienda y se ha llevado casi todas sus pertenencias. *Incluso le ha dicho que ya mantienen otra relación con otra mujer. ············· *Guardo nota en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-03-25','-Amalia , email de TS de la RM : Buenas de nuevo, os respondo: - Adjunto tenéis la documentación del usuario pendiente para firmar.( puesta a firma por Tere ) - El usuario en la cuota mensual que le establecen: 438,53 €. Es la misma cuota que pagaba al otro centro residencial, Caser en Olivenza. En esta cuota tiene todo incluido excepto (GASTOS APARTE): peluquería (8 € cortar) podología (15€/servicio) marcaje de ropa inicial (40 € + 10% iva). Veremos con el centro de origen si ya han marcado la ropa, para evitar este gasto, sino se le marca aquí pero lo cobramos más adelante. medicación (según pauta de medicación que traiga), la cantidad será variable. Me encargaré de enviaros cada mes todas sus facturas para que llevéis el control del gasto. Confirmame que autorizáis a pasar por su cuenta estos gastos que tiene aparte. Gracias por vuestra labor. Buen día. María Martín Rivero Trabajadora social. Encinar de las Cruces Nº COL. 07-1209 924 81 25 99/ 618 95 70 59','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-03-25','-Amalia , email de TS de la RM : Buenas de nuevo, os respondo: - Adjunto tenéis la documentación del usuario pendiente para firmar.( puesta a firma por Tere ) - El usuario en la cuota mensual que le establecen: 438,53 €. Es la misma cuota que pagaba al otro centro residencial, Caser en Olivenza. En esta cuota tiene todo incluido excepto (GASTOS APARTE): peluquería (8 € cortar) podología (15€/servicio) marcaje de ropa inicial (40 € + 10% iva). Veremos con el centro de origen si ya han marcado la ropa, para evitar este gasto, sino se le marca aquí pero lo cobramos más adelante. medicación (según pauta de medicación que traiga), la cantidad será variable. Me encargaré de enviaros cada mes todas sus facturas para que llevéis el control del gasto. Confirmame que autorizáis a pasar por su cuenta estos gastos que tiene aparte. Gracias por vuestra labor. Buen día. María Martín Rivero Trabajadora social. Encinar de las Cruces Nº COL. 07-1209 924 81 25 99/ 618 95 70 59 -------------------------------------------------------- Amalia , envío email a sección eco : Buenas , David será trasladado el día 1/04/2022 de la residencia de Caser a la RM de Encinar de la Cruces . Percibe PNC de 421,40€ y el copago de la plaza sociosanitaria es de 438 € / mes. Se le ha enviado datos para que nos pase el modelo 50 . Los gastos de peluquería y podología lo cargan en cuenta , ya le he explicado que no tiene dinero. No se queda con nada de gastos de bolsillo y poco se podrá ahorrar. En cuenta tiene ahorrado sólo 26€. Hay que revisar sus cuentas , veo que tiene gastos de tf de 45 € que no podrá abonar . Podéis ver si paga algún seguro de decesos ? Si no es así , habría que hacerle uno , teniendo en cuenta que tiene poco dinero , tendrá que ser muy básico. Buen finde .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-03-28','miguel, llega la aceptacion de internamiento involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-03-25','Ana: Correo de Sonia, TS y Directora de Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, han dado el alta a Aaron y regresa en un rato. Ayer hablamos con su padre para informarle y nos decía que lleva un mes sin verle. Le comentamos también que según nos dicen no tardarán en llamarle para ingreso en la UHDAC, él lo entiende, pero lo único que quiere es tener contacto con su hijo, que pueda venir a visitarle,... Le he dicho que por lo que conozco del funcionamiento suelen permitir salidas si todo va bien, por lo que esté tranquilo que ya le informaremos cuando llegue el momento. Como hace tanto que no se va a casa (cada vez que organizábamos tenía alteración de conducta y era derivado a Salud Mental, entonces este finde hemos visto que sería bueno, ya que llevan tiempo sin verse y no sabemos cuándo será el ingreso, que se fuera a casa este fin de semana. Se iría a lo largo de la mañana, cuando toda la medicación y equipaje esté preparado y regresa el lunes por la mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-03-28','Ana: Recibimos nueva valoración del CADEX, ha mantenido el mismo grado de discapacidad a Antonia (65%), pero ya con carácter DEFINITIVO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2022-03-28','Ana: remito correo al Centro Residencial Banium (residencialbanium@villatermal.com): "Buenos días, Adjunto Contrato Residencial relativo a Concepción Barbero Sánchez, debidamente cumplimentado y firmado por el representante legal. A la compañera de dependencia se lo enviaré una vez me traigan del banco mis compañeras de sección económica el alta de terceros. Adjunto también copia de: - Testimonio de la sentencia - Testimonio de aceptación del cargo" ··················································································································································· Pte. el ALTA DE TERCEROS, cumplimentado y entregado a Icíar, secc. ecca. para que lo lleve al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-03-28','Ana: Llamo a Marta, TS SSASB Cilleros (927 51 20 37 / tsocial@ayuntamientodecilleros.es): está ocupada, le pasarán nota para que me devuelva la llamada. ································································································································································································ Conversación con Marisa, TS del ESM y ECA (Equipo Conductas Adictivas) de Coria (70841): Julia ha estado allí esta mañana, ha acudido en autobús, la ve muy bien, bastante tranquila y estable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2022-03-28','miguel, remito al jzdo nº7 de Caceres solicitud para nos autoricen a no entregar los 10.000€ que nos solicita la hija','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2022-03-28','Ana: A petición de Carmen (633 616 167), llamo varias veces a su madre, Benita (628 88 79 28), pues según dice necesita dinero y quiere ayudarle. ·············· Tras conversar con Benita, envío correo a Alberto, jefe secc. ecca.: "Buenas Alberto, CARMEN SOLANA CHANCLÓN quiere ayudar a su madre económicamente, pues está pasando por una mala situación. *Carmen pasa mensualmente 150 € a sus dos hijos, 75 de los cuales los administra su madre, Benita, por tener acogido a su nieto (hijo de Carmen). Recientemente a Benita le han sobrevenido diversas circunstancias por las que no puede hacer frente a todos los gastos, en parte debido a actos de su nieto, como haber dejado las clases antes de los exámenes, motivo por el que le reclaman la beca concedida y gastada… ahí hay algún error en la cuantía que están reclamando, pero mientras no se resuelva debe abonar más cantidad de la debida. Por otra parte, la ayuda por acogimiento que le pasaban de la Junta, se la han dejado de pasar, otro error que está reclamando, pero de momento no se lo ingresan. Las otras cuestione son ajenas al hijo y a ella misma (relacionadas con toda la comunidad de vecinos). El caso es que necesita dinero, pero he hablado con la propia Benita y le da mucho apuro. No se atreve a decir cuantía, ella de hecho no quería llamarnos. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-03-21','-Amalia : he solicitado a Futuex primera visita . Espero informe para hacer plan de intervencion . Cuando le abran cuenta nueva , tengo que solicitar cambio de la pensión.','2');
