insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-03-29','Ana: Correo de Rosario Hernandez Casado, C. Penitenciario (rosario.hernandez@dgip.mir.es): "Buenos días Ana!! Te envío instancia del interno de este Centro Penitenciario Saturnino Miguel solicitando comunicar por locutorio o llamada telefónica con su abogada. A la espera de recibir contestación. ···························································· Mi respuesta: "Buenos días Rosario, Mi compañero Miguel, Asesor Jurídico de la CTAEX, es quien tiene el contacto con la abogada de Saturnino Miguel. Le pongo en copia para que contacte con ella al respecto." ····················· Maite, TS del C. Penitenciario, también envía la misma instancia. Informo que ya lo he comunicado a Miguel. ·································· Correo de Oscar, secc. ecca, a Maite, TS C.Penitenciario, en relación a la instancia de Saturnino solicitando el arreglo o la compra de la TV: "Buenos días. Su situación económica actual no permite la compra de un televisor nuevo, ya que debe de tener ahorros por la deuda que aún tiene por ingresos indebidos. Si puede arreglarlo con su disponible del peculio, puede hacerlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISPIN'and edp.apellido1='ALONSO'and apellido2='ALONSO'),'2022-03-29','Ana: Mi respuesta a los correos de ayer de Emilia, TS CSS: "Buenos días Emilia, Por mi parte ok a ambas cosas, sin problema. Pongo en copia a Oscar, compañero de la sección económica para que estén al corriente. Si no me equivoco, cuenta con buenos ahorros y en el centro tenéis autorización para retirada de efectivo para lo que pueda necesitar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISPIN'and edp.apellido1='ALONSO'and apellido2='ALONSO'),'2022-03-28','Ana: Correos de Emilia Almodóvar, TS del CSS-Plas.: "Referente Alonso Alonso Crispin, solicitamos una salida de ocio a Losar de la vera, durante aproximadamente 3 horas, para la ceremonia nupcial el día 9 de abril. Ira acompañada por un Auxiliar trabajado/ar de su unidad, en el coche propio, pues los de la casa no trabajan en fin de semana. A espera de contestación." ········ "Ana, disculpa me olvide de solicitar también autorización para compra camisa, pantalón y pajarita, para el evento. nos autorizáis sacar dinero (reintegro) para la compra?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2022-03-25','Ana: Correo de Minerva, TS del C.R. Cervantes (minerva.salvador@salud-juntaex.es): "Sobre el asunto de la autorización del extra para las zapatillas, Gloria ha acompañado al banco a Eugenia esta mañana y esta vez sí ha podido sacar el dinero y han comprado las zapatillas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-03-29','miguel, Ana Ts, me reenvía email de Rosario del Centro Penitenciario (rosario.hernandez@dgip.mir.es> ): Buenos días Ana!! Te envío instancia del interno de este Centro Penitenciario Saturnino Miguel solicitando comunicar por locutorio o llamada telefónica con su abogada. A la espera de recibir contestación. ****************************************************** reenvío email a la abogada mlucasduran@icac.es: Buenos días, adjunto la solicitud de Saturnino para hablar contigo. Le vale sea telefónicamente. Como sabrás, la ley 8/2021 de 2 de junio, por la que se reforma la legislación civil y procesal para el apoyo a las personas con discapacidad en el ejercicio de su capacidad jurídica (es fruto de la Convención internacional sobre los derechos de las personas con discapacidad, hecha en Nueva York el 13-12-2006) Teniendo en cuenta la reclamación de su hermano al Defensor del Pueblo y teniendo en cuenta que con la actual ley 8/2021 de 2 de junio, por la que se reforma la legislación civil y procesal para el apoyo a las personas con discapacidad en el ejercicio de su capacidad jurídica, él tiene la misma capacidad jurídica y de obrar que cualquier persona, y hay que respetar su voluntad y preferencias, por lo cual hay que escucharle y cumplir su voluntad. Si quieres llámame y lo comentamos. ********************************************* La abogada contesta que le llame el interno mañana día 30-3-2022 a las 6h. Reenvío dicho email a Ana Ts y Rosario del Centro Penitenciario (rosario.hernandez@dgip.mir.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2022-03-28','Ana: Correo Mª del Carmen Sánchez, TS Centro de Personas sin Hogar - Caritas (mcsanchez.cdcoriacaceres@caritas.es): "Me dirijo a ti para informar que la pasada semana Francisco Cacho Garrido tuvo cita en Salud Mental (Trabajadora Social, Psicóloga y Psiquiatría). Unos días antes había estado hablando con Pilar (Trabajadora Social) para buscar recurso a Francisco, quedamos en que le propusiera piso tutelado, a pesar que Francisco no estaba muy convencido debido a la mala experiencia en Mérida, según él, después de varias conversaciones con Fráncico para que por lo menos escuchará a Pilar y luego se valorará la propuesta de recurso, pero ha decidido aceptar la derivación a pisos tutelados de Zafra y Don Benito. Hoy he estado hablando otra vez con Pilar para valorar el tema del tiempo, ya que me da miedo que esto se retrase mucho y Paco abandone nuestro recurso, y perdamos todo lo avanzado hasta ahora, no se si vosotros como Comisión Tutelar podéis ayudar en este sentido para agilizar el tiempo de espera."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2022-03-29','TERESA Confirmamos el ingreso de Ramón para el miércoles Si es posible que sea después de las 11.30h Necesario resultado negativo de pcr','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2022-03-29','Ana: Respondo al correo de Mamen Sánchez, TS Centro de Personas sin Hogar - Caritas (mcsanchez.cdcoriacaceres@caritas.es): "Buenos días Mamen, Gracias por informar. Es estupendo que Manuel haya aceptado la derivación a Piso, esperemos que en esta ocasión aproveche el recurso y no se agobie al poco tiempo de estar allí. Ojalá y que la adjudicación de plaza no tarde mucho, pero lamentablemente no está en nuestra mano agilizarlo. Las personas, cuyo cargo/medidas judiciales, ostenta la CTAEX, acceden a los recursos de la comunidad por las mismas vías que el resto de la ciudadanía extremeña, no tienen prioridad. No obstante, hablaré con mi jefa de sección y con las compañeras de la sección de salud mental para estar pendiente más que nada y nos mantengan informadas al respecto. Seguimos en contacto." ····························· Maite, Jefa de Secc. CTAEX, habla con las compañeras de la Secc. Acceso a RR. Salud Mental, conocen perfectamente el caso. Pasará a comisión de valoración. Nos mantendrán informadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-03-28','Ana: Correo de Alberto, Jefe secc. ecca.: "OK A REINTEGRO PERMANENTE DE 160 €/QUINCENA A PARTIR DE 01/04/2022...ANA: NOS ARRIESGAMOS A QUE PILLE EL IMPORTE DE ESA SEMANA Y EL DE INICIO DE QUINCENA (SALVO QUE QUIERAS COMENTARSELO A ELLA). LO IDEAL ES QUE FUERA A SACAR LA PRIMERA QUINCENA EL DÍA 04/04/2022 O POSTERIOR." ······················ Envío correo a Toni-Futuex: "... Desde la sección económica se acepta la propuesta de “REINTEGRO PERMANENTE DE 160 €/QUINCENA” a partir del próximo lunes día 4 en Arroyo de la Luz. Aunque yo voy a llamar a Felisa luego para ver cómo está y para informarle, agradecería que la compañera estuviera pendiente también de esta cuestión. Y cuando el sobrino ya no pueda acompañarle, lo ideal sería el apoyo de la compañera las primeras veces que tuviera que coger el autobús y acudir a la oficina, para asegurarnos de que puede realizar el traslado y la gestión por sí misma sin problema." ····························· Llamo a Felisi (722 494 033): *Responde Jesús, Felisi ya no tiene este número. ·········· *Solicito a Toni de Futuex el nº nuevo. ······························· Llamo a Felisi a su nuevo nº : 624 85 67 46. No obtengo respueta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-03-29','Ana: Correo de Oscar, secc. ecca, en relación a la instancia de Saturnino docilitando el arreglo o la compra de la TV: "Buenos días. Su situación económica actual no permite la compra de un televisor nuevo, ya que debe de tener ahorros por la deuda que aún tiene por ingresos indebidos. Si puede arreglarlo con su disponible del peculio, puede hacerlo."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='CASARES'and apellido2='MARISCAL'),'2022-03-29','INGRESADO EN HOSPITAL DE BADAJOZ . POSITIVO EN COVID','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='ALEGRE'and apellido2='GOMEZ'),'2022-03-29','Ana: José se encuentra residiendo en la URH (Unidad de Rehabilitación) del CSS - Plas. ········ La TS de referencia es Mariví Clemente. ·········· Tras comunicarme Alberto, jefe sección económica "QUE CSS PLASENCIA GASTA MÁS QUE INGRESA...ESTE AÑOS TIENE -650 € TIENE PNC X 421,70 € X 14 Y UN SALDO DE 4.500 € APROX." consulto si el gasto es imprescindible, pues de lo contrario, es necesario reducirlo, ya que se están mermando sus ahorros. ································ Respuesta de Mariví Clemente: "Calcularemos a que es debido el gasto extra y en cualquier caso reduciremos sus cantidades." ·············· Le especifico lo que indica Alberto: "COMO MUCHO PUEDEN GASTAR 140 €/MES (QUE PERMITE AHORRAR 1 SÓLA PAGA EXTRA) (ACTUALMENTE CENTRO GAST 213 €/MES)” ··············· Pongo en copia a Oscar, Jefe Negociado, Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2022-03-29','Ana: Llamo a Miguel, Empresa "Limpieza extrema" (664 62 19 46 / info@limpiezasextremas.com): no se encuentra disponible. ······················ Envío correo: "Buenos días Miguel, Mi nombre es Ana, Trabajadora Social de la Comisión Tutelar de Adulto, soy compañera de Teresa. Me pongo en contacto con usted para preguntar si podrían acudir a visitar una vivienda en la localidad de Alcuéscar y enviarnos PRESUPUESTO para realizar una limpieza en la misma. Le he llamado pero su teléfono no está disponible. Puede ponerse en contacto conmigo en el teléfono que aparece a continuación en la firma o a través de este medio (mail) para confirmar su interés y en tal caso facilitarle el resto de dato necesarios. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-03-29','miguel, llega por email de Inmaculada de Cid y Villafaina con la liquidación del impuesto de sucesiones de la cuenta de la Caixa, que a su vez reenvío a la parte económica y a Tere Ts: Hola, adjunto declaración del impuesto de sucesiones de esta cuenta de la Caixa, que se quedó fuera de la otra liquidación porque no se conocía. El único heredero es él y por tanto la parte económica debéis hablar con la Caixa y poned a José Vicente para el control de dicha cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-03-17','miguel, envío email al abogado Pablo Garrote Delgado, pablogarrotedelgado@icaba.com Buenos días, conforme hemos hablado por teléfono, necesitamos nos gestiones la herencia y venta de inmueble a nombre de su madre fallecida Doña Aurora Chaves Caballero. Estamos tramitándolo con el trabajador social del pueblo José (trabajador social de los Servicios Sociales de Base del Ayto de Monesterio), cuyo teléfono es 924-516509 para que contactes con él y te informe y aporte la documentación que vayas necesitando. Adjunto lo único que tenemos que es certificado original de defunción de su madre fallecida Doña Aurora Chaves Caballero, certificado catastral de la vivienda, dni de nuestro tutelado (actual curatela representativa conforme la nueva ley 8/2021 de 3 de junio) y sentencia de incapacitación y aceptación del cargo de tutor a favor de la Comisión Tutelar de Adultos. Desde Mérida te facilitaré lo que me vayas solicitando, para lo que te dejo mis datos en este email. Cuando tengas la información necesaria por favor mándame un presupuesto desglosado para trámites previos a la herencia, firma de la herencia en notaria, autorización de aprobación y aceptación de la herencia ante el Juzgado, y los trámites de la venta incluyendo firma en notaria (desde la Comisión Tutelar de Adultos firmaríamos la ratificación a dicha venta desde la notaría de Mérida de los notarios de la calle Romero Leal: Don Gonzalo Fdez Puignaire, Don Borja Igartua…. Quedo a tu disposición para aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-03-23','miguel, recibo email del abogado:Buenos días, He estado mirando la documentación y lo que me faltaría por saber es si en el certificado de últimas voluntades hay testamento o si hay que hacer un testamento ab intestato. Entiendo que los trámites a realizar son: autorización judicial para la aceptación de la herencia, aceptar la herencia y liquidar el impuesto, autorización para la venta de la vivienda y firma de la compraventa en notaría. Corrígeme si me equivoco para desglosar los conceptos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-03-24','miguel, recibo email del abogado Adjunto envío el presupuesto solicitado para la tramitación de la aceptación de la herencia y la posterior venta del inmueble.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-03-25','miguel, remito email al abogado Buenas tardes, te confirmo que comiences los trámites. Si necesitas algún ingreso o depósito envíame encargo y concepto para pasarlo a la parte económica. ********************************************** Contestación del abogado: Perfecto, pues voy a preparar la hoja de encargo para que se firme. Además aclarar que los costes que supongan el pago a notaría, al procurador y los impuestos pertinentes no están incluidos en el presupuesto enviado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-03-25','miguel, remito email al abogado Buenas tardes, te confirmo que comiences los trámites. Si necesitas algún ingreso o depósito envíame encargo y concepto para pasarlo a la parte económica.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-03-30','Ana: Conversación con Marta, TS del SSASB de Cilleros (927 512 037), Julia le ha llevado una notificación de una multa/denuncia de noviembre. Me la envía al correo (tsocial@ayuntamientodecilleros.es). Es la misma multa que ya se abonó. Nos la remitió a través de Futuex. ············································································································································· Conversación con las compañeras de la Secc. de Acceso a los recursos de Salud Mental: me comunican que Julia está la 5ª en la lista de espera para CRR. *Confían en que no ocurra como cuando estuve en el Mérida, que NO superó el periodo de prueba. ··········· Le comunico la posición de la lista a Marta, TS SSASB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-03-30','miguel, recibo email de la abogada Carmen Lucas: Miguel cuando puedas me dices cuando hablamos, no hay ninguna novedad, si hubiera señalamiento, habría que hablar con él para ver si llegamos a acuerdo o no, pero lo que tenía que decirle se lo dije en una carta ¡Qué agobio! ¿Puede llamarme él? A ver, cómo contacto con él… ******************************************************* recibo email de Rocio del Centro Penitenciario: Buenos días!! Ya les comenté en un correo anterior que para que el interno pueda hablar por teléfono o bien comunicar por cristales con su abogada ésta debe acreditarse como que es su abogada y además, debe enviar su número de teléfono para que se lo puedan autorizar en el Dpto. de Seguridad. De lo contrario Saturnino no podría hablar con ella. *************************************************** contesto a Rocio del Centro Penitenciario: Buenos días, reenvío tu email a la abogada. ******************************************************* contesto a la abogada Carmen Lucas: Buenos días, adjunto email que envían desde el centro penitenciario donde solicitan que para que Saturnino y tú podáis hablar es necesario que te pongas en contacto con el centro penitenciario y les facilites: -Acreditación de tu representación como abogada de Saturnino -Tú número de teléfono. Puedes verlo en el email de debajo. Si quieres contesta tú directamente a Rosario del Centro Penitenciario. A final de la mañana estaré disponible por si me llamas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-03-28','miguel, recibo email de Pablo Garrote (abogado): Adjunto la correspondiente hoja de encargo para que sea firmada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-03-29','miguel, El número de cuenta es ES49 2085 4525 4903 3082 1916 que no aparecía en la hoja de encargo. El método de pago al final que se ha puesto en la hoja puede modificarse por si es necesario que sea otro.','1');
