insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='GARCIA'and apellido2='PEREZ'),'2022-03-30','TERESA he contactado con la empresa que nos realizará el cambio de cerradura de la vivienda de promoción pública situada en Plaza de América, 22 de Villafranca de los Barros. Los hemos citado el día 05/04/2022 a las 09:30 de la mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2022-03-29','TERESA HABLO CON MARISA DEL ECA DE CORIA 70841/70858 ME COMENTA QUE HA IDO A SU CONSULTA PARA COMENTARLE QUE NO ESTA BIEN LA RELACION CON SU HERMANA Y QUE YA NO QUIERE QUE SIGA VIVIENDO ALLI EL PROPONE IRSE A VIVIR DE ALQUILER LE HA PEDIO INFORME PARA PEDIR EL AL REVISION DE LA SENTENCIA Y NO ESTAR TUTELADO, ACTUALMENTE EN LOS CONTROLES ESTÁ DANDO POSITIVO HABLO CON ROSA SU HERMANA 665302945 Y ME COMENTA QUE ELLA NO LE HA DICHO NADA DE QUE SE VAYA DE CASA Y QUE CONTINUAMOS IGUAL CON LA TRANSFERENCIA. MANUEL LLEVA SEMANAS INTENTANDO HACERSE DE DINERO YA QUE ESTA EN CONSUMO ACTIVO Y DE AHI QUE NO DEJA QUE ACUDIR A LOS DIFERENTES RECURSOS CONTANDO HISTORIAS QUE NO SON REALES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2022-03-30','-Amalia : Tf. de su hijo Luis ( vive en el País Vasco y es educador ) 633176893 Su otro hijo tb vive allí y trabaja en Mercadona. Gestiono SAD concedido por dependencia con Asindi. SEPAD le abona 191€ y Asindi le cobrará unos 240€ , la diferencia lo abona Antonia. Ella quería que fuera la misma sra. que va con su madre , pero la otra el de la empresa El Angel .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-03-29','Ana: Correo de Sonia, TS y Directora de Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, Aaron ha regresado con cambios en su tratamiento médico. Llegó con ganas de ir a casa y ver a su padre porque llevaba un mes sin verlo. En casa ha estado adormilado,según su padre, pero bien. En ASINDI Aarón hoy ha ido con el grupo de actividad deportiva que organiza el monitor deportivo del Ayuntamiento, al principio decía que era un aburrimiento pero al llegar aquí cuando le han preguntado ha dicho que le ha gustado ir. Vamos a ir viendo el día a día y comprobar si el nuevo tratamiento le ayuda a sentirse mejor y estar más tranquilo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2022-03-30','-Amalia : Tf. de su hijo Luis ( vive en el País Vasco y es educador ) 633176893 Su otro hijo tb vive allí y trabaja en Mercadona. Gestiono SAD concedido por dependencia con Asindi. SEPAD le abona 191€ y Asindi le cobrará unos 240€ , la diferencia lo abona Antonia. Ella quería que fuera la misma sra. que va con su madre , pero la otra el de la empresa El Angel .','2');
