insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2022-03-30','Ana: Alberto confirma que el tratamiento dental que ha solicitado Jesús se puede afrontar. Icíar tramitará el pago con la clínica dental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-03-30','miguel, Sonia Bernabé de Asindi Plena Inclusión de Alcántara me remite oficio del juzgado de lo penal nº1 de Plasencia, procedimiento Ejecutoria 600/2021 de 22-3-22, comunicando que ha concluido la liquidación de condena de la medida de seguridad de internamiento impuesta a la tutelada. Y solicitan les informen de si continúa interna en el centro, y bajo qué régimen y tratamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-03-30','miguel, Sonia Bernabé de Asindi Plena Inclusión de Alcántara me remite oficio del juzgado de lo penal nº1 de Plasencia, procedimiento Ejecutoria 600/2021 de 22-3-22, comunicando que ha concluido la liquidación de condena de la medida de seguridad de internamiento impuesta a la tutelada. Y solicitan les informen de si continúa interna en el centro, y bajo qué régimen y tratamiento. ****************************************************** Buenos días, adjunto remito, en relación a Felisa Bruno Saavedra, oficio recibido del Juzgado de Plasencia. Daremos respuesta al mismo indicando que se encuentra interna en el Servicio de Residencia y acude, periódicamente a los seguimientos de salud mental ya que continua presentando alteración de conducta. Si es preciso que se aclare algún aspecto más me lo indica. *************************************************** mi contestación a Sonia, gracias, entiendo que es suficiente indiquéis que continúa interna en el centro y básicamente el tratamiento que toma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2022-03-30','Ana: Llamada de Belén, nueva Directora de la empresa Grupo ASUMA (600 525 247) que actualmente gestiona los PPTT de Mayores de titularidad municipal de Villa del Rey: El Ayto. le ha pedido que pasen ellos los cargos de las plazas. *Le facilito el contacto de Óscar, Secc. Ecca., para que le pida los documentos necesarios a través de email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-03-30','miguel, email que remite la abogada Carmen Lucas a Rosario del Centro Penitenciario junto con los documentos adjuntos: Buenos días Rosario, soy Carmen Lucas, Letrada designada por turno de oficio en el procedimiento penal que se sigue frente a Saturnino Miguel Salgado por presunto delito de Agresiones Sexuales. Me ha comentado Don Miguel Fernández de Llera, de la Junta de Extremadura, que Saturnino quiere hablar conmigo. Indicarle antes que nada que, cómo él sabe él está en prisión provisional como presunto autos del delito que se le imputa, se hicieron determinadas pruebas forenses tanto a la denunciante, como a él, y en el cuerpo de la anterior se encontraban restos fisiológicos compatibles con el Sr. Salgado, y por eso se acordó dicha prisión provisional, puesto que en la primera declaración ante su Sª, dicho Sr. no negó tampoco haber mantenido relaciones con la anterior y la entidad del delito es importante. El Auto de prisión provisional le fue notificado a él en persona. He solicitado recientemente la libertad provisional, y en su caso el cumplimiento en centro especializado debido a sus patologías, me lo han denegado, ahí le mando para que se lo muestre y entregue el auto del Juzgado denegatorio de tal petición. Decirle asimismo que, en la actualidad las Diligencias Previas, se han convertido en Sumario Ordinario, es decir el proceso sigue adelante y se tramitará ante la Audiencia, no me han dado aún plazo para presentar el escrito de defensa, no sé qué pena le piden, no se lo puedo decir, esto sigue su trámite, y hasta la fecha no tengo novedades. Les mando el Auto de conversión de las previas en Sumario Ordinario. En su momento, la Audiencia le notificará personalmente la Acusación del Fiscal y de la Junta de Extremadura (la Sra. afectada ha fallecido y tiene un hijo tutelado por la Junta, por lo que será esta entidad quien le represente), una vez se produzca esto, yo estudie todo de manera pormenorizada y siempre antes del juicio, tendré que hablar con el Sr. Salgado, para sopesar si EL quiere llegar a un acuerdo para ajustar la pena, o bien prefiere que nos arriesguemos a defender el juicio para sostener su inocencia, será una decisión exclusivamente suya. NO PUEDO DECIRLE MAS, ES TODA LA INFORMACION QUE TENGO, IGNORO LAS PENAS QUE SE VAN A SOLICITAR PARA ÉL, NO PUEDO DETERMINAR TAMPOCO EL TIEMPO QUE ESTO SE VA A PRORROGAR ES CUESTIÓN DE LA AUDIENCIA Y DE SU DISPONIBILIDAD, pero si pese a todo quiere hablar del tema conmigo, le diré exactamente lo mismo que le estoy refiriendo a Ud. en este mail, para que le de copia a él (ya le he comentado antes todo esto con la Junta de Extremadura, puesto que está tutelado, ellos pueden corroborárselo y a un hermano suyo de Madrid que contacta a veces conmigo), que me llame al 927226664 de 6 a 7 esta tarde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-03-30','Ana: Correo de Sonia, TS y Directora de Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, pues estamos esperando a la ambulancia porque lo derivan de nuevo. Hoy tenía consulta en Cáceres con la Psiquiatra pero ha empezado a golpear mobiliario, a personas hace el intento porque se le frena y se retiran,...Dice que oye voces, que quiere irse a la UHDAC,.. Ayer, a mediodía, las compañeras me decían que no lo notaban bien del todo y que tenía que tener supervisión continua porque no sabían cómo iba a reaccionar. Seguramente, esta tarde regrese, pero la doctora lo ha considerado así ahora mismo." ·················································· Nuevo correo de Sonia - Asindi, a las 18:29 h: "Hola Ana, Aarón ha regresado hace un rato con el mismo tratamiento. Estaremos pendientes de cómo va evolucionando. El viernes intentarán ir a la consulta de Salud Mental que tenía prevista para hoy."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='MULERO'and apellido2='SALGUERO'),'2022-03-30','TERESA HAY QEU CAMBIAR LA PENSIO A IBERCAJA UNA VEZ LA HAYASMO CAMBIADO CONTACTAR CON CENTRO PARA GESTION DEL PAGO Y PRESUPUESTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='NAVAS'and apellido2='VALENCIA'),'2022-03-30','TERESA ENVIO CORREO SOLICITANDO INFORMACION PARA PODER HACER LA FICHA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-03-30','Ana: Correo de Isabel al ctutelar@: "Hola Ana buenos días te quería comentar que mi madre necesita el dinero del piso de aquí de Plasencia porque se va a dejar con la pareja .porfavor aver si puedes hacer algo es importante .y también los 40 euros del día 13 y 18 para que venga a por mí 20 y para que me traiga otros 20 es importante porfavor contesta." ····················································································· Conversación telefónica con Isabel: Al preguntarle sobre si su madre, con sus escasos ingresos, puede permitirse vivir en Plasencia, pues sólo el alquiler son más de 300€, acaba reconociendo que todavía no lo ha dejado con su pareja y que se irá a vivir allí con él. Que le dejará después dice. ············ Vuelvo a explicarle lo mismo que la otra vez, cuando la llamamos Maite y yo, que en el momento en que se encuentra de su proceso terapéutico no le conviene que su madre viva en la misma ciudad que ella, sí el contacto y visitas periódicas, pero no esa trato personal diario. De momento no se le va a dar ese dinero a su madre. Se volverá a valorar más adelante. ··················· En cuanto a la solicitud de 40 € para el viaje a su casa, en este momento se le autorizará, pero a partir del mes que viene, ya le confirmaremos si debe abonarlo de su asignación mensual. *Ella rebate que se gasta buena parte de la asignación en comida porque no le gusta la que ponen en el centro y además es alérgica al marisco. *Dice que Paula le ha dicho que se compre comida aparte, e incluso la ha acompañado a comprarla. ········································································································································································································· Envío correo a Óscar, secc. ecca.: "En relación a ISABEL CANO BLÁZQUEZ, hay que hacer una transferencia a la madre de 40€ para que pueda ir a recogerla al centro y llevarla de vuelta, tras las salida de varios días en el domicilio familiar (Del 13 al 18 de abril). En mi opinión, hay que valorar si a partir de mayo, el coste de trasporte de las salidas debe abonarlo ella con su asignación periódica (300€) o si se le puede seguir dando a la madre dicha cantidad cada vez que vaya a casa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-03-30','Ana: Conversación telefónica con Felisi (624 856 746), está muy convencida con la decisión de dejar la relación de Jesús. Le han regalado una perrita, "Estrella" y está muy contenta. ·· Dice que ahora su casa está más ordenada y más limpia. Ha lavado incluso las cortinas, que estaban amarillas de todo lo que fumaba Jesús y su hermano. ········· Reconoce que Jesús se quedaba y "administraba" su dinero y se lo gastaba en lo que no debía, porros y otras cosas. *Su hijo Aitor dice que ya ha perdonado a Jesús y que le ha dado su número nuevo y ella no quería, pues ahora él no deja de llamarla. *Le indico que puede bloquear el número si es su deseo. ······· En cuanto a su asignación, ya le ha explicado Virginia que podrá retirarla cada 15 días, por el cierre de la sucursal. Cuando cierren podrá acudir a Arroyo de la Luz a sacar el dinero. Ella dice que sabe ir en autobús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-03-31','Ana: Maribel, TS Secc. Acceso a RR. Discapacidad, nos trae RESOLUCIÓN DE PLAZA RAL y C.O. en la Res. Francisco de Asuar en Fuente de Cantos. ································································································································································································ Llamo a Rosa, Directora de Res. Fco. de Asuar, Fuente de Cantos (667 69 32 16 // 924 50 02 11): en relación al ingreso de Juan Carlos, me dice que tiene que informar a su equipo y organizarlo. Me pide que le llame el lunes para que me confirmen, pero el ingreso podrá llevarse a cabo el martes o el miércoles próximo. ··········· En cuanto a la pauta de medicación y otros informes, pediré a Estrella, TS del CSS-Plas. que se ponga en contacto con ella para informarle y facilitarle lo que necesite. ································································································································································································ Llamo varias veces a Estrella, TS del CSS-Plas. (24146): no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-03-31','Ana: Tras hablar con Alberto Bueso, TO del EVD de Brozas (21841), envío correo a Alberto y Óscar, Secc. Ecca: "Buenos días a los dos, En relación a Mª ÁNGELES ROSADO ALBARRÁN (Administración de Bienes) me han llamado de Dependencia, si aceptamos Prestación Vinculada al Servicio de Residencia, sólo le concederían entre 175 y 185 €, necesito que me digáis si esto sería asumible. Por otra parte, tengo que preguntar a la residencia si su deseo es permanecer en esta o si no le importa cambiar a otro centro, para solicitar plaza pública mejor. He llamado ya varias veces sin éxito. Luego volveré a intentarlo. Pues si no le importa cambiar sería relativamente rápido. Pero si quiere quedarse allí, se podría pedir las dos cosas (Vinculada y plaza pública), es decir, estaría temporalmente con la vinculada (con la cuantía que os indico más arriba) hasta que pudiera cambiarle a plaza pública en el mismo centro, abonado sólo la parte proporcional correspondiente a sus ingresos (75% contando también las P. Extras). Decidme cuando podáis. Luego os digo yo qué me dicen desde el centro." ································································································································································································· Llamo a Gema, directora de la RR.MM. Sta. Ana, Malpartida de CC (670 381 292 // 927 276 471): Hoy Gema no está. Me piden que llame mañana. ····························································································································································································· *Vuelvo a hablar con Alberto Bueso, TO-EVD (21841): La cuantía que percibía Mª Ángeles correspondía a una Prestación Vinculada al SAD, por ello ahora le consta un PAGO INDEBIDO por esta P.V. del 10/08/20 al 31/01/22. *Hasta que no recibamos la carta no hay que abonarlo. ·················· Se lo comunico a Óscar, secc. ecca.','2');
