insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-03-31','-Amalia : se acepta pto. para el traslado . TAXISTA MIGUEL GONZALEZ TF. 659762423 Se ofrece para otros traslados posibles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2022-03-31','TERESA Vamos a contratar Eugenio Guisado Guisado, es un contrato de interinidad a media jornada como auxiliar de limpieza, seguirá compatibilizando con el CO porque solo estará a media jornada. El contrato es de limpieza porque como está en el taller de CO de limpieza, ha estado aprendiendo y ahora le queremos dar la oportunidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-03-31','Ana: Llamada a Pilar Martín, consultará lo de la cita de telefónica de psiquiatría y me informará al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-03-30','Ana: Llamada de José Luis, hermano de José Manuel (687 581 061): dice que su hermano tenía programada una cita telefónica de Psiquiatría con el Dr. Enrique el día 28/03 a las 10:50 h, pero no le llamó. ···· *Mañana llamaré a Pilar Martín, TS ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2022-03-31','-Amalia : el lunes que viene Luisa tiene que pedir informe en el ESM para que pueda ingresar en R.M. Espero a recibirlo para enviárselo a sección mayores del SEPAD .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-03-28','Ana: Llamada de José Manuel, quiere que se le suba la asignación, porque dice que como se gasta todo en tabaco, no tiene para leche y otras cosas para el desayuno. *Le recuerdo que fuma demasiado y por su salud debería reducir el consumo. Ya le han ofrecido varias veces desde Salud Mental derivarle al ECA (Equipo de Conductas Adictivas) para que reduzca el consumo y se ha negado. Podríamos solicitarlo si él acepta acudir. *NO quiere. ······ Le indico pues, que cuando retire su asignación debería comprar primero leche y otras cuestiones antes que el tabaco. *Le recuerdo, que además de los suministros, abona también catering. ············· Dice que luego a las 10:50 tiene la cita telefónica con el Psiquiatra (Dr. Enrique)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-03-31','-Amalia: registro de salida el traslado de la PNC a Segovia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-03-29','Ana: Pongo para la firma la SOLICITUD DE PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-03-31','Ana: Pongo para REGISTRO DE ENTRADA LA SOLICITUD DE PNC, junto a la Firmeza de la Sentencia y el Testimonio de Aceptación del Cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-03-31','Ana: Llamada de Julia y su madre Julia (644 876 893): Solicitan un extra de 100€ para el cumpleaños de Julia, que es el día 17 de abril. *Han cerrado la sucursal bancaria de Cilleros, no han dejado ni el cajero. *Ahora tienen que ir a Moraleja a retirar el efectivo. ········ Como el lunes tienen que acudir al médico a Coria, piden poder retirarlo allí. ·············· Envío correo a Alberto, jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='CUESTA'),'2022-03-31','Ana: Emilia Almodóvar, TS del CSS Plas., remite dos presupuestos para silla de ruedas. Lourdes se encarga de verlo con Alberto, pero *NO vamos a pedir la subvención del SES porque tiene dinero más que suficiente y tiene 87 años.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-04-01','Ana: correo de ayer de Desiré, Editorial Círculo Rojo (desire@editorialcirculorojo.com): "Buenas tardes, Ana y Ceferino. El coste del Epub es de 96 euros (IVA incluido). Se trata del libro en formato digital para subir a plataformas de distribución como Amazon KDP. En cuanto al contrato, al tratarse de un servicio adicional, no podemos hacer contrato por este servicio. ¿Podría servir una factura proforma? Quedo a vuestra disposición." ················································································· Envío correo a Miguel, Asesor Jurídico CTAEX: "Ésta es la respuesta de Desiré, de Círculo Rojo, en relación a la petición del contrato y del nuevo servicio que quiere contratar Ceferino (Editar su libro en formato digital), dinos si es factible hacerlo así. En cuanto nos digas, le podemos dar respuesta a ella y Ceferino." ········································································ Respuesta de Miguel: "Buenos días Ana, lo vemos la semana que viene con Angel, ya que desconozco al completo este asunto que ha sido tratado por él."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='RECIO'and apellido2='GARCIA'),'2022-03-31','Ana: Emilia Almodóvar, TS CSS-Plas., solicita mediante correo comprar silla de ruedas para Andrea. *El presupuesto es el mismo que remiten para María Rodríguez. *Andrea tiene más que dinero suficiente y 87 años. No hay necesidad de solicitar la subvención del SES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2022-04-01','-EMAIL DEL CSS Buenos días,informamos que el paciente Juan Bautista Ramírez de la Rosa ingresó ayer en el Hospital de Mérida. La familia ha sido informada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2022-04-01','Ana: Envío correo a Estrella, CSS-Plas.: "Te reenvío de Aprosuba 3, con CITA DE OFTALMOLOGÍA relativa a Remedios Chaves Masero. ¿Sería posible que solicitaseis el cambio de domicilio en el centro de salud de referencia actual, para que las citas las reciba ahí en el Sociosanitario? Creo que en principio no hay que firmar nada, si fuera así, hacédnoslo llegar, por favor. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-04-01','Ana: Recibimos de Belén, sección de acceso a recursos de discapacidad, me comunica que el próximo lunes día 4, se puede realizar el traslado de Brahim al CAMP-Plas. ·········································· Llamo a Amor López, TS ASPACE (690 79 16 38 / 678 975 906), ya lo había comunicado Ana Marta, TS del CAMP, hace varios días. Pero están a la espera de que les manden la RESOLUCIÓN desde la Ud. de Progr. y RR. Asistenciales. ·············· Tras hablarlo con Maite, jefa de secc., envío correo a Amor: "Confirmarte que sí que hay resolución de plaza en el CAMP de Plasencia para Brahim. Pero en principio esa sólo se la tienen que hacer llegar al centro en el que se producirá el ingreso, no al vuestro. Eso sí, el mismo día que se produzca el traslado (el 4 o el 5) firmaremos la renuncia a la plaza en vuestro centro y os la haremos llegar a vosotros y a la Secc. de Acceso a Recursos de Discapacidad. Así tendréis un documento que justifique ya no ocupa una de las plazas de vuestro recurso. Ya me confirmáis el día en que se va al CAMP." ······································ Correo de Amor - ASPACE (amor.lopez@aspacecaceres.es): "El proximo lunes 4 de abril se efectuara el traslado desde la residencia de Aspace en Jaraiz de la Vera hasta el CAM de Plasencia. La salida se realizará sobre las 10.15 AM para llegar a Plasencia sobre las 11 AM. Desde la residencia de Jaraiz se ha contactado con el CAM para avisarles de la hora de llegada. Este traslado se realizará con transporte privado ya que nosotros no disponemos de transporte para el servicio de RAE. Una vez se realice les pediré la factura a nombre de Brahim y os la haré llegar para su abono. . En cuanto al dinero en efectivo del que el dispone será entregado en mano en su nuevo centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-04-01','Ana: Ante el correo de Álvaro, EUEXIA (ameuexia@gmail.com) solicitando el cambio de la salida del sábado 16 (semana santa) al jueves previo, remito siguiente correo: "Pues precisamente nos han pasado resolución de plaza para otro recurso residencial para Juan Carlos, lo hemos comunicado al Centro Sociosanitario hace unos minutos. Lo más seguro es que el traslado tenga lugar la próxima semana, por lo tanto es posible que este sábado sea la última salida con vuestra entidad. *Os pido, por favor, que no le digáis nada a él, pues hasta el lunes no le daremos la noticia. En caso de que haya algún cambio os lo comunico. Muchas gracias por vuestra colaboración. Ante cualquier cuestión, seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-04-01','Ana: Correo de Maite a Estrella, CSS-Pla: "Buenos días Estrella, Ya se ha hecho la adjudicación de plaza de Juan Carlos en el centro ‘’Francisco Asuar’’ de Fuente de Cantos. Hablamos ayer con ellos. Nos han dicho que el ingreso será el martes o miércoles de la semana que viene. El lunes nos concretarán el día exacto. Ese día hablaremos con él para decírselo. Si lo considerais oportuno, comentádselo hoy. Piden desde el centro la pauta de medicación e informes. Ta paso los teléfonos y correo electrónico de la directora, Rosa, para que os pongáis en contacto con ella: 667693216 / 924 50 02 11. cofa@fuentesdecantos.es El traslado se hace en ambulancia ¿ verdad?. Vamos hablando"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2022-04-01','miguel, envío a Escalona informe elaborado entre Amalia y yo para el procedimiento de remoción ****************************************************** contestación de Escalona: Gracias por tu informe, pero me temo que no va a valer para nada. La Audiencia ha decido fallar sin vista en el recurso. Ya veremos que deciden','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-04-01','miguel, a petición de Amalia pido por fax información al Centro Penitenciario: En relación con D. José Vicente Vicente, tutelado de esta Comisión Tutelar de Adultos de Extremadura y con motivo de su ingreso en su centro penitenciario Solicitamos que nos remitan al número de fax: 924-003194, la resolución judicial e interna que acredite el motivo de su ingreso, así como la duración del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-04-01','miguel, email de la abogada Rocio: He hablado con Damián, pero con él es todo muy difícil, me dice primero que no puede ir al psiquiatra, después que tiene que pedir cita, y ahora acabo de recibir un correo en el que simplemente me dice que es imposible. En fin, vamos a dejarlo, presento solo vuestro escrito y que sea lo que Dios quiera..... Estamos haciendo todo lo posible por que todo salga bien. Por favor, remíteme vuestro escrito firmado. ************************************************** Le remito el escrito que me remitió la abogada rectificado, firmado por el gerente ***************************************** Emails de Damian:','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-03-31','miguel, email de la abogada: Buenas tardes Miguel, Damián me ha insistido en que hablara con la psicóloga llamada Paz y la he llamado. Me dice que ellos no pueden emitir informe y que lo más conveniente es que se le pida al psiquiatra de Damián. Dime si eso es posible y si no presentamos vuestro escrito solo y ya veremos que dice el Juzgado. Quedo a la espera **************************************** email de Damian: Buenos días señor Miguel me ha pedido la sicóloga un informe del siquiatra para el tema de plantear que me pregunta la sicóloga si quiero ir a juicio o no quiero ir al juicio del día 29.pero no sé qué informe le tengo que pedir a mi siquiatra estoy perdido pregúntele a Amalia si hace falta que yo le pida un informe al siquiatra o no y contacte por favor con rocío para a ver qué hago ******************************************* miguel, tras consultarlo por email a Amalia, me contesta: “Damián puede solicitar él directamente el informe , ya tiene toda la información para hacerlo” ************************************************* me escribe Damian: Pero yo ya no tengo que solicitar nada no? Si rocío me ha dicho que ya ella se encarga de todo que no hace falta que pida el informe ******************************************************* le contesto:Lo que diga Rocio, si se encarga ella usted no tiene que pedirlo. ******************************************** me vuelve a escribir damian: No puedo pedir el informe al siquiatra que le parece la idea si me presento yo al juicio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-03-31','miguel, email de la abogada: Buenas tardes Miguel, Damián me ha insistido en que hablara con la psicóloga llamada Paz y la he llamado. Me dice que ellos no pueden emitir informe y que lo más conveniente es que se le pida al psiquiatra de Damián. Dime si eso es posible y si no presentamos vuestro escrito solo y ya veremos que dice el Juzgado. Quedo a la espera **************************************** email de Damian: Buenos días señor Miguel me ha pedido la sicóloga un informe del siquiatra para el tema de plantear que me pregunta la sicóloga si quiero ir a juicio o no quiero ir al juicio del día 29.pero no sé qué informe le tengo que pedir a mi siquiatra estoy perdido pregúntele a Amalia si hace falta que yo le pida un informe al siquiatra o no y contacte por favor con rocío para a ver qué hago ******************************************* miguel, tras consultarlo por email a Amalia, me contesta: “Damián puede solicitar él directamente el informe , ya tiene toda la información para hacerlo” ************************************************* me escribe Damian: Pero yo ya no tengo que solicitar nada no? Si rocío me ha dicho que ya ella se encarga de todo que no hace falta que pida el informe ******************************************************* le contesto:Lo que diga Rocio, si se encarga ella usted no tiene que pedirlo. ******************************************** me vuelve a escribir damian: No puedo pedir el informe al siquiatra que le parece la idea si me presento yo al juicio *************************************** le vuelvo a contestar: lo que le diga Rocio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-04-01','Ana: Llamada de Guadalupe, TS del SAD del IMAS (927 212 335 / Ext. 4422), Ventura viene recibiendo el servicio de SAD 1 día/semana (total de 2 h). Dadas las dificultades que presenta Ventura y que ya no convive ni mantiene relación con Mª Ángeles, quien ayudaba a tener la casa más limpia, consideran necesario ampliar el servicio al menos 1 día más a la semana (otras dos horas). *Me enviará la propuesta por emial y si económicamente es viable, se aceptará y ampliará el servicio. *La Aux. también se encargará de prepararles comidas para varios días, es diabético y no está cuidando su alimentación con el riesgo que para él conlleva. *El precio del servicio es de 9,30€/h. ····· El SAD es prestado por empresa externa: EULEN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-04-01','Ana: Llamo a Gema, directora de la RR.MM. Sta. Ana, Malpartida de CC (670 381 292 // 927 276 471): no está. *Me dicen que vuelva a llamar el lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2022-04-01','Ana: Correo de Cristina Castro, Ed. Asoc. Vera (educadorasocial@asociacionvera.com), envía documento para firma: "...Desistimiento de solicitud de reconocimiento del grado de dependencia, se solicita esta firma ya que Mª del Carmen tiene reconocido un Grado I desde el 2019, se solicitó la revisión y la técnico nos expuso que si se aceptaba este último reconocimiento iba a empeorar su evaluación y por ello era más conveniente desestimarla y prevalecería el reconocimiento anterior."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='MORENO'and apellido2='REY'),'2022-04-04','-Amalia : rgto. solicitud de cambio de perfil del VT a RAL enviada por el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='MORENO'and apellido2='REY'),'2022-04-04','-Amalia : rgto. solicitud de cambio de perfil del VT a RAL enviada por el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='NOGALES'and apellido2='MUÑOZ'),'2022-04-04','-Amalia : le paso a Oscar el cobro indebido de PNC para reclamarlo a la entidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-04-04','Ana: Tras hablar con Gema, Directora de la Res. Malpartida Plas. (670 381 292 // 927 276 471). Envío correo a Alberto Arias, EVD (alberto.arias@salud-juntaex.es): "Buenos días Alberto, En relación a Mª ÁNGELES ROSADO ALBARRÁN, hasta hoy no he conseguido hablar con Gema, Directora de la Res. Me pide de plazo hasta el miércoles para hablar con ella y que entienda que no puede asumir el gasto que le correspondería de la plaza privada que ocupa, aún percibiendo la prestación vinculada. Pues además tendrá que hacer frente a la Deuda por el cobro indebido de la anterior prestación. La idea es que acepte la plaza pública en El Cuartillo. En cuanto me confirmen el miércoles, recabo la firma y pongo para registro. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-03-30','Ana: Correo de Alberto: "Hola a todos. En relación con Felisa Felipe Teomiro, de Navas del Madroño, e Isabel Muñoz Melchor, de Torrecillas de la Tiesa, nos encontramos con que estas 2 tuteladas no van a disponer de oficina bancaria para los reintegros. Desde Liberbank nos informan que van a dejar cajeros automáticos en esas 2 localidades. X tanto nos vemos obligados a tramitar TARJETAS PREPAGO para ellas. OSCAR: continúa con la tramitación para la obtención de las tarjetas y también con el aprendizaje de recarga, reemisión, comunicaciones extravío, olvido PIN (reactivación tarjetas). ANA: Desconocemos cuanto tiempo llevará el dar de alta el uso de estas tarjetas, pero cuando lo consigamos, tendrá que haber un período de adaptación y enseñanza por parte de FUTUEX. ANA: UNO de los problemas (hay varios), es que en este caso no hay reintegros permanentes como hasta ahora...tenemos que hacer la recarga manual cada vez que hace un reintegro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2022-03-30','Ana: Correo de Alberto: "Hola a todos. En relación con Felisa Felipe Teomiro, de Navas del Madroño, e Isabel Muñoz Melchor, de Torrecillas de la Tiesa, nos encontramos con que estas 2 tuteladas no van a disponer de oficina bancaria para los reintegros. Desde Liberbank nos informan que van a dejar cajeros automáticos en esas 2 localidades. X tanto nos vemos obligados a tramitar TARJETAS PREPAGO para ellas. OSCAR: continúa con la tramitación para la obtención de las tarjetas y también con el aprendizaje de recarga, reemisión, comunicaciones extravío, olvido PIN (reactivación tarjetas). ANA: Desconocemos cuanto tiempo llevará el dar de alta el uso de estas tarjetas, pero cuando lo consigamos, tendrá que haber un período de adaptación y enseñanza por parte de FUTUEX. ANA: UNO de los problemas (hay varios), es que en este caso no hay reintegros permanentes como hasta ahora...tenemos que hacer la recarga manual cada vez que hace un reintegro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='MORENO'and apellido2='REY'),'2022-04-04','-Amalia , entrego a Julio cambio de perfil para rgto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2022-04-04','-Amalia : se envia con acuse de recibo empresa ASINDE contrato .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-04-04','Ana: Llamada de Felisi (624 856 746): Jesús quiere volver con ella, está intentando convencerla, dice que no quiere volver con él, pero que le da mucha pena y no sabe qué hacer. Como sigue exponiendo argumentos negativos, le digo que ella misma se está dando la respuesta, sabe que no le conviene y como ella misma dice "no le viene bien". ·········· En cuanto a la visita de su hijo en semana santa, estamos de acuerdo en que es muy precipitado que vaya con su "novia" a pasar la semana, pues llevan menos de un mes juntos y apenas se conocen, sobre todo hablan a través del móvil, pero no se ven mucho. ··········· *Teresa, TS CTAEX, hablará con la directora de Adiser al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2022-04-04','TERESA Claudia, T.S del C.R El Cuartillo de Cáceres. Te informo que la sobrina de D. Carmelo Gracia Redondo nos solicita poder realizar periodo de vacaciones, en concreto quiere que se ausente desde el miércoles 13/ 04/2022 al lunes 18/04/2022, coincidiendo con Semana Santa. Pensamos que es positivo para el residente, y por nuestra parte lo vemos favorable. SE AUTORIZA LA SALIDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-04-04','Ana: Llamada de Rosa, Directora de la Res. Fuente de Cantos (667 693 216): dice estar muy preocupada, pues la Psicóloga de su centro ha hablado con Maripaz, Psicóloga y Coord. de la UHDAC y le han contado todos los problemas y alteraciones de conducta que ha presentado con anterioridad así como su condena de 10 años en prisión por agresión a personal de un centro. Entiende que en su centro no pueden atender a este perfil. ·········· Maite, Jefa de Secc. CTAEX, se incorpora a la conversación a mitad de la misma. Ambas le indicamos y reiteramos que aunque entendemos la preocupación, cuando le dan el alta en el CSS es porque está estable, que desde la CTAEX no adjudicamos la plazas, no depende de nosotras y que en cualquier caso, es algo que tendrían que hablar con Soraya Masa, Jefa de U.PP.AA. ······································································································································································································ Ana y Maite: Llamada a Juan Carlos, le comunicamos que el jueves se irá ya a un centro. Se emociona y se pone muy contento. Pregunta si podrá jugar al futbol allí, le digo que hará actividades deportivas, no sabemos exactamente cuáles y que hay un gran huerto con invernadero, hecho que también le alegra mucho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2022-04-04','TERESAMe pongo en contacto para consultarte la posibilidad de que Beatriz Muñoz fuese a casa en Semana Santa. La salida de Navidad resultó positiva y todo fue según lo previsto. Te planteo hacerlo de la misma manera que en Navidad: Se puede ir en tren con un compañero suyo de residencia (El chico va a Plasencia y Bea se bajaría en Cáceres) y su padre estaría allí esperándola con un taxi y el regreso sería de la misma manera: Su padre la llevaría en taxi hasta Cáceres y cogería el tren donde viene su compañero. El chico se va desde el día 7 hasta el día 18. Son muchos días, pero para que vaya acompañada en el tren sería la mejor opción. Ya me dices qué os parece y si creéis que son muchos días podemos ver la posibilidad de que se venga antes, pero supondría que se viniera sola en el tren, que tampoco habría problema puesto que no tiene que hacer trasbordo, es tren directo desde Cáceres a Llerena Te agradezco que me lo confirmes lo antes posible para organizarlo todo SE AUTORIZA UNA SEMANA HARA EL VIAJE DE VUELTA EN TREN ELLA SOLA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-04-04','miguel, remito a Tere nombramiento de la abogada de oficio Paula Ruiz Muñoz del Colegio de Abogados de Badajoz, tlfno 924801289, para su remisión al centro de la tutelada','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2022-04-04','Ana: Envío a Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com) documento de Ausencia Voluntaria, relativo a Antonia, firmado digitalmente por el Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2022-04-04','Ana: Pongo para REGISTRO DE ENTRADA el documento de Desistimiento de solicitud de reconocimiento del grado de dependencia.','2');
