insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='NOGALES'and apellido2='MUÑOZ'),'2022-04-04','NOS REMITEN RESOLUCIÓN PNC SOLICITANDO DEVOLUCIÓN COBRO INDEBIDO X 2.200,16 € SE HABLA CON CENTRO Y VAN A DEVOLVER EL MISMO IMPORTE A TUTELADO PARA QUE PODAMOS ABONAR DEUDA. OSCAR: TRATMITA. OSCAR YA REGULARIZA EL PAGO CENTRO AL 75 % DE LAS PENSIONES A PARTIR DE 04/2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2022-04-04','Ana: cumplimento y recabo firma de los siguientes documentos: - Comunicación de cambio de datos en el expdte. de Dependencia (cambio de cuenta de domiciliación bancaria) y Modelo para Alta de Terceros. ························ *Entrego a Icíar, secc. ecca., el Alta de Terceros para que lo lleve al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2022-04-04','Hola AMALIA. Económicamente es viable ya que tiene los ahorros de 11.000 € aprox., PERO NO ES UNA SITUACIÓN A MANTENER. OPINIÓN ECO: COMO MUCHO Y SI ÁREA SOCIAL LO VE ADECUADO, PODRÍAMOS EXTENDER ESTANCIA EN LOS OLIVOS DURANTE EL MES DE MAYO. Se queda 1 mes más en la RM y luego regresará a CRR .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2022-04-04','Hola AMALIA. Económicamente es viable ya que tiene los ahorros de 11.000 € aprox., PERO NO ES UNA SITUACIÓN A MANTENER. OPINIÓN ECO: COMO MUCHO Y SI ÁREA SOCIAL LO VE ADECUADO, PODRÍAMOS EXTENDER ESTANCIA EN LOS OLIVOS DURANTE EL MES DE MAYO. Se queda 1 mes más en la RM y luego regresará a CRR .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='LOZANO'and apellido2='PASCUAL'),'2022-01-19','Ana: Llamada de Mariví Clemente, TS CSS, comunica que el día 17 por la tarde Mª Carmen ingresó en el HVP-Plas. en estado semi-comatoso. Tuvieron que ponerle una sonda nasogástrica. Firmó el C.I. Pilar del Río, la Directora del CSS. *A día de hoy está mejor, pero ya no ha consentido en que le hicieran otras pruebas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='LOZANO'and apellido2='PASCUAL'),'2022-04-04','Ana: Envío correo a Emilia, TS CSS-Plas.: "Quería preguntarte por cómo sigue Mª del Carmen Lozano Pascual. En su día, me comunicó Mariví que le habían ingresado en el hospital y que le habían puesto una sonda nasogástrica, la evolución días después fue positiva, pero no he vuelto a preguntaros. Ya me dices cuando puedas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-04-04','Ana: Correo de Alberto, jefe secc. ecca., en relación a la edición del libro de Ceferino en formato digital: " En mi opinión x 95 € podemos abonar la factura sin más" ·············· Respuesta de Miguel, Asesor Jurídico: "al ser un tema que ha estado viendo Angel, mi opinión es que lo siguiera viendo él, que seguramente el jueves esté por aquí. Ahora bien, es cierto que 95€ no son nada y que si tiene dinero, desde nuestra parte no hay problema" ··············· Respuesta de Alberto: "QUE NOS PASEN LA FACTURA...SE LA DAS DRIECTAMENTE A LOURDES PARA QUE LA ABONE"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-04-05','Ana: Envío correo a Desiré, Editorial Círculo Rojo (desire@editorialcirculorojo.com): "Buenos días Desirée, Desde la sección económica se acepta el presupuesto que nos indicas para la edición del libro de Ceferino en formato digital. Podéis remitirnos la factura proforma con el número de cuenta para que la compañera haga el abono del mismo y a posteriori la factura. Ante cualquier cuestión, no dudes en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-04-04','Ana: Correo de Toni-Futuex, con información sobre el primer seguimiento realizado por la Ed. y la TS, de Programa de Apoyo comunitario: Juan José acepta el seguimiento. ···· "Comenta que no acudió a la última cita de salud mental porque se quedó dormido, se justifica diciendo que la inyección lo deja dormido un tiempo; se le dice que puede afectarle el día de la puesta y al día siguiente, pero no durante una semana, pues va regulado… Se le dice que se acudirá a salud mental y se consultará por su cita o se pedirá una nueva, acepta; así se hace y proporcionan cita para el día 9 de mayo con el psiquiatra." ··· "Juan José pide ir al podólogo y al dentista. En cuanto al podólogo solicita que pueda ser gratuito, se le dice que se consultará a ver qué opciones tiene, aunque no es un servicio con un coste elevado. Con respecto al dentista, al no tener discapacidad intelectual, según indica, no puede beneficiarse del PADDI, pero se le dice que sí hay coberturas que corren por cuenta de la seguridad social, las cuales se pueden aprovechar y después ya pedir presupuesto a una clínica privada. El tutelado está de acuerdo con todo lo que se le expone, a lo cual empezó a demandar que se le hiciese todo, se le dice que se le ayudará y acompañará, pero será partícipe, no se le va a llevar todo resuelto a casa." ··· "Durante la conversación de la visita y por comentarios que, después, hace la madre, se comprueba que Juan José mantiene un consumo activo" ··· "la vivienda está sucia, a pesar de que el día anterior, según cuenta y después verifica su madre, estuvo allí para ayudarle a adecentarla para recibir la visita. La dependencia que peor está es la cocina, hay mucha suciedad acumulada incluso por los baldosines de la pared." ··· "Se aprovecha para proponer el S.A.D. como apoyo" y acepta. ··· "En cuanto a su gestión económica, es una parte en estado deficitario, pues no tiene control alguno de su economía diaria y se duda que sea capaz de cubrir sus necesidades básicas sin pedir ayuda a su madre; hecho que afirmó su hermana, durante la conversación del día 31, indicó que suele exigir a su madre que le dé dinero y ésta cede" ··· "acabó señalando que se había pegado unos días de fiesta por si en la visita se le quitaba el dinero… Se le explica cómo se gestionará su economía a partir del momento que se intervenga su cuenta y sus tutores legales comiencen a hacer efectiva la tutela." ··········· Envían también aproximación de gastos para establecer presupuesto desde la CTAEX. ······· "Las relaciones sociales de Juan José en su entorno más cercano, barrio y demás, no son adecuadas, como era de esperar, se relaciona con personas con consumo activo, sin actividad laboral, prácticamente y con una vida basada en deambular." ···· En cuanto a la actividad en la Universidad, "cuenta que se trata de la Asociación SOL (Smart Open Lab)" (una red de espacios de laboratorio y fabricación que pone a disposición herramientas y conocimientos para crear proyectos y dar solución a problemas de la vida diaria. *Juan José facilita a la educadora el número de teléfono de uno de los profesores, para que pueda facilitarle más información al respecto. *A Juan José le viene muy bien la asistencia a dicha asociación, le mantiene ocupado y motivado. ······························································································································································································ Envío correo a Alberto, Jefe secc. ecca., con estimación de gastos y propuesta de asignación, así como transferencia a la madre para abonar suministros y seguros (hogar y decesos). ······························································································································································································· El próximo día 7 a las 10:40 h, han citado a Juan José en el INSS, en el "Organismo Extranjero", para un RECONOCIMIENTO MÉDICO. ··· Llamo al INNS, a P. Orfandad (927 62 00 56): el expte. es el nº: 10/2022800186. *Enviaré a Control de Pensiones la Comunicación de cambios de circunstancias por Remoción y nombramiento de nuevo tutor. ··· Tiene que pasar por EVI (Equipo de Valoración de Incapacidades) Tlf. EVI, Alfonso Galán: 927 62 08 89 / Pedro Duran - Jefe Secc. 927 62 00 54 / Carmen 927 62 08 63. ··· Llamo al EVI varias veces a los distintos números sin éxito. ············ Paso a Julio, Aux. Admvo. CTAEX, para que dé REGISTRO DE SALIDA y envíe, la comunicación al INSS de remoción del cargo y aceptación por parte de la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2022-04-05','Ana: Envío correo a Cristina Castro, Ed. Soc. Asoc. Vera (educadorasocial@asociacionvera.com): "Adjunto remito el documento de Desistimiento de Solicitud de Reconocimiento de la situación de Dependencia, relativo a Mª del Carmen Mellado Guardabrazos, ya registrado, para que lo tengáis en su expediente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2022-04-05','miguel, remito email a Loli de la notaria de Herrera del Duque, porque seguimos pendiente de que nos remita la declaración de herederos: Buenos días Loli, necesitamos nos confirmeis si fue firmada la declaración de herederos de Juan Felipe Rodriguez Montalban con nif 02884173L, en cuyo caso necesito me la remitas. Caso contrario indicame qué necesitas pues necesitamos preparar la herencia. ***************************************************** Remito email a Estefanía la abogada para saber cómo van los trámites de herencia, alquiler del piso de Madrid, etc: Comentarte que debemos retomar el expediente donde lo dejamos. Hay que preparar las herencias de los hijos y para ello necesitamos en primer lugar confirmar con la notaria de Herrera del Duque si finalmente se firmó o no la escritura de declaración de herederos (a mi no me contestan, por si tú puedes averiguar algo) y una vez lo cual se firme la escritura notarial de adjudicación notarial (en mi opinión debería ser en la misma notaria a ser posible para agilizar), y paralelamente habrá que tramitar la autorización de aprobación y aceptación judicial de la herencia y la autorización de venta del piso de Madrid (había comprador finalmente?). El tema del desembolso quedó algo de Doña Alfonsa? La cuenta donde se percibe el alquiler está controlada? Necesitaríamos saber como ya hablamos si está controlado los gastos e ingresos y si Doña Alfonsa puede recibir alguna cantidad. ************************************************** Respondo por email al email de Alberto (para Iciar, Teresa y yo) Buenos días, en la intranet está todo apuntado. La abogada de la otra parte Estefanía, ya liquidó el impuesto de sucesiones del hijo Juan Felipe (su exmujer es con quien nuestra tutelada tiene compartido el usufructo de los bienes), pero la mujer tuvo otro hijo que falleció Agustin y del que para poder tramitar la herencia y las posteriores autorizaciones judiciales de aceptación y aprobación de herencia e incluso la autorización para una posible venta del piso de Madrid (que está alquilado y hay un inquilino interesado en la compra). Como digo todo está bloqueado hasta que no tengamos la declaración de herederos del hijo fallecido Agustin, una vez lo cual se hará la herencia de ambos hijos a favor de nuestra tutelada Alfonsa… "He remitido un nuevo email a la notaria de Herrera del Duque para que me diga si está o no firmada la herencia (caso de no, el porqué) Y otro email a la Abogada de la otra parte (que también nos ha gestionado nuestra liquidación de impuesto de sucesiones y la reclamación al tanatorio del importe pagado, que ya lo reembolsaron y hubo que transferir, no recuerdo si el total a la cuenta que nos indicó la abogada Estefanía…), para que hable con la notaria y agilice la firma de la declaración de herederos y la escritura de herencia de los dos hijos fallecidos (Juan Felipe y Agustin)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2022-04-05','email de Alberto a Tere, Iciar y a Miguel: TERE: ANTES DE DECIDIR SI ASUMIMOS MÁS GASTOS HAY QUE TENER EN CUENTA QUE, DESDE HACE UNOS MESES CAMBIO A CENTRO CK SENIOR GE Y EL IMPORTE DEL MISMO SUBIO HASTA LOS 1.465,5O €/MES...VAMOS A MANTENER ESTE CENTRO??? SUS INGRESOS SON DE 1.260,33 € X 14. TERE: NECESITAMOS SABER SI LOS MESES DE PAGA EXTRA EL IMPORTE DE LA PLAZA ES DOBRE...EN ESTE CASO GASTOS SERÍAN MUY SUPERIORES A INGRESOS Y NO PODRÍAMOS AFRONTAR NADA MAS TERE: DESPUÉS DE AVERIGUAR ESTO Y LO SIGUIENTE: DECIDIMOS LO DE LOS PERROS Y LIMPIEZA MIGUEL: EN INFORME SOCIAL INVENTARIO INDICA QUE TUTELADA TIENE VIVIENDA EN MADRID (C/ CERRO DEL CASTAÑAR, 145, 4ºD MADRID) CON MUCHO VALOR: NO ESTA RECOGIDA EN INVENTARIO ...SÓLO EL 50 % DE UNA VIVIENDA EN TALARRUBIAS ICIAR: NO TENEMOS CLAVES DE LA OTRA CCC EN BBVA---ES URGENTE QUE OBTENGAMOS CLAVES Y, COMO MÍNIMO, MOVIMIENTOS ULTIMO/S AÑOS---TEN EN CUENTA QUE HAY DOMICILIACIONES EN ESA CCC (OAR, OTROS...) PERO NO HAY INGRESOS----TERE, EN BBVA PUEDE HABER GASTOS QUE HAGAN INCOMPATIBLE EL PERMANECER EN UN CENTRO TAN CARO. ICIAR: AVERIGUA LO DEL PAGO DE LA FUNERARIA Y EL RESUMEN INCLÚYELO EN LA FICHA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2022-04-05','Ana: Llamada de Juan José (667 958 878): ayer le hicieron una resonancia de la rodilla, ahora hay que esperar los resultados. ··· Dice que está intentando cuidar la alimentación todo lo posible. ··· Las analíticas ya no se las van a hacer todas la semanas, le irán llamando cuando correspondan. ···Por otra parte, Pedro, TO, ha enviado a la CTAEX el presupuesto para las mancuernas que quería.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-04-05','miguel, recibo llamada de la asesoría-despacho de abogados Loli-Carmen (nos recomendaron la Gestoria Garcia Reviriego), con teléfono 924671553 e email de Carmen carmen.afiex@telefonica.net. ******************************************* Hablo con Carmen y quedamos que en cuanto tenga la declaración de herederos se la envíe para iniciar los trámites, pero que vaya adelantandola documentación para estudiarla. *************************************** Hablo con la Cam de Don Benito para decirle a Tony que hable con la trabajadora social que en su día llevó a Francisco Rangel Porro para que me consiga dos testigos y poder firmar en la notaria de Don Benito la declaración de herencia de Francisco *********************************************** Remito email a Marisa de la notaria de Don Benito y mando email a Amalia comentandoselo (porque hará falta que vaya Eulalia a firmar a la notaria llego el momento)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2022-04-04','-Amalia : vamos Mayte y yo al CRR para hablar con ella con respecto a la peticion de plaza residencial . Escribo a Mª Luz Madrigal y May : Buenos días , se adjunta el informe médico de LUISA RODRIGUEZ GRAGERA que nos solicitó Raquel ( Sección Salud Mental del SEPAD ) para solicitar cambio de PIA y trasladar de plaza de CRR a ingreso en R. Mayores. Como os dijimos no se renuncia a la plaza y se limitará a plaza residencial en ciudad de Mérida y/ o Almendralejo por acercamiento familiar . El marido vive en Calamonte. May desconocía este expediente , le informo a través de este email para que cuando la pase a lista de espera sólo sea para esas dos ciudades. Por favor índicanos si tenemos que especificarlo en alguna solicitud. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-04-05','Buenas tardes, nos ha llegado esta resolución de la concesión de plaza T3 a DAVID ESTEVEZ FELIPE en nuestro centro. En dicha resolución aparece el precio público establecido(438,53€). Os la envío para que tengáis constancia. María Martín Rivero Trabajadora social. Encinar de las Cruces Nº COL. 07-1209 924 81 25 99/ 618 95 70 59 -------------------------------------------------------- Cargarán el precio de la plaza y los gastos personales ( de momento ninguno pq no hay dinero ahorrado ) en la cuenta directamente . Enviarán el modelo 50 . Está pendiente gestionarle un seguro de decesos pero hasta que no pasen un par de meses que ahorre algo no se puede abonar . La cuenta tras el pago del taxi para el traslado se ha quedado en muy pocos ahorros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-04-05','-Amalia , envio email a Julio y Tere. Buenos días , David ha sido trasladado el día 1 de Caser Olivenza a plaza sociosanitaria en R. Mayores del Encinar de las Cruces en Don Benito . Avda. Cánovas , paraje Lagunilla S/ N . Durante este mes sigo yo con todo el proceso de adaptación y cambios al nuevo centro , luego pasará a la zona de seguimiento de Tere. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-04-05','-Amalia , envio email a Julio y Tere. Buenos días , David ha sido trasladado el día 1 de Caser Olivenza a plaza sociosanitaria en R. Mayores del Encinar de las Cruces en Don Benito . Avda. Cánovas , paraje Lagunilla S/ N . Durante este mes sigo yo con todo el proceso de adaptación y cambios al nuevo centro , luego pasará a la zona de seguimiento de Tere. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-04-05','Hola Amalia, David se está adaptando bien, es muy amable y le gusta conversar con el compañero. Le vemos tranquilo. No os preocupéis, la cuota mensual se pasa a mes vencido por su cuenta bancaria, a través de un modelo 050 que yo os iré enviando para que llevéis el control de los pagos. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2022-04-05','-Amalia , he pedido a la Dtra. de la R.M que solicite informe de prescripción del médico y solicitud para pedir reembolso por los gastos de la silla de ruedas .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2022-04-05','Amalia : envío email a sección eco para que paguen a ASINDE 248€,14 . Tienen que hacer un copago pq de dependencia le abonarán 189€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-04-05','miguel, recibo email de la abogada Carmen Lucas: Miguel, te mandé la carta que remití a la asistente social del centro penitenciario, dando todo tipo de explicaciones y facilitandole mi telefono para que me llamen, no sé si la has visto porque no me has respondido y yo te he llamado muchas veces y nadie descuelga. Ahora me viene como ves, devuelto el acuse de recibo de la asistente social, que lo ha borrado sin leer. Si esto es así, se me bloquean las posibilidades de hablar con el recluso y darle mis datos para que me llame, lo he hecho por escrito, y le digo hora y telefono para que me llamen, no puedo hacer más. Dime si recibes este mail, e indícame cómo lo hacemos, porque la asistente social, borra mis mails directamente. ****************************************************** Mi contestación: Buenas tardes, disculpa pues no paro en la oficina. Comentarte que desde la Comisión no sabemos nada al respecto por lo que viendo el email que le remitiste, si está interesado en llamarte Saturnino, entiendo que queda acreditado tanto tu representación como tus datos de contacto. Si me entero de algo te aviso inmediatamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2022-04-05','TERESA RECIBO LLAMADA DE CRISTINA TRABAJADORA SOCIAL DE MENSAJEROS DE LA PAZ EN REALACION A ANTONIO PUES TIENE CONTACTO CON SU HERMANA COMENTA QUE NOTA A SU HERMANO TRISTE PUES ES MUCHA LA DISTANCIOA QUE LOS SEPARA PUES ELLA RESIDE EN BADAJOZ LE GUSTARIA QUE SU HERMANO FUERA TRASLADADO A UN CENTRO A BADAJOZ ME FACILITA EL TELFNO DE ELLA, SE LLAMA SANDRA Y ME PIDE QUE ME PONGA EN CONTACO CON ELLA TELEFN: 654758547','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2022-04-04','TERESA Mª Antonia se irá el jueves 7 de Abril hasta el lunes 18. Estará en Zafra','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='MARTINEZ'and apellido2='VAZQUEZ'),'2022-04-04','TERESA Concepción se irá el lunes 11 de Abril hasta el lunes 18. Estará en Jabugo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2022-04-04','TERESA He estado hablando con la trabajadora social de los SSB de Zafra. M.Antonia tal y como te comenté, estuvo allí para solicitar traslado a Plena Inclusión Zafra. Ya informé de que es su decisión y que desde el centro la apoyamos en la solicitud del traslado. La han vuelto a citar para que firme la solicitud el jueves, 7 de Abril a las 10.30h. Sería conveniente que la acompañase Susana de Futuex para así verificar la información que ella de.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-04-06','miguel, recibo email de la abogada Carmen Lucas: Me devuelve el mail la asistente social, no lo lee ¿Puedes reenviárselo? **************************************************** Reenvío email a Rosario del Centro Penitenciario (rosario.hernandez@dgip.mir.es): Buenos días Rosario, soy Miguel, compañero de Ana Matamoros de la Comisión Tutelar de Adultos, a petición de la abogada de Saturnino reenvío sus emails porque según comenta, parece ser que no llegan. En su día, ella remitió tanto su representación como sus datos de contacto para que el interno se pusiera en contacto con ella sin que a fecha de hoy se sepa porqué no lo ha hecho después de que fuese solicitado por él. **************************************************** Reenvío email a la abogada Carmen Lucas: Buenos días, adjunto debajo la remisión de email a Rosario del Centro Penitenciario. Si hay cualquier novedad te informaré.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-04-04','miguel, email de Alberto: EMBARGO 2021-10-06 2021-10-06 EMB. JUDICIAL 28972681H-JUZ.EMB.MECAN. -1152,8 399,2 MIGUEL: HAY QUE AVERIGUAR DE QUE DERIVA ESTE EMBARGO JUDICIAL Y SI TIENE MÁS DEUDAS PENDIENTES. TIENE COMO INGREOS UNA PRESTACIÓN X HIJO A CARGO Y UN SALDO HOY DE 1.000 €/APROX....UN DESASTRE. ********************************************** Le reenvío el email que en su día pregunté al Juzgado el 2-12-21: Buenos días, según conversación de ayer con el Juzgado de Coria nº1 me confirma que la deuda que se le embargó el 6-10-21 de Julia Moron Hernández corresponde a la ejecución judicial 35/19, es decir de 1 año antes a que fuera aceptado nuestro cargo de tutores por remoción a los padres. El origen de esa deuda era un préstamo con Cofidis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-04-05','miguel, reenvío a Marisa (marisa@notariadonbenito.com)notaria de Don Benito) de la documentación para que prepare para el 21-4-22 la declaración de herederos: Buenos días, necesito firmar el día 21 a las 11h la renuncia de declaración de herederos de D. Juan Carlos Rubio Galán. Asismismo necesito firmar y que tengas preparada ese día y hora la declaración de herederos de Francisco Rangel Porro (iré con su hermana, tutelada por la Comisión Tutelar de Adultos y cuya documentación te adjunto, sentencias de incapacitación y nombramiento a la Comisión Tutelar de Adultos y certificado de defunción y últimas voluntades del hermano fallecido, Francisco Rangel Porro. Verás que falleció en la Camp de Don Benito, y estoy pendiente de que me indiquen los dos testigos para dicha firma). En cuanto sepa el nombre y dni de los dos testigos te lo indico. Cualquier documento que necesites original o no indícamelo vía email lo antes posible por aquí para llevarlo preparado. Llevaré la firma legitimada de nuestro Gerente (Vicepresidente de la Comisión Tutelar de Adultos) que nos va a hacer la notaria de Romero Leal. Necesitamos que tengas todo preparado ese día y hora ya que a las 12h tengo que firmar la venta que está preparando tu compañero Rafael de D. José Luis Murillo Horrillo. **************************************************** Remito email a Amalia para que la tutelada acuda a las 10,30h el 21-4-22 para la firma de la declaración de herederos: Buenos día Amalia, ya he enviado a la notaria de don benito petición día de firma y hora 21-4-22 a las 11h, pero quiero que esté allí Eulalia Rangel Porro a las 10,30h para firmar la declaración de herederos de su hermano Francisco que falleció en la Camp de Don Benito en 2020 Ya tengo en una asesoría-despacho de abogados el encargo para que lo tramiten todo(puedes verlo en la intranet) Necesito por tanto que el 21-4-22 a las 10,30h alguien acompañe a Eulalia. Ya he hablado con la Camp de Don Benito para que me digan los dos testigos y acudan ese día a esa hora. ******************************************************** Por teléfono hablo con Montserrat de la Camp de Don Benito para que me remitan los datos de los 2 testigos de la declaración de herederos (para remitirselo a la notaria) y para decirle que el 21-4-22 esten en notaria los testigos para firmar dicha declaración de herederos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-04-06','Ana: Llamo a Toni, Futuex: José sigue buscando otro alojamiento alternativo con el apoyo de la Ed. pero de momento tendrá que seguir en el hostal, aunque sea más caro, pues no encuentran pensión adecuada con plazas disponibles. *Consideran necesario comprar una nevera para poner en su habitación, pues en el catering contratado no entran las cenas ni el desayuno. *Enviarán correo con información y presupuesto. ························ Confirmo a Lourdes, secc. ecca. que es necesario comprar la nevera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-04-06','Ana: Conversación con Toni-Futuex: La intervención con Ángel Félix está resultando muy difícil. Sólo quiere dinero y hay muchos indicios de su consumo de tóxicos. *En otras ocasiones ha estado incluso en comunidades terapéuticas, pero en la actualidad no reconocer su consumo activo y tampoco acepta acudir al ECA (Equipo de Conductas Adictivas). *Enviarán informe al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-04-06','Ana: llamada de Felisi, el mismo discurso de los días previos. Está contenta con que vaya su hijo a casa en semana santa. Jesús sigue llamándola e insistiendo y que le agobia. Le indico que lo más sencillo es bloquear su número para que no le entren las llamadas. *Hoy irán a visitarla del programa de familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2022-04-06','email de Alberto: ICIAR: SE PONE EN CONTACTO CON BBVA Y SACA TODA INFORMACIÓN POSIBLE SOBRE MOVIMIENTOS Y SOBRE RECIBOS (MÁXIMA INFORMACIÓN POSIBLE) MIGUEL: A MIGUEL SE LE PASA ESA INFORMACIÓN E INTENTAREMOS PASAR ESOS GASTOS A CCC DE LA MASA HEREDITARIA QUE FORMALIZO NUERA TUTELADA A INSTANCIAS DE SU ABOGADA. TERE: IMPORTE PLAZA + ACLARAR SI INCLUYE O NO LAS PAGAS EXTRAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-04-05','Ana: Llamo a Ana Marta, TS del CAMP-Plas. (21661): De momento Brahim está muy bien. Ha dormido bien y por lo que ven hasta el momento creen que no es conflictivo. Es muy inquieto, hay que estar muy pendiente de él y ayudarle a estar calmado y a que coma despacio, pero por lo demás, no hay ningún problema, creen que allí va a estar muy bien. *Hoy le han llevado a la sala multisensorial con Gemi-Psicóloga, y le ha visto a gusto y relajado. ·················· En cuanto al dinero en efectivo que llevaba de ASPACE (lo que les sobró), lo usarán para gastos de bolsillo y peluquería, que aún la cobran en efectivo. ············· **Desde la CTAEX se le realizará una autorización de retirada de efectivo a Palmira, Directora del Centro, al igual que con el resto de residentes cuyo cargo ostenta la CTAEX. ·············· **En cuanto a su documentación y los trámites de EXTRANJERÍA, me enviarán copia del pasaporte, y por las fechas de expedición y visado del mismo, es posible que puedan renovarlo en Madrid.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='MARQUEZ'and apellido2='CABEZA'),'2022-04-04','REVISION PIA PARA PLAZA RESIDENCIAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2022-04-06','miguel, hablo con la notaria de Herrera del Duque, y quedan en pasar el recado a Loli para me indique qué falta para firmar dicha declaración de herederos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2022-04-06','miguel, pedi ayer por email cita y quedo pendiente me confirme Marisa con la que hablo por teléfono para firmar el 21 esta declaración de herederos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-04-06','miguel, pedi ayer por email cita y quedo pendiente me confirme Marisa con la que hablo por teléfono para firmar el 21 esta declaración de herederos ************************************ Envío a Carmen de la asesoria de Almendralejo email: Y en este adjunto el nombramiento del cargo de tutor a la Comisión tutelar y el contrato de arrendamiento para que identifiques en relación al registro de la propiedad las fincas que catastralmente están relacionados Buenos días, te remito la documentación que creo que puedes ir necesitando para que vayáis preparando un presupuesto aproximado y desglosado de a qué importe puede ascender la gestión siguiente: 1.- Preparación de información previa, entrega y firma en notaria para la adjudicación de la herencia (ejemplo pedir notas simples) 2.-liquidación del impuesto de sucesiones 3.-Desbloqueo de las cuentas bancarias y transferencia a Eulalia del dinero en cuentas de Francisco. 4.-Solicitud de autorización judicial de aceptación, y aprobación de herencia 5.-La venta de los bienes rústicos y sus trámites notariales y judiciales dependerán de llegar a un acuerdo con el actual arrendatario. Quedo a tu disposición para aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-04-06','Ana: Nos comunican que hay un caso positivo de Covid en la Res. de Fuente de Cantos, por tanto Juan Carlos no podrá ingresar mañana. *Hoy mismo harán una videollamada desde el centro para que él vea que realmente le están esperando allí y que es verdad que lo antes posible podrá ingresar. ···· Desde el CSS nos piden que llamemos a Juan Carlos para comunicárselo. ······· Hablo con Maripaz, Psicóloga, realiza una videollamada con Juan Carlos. Le explico lo que ya le ha dicho ella también, y que será mejor para él estar mientras ahí que puede salir a irse mañana al centro pero tener que estar encerrado en su habitación durante una semana. *Aunque no le gusta la idea parece aceptarlo. ······· En unos minutos le harán también una videollamada Rosa, Directora y la Psicóloga del centro de Fuente de Cantos para explicárselo y enseñarles la que será su habitación, para que vea que es cierto y que tiene plaza allí. ········································································································································································································ Ana: Llamo a Álvaro, empresa EUEXIA (651 639 717): sin éxito. Le envío un correo (ameuexia@gmail.com): "En relación a JUAN CARLOS RUIS GARCÍA, comentarte que el ingreso en centro que había programado para esta semana, se ha pospuesto por haber caso positivo de covid en el mismo. Por tanto Juan Carlos seguirá mínimo una semana más en el Centro Sociosanitario de Plasencia. ¿Sería posible continuar con el servicio de acompañamiento que venía prestándose desde vuestra empresa este próximo sábado? Y si la próxima semana continuara en Plasencia, no habría problema, tal y como planteabais, en realizarlo el jueves 14 en lugar del sábado 16. A él, como sabéis, le vienen muy bien estas salidas, más ahora que se pospone el ingreso en centro que tanto desea. Espero tu confirmación. Pongo en copia a Estrella, compañera del Sociosanitario, para que esté al corriente." ··············· Respuesta de Álvaro (ameuexia@gmail.com): "Fenomenal, lo hacemos el Sábado a la hora de siempre y ya nos confirmas cuando lo sepas, si lo hacemos también el Jueves día 14."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-04-06','Ana: Ana Marta me envía el Pasaporte de Brahim escaneado. Lo guardo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2022-04-06','Ana: Correo de Teresa Nogueira, TS Novaforma (trabajadorasocial.novaforma@gmail.com): "Buenos días , he solicitado un extra de 300€ para Felipe Blanco, es para pasar un día en su pueblo, iría acompañado por un profesional , hemos estimado un coste de 100€ por el servicio para el profesional ya que es una gran responsabilidad, el resto seria para pagar comida, gasolina ya que irían en coche del profesional , flores para el cementerio ... y se le sobra dinerillo para comprar tabaco "especial de vacaciones". ······················ Doy a Lourdes, sección económica mi OK para esta solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2022-04-06','Ana: Envío correo a Cristina, Psicóloga del CRR-CC (crr@grupociudadjardin.com): "Adjunto Consentimiento Informado para Extirpación de Lesiones en la Piel relativo a Consuelo Nevado Pacheco debidamente firmado y sellado por el Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-04-06','Ana: Correo de Guadalupe, TS del SAD del IMAS-CC (guadalupe.cortes@ayto-caceres.es): "Buenos días Ana Siguiendo tus indicaciones te envío este correo relativo al Servicio de Ayuda a Domicilio de Ventura Gómez García: Ventura Gómez García, es usuario del Servicio de Ayuda a Domicilio (SAD) del IMAS desde el 20/04/2018. La propuesta inicial de atención era de 6 horas a la semana distribuidas en 3 días, para realizar las tareas de: limpieza y mantenimiento del hogar, elaboración de comidas y supervisión en el aseo. El SAD empezó a prestarse con 3h distribuidas en 2 días semanales. El 8/4/2019 se redujo el Servicio a 1día/2horas a petición del propio usuario, refiriendo que contaba con apoyo externo. Esta reducción fue comunicada a FUTUEX. El coste del servicio al que tiene que hacer frente el usuario es de 9,30€/hora. En la actualidad Ventura no cuenta con apoyo doméstico externo y el tiempo de SAD resulta claramente insuficiente para el abordaje de las tareas propuestas. Por todo ello se solicita que desde la Comisión Tutelar de Mayores se valore la posibilidad de ampliar el SAD para una mejor atención al usuario." ·············································· Envío correo a Oscar, Secc. Ecca: "Buenas tardes Oscar, Te reenvío correo de la Trabajadora Social del SAD del IMAS (Instituto Municipal de Asuntos Sociales) de Cáceres. Por mi parte OK a la ampliación del servicio, lo estuve hablando con ella la semana pasada y estoy de acuerdo en que es necesario ampliar el servicio. Así pues, si puede asumirse contestarle y ponerme en copia por favor, para que puedan ampliarlo lo antes posible."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-04-05','Ana: llamada de Felisi, el mismo discurso del día de ayer. Presenta necesidad de hablar y de refuerzo ante su decisión, pero está convencida. Jesús quiere volver con ella y ella dice no estar dispuesta de tener que cuidar otra vez a dos hombres (Jesús y su hermano Manolo). ············· En cuanto a su hijo Aitor, dice que su pareja, tiene un hijo, pero que éste convive con el padre. Ella todavía queda mucho con la expareja y eso dice no gustarle. *"Pero Aitor se enamora enseguida".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2022-04-06','Ana: Llamada de José, responsable de la empresa que gestiona varias RR.MM. (608 96 27 82) de la zona. *Van a cerrar la Res. Ntra. Sra. de Sopetrán el día 20 de abril. *Juan José ocupa plaza privada y acepta el traslado a la RR.MM. de Navezuelas, localidad cercana, en principio le mantendrán las condiciones del contrato actual. ·················· José firmará un documento de aceptación del traslado al otro centro, para que se ponga de manifiesto su voluntad. Y con esto lo comunicaremos al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='NAVAS'and apellido2='VALENCIA'),'2022-04-04','TERESA SE ACUERDA ESTABLECER UN REINTEGRO PARA GASTOS DE 25€ SE VA A DAR DE BAJA AL TELEFONO PUES ELLA NO LE DA USO EL REINTEGRO LO SACARA LA TS DE LA RESIDENCIA PURIFICACION MOLINA EN LA PRIMERA QUINCENA DE CADA MES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-04-07','miguel, llega por fax del centro penitenciario la ejecutoria del jzdo Penal nº1 de Don Benito Ejecutoria 49/20 conforme el que está cumpliendo 2 años de prisión desde 11-1-2022 y hasta el 22-3-24 por un delito de robo en casa habitada. Se lo reenvío a Amalia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-04-07','Ana: Correo de ayer de Sonia, TS Asindi (trabajosocial@asindi.e.telefonica.net): "...Aarón ayer le volvieron a derivar a Salud Mental por la mañana y regresó a las pocas horas. Hoy está nervioso y empieza a presentar conductas autolesivas y heterolesivas pensando en que quiere irse a casa y, estamos valorando con su padre adelantarle 1 día que se vaya. Si en casa surge algún problema Julio solo tiene que llamar para que regrese." ················· Mi respuesta: "...- En cuanto a adelantar la salida de Aarón, di desde el Equipo Técnico de vuestro centro lo veis oportuno y creéis que puede ayudarle a rebajar su malestar y su nerviosismo, de acuerdo. Ya nos vais contando cómo resulta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-04-07','Ana: Correo de ayer de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "¿tienes respuesta sobre la concesión de transporte subvencionado para los hermanos Hernández Castaño? Es por ver cómo organizamos los días de Semana Santa que irán a casa." ··············· Como en anteriores ocasiones, desde que se solicitara, consulto a Belén, Secc. Discapacidad, en esta ocasión por mail (maria.gutierrezgo@salud-juntaex.es): "Buenos días Belén, Desde Asindi vuelven a preguntarme por el trasporte de Cruz Roja solicitado para los hermanos Hernández Castaño, pues tienen que terminar de organizar el viaje de la semana que viene por “vacaciones de Semana Santa”. Dime en cuanto puedas porfa." ································· Respuesta de Belén: "te reenvío el correo que hoy por fin!!!! me ha mandado Cruz Roja. Los viajes se inician el 13 de abril con los hermanos Hdez. Castaño. Cruz Roja se pondrá en contacto con el Centro para los horarios."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-04-07','Ana: Correo de ayer de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "¿tienes respuesta sobre la concesión de transporte subvencionado para los hermanos Hernández Castaño? Es por ver cómo organizamos los días de Semana Santa que irán a casa." ··············· Como en anteriores ocasiones, desde que se solicitara, consulto a Belén, Secc. Discapacidad, en esta ocasión por mail (maria.gutierrezgo@salud-juntaex.es): "Buenos días Belén, Desde Asindi vuelven a preguntarme por el trasporte de Cruz Roja solicitado para los hermanos Hernández Castaño, pues tienen que terminar de organizar el viaje de la semana que viene por “vacaciones de Semana Santa”. Dime en cuanto puedas porfa." ······················ Respuesta de Belén: "te reenvío el correo que hoy por fin!!!! me ha mandado Cruz Roja. Los viajes se inician el 13 de abril con los hermanos Hdez. Castaño. Cruz Roja se pondrá en contacto con el Centro para los horarios."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-04-06','Ana: Correo de Paula, Progr. de Intervención en C. Penitenciarios de Plena Inclusión (paula@plenainclusionextremadura.org): "... vi a Saturnino el 18 de Marzo y luego no he vuelto a ir a Cáceres, este viernes voy a pasarle unas pruebas a Saturnino. En la primera entrevista no impresiona que tenga discapacidad intelectual pero para asegurarme este viernes le voy a ver. Estuve hablando con la trabajadora social Mayte( para nosotros la rubia)y ella me dijo que os demandaba demasiadas cosas, porque como sabe que cobra pensión . La semana que viene te cuento un poquito más."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-04-07','Ana: Llamo a Gema, directora de la RR.MM. Sta. Ana, Malpartida de CC (670 381 292): Ayer, a última hora, Mª Ángeles se mostraba muy resignada ante la idea de tener que cambiar de recurso residencial, pues está muy adaptada y a gusto allí. *Reitera que prefiere vender su vivienda para abonar la plaza antes que tener que cambiar de centro. *Me informa además, que dado el problema de comunicación que presenta derivado de su enfermedad de Parkinson, se comunican con ella de forma alternativa, de modo que tanto ella como los profesionales se hacen entender. *A Mª Ángeles le da miedo llegar a un centro nuevo en que no la entiendan. ················· Le informo que tras valorarlo con Miguel, Asesor Jurídico, y comprobar que la Administración de Bienes ya es firme, solicitaremos al Juzgado que con carácter de urgencia autoricen la venta de la vivienda, tal y como es su deseo. Para ello necesitaremos un Informe Social, donde se detalle la situación actual, su deseo de vender la vivienda para seguir residiendo allí, un documento firmado por ella en que así se exponga, Certificado de Ingreso en Centro y cuota del mismo e Informe Médico. ···· *Envío un correo a Gema (gsanchez@nexusintegral.com) detallando los documentos que nos tendrán que enviar y el contenido mínimo que entendemos debería tener el informes social. *Enviaré también el documento de "Autorización de venta de inmuebles" que me facilitará Miguel y que tendrá que firmar Mª Ángeles para corroborar su deseo de venderlo. ********************************************* MIGUEL: Envío a Ana los modelos de Autorización de venta para firmar Mª Angeles y la solicitud de autorización de venta judicial','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2022-04-07','Buenos días, ayer falleció Juan Bautista Ramírez de la Rosa, se comunicó a los familiares, que se encontraban en estos momentos aquí en Mérida y a la compañía de Seguro de Deceso. El número de teléfono de su cuñado es 619208666, se llama Luis.','2');
