insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-04-07','TERESA EMAIL DE ADISER Teresa buenas tardes, te remito autorización de salida a nombre de Aitor. Esta salida se programa para un día antes, tras hablar con el equipo de familia para que ellas puedan controlar la llegada de Aitor. Como siempre Aitor irá a casa con un presupuesto de 2 €/días, billete de ida y vuelta sacado, teléfono cargado, tabaco comprado y un lote de comida para esos días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-04-07','miguel, me contesta la trabajadora social del centro penitenciario: Buenos días Miguel. Ayer se lo entregué al interno para que él ahora solicite a Seguridad quien le tiene que autorizar las llamadas telefónicas con su abogada. Gracias y un saludo. ********************************* Se lo reenvío a la abogada Carmen Lucas','2');
