insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-04-07','miguel, envío email a Alberto y Oscar: Buenos días, tras hablar con el fiscal de Plasencia, en principio aunque podríamos entender extinguido nuestro cargo para con la mencionada Administración de bienes, no obstante no queda del todo clara, motivo por el que tras hablar con Ana, vemos que al no estar (que sepamos ) incapacitada, no sería de aplicación el actual 258 CC(antes 271CC) en el sentido de ser necesario pedir autorización de venta. Por eso estoy preparando una autorización de MARIA ANGELES ROSADO ALBARRAN a la Ctaex para vender la vivienda y al tiempo una solicitud al juzgado para que autorice la venta, en base precisamente a que la señora no está incapacitada. Lógicamente el juzgado tendrá en algún momento que dictar medidas de apoyo y nombrar curador asistencial o representativo a la Ctaex o a una tercera persona conforme a la nueva ley 8/21. Alberto/Oscar: necesito me enviéis al email movimientos de la cuenta desde que comenzamos a actuar con ella, junto con una relación de ingresos y gastos que tiene desglosados, lo antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-04-07','Ana: Llamada de Isabel, se cayó en la ducha y han tenido qu escayolarle el brazo durante 10 días. El próximo lunes se la quitan. ·············· Por otra parte, pide subida de la asignación, dice que no llega a final de mes. Se le explica que con 300 €, sólo para gastos de bolsillo debería de tener. Pues además a su madre se le dará el dinero mensual para el traslado cada vez que se vaya al domicilio familiar. ··················· Ha tenido que abonar el taxi para ir al hospital. Dice que por allí no pasan autobuses. *Después reconoce que lo han abonado con el extra anual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='TAPIERO'and apellido2='JIMENEZ'),'2022-04-07','TERESA ENVIO CONSENTIMIENTO INFORMADO PARA ANESTESIA POR CARTA CERRIFICADA A AL RESIDENCIA','2');
