insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2022-04-08','Ana: Paso a Julio - CTAEX, para REGISTRO: Comunicación de cambio de datos en el expdte. de Dependencia (cambio de cuenta de domiciliación bancaria) y Modelo para Alta de Terceros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2022-04-08','Ana: Paso a Julio - CTAEX, para REGISTRO DE SALIDA, a la atención de Carmen Gía, EVD-Plas., la documentación pendiente para la negociación PIA: "- Anexo Informativo al documento de aceptación PIA, debidamente firmado y sellado por su representante legal. - Contrato Residencial firmado por ambas partes - Alta de Terceros"','2');
