insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2022-04-07','-Amalia : visitamos Mayte y yo a Pilar en el C.O. Le explicamos que tiene plaza RAL en Ap. 3 La madre se opone , trato de convencerla . Quedamos para el martes dia 19 gestiono taxi si tiene dinero','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-04-08','Ana: llamo a Raquel - Equipo de Familia (609 382 439): están también muy pendiente de ella. El miércoles fueron a visitarla. La vieron muy convencida de su decisión, la ven segura. Además cuando habla con ellas se reafirma y empodera. ··· Pero esta mañana ya han hablado con ella y les decía que Jesús va a ir hoy a llevarle las cosas y tiene intención de instalarse allí. Le preguntan si ella quiere y dice que no, manteniendo el discurso de que le miente, le maneja el dinero, consume drogas... Pero por otra parte sigue diciendo que le da pena y además añade que "la soledad es difícil". *Estarán pendientes y confían en que finalmente Jesús no se instale. ······················ En cuanto a la tarjeta monedero, Raquel nos facilita sus datos (Apellidos y DNI), el día 21 acudirá a acompañarle a la sucursal bancaria. *Plantean coordinarse con Virginia-Futuex, para acompañarle a retirar las primeras veces hasta que aprenda. **Cree que custodiará bien la tarjeta, pues es ordenada y organizada. ································································································································································································ Envío correo a Toni-Futuex: "... Como sabéis la oficina bancaria de Torrecillas de la Tiesa y Navas del Madroño cerrarán en los próximos días. Queríamos comentaros que tanto con Isabel Muñoz Melchor como con Felisi Felipe Teomiro, se ha podido gestionar la tarjeta prepago (“Monedero”) y, al contrario que en otras localidades, ha sido factible. Eso sí, te cuento: - Felisi Felipe Teomiro podrá recoger su tarjeta el día 21 en la oficina de la Nava (el mismo día que cierra). He hablado con Raquel del Programa de Familia, por la situación en general, y ya se lo he comentado también. El día 21 le acompañará ella a recogerla. *Las tarjetas se le recargarán los días 1 y 15 de cada mes, pudiendo retirar la asignación cualquier día. Os pedimos, tanto a Virginia, como a las compañeras del programa de familia, que estéis pendientes los primeros meses hasta que aprenda a usarla adecuadamente. Supongo que podrán coordinarse para ir una u otra acompañarla. En cuanto a la custodia de la misma, Raquel cree que Felisi, dado que es organizada y ordenada, no la perderá."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2022-04-08','Ana: Envío correo a Toni-Futuex: "- Isabel Muñoz Melchor, la oficina cierra antes de que llegue la valija. Por tanto nos dicen que habrá que recogerla en Plasencia. ¿Sería posible que, en la fecha que nos indiquen los compañeros de la sección económica, cuando se lo confirmen, acudiera Gloria a recogerla y llevársela cuando pueda a Torrecillas? A ella se le recargará con carácter mensual, los días 1 (laborables)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-02-26','SALIDA Salida al desfile de carnaval de Cáceres. Organiza PAPIROLA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-04-08','TERESA HABLO CON LA TS DE LA RESIDENCIA, ANA AGUILA 924801726 EMAIL:TSDONBENITO@HHAADD.ORG LE COMENTO LA SITUACION ECONOMICA DE JULIO YA QUE TODA LA PENSION SE VA EN PAGAR LA PLAZA RESIDENCIAL Y TIENE 200€ GASTOS MENSUALES EXTRAS. ME DICE QUE EN EL CONTRATO PONE QUE EN TODO MOMENTO SE HARAN CARGO DE JULIO AUN CUANDO NO TENGA DINERO AHORRADO Y A PESAR DE NO TENER SEGURO DE DECESOS ELLAS SE ENCARGAN DEL SEPELIO. ME SOLICITA LE COMUNIQUE POR ESCRITO LA SITUACION ECONOMICA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-04-08','Ana: Conversación con Estrella, TS Malpartida de Cáceres (927 27 50 03), aclaro lo relativo al cobro indebido de la Prestac. ecca. vinculada al SAD. *Nos enviará el Cdo. de ingreso del Ayto. (pues la Res.es de titularidad municipal) y el Informe Social. ··························· Yo hablaré de nuevo con Alberto, Técnico EVD. ································································································································································································· Oscar, Secc. Ecca, solicitará el Alta de Terceros. ··················· Entrego a Julio, CTAEX; Oficio al INSS solicitud del Cdo. de Pensión actualizada y pidiendo que a partir de ahora remitan los cdos. a la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-04-08','-Amalia; escribo a S. eco : Buenas , me indican desde el centro penitenciario que el castigo se le levantaba para el 1 de abril y no ha percibido nada . Hay que volver activar cuenta peculio. Por otro lado , hay una factura de tratamiento dental pendiente , que por el momento no se va a autorizar porque existe la posibilidad de que lo trasladen de centro . Quedo a la espera de esa confirmación. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-04-08','-Amalia : se recibe email de TS Valdelacalzada y nos adjunta la resolución de baja. Buenos días Amalia, adjunto al correo resolución del rechazo a la ayuda a domicilio por dependencia de Dª MARIA ROSA SERRANO GARCÍA, al contar con servicio municipal y ser económicamente inviable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-04-08','Buenos días, adjunto la ejecutoria de sentencia del curatelado por la que le condenan a 2 años y que cumplirá desde el 11-1-2022 hasta el 22-3-2024.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2022-04-06','Buenos días , se adjunta el informe médico de LUISA RODRIGUEZ GRAGERA que nos solicitó Raquel ( Sección Salud Mental del SEPAD ) para solicitar cambio de PIA y trasladar de plaza de CRR a ingreso en R. Mayores. Como os dijimos no se renuncia a la plaza y se limitará a plaza residencial en ciudad de Mérida y/ o Almendralejo por acercamiento familiar . El marido vive en Calamonte. May desconocía este expediente , le informo a través de este email para que cuando la pase a lista de espera sólo sea para esas dos ciudades. Por favor índicanos si tenemos que especificarlo en alguna solicitud. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2022-04-11','Ana: Llama la hija, Puerto (661 273 204), en relación a una herencia. Le paso con Miguel, Asesor Jurídico CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-04-06','Ana: Llamada de José Manuel, dice que el jueves o el viernes pasado, no recuerda bien, le llamó por fin el Psiquiatra. ········ Por otra parte dice que quiere que le cambien la educadora de Futuex, pues Teresa no le hace caso. "He estado 2-3 días muy mal, le dije que me iba a tomar un bote de Haloperidol y no hizo nada". ·········· Las llamadas de atención y demandas de José Manuel vuelven a ser tan frecuentes como antes de ingresar al CRR, al volver a domicilio ha vuelto a las rutinas y hábitos inadecuados de siempre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-04-08','Ana: Llamada de José Manuel, de nuevo pide más dinero, pues dice que como fuma mucho, se lo gasta todo en tabaco y no le queda para leche y otros productos. ············ Se le vuelve a recordar que, sobre todo por salud, pero también por su economía, debería reducir el consumo de tabaco. ··· A colación de esto dice que por las noches le está costando bastante respirar. Que llamó al 112 y le dijeron que pidiera cita a su médico de atención primaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-04-08','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, los hermanos Hernández Castaño se marchan a casa del 13 por la mañana al 17 por la tarde. Ya hemos hablado con la persona de Cruz Roja que los lleva y con sus padres."','2');
