insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2022-04-11','miguel, tras conversación con la hija de la tutelada, Puerto (móvil 661-273-204) me comenta que nos remitió el viernes email para tramitemos la firma de la herencia de sus abuelos, donde su madre (nuestra tutelada) y sus 7 hnos serían los herederos, siendo Puerto y su hermano legatarios. Parece ser que los trámites los están llevando el abogado de los hermanos de la tutelada y el abogado de los legatarios (nietos de los causantes e hijos de la tutelada). Remito email al abogado con copia a Puerto (Alfredo Barca Durán; email alfredobarca@icac.es; y Puerto, email: puertopaniagua@hotmail.com: Buenos días Alfredo, en relación a la herencia que se está tramitando de los abuelos de Puerto, hija de la tutelada por la Comisión Tutelar de Adultos Doña Mª Jesús Martin Calle, necesitamos se ponga en contacto conmigo a efectos de informarnos de dicha herencia de la que era desconocedor, a efectos de poder nombrar un abogado y procurador para las correspondientes autorizaciones judiciales de aceptación, y tras la firma de la herencia, aprobación judicial. Necesitaríamos nos remitieran la documentación de la que conste la herencia (testamentaría y el inventario de la misma).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='CANELADA'and apellido2='GARCIA'),'2022-04-10','EXITUS Ocurrido el 10/04//2020.Informe sobre él FUTUEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2022-04-11','Ana: Llamada de Miguel, Empresa "Limpieza extrema" (664 62 19 46): Sí que están interesados en realizar la limpieza. Le pondré en contacto con Futuex para que acuerden día y hora de visita al domicilio para establecer presupuesto. ················· Llamo a Toni-Futuex, como no obtengo respuesta le envío un correo-e: " "En relación a la vivienda de Antonio Hidalgo Romo, consideramos necesario realizar limpieza, por prevenir problemas de infecciones a las viviendas vecinas. ¿Sería posible que Gloria acudiera un día visitarlo, le hablara de la necesidad de esta limpieza, para que diera su consentimiento, aunque sea verbal, pues es curatela para regir y administrar sus bienes, para proceder a la limpieza y que le facilite la llave para entrar? He contactado con Miguel, de la empresa LIMPIEZA EXTREMA (664 62 19 46) y están interesados en realizar un presupuesto. Pero creo que es mejor que os coordinéis vosotras con él para establecer fecha y hora de visita. Así que, si te parece, le digo que le llamaréis para concretar. Ya me confirmas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2005-04-21','Ingresa en el Centro Residencial de Rehabilitación de Cáceres el día 9 de diciembre de 2004. (Pertenece al SES)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2022-04-11','TERESA SALDO EN 03/2022: 4.000 € INGRESOS: PNC REINTEGRO ACTUAL: 140 € QUINCENA. TERE: PAGAMOS PSICÓLOGO HIJO + MUCHOS PEQUEÑOS GASTOS (ROPA...) EN MI OPINIÓN NO SE DEBE INCREMENTAR REINTEGRO...ACTUALMENTE EL DIFERENCIAL INGRESOS-GASTOS DES DE +230 €/AÑO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2022-04-11','Ana: Tras hablar con Miguel, de la Empresa Limpieza Extrema, envío correo a Toni-Futuex: "En relación a la vivienda de Antonio Hidalgo Romo, consideramos necesario realizar limpieza, por prevenir problemas de infecciones a las viviendas vecinas. ¿Sería posible que Gloria acudiera un día visitarlo, le hablara de la necesidad de esta limpieza, para que diera su consentimiento, aunque sea verbal, pues es curatela para regir y administrar sus bienes, para proceder a la limpieza y que le facilite la llave para entrar? He contactado con Miguel, de la empresa LIMPIEZA EXTREMA (664 62 19 46) y están interesados en realizar un presupuesto. Pero creo que es mejor que os coordinéis vosotras con él para establecer fecha y hora de visita. Así que, si te parece, le digo que le llamaréis para concretar. Ya me confirmas."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-04-11','Ana: A petición de Miguel, Asesor Jurídico, envío correo a Estrella, TS SSASB (ssb@malpartidadecaceres.es) y a Gema, Directora RR.MM. (gsanchez@nexusintegral.com): "Buenos días Gema y Estrella, Me comenta Miguel, Asesor Jurídico CTAEX, que dada la situación de Mª Ángeles Rosado Albarrán, él ya tiene preparado su escrito para solicitar la autorización de venta de la vivienda al Juzgado, pero necesita de los documentos que hemos hablado y pide por favor, que en la medida de lo posible, intentéis agilizarlo y hacérnoslo llegar a la mayor brevedad. Gracias y buen semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2022-04-11','miguel, llega del jzdo de lo penal nº2 de Merida, Procedimiento Abreviado 65/2022 por delito de apropiación indebida, de Carmelo Gracia Redondo','2');
