insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2022-04-11','De: Felipe Martín - Coordinador S. Vivienda Centro Ntra. Sra. de la Luz >residencia@centronuestrasradelaluz.es> Enviado: lunes, 11 de abril de 2022 11:10 Para: Soraya Masa Moreno >soraya.masa@salud-juntaex.es> Asunto: Comunicado desaparición de una usuaria Buenos Días Soraya, Queremos informarte que la usuaria DOÑA JUANA DE LOS REMEDIOS PALOMO, usuaria de residencia y de centro ocupacional, en una visita a su familia, se ha marchado del domicilio para un recado y no volvió. Hemos puesto una denuncia en la comisaria de policía y lo hemos comunicado a la comisión tutelar. Estamos en contacto con su madre por tf para informarnos por si volviera. Creemos que pudiera estar con su madre ya que ella pide constantemente poder residir con la misma. Te adjuntamos la denuncia que hemos presentado Un saludo. Felipe Martín Martín - Coordinador Servicio de Residencia y Viviendas Tuteladas Centro Nuestra Señora de la Luz- Asprodis (Instituto Secular Hogar de Nazaret) Avda. Godofredo Ortega y Muñoz Nº 3 C.P. 06011. Badajoz. Teléfono contacto: 924237551 FAX 924256190 Correo: residencia@centronuestrasradelaluz.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2022-04-11','-Amalia : envío email a sección eco /social / jurídica : Buenos días , sobre FRANCISCO CASILLAS GARCÍA , último caso del año pasado y primera curatela asistencial : sección eco : De momento no se le limita la PNC de 421€/ mes . No tiene seguro de decesos , pero ahora mismo , ese es un mal menor . Sin red familiar ni social de apoyo. Estoy iniciando plan de intervención, pero el perfil social es muy complejo y no tenemos recursos residenciales que ofrecerle de manera involuntaria . Reside en la calle , la casa familiar son escombros , y él se ha construido un chafardo en el campo ( tenéis fotos en el expediente , por si tenéis curiosidad ) . Patología mental asociada a consumo de alcohol , actualmente activo y no abordable porque no existe voluntariedad por su parte . Estuvo en centro de transeúntes durante la pandemia pero lo máximo que duró fueron días . No se adapta a centro ni a sus normas , obviamente no se permite el consumo de ningún tipo de droga. Este es uno de esos casitos fáciles que nos envía el juzgado , si no puede entrar finalmente en ninguno de los recursos residenciales que existen , lo comunicaremos al juzgado . Estoy pidiendo informes de psiquiatría por si tengo opción de solicitar un internamiento involuntario en UHB para compensar su enfermedad . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-04-11','Ana: Llamada de José Manuel (627 788 797): dice que se ha gastado ya toda la asignación mensual y que sólo le quedan 2 paquetes de tabaco. Quiere que le demos más dinero. *Tendrá que esperarse al próximo lunes, que puede retirar su nueva asignación. ··············· Dice que lo está pasando mal, que no puede estar solo. Que la semana pasada tuvo que echar, otra vez, de casa a su hijo. *Que le solicitemos plaza en Alcuéscar y sino que le alquilemos un piso en Olivenza. ···· Le digo que ha cambiado muchas veces de parecer y va a agotar las pocas alternativas que le quedan, como es la de ese recurso. **Insiste en que no va a cambiar de idea y que quiere ingresar allí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2022-04-11','-Amalia , tiene dinero para pagar el taxi para su ingreso del dia 19 . Le pido a Cati que llame al taxi.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2022-04-11','De: Felipe Martín - Coordinador S. Vivienda Centro Ntra. Sra. de la Luz >residencia@centronuestrasradelaluz.es> Enviado: lunes, 11 de abril de 2022 11:10 Para: Soraya Masa Moreno >soraya.masa@salud-juntaex.es> Asunto: Comunicado desaparición de una usuaria Buenos Días Soraya, Queremos informarte que la usuaria DOÑA JUANA DE LOS REMEDIOS PALOMO, usuaria de residencia y de centro ocupacional, en una visita a su familia, se ha marchado del domicilio para un recado y no volvió. Hemos puesto una denuncia en la comisaria de policía y lo hemos comunicado a la comisión tutelar. Estamos en contacto con su madre por tf para informarnos por si volviera. Creemos que pudiera estar con su madre ya que ella pide constantemente poder residir con la misma. Te adjuntamos la denuncia que hemos presentado Un saludo. Felipe Martín Martín - Coordinador Servicio de Residencia y Viviendas Tuteladas Centro Nuestra Señora de la Luz- Asprodis (Instituto Secular Hogar de Nazaret) Avda. Godofredo Ortega y Muñoz Nº 3 C.P. 06011. Badajoz. Teléfono contacto: 924237551 FAX 924256190 Correo: residencia@centronuestrasradelaluz.es','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-04-11','Muchas gracias por la información, me suponía parte de la información que me habéis dado pero él hoy estaba muy demandante. Volveré a hablar con él, pero no creo que comprenda al 100% todo. En cuanto al tabaco se lo va a enviar su tía y su primo, por lo que este tema resuelto. No veo conveniente que él disponga de dinero de bolsillo aún. Un saludo María Martín Rivero Trabajadora social. Encinar de las Cruces','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-04-11','Ana: Llamo a Juan José (643 641 375): Le explico que, tras haber hecho los cálculos con el jefe de sección económica, se ha acordado que se le hará una transferencia a su madre mensualmente, de 80€ desde su cuenta, en concepto de gasto de suministros. ···· A él se le autorizarán 67€/semana para sus gastos de higiene, alimentación y bolsillo. Aparte se mantendrá el Seg. de Hogar que venía pagando así como la cuota a la Asociación.*Expresa que entiende que sólo percibe ya la PNC y que no da para más. Acepta la propuesta. *En cuanto al poco dinero que quedaba en su cuenta, confirma que ya lo ha retirado todo. Le digo que con eso tiene que llegar a final de mes. Podrá comenzar a retirar su asignación a partir del 1 de mayo. ···································· Llamo a Josefa a Carreras, madre de Juan José (626 198 616): Le explico lo mismo que a Juan José. ··· Dice que su hijo no sabe ahorrar, siempre se ha administrado él sólo y que cada vez que necesita dinero recurre a ella. ········ Comenta además que Juanjo tiene pendiente varias vistas en el Jdo. Al parecer ha tenido problemas con la vecina de arriba. ··········· Ella no sabe el nº de cuentas, dice que hable mejor con su hija Helga. *Le pido que le comunique que mañana la llamaré.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='ALVES'and apellido2='MATEUS'),'2022-04-11','Ana: correo de Emilia Almodóvar, TS CSS-Plas: "COMUNICAR QUE EN LA UNIDAD DE ANCIANOS DE SOCIOSANITARIO DE PLASENCIA. EN LA RALIZACION DE CRIBADO EN COVID, HAY VARIOS PACIENTES POSITIVOS. EN PRINCIPIO SON TODOS ASINTOMATICOS. PARA VUESTRO CONOCIMIENTO SON: • JOSE ALVES MATEUS • JOSE CRESPO MARTIN • FRANCISCO MOLINA VAZQUEZ"','2');
