insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2022-04-12','-Amalia , escribo a la sección eco : necesito saber el saldo actual de JUANA DE LOS REMEDIOS PALOMO . La última declaración anual que puedo ver contiene el saldo a fecha 2020. Juana salió el sábado del Centro Ntra. Sra. de La Luz para pasar el día y no regresó . Se interpuso denuncia el sábado por la noche. Hemos estado haciendo gestiones con policía local porque creían desde el centro que podía estar en su casa . La madre no facilitaba que la policía entrara en la casa y estábamos pendiente de orden judicial . Ayer por la tarde nos avisaron de que ha aparecido en Lérida y quedó ingresada en la UHB de ese hospital . Necesito conocer el saldo para valorar posibles opciones para el traslado . Va a ser caro , mi primera opción es pedir presupuesto al SES para solicitar ambulancia. Quedo a la espera para hacer las gestiones . Gracias .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2022-04-12','-Amalia , escribo a la sección eco : necesito saber el saldo actual de JUANA DE LOS REMEDIOS PALOMO . La última declaración anual que puedo ver contiene el saldo a fecha 2020. Juana salió el sábado del Centro Ntra. Sra. de La Luz para pasar el día y no regresó . Se interpuso denuncia el sábado por la noche. Hemos estado haciendo gestiones con policía local porque creían desde el centro que podía estar en su casa . La madre no facilitaba que la policía entrara en la casa y estábamos pendiente de orden judicial . Ayer por la tarde nos avisaron de que ha aparecido en Lérida y quedó ingresada en la UHB de ese hospital . Necesito conocer el saldo para valorar posibles opciones para el traslado . Va a ser caro , mi primera opción es pedir presupuesto al SES para solicitar ambulancia. Quedo a la espera para hacer las gestiones . Gracias .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2022-04-11','-Amalia : Juana no regresó al centro el sábado . Se puso denuncia. - Felipe , director de RAL : Han llamado al Centro la policía de Lérida, para decir que estaba allí. Juani, ha entrado en la comisaria para pedir un DNI nuevo y al ver que se encontraba muy agitada y nerviosa, al meter los datos le ha aparecido la denuncia de la policía de Badajoz, por eso se han puesto en contacto con nosotros. A las 17’40 han vuelto a llamar para solicitarnos por correo la medicación actual y la denuncia puesta. Creo que le van a llevar a un hospital de Lérida. También nos han indicado que estaba acompañada por José Rubio Blanco (No sabemos quien es) Te facilito los correos que nos han dado ellos porque las llamadas han sido desde números privados. Desde el Centro le hemos comunicado la situación actual de Juani (Tutela), y nos han pedido que os pongáis en contacto con ellos. Correos electrónicos: itpg636@gencat.cat capsdetornreus.sem@gencat.cat Cualquier cosa no dudes en ponerte en contacto conmigo Un saludo. Felipe Martín Martín - Coordinador Servicio de Residencia y Viviendas Tuteladas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2022-04-11','-Amalia : esta tarde ha llamado Soraya , ha aparecido Juana en Lérida . Ha quedado ingresada en UHB hospital Santa Mª de LLeida tf T.S. 973727222 Ext. 1545','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='SOLE'and apellido2='LATORRE'),'2022-04-12','Ana: Llamadas de María, TS Mancomunidad (654 452 082) y Fermina, Directora de la RR.MM. Aldea del Cano (927 38 30 20). Hoy a las 7:15 h. ha fallecido Adela. Llevaba 2 años encamada y delicada. Apenas se comunicaba ya. De los hijos no saben nada, no han conseguido localizarlos. *Desconocen por completo cuál era el deseo de Adela con respecto a su si quería ser enterrada, incinerada o en qué localidad. Tampoco conocen su trayectoria vital en cuanto a sus creencias y/o confesión religiosa, si la tuviera. ********** Por todo ello, se acuerda que, si hay nichos disponibles, se le enterrará en Aldea del Cano. ············· *Tiene seguro de decesos en Santa Lucía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='SOLE'and apellido2='LATORRE'),'2022-04-12','EXITUS El centro informa de su óbito, acaecido el 12/04/2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-04-12','Ana: Llamo a Alberto Bueso, TO-EVD (21841), le explico la decisión adoptada finalmente, atendiendo a los deseos y necesidades de Mª Ángeles. ········ *En cuanto a la prestación que venía percibiendo por SAD, Alberto me aclara que cuando lo solicitó su capacidad económica era menor que en la actualidad, de ahí la diferencia en la cuantía. ····························································································································································································· Envío a Gema, directora de la Res., la Aceptación PIA de Prestación Ecca. vinculada al SAR y Aceptación PIA de Plaza Pública en Res. Santa Ana (la misma en que reside), para los firme Mª Ángeles. ······························ ················ *Envío a Miguel, Asesor Jurídico, la Autorización de Venta del piso firmada por Mª Ángeles, remitida por Gema, directora de la Res. ····························································································································································································· Estrella, TS (ssb@malpartidadecaceres.es), envía informe, pero al igual que en el Cdo. del Ayto. el precio de la plaza no está actualizado. Se lo digo. Me lo volverá a enviar. ·················· Le envío nuevo correo: "me piden desde Dependencia, para la PVSAR que aportemos también: - Contrato original o copia compulsada del servicio residencial, precio con IVA, régimen de estancia… - Facturas originales o fotocopias compulsadas y recibos bancarios (si el servicio se estaba prestando con anterioridad y tiene retroactividad) desde ingreso residencial. Así que agradecería que me lo hicieses llegar cuando puedas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2022-04-11','miguel, el abogado de la familia (ALFREDO BARCA - ABOGADO >alfredobarca@icac.es>, móvil es 927238105. me envía documentación de la herencia de los abuelos: Buenos días, Le adjunto los documentos sobre las herencias de D. EMILIANO MARTÍN DOMINGUEZ y DÑA. MANUELA CALLE GONZÁLEZ, que son los causantes de dicho proceso. Por otro lado, existe otro incapaz, cuya representación la tiene otro compañero, cuya tutela la ostenta su mujer y, por ello, han procedido a instar al Juzgado la Autorización Judicial pertinente para la adjudicación y aceptación de herencia, teniendo ya respuesta del mismo. Le adjunto en este correo el escrito y distintas resoluciones del procedimiento de ACEPTACIÓN O REPUDIACIÓN DE LA HERENCIA 171/2022 ante al Juzgado de Primera Instancia e Instrucción Nº1 de Plasencia. Este despacho junto con mi compañero, ha elaborado el escrito mencionado ante el Juzgado, el cual puede utilizar como borrador para realizar la solicitud de autorización judicial de DÑA. MARÍA JESUS MARTÍN CALLE. Una vez registren el escrito, ruego nos envíen copia del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2022-04-12','miguel, remito la documentación que me ha enviado el abogado a Jesús Bueno (nuestro abogado) para que vea la documentación, nos dé presupuesto: Buenos días Jesús, tenemos otro expediente que solicitar autorización y aprobación judicial de herencia. Necesitaría me dieras presupuesto en cuanto puedas. Debajo te dejo el contacto del abogado y los documentos que nos ha adjuntado. Parece ser que son dos partes y la otra tienen también abogado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-04-06','Ana: Conversación con Gema, directora Res. Mª Ángeles ha manifestado que quiere quedarse en la misma residencia en la que está. Está dispuesta a vender su vivienda. ········· Hoy mismo la ha visitado una sobrina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2022-04-12','PROTOCOLO SANITARIO PARA TRASLADOS INTRAHOSPITALARIO: -La psiquiatra o médico del hospital de otra CC.AA. lo debe comunicar a admisión de su hospital . -Admisión o secretaría de ese hospital contacta con el mismo servicio de los hospitales en Extremadura y organizan el traslado. -La ambulancia la pone el hospital extremeño , puesto que es un usuario de esta comunidad , recoge a la persona y vuelve . -Según el psiquiatra , puede solicitar hablar con su colega para valorar el caso . -Desde la CTAEX no se gestiona el traslado en sí , que es un recurso hospitalario . Tienen que coordinarse entre hospitales , aunque lo que hacen es utilizar este recurso de intermediario. Debemos trasladar que se siga el protocolo y lo gestionen entre ellos. Es el hospital donde se encuentre ingresada la persona quien tiene que iniciar los trámites y contactar con el hospital de Extremadura . En el H. U. Badajoz la psiquiatra ( Lucia ) no consintió llamar a su colega para valorar el caso , solicitó que fuese al revés; solicitando que yo le facilitara su tf.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-04-12','-Amalia : su hijo Flavio escribe para pedir que se le de de baja a otras 2 lineas de tf que tiene la madre y por las que hace compras en internet . Una a nombre de Blas , envio respuesta : Buenos días , no me queda muy claro tu mensaje . Se acordó contigo que se le daba de baja a la linea de tf con LOWI y tú te encargabas de proporcionarle una línea sólo para llamadas . Ya te indicamos que si hay otra línea abierta a nombre de Blas , obviamente nosotros no podemos darle de baja porque está a nombre de una persona que no es " incapacitada " . Indicas que tiene otra línea más de tf ?? entonces actualmente tiene 3 líneas activas ? dos con datos y una solo con llamadas ? Tras la publicación de la ley 8/2021 de 2 de junio , por la que se reforma la legislación civil y procesal para las personas con discapacidad , se ha producido un cambio radical . Todas las personas tienen la misma capacidad , se sustenta en medidas de apoyo , basadas en la preferencia , voluntad y deseo de la persona. Estamos a la espera de la revisión de sentencia de tu madre para resolver todas estas cuestiones . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-04-12','Ana: Recibimos informe de centro para la rendición anual: Isabel se ha adaptado bien al recurso, tanto que ya no quiere el traslado al CRR de Cáceres, como era la propuesta inicial. Ha aceptado las normas del centro y se ha incorporado a la dinámica del mismo. Aunque "Realiza un afrontamiento a través de conductas autolesiva e ingesta de objetos... Desde su derivación a esta residencia, esto ha ocurrido en 3 ocasiones" (Desde 19/01/22). Ha establecido relaciones de amistad, hecho significativo para su bienestar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-04-12','miguel, remito al jzdo nº3 de Cáceres solicitud de autorización de venta del inmueble y revisión de la sentencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTIAN'and edp.apellido1='CARRASCO'and apellido2='BLANDON'),'2022-04-18','TERESA SE SOLICITA PNC Y REVSION DEL GRADO DE DISCAPACIDAD DERIVACION A FUTUEX LA CASA ESTA DOSORDENADA Y CRISTIAN COMENTA QUE NO HACE NADA PASA TODO EL DIA JUNANDO A VIDEO JUEGOS, COMPRA A TRAVES DEL MOVIL CON UNA TARJE DE RECARGA QUE SE LA CARGA SU MADRE TELEFONOS DE CONTACTO ( 644 16 39 27 ). Y también se le pide el teléfono de su madre Lupe para poder llamarla y hacerle unas preguntas, este es su teléfono ( 643 0958 28 ). SERIA BUENO BUSCARLE ALGUNA OCUPACION: CURSO, TALLER O CO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-04-12','Ana: Llamo a Helga, hermana de Juan José (652 30 39 11), le explico lo mismo que a su hermano y a su madre ayer. Me remitirá por mail el nº de cuenta de su madre para hacerle la transferencia mensual y la copia de la póliza de decesos. ·················· Envío correo a Miguel, Asesor Jurídico, facilitándole el contacto de Helga para que se pongan en contacto con ella en relación a unas causas judiciales pendientes y otra cuestión relativa a la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-04-12','Ana: Envío correo a Álvaro, EUEXIA (ameuexia@gmail.com): "Buenas tardes Álvaro, Comunicarte, que, según me acaban de confirmar y si no surge nada, mañana por la mañana se procederá al traslado de Juan Carlos a otro centro residencial. Por tanto el servicio de acompañamiento del jueves no será necesario. Las facturas como siempre, podéis remitirlas a la atención de la sección económica. Gracias por vuestra atención y servicio. Si volvemos a necesitar otro acompañamiento en Plasencia no dudaremos en volver a contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='MARTINEZ'and apellido2='VAZQUEZ'),'2022-04-12','miguel, envío email afierro7811@hotmail.com,(movil 607771644) Buenas tardes, hemos recibido en la comisión su reclamación en relación a una herencia en la que una de las herederas es la tutelada por esta Comisión Tutelar de Adultos, Doña Concepción Martínez Vazquez. Ruego se ponga en contacto conmigo lo antes posible para intentar agilizar este asunto, pues el compañero Angel Marín hace meses que se encuentra de baja','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MENDO'and apellido2='RODRIGUEZ'),'2022-04-13','TERESA Ayer ingresó en nuestro Centro (Residencia de Mayores "Felipe Trigo"), procedente del Sociosanitario de Mérida, el Tutelado Pedro Mendo Rodríguez. No trae cartilla bancaria, es fumador activo y reclama poder tomar un café diario en cafetería. Tiene la cuenta el Ibercaja, con lo que necesitamos la autorización del SR. Gerente para que el director nuestro pueda sacar dinero para el tabaco del tutelado. Te ruego nos lo envíes cuanto antes, ya conoces a este tipo de pacientes, y lo complicados que son cuando rompen sus hábitos. Puedes adelantarlo por este correo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='MARTINEZ'and apellido2='VAZQUEZ'),'2022-04-13','miguel, llamo sin éxito al abogado Fco Javier Fierro Huertas, al que ayer envié un email para que se ponga en contacto conmigo para iniciar los trámites relacionados con su queja (solicitud de autorización judicial para aceptar la herencia)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2022-04-13','-Amalia : no han comunicado nada sobre el traslado desde Lérida. He informado a Felipe de todo , suponemos que en unos días será trasladada .Es posible que la envíen directamente a La Luz si la ven compensada. EScribo a Mª José TS del hospital .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2022-04-13','-Amalia : no han comunicado nada sobre el traslado desde Lérida. He informado a Felipe de todo , suponemos que en unos días será trasladada .Es posible que la envíen directamente a La Luz si la ven compensada. EScribo a Mª José TS del hospital .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2022-04-13','-Amalia : hablo con la madre , me indica que tiene cita en psiquiatría pero que no quiere ir. Se lo han notificado al psiquiatra. Se va a ir en S. Santa a Cerdañola con unas amigas de allí. Ya ha dejado la relación sentimental que tenía con Edu. Está trabajando en una pizeria , sin contrato , algunos días puntuales y le dan 20€. Los padres quieren información para rehacer su testamento , sus abogados ya le han informado de la nueva ley pero querían contrastar con la CTAEX . Les indico que eso se lo tienen que explicar sus abogados. El padre quiere que la CTAEX ponga límites a su hija , le explico la situación. Quiere hablar con algún superior , la próxima vez le daré el tf de la Jefa de Sección.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2022-04-13','-Amalia : hablo con la madre , me indica que tiene cita en psiquiatría pero que no quiere ir. Se lo han notificado al psiquiatra. Se va a ir en S. Santa a Cerdañola con unas amigas de allí. Ya ha dejado la relación sentimental que tenía con Edu. Está trabajando en una pizeria , sin contrato , algunos días puntuales y le dan 20€. Los padres quieren información para rehacer su testamento , sus abogados ya le han informado de la nueva ley pero querían contrastar con la CTAEX . Les indico que eso se lo tienen que explicar sus abogados. El padre quiere que la CTAEX ponga límites a su hija , le explico la situación. Quiere hablar con algún superior , la próxima vez le daré el tf de la Jefa de Sección.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-04-13','Ana: Llamada de Paula, Programa en C. Penitenciarios de Plena Inclusión (686 76 53 47): El viernes pasado visitó a Saturnino en el Módulo de Enfermería, donde permanece en la actualidad (anteriormente estuvo en el módulo 2). Le hizo una entrevista y le pasó 2 pruebas, en base a las cuales puede afirmar que NO presenta Discapacidad Intelectual. Él le ha verbalizado que ya casi está al día con las deudas que tiene en prisión, pero aún le queda algo pendiente. *Reconoce haber consumido porros estando en el módulo 2, en el de Enfermería dice que no. Le comenta también que el próximo sábado tendrá una comunicación con su madre y que le va a pedir un reloj Casio también para "pagar" tabaco. ···· A parte de estas cuestiones le habla de sus maquetas de música. ··· Y le pregunta cuándo vamos a ir a visitarle desde la CTAEX. ·············· *Aunque Saturnino no puede entrar en el programa de Plena Inclusión, pues no cumple el requisito, seguirá visitándolo de vez en cuando y nos mantendrá informadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-04-13','Ana: Tras llamada de Ceferino, remito correo a Alberto, jefe secc. ecca., con copia a Maite: "En relación al libro digital de Ceferino, éste plantea las siguientes cuestiones: - El precio al que quiere venderlo es 2,99 €. Dice, que según le ha dicho Desirée de Círculo Rojo, el precio está bien y él tendría una ganancia de 1€ por libro. - En cuanto a los beneficios, pide que se le abra una cuenta nueva para él y qué él mismo pueda manejarla. *Le explico que esto no es posible. Pero que ya veremos con qué periodicidad se le puede dar lo que vaya ganando. A mí no me parece mal que se le dé para sus gastos de bolsillo o similar y que así puede notar los “frutos de su trabajo”, considero que es una manera de reforzarle y animarle para que siga escribiendo y/o haciendo otro tipo de cosas productivas en su día a día. Ya me dices si te parece bien y, en tal caso, cómo se le podría dar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-04-13','Ana: Estrella, TS (ssb@malpartidadecaceres.es), envía informe social modificado con el precio público de la Res. actualizado a fecha de 2022. ·········· Más tarde me remite Certificado de Ingreso en Res. también modificado con el precio actual. ································································································································································································· Gema, directora de la RR.MM. Sta. Ana, Malpartida de CC (670 381 292): envía las facturas de la Res. (desde septiembre 2021 hasta marzo 2022).','2');
