insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-04-13','-Amalia . se recibe informe de Futuex . Coordino acciones a realizar de su plan de intervención : -Solicitar cita A.P. para derivación a ESM y pedir informes para solicitar dependencia . -Elaborar presupuesto de gastos e ingresos para establecer si procede asignación económica. Solicito a la sección eco que incluyan al Dtor gerente en su cuenta. Necesitamos más información de su hipoteca , tendremos que retomar el tema con la entidad bancaria para evitar el deshaucio. Gracias . Un saludo','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-04-13','-Amalia . se recibe informe de Futuex . Coordino acciones a realizar de su plan de intervención : -Solicitar cita A.P. para derivación a ESM y pedir informes para solicitar dependencia . -Elaborar presupuesto de gastos e ingresos para establecer si procede asignación económica. Solicito a la sección eco que incluyan al Dtor gerente en su cuenta. Necesitamos más información de su hipoteca , tendremos que retomar el tema con la entidad bancaria para evitar el deshaucio. ------------------------------------------------ Hemos conseguido contactar por teléfono con Justa y nos ha facilitado los números de dos de sus hijos: Alonso Ramón Díaz 681 188 756 Jorge Ramón Díaz 634 746 174 Hicimos el primer seguimiento la pasada semana, fue más o menos bien , ella está bastante receptiva, estamos pendiente de terminar de redactar el informe inicial, en cuanto lo tenga te lo paso. fUTUEX','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2022-04-13','Ana: Tras recibir requerimiento de PNC, remito correo a Toni-Futuex: "En relación a Mª del Mar Campos Encina, hemos recibido este requerimiento de PNC. Agradecería que se lo hicierais llegar y le explicaseis en qué consiste. Ella sigue empadronada en la dirección del recurso residencial en que vivía antes, pero en PNC el año pasado se actualizó su dirección, por eso ahora solicitan documentación relativa a los ingresos de su marido y del domicilio habitual actual. *Tendrá que empadronarse en la vivienda actual. ¿Podéis ayudarles a preparar la documentación y hacérnosla llegar para que se pueda dar registro? Es relativamente urgente, la hemos recibido hoy, pero como veis dan 10 días hábiles. Ya me vais diciendo. Por cierto, el Consentimiento que adjunto también tendrá que rellenarlo y firmarlo el marido."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2021-03-23','Ana: Se pone para REGISTRO declaración anual de PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-04-13','Ana: Llamo a Felisi, dice que está bien. El fin de semana Jesús acudió a visitarla y expresa: "hemos quedado como amigos". ·············· *Ya está su hijo Aitor en casa, para pasar la semana santa, pero finalmente no ha ido sólo, ha ido también su "novia". *Felisi dice que no le gusta porque da muchas voces y discuten mucho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-04-13','-Amalia : escribo a la seccion eco : Buenos días , tras elaborar plan de intervención incial de esta usuaria surgen temas económicos para ver : -Tiene cuenta en Caixa Bank , me indicó Iciar que queríais cambiar la entidad Bancaria . Tenéis ya la nueva cuenta donde esté el Dtor Gerente ?? para solicitar el cambio de su pensión de jubilación. -No abona los pagos de la hipoteca , tiene un proceso de deshaucio . Habría que investigar en la entidad bancaria sobre este hecho y ver qué se puede hacer . Un saludo. Buena Semana Santa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2022-04-13','Ana: email Embajada Mauritania ambarim@embajadamauritania.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-04-12','Ana: Llamada de Mª Carmen Rodríguez, TS HVP-Plas (56283 / mariac.rodriguez@salud-juntaex.es): Martín está ingresado en la UHB. Ingresó en el hospital por Urgencias con estado de salud muy delicado. Ha dado puntuación para T3 /25 puntos). Él quería ingresar en UME, según manifestó, pero dado los cuidados que necesita actualmente (entre otras cuestiones oxígeno) requiere plaza sociosanitaria. ·········· Tal y como acordamos, remito correo a Mª Carmen: "Hola, de nuevo, Maricarmen, De acuerdo a conversación telefónica mantenida, te envío copia del DNI y del resguardo de solicitud de tarjeta sanitaria, que obra en el nuestro expediente. En cuanto al Certificado de Pensión, voy a reclamarlo al INSS, cuando lo reciba, si aún se necesitara, te lo hago llegar. No obstante, tal y como hemos acordado, que firme él la autorización de recabar los datos de oficio. Ante cualquier otra cuestión, no dudes en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2022-04-13','-Amalia : tengo que revisar sentencia , priorizo el caso , le escribo a Miguel para ello. Voy a aprovechar el informe social del SSASB de declaración anual para pedirlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-04-18','miguel, llega a ctutelar el siguiente email de la oficina donde está la cuenta de Caixa Bank05917 FREGENAL DE LA SIERRA >5917@caixabank.com> Siguiendo sus indicaciones, hemos procedido a bastantear la documentación enviada, identificando en nuestro sistema al Sr. José Vicente Granando Granado, para el ejercicio de sus funciones como curador de Don José Antonio Delgado Rodríguez. Sin embargo, no es posible incluirlo en ningún contrato del curatelado, por cuanto el Sr. Delgado Rodríguez no titula ni ha titulado nunca ningún producto en nuestra entidad. Únicamente figuraba como autorizado (firma reconocida) en los productos de su difunta madre. No obstante, como saben, estas autorizaciones dejan de tener validez desde el momento de la defunción de quien las ha otorgado. Por lo que, si se acreditase la condición de heredero del curatelado, para facilitarles la información que precisan para el ejercicio de los derechos que pudieran asistir al Sr. Delgado, tales como certificados de saldo a la fecha de defunción, extractos previos al año anterior y extractos posteriores a la fecha de defunción, en el marco de los derechos sucesorios del declarado incapaz, precisamos que nos aporten: - Certificado de defunción - Certificado de últimas voluntades -Testamento o Declaración de Herederos Ab intestato (o bien Libro de Familia del que se desprenda vinculo de filiación con la causante) Una vez aportada toda la documentación requerida, estaremos encantados de prestarle toda nuestra ayuda y colaboración. ******************************************************* Remito email a Cid y Villafaina (inmaculada@delcidyvillafaina.com): Buenos días Inmaculada, necesito me remitas a este email la documentación que nos solicitan desde Caixa Bank para poner como titular de la cuenta a Jose Antonio Delgado Rodriguez , porque tenemos que poner como representante del mismo, en dicha cuenta, al vicepresidente de la Comisión Tutelar de Adultos José Vicente Granados Granados. Como verás en el email de mas abajo nos solicitan: - Certificado de defunción - Certificado de últimas voluntades -Testamento o Declaración de Herederos Ab intestato (o bien Libro de Familia del que se desprenda vinculo de filiación con la causante) Mandamelo escaneado para que se lo podamos remitir a la Caixa…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-04-18','miguel, confirmé con la notaria de Don Benito (Marisa la firma de esta declaración de herederos, para lo cual pedí por fax al registro civil de Retamal de Llerena, certificado literal de defunción del padre de Eulalia (Pedro Rangel Castillo), sin que hasta la fecha hayan contestado. Desde el centro de plena inclusión de Montijo (Eva Álvarez >trabajadorasocialco@plenainclusionmontijo.org>) me escribe remitiendo el certificado de defunción del padre: Acabo de incorporarme de vacaciones y he visto un correo que me mandó Amalia la semana pasada solicitado algunos datos del padre de Eulalia Rangel Porro. Buscando en los documentos que tengo ha aparecido el certificado de defunción. Te lo reenvío, aunque se ve un poco mal. *************************************************** la contesto solicitandole que si tiene el original me lo remita por carta certificada al SEPAD.','2');
