insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='ALMANSA'and apellido2='REDONDO'),'2022-04-18','TERESA ANGEL TIENE PROBLEMAS DE ALCOHOL Y POR ELLO TIENE CONTINUOS CONFLICTOS EN LA RESIDENCIA DESDE LA DIRECCION SOLICITAN QUE LO CAMBIEMOS DE CENTRO RMFUENTEATENOR@SALUD-JUNTAEX.ES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-04-19','Buenas tardes. Soy Ana de Celis da Silva, monitora del CRR de Olivenza (Caser). Te mando este correo para indicarles que la usuaria EMILIA MORALES BOTELLO ha sido trasladada en ambulancia al Hospital Universitario de Badajoz por intento autolítico, para ser valorada en la U.H.B. en la tarde del 13 de Abril de 2022. Un cordial saludo. Ana','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2022-04-19','miguel, el abogado PABLO GARROTE DELGADO >pablogarrotedelgado@icaba.com> , me envía email: Estuve en notaría para empezar con la herencia de Francisco. No sé si teneis constancia de los datos de defunción del padre, pues han requerido certificados de nacimiento y de matrimonio, así como el libro de familia si fuera posible por si hubiera habido otros hermanos fallecidos. Además de saber mediante nota simple las propiedades del matrimonio por si aparecieran otros bienes. ********************************************* Le remito certificado de defunción de la madre y de catastro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-04-19','-Hablo con Mª , psicologa del CRR . Tuvo dos intentos autolíticos pero no fue ingresada en UHB. Exigen que se pueda utilizar con ella la medida de salida terapéutica en un hostal .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-04-19','miguel, remito email a la notaria de Don Benito para avisar de que no he podido hacer el testimonio de firma del gerente José Vicente por estar éste enfermo esta semana: Buenos días Rafael, siento comunicarte que no es posible firmar esta semana la escritura por nuestra parte porque el representante y vicepresidente de la Comisión Tutelar de Adultos, Don José Vicente Granados Granados está con Covid desde hace 2 días. Estamos pendiente de a su vuelta poder hacer el testimonio de su firma en la notaria de romero leal de Mérida. De todas formas yo sí iré para asistir con tu compañera Marisa a la firma de unas declaraciones de heredero. En cuanto tengamos la firma testimoniada de Don José Vicente Granados Granados te aviso para que puedas fijar nueva fecha de firma. De todas formas aprovechando que de todos modos iré por allí este jueves día 21-4-22 necesitas que lleve algún documento del tutelado D. José Luis Murillo Horrillo, házmelo saber.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-04-18','miguel, tal como me indicó por tlfno el juzgado nº3 de Badajoz, le remito por carta, la solicitud de información del procedimiento abreviado 117/2021, y que si fuera preciso nuestra asistencia nos den videoconferencia, así como si fuera necesario se solicite por este juzgado abogado del turno al colegio de abogados de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-04-18','miguel, remito al juzgado nº3 Caceres el anexo a la solicitud de venta y aclaración de nuestra continuación o no como administradores de bienes para lo cual solicité se revise la sentencia conforme la ley 8/21.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-04-19','remito al colegio de abogados relleno los modelos que nos remiten para le asignen abogado de oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2022-04-19','Buenos días , Pilar va a ingresar en plaza residencial aprosuba 3 hoy. En la cuenta está de titular su madre , hay que cambiar ésto para que ya no tenga acceso y poner a J.Vicente. Se abonará el 75% de la PFHC para copago ( 414,70€ cuantía actual por 12 meses ) . El resto para gastos de bolsillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='CABEZAS'and apellido2='MAZON'),'2022-04-19','TERESA ENVIO CORREO A ANA AGUILAR TS DE LA RESIDENCIA PARA COMUMICAR QUE LA CUENTA ESTA EN NUMERO ROJOS TSDONBENITO@HHDD.ORG','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='CRESPO'and apellido2='CRUZ'),'2022-04-18','Ana: Correo de Mariví Clemente, TS del CSS-Plas (victoria.clemente@salud-juntaex.es): "Con fecha del 14 de abril de 2022 se trasladó al Hospital Virgen del Puerto de Plasencia a la Paciente Dª. Victoria Crespo Cruz, enferma internada en el ULE de este Centro socio Sanitario , permanece ingresada a día de hoy en el mencionado Hospital. Comunico el internamiento a esa CTAEX al tratarse de una incapacitada tutelada." ·················· Respondo: "Buenos días Mariví, Gracias por informar. Ayer no trabajé, y el correo del ctutelar@ todavía no lo había visto. Comunicarnos si es necesario contratar algún acompañamiento. Por cierto, ¿a qué es debido el ingreso?, ya me informas cuando puedas. Un saludo y buena mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-04-19','Ana: Correo de Paula, TO CRR-Plas (tocupacional.crrplasencia@grupo5.net): "Isabel Cano, está en el Hospital porque ayer hizo una ingesta de un producto y se encuentra en la UCI." ······················· Llamo a Paula (682 70 44 01): conectan el manos libre y hablamos Paula, Blanca (Directora CRR) y yo. Isabel, en el día de ayer, al rato de haber regresado al CRR de la estancia por vacaciones de semana santa en su pueblo, verbalizó a la monitora que se había tomado un bote de detergente friegasuelos y explica que en la visita anterior, la pareja de su madre le realizó tocamientos sin su consentimiento. En este viaje, la madre no ha querido dejarlos a solas para evitarlo, por tanto no ha ocurrido. Al poco de contarlo llegó la ambulancia por lo que no pudieron abordar más el tema. ·········· Desde el hptal. informan que llamaron a la madre y ésta contestó que ella no iba a ir al hospital. ············· En cuanto a la ingesta, sigue en la UCI, han descartado secuelas tanto los especialistas de Digestivo como el Endocrino. Mañana van a retirarle la sedación poco a poco. *Desde el centro han intentado contactar con la Policía Judicial sin éxito. Volverán a llamar. ······ *Lo comentarán también con Psiquiatría para que puedan abordar el asunto. ······················ Lo pongo en conocimiento de Miguel, Asesor Jurídico. ···················· Envío correo a Blanca y Paula CRR: "En relación a ISABEL CANO BLÁZQUEZ, y a petición de Miguel, Asesor Jurídico CTAEX, os solicito para que pueda remitir al Juzgado: - Informe Médico del Hospital del incidente acaecido (Ingesta). - Informe de lo ocurrido (lo narrado en vuestro centro) El primero, ¿podríais solicitarlo vosotras al hospital? Más que nada porque sois las que estáis en contacto. Si os pusieran alguna pega, decírmelo e intento contactar yo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-04-18','Ana: Correo de Pilar Martín, TS del ESM-CC: "Hola Ana, la madre de Doroteo me facilita el nº de cuenta propio-ES02 2048 1200 1130 0020 1532. Un abrazo." ················· Se lo paso a Óscar, Secc. Ecca., para que a partir del mes de mayo comiencen a hacerle la transferencia en concepto de manutención, tal y como se había previsto en presupuesto inicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-04-19','-SALDO ACTUAL : ESTE ES EL SALDO A FECHA DE 19/04/2022 7.455,35 €','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-04-19','Buenos días, se está tramitando el cambio de la cuenta a LIBERBANK, pero de momento está pendiente. Del tema de la hipoteca y del desahucio no hemos averiguado nada, caixabank aún no nos ha informado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-04-19','TERESA RECIBO LLAMADA DE TONY DE ADISER PARA COMENTARME LA SITUACION DE AITOR AITOR HA PASADO UNOS DIAS EN CASA DE SU MADRE Y HA ESTADO ALLI CON LA PAREJA QUE ACABA DE EMPEZAR A SALIR CON ELLA LA MADRE MANIFIESTA QUE HAN TENIDO RELACIONES SEXUALES SIN PROTECCION A PESAR DE QUE DESDE LE PROGRAMA DE FAMILIA LE HAN EXPLICADO DEL RIESGO QUE ELLO CONLLEVA AITOR VUELVE HOY AL CENTRO Y HABLARA LA PSICOLOGA CON EL FELISI COMENTA QUE LA PAREJA DE AITOR QUIERE QUEDARSE EMBARAZADA, SU PRETENSION ES ES SER MADRE Y SER LA TUTORA DE AITOR Y VIVIR CON EL Y CON SU HIJA EN PRINCIPIO VAMOS A RESTRINGIR LAS SALIDAS DE AITOR HASTA EL VERANO A VER COMO EVOLUCIONA LA RELACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2022-04-19','Buenos días, se está tramitando el cambio de la cuenta a LIBERBANK, pero de momento está pendiente. Del tema de la hipoteca y del desahucio no hemos averiguado nada, caixabank aún no nos ha informado.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2022-04-19','Buenas tardes Amalia, ya tenemos la prescripción medica, fotocopia del DNI, de la TJ SS, factura original y te envio tb un modelo de alta a 3º Esta documentación es lo que hay que entregar a una trabajadora social del SES para que abonen la prestación A que dirección de correo ordinario tengo que enviarla? Un saludo Vere','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='ALMANSA'and apellido2='REDONDO'),'2022-04-19','TERESA ENVIO CORREO SOLICITANDO COPIA DEL DNI E IFORMACION ECONOMICA DE ANGEL SE VALORA EL TRASLADO DE RESIDENCIA Y SE INDICA DERIVACION A ECA EN EL CASO DE QUE EL QUIERA ASISTIR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-04-19','email del centro Buenos dias comunicar que el usuario tutelado por ustedes de la residencia de mayores de Barcarrota, Anastasio Vaquerizo Pizarro ha sido ingresado esta noche en el hospital universitario de Badajoz . Saludos y seguiremos informandoles .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2022-04-19','Ana: Correo de Julián, Gerente de COCEMFE (gerencia@cocemfecaceres.org): "Buenos días Ana. Informarte que Tomás Estebán debe ir a revisión médica al Hospital Nacional de Parapléjicos de Toledo el día 9 de mayo. Debe ir acompañado de un asistente personal (cuidador/a) como en años anteriores. En principio tiene que ir otra usuaria de COCEMFE ese mismo día con lo cual compartirían los gastos del asistente personal. Te enviaré la declaración jurada de la persona acompañante y el presupuesto de los gastos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2022-04-19','TERESAMaria Elena quiere subir la asignación de bolsillo porque dice que no llega el dinero. Alberto dice que para subir asignación habría que dejar de pagar las terapias de su hijo que son 100€ mensuales He hablado con Lupe la trabajadora social y me comenta que las terapias para Juan son muy necesarias ya que Juan se encuentra muy tocado por las situación familiar que tiene. Hemos acordado que ella va a solicitarle la comida a través del ayuntamiento para que tenga menos gastos y así poder seguir pagando las terapias a su hijo Juan a pesar de que ella no esta de acuerdo con este gasto. Vamos a comunicarlo al juzgado acogiéndonos a la obligación de alimentos que tiene Elena para con su hijo. Como se administra mal el dinero es necesario que la educadora le acompañe en las retiradas de asignación que son de 140€ quincenales y le ayude con la gestión del dinero de bolsillo. En principio no voy a cambiar la autorización al banco, simplemente que la educadora se cuadre con Elena y la acompañe a ver qué tal funciona así y valoramos más adelante si se lo restringimos a que solo pueda sacar acompañada como hacemos con Cándido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2022-04-19','miguel, me pregunta Jose Mª de Asesoría Pinilla tlfno 924-047828, email pinilla@cayetanoasesores.es, porque el borrador de datos fiscales 2021 del tutelado aparece una finca como si la hubiera vendido. Tras revisar el expte veo que Angel canceló en el registro un embargo, autorizó el cambio de cerradura de uno de los locales. Creo que quedan 2 y se vendió en tiempo uno. Y aunque estuvo en contacto con el abogado Ignacio creo que no se ha hecho autorización de venta. Veo que se solicitó tasación a la inmobiliaria bpastor@iconinmobiliaria.es. Reenvío a Angel email para compruebe si efectivamente se vendió y/o el estado en que se encuentra este expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-04-19','Ana: Envío correo a Maite, Jefa Secc. y Rosa, Res. Francisco Asuar de Fuente de Cantos (cofa@fuentedecantos.es): "Buenos días a las dos, Juan Carlos percibe: - Orfandad Absoluta: 402,97 € x 14 - PFHC: 417,70 € x 12 La cuenta la tienen en IBERCAJA y el nº es el siguiente: ES28 2085 4511 9203 3187 4889 La cuantía habrá que establecerla con el jefe de sección económica, en función del dinero que le queda descontando el abonado de la plaza (el tanto por ciento correspondiente de sus ingresos). Pongo en copia a Óscar, de la sección económica, para que cuanto Alberto se incorpore lo vean. *En cuanto a la hora de las llamadas, si os viene bien, mañana sobre las 12:30. Se pueden mantener cada 15 – 21 días según disponibilidad, iríamos cuadrándolo en cada llamada. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2022-04-19','Ana: Correo de Estrella, TS CSS-Plas (estrella.duranc@salud-juntaex.es) en respuesta a mi consulta: "Andrés está, hoy mejor, pero mañana, a lo peor, ya no lo está, es muy cambiante, también en lo que respecta a sus deseos de futuro...unas veces dice que quiere volver a su centro y al día siguiente, quiere quedarse aquí para siempre...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2022-04-20','Ana: envío a Toni-Fututex correo-respuesta al suyo enviado ayer a las 14:37: "En cuanto a la asignación de Sandra, efectivamente es muy precipitado. He revisado el correo, tanto el mío personal como el común (ctutelar@salud-juntaex.es) y aquí NO HA LLEGADO NINGÚN PRESUPUESTO relativo a Sandra Sandín hasta ahora y por tanto no ha podido valorarse. Además Alberto, jefe de Sección económica no está esta semana. Hablaré con Maite, a quién pongo en copia, al respecto, pero no puedo garantizar nada y menos para hoy. Seguimos en contacto. Un saludo y buen día." ····················· Remito presupuesto a Óscar, secc. ecca, en principio, si Alberto no dice lo contrario, para el próximo miércoles día 27 estará la autorización en el banco. *Es la fecha acordad con Toni-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-04-20','TERESA se encuentra ingresado en la planta quinta habitación (503), está a cargo de Medicina Interna , en estudio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2022-04-20','Ana: Llamada de Minerva, CR Cervantes (22237): Me comunica que la Directora del Centro ha llamado a May, Jefa Secc. Acceso a Recursos de Mayores, en relación a la solicitud de traslado de Mª Luisa y le ha dicho que no hay constancia de dicha solicitud. *Informo a Minerva que tenemos copia del documento registrado. Llamo a Ana Isabel Moreno Gilgado, TS Gerencia Territorial de BA (924 01 01 49 / 20533): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-04-20','miguel, avisé a Rafael ayer por email de que no hemos podido hacer el testimonio de firma en la notaria de Mérida porque el gerente está con Covid. Recibo email de Ana de Pablos (abogada de la familia): me han comunicado que no ha podido realizarse la firma por motivo del Covid. Le pido por favor que si es posible que la nueva fecha de firma sea antes del 29 de abril, según me lo solicita la gestora del banco Santander, para que lo comunique usted a la Notaría. ¿Podrá firmarse antes del 29 de abril? ********************************************* Mi contestación: Buenos días, aunque yo iré mañana a la notaria de Don Benito, ésta nos requieren un testimonio de firma del representante de la Comisión Tutelar de Adultos, que actualmente tiene Covid. Una vez que vuelva dicho representante de la Comisión Tutelar, se intentará firmar enseguida dicho testimonio en una notaria de Mérida para posteriormente firmar en Don Benito, pero como digo depende del tiempo de baja que esté esta persona. Tomo nota de su email y en cuanto tengamos el testimonio firmado le aviso a ambos a la notaria y a ustedes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-04-20','TERESA Buenos días Teresa, te resumo el día de ayer en relación a Aitor Moreno. Virginia de FUTUEX y yo estuvimos toda la tarde en contacto por el tema de Aitor. Virginia comprobó en la estación de tren que Aitor no subió finalmente al tren. La madre de Aitor me llamó para decirme que su hijo estaba pidiendo dinero a todos los conocidos para irse con la novia a Badajoz y que como no lo consiguió se puso en contacto con ella para que le pagara un taxis a Badajoz o a su casa nuevamente en Navas. A este centro llamaron de la Policía de Badajoz y del 112, porque Jesús, la expareja de Felisi, llamó identificándose como su padrastro diciendo que Aitor se había escapado de este centro. En conversaciones con Virginia, sé que se contactó con Aitor para informarle sobre la posibilidad de pasar la noche con su novia en un albergue que hay en Cáceres. La comunicación con Aitor nula totalmente. Acabo de contactar con la madre y me comunica que Aitor volvió allí con la novia y que sus intenciones son de quedarse allí y no volver al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2022-04-20','Ana: *En cuanto a la dificultad ecca. con el banco, hace semanas que están dándole de nuevo el efectivo de las asignaciones autorizadas desde la CTAEX. *Seguimos en espera de las Tarjetas Monedero. ························ *Recibo correo de Toni-Futuex con informe médico y nota con las cremas pautadas (una de las cuáles no entra por la Seguridad Social). ······· Nos remite también informe de la última consulta en Psiquiatría, ESM. Al final del mismo, el Psiquiatra, Enrique Goenaga, especifica: "El juzgado debe ordenar que el curador acompañe al paciente a las consultas. EL PACIENTE DEBE VENIR ACOMPAÑADO. UNA PERSONA DEBE RESPONSABILIZARSE DE QUE ACUDA A PONERSE EL INYECTABLE" ·············· Se lo remito a Maite y a Miguel, CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-04-20','miguel, email para Oscar, Julio y yo de Ana Ts: Os comunico el INGRESO VOLUNATRIO de MARTÍN DOMINGUEZ PALENCIA en el Centro Ciudad Jardín Virgen de la Montaña del Casar de Cáceres. Ingresará esta misma tarde. Ocupa una plaza Sociosanitaria modalidad T3, cuyo coste según resolución asciende a: 861,56 €/mes, le pasarán el cobro, no sé si habrá problemas dado el “bloqueo de la cuenta” - Julio, cuando puedas actualiza la base de datos - Miguel, dinos si hay alguna novedad en cuanto a la reclamación al banco de España. - Miguel, en cuanto reciba el Certificado de Ingreso en Centro, que ya lo he pedido, te lo paso para que puedas comunicarlo al Juzgado. - Óscar, espero que no haya problemas con el cobro. Posiblemente también nos envíen correo comunicando necesidad de comprar ropa. - Óscar, en cuanto al coste de la plaza, sé que es elevado, pero se le valoró en su día por Dependencia y dio sin grado. Pediré al centro que soliciten revisión, por si diera grado II y se le pudiera abaratar el coste o a las malas, llegado el momento, cambiara de tipo de plaza y/o incluso de centro residencial. - *Óscar, no podemos olvidar que sigue sin seguro de decesos, por el bloqueo bancario, tras varios meses sin pasarle el cobro, se lo dieron de baja, a ver si contestan del Banco de España o no sé de qué otra forma se puede solucionar. De momento sigue siendo Curatela para el ámbito patrimonial principalmente **************************************** Hola, Ana, el internamiento involuntario que dictó el juzgado no sirve para que sea menor el coste del centro? En cuanto me envíes el justificante lo comunicamos al juzgado. Del Banco de España no tengo noticias, si me entero de algo os diré. ·································································································································································································· *Recibimos resolución de Plaza T3.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-04-20','Ana: Correo de Cristina, Ed. Soc. As. Vera (educadorasocial@asociacionvera.com): "Buenos días, Solicito autorización para que Adrián Ortigosa Fuentes pueda pasar unos días con su familia y asistir a la boda de su hermano que será el día 30 de abril. Hemos esperado hasta ahora para ver la evolución de su conducta, como su conducta ha sido adecuada, desde el equipo técnico del centro aconsejamos que se autorice dicha salida (Adjunto Ausencia Voluntaria). Viaje desde el 25 de abril hasta el 6 de mayo. Detalles del viaje: Autobús ida y vuelta desde Plasencia a Badajoz, Taxi ida y vuelta desde Badajoz a Villanueva del Fresno: • Ida: salida desde Plasencia a las 17:00 horas, llegada a las 20:30 a Badajoz dónde le esperará Teresa Futuex para acompañarle al taxi que lo llevará hasta Villanueva del Fresno. • Vuelta: salida desde Villanueva del Fresno con el taxi que lo recogerá en su domicilio hasta Badajoz, allí le esperará Teresa Futuex para acompañarle al autobús que lo llevará desde Badajoz a las 9:00 horas a Plasencia que llegará a las 12:40 a Plasencia. Presupuesto del viaje: • Billetes de autobús: 39.06 € • Taxi ida y vuelta: 160 € aproximadamente • Ropa para acudir a la boda: camisa y pantalones 90 €. Necesito saber lo antes posible si se autoriza dicha salida y puede asumir los costes del viaje." ····················· Envío mail respuesta a Cristina, Ed. Soc. As. Vera: "Buenas tardes Cristina, El Gabinete Técnico de la CTAEX autoriza tanto la salida, adjunto el documento de Ausencia Voluntaria firmado y sellado, como la retirada de efectivo para los conceptos detallados. *La autorización estará lista para que podáis retirar el dinero en la oficina bancaria habitual a primera hora del viernes 22. Ante cualquier otra cuestión, no dudes en volver a contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-04-20','TERESA SE REALIZA LLAMADA A FELISA MADRE DE AITOR PARA CONFIRMAR QUE ESTA EN EL DOMICILIO CON SU MADRE NOS COMENTA QUE ESTA ALLI SU HIJO Y LA NOVIA DE AITOR Y QUE ELLA ESTA DE ACUERDO CON QUE SE QUEDEN ALLI CON ELLA HABLAMOS CON AITOR PARA INTENTAR CONVERCERLE DE QUE VUELVA AL CENTRO PERO EL NO QUIERE INSISTE QUE QUIERE VIVIR COMO VIVE SU MADRE QUE NO QUIERE ESTAR MAS EN CENTROS QUE QUIERE SALIR CON SUS AMIGOS QUE LLEVA TODA LA VIDA DE CENTRO EN CENTRO COMENTA QUE VA A TENER UN HIJO CON MIRELLA MIRELLA TAMBIEN PARTICIPA EN LA CONVERSACION Y AFIRMA EL DESEO DE SER MADRE Y QUE CREE ESTAR YA EMBARZADA PUES SE LO NOTA SE LE COMENTA QUE SON MUY JOVENES, QUE LLEVAN POCO TIEMPO JUNTOS PARA TOMAR ESA DECISION Y QUE ADEMAS NO TIENEN MEDIOS ECONOMICOS PAR CRIAR UN HIJO AITOR PARACE CONVENCERSE Y ABANDONAR LA IDEA DE SER PADRE PERO NO QUIERE VOLVER AL CENTRO BAJO NINGUN CONCEPTO SE LE INDICA QUE SE HAGA UN TEST DE EMBARAZO PARA ASEGUARNOS QUE NO ESTA EMBARAZADA VAMOS A HABLAR CON EL PROGRAMA DE FAMILIA PARA QUE LE HAGAN SEGUIMIENTO Y LE DERIVEN A PLANIFICACION FAMILIAR SE VA A COMUNICAR LA SITUACION AL JUZGADO YA QUE CONSIDERAMOS QUE AITOR SE ENCUENTRA EN UNA SITUACION DE DESPROTECCION YA QUE NO TIENE CAPACIDAD PARA VIVIR SOLO, SU MADRE TAMBIEN TUTELADA POR LA JUNTA DE EXTRAMADURA TAMPOCO TIENE CAPACIDAD PARA CUIDAR DE EL. LA PAREJA DE AITOR ES MUY RECIENTE SE HAN CONOCIDO A TRAVES DE LAS REDES SOCIALES NO TENEMOS MAS INFORMACION DE ELLA TAN SOLO QUE FUE MADRE SIENDO MENOR DE EDAD TENIENDO LA CUSTODIA EL PADRE DEL BEBE. A ESTO SE LE SUMA QEU AITOR TIENES PORBLEMAS DE CONSUMO LO CUALES SE DISPARAN CADA VEZ QUE ESTA EN EL DOMICILIO FAMILIAR PUES SUS AMISTADES CONSUMEN.','2');
