insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-04-21','Ana: Correo de Marily, CO Miajadas al ctutelar@: "Buenos días necesito que me enviéis a la mayor brevedad posible un escrito de renuncia a la plaza en el centro ocupacional de Miajadas de D. Felipe Rodríguez Solís, tutelado por la Junta, para proceder a la baja en dicho centro. un saludo" ····························· Respondo: "Buenos días Marily, Desde que yo trabajo aquí Felipe no acude a CO, así que pensaba que esto ya estaba hecho… a lo largo de la mañana, en cuanto la tenga firmada por el D. Gerente te la envío. Un saludo y buen día." ····························· *Remito a Marily por mail la Renuncia a la plaza del Servicio de C.O.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='MARQUEZ'and apellido2='CABEZA'),'2022-04-06','- Email del CRR : Amalia ya tengo toda la documentación para el cambio de PIA a residencia de mayores de Vicente Márquez, tal y como hablamos por teléfono. Pero son muchos folios, por lo que si no hay problema te lo mando todo por correo ordinario, así lo acabáis de rellenar y ya lo entregáis vosotros mismos al SEPAD. -------------------------------------------------------- Lo termino de cumplimentar y se ha registrado a dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2022-04-21','TERESA ENVIO SOLCITO CAMBIO DE DIRECION A EFECTO DE NOTIFICACIONES AL INSS Y SOLICITO NOS ENVIE LA ULITAMA ACTULIACION DE LAS PENSIONES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-04-21','-Amalia , envío email a su hijo Flavio : Buenos días, acabo de recibir un email de la sección económica de esta Comisión. Se dió de baja a la compañía LOWI como se acordó , pero efectivamente aún no le han dado de baja y han enviado el recibo. Me dicen los compañeros que han solicitado la devolución del recibo a Ibercaja. Estamos hablando del Nº de tf. cuyo titular es tu madre y en el contexto que habíamos acordado en el que tú le entregabas otro tf . con llamadas, para evitar sus compras compulsivas por internet. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2022-04-21','-Amalia , envío email a su hijo Flavio : Buenos días, acabo de recibir un email de la sección económica de esta Comisión. Se dió de baja a la compañía LOWI como se acordó , pero efectivamente aún no le han dado de baja y han enviado el recibo. Me dicen los compañeros que han solicitado la devolución del recibo a Ibercaja. Estamos hablando del Nº de tf. cuyo titular es tu madre y en el contexto que habíamos acordado en el que tú le entregabas otro tf . con llamadas, para evitar sus compras compulsivas por internet. Un saludo. --------------------------------------------------------- Respuesta de Flavio: Muy buenas Amalia. Estoy en comunicación permanente con mi madre para que en cuanto se le dé de baja a ese número yo le provea de la tarjeta de llamadas ilimitadas y sin conex. a Internet. De todas formas y, de momento, ella tiene otra línea de teléfono que no usa para internet y con la que ella se comunica por teléfono conmigo y con otras personas regularmente (la 611650311). Un saludo y muchas gracias por la pronta respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2022-04-21','Ana: Tras conversación con Modesto, Res., reenvío a Óscar, Secc. Ecca, correo con presupuesto de tratamiento dental: "Buenas tardes Óscar, Me envían presupuesto para tratamiento dental relativo a JUAN SANGUINO LANCHO. Según me informa el Director del centro, ya lo enviaron en noviembre y estaban a la espera de respuesta. Imagino que este presupuesto ya no estará vigente, pero será aproximado. Juan tiene dinero y necesita el tratamiento, así que por mi parte ok al mismo. Dado el tiempo que hace que lo enviaron, habría que darle prioridad. Por cierto, próximamente también enviarán presupuesto de ropa, con lo que también estoy de acuerdo, pues la necesita y puede permitírselo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2022-04-21','-Amalia , escribo a sección eco : Buenas , tras contactar con las TS del centro sociosanitario se ha podido averiguar lo siguiente : Ha sido un hermano de Barcelona el que ha sacado los 1500€ de la cuenta en la que está con su padre , para pagar una puerta de la casa familiar . El padre está ingresado en R. Mayores en Medina de las Torres , por eso me extrañaba tanto que este señor tan mayor hubiese hecho un reintegro. Se ha hablado con su hermano y va a devolver el dinero a la cuenta . Podéis esperar a ver que ha reintegrado ese dinero y que la pensión se empieza a percibir en la otra cuenta para traspasar todo ese dinero a la cuenta en la que está como único titular y cancelar ésta . Se ha hecho un nuevo presupuesto de gastos con el centro , se tiene que reducir su consumo de tabaco y coca colas ( consume 4 al día ) . Se van a reducir esos consumos para que en ningún caso pueda sobrepasar los ingresos . Vuelvo a solicitar cambio de Nº cuenta de la pensión, desconozco porqué no se llevó a cabo la petición . Un saludo .','2');
