insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-04-21','-Amalia : envio email a Manuel Picado de Pisos : Buenas Manuel , con respecto al presupuesto dental y de móvil , he escrito a la sección económica para valorar viabilidad . Te daré respuesta . Con respecto a ayudas de alquiler , emancipación, solicitud de vivienda de protección oficial ... existen varias vías . La más directa que ya le facilité yo a la chica , es que pida cita en la Consejería de Movilidad , transporte y vivienda, en la Dirección General de vivienda. En internet tenéis teléfonos para preguntar sobre todas estas ayudas. Está ubicada en el Tercer Milenio en la zona del Peri , por si quiere ir presencial a solicitar la cita . Servicio gestión ayudas : 924332050 Servicio adjudicación vivienda 924332454 Oficina de atención al público 924303554 Un saludo .','2');
