insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-04-21','miguel, remitimos por carta (sirex) contestación al juzgado del requerimiento que nos hicieron ratificándonos en la solicitud del internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-04-21','-Amalia , escribo a Futuex: Buenas , acabo de hablar con TS del ESM . Me dice que según sentencia por el tema del incendio en los Montitos se le ha impuesto tto. ambulatorio en ESM. Podéis haceros copia de esta sentencia ? Me indica que cree que la revisión del CADEX ya le ha llegado , también se necesita copia para que desde el ESM se pueda valorar solicitud de UHDAC. Estas sentencias la necesitan en el ESM , para la próxima cita se las entregáis a Carmen o si preferís me las podéis enviar a mí y yo se lo reenvío.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2022-04-21','miguel, he ido a la notaria de Don Benito y me piden de este expte para hacer la declaracion de heredero de su hermano Frnacisco: 1.-certificado de defunción de sus padres 2.-libro de familia (y caso de que no haya certificado de nacimiento del fallecido Francisco Rangel Porro y Certificado de Matrimonio de los Padres) *********************************************** Se lo pido a Amalia para que lo solicite al Plena Inclusión de Mérida. Amalia envía el siguiente email: Buenos días , a petición de mi compañero el jurídico me solicita información sobre la documentación de sus padres. Ya te envié una petición de los documentos de la madre pero también se necesitan del padre. En su expediente tenéis por casualidad libro de familia , cdo. defunción de los padres , cdo. de matrimonio ó Lali sabe dónde pueden estar esos documentos ??','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-04-21','Ana: Llamo a Celia, TS de HVP-Plas. (78206): Ya han pasado a Isabel de la UCI a UHB. Mañana hablará con el Psiquiatra a primera hora y le solicitará el Informe para hacérmelo llegar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2022-04-21','Ana: Llamo a Ana Isabel Moreno Gilgado, TS Gerencia Territorial de BA (924 01 01 49 / 20533): A May no le aparece la solicitud de traslado porque ella sólo puede ver los de Dependencia y el de Mª Luisa se solicitó a través de Decreto, pues fue un ingreso involuntario por emergencia social. Mantiene Grado I de Dependencia. *Mª Luisa continúa en lista de espera, no hay plazas libre en la Res. de Castuera que es la única que ha pedido (no aceptaba otra). ··········· La única forma de agilizarlo sería que Instruyeran expediente sancionador o que, partiendo de informe del centro, dieran prioridad en la Dirección Gerencia (May o Víctor, Jefe Ud.) ······························································································································································································ Llamo a Minerva, CR Cervantes (22237): sin éxito, volveré a llamar mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-04-22','miguel, me llaman del jzdo nº1 de Villanueva para decirme que ya tiene abogado y procurador de oficio y que remiten a la Audiencia Provincial el procedimiento para continuar su curso','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2022-04-22','miguel, remito al jzdo nº2 de Caceres por Inside solicitud para que de oficio remitan el testimonio de sentencia firme de nombramiento al registro civil de Madrid para su inscripción en el libro de nacimiento a efectos de cumplir con lo solicitado por la asesoría, para que puedan inscribir en el registro de la propiedad el cambio de titular registral','2');
