insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-04-22','Ana: Tras conversación con Mariluz Madrigal, Eva y Raquel, Secc. Salud Mental, llamo al CRR. Hablo con Javier, Gerente del CRR: Una vez ha pasado a UHB, el Dr. Blanco, Psiquiatra, considera que se le puede dar el alta, pero dado que no está para volver a CRR, considera que debe ingresar una temporada en UME, pero el Dr. Daniel está de excedencia y el Dr. Agapito no está de acuerdo en dicha derivación. *Además plantea que como ella ahora no quiere volver a UME, dice que la CTAEX deben autorizar medidas de contención mecánica y el ingreso involuntario. *Esto no es así, y en todo caso debe autorizarlo el juzgado, habría que solicitarlo con los informes médicos oportunos y el trámite es mucho más lento. ·············· Más tarde envío correo a Blanca, Directora del CRR (direccion.crrplasencia@grupo5.net / 673 22 55 27): "Buenas tardes Blanca, Como sabes, hablé esta mañana con Javier y previamente con Mariluz Madrigal, Jefa de Sección de Recursos de Salud Mental. De momento no hay novedad, que yo sepa. A ver qué determinan el lunes los psiquiatras, pues la vía más rápida está en su mano. El lunes hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-04-22','Ana: Correo de Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com): "Buenos días, Adrián solicita autorización para realizar el viaje de Badajoz a Villanueva con su padre que le va a recoger a él y a su novia... Desde el centro creemos que no es lo más indicado porque no nos aseguramos que llegue a su domicilio. Pero necesitamos saber si vosotros lo autorizáis o no. También me comenta la posibilidad de ir con él en el Taxi." ····························· Mi respuesta: "Buenas tardes, Dado vuestro criterio y los antecedentes, nos reiteramos en el plan y autorización inicial, no autorizando a realizar dicho viaje con su padre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2022-04-22','Ana: Toni-Futuex me remite seguimiento del mes de abril. Envían factura del Hotel. ···· *En el Serv. de Lavandería Tele-lavo, han subido el precio 10€, por lo que han hablado con el hotel y asumen el servicio de lavado y planchado por 55€. Se acepta pues es mejor precio. Lo cargarán en la factura. ·········· Han consultado en el otro alojamiento pero no hay habitaciones disponibles aún. ·········· En el hotel van a valorar la posibilidad de rebajar un poco el precio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-04-25','miguel, recibo email de Sonia Bernabé Asindi Plena Inclusión >trabajosocial@asindi.e.telefonica.net> Hola Miguel, quería comentaros que una de las agresiones de Aarón hacia un compañero que había sido archivada, ha sido reabierta por el fiscal. Si recibimos algún documento al respecto por parte del Juzgado al lo remitiremos enseguida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-04-20','Ana: Llaman desde Adiser a Teresa, TS CTAEX, comunicando que Aitor, hijo de Felisis, no quiere regresar al centro. ·············································· Hablamos con Miguel, Asesor Jurídico CTAEX, quien confirma que no podemos obligarle para que vuelva al centro y en todo caso, si se valorasen motivos suficientes, habría que solicitar autorización de internamiento involuntario al Juzgado aportando Informes. ··························· Llamamos a Felisi, pone el manos libre, están allí en su casa Aitor y la pareja de éste. Dice que ellos se quieren quedar allí a vivir los dos, con Felisi. Felisi cree que lo mejor es que vuelva al centro, pero que si ellos quieren se pueden quedar. La chica dice que sus padres le ha dicho que ya es mayor de edad y ya puede hacer lo que quiera. **Dicen que quieren tener familia, durante la semana santa no han usado anticonceptivos de ningún tipo. ········· Conseguimos que razonen que son muy jóvenes y no tienen medios para criar a un hijo. Acordamos que comprarán un test de embarazo y se hará la prueba para descartar. En cuanto al hecho de quedarse a vivir con su madre (ella no se opone pero no parece convencida) se puede valorar, aunque en principio no pensamos que sea la mejor opción. ······························································································································································································· Correo de Toni-Futuex: "Adjunto la info, relativa a los ultimos dias, de la tutelada Felisa Felipe, y su hijo. Los acontecimientos con el dinero de los ultimas dias, y la negativa por parte de Aitor, de regresar al centro donde vive, asunto del que creo estais al tanto. Hasta donde sabemos ha vuelto a Navas y se niega a regresar. Dificil se plantea, con todo lo que ya tenia ella encima ahora la situacion contextual y social de la tutelada. Mañana si quieres vemos como podemos intervenir, si es que se pude hacer algo.." ··············· Adjunta nota del 22/03/22','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-04-21','Ana: Correo de Toni- Futuex: "...envio ahora la del 4 al 19 de Abril... Hoy además estaba alli la compañera, a ver que información nueva obtiene, de momento el hijo sigue alli y lo peor es que creemos que le está sacando el dinero a la madre y posiblemente para comprar cannabis.. en cuanto tenga mas info de la visita de hoy te la paso. Supongo que al respecto del regreso al centro no se podrá hacer gran cosa, ya que no fue alli con internamiento involuntario no? Aitor, me refiero."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2022-04-25','Ana: Llamo a Minerva, CR Cervantes (22237): le explico la situación, tal cual me informa Ana I. Moreno de la Gerencia Territorial. ····· Acordamos que llamará ella directamente a Ana Isabel para preguntarle que otras opciones de residencia tienen por la zona, que no sean Don Benito, Villanueva ni las poblaciones más cercanas a éstas localidades. Para poder ofertárselas a Mª Luisa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-04-25','Ana: Recibo llamada de Pilar Rguez. Rosado, sobrina de Mª Ángeles (645 90 95 26 //927 21 21 38). Explica que ella es la sobrina que más pendiente ha estado siempre de ella. Excepto durante una temporada que dejó de tener contacto por decisión de la propia Mª Ángeles, hasta que ésta ingresó en el hospital y estuvo con ella durante prácticamente todo el ingreso. A partir de ese momento retomaron la relación. A la residencia le lleva ropa y otros artículos de higiene tal y como le solicitan desde allí. *Normalmente le han ido abonando los tiques con el dinero de Mª Ángeles, pero hace tiempo que le pidieron el nº de cuenta para que se lo abonásemos mediante transferencia desde la CTAEX. Tiene pendiente uno de entre 30-40 € de ropa. *"No me importa hacer la gestión pero no me sobra el dinero". Pide que se siga contando con ella para lo que necesite, pero no puede asumir más tiempo esos gastos. *En su cumpleaños dice la visitó y le llevó una tarta y bombones, detalle que le apeteció y pudo tener. ································································································································································································ Llamo a Gema, directora de la residencia (670 381 292): Desde el centro no están retirando los 50€ para gastos de bolsillo. ······ Le indicó a Pilar, sobrina, la dirección de mail para que nos remita ella los tiques de los productos que le compre a su tía. ······ El tique de la ropa lo envío gema al ctutelar@ antes de navidades, cree recordar. ·········· Localizo 2 correos, uno con el tique y otro con el nº de cuenta. Se los reenvío Óscar, secc. ecca.','2');
