insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2022-04-25','Email de ap. 3. : -Se empadrona a su Pilar en San Javier y se envía copia del empadronamiento a la madre. La madre envía audios por whatsaap muy enfadada porque dice que le hemos quitado la paga del banco, que se queda sin nada e la niña para comprar le comida para los fines de semana y festivos, así que la niña se queda en San Javier, deja de ir a casa. Esperaremos por el fin de semana a ver que dice la madre. ------------------------------------------------------------ Cuando vaya a pasar el fin de semana llevará dinero .','2');
