insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2022-04-25','OSCAR: SUBIMOS LA ASIGNACIÓN A 108 €/MES A PARTIR SEMANA DEL 02/05/2022 Y MANTENEMOS ALGO DE CONTROL SOBRE EL SUPERMERCADO. OSCAR: SE LO COMUNICAMOS A REME','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='CRESPO'and apellido2='CRUZ'),'2022-04-20','Ana: Correo de Emilia Almodóvar, TS del CSS-Plas, en respuesta a mi consulta: "Hola Buenos días Ana. Los motivos del ingreso de la paciente Victoria Crespo Cruz ha sido por presentar episodios de vómito, diarrea, y ahora por la tarde vómitos oscuros en escopetasos , en los últimos días ha presentado cifras de hiperglucemia que se han tratado con insulina rápida. En principio no necesita acompañamiento Hospitalario, cuando sea necesario os lo informamos. Para más información sanitario, contactar con su médico."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2022-04-25','La cuenta por la que cobra J. Luis Calvo es ES25 2085 4518 0203 3085 7593 y en la que está sólo él de titular es ES80 2085 4621 1803 3080 3527, donde hay que cambiar la pensión. Por cierto, ya han devuelto los 1.500 €.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2022-04-25','Ana: Entrego a Julio, CTAEX, Oficio-respuesta al requerimiento de documentación del Serv. de Prestaciones Sociales (PNC), para que le dé REGISTRO DE SALIDA junto a la documentación detallada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-04-25','Ana: Llamada de Isabel Jiménez, madre de Saturnino (927 028 028) dice que hay que hacer algo, que a su hijo le han engañado, que entraron a su casa y le drogaron, que sólo hay que ver que la chica falleció a las 2 semanas, qué su hijo nunca ha hecho nada malo... Que ella con 90 años no puede ver que su hijo siga ahí dentro... Pide el número de la abogada para hablar con ella, pues cuando a fue a ver a Saturnino éste lo había perdido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2022-04-25','-Amalia . regitro cambio PIA para pasar a residencia de mayoers.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2022-04-25','La cuenta por la que cobra J. Luis Calvo es ES25 2085 4518 0203 3085 7593 y en la que está sólo él de titular es ES80 2085 4621 1803 3080 3527, donde hay que cambiar la pensión. Por cierto, ya han devuelto los 1.500 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-04-25','Ana: correo de Toni-Futuex: ".. traslado, taxi y demás, que lo haremos como estaba previsto inicialmente como dices, (si no se pone una vez que llegue a la estacion y dice que se va con la novia y con el padre) se ha valorado el hecho de que se acorte el periodo de convivencia en un entorno no seguro, con su pareja actual? tal y como te decía el viernes en un mail, desde el equipo de apoyo social comunitario, entendemos que conociendo las conductas y el tratamiento que Adrián requiere, en el contexto de su hipersexualidad, por el que necesita y mantiene un control de endocrinología y psiquiatría, se consideramos no adecuado, que el tutelado resida tantos días, en un entorno totalmente desfavorable en muchos aspectos, con esta chica. El viaje está previsto del 25 de Abril al 7 de Mayo, no sabemos cual ha sido el motivo por el que desde el centro se han solicitado la semana de antes y la despues de la boda... y sobretodo que todo este tiempo este acompañado por esta pareja en ese entorno familiar, tan complejo, aunque lo de la chica, creo que ha sido algo de ultima hora, inesperado para todos." ······························································································································································································· Respondo con copia a Cristina, P.I. Vera y a Maite, CTAEX: "Buenas tardes Toni, Tras haberlo valorado con Maite, Jefa de Sección, consideramos que modificar la autorización de salida para reducir los días de estancia puede ser contraproducente, pues puede desencadenar una desestabilización o alteraciones de conducta en Adrián. Más aún cuando él ha cumplido, en las últimas semanas, con el acuerdo al que llegó con el Centro para poder acudir a su casa los días indicados. Por otra parte, no podemos impedir que la otra chica acuda a casa de los padres de Adrián, si tanto la familia de uno como el de la otra así lo han permitido y aceptado. Lo que si pedimos, si fuera posible, que en los días de estancia en el domicilio familiar, se le haga, al menos, un seguimiento telefónico, tanto por parte de Teresa, Educadora Futuex, como por parte de los profesionales de la Asociación Vera, por si se detectara alguna incidencia por la que fuera preciso tomar alguna otra decisión o comunicar al Juzgado. Pongo en copia a Cristina, Educadora Plena Inclusión Vera y a Maite, jefa de sección. Si cualquiera de vosotras lo consideráis, hablamos mañana." ·········· "Por cierto, con respecto a que la novia iba a acudir a la boda, nosotros tampoco sabíamos nada, nos enteramos el viernes a última hora al leer el correo previo de Cristina. El tuyo lo hemos visto ya estas mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2022-04-26','miguel, llega inicio de procedimiento sancionador del ejercicio 2018, comunico via email a la parte económica y a Amalia que no alegaremos, no podemos... y esperaremos para pagar a que sea firme la resolución','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-04-26','miguel, remito al juzgado nº4 de Badajoz solicitud de revisión de sentencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-04-22','miguel, llama por teléfono su sobrina Mª Pilar Rodriguez Rosado (esposo Angel Pinero Sanchez, tlnfo 645909526 y 927-212138) para quejarse de que la directora del centro les ha reunido y les insiste en que Ana Mª Rosco Avalos no cambie de centro, además de llamarles para las necesidades del día a día de Ana Mª (ropa etc). La explico que de nada de lo que comenta tiene constancia la Comisión Tutelar de Adultos y se hace preciso que le dejen claro a la directora que cualquier petición debe dirigirla a la Comisión','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-04-26','Ana: Llamo a Felisi (624 856 746): Dado que es temprano, su hijo y Mirella, pareja, están aún acostados, con lo que puede hablar libremente. Expresa que no quiso dejar a su hijo en la calle. "Me da pena", pero que está más tranquila si está en el centro, pues allí no consume porros y está más controlado. *Cuenta también que Mirella y Aitor riñen mucho y ninguno de los dos colabora en la casa, no hacen ni la cama. *Ahora tiene la nevera vacía y cuanto se quedó sola podía incluso ahorrar. **Reconoce que le está dando dinero a Aitor para tabaco y cannabis, qué él le pide y si le dice que no, se pone "borde". Ayer le estuvo dando voces. ······· Felisi dice que ayer tuvo que ir al médico con mucho dolor de brazo. Le dijeron que es por el estado de nervios en que se encuentra. ············ *Mirella y Aitor no han ido a la farmacia a comprar el test de embarazos. ···· Ella ha preguntado en el centro de salud y la enfermera le ha dicho que se lo tiene que hacer en su centro de salud en Badajoz. ············ *Una de las tardes-noche Aitor se ha ido con un amigo a Cáceres y ha dejado a Mirella en casa con su madre. ········· Virginia, Ed. Futuex, acudió a visitarles el martes de la semana pasada. ···· Hoy cree que van a ir del programa de familia. ··································································································································································································· Llamo a Raquel - Equipo de Familia (609 382 439) varias veces a lo largo de la mañana, en todas las ocasiones salta el buzón de voz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-04-26','Ana: Envío correo a Maite y Alberto, Jefes CTAEX: "Buenos días a los dos, Este correo de Toni lo tenía pendiente. La semana pasada hablé con Ángel Félix, quien pide se le suba la asignación y se le facilite dinero para colaborar con los gastos del lugar donde reside, según afirma dicen que están en casa de un amigo, pero según le ha comentado a la Educadora, les van a desahuciar, están arreglando una casa en Malpartida de Plasencia, en teoría, propiedad de su amigo también. *Por otra parte dice que está en la calle… *La educadora no ha conseguido que colabore en la elaboración de presupuesto aproximado. Viendo el resultado de la visita, que no es posible intervenir a otros niveles, pues él no lo permite, y que se trata de una curatela para Administrar sus bienes, considero que hay que subir la asignación todo lo posible ahorrándole las extras y dejarle claro que ya no podrá solicitar extras para ninguna otra cuestión. **Al teléfono que ha facilitado (603440408), supuestamente de su amigo, he intentado llamar varias veces y no da ni llamada. Lo hablamos si lo estimáis oportuno."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-04-21','Ana: Llamada de Ángel Félix (643 622 174): Dice que está sin comida y que está acudiendo al comedor social. Que sólo le dan una comida (1º, 2º y fruta). A primeros de mes un lote de alimentos, pero de cosas "banales". *Pide que se le suba la asignación a 70-80 €/semana. *Y que para colabora con su amigo, se le abonen a éste las facturas del agua.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-03-31','miguel, recibo email de la trabajadora social de alcuescar; Trabajadora Social Alcuéscar >trabajadora_social_alcuescar@imserso.es> (tras nuestra conversación telefónica donde le indico el baremo % de cantidades entre las que habrá de venderse la parte de la tutelada: "Estimado letrado, está conmigo la residente Carmen Gómez Muñoz, le he explicado tal y como hemos hablado por teléfono que sin liquidación de gananciales y según el Código Civil le puede corresponder entre un 10 y un 30% del usufructo. Según el cálculo sería la cantidad de 41.610 euros. La misma se muestra conforme con la cantidad. Pongo en copia a su abogado de oficio Aquilino a los efectos oportunos. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-04-26','miguel, llega demanda solicitando se despache ejecución contra la tutelada por un procedimiento monitorio que se tramitó ante el juzgado de 1º instancia e instrucción nº7 de Cáceres (PROC EJECUCION DE TITULOS JUDICIALES 120/2018) por importe de principal de 809,20€ y de 242€ de intereses y costas de ejecución','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2022-04-26','miguel, llega demanda solicitando se despache ejecución contra la tutelada por un procedimiento monitorio que se tramitó ante el juzgado de 1º instancia e instrucción nº7 de Cáceres (PROC EJECUCION DE TITULOS JUDICIALES 120/2018) por importe de principal de 809,20€ y de 242€ de intereses y costas de ejecución','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2022-04-26','20/04/2022 336,00 € copago abril y taxi El copago de los días de abril será 125.31 (entra el 19). Hay que pagar 30 euros taxi (se ha pasado factura) Se le entrega a Pilar 10 euros para dinero de bolsillo del mes de abril (se le dará un recibí para que firme) (sobran 180, hay que comprar ropa interior y algo mas que necesita, pediremos factura). 26/04/2022 417,70 € copago mayo y gastos 75% de la pensión será 313.27 40 euros de dinero de bolsillo Si os parece bien, por ahora haríamos esta gestión. SALUDOS. Catarina Mª Ferreira Barbedo Servicio de Apoyo a Familias Aprosuba 3 Plena Inclusión Badajoz Tfno.: 610292594 www.aprosuba3.org','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-04-26','Ana: Envío correo a Pilar Cerrillo (calidad@grupociudadjardin.com): "En relación a Martín Domínguez Palencia, además de preguntarte qué tal sigue y cómo se está adaptando al centro, quería pedirte que cuando os sea posible solicitéis la documentación necesaria para solicitar la valoración de dependencia, pues en su día se valoró y dio sin grado, pero en la actualidad su situación ha variado mucho y sería conveniente que le volvieran a valorar. ¿Podríais pues solicitar Informe de Salud (Modelo oficial) + Índice de Barthel al Médico de Atención Primaria y a la Trabajadora Social, Solicitud e Informe Social, si lo estimara oportuno? Dado que a día de hoy sigue siendo curatela para el ámbito patrimonial, principalmente, desde la CTAEX no podemos cumplimentar y firmar la solicitud. Ya me dices cuando puedas. Gracias." ······················· Respuesta de Pilar: "De acuerdo Ana, yo me encargo de pedírselo y de entregarlo en registro, lo puede firmar el verdad? Luego te mando copia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MARTINEZ'),'2022-04-26','Ana: Remito CI para Tratamiento Quirúrgico Dupuytren, debidamente firmada a Mª Ángeles, TS del Hptal. de Coria (77227 // mangeles.ramosg@salud-juntaex.es) ·············· Envío nuevo correo a Mª Ángeles, TS, con copia a Maite, Jefa secc. CTAEX, y a Toni-Futuex: "Hola de nuevo, Mª Ángeles, Decirte que desde el Gabinete Técnico de la CTAEX, nos retractamos en los Consentimientos Médicos enviados, disculpa, pero las prisas no son buenas consejeras. Por error he mirado el expediente y la sentencias de incapacitación de su hermano Manuel, para quién sí nombran a la CTAEX curador para las cuestiones relativas a tratamientos médicos a que deba someterse. En cambio no es así para Juan María, de quién adjunto la sentencia. En la misma se nombra a la CTAEX Curadora para la ADMINISTRACIÓN DE SUS BIENES. Por tanto, todos los Consentimientos Informados deben ser firmados por el propio paciente. Disculpa las molestias. Pongo en copia a Maite, Jefa de Secc. y a Toni, Coordinadora de Virginia, Educadora del Programa de Apoyo Comunitario gestionado por Futuex. Un saludo." ······························································································································································································ Nuevo correo a Toni-Futuex: "Con respecto al SAD, por lo que veo no te di repuesta en su día… ni uno ni otro hermano están “incapacitado” (lo pongo entre comillas dada la nueva ley), en el ámbito personal. El cargo que ostenta la CTAEX en relación a Juan María es sólo Curatela para la Administración de Bienes. Y en el caso de Manuel, aunque sí que dice “para regir su persona y sus bienes”, especifica “…para las cuestiones relativas a tratamientos médicos a que deba someterse”. Por lo tanto, la solicitud del SAD deber firmarla ellos. *A mis compis de la sección económica les paso la Autorización Bancaria. *Desde aquí se puede remitir directamente al Ayto. para agilizar. El informe médico que adjuntas en el otro correo, supongo que se lo llevará la compañera al MAP para que lo cumplimente, no? Ante cualquier otra cuestión, seguimos en contacto." ··························································································································································································· Envío correo a Óscar, Secc. Ecca.: "Buenas tardes ya, compañero, Te remito Autorización Bancaria para abonar el Servicio de Ayuda a Domicilio de Titularidad Municipal, relativa a los Hermanos Manuel y Juan Mª Rodriguez Martinez. Ambos conviven juntos y perciben distintas prestaciones para que en cómputo puedan cobrar mayor cuantía. Habrá que mirar en cuál de las dos cuentas merece más la pena la domiciliación bancaria. Me dicen que el coste máximo es de 1,50€/hora, pero no sé exactamente las horas semanales que les concederán. Mañana hablaré con la TS, le han dejado nota para que me devuelva la llamada. Y ya te confirmo o le pido que te envío un correo confirmando las horas de atención y el precio final del servicio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2022-04-26','-AMALIA : REGISTRADA SOLICITUD DE PNC DE INVALIDEZ , CON LA CUENTA NUEVA Y EL NUEVO EMPADRONAMIENTO. NOS ENVIARÁN LA OPCIÓN AL ESTAR PERCIBIENDO PFHC Y TENDREMOS QUE ELEGIR QUEDARNOS CON LA PNC.','2');
