insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-04-28','miguel, firmo en notaria de Don Benito de D.Gerardo Holgado Cabrera protocolo 892 venta del inmueble del Valle de la Serena. En cuanto llegue la transferencia de la venta enviaré al juzgado tal como requirieron en la autorización judicial de venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2022-04-26','miguel, dejo firmada la ratificación de la aceptación de herencia. En cuanto tenga la documentación completa, remitirla al abogado para que solicite la aprobación judcial de la herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2022-04-28','miguel, firmo junto con Juan Carlos la renuncia a la herencia de su madre Rosa Galan Merino ante el notario de Don Benito D. Gerardo Holgado Cabrera','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-04-20','Ana: Correo de Blanca, Directora CRR-Plas (direccion.crrplasencia@grupo5.net): "He acudido a la Policía Judicial, he interpuesto denuncia para la protección de Isabel y como directora del recurso, para que lo tengáis en cuenta por si os avisan. Como os he comentado se encuentra en el Unidad de psiquiatría, no he conseguido hablar con su psiquiatra de referencia. Por la situación del caso, vamos a plantear una reunión con las personas implicadas para valorar la situación de Isabel, su vuelta o no al recurso etc. Os vamos informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-04-29','TERESA el teléfono de Aitor: 641362231','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-04-29','TERESA INFORMA QUE TUTELADO SE ENCUENTRA EN CASA MADRE Y SE NIEGA A VOLVER AL CENTRO. ACTUACIÓN: • CANCELAR INMEDIATAMENTE TRANSFERENCIA A CENTRO X GASTOS MANUTENCIÓN TUTELADO DE 100 €/MES. • MANTENER EL PAGO AL CENTRO (ADISER HORIZONTE) YA QUE ÁREA SOCIAL QUIERE MANTENER EL DERECHO A OCUPAR SU PLAZA - ADEMÁS SE ESTÁ GESTIONANDO UN INTERNAMIENTO INVOLUNTARIO ANA: VA A GESTIONAR DESTINAR ESOS 100 € A ABRIR UNA CUENTA CREDITO EN UN SUPERMERCADO DE LOCALIDAD DONDE RESIDE SU MADRE FELISA (TAMBIEN TUTELADA), QUE SE ABONARÁ X TRANSFERENCIA. ANA: CUANDO ESTE GESTIONADO SUPERMERCADO: TENGAMOS CCC PARA ABONO Y SEPAN QUE DEBEN REMITIRNOS LAS FACTURAS MENSUALMENTE PARA PAGO (SIN SUPERAR LOS 100 €/MES) SE LAS PASAS A LOURDES DIRECTAMENTE PARA PAGO. LOURDES: CANCELACIÓN INMEDIATA TRANSFERENCIA PERMANENTE A CENTRO X GASTOS (LA DE 100 €/MES). LOURDES: CUANDO ANA TE DE LOS DATOS YA ORGANIZAS LOS PAGOS MENSUALES AL SUPERMERCADO, EN TANTO EN CUANTO SE SOLUCIONA ESTA CUESTIÓN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-04-29','miguel, llega email de Tere: Me ha llamado una vecina de anatasio porque se le esta filtrando agua a través del muro medianero. La vecina ha avisado al seguro de su vivienda y le dicen que el problema viene de la vivienda de Anastasio La dirección de la vivienda es C/ Francisco Rubio 16 de Barcarrota Oscar: Mirame si tiene seguro de hogar Miguel: Dime como procedemos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-04-29','Ana: Llamo a María, Programa de Familia (609 38 24 39): la situación sigue igual, pero aclararon que el enfado de Aitor de hace 2 días, fue porque Felisi le dijo que era "subnormal", que por parte de su padre no había nadie que estuviera bien y que a su abuelo le llamaban "el loco", por ello Aitor se enfadó mucho y le dijo que quien estaba loca era ella... ···· La actitud de Mirella tampoco les gusta, "se enciende como una cerilla, a la mínima se pone a dar voces". *Dice que su padre le va a mandar 80€ todos los meses. ········ La pareja de su padre está embarazada. ······· Y la propia Mirella, aunque no se haya hecho el test, afirma que también lo está. ········· *Por otra parte, temen que cuando finalmente Aitor vuelva al centro, Jesús vuelva a vivir con Felisi. ·············· *A María le parece bien llegar a un acuerdo con un supermercado para dejar un "depósito" mensual, para que Felisi pueda acudir a adquirir alimentos. *Pero quién suele acompañar a Felisi a comprar es Virginia-Ed. Futuex, mejor preguntarle a ella los datos del comercio. ····· *Se acuerda con Alberto, Jefe sección económica, que se hará con la asignación mensual de Aitor la transferencia a la tienda, mientras esté en casa, en lugar de hacérsela al centro. ················· Llamo a Toni-Futuex: Acordamos que Virginia intentará contactar con la tienda para ver si es posible "dejar allí un depósito" para que Felisi compre alimentos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2022-04-28','Ana: Recibimos Informe de Seguimiento del CRR para rendición anual: "Habiéndose producido un cambio residencial por razones ajenas a la persona usuaria, sino a razones estructurales, a centro residencial de rehabilitación en Cáceres desde noviembre de 2021 que afecta de manera significativa a su estado psicopatológico. En seguimiento en el CEDEX por consumo de alcohol. Se ha comenzado a realizar analítica semanal aleatoria para continuar con su proceso en el dispositivo. En seguimiento en los servicios de cardiología, neumología y traumatología en estos momentos." ····· "sigue teniendo una gran dificultad en el manejo del dinero, más concretamente en la planificación y gestión del gasto a corto y medio plazo." ············ "se ha implementado con él un sistema de ahorro, al que semanalmente decide destinar un pequeño porcentaje del ingreso y así poder hacer frente a imprevistos económicos personales" este sistema se vio interrumpido debido a las dificultades con la entidad bancaria para retirar su asignación. "Juan José presenta una gran dificultad en el manejo del dinero, especialmente en la planificación e inhibición del gasto y en el establecimiento de un presupuesto adecuado..." "J.J manifiesta de manera reiterada la posibilidad de acudir a retirar el dinero quincenalmente, sin embargo en estos momentos desde el CRR consideramos necesario poder continuar trabajando la realización de un presupuesto semanal y el ajuste al mismo, sin que esto conlleve un aumento de la ansiedad y de las conductas desadaptativa" ······ "pasa gran parte de su tiempo fuera del centro. Sin embargo, sus activades no se encaminan a un ocio programado y de disfrute. Sino a deambular por la ciudad en solitario. A pesar de tener la oportunidad de realizar actividades con sus compañeros del centro..." "Acude al Programa de Apoyo Sostenido del CRPS en Cáceres, sin embargo, su asistencia es irregular, no siendo constante en los compromisos adquiridos. Las relaciones sociales en el mismo prácticamente son inexistentes." "A pesar, de no mostrar dificultades instrumentales, son numerosas las ocasiones en las que descuida su autocuidado si se le retiran los apoyos de recordatorio y supervisión. Necesita apoyo para la reducción del consumo de bebidas energéticas, mantenimiento de una dieta adecuada y la creación de una rutina básica de cuidados."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-04-29','Ana: Envío correo a Alberto, Jefe secc. ecca., con copia a Maite: "Buenos días Alberto, Tal y como acordamos ayer en reunión mantenida, te reenvío correo de Rosa, Directora de la Residencia de Fuente de Cantos con los datos de las personas que pueden ir a retirar la asignación de Juan Carlos Ruiz García al banco. Te recuerdo que habíamos acordado la cantidad de 150 €/mes que le administrarán en el propio centro. Ha llegado también el presupuesto para comprarle un teléfono móvil, también lo hablamos el otro día Maite, tú y yo, y estamos todos de acuerdo. *Oscar va a hacer la transferencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2022-04-29','miguel, solicito por fax resolución definitiva al juzgado de lo penal 1 de Mérida para saber el tiempo que ha de estar en la cárcel (conforme petición de Amalia por email)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-04-28','Ana: Maite y yo llamamos a María Antonia, Psiquiatra de la UHB (81284): Nos confirma que el martes día 3 de mayo Juan Carlos retornará al Centro Fco. Asuar de Fuente de Cantos. Hoy está muy tranquilo y más espabilado. Ayer se alteró un poquito. ········ Aunque Mª Antonia va a indicar en el informe que considera que no es el recurso más adecuado para el perfil de Juan Carlos, finalmente le dará el alta, pues está estable y se intentará de nuevo que se adapte al recurso. ·················· Llamamos a Juan Carlos, al Control de Salud Mental (924 38 10 42 / 81616) Juan Carlos está tranquilo, se le entiende mejor, más espabilado y animado. Está convencido de querer volver al centro. Dice "me voy a portar bien". Pregunta por su TV, sus cosas y su dinero. *Le decimos que se irá el próximo martes, que faltan 5 días y que pida que se lo enseñen en un calendario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-04-29','miguel: recibo email de Oscar: Dos cuestiones: - En cuanto al seguro de hogar, según la ficha tenía un seguro con Nortehispania, pero no aparece ningún pago en su cuenta actual de Ibercaja ni en la antigua de Banco Santander. Al parecer no se pagó porque no tenía ninguna propiedad según el Catastro. - Teresa: en marzo le han cobrado del centro los 800€ mensuales y otro recibo de 960€. En abril, además de los 800€, le han cobrado 1.600€ en otro cargo, para que lo consultes con ellos. Adjunto los cargos extra.**************************************contesto a Tere y Oscar: haciendo memoria creo que es el expediente en que se dejó de pagar el seguro de hogar porque ni en catastro ni en registro de la propiedad aparece a nombre del tutelado nada y por tanto no tiene nada que ver con esa vivienda, salvo que alguien demuestre lo contrario. Por tanto Teresa, si el vecino quiere reclamar que se le arreglen los daños tendrá que demostrarnos que esa vivienda es del tutelado. Adjunto certificado de catastro y nota simple del registro de la propiedad negativas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-04-20','Ana: Soraya Masa nos reenvía correo de Rosa, Directora de Fuente de Cantos, con Informe de Incidencia grave acaecida en el día de ayer. Juan Carlos se alteró mucho, golpeó con los puños y cabeza la pared, haciéndose sangre en los nudillos. Rompió el cristal de una ventana y amenazó con cortarse las venas y agredir. *Llamaron al 112, lo trasladaron en ambulancia al Hptal de Llerena y de ahí lo derivaron al de Mérida. Está ingresado en la UHB. ······························ Llamamos a Fuente de Cantos y mantenemos conversación a 3, Rosa, Maite y yo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-04-22','Ana: Visitamos a Juan Carlos en la UHB. ····· Está tranquilo, pero muy adormecido. ···· Dice que quiere volver al centro nuevo, a Plasencia no. Y que no lo va a hacer más... ························· Hablamos con Mª Antonia, Psiquiatra, no está convencida de que Juan Carlos regrese al C. Discapacidad, considera que su perfil no es adecuado para este tipo de centros. Nunca se sabe qué puede pasar por su cabeza y cómo va a reaccionar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2022-04-29','miguel, recibo email de Amalia: Buenas , por si no te lo ha reenviado Mayte , te adjunto informe de incidencias del caso de Juana para que se comunique al Juzgado. Indicame por favor , la fecha de registro del documento ó anótalo en la intranet. ****Siendo el informe de 27-4-22*******','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='RODRIGUEZ'and apellido2='MARTIN'),'2022-04-29','Ana: Llamo al Ayto. de Ceclavín (927 39 30 02): Marta, TS, no está allí hoy. ············· Llamo a la Mancomunidad de la Rivera de Fresnedosa, Despacho de las TS (927 30 33 66): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MARTINEZ'),'2022-04-29','Ana: Llamo al Ayto. de Ceclavín (927 39 30 02): Marta, TS, no está allí hoy. ············· Llamo a la Mancomunidad de la Rivera de Fresnedosa, Despacho de las TS (927 30 33 66): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-04-29','Ana: correo de Blanca, Directora CRR-Plas: "Buenos días Ana, te informo que Ceferino Mariscal Crespo ha dado positivo en covid, se encuentra bien de momento con pocos síntomas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2022-04-29','TERESA La hermana de Antonio Jesús Morales Esquivel quiere pasar el puente de mayo con él, desde el sábado hasta el martes a Badajoz. Vendría a por él el sábado por la tarde, después de comer y regresaría al centro el martes a mediodía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-05-03','Ana: Envío correo a Alberto Arias, TO EVD (alberto.arias@salud-juntaex.es): "Buenos días Alberto, ¿qué tal estás? Espero que hayas podido disfrutar de estos días. Me comunican desde el SSASB de Malpartida de Cáceres, que ha quedado una plaza pública libre en la Residencia de Malpartida. No sé si hay lista de espera en la que, MARÍA DE LOS ÁNGELES ROSADO ALBARRÁN, tenga gente delante, pero si no es así, como tiene grado III, entiendo que tiene una oportunidad estupenda para acceder a esa plaza. Pues aunque desde el Gabinete Técnico de la CTAEX, ya se ha solicitado al Juzgado la autorización de venta de su vivienda, el procedimiento puede tardar y tampoco tenemos seguridad de la respuesta que vayan a dar. Ya me dices cuando puedas. Gracias y buena mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2022-05-03','TERESA Eugenio es positivo de covid. Esta en aislamiento con síntomas leves.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-05-03','Buenos días , perfecto , me alegro que esté más animada y con ganas de trabajar . Quedamos pendiente de los datos de la clínica , un tf. de contacto nos servirá para aceptar el presupuesto y que inicie tratamiento. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-05-03','TERESA EL PASADO JUEVES VOLVIO PABLO AL DOMICLIO ALLI LE ESTABA ESPERANDO UNA DELEGADA TUTELAR PARA RETIIRAR 100 EUROS Y HACER LA COMPRA NOTA FUTUEX. Se realizó una compra de alimentación y cervezas 0.0 para provisión de unos 10 días, pero al ser la primera vez, tenemos que observar cómo se gestiona y desenvuelve Pablo. El dia 3 se le ha pedido cita con su medico de primaria, para que acuda a que le puedan poner la medicacón en receta electronica, pq desde el socio le dieron para algunos dias, pero no lo tienen por el momento en receta., una vez, pasen estos diez dias, de provisiones digamos, volveremos para alla, a ver como se puede volver a plantear la distribucion de apoyos en el entorno.,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-05-03','Ana: Reenvío a Rosa Bravo, CSS Plas (rosamaria.bravop@salud-juntaex.es) correo de Miguel, Asesor Jurídico CTAEX, explicando: "Buenos días Rosa, En relación a JOSÉ LUIS MURILLO HORRILLO, ¿podríais hacer desde el centro las gestiones oportunas para empadronarlo ahí? Como ves me lo solicita mi compañero Miguel, pues aún consta empadronado en la vivienda que han vendido. Supongo que la solicitud tendrá que firmarla el Presidente de la CTAEX, así pues, me la facilitas cuando la tengáis y os la devolveré firmada por él. Ante cualquier cuestión, hablamos. Gracias y buen día!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='ALMANSA'and apellido2='REDONDO'),'2022-05-03','miguel, tras la llamada de la directora del CR Fuente Atenor de Azuaga (Lali 924-000738) informando de incidente del tutelado que quiere irse pongo email a Tere y Maite: Buenos días, con carácter urgente Tere llama a Cr Fuente de Cantos, ha llmado la directora Lali muy nerviosa porque no logra localizaros por teléfono a ninguna de vosotras. Teiene a un residente Angel Almansa Redondo que quiere irse y está violento, ha llamado a la policía y al juzgado de Llerena, donde le dicen que cualquier renuncia al centro y a irse tiene que firmarla la Comisión. Le he dicho que ponga un email a ctutelar y que yo os avisaría para la llaméis urgente. Me dice que ella sepa no toma medicación y que el perfil de esta persona no es para ese centro. El quiere irse a Villanueva de la Serena con una supuesta hermana (Lali ha llamado a Villanueva y allí no hay ninguna hermana de este hombre) Por favor llamadla lo antes posible ****************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2022-05-03','miguel, pongo email a Alberto, Oscar, Ctutelar con lo que solicita la abogada, mariaflorianocampon@gmail.com >mariaflorianocampon@gmail.com> tlfno 927580392: En relación al asunto de referencia, revisando la documentación que según nuestra conversación telefónica me remitió, necesitaría los movimientos bancarios completos, pues en la documentación que me adjunta solo aparecen unos movimientos y solo veo la extracción de los 4.797,07 euros el pasado 19 de julio de 2021, pero no tengo la disposición de los 48.675 euros del 7 octubre de 2021. Si no los tienen en el expediente, hay que solicitarlo a la entidad bancaria. Igualmente habría que solicitar de la entidad el contrato de apertura de la cuenta bancaria e igualmente solicitar si los ingresos que entran son únicamente de Doña Florencia o su hermano en este caso también realiza ingresos de forma regular, porque por lo que puedo ver en los movimientos que me ha remitido como documento nº 2, hay ingresos de dos pensiones, una de la Sra. Florencia y la otra no sé si podrá ser de su hermano. Quedo a la espera.','2');
