insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-05-03','Buenos días Amalia. No la ingresaron. El sábado volvió a tener otros 2 gestos autolíticos , llamamos al 112 y se la llevaron al HUB pero tampoco la ingresaron. Al ratito regresó al centro. El domingo y el lunes ha estado algo más tranquila . Hoy tiene cita en el ESM para ponerse el inyectable. Le he ofrecido mi acompañamiento para intentar que el psiquiatra la atienda pero se ha negado. Voy a intentar contactar telefónicamente con el ESM . No hemos podido trabajar la consecuencia de su conducta de agresión a un compañero por la desestabilización que presenta, y el padre del compañero afectado está muy preocupado con este tema. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-05-03','miguel, remitimos originales de certificado de defunción, últimas voluntades y fotocopia del libro de familia y nombramiento judicial del cargo a la Ctaex a la notaria de Brihuega para que nos remitan los testamentos de los padres a efectos de poder preparar las herencias','2');
