insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-03-01','-Amalia: Sra. de 85 años , que lleva 26 institucionalizada en la R. Mayores Ciudad Jardín Cánovas de Cáceres. Incapacitación total. Deterioro cognitivo.Trastorno mental depresivo. Soltera. Sin red familiar , un hermano en Madrid que hace años no la visita por enfermedad. Tiene una sobrina y prima ( tf. en el informe social ) Muy religiosa , recibe visitas de congregaciones de monjas. G.III dependencia , pendiente de recibir el PIA con atención residencial . Percibe P. Jubilación por 689,70€ + 2 pagas extras. El 85% de la pensión + 50% de la extra, lo abona a la residencial. Tiene nicho propio pero no tiene seguro decesos. Tiene en cuenta 5773,89€ .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-05-03','Buenos días Amalia. No la ingresaron. El sábado volvió a tener otros 2 gestos autolíticos , llamamos al 112 y se la llevaron al HUB pero tampoco la ingresaron. Al ratito regresó al centro. El domingo y el lunes ha estado algo más tranquila . Hoy tiene cita en el ESM para ponerse el inyectable. Le he ofrecido mi acompañamiento para intentar que el psiquiatra la atienda pero se ha negado. Voy a intentar contactar telefónicamente con el ESM . No hemos podido trabajar la consecuencia de su conducta de agresión a un compañero por la desestabilización que presenta, y el padre del compañero afectado está muy preocupado con este tema. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-05-03','Plan de intervención inicial : Señora ingresada en la Residencia de mayores de Ciudad Jardín de Cánovas desde hace 26 años . tf. de la residencia 927233221 Desde la sección eco habría que realizar varias gestiones -Tiene una cuenta bancaria con 5773€ de ahorros , donde se ingresa su pensión. Incluir como titular a J. Vicente . -Habría que hacerle un seguro de decesos , aunque creo que ya por la edad no nos van a dejar hacerlo . Tiene 85 años. Si bien , tiene un nicho en propiedad. -Tiene una pensión de jubilación de 689,70€ más 2 pagas . Abona el 85% de la pensión + 50€ de las extras como pago de la plaza residencial . Pendiente de recibir listado con los gastos personales de la residencia . Estoy pendiente de cambiar su PIA y pedir plaza residencial . La Tecnico PIA es Ana Isabel Teomiro . Le he escrito para que me envie el PIA . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-05-03','Ana: Paso a Julio, Oficio Solicitud de Cdo. de PNC, para que le dé REGISTRO de salida. ·················································· Solicito al ESM por fax, Informe de las últimas consultas programadas de Psiquiatría desde noviembre de 2021 hasta la actualidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-05-03','miguel, tras indicarnos el jzdo nº4 Badajoz que debíamos enviar la solicitud a el jzdo Decano de Badajoz, envíamos (Inés) hoy por sirex y carta certificada e email de nuevo dicha solicitud','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2022-05-03','Ana: Correo de Mamen, TS Centro de personas sin hogar de Caritas (mcsanchez.cdcoriacaceres@caritas.es): "Buenos días Ana! Te escribo este correo para informarte que Francisco Cacho Garrido ha abandonado nuestro centro con fecha de hoy, llevaba unos días inquieto, la gente le molestaba, al verdad que para lo que es él, ha aguantado mucho y se han comportado muy correctamente, pero se le estaba haciendo ya muy larga la espera al piso, y se ha marchado. Es una pena que los recursos tarde tanto, al final se pierde a las personas y ellas son las que pagan las consecuencia. Bueno si regresara te volvería a informar. gracias y un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2022-05-03','Ana: Correo de Cristina, Asoc. Vera (educadorasocial@asociacionvera.com): "Buenos días, Adjunto envío Resolución del Grado de Dependencia de su tutelado D. Joaquín Herrero Jiménez, dónde no se le reconoce grado. Un saludo." ········· Guardo la Resolución en su expdte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-05-04','miguel, me llama Francisco el subdirector de la Caixa, móvil 686335313 para pedirnos el primer impuesto de sucesiones pagado. Aunque le reenvío los dos compruebo que la liquidación que tenemos del primero tiene el sello del banco pero no la pegatina de la junta, con lo que envío email a Inmaculada de Cid y Villafaina para que me lo remita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-05-04','Ana: Llamo a Noelia, Secc. Mayores (924 00 84 90/68490), Mª Ángeles, aún teniendo grado III de dependencia, debido a sus altos ingresos, tiene a más de 20 personas por delante en la lista de espera para acceder a plaza pública en la residencia de Malpartida de Cáceres. ······················ Se lo comunico a Estrella, TS del SSASB (ssb@malpartidadecaceres.es).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-05-04','Ana: Solicito por fax informe de consulta al ESM-CC. ········································ Envío correo a Cristina y Pedro, CRR CC, en relación al informe que remitieron sobre el estado a incidencias de Juan Mario: "Buenos días Cristina y Pedro, Ayer estuve hablando del caso con Mariluz Madrigal y las compañeras de la sección. Lo cierto es que es un caso complejo. Yo ya he solicitado el Informe de la última consulta en Psiquiatría el pasado mes de abril. En cuanto me lo remitan, comunicaremos la Situación al Juzgado adjuntando vuestro informe y el del ESM."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='GARCEO'and apellido2='ESTEVEZ'),'2022-05-04','EXITUS Se recibe Certificado de Defunción del Rgtro. Civil en el que se marca la f/ del 23/03/22 como momento del óbito.*****Así mismo, Inés solicitará el archivo del procedimiento. Aún no se había aceptado el cargo, aunque sí se había solicitado nos informaran si la sentencia era firme para proceder a ello (St. 16/22, de 16 febrero. CR.). Al momento de este apunte, el Jzdo., no había contestado, aún, sobre la firmeza de la St.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-05-03','Ana: Hablo con Mariluz, Eva y Raquel, ESM. Desde el CRR han remitido informe se seguimiento y Registro de incidencias en relación al consumo e incumplimiento de normas durante los últimos 6 meses. Plantean la búsqueda de un recurso residencial alternativo, pues dadas las características del CRR, el estado de salud y las conductas de Juan Marío, no puede seguir residiendo en dicho centro. *Juan Mario consume tóxicos: alcohol, tabaco y bebidas energéticas a diario y de forma menos frecuente cannabis. Presenta Diabetes Mellitus tipo II, siendo insulinodependiente, y en la actualidad graves alteraciones psicopatológicas que le impiden un funcionamiento correcto. ··· Escasa conciencia tanto de su enfermedad orgánica como de la mental. ···· En el CEDEX no ha funcionado. ·········································· Consideramos la necesidad de solicitar ingreso en CSS, UME y/o Unidad de Alcoholismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ESTEVEZ'and apellido2='DE FELIPE'),'2022-05-04','TERESA acaba de solicitarme el traslado con la plaza T3 que ocupa en nuestro centro a otro centro más cerca de su localidad de origen. Solicita centros en Badajoz. Adjunto el modelo de solicitud firmado para que me confirméis si estáis de acuerdo al estar tutelado y tras esto ya lo enviaría al SEPAD. SE LO PASO A MIGUEL PARA QUE LO COMUNIQUE AL JUZGADO TAL Y COMO INDICA EL FALLO DE SU SENTENCIA DE INCAPCITACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-05-04','miguel, envío email a Tere con copia a Eva (hija de la vecina de la vivienda colindante): Buenos días Tere, he hablado con la hija de la vecina (Eva-móvil 629-464-556) que será el contacto para el arreglo de la vivienda. Necesitamos que coordines con ella la visita del perito que tenga que hacer el presupuesto porque ellos no bajarán a Barcarrota hasta junio y por otro lado no sabemos quién tiene la llave de la vivienda de la madre fallecida (madre soltera) del tutelado. Por tanto cuando tengas localizada la llave, ponte en contacto con Eva para coordinar con ella qué perito y a qué persona mandan ellos para ponerlos en contacto con quién mandemos nosotros y asi poder entrar en las dos viviendas y preparar presupuesto de arreglo. Mientras yo hablaré con el ayto de Barcarrota para hacerme con la documentación acreditativa de la madre e intentar poner a nombre de Anastasio Vaquerizo…tendremos seguramente que preparar la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CASILLAS'and apellido2='GARCIA'),'2022-05-04','Francisco Casillas Garcia 03-03-2022: Seguimiento Presencial Llevamos a cabo seguimiento presencial en la localidad de residencia de Francisco, Oliva de Mérida. Nos ponemos en contacto con la Policía Local (Juan Manuel) para que pueda avisar a Francisco de nuestra visita, ya que no tiene teléfono para poder localizarle. Nos entrevistamos con él en las dependencias del Ayuntamiento de la localidad, la trabajadora social y la terapeuta ocupacional del equipo de apoyo social comunitario. Su aspecto físico es bueno, aunque su vestimenta y aseo personal dejan ver la falta de aseo frecuente. Donde duerme no existe baño ni acceso a agua corriente. Indica que se lava en un pilar de la localidad. Hace unos meses vivía en la localidad un amigo que le permitía ducharse en su vivienda. Indica que no tiene nada de dinero, que lo retiró el pasado día 25 y le duró varios días porque tuvo que pagar a dos tiendas que le habían facilitado comida. El policía local nos dice que la información cree que no es cierta, que le dura el dinero pocos días porque principalmente lo gasta en alcohol, tabaco y drogas (solo nos confirma el consumo de cannabis). La comida que le facilitan desde Caritas la suele tirar, no tiene nada para cocinar y principalmente come lo que encuentra en los contenedores o en algún bar el día que retira la pensión. En relación a las consultas médicas no asiste hace años a psiquiatría, nombra al doctor Simón profesional que creemos que ya no ejerce al estar jubilado. Dice que todas las noches toma una pastilla de zyprexa (policía local cree que no) y cada tres meses se pone un inyectable, añade con mucha seguridad que le toca el próximo el 10 de marzo y que se lo pone en su centro de salud. Retira la PNC al completo el día que se la ingresan, la malgasta en pocos días y el resto del mes sobrevive mendigando. Rechaza que le ayuden a administrar el dinero. Su discurso es coherente, pero se escuda en mentiras para falsear la realidad. Le preguntamos sobre la posibilidad de un ingreso voluntario en un centro, pues duerme en un terreno de la localidad abandonado y al que tiene que acceder de forma ilegal ya que su dueño lo tiene alambrado y con candado, pero a través de un extremo roto se mete diariamente. Para dormir se refugia en una parte que es una obra en mal estado. No quiere trasladarse a ningún centro de los que estuvo anteriormente, indica que si estaría bien en un piso tutelado donde pueda entrar y salir, pero Juan Manuel (Policía Local) afirma que voluntariamente no se quedaría allí que en varias ocasiones ha sido derivado a algún recurso y cuando tiene dinero se va nuevamente a su localidad. 10-03-2022: seguimiento presencial: En esta ocasión, se aborda el ámbito sanitario corroborando que efectivamente cumple con el inyectable cada tres meses y retira tratamiento en farmacia. Se desconoce, eso sí, si cumple adecuadamente con el tratamiento farmacológico o no. Desde que volvió del CRR de Plasencia no ha tenido revisiones en psiquiatría, manteniendo desde entonces el cumplimiento del inyectable. Seguidamente, nos reunimos con la trabajadora social de los SSB de la localidad. En primer lugar, en presencia de Francisco, después, se aborda la situación entre el equipo de apoyo social comunitario y los SSB. La voluntariedad de ingreso en centro del tutelado existe, pero es cierto que su única demanda es un piso tutelado mientras le habilitan su vivienda habitual. Dicho discurso junto a lo sucedido con anterioridad en numerosas ocasiones tras los ingresos en centros efectuados, hace sospechar que el ingreso puede ser voluntario pero el tiempo en el mismo es puntual pudiendo retornarse a la localidad de Oliva de Mérida en unos días o en unos meses. Actualmente su demanda principal es el arreglo de su vivienda, asimilando su situación actual (vivir en la calle) como una situación transitoria de regreso a su domicilio. A pesar de abordarse este tema con el tutelado y hacerle entender que su vivienda está totalmente derrumbada y su situación actual es insostenible y de riesgo para su bienestar y salud, continua en las mismas. A todo ello, se le añade las actuaciones graves por parte de malas compañías que hacen peligrar su salud recibiendo trato denigrante, agresiones físicas, ofensas y abusos de todos los indoles. En ocasiones, siendo grabadas y subidas a las redes sociales. Estas, han sido denunciadas y llevadas a juicio. La trabajadora social comenta que el trámite de declarar en ruina la vivienda ya está en proceso. Ya ha sido visitada por el aparejador de la diputación de Badajoz. Una vez declarada en ruina, la idea es proceder a su derribo total y posterior construcción, por parte del ayuntamiento, para un solar habitable en el que pueda vivir Francisco. 31-03-2022: presencial - gestión cita ESM. Mediante la policía local conseguimos cuadrar la visita en Oliva de Mérida para ver a Francisco y visitar con él a su médica de familia. En la consulta, la médica nos facilita el último informe de salud mental que consta en JARA, es de Julio de 2021 cuando se encontraba en el CRR de Plasencia. Solicita nueva cita para revisión en el ESM de Mérida el cual le corresponde al encontrase actualmente en la localidad. La dirección de Fco que consta en el sistema es la de su casa en ruinas. Por ello, tenemos que cambiar dicha dirección por la de Comisión tutelar para que le llegue la cita de psiquiatría, su médica nos indica que dicha gestión se tiene que realizar en el Centro de Salud de Guareña. En el centro de salud de Guareña no nos pudieron cambiar la dirección a no ir con Francisco en persona ni nosotros acreditar la sentencia de incapacidad judicial, la solución que nos dieron fue añadir la dirección de la comisión tutelar como segunda dirección. Francisco comenta que retiró el dinero de su pensión hace unos días y que ya no tiene dinero en efectivo consigo. Tuvo que pagar dinero que debía en algunos bares y comercios de la localidad. La situación del tutelado no puede mantenerse durante mucho tiempo pues las condiciones en las que vive son inhumanas y suponen un riesgo para su salud. Es totalmente una situación de emergencia social. Su actitud ante el ingreso en centro es cada vez mas favorable. El problema que se plantea es si al cabo de cierto tiempo abonde el centro, como ha pasado en ocasiones anteriores. Ademas de que en este estado actual de calle, no se puede precisar en que tipo de centro podria tener acceso. Se adjuntan las fotografías del interior del lugar donde actualmente vive Fco. Conclusiones: Tras valorar la situación y contrastar información tanto con los servicios sociales de base como con la policía local de Oliva de Mérida, recursos referentes e implicados en abordar la situación de Francisco, se estima que, a pesar de su voluntariedad inicial para ingreso, no va a cumplir con el mismo y por ello, lo recomendable sería iniciar el procedimiento de ingreso involuntario mediante emergencia social para el tutelado Francisco Casillas García. Uno de los problemas que se observan para determinar el acceso a un recurso, es el tema del consumo de alcohol y cannabis, aunque comenta la trabajadora social que dicho consumo es puntual en el momento que retira el dinero de su pensión sin ser un consumo diario. Es más, menciona que se puede contrastar con otros centros en los cuales ha estado ingresado, que no ha sufrido síndrome de abstinencia ni problemas a causa del consumo. Lo cual no indica que el problema no existe. Seguimos en contacto!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-04-27','Maite: he recibido correo de la trabajadora social del centro de Arévalo solicitando salida de José María durante una semana a casa. Tras reunirnos Tere, Ana y yo hemos decidido que no se autoriza debido a los antecedentes con su familia. He hablado con Diana ( trabajadora social del centro) para explicarle el motivo de nuestra negativa ( sus relación con su familia ha sido complicada y no tienen habilidades para garantizar una atencióna adecuada de José María, pudiendo perjudicar su evolución positiva en el centro. Hemos sugerido visita de la familia durante un fin de semana.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-04-28','Maite: he recibido correo de la trabajadora social del centro de Arévalo solicitando salida de José María durante una semana a casa. Tras reunirnos Tere, Ana y yo hemos decidido que no se autoriza debido a los antecedentes con su familia. He hablado con Diana ( trabajadora social del centro) para explicarle el motivo de nuestra negativa ( sus relación con su familia ha sido complicada y no tienen habilidades para garantizar una atencióna adecuada de José María, pudiendo perjudicar su evolución positiva en el centro. Hemos sugerido visita de la familia durante un fin de semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-05-04','Maite: Tere y yo hemos hablado con José María, repecto al tema de la salida a casa. Le ha parecido buena idea que su familia lo visite durante unos días. Me pondré en contacto con Diana para ver el presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-05-04','miguel, hablo con Patricia (tía del curatelado 628-297-513 quien me pregunta cómo se a a cumplir la pena que le han impuesto de una parte de multa y otra de tratamiento ambulatorio por 4 años. Le explico que vamos a solicitar internamiento involuntario pero que lo que dure el procedimiento y cuál sea su resolución no lo sabemos. En cuanto a la forma del cumplimiento de dicha pena hablo con el juzgado y me dicen que hay que esperar a la Ejecutoria, a la que se le acaba de dar nº 171/22, pero que hasta dentro de unos días no llame para preguntar cómo se va a cumplir la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-05-04','miguel, a petición de Amalia preparo solicitud de internamiento involuntario basandome en el informe de la subcomisión que se hizo en diciembre de 2021, que incluye informe del equipo de salud mental, al que adjuntaré los incidentes que tuvo y comunicamos al juzgado.*********** Hablo con Patricia (tía del curatelado 628-297-513 quien me pregunta cómo se a a cumplir la pena que le han impuesto de una parte de multa y otra de tratamiento ambulatorio por 4 años. Le explico que vamos a solicitar internamiento involuntario pero que lo que dure el procedimiento y cuál sea su resolución no lo sabemos. En cuanto a la forma del cumplimiento de dicha pena hablo con el juzgado y me dicen que hay que esperar a la Ejecutoria, a la que se le acaba de dar nº 171/22, pero que hasta dentro de unos días no llame para preguntar cómo se va a cumplir la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2022-05-04','miguel, en llamada al centro por Ana y por mi, hablo con el tutelado quién me confirma que no ha vendido nada, pero me dice que cada uno de sus dos hijos tiene un local cada uno y que tiene una tía Pilar Bacas Leal (927-290470 y móvil 661-958501)y que me ponga en contacto con ella (porque él no tiene contacto con nadie de la familia). Dicha prima podrá ponerme en contacto con su hermano que es abogado.*********** Tras revisar de nuevo la documentación solicitaré las notas simples al registro de la propiedad para ver a nombre de quién están.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-05-04','Ana: En relación a la instancia de Saturnino Miguel, solicitando "hablar con alguien del SEPAD" remitida por Maite, TS del C. Penitenciario, (trabajosocialcpcaceres@dgip.mir.es), envío el siguiente correo con copia a Maite, Jefa Secc. CTAEX: "Buenas tardes Maite, Me pregunta Miguel, Asesor Jurídico, si Saturnino Miguel ha llegado a hablar con la Abogada Carmen Lucas. Plantea también, que si de lo que quiere hablar tiene que ver con el procedimiento judicial en que está inmerso y que lleva precisamente esta abogada, con quién debe hablar es con ella, pues él no tiene más información de la que ella le pueda proporcionar. Si se tratase de otra cuestión, puede hablar con Maite, Jefa de Sección, y conmigo. En este caso, agradeceríamos que no expliques cuál es el procedimiento, si nos llama él desde allí o si tendríamos que llamar nosotras y qué hay que hacer para ello. Sería al despacho de Maite, para mayor privacidad (924 00 60 57). Dinos también, qué día y hora sería factible. *Mañana yo no estaré. Pongo en copia a Maite, Jefa de Sección."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='RODRIGUEZ'and apellido2='MARTIN'),'2022-05-04','Ana: Correo de Marta Hdez. Fiz, TS Ceclavín (martarf043@hotmail.com): "Hola Ana. Soy Marta Hernández Fiz , Trabajadora Social de Ceclavin, ayer estuve hablando contigo telefónicamente sobre el caso de Manuel y Juan María Rodríguez Martin, para adjudicarle la ayuda a domicilio municipal que le urge puesto que Juan María se va a operar. Ya tengo toda la documentación , me faltaría la autorización bancaria para efectuar el cobro, que te adjunto, para que me la remitas y poder adjuntarla a su expediente. Si tienes alguna duda , estamos en contacto. Un saludo" ············· Reenvío el correo a Lourdes para que se encarguen de la autorización. ·············· Pregunto a Marta, por mail, las horas/semana del servicio y el coste total, así como si el SAD estará a nombre de los dos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MARTINEZ'),'2022-05-04','Ana: Correo de Marta Hdez. Fiz, TS Ceclavín (martarf043@hotmail.com): "Hola Ana. Soy Marta Hernández Fiz , Trabajadora Social de Ceclavin, ayer estuve hablando contigo telefónicamente sobre el caso de Manuel y Juan María Rodríguez Martin, para adjudicarle la ayuda a domicilio municipal que le urge puesto que Juan María se va a operar. Ya tengo toda la documentación , me faltaría la autorización bancaria para efectuar el cobro, que te adjunto, para que me la remitas y poder adjuntarla a su expediente. Si tienes alguna duda , estamos en contacto. Un saludo" ············· Reenvío el correo a Lourdes para que se encarguen de la autorización. ·············· Pregunto a Marta, por mail, las horas/semana del servicio y el coste total, así como si el SAD estará a nombre de los dos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2022-05-04','Ana: Correo de Blanca, directora del CRR (direccion.crrplasencia@grupo5.net): "Buenas Ana, te comento que Concepción González tiene prevista una salida a Trujillo para este fin de semana de 6 al 8 de mayo. Se ha acordado con ella y con la familia que pernocte en hotel de acuerdo a su proceso de rehabilitación y a la relación con su familia que actualmente es el apoyo que la pueden dar. No necesita dinero extra, esta ya todo planificado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2022-05-04','Ana: Correo de Pilar Cerrillo, TS de la Res. (calidad@grupociudadjardin.com): "Buenos días Ana, adjunto te envío copia del DNI de Martín actual. Como el original se le ha perdido, le pido cita también. Habéis valorado la posibilidad de solicitar para el un CRRR?, si quieres puedo iniciar yo los tramites, ya te voy informando. Me comenta su hermano, que la semana pasada sacó dinero y esta semana quiere sacar otra vez, no se que asignación le tenéis, pero como ahora esta en la Res. donde todas las necesidades las tiene cubierta lo podéis valorar. De momento se está adaptando bien. Cualquier cosa me dices." ··················· Mi respuesta: "Buenas tarde Pilar, Creo recordar que te comenté que el juez no había autorizado para ingreso en centro sociosanitario, con el ingreso suyo por urgencias la situación cambió mucho. ¿Tan recuperado está para que acceda al CRR? Como sabes requieren plena autonomía para acceder al mismo. Además, él debe aceptar este ingreso, pues uno de los criterios para ingreso es la Voluntariedad de las personas, ¿Lo ha manifestado él? En cuanto a su asignación, creo que no sería conveniente que sacara la misma cuantía que cuando estaba en su casa. Pongo en copia a Lourdes, compañera de la sección económica, para que cuando pueda nos diga cuál es su asignación y con qué periodicidad y que incluso se valore con el Jefe de la sección la modificación de la misma, al menos mientras siga ingresado en vuestro recurso. Seguimos en contacto."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-05-04','TERESA SE REALIZA LLAMADA A JOSE MARIA PARA VER COMO SE ENCUENTRA NOS COMENTA LA PSICOLOGA QUE SE ESTA ADAPTANDO BIEN Y PARTICIPANDO EN LAS ACTIVIDADES QUE ESTA CUMPLIENDO EL MINIMO EXIGIDO PARA PODER HACER UNA SALIDA Y NOS PROPONE UNA SALIDA AL DOMICILIO LE COMENTAMOS QUE DEBIDO A LAS CARACTERISTICAS DE LA FAMILIA ES MEJOR QUE LA FAMILIA ACUDA A ALLI A VERLO EN VEZ DE IR EL AL DOMICILIO FAMILIAR JOSE MARIA LE PARECE BIEN ESTA IDEA QEU VAYA ALLI SU FAMILIA UN FIN DE SEMANA Y PUEDA REALIZAR SALIDAS CON ELLOS POR LA ZONA SE PIDE PRESUPUESTO DE TAXI Y DE HOSTAL PARA VALORAR GASTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-05-05','miguel, recibo email de Eva (hija de la vecina)eva_barbara_2000@hotmail.com> , que remito a Tere: He conseguido un teléfono un familiar lejano, que se supone que tiene llave del portón trasero, 691302207 se llama Lola, espero que sea de ayuda','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2022-05-05','miguel, remito email a Jesús Bueno (abogado) de las llamadas recibidas por Puerto (hermana de la tutelada) y del despacho de la otra parte Alfredo Barca donde querían saber el estado de los trámites y que le llamarán','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='ALMANSA'and apellido2='REDONDO'),'2022-05-05','TERESA EMAIL DE FUENTE ATENOR Ángel Almansa demanda constantemente tener todo su dinero. si le permitimos tener los 95E los gastará inmediatamente bebiendo, hasta ahora al acompañarlo al banco teníamos discusiones fuertes por no permitirle manejar su dinero libremente. se lo entrego poco a poco y le dura toda el mes, peros siempre está quejándose, de forma bastante airada. Nos dices si el dinero lo recoge él, y lo maneja libremente, o se lo entregamos nosotras. En tal caso preferiría ir sola al banco para evitar los conflicto que actualmente se producen. por otra parte no nos queda claro como actuar en caso de que él insista en marcharse. Si es posible llámanos par teléono para aclarar dudas. muchas gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-05-05','TERESA ENVIO CORREO A EVA En marzo le han cargado del centro los 800€ mensuales que paga por su plaza y otro recibo de 960€. En abril, además de los 800€, le han cobrado 1.600€ en otro cargo, ¿Me puedes aclarar en concepto de qué son estos importes¿ Por otra parte comentarte que se han puesto en contacto con la comisión un vecino que linda su pared con la casa de la ya falelcida madre de Anastasio. A fecha de hoy no se ha hecho la herencia de esta vivienda, vamos a hacer los tramites para gestionar la herencia y arreglar el problema de humedad. Necesitamos entrar en la vivienda para que el albañil valore de donde viene la humedad, le puedes preguntar a Anastasio si tiene llaves de la vivienda o sabe de quien la puede tener¿','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-05-04','TERESA EMAIL DE LA VECINA DE ANASTASIO EVA maria gonzalez falcon >eva_barbara_2000@hotmail.com> He conseguido un teléfono un familiar lejano, que se supone que tiene llave del portón trasero, 691302207 se llama Lola, espero que sea de ayuda, un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2022-05-05','TERESA EMAIL FUTUEX Buenos días Teresa., enviamos nota del tutelado para trasladar la información que nos ha facilitado su pareja (Candi), donde nos informa que no localiza al tutelado desde el día anterior. Siguiendo en este momento, ilocalizable, ha tenido alguna conexión por whatsapp en el móvil, pero lo llamamos y está apagado. Realizamos nota desde el programa de apoyo social comunitario para informar de la situación del tutelado a fecha de hoy (5 mayo 2022). En la mañana del 3 de mayo (martes) concretamos cita con Pedro Tomás por teléfono, planificando el seguimiento para la retirada de dinero y la compra de necesidades básicas el día 5 (jueves). En esa llamada nos indica que ambos están bien y que el 4 de mayo (miércoles) no puede ser la visita ya que tienen que ir a Don Benito porque su pareja (Candi) tiene revisión en psiquiatría. El miércoles por la tarde nos informa Candi que, en Don Benito Pedro le engañó diciéndole que tenía que ir a ver a una prima que había sido maltratada (desde el programa desconocemos que tenga familia en la localidad de Don Benito) y le pidió 20 euros para regresar en autobús a Monterrubio de la Serena. Cuando ella llega al domicilio, accede a su WhatsApp ya que también lo tiene instalado en el ordenador y localiza conversaciones donde refiere que Pedro “se ha tirado toda la tarde buscando prostitutas para consumir”. Nos dice que no tiene medios para volver a casa y que lleva 4 días sin tomar antabus (medicación que toma para deshabituación alcohólica) , rechazando en este periodo seguir con el tratamiento. En la mañana de hoy Candi se vuelve a comunicar con el programa, nos dice que Pedro Tomás no ha regresado en toda la noche y que no puede localizarlo ya que tiene el móvil apagado. Lleva sin revisión de psiquiatría desde el 2 de julio de 2021. Indican que la psiquiatra se encuentra de baja, siendo este el motivo de la demora para ponerle la próxima consulta. Desde el CEDEX el médico le va dando pautas para mejorar la efectividad de su tratamiento y disminuir la ansiedad que continuamente manifiesta. Este momento, está en paradero desconocido, suponemos que sigue en Don Benito, pero no sabemos donde ha podido pasar la noche, ni en que condiciones, ya que puede estar en una situación descompensada, por su adicción alcohol y la cocaína, concomitante con su enfermedad mental. La pareja nos dice que ha hablado con el ayuntamiento de Monterrubio, y que se iban a poner a buscarlo.. (no sabemos tampoco la precision de esta información) ya que la pareja tiene enfermedad mental,.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2022-05-05','TERESA RECIBO EMAIL DE ADISER ha llamado en varias ocasiones al centro la abuela de Natalia, Pilar Miró. Nos pregunta si ella puede mantener contacto con su nieta, porque no sabe nada de ella. Necesitamos que nos digáis si le está permitido a Natalia el contacto con este familiar. AUTORIZAMOS EL CONTACTO SIEMPRE Y CUANDO NATALIA LO DESEE Y SEA BENEFICIOSO PARA ELLA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2022-05-05','miguel, envío email a Maite y Amalia, Buenas tardes, para vuestro conocimiento, y por si lográis hablar con la tutelada; para la solicitud de internamiento involuntario de Ana Mª Rosco Avalos la van a citar el 23-6-22 a las 10h donde deberá ir con su documentación médica. Nosotros no asistiremos, salvo que se nos requiera, y el documento no lo dice.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2022-05-05','TERESA EMAIL FUTUEX Buenos tardes, seguimos sin información nueva de Pedro Tomás, pero si nos han contactado desde la Guardia Civil de Monterrubio de la Serena, se ponen en contacto con el programa indicando que van a remitir el atestado de su búsqueda a diferentes comisarías de la zona, por ello nos piden información sobre su situación y tratamiento pautado. Se lo facilitamos, y les decimos que está tutelado y los datos de contacto de la comisión, no sé si se habrán puesto en contacto, pero estos son los datos por si acaso: El contacto en la guardia civil es Ángel (Sargento) Número de teléfono 661878929 Correo electrónico; ba-pto-monterrubiodelaserena@guardiacivil.org','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2022-05-03','-Amalia : registro solicitud de la valoración de discapacidad con informes .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2022-05-05','miguel, tras el aviso de Toni de Futuex, Teresa y Maite me piden lo denunciemos. Intento hablar con la policía local de Monterrubio de la Serena (lugar del domicilio que tienen alguilado el tutelado y su pareja Candi)pero lo tienen apagado. Llamo a la guardia civil de Monterrubio de la Serena y le digo todos los datos e información que Futuex nos ha dado. Me dicen que iran al domicilio y me informarán. *********************************Recibo email de Toni de Futuex que envía también a Maite: Buenos tardes, seguimos sin información nueva de Pedro Tomás, pero si nos han contactado desde la Guardia Civil de Monterrubio de la Serena, se ponen en contacto con el programa indicando que van a remitir el atestado de su búsqueda a diferentes comisarías de la zona, por ello nos piden información sobre su situación y tratamiento pautado. Se lo facilitamos, y les decimos que está tutelado y los datos de contacto de la comisión, no sé si se habrán puesto en contacto, pero estos son los datos por si acaso: El contacto en la guardia civil es Ángel (Sargento) Número de teléfono 661878929 Correo electrónico; ba-pto-monterrubiodelaserena@guardiacivil.org *************************************************** Contesto a Toni de Futuex','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-05-06','Ana: Nuevo correo del CRR () narrando las nuevas incidencias de los últimos 4 días (2 - 5 de mayo): consumo de alcohol, incumpliendo de normas e incontinencia urinaria. ·········· Guardo en el expte. ·································································································································································································· Envío correo a Miguel, Asesor Jurídico: "Buenos días Miguel, Tras haber hablado con Mariluz Madrigal, Jefa de Secc., y las compañeras de la Sección de acceso a Recursos de la red de Salud Mental, te remito informe del CRR (Centro Residencial de Rehabilitación) de Cáceres, comunicando que a día de hoy JUAN MARIO SAN ROMÁN BLÁZQUEZ, no puede seguir en el centro debido a su consumo activo de tóxico e incumplimiento de las normas, que sumado a su enfermedad orgánica (Diabetes Mellitus Tipo II) y su nula conciencia de patologías, tanto orgánica como mental, supone un grave riesgo para su salud. El equipo técnico del recurso expresa literalmente “Considerando necesario realizar una intervención específica con contención estimular y deshabituación del consumo de tóxicos para poder seguir beneficiándose de su proceso de rehabilitación y recuperación, facilitando así la consecución de sus objetivos y aumentando la calidad de vida de Juan Mario dejando a la vez de ser modelo de conductas de riesgo para otras personas usuarias del centro.” Se considera necesario solicitar un ingreso involuntario en la Unidad de Alcoholismo del Centro Sociosanitario de Plasencia, el tiempo necesario para su tratamiento. A posteriori se valoraría bien el retorno a su centro actual, bien el acceso a algún otro recurso residencial. Pongo en copia a Maite, para que esté al corriente o por si quiere aportar alguna cuestión."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2022-05-06','Ana: Correo de Jesús Manuel al ctutelar@ : "Soy Jesús Manuel les informo que la semana que viene necesitaré otra crema y les informo que la vecina de arriba tira sus desechos orgánicos en mi balcón como esto sige de forma descontrolada ya que el piso lo aveis alquilado vosotros tomas las medidas legales en este caso así como mandarme un equipo de limpieza y que lo Page la de arriba de no ser así sois igual que ella espero vuestra llamada" ······························································································································································································ Envío correo a Toni-Futuex: "En relación al correo que te reenvío remitido por JESÚS MANUEL RAMOS BARGÓN, ¿podríais acudir a verificar lo que indica y en caso de ser cierto, intentar mediar con la vecina? A posteriori, si fuera necesario, acompañar a Jesús a interponer una denuncia. Ya nos vais informando al respecto. Gracias y buena mañana." ····························································································································································································· Contesto a Jesús Manuel: "Buenos días Jesús Manuel, En relación a lo que comunicas sobre la vecina, ya está solicitada la colaboración al respecto al Programa de Apoyo Comunmitario. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-05-06','Ana: Llamada de Cristina Castro, Ed. Soc. Asoc. Vera (681 14 39 11 / educadorasocial@asociacionvera.com): Adrián se ha negado a volver al centro. No ha cogido el taxi en su pueblo y por ende el autobús para que ya tenía billete en la estación de Badajoz. *Ayer habló con él Laura, la Directora del centro, pero no ha servido de nada. *Desde la Asociación lo comunicarán a la policía. ············· Cristina me enviará informe para solicitar Autorización de Internamninto Involuntario. ···························································································································································································· Hablo con las compañeras del Area Social y con Miguel, Asesor Jurídico. Enviará escrito al Juzgado comunicando la situación y solicitando el ingreso involuntario de Adrián para que regrese al centro. ············································································· Al final de la mañana, recibo nueva llamada de Cristina, Ed. Vera: Adrián ha comunicado que quiere regresar al centro. ······ Laura, Directora de As. Vera, ha acudido a hablar con la Guardia Civil. *Éstos han llamado a los padres, comunicando que iban dar aviso también a la Comandancia de Vva. del Fresno. Ante esto han convencido a Adrián para que regrese. ·································································································································································································· Llamo a Toni-Futuex al respecto, solicitando la colaboración de Teresa para la gestión del taxi y bus. Ella adelantará el dinero del billete. ·············· Correo confirmación de Toni: "Ana, ok a lo que hemos hablado del taxista. Ya se le ha hecho llegar el DNI y el dinero para el billete de bus, en un sobre y está informado de todo. Dice que sin problemas.. que lo recoge sobre las 5 y que se queda hasta que se monte en el bus. También avisada la madre, que se ha puesto como un basilisco con Teresa, porque dice que van a coger un abogado para la tutela de sus hijos la tengan ellos y en fin, ni caso, porque esto es lo siempre. Asique esperemos que a la segunda, vaya la vencida, definitivamente y no surgan mas complicaciones con el taslado " ····························································································································································································· Más tarde, recibo llamada de Macarena, cuñada de los padres de Adrián (621 33 88 27), dice que los padres "quieren ser los tutores de Adrián". Les indico que deben acudir al Juzgado de 1ª Instancia de Olivenza para solicitarlo, allí le informarán de procedimiento a seguir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2022-05-13','TERESA RECIBO EMAIL DEL HERMANO DE ADOLFO Teresa buenos días como estas? Ya tengo el ingreso de los accesorios en cuenta Gracias , Bueno no se si te ha comentado algo la coordinadora de susana le dije que me ha llamado la empresa de Baleares para empezar el día 1 de junio ya parece que la pandemia se acabó entre Comillas, y era para que Adolfo le llevaran un catering la comida de aquí de Villafranca y por lo menos un par de días a la semana o tres le fuera una chica de los servicios Sociales del ayuntamiento a limpiarle, esto tu te pondrías en contacto con Marisa Tello s social Villafranca . Esto lo notifico por que tenemos que cumplir con la empresa , ya me dices tu los pasos y resolución.','2');
