insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2022-05-06','TERESA Escribimos está nota para indicar que Pedro Tomás Murillo ya se encuentra en su domicilio de Monterrubio de la Serena. Encontrándose en buen estado de salud, aunque la pareja refiere que sufrió una crisis por la que fue derivado a Salud Mental del Hospital de Mérida. (la realidad, de lo que pasó, no la sabremos, pero probablemente tenga algo que ver con algun consumo) Desde el programa de apoyo social comunitario para informamos que ayer día 5 de mayo de 2022 (jueves) a las 22:00 horas se pone en contacto Candi (pareja de Pedro), por teléfono, con la profesional que realiza los seguimientos presenciales. Indica que ya han localizado a Pedro Tomás y que en esos momentos se encuentra en el domicilio (Monterrubio de la Serena). Nos comunica que estando en Don Benito (miércoles 4 de mayo) sufrió una crisis y la policía local se lo encontró tirado en la calle, por este motivo fue derivado a la unidad de salud mental del hospital de Mérida donde fue estabilizado y dado de alta el jueves 5 de mayo. Desde el hospital contractan la pauta de tratamiento que tenía puesta desde Salud Mental y CEDEX, con las dosis que él indica tomar existiendo un aumento de la cantidad estipulada por esos profesionales de referencia. Desde el programa nos pondremos en contacto con Salud Mental para que le vuelvan a dar cita en psiquiatría ya que desde julio del 2021 no tiene revisiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSE'and edp.apellido1='MOLINA'and apellido2='SALAZAR'),'2022-05-06','TERESA SOLICITO A CADEX CERTIFICADO DISCAPACIDAD Y DICTAMEN TECNICO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-05-05','Ana: Correo de Óscar y Alberto, Secc. Ecca: "OSCAR: REINTERAMOS A BANCO...HAZ CONSTAR QUE ES REITERACIÓN Y QUE AFECTA NEGATIVAMENTE A FACETAS VIDA TUTELADO. ANA: EL TUTELADO TAMPOCO CUMPLE CON LO QUE HA PACTADO CONTIGO...LO DECIMOS POR SI QUIERES HABLAR CON EL ________________________________________ De: OSCAR GONZALEZ CERRATO >oscar.gonzalez@salud-juntaex.es> Enviado: jueves, 5 de mayo de 2022 9:03 Para: ALBERTO MARTIN ROSETE >alberto.martinr@salud-juntaex.es>; ANA MATAMOROS GOMEZ >ana.matamorosg@salud-juntaex.es> Asunto: RE: GONZALEZ CARRERO JUAN JOSE: SITUACION ECO Después de realizar las gestiones con Liberbank de reintegro permanente de 67€ semanales y transferencia mensual de 80 € a su madre, tanto él como Liberbank han hecho caso omiso. La transferencia a la madre si la han realizado, pero desde que les envié el oficio a Liberbank el 21 de abril ha extraído: • 25-04-2022: 50€. • 26-04-2022: 50€. • 27-04-2022: 70€. • 28-04-2022: 270€. • 30-04-2022: 50€. • 02-05-2022: 150€. • 04-04-2022: 50€. Además, ha recibido un ingreso el 28-04 de 1.044€ de Pensión de la TGSS, además de su PNC de 421,40 €. Desconozco si se la ha solicitado alguna pensión."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2022-05-09','Ana: Preparo y envío a Julio, Aux. Adtvo. CTAEX, la solicitud de traslado de centro residencial de mayores (para añadir el C.R. El Prado a la solicitud inicial) y el oficio a tal fin, para que le dé REGISTRO. ····················· Registrado a fecha de hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2022-05-09','Ana: En relación al correo de José, director de la Residencia: "Buenos días Ana, soy José el director que había en la residencia de Jaraicejo, creo que me recordarás..te llamé por el tema de Jarandilla, el traslado de Juan José Hornero Rodriguez a la residencia de Navezuelas, me comentabas que si el estaba de acuerdo no había problema, nos tenía que firmar el consentimiento y hacértelo llegar. Hay lo tienes vale?" ························································ Envío correo-respuesta: "Buenos días José, Gracias por el escrito, aunque está firmado en el lugar de la firma del familiar, no en donde aparece su nombre. ¿Sería mucho trastorno que le dierais una nueva copia y que lo firme de nuevo en el lugar correspondiente? Por otra parte, necesitaríamos un Certificado de Ingreso en el nuevo centro residencial para comunicarlo al Juzgado. ¿Qué tal ha ido el cambio? Espero que se adapte bien."','2');
