insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2022-04-28','Ana: Correo de Cruz Merino, TS (cruzmerino@tajosalor.es) en respuesta a mi pregunta: "Dori, la última vez que la ví estaba pendiente de la operación de cataratas, está deseando poder "ver" y así poder tener más independencia para moverse por el pueblo, la verdad es que la falta de visión la imposibilita hacer una vida más autónoma, por lo demás, está como siempre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2022-04-28','Ana: Correo de Cruz, TS UTS Alcántara - Mancomunidad Tajo-Salor (cruzmerino@tajosalor.es): "Me llamó la semana pasada la directora de la residencia de mayores de Alcántara. Hay un señor que reside en ella y está tutelado, se llama Martín Quirós Berrocal con DNI 7209715-C. Ha recibido una carta en la que señala que tiene el DNI caducado, yo he mirado en su expte y también la copia que tengo caducó. Pregunté en el ayto y me dijeron que la Policía, que viene una vez al año (aporx.) a realizar la renovación de los DNIs a Alcántara, vendrá a finales de año. Estaré pendiente y os lo comunicaré cuando es la fecha para que se pueda organizar la renovación del mismo. Tendríais que tener previsto que una persona le acompañe los dos días que se necesita para el trámite; uno para hacerse la foto y solicitar el DNI y otro para firmar el DNI renovado y recogerlo. No sé si Gloria (la persona que acompaña a Dori al médico o a retirar dinero a Brozas) podría hacerse cargo de estos dos acompañamientos, ya me dices y yo me quedo pendiente de avisaros del día concreto que viene la Policía."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2022-05-09','Ana: Envío correo a Toni, Futuex, solicitando la colaboración de Gloria, Ed., para acompañar a Martín en los trámites de renovación del DNI. ············· Pido a Cruz, TS, que nos avise cuando vaya a acudir la policía a Alcántara.','2');
