insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-05-09','Ana: envío correo a Maite, TS C. Penitenciario (trabajosocialcpcaceres@dgip.mir.es), en relación a la solicitud de llamada de Saturnino: "Buenas tardes Maite, En relación al interno SATURNINO MIGUEL SALGADO JIMÉNEZ, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura, comunicamos que desde el Gabinete Técnico de la CTAEX no tenemos inconveniente en recibir sus llamadas. Los número a los que puede llamar son: - Maite, Jefa de sección: 924 00 60 57 - Ana, Trabajadora Social: 924 93 02 45 Creemos que el mejor día de la semana y hora para hablar es el jueves sobre las 12:30 h. *No obstante, aunque se autoricen estos teléfonos, agradecemos que nos avisen con carácter previo a cada llamada para confirmarnos. Como sabéis, podemos tener otras gestiones y reuniones. Se adjunta Testimonio de sentencia de incapacitación y aceptación del cargo Quedamos a la espera de confirmación para el próximo jueves día 12. Ante cualquier cuestión, no dudéis en volver a contactar."','2');
