insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-05-10','Ana: Llamada de Julia (644 897 339): le informo que actualmente está la 3ª en la lista de espera para acceso a CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-05-10','TERESA EMAIL DE TONI FUTUEX el pasado 9 de Mayo se recibe una llamada de Beatriz Mejías de la Morena comentando que la han llamado del juzgado para decirle que tiene una citación judicial el miércoles 11 de Mayo a las 12 de la mañana en los Juzgados de Zafra. Es la misma citación que tenía hace un par de meses y que tuvo que suspenderse porque uno de los implicados tenía Covid. Por una supuesta agresión .. pero todo muy raro, sin pruebas ni nada. Acude en calidad de denunciada por una mujer que estuvo discutiendo con ella en la antigua vivienda de alquiler en la que residía Beatriz hace un par de años. También aparece denunciada por su pareja, Toni, la acusan de que tirara al niño de la mujer con la que estaba discutiendo por las escaleras. Algo que nos cuesta mucho creer que sea cierto, la verdad. Se acompañará a Beatriz en la citación porque está bastante nerviosa por encontrarse otra vez con esta mujer y con su actual pareja, de Beatriz, que es Toni. El personaje que la ha denunciado en varias ocasiones entre ellas ésta. Pero solo queda con ella en su casa y cuando están fuera es como si no lo conociera. Es increíble. En la medida que podemos, intentamos que tome conciencia de que esto es una relación no sana y que no deberia continuar con el, pero ya sabes que eso es tremendamente complicado con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MARTINEZ'),'2022-05-10','Ana: Conversación con Marta, TS de Ceclavín (Nº Personal: 636 725 521): El SAD irá a nombre de los dos. Aún no tienen horas libres del servicio y por tanto no saben cuántas horas semanales le podrán conceder, pero quieren tener el documento de Autorización de Domiciliación Bancaria ya preparado y firmado para que llegado el momento no se demore el inicio de la prestación del servicio.·············· Se pasará el cobro por la cuenta de Manuel que es quién percibe mayores ingresos. ··················· Se lo confirmo a Lourdes, secc. ecca., quién enviará el documento firmado a Marta, TS.','2');
