insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-05-10','Ana: Saturnino de nuevo debe paquetes de tabaco en el centro. Ante la petición de éste y el correo de Maite, TS C.P., Alberto aprueba la retirada de hasta 150€ que hay en la cuenta peculio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-05-10','Ana: Correo de Toni-Futuex: el día 6/05 la educadora acompañó a un juicio a Juan José, 2ª vista por la denuncia interpuesta por la vecina. En el juicio dice no recordar nada por estar "enajenado" debido al empeoramiento por la enfermedad, motivo por el cuál le incapacitaron. "A la salida, Juan José deja caer que dijo lo mencionado en el juicio por la acusada". ·····*Guardo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2022-05-11','Hola, adjunto envío certificado de defunción del padre de José Luis Calvo Gónzalez. El teléfono de su hermano José es 697288844.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2022-05-11','TERESA El pasado 6 de Mayo se recibió una llamada de Lorenzo, el hermano de Adolfo, donde tambien nos comentaba que le han llamado de su antiguo trabajo de Palma de Mallorca y se va a incorporar a principios de Junio. Por lo que habría que mirar empresas de catering en Villafranca para que le llevaran la comida a Adolfo todos los días. Se habla en primer lugar con Marisa de los SSB por si hubiera algún servicio de catering en el centro de día o la residencia de la localidad. Pero Marisa comenta que no existe ese servicio de manera pública y que la única opción sería que Adolfo fuera a comer y a cenar a la residencia, algo que sabemos que no va a hacer. - Se llama a la empresa La Gran Familia (924 53 50 12) y se habla con Cecilia de administración. Ella explica que tienen un menú diario a 8€ que incluye dos platos, pan y postre. Admiten pagos por transferencia y podrían emitir facturas mensuales del servicio. Al mes serían unos 248€ Email de contacto: administracion@cateringlagranfamilia.com - Seguidamente se llama al restaurante Europa (924 96 33 77) y se habla con Toni, uno de los dueños. Toni comenta que tienen un menú del día a 6,50€ que incluye un plato de cuchara muy abundante y un segundo que suele servir para que los usuarios cenen. Entra el pan y fruta, aunque a veces les dan natillas o arroz con leche. Admiten pagos por transferencia y emiten facturas mensuales. Al mes serían unos 201€. Email de contacto: Tonieuropa73@hotmail.es Al parecer ambos se lo llevarian a casa. Se queda a la espera de que la comisión decida qué tipo de catering prefiere.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2022-05-11','TERESA Acabo de hablar con la TS del centro de salud, Charo, y me comenta que ha visto a Lorenzo y que parece ser que ya no se va porque tiene problemas con una rodilla. También le ha comentado a Charo el tema del catering, parece ser que ya no quiere ni hacerle la comida a su hermano a pesar de que se comprometió con el psiquiatra que cuidaría de él Parece ser que está rozando Diógenes… el hermano se limita a dejarle la comida, hasta le ha dicho a Charo que no tiene que tomar medicación cosa que no es cierta ya que si que se le pauto en el informe de alta medicación para la esquizofrenia. A fecha de hoy Lorenzo no me ha comunicado nada al respecto, no hay problema en contratar el catering, l Voy a anular esa orden de transferencia y ese dinero lo usamos para catering. Hable con Marisa y me dijo que sabe de un chico que trabaja muy bien y que quizás le interese ir a casa de Adolfo, me dijo que le facilitaría el teléfono a Susana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2022-05-11','Pilar madre 643969847','2');
