insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-05-11','Ana: Correo de Óscar, secc. ecca. a Toni-Futuex: "Buenos días. Se autoriza la transferencia de 200€ a la cuenta de Mª Teresa Pacheco Cruz. Educadora equipo de apoyo social comunitario de Badajoz, para la compra de ropa del tutelado. Una vez realizadas las compras, nos enviáis las facturas correspondientes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-05-11','Ana: Llamada de Rosana (699 198 186) Mateo tiene cita de Psiquiatría en ESM en Cáceres mañana día 12. Confirmo a Rosana que se podrá abonar un taxi y acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-05-11','Ana: Soraya comunica a Maite que Juan Carlos protagonizó anoche nueva incidencia. Amenazó con un cuchillo que no saben de dónde sacó. Tuvieron que activar el 112 y la Guardia Civil tuvo que reducirlo. Le trasladaron en ambulancia al Hpta. de Llerena. ·················· Llamada de Mª Antonia Gía, Psiquiatra UHB-Mérida (81284): Juan Carlos fue derivado anoche (de madrugada, sobre las 2:00) al Hptal. de Mérida, pues aún no se le ha empadronado en Fuente de Cantos. Considera que hay que buscar otro recurso, pues no debería volver al Centro Fco. de Asuar, dadas sus características. *No obstante, añade que al ser un segundo ingreso en UHB en menos de un mes, se considera reingreso y podrían volver a derivarlo a la UHDAC. ·· *Por otra parte, ha realizado una ingesta de pilas y tienen que hacerle una endoscopia de urgencias. ····································································································································································································· Envío correo a Ana Mª Timón, TS Hptal. de Mérida (ana.timonm@salud-juntaex.es): "Buenas tardes Ana, Adjunto el consentimiento informado para realizar endoscopia digestiva a JUAN CARLOS RUIZ GARCÍA, debidamente firmado por el Presidente de la Comisión Tutelar de Adultos por delegación. Ante cualquier otra cuestión, no dudéis en contactar." ······················· Llamo a Mª Antonia, Psiquiatra UHB: (81284 // antonia.garciar@salud-juntaex.es). Le solicito informe de alta del ingreso anterior, pues no nos lo enviaron. ···················· Taciana, Psiquiatra UHB (taciana.valverde@salud-juntaex.es) me remite informe de Alta del ingreso anterior. *Guardo en el expte. ························· *Por fax me remiten desde el HME: "Justificante de Ingreso" actual de Juan Carlos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2022-05-11','Ana: Correo de Óscar, secc. ecca., a Toni-Futuex: "Buenas tardes. Desde la sección económica se autoriza el gasto por importe de 2.420€ (IVA no incluido) para la limpieza a fondo de la vivienda de Antonio Hidalgo Romo. Una vez recibamos la factura con los datos fiscales del tutelado y un número de cuenta para realizar la transferencia, se abonará la misma."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2022-05-12','Ana: Remito a Rosa Bravo, CSS-Plas. Cita médica para la consulta de Endocrinología para el día 20 de junio de 2022 a las 9:00. La recibieron en Aprosuba 3, por lo que pido a Rosa que cuando puedan acudan al centro de salud a comunicar de nuevo la dirección actual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-05-10','Ana: Correo del Dpto. de Distribución de Editorial Círculo Rojo (distribucion@editorialcirculorojo.com) al ctutelar@: "Buenos días, Tras conversación mantenida con Ceferino, nos ha solicitado la gestión del alta del epub en las plataformas de Amazon, Kobo, Google play y applebooks. Necesitamos confirmación por parte del centro tutelar para terminar la gestión y solicitar el alta en estas plataformas"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2022-05-12','Ana: Respuesta dada al Dpto. de Distribución de Círculo Rojo (distribucion@editorialcirculorojo.com) con copia a Ceferino: "Buenos días, Si la gestión de alta en dichas plataformas se ajusta al presupuesto indicado (96€ apróx.), se confirma y aprueba el alta en epub en las plataformas especificadas. Si por el contrario, el precio total superase los 100 €, no se aprueba dicha gestión. Ante cualquier cuestión no dude en volver a contestar." ················ Más tarde remiten el presupuesto con importe de 96€. ········ Lourdes, secc. ecca., confirma su aprobación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2022-05-12','Ana: Con respecto al correo de ayer de Teresa, TS Novaforma (trabajadorasocial.novaforma@gmail.com): "Os comento , he solicitado un extra para Fermín García para una consulta privada en psiquiatría así como que valoren la posibilidad de la contratación e un apoyo privado para salir por las tardes de paseo con el ,o no se si es factible que el apoyo lo de Futuex. A nivel de salud mental esta muy inestable por lo que no puede salir solo, la semana pasada tuvo una llamada de atención con un intento de autolisis por lo que no se le deja sin vigilancia en ningún momento." ····································· Contesto: "Gracias por avisar. Ya he hablado con una compañera de la sección económica con respecto a la consulta privada, dando mi aprobación, falta la del Jefe. Si económicamente lo puede asumir, no creo que hay problemas. Con respecto a las salidas con Futuex por las tardes lo veo complicado y en todo caso serían días muy puntuales espaciados en el tiempo. ¿Conocéis a alguien que pudiera/quisiera prestarle este apoyo y/o empresa que se dedique a ello? Necesitaríamos un presupuesto aproximado mensual, en que se especificaran las horas del acompañamiento semanal, para poder valorarlo con la sección ecca. Yo entiendo que es necesario hacerlo. Pongo en copia a Maite. Seguimos en contacto. Buena mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2022-05-12','Ana: Llamo a Lourdes Pérez Ortega, TS de SAD-IMAS (927 212 335 / Ext. 4425): en relación al recibo de SAD remitido por el OAR correspondiente a la mensualidad de diciembre de 2021, va a consultar si hay más recibos pendientes de abono. ·· Me llamará a lo largo de la mañana. ························· Llamada de Lourdes, TS SAD: Me confirma que anteriormente Pilar no tenía que abonar el servicio, pero que se procedió a una revisión de tasas y desde el pasado mes de diciembre tiene que abonarlo. Percibe 9h/semana de SAD, y abonará en torno a 1,5 €/hora. **Es conveniente domiciliar el pago. Los recibos los pasan con cierto retraso (A 4-5 meses vencido). Las cuantías aproximadas de enero a marzo, son respectivamente: 82€, 75€ y 68€. ························ *Se lo comunico a Óscar, secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-05-12','Ana: Remito correo-e a Julia, coordinadora de la Casa de la Misericordia de Alcuéscar (casadelamisericordia.alcuescar@gmail.com): "Buenos días Julia, Hasta ahora no te he escrito, pues estaba esperando a recibir tanto el informe de Psiquiatría del Equipo de Salud Mental como el Certificado de Pensión No Contributiva, pues en la Declaración Jurada de PNC de los últimos años no consta la cuantía que percibe. De cara a que valoréis la posibilidad de ingreso de JOSÉ MANUEL ROMERO MEDIAVILLA en vuestro centro, tal y como acordamos, os remito: - Certificado PNC - Informe Evolución en recursos residenciales de la Red de Salud Mental firmado por la Jefa de Secc - Informe del ESM de Cáceres Si necesitáis cualquier otra cosas, no dudéis en contactar. Quedo a la espera de vuestra valoración. Un saludo y buen día." ··································································································································································································· Correo de Pilar Martín, TS del ESM-CC (pilar.martinp@salud-juntaex.es): "Buenos días, Ana te informo de la próxima cita de José Manuel Romero Mediavilla el día 6-6 a las 10,10 con su psiquiatra Enrique Goenaga. saludo. (Ya se lo he dicho por teléfono a Virginia).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-05-12','Ana: Ante el correo de Cristina, Ed. Vera (educadorasocial@asociacionvera.com) comunicando incidencia del día 9 y aportando informe y parte judicial de lesiones. Respondo: "Buenos días Cristina, Gracias por informar. Si antes me dices el lunes que está tranquilo… antes se produce… Qué complicado todo siempre con este chico. Espero que las medidas adoptadas surtan efecto y que el ojo del otro chico evolucione bien. ¿Habéis comunicado la incidencia a la sección de Discapacidad? Si no lo habéis hecho aún, por favor, remitirle también los informes a Maribel Mesa o Belén Gutiérrez. A ver cómo sigue en estos días. Un saludo y buena mañana."','2');
