insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-05-12','TERESA HABLO CON CENTRO ME INDICAN QUE SE HARIAN CARGO DE TUTELADO AUNQUE NO TUVIERA DINERO (VA A SOLICITAR EL CONTRATO)...MIGUEL: CUANDO TERE NOS PASE EL CONTRATO TENEMOS QUE VER SI ESTO ES POSIBLE DE ASUMIR O SI DEBEMOS COMUNICAR AL JUZGADO ...YO NO LO TENGO CLARO','2');
