insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2022-05-06','Ana: Recibimos resolución del RECONOCIMIENTO DE SITIACIÓN DE DEPENDENCIA: GRADO III ······················· Lo remito a Claudia, TS del CR El Cuartillo (claudia.alonso@salud-juntaex.es) ··············· En cuanto a mi consulta, Claudia me informa: "Emilia en general bien, nos cuesta un poco controlarla por la necesidad deambulación constante que tiene, pero bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-05-12','Ana: Correo de ayer de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, Plena Inclusión pone en marcha el programa Apoyo en contextos naturales de Plena Inclusión y el equipo técnico ha pensado en Felisa Bruno para poderse beneficiar. Como sabes Felisa no tiene una familia o amigos con los que pueda acceder a nuevas oportunidades diferentes a las que se le puedan ofrecer desde el centro. El poder tener a una persona de apoyo que indague en el entorno, en la comunidad y le pueda ofrecer alternativas que le motiven, que contribuyan a llevar su vida deseada, unas horas a la semana contribuirá a mejorar su conducta, a sentirse valorada y crear nuevos vínculos. Es un programa subvencionado por lo que las personas que finalmente se beneficien, tendrán un copago ya que la otra parte del coste se asume con la subvención de Plena Inclusión. Hemos calculado según su pensión y para 4 horas semanales sería un coste de 20,18 € al mes. El programa tiene una duración de 6 meses y comenzarían en Julio, siempre que su solicitud cumpla con los requisitos y sea aceptada. Desde ASINDI, si nos autorizáis, haríamos la solicitud y trámites correspondientes. Pero es necesario que nos confirméis si puede asumir el copago de 20,18 € mensuales. Por nuestra parte intentaríamos ayudarle a controlar los gastos en otros temas de ocio,...porque creemos que sería beneficioso para ella. Puedes verlo tu con los compañeros de la sección económica y nos confirmáis? ·················· Envío la consulta a Óscar, por mi parte, si es viable económicamente, OK.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-05-12','-Amalia : registro informe médico para dependencia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2022-05-13','TERESA El pasado 5 de Mayo se visitó a Paloma Rodríguez en su domicilio de la calle Cristo de la Piedad, 9 de Jerez de los Caballeros. Ella hizo entrega de una factura sin abonar del arreglo de la antena de su vivienda que asciende a algo más de 190€. Se explica a Paloma que estas cosas no funcionan así y que ya se había mandado un presupuesto a la comisión de otro profesional para que ellos valoraran si era posible este gasto y sin consultarlo con nadie, avisa a otro técnico para que se lo arregle y espera que la comisión acepte el pago. Se adjunta envía la factura sin abonar. Seguidamente se le pregunta por un ruido en el frigorífico, ella dice que lo escucha por la noche solamente. Se va con ella a la cocina para escuchar un rato el ruido del frigorífico, no se escucha nada. Se abre tanto el congelador como el frigorífico y se comprueba que funciona perfectamente. Se le explica a Paloma, que los frigoríficos hacen ruido cuando el ventilador empieza a funcionar y que quizá lo escuche más por la noche porque hay menos ruido de fondo y tienen la televisión apagada. Se concluye que el frigorífico está en buen estado y no tiene ningún problema de funcionamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-05-13','Ana: Recibimos requerimiento de varios documentos de PNC. ····· Solicito a Ana: Mª José, Directora del CAM Fco. Pizarro - Trujillo (61091), Certificado de residencia en el CAM y solicitud de certificado de empadronamiento individual. ······················· El alta de terceros se lo entrego a Lourdes, secc. ecca. para que lo lleven a banco el lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-05-13','Ana: Llamada de Rosana (699 198 186): a Mateo finalmente le acompañó una auxiliar del centro a la cita médica, por lo que sólo enviarán la factura de taxi. Se lo digo a Óscar, secc. ecca. ······················· *Por otra parte, cuentan con una persona voluntaria para hacer acompañamientos a partir de ahora.','2');
