insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-05-02','Ana: Correo de Sara, Técnica en integración de Asindi (ocioytiempolibre.asindi@gmail.com): "Buenas tardes, me pongo en contacto con usted para comentarle que con motivo del 36º edición del Festival de Teatro Clásico de Alcántara, se va a realizar un casting para seleccionar un grupo de personas para que sean la imagen de este festival. Felisa Bruno Saavedra y Justo Hernández Castaño nos han manifestado querer participar. Por lo que necesitamos saber si nos conceden autorización para que puedan presentarse al casting y si son seleccionados se pueda mostrar sus fotos. Las fotos serían para la promoción de la cartelería de dicho festival. Quedo a la espera de su respuesta." ························· Se lo reenvío a Miguel, Asesor Jurídico.','2');
