insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2022-05-16','Ana: Envío a Miguel, Asesor Jurídico CTAEX, el correo remitido el viernes por el CRR: "Buenos días: En relación a la persona usuaria Félix Valle Simón, debido a las dificultades detectadas y a un incremento progresivo del consumo de alcohol, y debido a sus antecedentes de consumo y para evitar otras consecuencias por incumplimiento de normas del centro se le propone y se acuerda con él acuerda con él la medida terapéutica de acudir al CEDEX para tratamiento y ayuda ante la dificultad. La persona usuaria acepta, se inicia el proceso de derivación y está acudiendo desde mediados del mes de abril. Se están realizando analíticas semanales de orina. Desde el CEDEX nos comunican que para poder informarnos de los resultados de dichos análisis semanales se necesita una autorización de la comisión tutelar al personal del centro del CRR para ser informados de dichos resultados ya que al estar tutelado por la comisión no pueden dar la información a otro personal sin dicha autorización. Muchas gracias."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2022-05-16','Ana: Envío a Miguel, Asesor Jurídico CTAEX, el correo remitido el viernes por el CRR: "Buenos días: En relación a la persona usuaria Félix Valle Simón, debido a las dificultades detectadas y a un incremento progresivo del consumo de alcohol, y debido a sus antecedentes de consumo y para evitar otras consecuencias por incumplimiento de normas del centro se le propone y se acuerda con él acuerda con él la medida terapéutica de acudir al CEDEX para tratamiento y ayuda ante la dificultad. La persona usuaria acepta, se inicia el proceso de derivación y está acudiendo desde mediados del mes de abril. Se están realizando analíticas semanales de orina. Desde el CEDEX nos comunican que para poder informarnos de los resultados de dichos análisis semanales se necesita una autorización de la comisión tutelar al personal del centro del CRR para ser informados de dichos resultados ya que al estar tutelado por la comisión no pueden dar la información a otro personal sin dicha autorización. Muchas gracias."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2022-05-16','miguel, recibimos email de un familiar:De: Salud Extremadura >inf.saludextremadura@salud-juntaex.es> Enviado el: jueves, 12 de mayo de 2022 12:15 Asunto: Contacto Comisión Tutelar de Adultos Nombre: Luciano Apellidos: Muñoz Castaño Asunto: Partición de una herencia. Mensaje: Buenos dias. Me pongo en contacto con ustedes porque mi tio está tutelado por la Junta de Extremadura y actualmente reside en la residencia de San Vicente de Alcantara. El nombre de mi tio es Agustin Castaño Tornavaca. La cuestión es que sus hermanos quieren vender una vivienda que heredaron de su madre y comparten la herencia con mi tio Agustin. La cuestión es la siguiente, ¿Que procedimiento hay que hacer para poder vender dicha vivienda ? Gracias. Correo Electrónico y/o Teléfono de Contacto: lucianomunoz@hotmail.com ************************************************************* mi contestacion: Buenos días, hemos recibido una email suyo en relación a su tío tutelado por nosotros, necesitamos nos indique un teléfono y le llamaremos para explicarle los pasos porque se requiere previo a la firma de la herencia en la notaria, autorización judicial de aceptación de la herencia, y tras la firma se necesitará autorización judicial de aprobación de herencia, y como imaginará son trámites que requieren contratar abogado y procurador, los cuales necesitaran que se les aporte una serie de documentación de testamentaria (certificado de defunción, últimas voluntades, certificado de fallecimiento, certificados de los saldos de las cuentas a repartir, notas simples de las fincas que se quieran adjudicar en herencia…)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2022-05-16','Ana: Habiéndome comunicado desde la secc. ecca. que a Juan le hacen un ingreso periódico mensual y no sabemos en qué concepto, llamo a Emilia, TS del CSS (24164 / 240205), pero no obtengo respuesta. ·················· Le envío un correo-e: "... En relación a Juan Mendo Palacios, me informan mis compañeros de la sección económica, que lleva tiempo percibiendo un ingreso mensual de forma periódica que no saben a qué corresponde. ¿Tú sabes si tiene alquilado algo o alguna idea de a qué puede deberse este ingreso? En caso contrario, ¿podríais preguntarle a él? Más que nada para tenerlo controlado y poder comunicarlo al Juzgado." ·················· Respuesta de Emilia, TS: "89, 98 € que aparecen en la cuenta desde hace algunos años. Es el alquiler de la casa que pose Juan Mendo en la localidad de Riolobos, era una casa entre el antiguo tutor que ya falleció y Juan, un alquiler que se hizo en su día. La familia quiere que el inquilino abandone la casa, pero parece que tienen algún problema." ········ Se lo reenvío a Óscar, secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2022-05-16','Ana: llamo a Paula, TO CRR-Plas. (682 70 44 01) en relación a la llamada de Flora del pasado jueves. No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2022-05-12','Ana: Llamada de Flora (687 316 191), dice que no le están ingresando dinero desde que he le han abierto la cuenta en Liberbank. Que tiene ya 57b años y se quiere ir del CRR. Que ella no tiene problemas de salud mental. "Quiero volver a Pais Vasco a una residencia de minusválidos de mi edad", "allí sería feliz". ·········· La Dra. Ana Mayo le ha derivado a Neurología, porque e ha caído muchas veces. " Me cuesta subir a mi habitación". También pide que le hagamos una visita desde la CTAEX. *Vuelve a insistir en que no cobra, "no estoy puesta en la cuenta de Liberbank de la Comisión", le explico que eso si que no puede ser, que las cuentas se abren siempre a nombre de las personas tuteladas. ··········· Mañana tiene cita con Paula, TO a las 10:30 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2022-05-10','Ana: Conversación con Estrella, TS de Malpartida de CC (927 27 50 03). Andrés reside en la Res. de Mayores de Santa Marta de Magasca, en la localidad de Santa Marta de Magasca. Pero lleva años en lista de espera para plaza privada en la Residencia de Malpartida de CC, donde justo ahora han quedado 2 plazas vacantes, podrían acceder tanto él como su hermano, quién también está en lista de espera. *Actualmente presente mayor deterioro cognitivo, aunque sólo tiene reconocido Grado I de Dependencia. *No tiene derecho a Prestación Ecca. Vinculada al SAR. *El precio de la plaza, acorde al grado I, es de 1303,68 €/mes. *En Santa Marta cree que es algo menos, pero no sabe exactamente cuánto. **Cuando ingresó allí su deseo expreso, era el de estar allí sólo hasta que quedar plaza libre en Malpartida, cuando aún no presentaba deterioro cognitivo. *Su hermano, Dionisio, está deseando poder trasladarlo al pueblo. ····················· Dado que es su deseo y que tiene propiedades que llegado el momento se podrían vender, acordamos que lo veré con la sección económica, pero si a día de hoy es viable, realizaremos los trámites para que se vaya a su pueblo, tal y como él deseaba.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2022-05-16','Ana: Correo de Sonia Bernabé, TS y Directora ASINDI (trabajosocial@asindi.e.telefonica.net): "Hola Ana, únicamente informaros que Juan Gabriel Sobrino Tardío es positivo desde el sábado. De momento, presenta como único síntoma la tos. Esperemos que le dure poco tiempo y que lo pase leve."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2022-05-16','Ana: correo de Óscar, sección económica: "Juan José sigue extrayendo efectivo del cajero todos los días sin control. Liberbank no ha hecho caso a los tres escritos que les hemos enviado." ····················· Respondo, con copia a Maite y a Miguel, CTAEX, que la única opción que veo es comunicarlo al Juzgado y que desde éste hagan un requerimiento al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2022-05-16','Ana: Llamada de Juan José, ha tenido la cita en Cardiología, dice que le han dicho que el corazón está bien. Pero que tiene que dejar de fumar y de tomar bebidas con cafeína. *Dice que lo va a dejar ya, que tiene fuerza de voluntad.','2');
