insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2022-05-16','TERESA ANTE LA IMPOSIBILIDAD DE ENTRAR EN LA VIVIENDA PORQUE NO COSIGO CONTACTAR CON LA PERSONA QUE NOS FACILITO LA VECINA Y ANASTASIO COMENTA QUE EL NO TIENE LLAVES DE LA VIVIENDA, LE COMENTO A MIGUEL LA OPCION DE FORZAR LA CERRADURA MIGUEL ME DICE QUE PARA HACER ESTO TIENE QUE ESTAR ANASTASIO PRESENTE MANDO EMAIL A LA RESIDENCIA mailto:vanegomez1979@hotmail.com SOLICITANDO LA PRESENCIA DE ANASTASIO PARA FORZAR LA CERRADURA DE LA VIVIENDA DE SU MADRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2022-05-13','Maite: nos han notificado desde Plena Inclusión Cabeza del Buey que a Marta le han concedido tratamiento piscológico del servicio de Habilitación Funcional con fecha fin 31/05/2024. Hemos enviado firmado el documento de alta.','2');
