insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-05-16','Ana: Correo de Óscar, secc. ecca., con copia a mí: "Buenas tardes Sonia. A nivel económico no hay objeción al gasto de 20,18 € mensuales durante 6 meses para el programa Apoyo en contextos naturales de Plena Inclusión."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2022-05-16','Ana: Correo de Emilia, TS CSS-Plas.: "...YOLANDA CALDERA MARTIN, (UDAC) ES positivo en COVID. no tiene síntomas de importancia según refiere su medico."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2022-05-16','Maite: Este fin de semana ha estado la famlia de Morón visitándolo. Esto dice la trabajadora social del centro:Hola. Si, vinieron. En principio todo ha ido bien, sin incidencias. El me dijo que había estado muy contento. No le he podido ver mucho porque hemos tenido un fin de semana ajetreado pero estoy a la espera de poder sentarme a hablar con el y que me cuente. Llamaré a la familia por seguimiento también. Me he puesto en contacto con los administradores del apartamento y del taxi para que me pasen las facturas y enviároslas. Un saludo, Diana.' 'Vinieron sus padres y su hermana. Aproveché para conocerles en persona el día que vinieron' 'Justo ya he podido recabar más información, he llamado a la familia y he hablado con Jose María y todo perfecto. Dicen que no han tenido ningún conflicto, que han estado todos muy tranquilos, que con la hermana también todo bien. La chica del apartamento también ha estado bastante pendiente de que todo estuviese bien y ha estado en contacto y me dice que todo perfecto. José María está encantado, dice que se lo ha pasado super bien, y entiende que es mucho gasto y que tendrá que esperar para poder volver a repetirlo. Un saludo, Diana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2022-05-16','Ana: correo de Guadalupe Cortés, TS del SAD-IMAS CC (guadalupe.cortes@ayto-caceres.es): "Informar que la ampliación del SAD propuesta se hará efectiva desde hoy 16/05/2022."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-05-16','Maite: el viernes 13 de mayo enviamos al juzgado la solicitud de internemiento involuntario de Aitor, poniendo de manifiewsto la situación en la que se encuentra tanto él como su madre, adjuntando los informes realizados por FUTUEX y ADISER.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2022-05-17','Ana: Correo de ayer en el ctutelar@ de David, Centro de Entrenamiento para la Salud, Kame (kameentrenamiento@gmail.com): "Buenas tardes, os quería comentar sobre Aída Martín De Piñol. Esta apuntada al centro de entrenamiento para la salud, Kame, en el cual realiza ejercicio físico a modo terapéutico. Contrató dos días a la semana, pero el último mes ha fallado mucho, viniendo de media la mitad de los días que le tocan. No me avisa y después de la hora le pregunto y me dice que ha tenido algún dolor, todos de diferentes tipos e inconexos entre sí, y también me dice que tuvo que ir al banco, suelen ser sus justificaciones. Yo intento estar encima y comunicarme con ella, pero quisiera preguntar si tenéis alguna estrategia para intentar conseguir que venga más, lo necesita y creo que le puedo ayudar, pero como comprenderéis, me gustaría que utilizase los dos días por continuidad y aprovechamiento de lo que paga y también, lógicamente, porque está ocupando un hueco en mi centro que la mitad de los días desaprovecha. Todo esto, esperando conseguir algo más de constancia, espero respuesta. Gracias, un saludo, David, CEO de Kame." ···················· Mi respuesta: "Buenos días David, Gracias por informar. Nos coordinaremos con la educadora que le visita periódicamente para que aborde este asunto con ella. Esperemos que surta efecto y aproveche el servicio que está abonando, si no fuera así, posiblemente haya que decirle que se le dará de baja en vuestro centro. Desde este Gabinete Técnico, por el tipo de cargo que tiene asumida la Comisión Tutelar de Adultos con respecto a Aída, no podremos hacer mucho más. Un saludo y buen día." ··································· Envío correo a Toni-Futuex: "Nos remiten este correo desde el CENTRO DE ENTRANAMIENTO KAME, en relación a la asistencia de AÍDA MARTÍN DE PIÑOL. ¿Podría por favor la compañera hablar con ella al respecto? Este servicio se abona periódicamente para que lo aproveche, pues se aceptó por ser positivo para su salud. Hay que hacerle entender que si no va regularmente la terapia no funciona y por tanto sería un gasto innecesario. Creo que hablar con ella en persona será más efectivo que decírselo desde aquí por teléfono. Ya nos vais informando qué os dice y si surte efecto vuestra intervención al respecto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2022-05-17','Ana: correo-e de Teresa, TS Novaforma (trabajadorasocial.novaforma@gmail.com): "Buenos dias para las salidas de Fermín hemos calculado 50€ al mes , saldria con una compañera un ratillo todas las tardes unos 40 minutos. No sabemos si este coste puede asumirlo." ············ Se lo remito a Lourdes y Alberto, secc. ecca., dando el ok por mi parte en caso de ser asumible económicamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-05-17','Ana: Entrego a Julio, aux. adtvo. CTAEX, oficio y documentación para REGISTRO DE SALIDA, a los SS.TT. Cáceres (PNC): la documentación requerida: - Alta de Terceros, Certificado de Empadronamiento y Cdo. de residencia en el CAM de Trujillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTIAN'and edp.apellido1='CARRASCO'and apellido2='BLANDON'),'2022-05-17','TERESA • ESTA COBRANDO VINCULADA SEPAD X 300 €/MES DE FORMA INDEBIDA PUES NO ESTA ACUDIENDO A LA TERAPIA QUE TIENE CONCEDIDA. HE HABLA CON JORGE (DEPENDENCIA) PARA QUE DEJEN DE ABONAR Y NOS PASEN CARTA PAGO X DEUDA, QUE POSIBLEMENTE SUPERE LOS 3.000 €.... • HE SOLICITADO PNC X 421,40 POSIBLEMENTE LA COBRE EN JUNIO • HAY QUE ESTABLECER ASIGNACIÓN, TENIENDO EN CUENTA QUE VIVE CON SU MADRE, TIENE NECESIDADES BÁSICAS ASEGURADAS Y HAY QUE IR PAGANDO LA DEUDA GENERADA. • ¿ LA MADRE PIDE ALGO DE DINERO PARA MANUTENCION DEL HIJO?, SI ES ASI ACTUALMENTE NO SE LA PODRIAMOS DAR HASTA QUE SE SALDE LA DEUDA CON DEPENDENCIA • CON EFECTO INMEDIATO VAMOS A "BLINDAR" LA CCC: PARA QUE, HASTA QUE NO HAGAMOS REINTEGROS AUTORIZADOS, NO PUEDA SACAR DINERO EL TUTELADO Y DEJE DE GASTAR ASI EL DINERO DE LA VINCULADA DE DEPENDENCIA • CON EFECTO INMEDIATO VAMOS A CANCELAR CUALQUIER POSIBLE TARJETA QUE ESTE ASOCIADA A ESTA CCC. • CON EFECTO INMEDIATO VAMOS A DEVOLER Y CANCELAR CUALQUIER RECIBO O TRANSFERENCIA QUE SE HAGA RELACIONADA CON TELEFONÍA O JUEGOS.','2');
