insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2022-05-18','Buenos días Amalia, a día de hoy la libertad es del día 21 de Mayo, porque tiene otra condena que cumplir pero el juzgado aún no ha mandado la orden de prisión, sino le viene el viernes como muy tarde, hay que ponerle en libertad el sábado. El cobrará sus 50 euros el jueves, y lo que no se gaste más lo que le quede del ingreso mensual que le hacéis se lo lleva todo el sábado. Mañana te puedo averiguar con el dinero que va a salir el sábado. Un saludo PAULA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='RODRIGUEZ'and apellido2='FERNANDEZ'),'2022-05-18','Amalia , llama su hermano 924760723 , quiere que se le de un dinero para venir a verlo al CSS . Se le abonarÁ kilometraje y 15€ por menÚ .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2022-05-18','miguel, recojo la ratificación y doy a Inés para remitirla a la notaria de los santos de maimona Carlos Duro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2022-05-18','miguel, se firma la venta en Plasencia (Notaria de Manuel Gomez Moro) de la cual le abonarán a ella unos 8.900€. No podemos ratificar porque falta original de sentencia de incapacitación y aceptación del cargo (Inés lo pide al juzgado) y la Csv en testimonio de venta (que solicito su rectificación a la abogada)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-05-18','Ana: Icíar pone al día las deudas con la Residencia de mayores: "Podología y peluquería parte de 2020/21/22......420€ Arreglo de dentadura 40 € Viajes a urgencias 176€ Total....636€" ·············· Félix presenta un estado de salud muy delicado. ······················ En cuanto a la Prestación Ecca. Vinculada al SAR, se registró la aceptación en octubre de 2021. Le concedían 175€. Pido a Icíar que comprueben si se le está haciendo el ingreso y desde cuándo, para poner también al día el copago en la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2022-05-19','Ana: Correo de ayer de Pilar Cortijo, Supervisora Res. Navezuelas (pilarcortcer@gmail.com): "Buenos días, soy la supervisora de la residencia de mayores de Navezuelas , donde fue trasladado desde otra residencia Juan Jose Horneros Rodriguez, el cual está tutelado por la Junta de Extremadura. Me han dado su contacto para que le pregunte a usted sobre la manera de gestionar sus gastos del día a día ( peluqueria, podologia, necesidades de ropa, acompañamientos a hospital,...). También tengo más dudas sobre el tema de empadronamiento y demás. Si fuese tan amable de facilitarme un número de teléfono para poder dirigirme a usted y resolver estas dudas, o si así lo prefiere podemos comunicarnos mediante correo electrónico. Un saludo." ························ Respondo explicando como proceder para las gestiones de empadronamiento, compra de ropa y acompañamientos hospitalarios. Para los gastos del día a día, paso la consulta a Óscar, secc. ecca., para que se pongan en contacto con ellos, entiendo que los gastos y modo de proceder serán los mismos que en la residencia de la que procede. ·········· Comunico también a Julio, aux. adtvo. CTAEX, el cambio de centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2022-05-19','Ana: Reenvío a la secc. ecca., Declaración Jurada de acompañamiento a cita médica programada en el Serv. de Psiquiatría, del ESM-CC, remitido por Fefi, Residencia Francisco Sánchez Salazar de Aldea del Cano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-05-19','Ana: Envío correo a Alberto, Miguel, Óscar y Maite: "Buenos días, Os reenvío correo de Futuex, con notificación de nueva deuda de MARTÍN DOMÍNGUEZ PALENCIA… Miguel y Alberto, echarle un vistazo. En cuanto a las incidencias en la residencia de mayores, he solicitado informes (social y de psicología) a Pilar Cerrillo, la TS de la Residencia. Si me los envían, espero poder activar el ingreso en el C. Sociosanitario de Plasencia, para el que la Autorización Judicial aún está en vigor. Sería la forma de agilizar el ingreso. Tal y como yo lo veo, vuelve a haber motivos para ello.". ················ Guardo en el expte. correo de Futuex con incidencias en el centro residencial: lanza objetos por la ventana, quema ropa, rompe algunas prendas...','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-05-19','Ana: Envío correo a Alberto, Miguel, Óscar y Maite: "Buenos días, Os reenvío correo de Futuex, con notificación de nueva deuda de MARTÍN DOMÍNGUEZ PALENCIA… Miguel y Alberto, echarle un vistazo. En cuanto a las incidencias en la residencia de mayores, he solicitado informes (social y de psicología) a Pilar Cerrillo, la TS de la Residencia. Si me los envían, espero poder activar el ingreso en el C. Sociosanitario de Plasencia, para el que la Autorización Judicial aún está en vigor. Sería la forma de agilizar el ingreso. Tal y como yo lo veo, vuelve a haber motivos para ello.". ················ Guardo en el expte. correo de Futuex con incidencias en el centro residencial: lanza objetos por la ventana, quema ropa, rompe algunas prendas...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2022-05-19','Ana: Reenvío a Toni, Futuex, nuevo correo de David, Centro Kame, pidiendo que Gloria, Ed., se ponga en contacto con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2022-05-18','Ana: correo de Estrella Durán: "Te comunico que Carlos Alberto Vicente Calderero ha dado positivo en covid"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-05-19','-Amalia . ya tengo PIA firmado , vuelvo a solicitar a la TS de la R. M . la documentación que necesito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-05-04','Ana: Correo de Pilar Cerrillo, TS de la Res. (calidad@grupociudadjardin.com): "Buenos días Ana, adjunto te envío copia del DNI de Martín actual. Como el original se le ha perdido, le pido cita también. Habéis valorado la posibilidad de solicitar para el un CRRR?, si quieres puedo iniciar yo los tramites, ya te voy informando. Me comenta su hermano, que la semana pasada sacó dinero y esta semana quiere sacar otra vez, no se que asignación le tenéis, pero como ahora esta en la Res. donde todas las necesidades las tiene cubierta lo podéis valorar. De momento se está adaptando bien. Cualquier cosa me dices." ··················· Mi respuesta: "Buenas tarde Pilar, Creo recordar que te comenté que el juez no había autorizado para ingreso en centro sociosanitario, con el ingreso suyo por urgencias la situación cambió mucho. ¿Tan recuperado está para que acceda al CRR? Como sabes requieren plena autonomía para acceder al mismo. Además, él debe aceptar este ingreso, pues uno de los criterios para ingreso es la Voluntariedad de las personas, ¿Lo ha manifestado él? En cuanto a su asignación, creo que no sería conveniente que sacara la misma cuantía que cuando estaba en su casa. Pongo en copia a Lourdes, compañera de la sección económica, para que cuando pueda nos diga cuál es su asignación y con qué periodicidad y que incluso se valore con el Jefe de la sección la modificación de la misma, al menos mientras siga ingresado en vuestro recurso. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2022-05-19','Amalia : Ingresado desde 2021 por emergencia social en la R. M . Mª Jesus Lopez Ruiz en Plasencia . TF R.M. 927017270. Presenta retraso mental grave . Con grado III dependencia . Percibe PNC con cpto. 632€ , 88% G.Discapacidad.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2022-05-19','Amalia : Ingresado desde 2021 por emergencia social en la R. M . Mª Jesus Lopez Ruiz en Plasencia . TF R.M. 927017270. Presenta retraso mental grave . Con grado III dependencia . Percibe PNC con cpto. 632€ , 88% G.Discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2022-05-19','miguel, llega directamente del juzgado de lo penal 1 de Plasencia, ejecutoria 146/21, por la que se condena al tutelado hasta 15-12-2023, y se lo reenvío a Ana para su constancia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-05-19','Ana: Correos de Maite, Jefa Secc. CTAEX: "Ya tengo la autorización de internamiento involuntario de Juan Carlos. Lo he enviado al centro y he hablado con la trabajadora social. Estoy a la espera de que nos digan el dia de ingreso para avisar a Mª Antonia y que preparen La PCR y el traslado." ······················· "En principio ingresa en Avila el 24 de Mayo. Ya esta todo hablado con el centro y la UHB"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VERA LUCIA'and edp.apellido1='DA CONCEIÇAO'and apellido2='BEZERRA'),'2022-05-19','-Amalia : nos comunican desde el CSS que tiene caducado su permiso de residencia desde 2020 y tb su pasaporte , voy a contactar con asesoría de extranjeros para el trámite. Según el libro de familia no están casados y tiene un hijo menor de edad en España . Desde la pandemia no ve a su hijo se quieren retomar las visitas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-05-20','Ana: Correo de Maite, Jefa Secc.CTAEX, a Araceli, TS de Mentalia Salud - Arévalo (tsocialpsicogeriatria.arevalo@mentaliasalud.es): "Hablé ayer con la Unidad de psiquiatría del hospital. Les parece bien que el ingreso de Juan Carlos sea el martes 24 de mayo. La llegada será sobre las 11:30-12:00. Les he pasado vuestro contacto. Harán la PCR y nos van a facilitar el certificado de vacunación Covid." ································ Correo de Maite, Jefa secc., a Rosa, C.R. Fco. de Asuar (cofa@fuentedecantos.es): "El ingreso de Juan Carlos en el centro de Ávila, sino hay incidencias, será el próximo martes 24. Esta es la dirección del centro para que enviéis sus cosas: Mentalia Arévalo Paseo San Juan Bosco 2 05200 Arévalo Tel 920 301 400"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2022-05-20','Ana: Guardo en el expdte. digital las Resoluciones de Grado de Dependencia (Grado III) y de Prestación Ecca. Vinculada al SAR (175€/mes desde el 1/12/21 ····· Atrasos: 2.718,33€, correspondientes al periodo: 15/08/2020 - 30/11/2021)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2022-05-20','Ana: Dado que sigo sin poder contactar con Montaña, TS, envío un correo al Ayto. de Santa Marta de Magasca (aytosantamarta@hotmail.com): "Buenos días, Mi nombre es Ana, soy Trabajadora Social del Gabinete Técnico de la Comisión Tutelar de Adultos de la Junta de Extremadura. Necesitaría hablar con Montaña, la Trabajadora Social, agradecería me facilitaran una dirección de e-mail para poder ponerme en contacto con ella o que le faciliten este mío para que me escriba cuando pueda. Quería consultarle sobre una persona, residente en la Residencia de Mayores de su localidad, y cuyo cargo de Curatela se ha aceptado recientemente por la CTAEX. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2022-05-20','Ana: Glora Mayoral, PP.TT. me remite factura de tratamiento dental. ············· La reenvío a la sección económica para su abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-05-19','Ana: Tras varios intentos fallidos de hablar por teléfono con Paula, TO del CRR y Piso Supervisado Plas., le envío correo (tocupacional.crrplasencia@grupo5.net): "Me dijo que había encontrado habitación para alquilar en piso compartido y que prefería que no fuerais nadie del CRR para verlo, intenté que me explicara el por qué, pero sólo decía que estaba harta del centro… no obstante, sí acepta que le visite allí la educadora del Programa de Apoyo que gestiona Futuex."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-05-20','Ana: Correo de Paula, TO del CRR y Piso Supervisado Plas.(tocupacional.crrplasencia@grupo5.net): "Entiendo que vosotros gestionáis todo lo relativo a los apoyos o visitas de futuex. Toñi nos informa que su intención es irse a partir del día 1 de Junio, por lo que si estáis de acuerdo, para esa fecha formalizamos la salida del recurso y os enviamos el informe." ································ Respondo: "como en otras ocasiones hemos hablado, siempre que desde el equipo técnico del recurso estéis de acuerdo de que está preparada para dar el paso y consideréis que es el momento, por nosotros de acuerdo. El seguimiento se le asignaría al programa de apoyo que gestiona Futuex, con una de las dos educadoras de la provincia de Cáceres, a nosotras nos van informando periódicamente y de forma puntual cuando es necesario también. En este caso, confiemos en que vaya bien y que continúe acudiendo a su seguimiento en el Equipo de Salud Mental. Ya me vais diciendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2022-05-20','Ana: Correo de Emilia, TS CSS-Plas. al ctutelar@: "Respecto Jairo M.P: nos comenta en la reunión de Equipo que le vais a enviar desde la comisión otros 100 por este segundo semestre del año, pues él dice que los 100 € que tenemos del mes pesado es del primer trimestre y le pertenecen 200 al año. Por otra parte, ya no quiere gastar todo en ropa y calzado, ahora quiere un altavoz musical y lo que sobre para ropa. Necesitamos sabes ¿sí podemos disponer de otros 100E en junio? para solicitarlos al banco antes de finales de este mes, y si, ¿puede comprar el altavoz musical? Por otro lado, quiere 15 € todo los mese porque quiere que se le descuente del tabaco, ¿es posible?" ································· Respondo desde mi correo: "- Jairo Puertas Martín tiene aprobada dos retiradas anuales de efectivo, de 100€ cada una, para comprar ropa; una es para ropa de verano y otra para ropa de invierno. Lo de invertir parte de dicho dinero en un altavoz, se podría aceptar en caso de no necesitar ese dinero para ropa. No entendemos que siempre esté demandando ropa y ahora que puede comprarla pida gastar el dinero en otra cosa. Si en el centro, que conocéis mejor sus necesidades, valoráis que de los 100€ previstos para ropa y calzado le puede sobrar algo para destinar al altavoz, de acuerdo, pero la prioridad es calzado y ropa. Una de las últimas veces que he hablado con él ha verbalizado que tiene rotas las zapatillas. En cuanto al tabaco, sería bueno para su salud que redujese el consumo, e incluso que llegara a dejarlo. Si le sirve de motivación para dicho objetivo el disponer de pequeñas cantidades para gastos de bolsillo, del dinero que se ahorra al no gastarlo en tabaco, no nos parece mal. Pero siempre dentro de tener cubierta es “necesidad” y dentro de la cuantía destinada a tabaco, no dinero extra."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2022-05-20','Ana: Correo de Emilia, TS CSS-Plas. al ctutelar: "Margarita Antich: Por necesidades médicas, se ha realizado por su médico somático, un estudio podológico y probablemente necesitara plantillas de corrección. ¿Por este motivo o solicitaremos algo más de dinero para el mes de junio, o lo pagamos a través de factura desde el centro? ··············· Respondo: "- En cuanto a lo que planteas de Margarita Antich Arroyo, en el centro disponéis de autorización para retirar dinero de efectivo para las cuestiones que pueda necesitar, excepto cuando son gatos mas grandes, como de odontología, material ortoprotésico y demás cuestiones de esta índole… Entiendo que en este caso el gasto no será muy elevado, pero creo que no estaría de más que enviéis primero el presupuesto a la sección económica para que el jefe de sección dé el visto bueno y os indiquen también cómo proceder al abono de las plantillas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2022-05-23','Ana: Correo de María, Programa de Familia Tajo-Salor (programafamilia@tajosalor.es): "Buenos días Ana! La persona a la que me refiero es Miguel Ángel Ramos Andrés, es de Aliseda, la sentencia de curatela es del 22 de Marzo de 2022, no sé si ya os ha llegado. La situación social de este chico es complicada, en la actualidad está cumpliendo una medida de tres meses de internamiento en prisión. La salida está prevista para mediados de junio. En el momento que salga de prisión no tiene donde ir, tiene una orden de alejamiento de su madre y su hermano durante 16 meses, además de tener que cumplir cuatro años y seis meses de libertad vigilada en la que tiene la obligación de seguir un tratamiento médico externo adecuado a las patologías que padece. La cuestión es que cuando salga de prisión no tiene donde ir, lleva en la calle alrededor de un año, viviendo en pisos ocupados , albergues, comiendo en comedores sociales , malviviendo. Antes de entrar en prisión cobraba 216€. Durante el último año y medio ha pasado por 6 comunidades terapéuticas , de las cuales ha salido siempre por problemas de conducta. Este chico tiene una patología dual, tiene discapacidad y un trastorno de salud mental, además de tener problemas de drogodependencias. Unas de las dificultades que tenemos con él, es que en los recursos en los que podría estar no puede entrar por el problema de consumo que tiene. Ya está avisado el servicio de salud mental y dependencia. Sería interesante que pudiéramos hablar , así explicarte detenidamente como es la situación y ver cómo podemos ayudar a Miguel Ángel. Nuestro teléfono es el 659926956, Sonia o María." ······························································································································································································ Mi respuesta: Buenos días Sonia y María, En relación al joven del que hablas, desde la CTAEX, hasta la fecha, sólo se ha aceptado el cargo de Defensa Judicial. Según el Decreto de dicho nombramiento, la atribución que se confiere es sólo la de “representación de MIGUEL ANGEL RAMOS ANDRES en el procedimiento de incapacitación”, y a dichos procedimientos no asiste nadie del Gabinete Técnico de la CTAEX, sino de Abogacía General de la Junta de Extremadura. La Sentencia de Curatela que citas, todavía no ha llegado, por lo que desde aquí, por mucho que queramos, no podemos hacer nada. No obstante, tomo nota de todo y en cuanto recibamos la sentencia me pongo en contacto con vosotras y hablamos. Eso sí, como bien habéis dicho, es un caso complicado y el margen de intervención es mínimo dado el perfil y los recursos por los que ha pasado con el resultado que indicáis. Desde el Centro Penitenciario también se han puesto ya en contacto conmigo, pero al igual que con vosotras, les he dicho que en cuanto llegue la sentencia les llamaré. Pongo en copia a Maite, Jefa de sección, para que esté al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='BARRIGA'and apellido2='CARNERERO'),'2022-05-23','-Amalia : Ingresado en plaza T3 en Rosalva desde hace años . Original de Barcarrota . Perceptor de PNC , la plaza se le pasa por Banca Pueyo . Sin red familiar ni social de apoyo. Sin gastos de bolsillo actualmente , se lo paso a sección eco para ver si podemos darle algo. Tiene seguro decesos en CASER .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='BARRIGA'and apellido2='CARNERERO'),'2022-05-23','Amalia : escribo a sección eco para cuadrar sus cuentas: Buenos días , este es el último caso de diciembre del año pasado . Acabo de hacer su plan de intervención inicial , ya tenemos inventario hecho . Es perceptor de PNC de 421€ y abona por la plaza sociosanitaria 354,84 . Se lo cargan desde la Residencia de Rosalva en Mérida directamente a la cuenta que tiene abierta en Banca Pueyo . Habría que poner como titular con él al Gerente . Tambíen se le carga el seguro de decesos que tiene con CASER . Desconozco si se le carga algo más , aparece como propietario de una vivienda en Barcarrota , igual abona IBI ... Si hay suministros en alta , agua, luz... yo los daría de baja para poder ahorrar algo . Actualmente no percibe nada de dinero de bolsillo , cuando se actualice su cuenta me indicáis , aunque seal 50€ al mes habría que enviarle . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2022-05-23','Ana: A fecha de hoy no constan datos en el CADEX relativos a Mateo, no tiene discapacidad reconocida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-05-23','TERESA RECIBO CORREO DE TONY ADISER te he llamado para informarte de la llamada de la madre de Aitor esta mañana. Me informa Felisi que Aitor se fue a Badajoz, y allí habrá estado un par de semanas, discutiría y reñiría con su novia y la cosa no acabó bien por lo visto, por lo que Aitor volvió a casa. Me indica su madre que ella está en Casar con el novio (Jesús) y que Aitor se ha saltado por el patio de la casa y está en Navas; que ella no quiere que esté en su casa y que no sabe donde llamar para solucionarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-05-23','TERESA CORREO MARI CIELO DEL CRPS Nos ha llamado muchas veces Beatriz, se encuentra mal. Ha acogido a un chico que conoció en el centro en su casa, esta intentando que se vaya de casa pero él no quiere y la está amenazando. Ha llamado a la Policía, pero le han dicho que para proceder a echarlo de la vivienda tiene que haber denuncia y tenéis que ponerla vosotros. No puede contactar con vosotros. Por favor, ponte en contacto con ella, está muy nerviosa. La denuncia era para Toni; Lleva una semana muy nerviosa, ha acudido a urgencias en varias ocasiones. sabemos que ha acudido los servicios de urgencias a verla y se la han llevado, supongo que a la UHB de Llerena. Mañana me infomaré si esta unos días ingresada o solo la han llevado para que la vea la psiquiatra de urgencias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='LAVADO'and apellido2='MACEDO'),'2022-05-23','Se Adjunto mandato SEPA donde aparece el número de cuenta de la curatelada. autorización bancaria para el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2022-05-23','Ana: Fefi, Residencia Francisco Sánchez Salazar de Aldea del Cano (fechago73@hotmail.com) nos remite foto del Informe del Serv. Psiquiatría - ESM-CC.: "Esquizofrenia de curso continuo.", "Estable desde el punto de vista psicopatológico" Reducen el Xeplion de 150 a 100 mg cada 28 días.. ········· Próx. revisión a los 6 meses. ··· Guardo en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-05-24','Ana: Respuesta de Julia, Casa de la Misericordia - Alcuéscar (casadelamisericordia.alcuescar@gmail.com) a la petición de ingreso en centro: "...Una vez que hemos evaluado el caso y sintiéndolo mucho, no nos podemos hacer cargo de este caso. Si quieres que lo comentemos llámame cuando estimes oportuno." ···························· Ana: Llamo a Julia García Félix, Coordinadora de la Casa de la Misericordia de Alcuéscar (927 12 00 24): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2022-05-24','TERESA , Virginia, la arrendataria , el teléfono 646749908. COMENTA TENER QUEJAS VECINALES POR LO ACONTECIDO AYER, LE EXPLICO LO SUCEDIDO, SI VUELVE A RECIBIR QUEJAR VECINALES TRENDRA QUE IRSE DEL PISO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-05-24','miguel, llega email de Programa de Atención a Familias de la Mancomunidad Tajo-Salor; programafamilia@tajosalor.es> Hola Ana!!! Desde el Programa de Atención a Familias nos ponemos en contacto con usted para informar de la situación actual de Aitor Moreno Felipe que consideramos de alta gravedad y necesitamos indicaciones de la comisión tutelar para la intervención con este caso. Le agradeceríamos que se pusieran en contacto con nosotras a la mayor brevedad posible ya que es urgente ************************************************* contesto a Ana, Tere y Maite a la pregunta de qué podemos hacer al informe social remitido por la Mancomunidad Tajo-Salor: Buenos días, Ana mejorate pronto. Comentaros que las denuncias las interpone quién las presencia y se basan en un ilícito legal. Aquí no hay ilícito legal pues no hay ningún delito en que un hijo entre en su casa… En principio sólo puedo comunicar al juzgado los hechos. Si queréis que solicitemos un internamiento involuntario urgente, sería necesario informe médico (junto a este informe social) y si no hay dicho informe médico dudo que nos den autorización de internamiento involuntario. La otra solución es que activen el 112 si entienden que exista descompensación…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-05-24','Ana: Correo de Isabel (imariacano.ic@gmail.com) al ctutelar@ : "Ana mi madre necesita 20 euros que el viernes viene a verme con su pareja pero su pareja se va a su pueblo con su hija y luego recoge a mi madre asique a él no le voy a ver.porfa quiero ver a mi madre ya me trae las sábanas de verano y ropa. Un saludo." ···························· Envío un correo a Estrella Durán, TS CSS, preguntando al respecto de la visita, así como por el estado y evolución de Isabel. ················ Respuesta de Estrella, TS CSS (estrella.duranc@salud-juntaex.es): "Isabel ha estado muy bien estos días. Sí, se ha ido hoy de alta al CRR. Respecto al tema de que la madre la visite el viernes, aquí no sabemos nada." ······················ *Envío correo a Blanca, Directora CRR, y Paula, TO CRR-Plas., preguntando por el regreso de Isabel y su opinión sobre la visita de la madre el próximo viernes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2022-05-24','Ana: Correo de Emilia Almodóvar, TS CSS, al ctutelar@: "Desde el departamento de Terapia Ocupacional y con el fin de fomentar la participación del centro y de los alumnos de terapia se realizará el día 31 de mayo 2022 una excursión a Segovia organizada desde el Centro Sociosanitario, para ello solicitamos la autorización por parte de la Comisión tutelar. Autorización para excursión a Segovia de: Margarita Antich Arroyo" ························· Mi respuesta: "Por parte de este Gabinete Técnico, de la CTAEX, nos parece una actividad positiva para Margarita. Si desde Psiquiatría se da el visto bueno y pase de salida y desde el equipo técnico de vuestro centro también lo consideráis, se AUTORIZA LA ASISTENCIA DE MARGARITA ANTICH ARROYO A DICHA EXCURSIÓN."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2022-05-24','Ana: Coreo de David, Centro Entrenamiento KaMe (kameentrenamiento@gmail.com); "Buenos días, ya hablé con la educadora, hemos acordado en que le paso el control de la asistencia a ella y vamos a renovar su cuota con ese control. Os adjunto la justificación del pago que corresponde a medio mes de mayo y el mes de junio entero. Gracias por la atención, un saludo, David."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-05-24','miguel, llega 3º escrito del defensor del pueblo: ************************************************ Reenvío los tres escritos y contestación a los dos primeros a Soraya, Maite y Ana, para reunirnos próximamente para una solución y les reenvío el email que he enviado a la abogada Carmen Lucas con el 3º escrito que hemos recibido del defensor del pueblo. ******************************************************* Reenvío email a la abogada Carmen Lucascarmen.lucas@lucasabogados.com> : Buenos días Carmen, ha llegado un 3º escrito donde básicamente preguntan si hemos solicitado un perito psiquiatra para acreditar la enfermedad y aclarar si se ha solicitado su traslado a un centro adecuado a su patología. Indicame si es posible solicitar ambas cosas. Al tiempo indican que únicamente tienen la primera página de tu escrito de defensa (yo tampoco la tengo completa). Por favor aclárame si es posible actuar en ese sentido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-05-24','Maite: Juan Carlos ha ingresado hoy en el centro Mentali Arévalo. Araceli, trabajadora social, me ha informado que ha llegado tranquilo y está bien. Mañana volvee a hablar con élla para ver como sigue. Desde el centro de Fuente de Cantos le han enviado sus cosas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2022-05-25','Ana: Rosa Bravo, CSS Plas., me remite el Cdo. de Empadronamiento en el CSS de José Luis. ·················· *Se lo remito a Miguel, asesor jurídico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='CRESPO'and apellido2='PEREZ'),'2022-05-25','Ana: Rosa, Adtvo. CSS, nos remite el Cdo. de Empadronamiento de Ángel en el CSS. ················ Se lo remito a Miguel, Asesor Jurídico y a Emilia, TS CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-05-25','Ana: Envío correo-derivación a Toni-Futuex: "Procedo a realizarte una nueva derivación: Se trata de Mª ANTONIA BERNARDO PIRIS, actualmente reside en el Piso Supervisado de Salud Mental de Plasencia (asociado al CRR). Las profesionales del recurso consideran que está preparada para vivir de forma independiente. De hecho ella sola ha buscado una habitación en piso compartido al que se irá a vivir a primeros de junio. Ya sé que el tiempo es ajustado, pero ¿sería posible que fuerais a visitarla por primera vez al piso, antes de irse a su nueva dirección y a partir de ahí establezcáis un seguimiento periódico? Al principio más intensivo a ser posible, eso sí, teniendo en cuenta que es un poco reticente a los seguimientos, e incluso plantea que la mayoría de los encuentros tengan lugar fuera de su nuevo piso. No quiere que sepan que está tutelada ni de su enfermedad por los hándicaps que le pueden suponer. *Acepta una primera visita al piso (como si llevase a una conocida/amiga) para ver las condiciones en que se encuentra el mismo. Es importante también que la compañera que asignéis, esté pendiente también de sus citas en Salud Mental, pues entendemos que este seguimiento es fundamental. También podéis contactar con Ana Benavente, TS del ESM, pues con ella también acude de vez en cuanto. Las últimas veces ha sido para gestionar su tarjeta de transporte. Para vuestro conocimiento, de cara a la intervención: - En revisión del CADEX, ha mantenido el mismo grado de discapacidad (65%). - Es perceptora de PNC (421,40 € x 14). Por lo que sus ingresos son justos y limitado. Tengo pendiente cerrar con Alberto, Jefe Secc. la subida de asignación para que pueda abonar el alquiler. Para el cuál no le han hecho contrato. - Su asignación actual = 250€/mes. - El precio de la habitación = Hab. 160€/mes (incluido gastos suministros) - Ahora pide 400€/mes. *Como digo, pendiente de aprobar. Datos e contacto: - Telf.: 677 407 893 - Domicilio actual: PISOS SUPERVISADOS PLASENCIA GRUPO 5. C/ PUERTA DE BERROZANA, 2." ··························································································· Envío a Alberto, Óscar y Maite, CTAEX, correo con propuesta de subida de asignación de 250 €/mes a 400€/mes para poder ir vivir de forma independiente a piso compartido. ··························· Respuesta de Toni-Futuex: "Hola Ana, vale, pues me apunto todo, y mañana a ultima hora de la tarde, veré a los compis del equipo de Cáceres, las dos conocen y acuden al CRR de plasencia por otros seguimientos, asique esperemos que eso contribuya a que se sienta más cómoda la tutelada en la primera visita, pretenderemos que esto sea lunes o martes antes de irse al piso sin problema."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-05-25','miguel, Manuela de Centros nos remite email que recibe de plena inclusion de Jaraiz de la Vera: Buenos días Manuela: Adrián Ortigosa Fuentes y su familia (padre, madre y cuñada) está amenazando gravemente a varios usuarios y trabajadores del centro. Algunas familias quieren presentar denuncia y nosotros como profesionales creemos que deberíamos también. Nos da medo que se presente aquí toda la familia. Vamos a preparar informe con los hechos de ayer y lo registramos esta mañana. Por otro lado, voy a hablar con el Sargento a ver que nos recomienda. ******************************************** email de Manuela: Me comenta Laura de VERA que ayer fue un día intenso. Adrián amenazó a varios usuarios y trabajadores y por si fuera poco la familia (padre, madre y la cuñada) también amenazó gravemente a la directora. No sé si a esto último se puede poner algún tipo de límites. ********************************************** email que nos remite Ana: Buenas, de nuevo, Manuela, Pongo en copia a Miguel y a Ángel, por si ellos nos pueden aclarar, cómo puede proceder Laura, Directora de Asociación Vera, porque yo supongo que puede denunciar a la familia por estas amenazas, no? En cuanto a Adrián, no sé si podríamos poner en conocimiento del Juzgado todas las incidencias y limitar, aún más, las salidas al domicilio. Y con respecto al uso del móvil, tampoco sé si se puede solicitar y llevar a cabo de alguna forma, la limitación en su uso. Miguel y Ángel, en el expte. he guardado informe con todas las incidencias desde que ingresó en Vera. Ya nos vais diciendo qué os parece.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-05-26','miguel, contesto a Manuela, parte social, y Angel: Buenos días, estos hechos debemos de comunicarlos al juzgado a los efectos oportunos para lo cual desde el centro deberían remitirnos un informe de hechos de todas las incidencias (no sólo la última) y desde la parte social si es posible proponer las medidas que puedan o deban adoptarse. Junto al informe social (y médico si los hubiera por lesiones…) que nos remita el centro y si las hubiese las denuncias que presenten… En cuanto a la limitación en el uso del móvil, o cualquier otro impedimento (como por ejemplo que no pueda acceder a distintas dependencias del centro)es el centro quién debe establecer unas normas de conducta y el que tiene que valorar quitárselo o no durante el tiempo que esté en el centro (no una vez que salga del mismo), pero tendrá que valorar que no suponga una descompensación de Adrian en cuyo caso tendría que informarnos para comunicarlo al juzgado. En definitiva hay que comunicar a fiscalía/juzgado las incidencias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-05-26','miguel, recibo email del abogado de la aceptación de la herencia Manuel Andrino, y email donde me aporta documentación acreditativa de que también está pendiente de tramitarse la herencia del padre: Conforme a lo comentado por teléfono, adjunto te envío el Decreto del Juzgado citando a una comparecencia a la Comisión Tutelar de Adultos de la Junta de Extremadura, al Ministerio Fiscal y a D. Jose Antonio Delgado Rodríguez, para el día 06/06/2022, a las 10:45 horas. Solicité la suspensión y nuevo señalamiento de la comparecencia porque ese día tengo unas pruebas radiológicas en Badajoz, pero el Juzgado lo que ha hecho, en DIOR de 20-05-2022, es denegar el nuevo señalamiento y retrasar la hora de celebración a las 12:30 horas. Como te he comentado, pensé que sería conveniente aportar en la comparecencia notas del Registro de la Propiedad de los tres inmuebles que se relacionan en la declaración del Impuesto sobre Sucesiones de la fallecida Dª. Josefa Rodríguez Casero, con objeto de acreditar la inexistencia de cargas o embargos sobre dichos bienes, pero me he encontrado con la sorpresa de que figura inscrito también como titular de los bienes D. José Delgado Repilado, marido de Dª. Josefa Rodríguez Casero, habiéndose adquirido e inscrito los bienes con carácter ganancial. Te adjunto las notas del Registro de la Propiedad que he pedido. La Asesoría de Fregenal, Del Cid y Villafaina, me remitió ayer certificado de defunción de D. José Delgado Repilado, fallecido el 23-06-2004, pero sería necesario conocer con seguridad si se tramitó la herencia de D. José Delgado Repilado y de no haberse hecho, como así me has comentado por teléfono, la solitud de autorización ante el Juzgado debería haberse pedido también respecto de la herencia de D. José Delgado Repilado. Como la comparecencia se ha señalado por el Juzgado para el día 6 de Junio a las 12:30 horas, no aceptando el Juzgado la suspensión de la comparecencia y el señalamiento de otro día para su celebración, sería necesario disponer cuanto antes de la siguiente documentación de D. José Delgado Repilado: certificado de defunción; certificado del Registro de Actos de Última Voluntad; copia autorizada del testamento, en su caso; declaración que se hubiese presentado del Impuesto sobre Sucesiones, en su caso. La Asesoría Del Cid y Villafaina se está encargando de pedir esa documentación, habiendo contactado con la Notaría. Si tuviéramos esa documentación podríamos presentar un escrito en el Juzgado informando de esta circunstancia y solicitando ampliación de la autorización también para la herencia de D. José Delgado Repilado, aportando la documentación justificativa de su fallecimiento y últimas voluntades. Si no dispusiésemos en breve plazo de esa documentación, ante la premuera derivada del señalamiento, intentaríamos solicitar la suspensión de la comparecencia. Estamos en contacto Miguel. Te informo si podemos tener la documentación y de la solicitud que hagamos al Juzgado en un sentido u otro. Como bien has apuntado, sería conveniente informar también al Ministerio Fiscal. ********************************************** Reenvío email a Tere: Buenos días Tere, me ha escrito el abogado porque nos han citado para el día 6-6-22 a las 12,30h en el juzgado nº1 de Fregenal de la Sierra para vista para la aceptación de la herencia de la madre de José Delgado Rodriguez. Resulta que el abogado ha pedido las notas simples y yo he comprobado ctastro y efectivamente aunque el padre falleció en 2004 no se ha llegado a hacer la herencia (que sepamos) por lo que debería ampliarse la petición de heredar no sólo de la madre sino del padre. Por otro lado ni en el inventario ni en las rendiciones anuales de cuenta se hace mención de los bienes que tiene el tuetelado… Por tanto, vamos a esperar si el abogado logra que pronto le puedan facilitar desde una notaria de allí certificado de últimas voluntades y testamento si lo hubiera (para asegurarnos de que no haya otros herederos) y a partir de ahí solicitar la suspensión del procedimiento para ampliarlo a que herede también la parte de su padre. En resumen, que te esperes a que el abogado me confirme si va a solicitar o no la suspensión de la vista del día 6-6-22, y que en caso de que la vista siguiese adelante alguien tendría que acompañar al juzgado ese día a las 12,30h sería la vista. En cuanto sepa algo te aviso… ************************************** Reenvío a Manuel Andrino (Manuel Andrino >mandrino@andrinoabogados.com> 924 22 90 23 / (+34) 924 25 98 62) : Buenos días Manuel, adjunto catastro y por si te sirve certificado de discapacidad y libro de familia, etc Quedo a tu disposición para cualquier aclaración y/o duda','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-05-26','miguel, recibo email de contestación de la abogada Carmen Lucas: Miguel ¿Y quien pide eso? Como profesional yo dirijo el proceso, si no le agrada a la familia me aparto. El forense ha hecho su informe, entiendo que como profesional yo valoro la prueba a pedir, se trata de juzgar unos hechos, no de diagnosticar ahora a esta persona. Mañana estaré en el despacho, por si quieres hablar. **************************************************** remito email a Ana, Maite y Soraya de la conversación con la abogada Carmen Lucas: Buenos días, tras conversación con la abogada Carmen Lucas, que ya os podéis imaginar lo enfadada que está, porque ni el hermano ni el defensor del pueblo están respetando la libertad profesional (presión y casi coacción a su actuación profesional…) Me comenta que todavía no ha llegado el momento de las conclusiones, que tendrá que estudiar pues existen incongruencias en los hechos en lo que dice Saturnino, el cual no para de llamarla y que quiere que vaya a verle. Ahora habla de unos posibles testigos a los cuales no identifica. Tanto ella como yo entendemos que no hay que remitir más documentación al defensor del pueblo, si no una breve respuesta remitiéndonos a lo ya remitido. Me insiste que lo que piden ya lo pidió ella y se lo denegaron, ya que solicitó la libertad provisional y su atención en centro, pero se lo denegó el juzgado. Por otro lado el informe forense (que os adjunto) y los informes psiquiatricos históricos, unidos al hecho que ya en 2015 se decidió su traslado del psiquiatrico del Centro Penitenciario de Sevilla al Centro Penitenciario de Cáceres y que en 2017 se intentó por el Sepad (y se negó la familia) a buscarle un centro adecuado….todo ello por cierto recogido en mi 2º escrito al Defensor del Pueblo. En definitiva hemos quedado en que no se debe dar información al hermano de ningún tipo y que la semana que viene hablamos de pasos a seguir, para lo cual me ha pedido que solicite a la parte social que averigue lo siguiente: Ana-por favor averigua: 1) si en la cárcel está bajo tratamiento de psiquiatría, y todo lo que puedas averiguar: incidencias, cambio de medicación, como evoluciona, etc 2) Si con el perfil de Saturnino existe algún tipo de centro específico (porque ella propone que podría hacer un escrito llegado el momento indicando que por expresa petición de Saturnino se solicita su traslado al centro…) Con lo que averigues yo la llamaré la semana que viene, pero ya digo, que independientemente de todo esto ella tiene que estudiar el caso ya que dice que hubo varias relaciones de distintas personas (no sabemos consentidas o no) y que tardó 1 semana en decirlo con lo cual todo es dificil de demostrar…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2022-05-26','TERESA Estamos teniendo problemillas con las hermanas de Eugenio No dejan de llamar diciendo que se lo van a llevar, que tienen una habitación preparada para él, que ya lleva mucho tiempo aqui encerrado.... El problema es que también hablan con Eugenio y está provocando problemas de conducta que afectan a su trabajo y a su vida diaria. Les hes explicado por activa y por pasiva que no se lo pueden llevar sin la autorización de sus tutores por mucho que ellas quieran y que Eugenio diga que lo quiere también. Teniendo en cuanta también los antecedentes de su hermano Maxi.... Sería posible que llamáseis a la hermana de Eugenio y le aclaráseis que no se puede ir con ella? La hermana se llama Juana y este es su tf 601 62 41 311 HABLO CON JUANA PARA DARLE LA OPCION QUE EUGENIO PASE ALLI EL FIN DE SEMANA YA QUE ANDA DELICADO DE SALUD Y NECESITA MUCHA ATENCION ELLA SE NIEGA A ESTO Y SE ENFADA, QUIERE QUE VIVA CON ELLA Y AMENAZA CON IR AL JUZGADO 7','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-05-26','miguel, recibo email del director de la Caixa: francisco.rodriguez.t@caixabank.com> Desde el Departamento que gestiona la testamentaría, para completar este expediente nos solicitan que se aporte documentación adicional. Concretamente DOCUMENTO DE ACEPTACIÓN Y REPARTO DE LA HERENCIA. Al tratarse de un incapaz, siguiendo sus indicaciones, les comunico que, según lo previsto en el Código Civil, habría dos posibilidades: 1.- Para aceptar herencias de forma pura y simple (documento privado) se requeriría de autorización judicial. 2.- Si no fuera posible aportar autorización judicial, la aceptación tiene que ser a beneficio de inventario (para lo que siempre se requiere de intervención notarial y, por ello, documento público). **************************************** mi contestación: Buenos días, actualmente se está tramitando a través de del Cid y Villafaina con un abogado la tramitación judicial de la aceptación de herencia. En cuanto la tengamos os la remitiremos. ********************************************** remito email a Inmaculada de DEL CID Y VILLAFAINA: Buenos días Inmaculada, aunque seguimos pendiente tal como me ha explicado hoy el abogado Manuel Andrino de recabar los datos de testamentaria del padre del tutelado para ampliar la petición de aceptación de la herencia. Te adjunto email de debajo en contestación a la Caixa para que una vez que tengamos la resolución de la aceptación de la herencia firme, se la remitamos o bien vosotros o bien nosotros a la Caixa para el desbloqueo y liquidación de la cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2022-05-26','Ana: Paso a Julio, Aux. Advto., oficio-solicitud de Certificado actualizado de la Pensión de Incapacitación Permanente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-05-25','miguel, remitimos por sirex los dos informes que me remite Ana para que se unan al procedimiento solicitado de internamiento involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2022-05-27','Ana: Recibo llamada de Aurora, TS que realiza la sustitución de Montaña, Mancomunidad de Trujillo (927 33 12 94 / mancomunidadaurora@hotmail.com). Contactará con la residencia para consultar precio, otros gastos (podología, peluquería...), así como la situación de Andrés, evolución desde que ingresó en esa residencia, si podría trasladarse en taxi y si cuentan en el centro con algún taxista de confianza para el traslado llegado el momento. ····························· Conversación con Gema Sánchez, Directora de la Residencia de Mayores de Malpartida de Cáceres (670 381 292): El coste de la plaza en su centro es de 1.303,68€/mes. Los gastos de podología y peluquería son de 10€ apróx. cada uno. Estos servicios los usaría meses alternos (cada mes uno de ellos). ···················','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-05-27','miguel, enviamos contestación a la diligencia del jzdo nº4 de Badajoz donde preguntaban la dirección donde está residiendo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-05-27','reunión Soraya, Maite y Miguel: -pedir informes del ESM actualizados -comunicar a la abogada que 6 meses antes de que el juzgado entienda que pueda salir de la carcel para su ingreso en centro adecuado, avisar al SEPAD para preparar su incorporación','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-05-26','Ana: Pilar Cerrillo, Grupo Ciudad Jardín, me remite Informe Psicológico indicando que Martín no reúne requisitos para residir en ese centro y que ya está mejor de los motivos que motivaron su ingreso en plaza T3.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2022-05-27','Ana: envío correo a Pilar Cortijo, Supervisora Res. Santiago Apóstol de Navezuelas (pilarcortcer@gmail.com): "Adjunto solicitud de alta en el Padrón de Habitantes relativo a JUAN JOSÉ HORNERO RODRÍGUEZ, debidamente firmado y sellado por la persona física que ostenta el cargo de curador." ····························································································································································································· Correo de Óscar, secc. ecca. a Pilar Cortijo: "Buenos días Pilar. Resumo la conversación telefónica que hemos tenido: - Cualquier gasto que se pueda abonar mediante factura (farmacia, acompañamiento) nos la enviáis incluyendo el número de cuenta. - Los demás gastos de podología, peluquería y demás que no se puedan justificar documentalmente, los cargáis en la cuenta bancaria trimestralmente y nos enviáis un extracto de gastos firmado para cotejarlo con los cargos bancarios. - Los datos del tutor para la firma del contrato son: JOSÉ VICENTE GRANADO GRANADO, DNI 76015154Q, Avda. de las Américas 4 (06800) Mérida. Tened en cuenta que Juan José gasta más de lo que ingresa, por lo que hay que intentar gastar lo justo para no agotar todos los ahorros."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSE'and edp.apellido1='MOLINA'and apellido2='SALAZAR'),'2022-05-27','TERESA ENVIO OPCION DE PNC A PRESTACIONES BADAJOZ','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-05-27','Ana: Llamo a Mª Antonia (677 407 893 = Nº del piso supervisado): Le comunico que desde la sección económica se ha aceptado la propuesta y a partir del día 1 de junio podrá retirar 400€/mes. ······· Se muestra contenta y agradecida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-05-27','Ana: Correo de Sonia Bernabé- Asindi (trabajosocial@asindi.e.telefonica.net): "Buenos días Ana, quería comunicaros que Aaron Rosado está ingresado en Salud Mental de Cáceres. Tuvo conducta agresiva en la mañana del miércoles y fue derivado. Por lo que nos dice el psiquiatra estará unos días. Ya os iremos informando"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-05-27','Ana: Envío correo a Alberto y Óscar, secc. ecca.: "Buenas tardes a tod@s, En relación a SATURNINO MIGUEL SALGADO, ayer Maite mantuvo una conversación telefónica con él. De nuevo demanda un incremento de la Asignación Mensual, ya se le explicó que no creía que fuera posible en la actualidad, pues aún tiene deudas y en cuenta tiene poco más de 600€ según nos informó Óscar. ¿Sería posible que nos pasaseis extracto de los movimientos bancarios del último año y salto actual para que enviárselos a la TS, para que pueda explicárselo y mostrárselo documentalmente? Él está convencido de que debe tener mucho dinero en cuenta. Además de dicho extracto le recordará todos los últimos gastos que ha asumido Saturnino."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2022-05-27','TERESA SOLITICO AL INSS RESOLUCION INCAPACIDAD LABORAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2022-05-30','Ana: Llamo a Ana, directora de la Res. de Torrecillas de la Tiesa (927 33 80 76): Me informa de que Isabel está muy contenta, se ha adaptado estupendamente y ahora no quiere regresar ya a Jaraicejo, se quiere quedar allí en Torrecillas. ············ En relación a la tarjeta monedero, es ella quien la tiene custodiada, al igual que las claves de la misma. Acudirán a utilizarla por primera vez el día 2 de junio. La oficina bancaria finalmente permanecerá abierta también todo el mes de junio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-05-30','Ana: Envío correo-e a Alberto, con copia a Maite y Óscar, CTAEX: "Por otra parte, una vez visto los movimientos bancarios, compruebo que le siguen pasando los suministros. No sé si se llegó a solicitar la baja de los mismos (Alberto, este tema ya lo habíamos tratado, si no recuerdo mal), pero si no se ha hecho hay que hacerlo y en caso de haberlo pedido, reiterar la petición, pues no hay previsión de que vaya a salir pronto de Prisión y dada su situación económica, entiendo que es mejor dejar de abonarlos." ·························································································································································································································································· Ana: Envío correo a Maite, TS C. Penitenciario (trabajosocialcpcaceres@dgip.mir.es): "Buenos días Maite, En relación a Saturnino Miguel Salgado Jiménez, queríamos facilitarte información documental y por escrito, sobre su situación económica, con objeto de que, si es posible, puedas facilitárselo y explicarle aquello que de entrada no entienda. Gracias de antemano. El jueves pasado Maite, Jefa de Sección, estuvo hablando con él, yo estaba presente. Ante su demanda de aumento de la asignación, le estuvo explicando que difícilmente se le podrá aprobar, pero que igualmente lo trataría con la sección económica. Le explicó que tenía poco saldo y que aún tiene deudas pendientes. Él insistía en que debe tener mucho dinero en cuenta, pero la realidad es que el saldo actual de su cuenta es 687,04 €. Se adjunta extracto de movimientos del último año. Por otra parte, todavía debe: - 3.000€ del cobro indebido de Dependencia (De la vinculada al servicio que no llegó a percibir) - 2.094,40 € de 16 multas de tráfico (se adjunta respuesta del OAR). - Recientemente la Agencia tributaria le ha pasado también un embargo de 195,73 €. Y seguramente habrá más deudas desconocidas de la Agencia Tributaria, pero ésta aún no nos ha contestado a los escritos enviados en relación a los embargos. Hay que recordarle también, que en la medida de lo posible se ha atendido a sus demandas y que las cuestiones realmente necesarias también se han asumido: tratamiento dental y gafas, entre otras cuestiones. Si vuelve a llamar el próximo jueves, se le volverá atender y a explicar todo de nuevo, si fuera preciso, pero creemos que será de ayuda el que le puedas mostrar los documentos adjuntos y explicar el resto de información detallado en el correo. Ante cualquier cuestión, no dudes en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='SOLE'and apellido2='LATORRE'),'2022-05-30','Ana: Recibo llamada de Rosi, de la compañía de seguros Santa Lucía de Blanes, Girona (972 358 855), localidad en la que antes residía Adela. Nos remitirá por mail al ctutelar@ y por correo postal: Cdo. de Defunción y Certificado de Últimas Voluntades para la Rendición Final.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-05-26','Ana: correo de Óscar, secc. ecca.: "Tiene 12.375€ ahorrados. He realizado la simulación en la ficha con el reintegro de 400€ y le sale una diferencia positiva anual de 1.167€, con lo que tendría para algún extra. Si tiene decesos con Generali. Ya está anotado y la póliza escaneada. ALBERTO: si das OK, remito la documentación a Unicaja."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-05-30','miguel, recibo email del abogado Manuel Andrino: Buenos días Miguel. He hablado con la Asesoría “Del Cid y Villafaina” y me dicen no me pueden asegurar que el certificado del Registro de Actos de Última Voluntad y, en su caso, el testamento de D. José Delgado Repilado, nos pueda llegar en esta semana. He preparado un escrito para presentarlo hoy en el Juzgado, solicitando que la autorización se extienda también a la herencia de D. José Delgado Repilado y, asimismo, la suspensión de la comparecencia por estar pendiente de recibirse la documentación. Te envío el escrito, sometiéndolo a tu consideración. No sé qué hará el Juzgado. He pedido que se dé previo traslado al Ministerio Fiscal. Recibe un cordial saludo. Manuel Andrino Delgado Abogado Telf.: (+34) 924 22 90 23 / (+34) 924 25 98 62 Fax: (+34) 924 24 79 04 ************************************************ mi contestación: Buenos días, veo correcto el escrito, únicamente mencionar si lo crees oportuno la necesidad en la resolución lo antes posible del procedimiento debido a que hay una cuenta de la herencia de la madre del tutelado en la Caixa que nos han comentado lo siguiente: “Aún no ha sido posible la cancelación de la cuenta de Doña JOSEFA RODRÍGUEZ RASERO, con adjudicación de su saldo y transferencia a la cuenta indicada del Sr. Delgado Rodríguez, por encontrarnos a la espera de documentación requerida a la Comisión Tutelar de Adultos de Extremadura, concretamente autorización judicial para la aceptación de la herencia, imprescindible para la finalización del expediente de referencia, y de la que, según nos ha informado recientemente, se encuentra en trámite. En cuanto dispongamos de la documentación, atenderemos la solicitud de cancelación y transferencia que nos han hecho llegar, informándoles convenientemente, a fin de que puedan desarrollar de forma correcta la labor que les han encomendado” Quedamos por tanto de la contestación del juzgado a tu escrito. A parte obtenida por Del Cid y Villafaina la documentación de la testamentaria, entiendo que deberán agilizar y remitirnos a ambos la liquidación del impuesto de sucesiones ya prescrito del padre del tutelado. Quedamos a vuestra disposición para lo que necesitéis','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2022-05-27','miguel, recibo nuevo email de Francisco Rodriguez (Caixa Bank): Buenas tardes, Aún no ha sido posible la cancelación de la cuenta de Doña JOSEFA RODRÍGUEZ RASERO, con adjudicación de su saldo y transferencia a la cuenta indicada del Sr. Delgado Rodríguez, por encontrarnos a la espera de documentación requerida al Asesor Jurídico de la Comisión Tutelar de Adultos de Extremadura, Sr. Miguel A. Fernández de Llera, concretamente autorización judicial para la aceptación de la herencia, imprescindible para la finalización del expediente de referencia, y de la que, según nos ha informado recientemente, se encuentra en trámite. En cuanto dispongamos de la documentación, atenderemos la solicitud de cancelación y transferencia que nos han hecho llegar, informándoles convenientemente, a fin de que puedan desarrollar de forma correcta la labor que les han encomendado. Saludos. Francisco Rodríguez Toledano CaixaBank – Subdirector Comercial / Fregenal de la Sierra francisco.rodriguez.t@caixabank.com Móvil: +34 686 335 313 C/ Reyes Huertas, 26.06340 - Fregenal de la Sierra','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2022-05-30','TERESA SE ACUERDA CONTRATAR SERVICIO DE CATERING CON BAR EUROPA 6,5€ AL DIA, EMPEZARA EL DIA 1 MARISA LA TRABAJASORA SOCIAL SABE DE UN CHCIO QEU PUEDE ESTAR INTERESADO EN EL SAD PARA ADOLFO, LE PASARA EL CONTACTO A SUSANA PARA GESTIONARLO Y VALORAR PEDIR LA REACTIVACION DEL EXPEDIENTE SE ANULA TRANFERENCIA PERIODICA A LORENZO, NOS PAASRA POR EMIAL LOS RECIBOS DE LUZ Y AGUA PARA QUE SE LO ABONEMOS SUBIRDA DEL REINTEGRO PARA ADOLFONO A 250€ MES EL HERMANO SE MARCHA A TRABAJAR FUERA Y YA NO PUEDE ATENDER A ADOLFO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2022-05-30','Ana: Remito a Carmen Gía Martín, EVD Plas (carmen.garciamarti@salud-juntaex.es): Aceptación PIA, para Mantenimiento de Servicio: Plaza Discapacidad RAL y C.O. ·················· Se lo envío también a Julio, aux. adtvo. CTAEX, para que le dé registro en SIREX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2022-05-30','-Amalia . Hablo con su hermana , quiere saber si se le puede impedir que se marche fuera de España como es su intención . La remito a la nueva ley . Me dice que esta mal y consumiendo , en febrero estuvo 2 semanas ingresado en la UHB .','2');
