insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-05-25','Buenos días Informar que ayer tarde Emilia volvió a provocar una situación de conflicto y agresión a un compañero del centro. Ambos se encuentran bien . Estamos a la espera de que contacte con nosotros la CTAEX para organizar una salida del centro este fin de semana como consecuencia de su comportamiento. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-05-30','miguel, Ana me remite la información e informes que hay en el expte únicamente a falta de algo que quieran anexar desde el centro (ejemplo denuncias...)En 2 o 3 días lo comunicaremos al juzgado tanto si remiten documentación complementaria como si no...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2022-05-25','-Amalia : ha tenido salida terapeutica de fin de semana en un hostal + 30 €. Me confirma la delegada tutelar que la expareja de Emi de Villanueva , es Miguel Angel , el que fue pareja de Almudena Correyero .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2022-05-30','-Amalia . Hablo con su hermana , quiere saber si se le puede impedir que se marche fuera de España como es su intención . La remito a la nueva ley . Me dice que esta mal y consumiendo , en febrero estuvo 2 semanas ingresado en la UHB .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-05-27','Buenos días Amalia, os informamos que José Vicente Vicente, ha sido trasladado el pasado 27/05/2022; al C.P. Extremera.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2022-05-27','Buenos días Amalia, os informamos que José Vicente Vicente, ha sido trasladado el pasado 27/05/2022; al C.P. Extremera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-05-30','Maite: he hablado con Julia, coordinadora de la Casa de la Misericordia de Alcuéscar para que me dijera cual era el motivo por el que no aceptan José Manuel. Me ha dicho que estuvo anteriormente con ellos y causó muchos problemas ( robaba, intento de sucidio); y que no tienen medios para atenderlo cuando se descompensa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2022-05-30','Maite: desde la policia local de Zalamea nos han dicho que Pablo tiene interés por entrar en el centro Casa de la Misericordia de Alcuéscar. Me he puesto en contacto con ellos, y he enviado por correo electrónico la documentación para que valoren la posibilidad de ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2022-05-30','Ana: Correo de Aurora, TS que realiza la sustitución de Montaña, Mancomunidad de Trujillo (927 33 12 94 / mancomunidadaurora@hotmail.com): "Te remito los datos que me han facilitado sobre Andrés Lancho Sanguino, del municipio de Santa Marta de Magasca. Además, me informa que la tarifa que abona en el centro son: 730 € mensuales por 12 mensualidades." ······························································································································································································· Envío correo a Alberto, jefe secc. ecca, con copia a Maite, Jefa secc. CTAEX: "En relación a ANDRÉS LANCHO SANGUINO, como hemos hablado hace un momento, reside en la Res. de Santa Marta de Magasca. Su deseo, desde antes de aceptar el cargo la CTAEX, era el de ingresar en la Res. de Malpartida de Cáceres (gestionada por NEXUS residencial), para la que hizo la solicitud correspondiente y en la que estaba en lista de espera para plaza privada. *Actualmente le han llamado para ingresar en ésta última. - La tarifa que abona en el centro de Santa Marta: 730 € mensuales por 12 mensualidades. - En la Residencia de Mayores de Malpartida de Cáceres el coste de la plaza es de 1.303,68€/mes. Andrés presenta en la actualidad deterioro cognitivo, pero la valoración que tiene de Dependencia es de Grado I, con lo que no puede acceder ni a plaza pública ni a prestación económica vinculada. *Pero suponemos, que dado el avance de la enfermedad, se podrá solicitar revisión y cuando dé grado II, podrá optar a alguna de las dos opciones mencionadas. Por otra parte, tiene una vivienda en propiedad (titularidad 100%). *Se podría solicitar al Juzgado la venta de la misma si fuera necesario. Otros datos de interés: - Tiene 72 años - Percibe una Pensión de Jubilación de 756,28 € - El documento adjunto nos lo mandan desde la Residencia de Santa Marta, con información económica *Desde la sección social, si es sostenible, al menos hasta que pueda volver a ser valorado por dependencia, consideramos que lo mejor para él sería atender a su deseo y voluntad manifiesta de traslado al centro residencial de Malpartida de CC. Quedamos a la espera del a valoración económica. Pues desconocemos cuánto dinero tiene exactamente en cuenta, si tiene ahorros…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-05-30','TERESA He hablado con Aitor y por suerte estaban allí las chicas del programad de familia, Raquel y María. Aitor me comenta que no tiene dinero, que comen de cáritas y de las vecinas y que cáritas le has dicho que como tiene pensión no le pueden dar comida. Le digo que no le podemos dar dinero porque lo gasta en consumir, él me dice que confíe en él que solo consume el fin de semana y porque se lo invitan. Me pasa con las compañeras del programa y me confirman que consume a diario, que la situación es crítica pues solo les queda comida para hoy. Acuerdo con las compañeras hablar con una tienda para que compren la comida y nosotros paguemos a la tienda. Desde el programa de familia les acompañaran para hacer la compra de manera semanal con el límite que me indique Alberto. Me insisten que tenemos que hacer algo, les comento que hemos enviado múltiples comunicaciones al juzgado y estamos a la espera de respuesta, que de momento vamos a cubrir sus necesidades con el acuerdo de la tienda. Les planteo la opción de ir a tratamiento al ECA (CEDEX) y me dice que el inconveniente es el desplazamiento y que no tienen claro que Aitor esté dispuesto a ir. Mañana contacto con la tienda les he dicho que vayan y hagan una compara con lo básico como máximo de 50€ hasta que Alberto me indique cantidades.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2022-05-30','Ana: Llamada de Rosa, Serv. Protección Menores de SS.TT.- CC (64851): plantea que Juanjo sigue en el CAM de Trujillo, pero que ya ha cumplido la mayoría de edad y además la CTAEX tiene ya asumida la tutela. ······························································································································································································ Tal y como habíamos acordado la semana pasada, mediante correos-e, llamo a Felipe, Educador del CAM Fco. Pizarro (nº personal: 620 263 528 // Nº directo del hogar: 61081). En los años anteriores, Juanjo acudió a pasar las vacaciones de verano a casa de su padre. *Para ello se aportaba un dinero a su padre para contribuir con los gastos de manutención. *Felipe preguntará a Juan Pedro, anterior director (ya jubilado) por la cuantía que se le entregaba al padre y nos lo comunicará. *En el CAM consideran que, dado el ambiente actual en el centro, es mejor para él que pase el verano con su padre, que quedarse en el centro. ··· En cuanto a otro tipo de actividades (campamentos, por ejemplo), dicen que no han encontrado nada que se adecúe al perfil de Juanjo. ············· En la casa de Eloy (padre legal, pero no biológico, recalca Felipe, conviven también otras dos hermanas. Eloy siempre se ha implicado mucho con Juanjo. Pero presenta problemas de salud. cobra una pensión) ·················· Por otra parte, Juanjo finalmente ha aprobado la FPB de Administración. ······················· Ante el planteamiento de visita al centro, acordamos que nos enviarán una propuesta de fecha y horario, para que pueda acudir también Eloy. *Mantendremos reunión en el CAM, con Eloy para explicarle todo lo relativo al cargo y a la CTAEX, con Juan José y también con los educadores del hogar de referencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-05-30','miguel, llega email que remito a Amalia y Oscar: Buenos días señor Miguel me alegro de saludarle he pensado y madurado para que se lo comente usted a la parte economica que he decidido que me ayude la comisión una vez que el piso se quede libre que el juicio es el próximo 15 de junio para echar a los inquilinos.una vez que consigamos echar a los inquilinos tengo decidido vender mi piso de Málaga y comprarme un piso aquí en Mérida.problematica no tengo las escrituras del piso y eso rocío la abogada que tengo en malaga en el registro de la propiedad se puede pedir copia simple de la escritura porque el piso lo tengo yo como herencia y he decidido estar cerca de la comisión y vender definitivamente mi piso de Málaga y comprarme un piso en Mérida para el día de mañana cuando quiera irme unos días fuera del centro tengo mi piso aquí en Mérida.comuniquelo por favor a la comisión porque es una idea interesante porque yo mi vida ya la voy ha hacer aquí en Mérida.buen domingo espero su contestacion *********************************************** contestación de Amalia: Buenas , según la nueva ley podría venderlo . Desde la parte social no tengo nada que objetar es curatela económica .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2022-05-30','Ana: Estrella Durán, TS CSS-Plas, nos comunica que ya ha dado NEGATIVO en COVID.','2');
