insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-05-27','Ana: Correo de Sonia Bernabé - Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, adjunto te remito la previsión de los viajes a casa de los hermanos Roberto y Justo. Digo previsión porque estamos organizando viaje de vacaciones y aún no están las fechas cerradas entonces las adaptaremos en función de estos viajes. Partimos inicialmente con estas fechas." ·················· En principio irán a casa: Del 10 - 12 de junio. / Del 15 - 17 de julio / Del 12 - 17 agosto. ······· Guardo el documento en el expdte. digital. ······················· *Se lo reenvío a Belén, TS Secc. RR. Discapacidad - UPPA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-05-27','Ana: Correo de Sonia Bernabé - Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, adjunto te remito la previsión de los viajes a casa de los hermanos Roberto y Justo. Digo previsión porque estamos organizando viaje de vacaciones y aún no están las fechas cerradas entonces las adaptaremos en función de estos viajes. Partimos inicialmente con estas fechas."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-05-27','Ana: Correo de Sonia Bernabé - Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, adjunto te remito la previsión de los viajes a casa de los hermanos Roberto y Justo. Digo previsión porque estamos organizando viaje de vacaciones y aún no están las fechas cerradas entonces las adaptaremos en función de estos viajes. Partimos inicialmente con estas fechas." ··············· En principio irán a casa: Del 10 - 12 de junio. / Del 15 - 17 de julio / Del 12 - 17 agosto. ······· Guardo el documento en el expdte. digital. ···················· *Se lo reenvío a Belén, TS Secc. RR. Discapacidad - UPPA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2022-05-31','Ana: Llamo a Felisi (624 856 746): coge el teléfono Jesús. Después pone el manos libre. Confirman que la tarjeta monedero la tiene ella. Le comunico que hoy le harán la recarga quincenal. Había quedado mañana con la Ed. del programa de familia para ir al banco. Jesús intenta convencer para ir él con ella a sacarlo. *Le explico, que dada la situación, es mejor que acuda con las compañeras del programa de familia, para que puedan continuar con el seguimiento y poder completar sus informes. *Aitor sigue en su casa con la novia y Felisi está disgustada por ello. *Han ido varias veces a dar una vuelta a la casa y les han llevado comida. Dicen que tienen la casa patas arriba y la cocina llena de aceite y salpicaduras por todo sitios. ··· Quieren que se vayan de la casa. *Les vuelvo a explicar que ya se ha comunicado todo al Juzgado y mientras el juez no se pronuncie no podemos hacer nada. Ni podemos obligarle a volver al centro ni a abandonar la casa, pues al fin y al cabo está en casa de su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2022-05-31','Ana: Llamo a Pilar, TS ESM - CC (54612), en relación al correo que envió: "Hola Ana, te informo que la Comisión aprueba la solicitud de CRR, pero en vez de por emergencia social, le pondrán en lista ordinaria. (Supongo que al solicitar solo uno de los destinos). Creo que podemos plantear al paciente solicitar todos los destinos, o ver la posibilidad de revisión de grado. Ya me dices.": Descartamos la opción de solicitar revisión de grado de dependencia, pues no va a dar más grado. *En cuanto a la ampliación de centros en la solicitud, pediré que trabajen este asunto con él desde el Programa de Apoyo Comunitario (Futuex), pues él a día de hoy se niega, sólo acepta ingresar en el de CC. ·········· De momento tendrá que seguir en el domicilio familiar, aunque la relación con la madre no sea buena. ···························· Envío correo a Toni-Futuex: "En relación a Doroteo Díaz Cerro, como sabéis, sólo acepta ingreso en el CRR de Cáceres. Dadas las malas relaciones y las dificultades en la convivencia con su madre, ¿podríais trabajar desde el programa de apoyo comunitario con él para concienciarle de la situación (cada vez más insostenible) y que aceptase ampliar la solicitud a todos los centros? Poniendo sólo un centro no puede optar por Emergencia Social, por lo que va a lista general, y en tal caso el ingreso puede tardar muchísimos en producirse."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-05-31','Ana: Llamo a Pilar, TS ESM - CC (54612): solicito que, cuando pueda, me corrobore si a Saturnino se le está haciendo seguimiento desde el ESM y, en tal caso, que nos diga que facultativo lo realiza. *Consultará en JARA y me enviará un correo. ····························· Envío FAX al Servicio Médico del Centro Penitenciario (Tlf. 927 18 10 52 // Fax: 927 18 11 50) solicitando nos remitan Informes de Psiquiatría relativos a todas las consultas y seguimiento realizado desde que ingresara en el C.P.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-05-30','miguel, recibimos email de la notaria de Brihuega: Buenos Días. Hemos recibido en la notaria de Brihuega, solicitud de testamentos por fallecimiento de DON MAXIMO GIL GARCÍA Y DOÑA TERESA SANZ CARRASCOSA, cuyos hijos Sergio y Raúl Gil Sanz, están bajo la tutela de la Junta de Extremadura, revisando la documentación les comunicamos que la forma de proceder para identificar al representante de la Junta, es necesario lo haga en está notaria en presencia o bien por medio de una notaria de su zona, solicitando por media de está dicho testamentos. Para cualquier aclaración seguimos en contacto. ********************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-05-31','miguel, mi contestación a la notaria de Brihuega: Buenos días, conforme al email que nos remitieron indicando que la petición de los testamentos abiertos de los padres de los tutelados Gil Sanz, Sergio y Raúl debía ser solicitado en la notaria, entendemos que no es necesario, ya que queda perfectamente acreditado la autenticidad del representante con el acuerdo con firma electrónica que se adjunta, junto con la documentación que acredita su nombramiento y acreditación. Asimismo se adjuntan los testimonios de incapacitación y nombramiento a la Comisión Tutelar de Adultos. Entendemos que esta documentación unida a la ya remitida son suficientes para acreditar dicha legitimación para poder continuar los trámites de herencias de los padres de los tutelados. Una vez las tengan preparadas avisenos para su abono pero no nos las remitan ya que intentaremos que su tía Amelia pase por allí a retirarlas o no, ya que habrá de preparar la adjudicación de herencia. ***************************************** Reenvío dicho email a Amelia para que también esté pendiente... Buenos días Amelia, la notaria de Brihuega nos requiere que acreditar la petición de los testamentos por el representante de la Comisión Tutelar. Esta misma mañana como verás en el email de debajo les he enviado este email para acreditar la representación del representante de la Comisión Tutelar (que es el actual gerente del SEPAD de la Junta, es decir un político y por tanto no es tan fácil como pedía la notaria de Brihuega de ir a una notaría de aquí para solicitar dichos testamentos, además del importe que supone pedirlos...)Es por ello que le he remitido la documentación que debajo menciono y que acredita tanto la identidad del representante de la Comisión Tutelar como la legitimación para solicitar dichos testamentos en base a los testimonios de nombramiento del cargo de tutor por sentencias judiciales que también les remití y he vuelto a remitir por esta vía. Recuerda que ya les envié a la notaria originales y fotocopias de todo(pago de impuestos, testamentaria (certificados de defunción y últimas voluntades de los padres), etc. Te envío este email para que por favor hables con ellos y estés pendiente en el momento de que lo emitan para retirar toda la documentación de la notaria. Desde aquí haremos el abono de la factura. Pero es conveniente que tú te quedes toda la documentación porque el trámite siguiente será que la dejes en una notaria (no sé si podrá ser la de la misma Brihuega) para que prepararen la aceptación y adjudicación de herencia. Una vez que la notaria haga el borrador de dicha aceptación y adjudicación de herencia, desde aquí habrá que buscar un abogado de allí (donde fallecieron los padres) para solicitar vía judicial la aceptación de la herencia, y una vez que nos la concedan, con otro abogado de Extremadura (lugar donde residen tus sobrinos) solicitara al juzgado la aprobación de la herencia. Sin estos requisitos el registro de la propiedad no aceptará la inscripción del cambio de titularidad. Si en este tiempo de trámites encontraras un comprador para los bienes inmuebles que puedan corresponder a tus sobrinos, en ese caso necesitaríamos una tasación que puede emitir incluso una inmobiliaria (no es obligatorio que sea un perito). Y con dicha tasación el abogado (de la aceptación de herencia)podría intentar simultáneamente pedir la autorización judicial de venta. Pero por ahora lo único que te pido es que estes en contacto con la notaria de Brihuega para asegurarnos que te entregan copia autorizada de los testamentos abiertos de los padres. Cualquier duda no dudes en llamarme. Gracias, saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2022-05-31','TERESA HABLO CON ISABEL PROPIETARIA COVIRARN PARA ESTABLER ACUERDO DE COMPRA DE ALIMENTOS PARA AITOR SIEMPRE QUE VAYA ACOMPAÑADO DE LAS TECNICOS DEL PROGRAMA DE FAMILIA VANA A HACER UNA COMPRA INICIAL Y LUEGO SE HARA COMPRA SEMANA EN FUNCION A PRESUPUESTO SEMANAL QUE MARQUE ALBERTO SE LE PAGARA A LA TEINDA MEDIENTA TRANSFERENCIA UNA VEZ RECIBA EL TIKET DE COMPRA A TRAVES DEL PROGRAMA DE FAMILIA TELFN ISABEL COVIRAN: 646098000 N CUENTA: ES 97 2048 1239 4730 0002 2281 M ISABEL ALNCANTARA MORENO TLFNO PAF: MARIA Y RAQUEL 609382439 TLFNO AITOR: 641362231','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2022-05-30','miguel, recibimos email de la notaria de Brihuega: Buenos Días. Hemos recibido en la notaria de Brihuega, solicitud de testamentos por fallecimiento de DON MAXIMO GIL GARCÍA Y DOÑA TERESA SANZ CARRASCOSA, cuyos hijos Sergio y Raúl Gil Sanz, están bajo la tutela de la Junta de Extremadura, revisando la documentación les comunicamos que la forma de proceder para identificar al representante de la Junta, es necesario lo haga en está notaria en presencia o bien por medio de una notaria de su zona, solicitando por media de está dicho testamentos. Para cualquier aclaración seguimos en contacto. ********************************','2');
