insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-05-20','Ana: Recibimos del INSS, Cdo. actualizado de Pensión de Jubilación: Líquido 1.183,53 € x 14.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-06-02','-Amalia : registro de entrada en dependencia Caceres : PIA ( prestacion vinculada a servicio residencial ) Modelo alta 3º Contrato original del servicio residencial','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-06-02','-Amalia : registro de entrada en dependencia Caceres : PIA ( prestacion vinculada a servicio residencial ) + Modelo alta 3º+ Contrato original del servicio residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2022-05-20','Ana: Recibimos del INSS, Cdo. actualizado de Pensión de Jubilación: Líquido 1.183,53 € x 14.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2022-05-20','Ana: Recibimos del INSS, Cdo. actualizado de Pensión de Incapacidad Permanente Absoluta. Líquido a percibir: 813,89 € x 14.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-06-02','Ana: Llamada de Maite, TS del C.P. (927 181 407): Ayer a media mañana estuvo reunida con Saturnino explicándole las cuestiones económicas que le remitimos. ············· *Por la tarde, sobre las 17 h, le dieron la LIBERTAD PROVISIONAL, a la espera de que se resuelva el juicio. *Al parecer se fue sin su medicación y sin los informes. * ······························································································································································································ Llamo a Carmen Sánchez, TS del Centro de personas sin hogar de Caritas (607 680 553 / 927 23 50 82 / mcsanchez.cdcoriacaceres@caritas.es): Me comunican que Carmen tiene reunión toda la mañana, sobre las 14 quizá haya terminado. Pregunto igualmente a la persona que me atiende y confirma que NO HAY NINGUNA PLAZA DISPONIBLE EN EL CENTRO. ··············· Llamo a Saturnino, al nº que nos constaba previo a su ingreso en prisión (671 37 45 84), pero "el número no corresponde a ningún cliente". ··································· Envío correo a Toni-Futex con copia a Maite, indicando todas las gestiones e información obtenida en las últimas horas. *Solicito retomen los seguimientos, lo localicen en el hostal y pregunten allí si está abonando su estancia. Y le pregunten a él si estaría dispuesto a ingresar en el centro de Pinofranqueado. *Guardo correo en el expte. ········ En nueva conversación con Mar, hermana, nos dice que el regreso al piso en que vivía antes, no es viable, entre otros motivos porque lo destrozó cuando estuvo viviendo allí. ··············· En cuanto a si dispone de efectivo: Ayer salió con los 95€ que había en la cuenta peculio y hoy ha retirado 100€ de la cuenta sin autorización.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-06-02','Buenos días , terminado el plan de intervención de esta señora que está en un Centro residencial de Cáceres, tenía pendiente terminar algunas gestiones con dependencia Os indico las gestiones a realizar desde sección eco en el anexo en negrita . Se abona el 85% de la P. jubilación + 50% de las extras. Ya está hecha la solicitud PIA , se ha solicitado prestación vinculada a servicio para pagar la plaza residencial . He solicitado al centro residencial gastos de esta señora y son mínimos , podología y peluquería cuando lo necesita . Os paso TF de la trabajadora social para que cuadréis forma de abono de la plaza . Creo que la cargan en su cuenta . Una vez realizado el Plan inicial , lo derivo a Ana para seguimiento al ser zona de Cáceres. ( Ana , todas las gestiones están ya realizadas . En la intranet puedes leer un breve resumen de su situación . LLeva ingresada 20 años , sin ningún problema ) Plan de intervención inicial : Señora ingresada en la Residencia de mayores de Ciudad Jardín de Cánovas desde hace 26 años . tf. de la residencia 927233221 Desde la sección eco habría que realizar varias gestiones -Tiene una cuenta bancaria con 5773€ de ahorros , donde se ingresa su pensión. Incluir como titular a J. Vicente . -Habría que hacerle un seguro de decesos , aunque creo que ya por la edad no nos van a dejar hacerlo . Tiene 85 años. Si bien , tiene un nicho en propiedad. -Tiene una pensión de jubilación de 689,70€ más 2 pagas . Abona el 85% de la pensión + 50€ de las extras como pago de la plaza residencial . Pendiente de recibir listado con los gastos personales de la residencia . Estoy pendiente de cambiar su PIA y pedir plaza residencial . La Tecnico PIA es Ana Isabel Teomiro . Le he escrito para que me envie el PIA . Un saludo .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SANCHEZ'and apellido2='DIAZ'),'2022-06-02','Buenos días , terminado el plan de intervención de esta señora que está en un Centro residencial de Cáceres, tenía pendiente terminar algunas gestiones con dependencia Os indico las gestiones a realizar desde sección eco en el anexo en negrita . Se abona el 85% de la P. jubilación + 50% de las extras. Ya está hecha la solicitud PIA , se ha solicitado prestación vinculada a servicio para pagar la plaza residencial . He solicitado al centro residencial gastos de esta señora y son mínimos , podología y peluquería cuando lo necesita . Os paso TF de la trabajadora social para que cuadréis forma de abono de la plaza . Creo que la cargan en su cuenta . Una vez realizado el Plan inicial , lo derivo a Ana para seguimiento al ser zona de Cáceres. ( Ana , todas las gestiones están ya realizadas . En la intranet puedes leer un breve resumen de su situación . LLeva ingresada 20 años , sin ningún problema ) Plan de intervención inicial : Señora ingresada en la Residencia de mayores de Ciudad Jardín de Cánovas desde hace 26 años . tf. de la residencia 927233221 Desde la sección eco habría que realizar varias gestiones -Tiene una cuenta bancaria con 5773€ de ahorros , donde se ingresa su pensión. Incluir como titular a J. Vicente . -Habría que hacerle un seguro de decesos , aunque creo que ya por la edad no nos van a dejar hacerlo . Tiene 85 años. Si bien , tiene un nicho en propiedad. -Tiene una pensión de jubilación de 689,70€ más 2 pagas . Abona el 85% de la pensión + 50€ de las extras como pago de la plaza residencial . Pendiente de recibir listado con los gastos personales de la residencia . Estoy pendiente de cambiar su PIA y pedir plaza residencial . La Tecnico PIA es Ana Isabel Teomiro . Le he escrito para que me envie el PIA . Un saludo .','2');
