insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='BARRIGA'and apellido2='CARNERERO'),'2022-06-02','Buenas , acabo de hablar con la residencia , no tiene apenas gastos , prefieren pedir un extra cada 6 meses y administrárselo . Asi que por ahora , no se hace nada más con las cuentas. Gracias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='GONZALEZ'and apellido2='BERNALDEZ'),'2022-06-02','ARCHIVO EXPTE. Por St. 60/22, de 30 de marzo (firme según DIOR de 26/05/22), dicta por el Jzdo. de 1ª inst. e inst. n.º 1 de Zafra, se nombra Curador Asistencial a D. José María Parra Sánchez. Se procede al archivo del expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2022-06-02','-Amalia : cuando esté listo el nuevo Nº cuenta bancaria , haré cambio de PNC y comunico a anamarta.fernandez@salud-juntaex.es del CAMP de Plasencia el cambio. Una vez terminadas estas gestiones derivo el caso para seguimiento a Ana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2022-06-02','-Amalia: nació en 2001 , tiene 21 años , en clases pasivas la P. orfandad es hasta los 25 años , incompatible con trabajo remunerado . Desconozco si seguirá después al tener 65 G. Discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SIXTO NICANOR'and edp.apellido1='ALMODOVAR'and apellido2='JIMENEZ'),'2022-06-02','-LLama la hna( tf . Consolacion 656812683 para que le paguemos la lápida , lo ha enterrado con su padre y la lapida que tenian se ha roto. No tenia seguro decesos . No se abona nada despues de fallecido , que lo abone de la herencia.','2');
