insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2022-06-02','miguel, asisto al juicio y nos adherimos al acuerdo que establece el Ministerio Fiscal que será condenatoria para el hermano y la cuñada (extutora) de multa de 3000€ y carcel 1 año, ya que resulta complicado el cálculo de cuánto dinero quitaron al tutelado. Se advierte también al Ministerio Fiscal por Teresa que el tutelado está autorizado a visitar a su sobrina en Mérida los fines de seman y que ésta ha pedido la Remoción del cargo y estamos pendientes de recibir informe social para oponernos porque entendemos que detrás hay un interés económico','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2022-06-02','miguel, ratifico la escritura de venta ante el notario D. Gonzalo Fernández Puignaire con protocolo nº 848, y lo comunico por email a la notaria de Plasencia a donde llegará telemáticamente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2022-06-03','Ana: Raquel, Enfermera Secc. Salud Mental, nos trae la RESOLUCIÓN de BAJA en el CRR, por ALTA TERAPÉUTICA (cumplimiento de objetivos). ··········· Guardo en el expte. físico y digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-06-03','Ana: Envío nuevo mail a Toni - Futuex: "En relación, de nuevo, a SATURNINO MIGUEL SALGADO JIMÉNEZ, nos comunican desde el C. Penitenciario, que las gafas graduadas que se le hicieron, no habían llegado a llevarlas al Centro. Ya están pagadas. Os solicitamos que cuando sea posible, acompañéis a SATURNINO a recogerlas a la óptica BLUE ÓPTICA, C/ San Pedro de Alcántara, 2. Tlf. 927 28 86 61." ········································································ Conversación con Mar, hermana de Saturnino (690 67 12 04): Su hermano ha aceptado muy convencido el ingreso en el Casa de la Misericordia de Pinofranqueado. ··········· Además Saturnino ha llegado a casa de su madre con una tarjeta de teléfono (636 154 711) y le han dado un terminal libre que tenían de su madre, por lo que ya estará de nuevo localizable. ····································································· Envío correo-e a Fernándo Pecero, Casa de la Misericordia de Pinofranqueado (aromasdecaridad@hotmail.com): "... Queríamos haceros la propuesta de derivación de un chico que recientemente, el miércoles por la tarde para ser exactos, ha salido de prisión (ingresó el pasado mes de diciembre en régimen de Prisión Provisional) con LIBERTAD PROVISIONAL, y de lo cuál no nos habían comunicado nada ni a la abogada que lleva su caso, ni al Gabinete Técnicos de la Comisión Tutelar ni a la propia Trabajadora Social del C. Penitenciario, que le atendió esa misma mañana sin saber que por la tarde saldría del centro. A parte de que no nos han dado tiempo para gestionar nada, a priori este chico no da perfil para Recursos de Salud Mental ni para ningún otro. Además su situación económica es complicada, no por las pensiones que percibe (Pensión Simple de Orfandad y Prestación Familiar por Hijo a Cargo), si no por la cantidad de deudas que tiene acumuladas, más de 20 por multas de tráfico, entre otras que aún no nos han aclarado desde la Agencia Tributaria. Tampoco puede quedarse en casa de ningún familiar y en el Albergue de Personas sin hogar de Cáritas tampoco hay plazas. Te remito informes de Salud Mental así como certificados actualizados de sus pensiones. *De momento se está alojando en un hostal, pero no puede permitírselo mucho más tiempo. *Él acepta el ingreso en vuestro recurso. Sus datos son: SATURNINO MIGUEL SALGADO JIMÉNEZ, 49 AÑOS. Fecha de nacimiento: 12/11/1973 Si necesitáis alguna otra información, házmelo saber. Gracias de antemano y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2022-06-02','Ana: correo de Lourdes, secc. ecca., a Alberto, jefe secc., con copia a mí: "Tras conversación mantenida con Cristina, te envío los detalles de sus gastos ANTONIA BRAVO PATILLA (60años) Tiene una asignación semanal de 15€. Sale al pueblo en Navidad, Semana Santa y Verano, y se le da al hermano 100€ para el viaje Ahora por castigo le han reducido la asignación a 3€ por que come a escondidas dulces. De farmacia, solo paga 4€ Alguna vez se solicita dinero para ropa, pero en contadas ocasiones Tiene pensión 220,70€+417,70€. Puede solicitar el complemento de 3ª persona porque reúne los requisitos, serían 208,90€, lo que veo es que el centro se sigue quedando con 75%..." *De este complemento a ella le quedarían para sus gastos otros 50 €/mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2022-06-03','Ana: Dado que tiene reconocido 84% de discapacidad por el CADEX, le han reconocido Grado I de Dependencia y su situación económica lo precisa, cumplimento y pongo para REGISTRO DE ENTRADA la Comunicación de Variaciones de PFHC, solicitando le concedan el complemento ATP. *Adjunto resolución de Grado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='SERRANO'and apellido2='TRANCON'),'2022-06-03','Ana: Acuerdo de la Secc. Ecca.: Aunque Agustín tiene reconocido 79% de Discapacidad y Grado II de Dependencia, no se le solicitará el Complemento a Tercera Persona, por no necesitarlo. Actualmente tiene en cuenta 108.896,39 €. ··········· Si en el futuro fuera necesario se le podría solicitar. ····················· Lo comunico a Cristina, Ed. Social Asoc. Vera (681 14 39 11).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2022-06-02','Ana: correo de Lourdes, secc. ecca., a Alberto, jefe, con copia a mí: "Tiene una asignación semanal de 20€ Podólogo mensual 7€ Peluquería 32€ cada dos/tres meses, normalmente lo paga de su asignación, salvo en estos últimos 4 meses en los que la educadora social, ha estado de baja. Tiene problemas con diabetes, que de momento toma pastillas, pero el problemas es que cuando sale se atiborra de chucherías y encima está engordando. El gasto más importante lo tiene cuando va al pueblo (HOYOS) en verano con su pareja, porque no se lleva bien con su madre y entonces se va a un hotel, donde gasta unos 500€. También indican que en enero se compró un televisor"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-06-03','miguel, hablo telefónicamente con la abogada Carmen Lucas quien me comenta que nadie le ha notificado el motivo por el que etá en la calle. Que no logra hablar con el juzgado por teléfono. Que se entero por la hermana del tutelado quien estaba aterrorizada con la salida de Saturnino. La abogada está intranquila pues comenta que no quiere recibir en el despacho a Saturnino y le da miedo. Ha presentado un escrito al colegio de abogados solicitando la baja por motivos de conciencia y que la sustituya alguien en la cita del día 8-6-22, al tiempo que solicita al colegio que en caso de que se le obligue a citarse con el tutelado sea en presencia de la junta de gobierno del colegio y asistida por un psicólogo ya que comenta que Saturnino no se toma la medicación y sólo dice incongruencias. También le comento cuáles serán los pasos a seguir por la Comisión que son comnuicación al juzgado al que rendimos cuentas, escrito al defencosr del pueblo contestando el 3º escrito, y fax a la carcel y al jzdo nº6 de Cácres para que nos faciliten el documento y motivo por el que está en la calle el tutealdo. Me indica que si queremos solicitar el internamiento involuntario se lo tenemos que solicitar a ella por escrito para que lo presente. Reenvío toda esta conversación para su conocimiento a Soraya, Maite y Ana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2022-06-03','Ana: Pongo para la firma todos los documentos que nos remiten del CAMF para el viaje a Lourdes del 30 de junio al 5 de julio. *Como en años anteriores, se autoriza.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2022-06-03','Ana: Pongo para la firma todos los documentos que nos remiten del CAMF para el viaje a Lourdes del 30 de junio al 5 de julio. *Como en años anteriores, se autoriza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2022-06-03','miguel, Amalia me remite email de la sobrina Cristina: Buenos días Amalia! Por favor cogerme el teléfono llevo 6 meses esperando a traerme a mi tío a Badajoz, no me has contestado ni por email ni atendeis por teléfono. O llamame al 677773233 ********************************************* contesto a Amalia y Maite: Buenos días, cualquier tipo de petición que haga un familiar, como es esta remitidles con el número de procedimiento de tutela/curatela al juzgado y que lo soliciten allí directamente. Una vez que el juzgado nos requiera deberéis aportar algún informe social dando el visto bueno o no de la Comisión Tutelar de Adultos. ******************************************* email Amalia: Buenos días , habréis visto el correo de la sobrina de Pedro. Miguel , lo ibas a mandar al juzgado , se hizo ?? hay respuesta ?? Esta chica ya se dirigió a Juzgado para sacarlo de la residencia de Gata y el juzgado nos instó a que en 72h teníamos que facilitar la salida . Un saludo ************************************************ email de Amalia: buenos días Miguel , sería posible hacer la consulta directamente al juzgado o al Fiscal ? Te hago un breve resumen de la trayectoria de Pedro y creo que velando por su integridad física y mental , su salud y su economía es necesario abordar el caso desde los juzgados. Pedro Sudón es curatela , con una patología de salud mental y consumo de alcohol crónico. Hace años después de años viviendo en la calle aceptó un ingreso voluntario en R.M. de la Granadilla en Badajoz . De ella salía a su antojo para consumir alcohol y regresaba en malas condiciones , llamando él directamente al 112 utilizando el servicio de ambulancia como taxi. Fue trasladado al ser expulsado de esa residencia a otra en Gata. Allí se adaptó perfectamente , era un pueblo muy pequeño donde no tenía acceso al alcohol. Hasta que su sobrina Cristina y su hermano Antonio ( que reside en Alemania y con el que no tiene contacto hace años ) escribieron al juzgado para decir que Pedro quería salir de la residencia ( Pedro directamente a nosotros ni a la dirección del centro no lo solicitó ) y que la Comisión se lo prohibía, cosa totalmente incierta. Se hicieron informes al juzgado explicando la trayectoria de Pedro , su situación sociosanitaria había mejorado y las consecuencias que tendría esa salida .Motivada por tema económico , la sobrina quería administrar su pensión . El juzgado no lo admitió e instó para que Pedro saliera de esa residencia . Se trasladó a casa de la sobrina y a los pocos meses como no era capaz de atenderlo , presionada por denuncias vecinales , su consumo de alcohol y pedir por las calles le buscó un apartamento. Toda su motivación era económica , llegó a pedir autorización para comprarse un coche con el dinero de Pedro . Cuando vió que no tenía acceso a sus cuentas solicitó remoción del cargo , puedes ver el informe que se hizo desde esta Comisión en contra del mismo y el juzgado se lo denegó. Durante el tiempo que estuvo en ese apartamento , estuvo desatendido , alcoholizado , pidiendo por las calles , con múltiples denuncias vecinales . Llegó a atascar el cuarto de baño en varias ocasiones , al que introducía ropa y objetos . Y tuvieron que desatascar con empresas especializadas y muy costosas. La sobrina agobiada por la situación y viendo que económicamente no había tenido el efecto esperado , en una de sus descompensaciones lo llevó al hospital y desde allí nos exigió que nos hiciéramos cargo de él y lo volviéramos a llevar a una residencia. Al ser curatela económica , se le instó a que fuese ella quien le ayudara a solicitarla y lo ingresó en Residencia de Caser de Olivenza. Fue expulsado de esta residencia privada por robos tanto a personal del centro como a residentes , robaba el vino para uso culinario de la cocina y se lo bebía. .. Se quedó en la calle de nuevo y su sobrina lo ingresó en la Residencia Los Olivos de Mérida donde residía un hermano ,al principio en plaza privada . Al agotarse todos sus ahorros , para que no se viera en la calle y de forma voluntaria a permanecer en esa residencia , desde la Comisión se hacen gestiones para solicitar plaza pública por emergencia social y se le concede. Lleva meses allí , los dos primeros meses los llevó mal pero actualmente bastante adaptado y desde la residencia no nos han comunicado incidencias ( el primer mes necesitó de ingreso en psiquiatría por desconpensación y agresión a personal del centro) . Su sobrina vuelve a solicitar que su tío salga del centro , cosa que desde la Comisión no se le prohíbe en ningún momento . Ha mandado unas fotos en las que según ella su tío firma un documento que ha elaborado ella en el que muestra su deseo de salir . Quiere alquilarle un piso en Cerro Gordo , un barrio alejado de donde vive ella y entre sus razones están que le supone mucho esfuerzo ir a verlo algunos domingos por la distancia que existe a Mérida. Desde esta Comisión ya se informó al juzgado anualmente de las consecuencias que tuvo el que saliera la última vez. Y es muy probable que se repita todo lo anterior . No consideramos que su sobrina pueda atenderlo de forma correcta , igual que no fue capaz de hacerlo la otra vez , además de sus propias responsabilidades familiares , tiene tres hijos pequeños y trabaja en una peluquería mañana y tarde. Por otro lado , una cuñada de Pedro se personó en las oficinas para solicitar que quería que Pedro viviese con ellos en su casa y ella administraría su pensión . Toda la familia estaba desempleada y no tenían recursos económicos. Ante esta situación, creo que es necesario que sea el juzgado el que se pronuncie al respecto y que valoren si Pedro tiene capacidad de decidir libremente dónde quiere residir y si tiene capacidad y aptitud para mantener una vida aútonoma viviendo sólo en un piso. . Desde la Comisión ni se le ingresó en la residencia actual ni se le prohíbe que se marche. Creo que lo que la sobrina busca es alguna autorización de esa salida , sabe que puede irse cuando quiera , para justificarse ante el resto de los miembros de la familia y por si ocurre algo que pueda volver a solicitarnos una residencia y eximir su responsabilidad . Un saludo ************************************************* mi contestación: A ver, Hablamos si quereis pero en mi opinión es que si lo solicita la sobrina y el juzgado le da la razón que me mande la autorización judicial, o bien si queda acreditada la voluntad del curatelado (no tutelado…). Si aun así preferís comunicación judicial pues envíame un informe y hago un oficio para enviar al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-06-06','Ana: Aarón tiene cita para RECONOCIMIENTO DEL MÉDICO FORENSE el día 13 de junio. ········ Ese mismo día tiene cita con la Psiquiatra de Salud Mental para seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2022-06-06','miguel, llaman del Centro de Mayores de Azuaga de este tutelado indicando que le ha citado el forense para revisión de sentencia que creen que ha solicitado él. Le pido que envíe a email de ctutelar la citación para ponernos en contacto con el juzgado y personarnos como parte interesada','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-06-06','miguel, envío email a Ana, Maite y Soraya, en contestación a la indicación de Soraya de incluir al escrito de comunicación al jzdo nº2 de Cáceres (el que ostenta la tutela). Mientras que el jzdo nº6 de Cáceres es donde está el procedimiento penal de agresión sexual: Buenos días, os adjunto los fax remitidos el viernes donde pedía tanto al jzdo nº6 que es el que está conociendo del supuesto delito y al centro penitenciario que nos justifiquen el motivo por el que Saturnino está en la calle. Al tiempo le indiqué al jzdo nº6 (que es el que corresponde por estar conociendo la causa) que de oficio autoricen el ingreso de Saturnino en centro adecuado…(esto es una medida alternativa como sabéis a la cárcel, que debe ser dictada por el jzdo que está conociendo el procedimiento). Este jzdo nº6 de Cáceres es distinto del jzdo nº2 de Cáceres que es el que corresponde a su tutelada (donde hacemos las comunicaciones como la que he hecho, las rendiciones de cuenta anual, etc) Lo lógico es que desde el Jzdo nº6 de Cáceres nos digan que la solicitud de internamiento involuntario tenemos que hacerlo através de nuestro abogado, y si bien la nuestra, Carmen Lucas, ha solicitado su renuncia al caso en el Colegio de Abogados, hasta que no nombren a otro ella seguirá siendo la abogada de Saturnino… Esperemos que a lo largo de la mañana nos contesten sobre el motivo por el que está en la calle. Preparo el borrador de contestación al defensor del pueblo y de petición a la abogada para un internamiento involuntario para que lo veáis y modifiquéis y a ver si hoy podemos tener este tema cerrado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSE'and edp.apellido1='FRAGUAS'and apellido2='CARPINTERO'),'2022-06-06','miguel, llega email del hijo de la tutelada fraguasvidal@hotmail.com> : Buenas Tardes: Se cumple ahora un año desde que les envié toda esta información cómo me indicaron ustedes referente a su tutelada MARÍA JOSÉ FRAGUAS CARPINTERO. No he recibido ninguna respuesta por su parte, ni una solicitud de aceptación de herencia ni nada de nada. Necesito que realicen esa gestión para remitirles el dinero que Manuel tenía en su cuenta y que corresponde a María José cómo heredera, así cómo para poder inscribir en el registro de la propiedad el piso de mis abuelos, dónde Manuel residía, y que pertenece en un porcentaje a María José. Por favor, les ruego se pongan en contacto conmigo y realicen las gestiones oportunas para poder realizar todo lo comentado. ************************************ Lo reenvío a Angel: Buenos días, tú sabes algo de este tema??. He mirado en intranet y no veo nada, pero si veo un email en la carpeta herencia del año pasado en relación a este tema…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-06-06','Re: Miguel Ortiz Gordillo >miguelortizgordillo9@gmail.com> Hola buenas tardes Amalia soy Miguel me pongo en contacto contigo para decirte que el miércoles por la tarde nos agredimos una cuidadora y yo el presidente a mutuamente lo cual actúe de forma violenta tanto ella como yo legajo una broma a la cuidadora no muy pesada o sea la cojo por el brazo sin hacerle daño y me arreba un tortazo con lo cual me salga las terrazas de los cuidados de probar un cigarro y le diga la cuidadora que sea la última vez que me arreaba ese tortazo que la próxima vez me iba al rayó ese tortazo se levantaba cuidadora de los ordenadores y me empieza a zarandear tengo un corazón en el brazo derecho en el muslo del mismo soltero para quitarme de cuidadora de encima cojín pedrusco que tiene felipe en el despacho de los cuidadores y lo iba a lanzar contra la ventana de los cuidadores pero con tal mala suerte que le pegué a ella en la cabeza nos tiramos los dos de los pelos justamente antes de coger la piedra el cuál el gerente el colegio y la la directora del colegio me dicen que por qué he hecho eso le cuento la versión el cual no me cree y por lo visto le he hecho una brecha a la cuidadora en la cabeza le han tenido que dar puntos según segunda la directora del colegio general me ha dicho que tuvo que venir el 111 al colegio a mí no me hicieron nada yo me puse a ver la tele en mi cuarto y me transmite el cual se hablado con el psiquiatra y me ha aumentado la dosis yo estoy echando que vengas a verme al colegio porque estos insostenible y segunda me ha recomendado este fin de semana que me vaya a casa de mi familia al de las artes no he hablado con sole pero tengo que hablarlo no sé si os ha mandado el informe Sole te lo corrido esa es la versión que te doy mia ahora créete la que tú creas conveniente pero lo mismo que te digo tanto para lo bueno soy la cara para lo malo si tengo que enfrentarme apenas de cárcel o tengo que enfrentarme a consecuencias más graves de lo que he hecho lo cumplo para eso tengo dos agallas para cumplirlo lo único que le he dicho a segunda que dice cuidadora no me quiere más al médico que me lleve otra persona lo miro por favor porque cualquier día me vais a llevar preso y ahora que voy en el autobús y estoy más tranquilo escrito este correo gracias recibe un cordial saludo Miguel Ortí gordito','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2022-06-06','TERESA remito documento recibido por Agustín Rastrollo Barragán para reconocimiento forense en el juzgado nº1 de Llerena. el día 9/6/22 a las 11.00 horas','2');
