insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORCILLO'and apellido2='HERRERO'),'2022-06-07','Ana: Lourdes, secc. ecca., me confirma que, en su día, enviaron Autorización Gral. de disposición de efectivo al centro y se aprobó una asignación mensual para gastos de bolsillo de 60€/mes, que retira habitualmente. *Abona al centro: 641,73€/mes. ······················ Envío oficio-solicitud al INSS de Certificado Actualizado de Pensión solicitando que a partir de ahora nos remitan todas las comunicaciones y revalorización a la CTAEX, cuya dirección debe constar a efectos de comunicaciones.','2');
