insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2022-06-07','Ana: Correo de Óscar, secc. ecca., a Carol, Psicóloga CRR: "- Concepción podrá retirar la cuantía de 275€ extra la próxima semana." **Es el extra que se ha aprobado para celebrar la comunión de su hija.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2022-06-06','Ana: correo de Sonia Bernabé, ASINDI: Roberto Hernández Castaño el sábado día 4 ha agredido a una cuidadora que trataba de separarle de otro residente al que tenía sujeto por el cuello contra la pared. Se tuvo que llamar al Centro de Salud para que valoraban si precisaba algún calmante y que atendieran a las personas que había agredido. Han emitido parte de lesiones de la profesional agredida." ············ Pido a Sonia que lo comuniquen a la UPPAA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2022-06-06','Ana: Correo de Blanca, Directora CRR-Plas. (direccion.crrplasencia@grupo5.net): "Buenas, os adjunto informe sobre Isabel Cano, esta en el hospital Virgen del Puerto por sobre ingesta de medicación (paracetamol)." ·········· El informe adjunto es emitido por Blanca, Directora CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2022-06-08','Amalia . Jonathan salió de carcel el dia 21 con la intención de volver a casa de su padre en Merida. No nos ha llamado ni ha pasado por la oficina para pedir su asignación, 97€ semanal. Al comprobar sus cuentas , se detecta que ha sacado sin autorización 1800 € dejando la cuenta en negativo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-06-07','miguel, recibo email de Damian: Buenos días señor Miguel quería hacerle una preguntilla he ido a pedir un estracto al banco y me han ingresado 1700 euros del juzgado de lo penal número 2 y no sé si viene de un dinero que me ha pagado el inquilino por el juicio que tengo el próximo 15 de junio o me viene del atropello que tuve el pasado 31 de enero me lo puede mirar por favor ? Muchas gracias que pase buen dia ******************************************* Oscar me remite email adjuntando justificante de ingreso: Es una indemnización por un juicio penal y aún resta por recibir 2.096 €. En el expediente he visto que había un juicio penal en el que él era acusación particular, pero sólo hay una célula de citación. En la intranet aparecen dos juicios penales: por robo en su casa y por atropello, pero no hay sentencia. ****************************************** contesto a Damian: Buenos días, lo único que podemos comprobar es lo que aparece en el movimiento bancario. Dudo que el banco pueda decirle algo más, pero si quiere acérquese con el justificante que le adjunto de ingreso y a ver si al menos le saben decir qué juzgado de lo penal 2 es Mérida, Málaga, Plasencia? Es imposible localizar con las referencias que aparecen en el movimiento de cuenta el juzgado y el procedimiento al que pertenece este ingreso…Al ser la resolución de un procedimiento dudo que pueda tratarse del atropello por ser muy reciente, y el inquilino de Málaga tampoco porque este procedimiento judicial es civil no penal y no está finalizado. Puede ser de aquella denuncia por robo que interpuso usted en su día? Ya le digo que lo único que se me ocurre es que pregunte con este justificante en el banco a ver si le saben decir algún dato más que no aparezca en el recibo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2022-05-30','email de Víctor Guareño >betico14@hotmail.com> : Buenos días: Mi nombre es Víctor Manuel Guareño, vecino de Monesterio. He conseguido su correo a través de los asistentes sociales del municipio donde resido. Me pongo en contacto con usted para informarle de un incidente que hemos tenido con María Delgado, vecina de Monesterio, y de quienes llevan su tutela. El pasado sábado me encontraba limpiando los cristales de mi chimenea en la puerta de mi casa, en la acera. En un momento determinado, entré en mi casa y dejé por dos minutos el cristal sólo, con una goma de agua encima de color verde muy brillante para señalizarlo, cosa que no hacía falta porque es una puerta de cristal de dimensiones muy grandes. Desde dentro, escuchamos como se rompe el cristal. Salió mi mujer y pudo ver a una mujer acompañada de un perro y un señor que caminaba detrás de ella. Le llamó la atención y la mujer sólo hacía lanzar palabras mal sonantes a mi esposa, sin volver la cara en ningún momento ni ella ni su acompañante. Como tenemos cámaras de vigilancia en casa, decidimos mirarlas y llamar a la policía municipal para que identificara a las personas. Se presentó el municipal D. Antonio Vasco, quien rápidamente reconoció a los dos vecinos. Nos acompañó muy amablemente a casa del hombre, ya que me indicaba que conocía a la mujer y era mejor no hablar directamente con ella. El señor reconoció que María Delgado había pegado una patada al cristal, porque según palabras propias, " esa mañana estaba fuera de sí y no había quien le controlara". El policía municipal se puso en contacto con la madre de María, quien nos indicó que hablase con los servicio sociales de Monesterio para que me dieran una solución y se hicieran cargo del importe del cristal de la puerta de la chimenea. En el día de hoy lunes, he hablado con José, asistente social de Monesterio, quien me facilita su correo y teléfono para que me indiquen de qué manera poder solucionar este incidente. Esperando su respuesta, y agradeciendo su tiempo, reciba un cordial saludo. Víctor Manuel Guareño Areses Tlf: 649 333 973','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2022-05-30','email de Víctor Guareño >betico14@hotmail.com> : Buenos días: Mi nombre es Víctor Manuel Guareño, vecino de Monesterio. He conseguido su correo a través de los asistentes sociales del municipio donde resido. Me pongo en contacto con usted para informarle de un incidente que hemos tenido con María Delgado, vecina de Monesterio, y de quienes llevan su tutela. El pasado sábado me encontraba limpiando los cristales de mi chimenea en la puerta de mi casa, en la acera. En un momento determinado, entré en mi casa y dejé por dos minutos el cristal sólo, con una goma de agua encima de color verde muy brillante para señalizarlo, cosa que no hacía falta porque es una puerta de cristal de dimensiones muy grandes. Desde dentro, escuchamos como se rompe el cristal. Salió mi mujer y pudo ver a una mujer acompañada de un perro y un señor que caminaba detrás de ella. Le llamó la atención y la mujer sólo hacía lanzar palabras mal sonantes a mi esposa, sin volver la cara en ningún momento ni ella ni su acompañante. Como tenemos cámaras de vigilancia en casa, decidimos mirarlas y llamar a la policía municipal para que identificara a las personas. Se presentó el municipal D. Antonio Vasco, quien rápidamente reconoció a los dos vecinos. Nos acompañó muy amablemente a casa del hombre, ya que me indicaba que conocía a la mujer y era mejor no hablar directamente con ella. El señor reconoció que María Delgado había pegado una patada al cristal, porque según palabras propias, " esa mañana estaba fuera de sí y no había quien le controlara". El policía municipal se puso en contacto con la madre de María, quien nos indicó que hablase con los servicio sociales de Monesterio para que me dieran una solución y se hicieran cargo del importe del cristal de la puerta de la chimenea. En el día de hoy lunes, he hablado con José, asistente social de Monesterio, quien me facilita su correo y teléfono para que me indiquen de qué manera poder solucionar este incidente. Esperando su respuesta, y agradeciendo su tiempo, reciba un cordial saludo. Víctor Manuel Guareño Areses Tlf: 649 333 973 *************************************** email de Tere: Alberto: Le he pedido presupuesto o factura para saber el coste del cristal y que lo autorices Miguel: A nivel jurídico necesitamos algo más para aprobar el pago? ******************************************** miguel, contesto: Buenos días, lógicamente cuando me remitas presupuesto lo comunicaré al juzgado para su conocimiento… ************************************* tere me envía el presupuesto del cristal,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2022-06-06','email de Alberto, TODOS: SALDO BBVA 03/06/2022: 3,52 € INGRESOS: PNC. PROBLEMAS: • TIENE PAGOS A TRAVÉS DE BIZUM X 3.659 € SIN AUTORIZACIÓN. • REINTEGROS: NO TIENE NINGÚN TIPO DE LIMITACIÓN...HACE Y DESHACE TODO COMO LE PLACE...(HISTORICAMENTE NO SE HA INTERVENIDO CON ESTA SEÑORA PORQUE DESDE AL ÁREA SOCIAL ASÍ SE HA DECIDIDO (CREO RECORDAR QUE X MIEDO A SU POSIBLE REACCIÓN)...CREO RECORDAR TAMBIÉN QUE SU MADRE, EN ALGUNAS OCASIONES NOS HA AYUDADO/ASESORADO??? • PAGO DEUDA QUE INDICA TERES: EVIDENTEMENTE ES IMPOSIBLE SI NO INTERVENIMOS AL RESPECTO • ES MUY POSIBLE QUE TENGA EMBARGOS Y SIMILARES DERIVADOS DE MULTAS O SANCIONES, Y QUE, DEBIDO A LA FALTA PERMANENTE DE SALDO, NUNCA ACABEN DE ENTRAR EN SU CCC (ESO QUIZÁS LO PUEDA COMPROBAR MIGUEL) X TANTO...O LA CTAEX DECIDE INTERVENIR CON ESTA SEÑORA DE ALGUNA MANERA (SI ELLO ES POSIBLE) O NO TIENE SENTIDO VALORAR NADA A NIVEL ECONÓMICO SOBRE ESTA PERSONA...YA MEDIREIS. SI NO INDICAIS LO QUE EL ÁREA ECONÓMICO PUEDE HACER AL RESPECTO...NO PODREMOS HACER NADA SOBRE LA PARTE ECO ***************************************** miguel, contestación: Hola, ya me diréis, entiendo que no hay forma de pagar. Si es así Tere tendrás que hablar con ella y explicarle que de su asignación tendrá que pagarlo poco a poco y explicarle la situación…Independientemente de que hay que comunicar al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2022-06-08','miguel, email de Alberto: Hasta que el resto manifestéis vuestra opinión sobre como actuar, mi opinión es la siguiente: Desde la CTAEX, se debería elaborar URGENTEMENTE un INFORME detallado que incluya PROPUESTA de actuación y que debería ser remitido al Juzgado. Entiendo que para la elaboración del informe se debería contar con la información y opinión de FUTUEX y quizás también con lo que pudiera aportar la madre de la tutelada. Reitero que, a nivel ECONÓMICO, no se está aplicando ningún tipo de RESTRICCIÓN sobre la esfera económica de esta persona (esta actuación de la CTAEX deriva del criterio establecido desde hace bastante tiempo por el Área Social, que entiende que estas restricciones podrían suponer una mayor desestabilización de la tutelada que podría generar situaciones de peligro para ella misma y para otras personas). ******************************************** miguel, contestación: Buenos días, en opinión de la parte jurídica es que debe abonar el desperfecto, porque caso contrario pueden solicitar la responsabilidad subsidiaria de la Comisión Tutelar de Adultos, con los dolores de cabeza que puede acarrear…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2022-06-08','La jurista llamó al juzgado para que le mandasen todo lo que tenía pendiente pero no lo mandaron. Pues ahora como no dejo domicilio de notificaciones le pondrán en búsqueda y captura cuando el juzgado mande ejecutar la sentencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2022-06-08','Amalia Miguel escribe a Cristina comunicándole que su solicitud de sacar a Pedro de la residencia tiene que trasladarla directamente al juzgado . He solicitado informe a la RM, guardado en su expediente . No nos opendremos a la salida , siempre que se responsabilicen de sus cuidados y alguien asuma la responsabilidad de los cuidados. La última vez , después de sacarlo de la R.M . no funcionó ni en casa de Cristina ni en el piso de alquiler . Dejando Cristina a su tia ingresado en el hospital . Exigió que se le buscase una R.M. porque ya no podía antenderlo . Y ahora lo vuelve a solicitar. Pedro es dependiente para AVD , actualmente vida cama_sillón . Que sea el juzgado el que de la respuesta , dado que hay otro familiar , una cuñada que también solicitó el año pasado en oficina traerlo a su casa .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2022-06-08','Amalia Guardo la respuesta dada por el Gerente de la RM Los Olivos , al que le pregunto si Pedro ha manifestado su deseo de salir . Los Olivos Mérida Badajoz >secretarialosolivosdemerida@gmail.com> PEDRO EN NINGÚN MOMENTO PEDRO NOS HA MANIFETADO SU DESEO DE SALIR DE LA RESIDENCIA NI DE IRSE A VIVIR CON SU SOBRINA. SE ENCUENTRA TOTALMENTE ADAPTADO A NUESTRA RESIDENCIA. Un Saludo. JAVIER FLORES LORENZO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2022-06-08','Ana: Llamo a Carlos, amigo de Félix (603 440 408), en relación a las facturas de agua con cuyo abono quiere contribuir Félix: El número ni siquiera da llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-06-08','Amalia , nos comunican que tiene alta de UHB . Solicitan desde el ESM ayuda a domcilio , se les explica que es inviable , ella no facilita el servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-06-08','Ana: Correo de Toni-Futuex, con información sobre el seguimiento a Saturnino. A día de hoy desconocen su paradero. A la cita de ayer para acudir a Salud Mental a solicitar cita, no se presentó. No saben si ha acudido al Juzgado. Debe personarse todas las semanas. ································································································································································································ Tras conversación con Mar, hermana de Saturnino (690 671 204), envío correo a Miguel, Asesor Jurídico: "Informarte que en conversación mantenida con Mar Salgado Jiménez, hermana de SATURNINO MIGUEL SALGADO JIMÉNEZ, me comunica que éste se encuentra en la casa familiar (antigua casa de su padre) ubicada en la C/ Juan Ramón Jiménez, nº 14, de la localidad de Alcuéscar (Cáceres). Hasta allí lo ha trasladado otro de los hermanos, Francisco Salgado. También nos comunica que esta casa no dispone de luz ni de ningún otro suministro dado de alta, pero no tienen otro sitio en que se pueda quedar. Expresa que “la convivencia con él es imposible”. Llevan ya 26 años con la compleja situación de su hermano y ella misma expresa que está “desesperada”. No entiende que desde la Comisión Tutelar de Adultos no se pueda hacer nada más. Le recuerdo que es un cargo de carácter administrativo y que la Comisión no cuenta con partida presupuestaria, ni recursos residenciales propios de ningún tipo. Tampoco tiene prioridad en el acceso a recursos, las personas a su cargo acceden por las mismas vías que el resto de la ciudadanía extremeña. Mar también comenta que un primo suyo, Miguel Bote, que regenta un Mesón en al misma calle, colaborará facilitándole comida. Desde el Gabinete Técnico de la Comisión Tutelar, se comunicará al Programa de Apoyo Comunitario de Futuex, la nueva dirección de Saturnino para que puedan retomar allí el seguimiento." ·············· Se lo reenvío a Toni de Futuex pido que retomen en seguimiento en Alcuéscar y acudan a hablar con el primo, entre otras motivos para solicitar su colaboración para activar el 112 si fuera necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2022-06-08','Ana: A última hora recibimos parte de informe, parte de incidencia y denuncia (vía penal) sobre la última incidencia de Adrián, el día 4. Agredió y bajó los pantalones a otro residente. *Mañana Adrián acudirá con la directora a la lectura de los hechos. ··· Lo han remitido también a la secc. de acceso a recursos de discapacidad. ···· La guardo en el expediente digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-06-08','Ana: Correo de Sonia - Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería informaros que Aaron ayer tuvo que ser derivado por alteración de conducta a Salud Mental. Estamos intentando contactar con el psiquiatra que le atiende para que nos informe de su situación. El lunes tiene cita en el médico forense y seguimiento con su psiquiatra en Salud Mental. Aprovecharemos para preguntarle por sus trámites de la UDAC, por saber posible fecha,... Nos preocupa su comportamiento que se puede agravar con las citas en el Juzgado y que van a operar a su padre y no podrá irse a casa con su frecuencia habitual. No sé si vosotros podéis averiguar sobre la plaza de la UDAC. Cuando tengamos más información te decimos. Un saludo,"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2022-06-09','Perfecto, recuerda que si se va firme un documento con su deseo de donde se va a vivir… Miguel Fdez. Llera','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2022-06-09','Ana: Recabo firmas para CI Cirugía Histeroscópica y solicitud de inclusión en lista de espera quirúrgica. ······· Preparo oficio y se lo paso a Julio, CTAEX, para que le de registro de salida y lo envíe por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2022-06-09','TERESA ENVIO CORREO ELECTRONICO A LA EMBAJADA DE ARGENTINA TRAS CONTACTA TELEFONICAMENTE PUE ASI ME LO INDICAN TAMBIEN LO ENVIO AL EMBAJAA ITALIANA PIDIENDO INORAMCION DEL PASAPORTE PUES LO NECESITAMOS PARA EXPEDIRLE EL DNI PUES YA NO SE LE PUEDE RENOVAR LA TARJETA DE RESIDENCIA, NOS PIDEN EN LA COMISARIA EL PASAPORTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2022-06-09','miguel, llega de Sonia de Asindi email: Buenos días Miguel, quería informarte que Aaron Rosado está ingresado en la Unidad de Salud Mental de Cáceres, creemos que hoy nos informarán sobre su estado y si regresa o continua. Como el lunes tiene la cita con el médico forense estaremos pendientes por si no le dan el alta en estos días solicitar un certificado como que continua ingresado el lunes. Estaremos en contacto con vosotros para informaros de su situación. ********************************* mi contestación: Por favor envíanos a Ana Matamoros y a mi justificante de su ingreso en caso de que te digan hoy que continuará ingresado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-06-09','Amalia: Buenos días Miguel , te envío informes de Miguel Ortiz , se encuentra ingresado en el Colegio La Luz donde ha protagonizado una agresión , tirando una piedra a una cuidadora. Desde el Centro lo han derivado al ESM y desde allí han solicitado ingreso en la UHDAC. Igual que hiciste para el caso a ALEJANDRO NUÑEZ BONO , la UHDAC pide autorización judicial de ingreso .Por cierto , no ha llegado nada ? Te envío todos los informes que justifican la necesidad del ingreso para enviar al juzgado . Un saludo ******************************************** contestación de miguel: Hola, no entiendo que haya solicitarlo, si en tu email dices ya está solicitado…” Desde el Centro lo han derivado al ESM y desde allí han solicitado ingreso en la UHDAC” Confirmame si finalmente lo solicitamos o no…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2022-06-09','Amalia: Buenos días Miguel , te envío informes de Miguel Ortiz , se encuentra ingresado en el Colegio La Luz donde ha protagonizado una agresión , tirando una piedra a una cuidadora. Desde el Centro lo han derivado al ESM y desde allí han solicitado ingreso en la UHDAC. Igual que hiciste para el caso a ALEJANDRO NUÑEZ BONO , la UHDAC pide autorización judicial de ingreso .Por cierto , no ha llegado nada ? Te envío todos los informes que justifican la necesidad del ingreso para enviar al juzgado . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2022-06-09','-Amalia : envío email al CRR Buenos días , el día 1 regresó al CRR Mari Loli , tras su estancia en R.M. Lo Olivos. Me está llamando desde su casa de Almendralejo , es que le habéis dado autorización para que salga ? En estos casos , tenéis que comunicar la salida por email para que sepamos dónde se encuentran y que van con autorización. Solicita poder arreglar la casa para quedarse a vivir allí . Se le ha indicado que pida presupuestos del arreglo y todo ello será derivado al juzgado para que valore si se le autoriza o no. En un mes , ha presentado 3 propuestas diferentes , quedarse en la residencia de mayores , volver a CRR y quedarse en su casa.. Difícil va a ser la valoración cuando ella no lo tiene claro . En unos meses está pendiente que la vayan a valorar de dependencia al centro. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2022-06-09','Ana: María, Aux. Adtvo. CTAEX, me comunica que ha hablado con Abraham, en relación a un recibo de IBI. Después ha aprovechado para decirle que no está conforme con Gloria, Ed. Futuex, entre otras cosas porque en la última cita de Nefrología entró con su madre a la consulta y a él no le dejó entrar. ······ Se lo comunico a Toni-Futuex, más que nada que tengan constancia pues seguro que hay otra lectura sobre lo sucedido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2022-06-14','Ana: Correo de Sonia Bernabé (trabajosocial@asindi.e.telefonica.net): "Hola Ana, tenemos noticias sobre cómo se encuentra Aaron. Han informado a mi compañera que le han hecho analítica y han comprobado que el ácido valproico tenía que estar entre 50 y 100 y lo tiene a 58, entonces le han ajustado tratamiento y le realizarán otra analítica el jueves o viernes para ver si ha subido. Ha presentado alteración de conducta después de hablar con el padre el fin de semana y están observando cómo mejora con el nuevo tratamiento y a la espera de que aumente el ácido valproico. Te iremos informando"','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-06-09','miguel, me llama Maite Longa (abogacía de la junta en Cáceres;email:mariateresa.longa@juntaex.es; tlfno 627652611 y 927-001126) que le han asignado el caso del jzdo de 1º instancia nº2 de Plasencia, Delitos leves 43/2022: "Buenos días, conforme hemos hablado por teléfono te informo que vamos a comparecer como tutores por videoconferencia en el procedimiento de referencia. Asimismo conforme el fax adjuntado se ha solicitado al juzgado que nombre abogado de oficio y nuestra intervención vía videoconferencia. El motivo es que en su día desde abogacía se nos aclaró que vuestra intervención únicamente se producía en los nombramientos y remociones de cargo de tutores y curadores (conforme la nueva ley 8/21 de curadores representativos y asistenciales), así mismo cuando tengan que representar a la Comisión Tutelar de Adultos (ejemplo cuando se nos reclame responsabilidad civil subsidiaria). A fecha de hoy no hemos recibido reclamación por responsabilidad civil subsidiaria a la Comisión Tutelar de Adultos, y en el caso que nos ocupa del tutelado Juan Carlos Ruiz Garcia tampoco nos consta que se haya solicitado responsabilidad civil a la Comisión Tutelar de Adultos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2022-06-09','Ana: Paso a Miguel, Asesor Jurídico CTAEX, los Informes del Serv. de Psiquiatría solicitados que hemos recibido, para comunicación al Juzgado. *Guardo en el expte. digital. ············ En el mismo se especifica: "Diagnosticado de esquizofrenia paranoide con síntomas positivos persistentes, de larga evolución.", "Consumidor habitual de alcohol y tóxicos (cannabis)", "Mal control diabético", "Discurso disgregado, perdida del hilo conductor", "Aspecto de abandono y conducta desorganizada". "Niega consumo de alcohol y tóxicos aunque los reconoce cuando lo evidencia la monitora".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2022-06-09','Ana: Según Citación del Juzgado de Primera Instancia e Instrucción nº6 de Cáceres, Saturnino también tenía que haber acudido ayer al Juzgado para "PROCEDER A TOMAR LA DECLARACIÓN INDAGATORIA DEL PROCESADO, señalando para ello el día 8 de junio de 2022 a las 11:00 horas". *No sabemos si ha acudido. ····· Entendemos que esta citación se la comunicaron antes de salir de prisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2022-06-10','email de Mayte. Respecto a Mercedes Pérez Pinna, el 2 de julio de 2021 se acordó lo siguiente: ‘’ por consenso de la CTAEX se acepta, en tanto en cuanto el Juzgado no se manifieste en contra o realice alguna instrucción o recomendación, que la tutelada genere unos gastos superiores a sus ingresos en cuantía similar a la del periodo mostrado. Por el Área Social se redactarán los motivos que recomiendan esta aceptación y que serán comunicados al juzgado para su estudio. Si se producen gastos de gran cuantía y cuyo pago es de obligado cumplimiento (multas, impuestos, embargos, deudas generadas...): se aceptarán dichos gastos sin que haya repercusión en los reintegros autorizados a la tutelada. Ejemplo: en el periodo estudiado ha habido un embargo por importe de 6.858,3 € RELACIONADO CON LA PLUSVALÍA DE LA VENTA DE SU VIVIENDA DE BADAJOZ. Los gastos incluidos podrán variar a lo largo del tiempo, ya que gran parte de los mismos están asociados a consumos (luz, agua, teléfono...) y, dadas las especiales características de la tutelada, su control resulta imposible. Criterios Económicos: NO SE AUTORIZARÁ NINGÚN REINTEGRO EXTRAORDINARIO MÁS ALLA DE LOS YA INDICADOS (REINTEGRO PERMANENTE Y AYUDA DOMICILIO). TUTELADA DEBERÁ HACER FRENTE A CUALQUIER GASTO CON LOS REINTEGROS PERCIBIDOS. EJEMPLOS: ROPA, CALZADO, LIBROS, SIMILARES. GIMNASIO, CLASES, SIMILARES. REPARACIONES VIVIENDA, COLCHON, MENAJE, SIMILARES. ELECTRODOMÉSTICOS, SIMILARES. GAFAS, AUDIFONOS, SIMILARES FARMACIA , FISIOTERAPIA, DENTISTA, SIMILARES EN CASO DE GENERARSE GASTOS QUE NO CUENTEN CON LA PREVIA AUTORIZACIÓN DE LA CTAEX Y CUYO ABONO SEA INELUDIBLE, ESTOS MINORARÁN EN DICHA CUANTÍA LOS REINTEGROS ASOCIADOS A LAS PAGAS EXTRAORDINARIAS DE LOS QUE LA TUTELADA DISPONE EN JUNIO Y DICIEMBRE Y SI NO FUESE SUFICIENTE CON LA TOTALIDAD DE LAS PAGAS EXTRAORDINARIAS, SE PROCEDERÁ A MINORAR EL IMPORTE DEL REINTEGRO PERMANENTE. POR LA CTAEX SE DEVOLVERÁ, DE FORMA INMEDIATA Y SIEMPRE QUE SEA POSIBLE, TODO RECIBO O DARÁ DE BAJA CUALQUIER DOMICILIACIÓN QUE SE PRODUZCA SIN CONTAR CON AUTORIZACIÓN PREVIA. TODA LA INFORMACIÓN Y DATOS CONTENIDOS EN ESTE DOCUMENTO SE PONEN EN CONOCIMIENTO (DE IGUAL FORMA QUE CON EL ACUERDO ANTERIOR) DE LA TUTELADA.´´ Toda la relación de sus gastos e ingresos se envió por Miguel al Juzgado , que no ha respondido . Como nos dijo Miguel la semana pasada si el juzgado no ha contestado ni lo va a hacer es porque no pondrá objeciones . Un saludo','2');
