insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2022-06-13','Ana: Desde la Res. de Mayores de Navezuelas (pilarcortcer@gmail.com), nos remiten informe de la TS, María Gía Recio: Juan José no ha recibido ninguna visita de la familia en el último año. Sí de un amigo, que también le llama. Está adaptado al centro, se muestra amable y colaborador, aunque apenas se relaciona con el resto de residentes. Prefiere estar solo. Su estado de salud es bueno. Toma la medicación de forma correcta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2022-06-13','Ana: A petición de Miguel, envío correo al CRR-CC (crr@grupociudadjardin.com): "Buenos días Cristina y Pedro, Me pide Miguel, Asesor Jurídico CTAEX, que os solicite, a ser posible, un certificado de empadronamiento actualizado de JUAN JOSÉ BERGANTIÑO GONZÁLEZ. Si no fuera posible, por favor remitirnos un Certificado de Residencia en el CRR, pue lo necesita para algún trámite en el Juzgado. Gracias de antemano."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2022-06-13','Ana: A petición de Miguel, Asesor Jurídico, CTAEX, envío correo al CRR-CC (crr@grupociudadjardin.com): "Buenos días Cristina y Pedro, Me pide Miguel, Asesor Jurídico CTAEX, que os solicite, a ser posible, un certificado de empadronamiento actualizado de JUAN JOSÉ BERGANTIÑO GONZÁLEZ. Si no fuera posible, por favor remitirnos un Certificado de Residencia en el CRR, pue lo necesita para algún trámite en el Juzgado. Gracias de antemano."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-06-09','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería comentarte que ayer Felisa pudo hablar con una educadora del Centro de Menores de Olivenza que coincidió con ella. A Felisa le gustó la llamada y estuvieron intercambiando información sobre qué actividades hace ahora y recuerdos de cuando estuvo en el centro. Como las llamadas no podrán ser con mucha frecuencia hemos acordado que Felisa realizará un marco o collage que les mandaremos para decorar el despacho. A ella le hace ilusión mandarles una foto actual suya para que vean cómo es actualmente. Dime si puede ser o tenemos que ver con ella otra propuesta. Un saludo,"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2022-06-13','Ana: Envío correo-respuesta a Sonia: "Buenos días Sonia, Cuándo me alegra leer esto! Espero que al menos cada cierto tiempo pueda hablar con alguna de ellas. En cuanto a la foto, dado que Felisa quiere mandarla, que no se le va a dar ningún otro uso distinto al de que les vean sus anteriores educadoras y además la foto no saldrá del CAM, entiendo que no hay problema. Si te confirman esto que te he dicho, no hay ningún problema."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-06-07','Ana: correo de Maite, Jefa CTAEX, a Alberto, Jefe Secc. Ecca. CTAEX,: "Juan Carlos Ruiz García ingresó en el centro Mentalia Arévalo ( en el que está José María Morón). Hasta que se pueda abonar la plaza desde el SEPAD , la paga él. Desde el centro nos piden su número de cuenta para hacer el cargo de la factura."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2022-06-09','Ana: Respuesta de Alberto, jefe secc. ecca., a Maite, Jefa CTAEX; "MAITE: En caso de que el cobro vaya a ser a través de cargo en cuenta...el nº del tutelado es ES28 2085 4511 9203 3187 4889. Tienes que facilitarnos el coste real mensual de la plaza para calcular el reintegro (IVA incluido)...una vez que tengamos eso calculamos el reintegro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2022-06-10','Buenos dás Amalia : me dirigo a ti , por el tema del Usuario Tomas Pérez Lima .del que la Junta tiene la tutela. La ultima vez que hablamos contigo , tanto yo como la directora de nuestro programa , Tomas ya no estaba en nuestra vivienda, ya que estaba compartiendo piso con otros dos chicos , por su cuenta , aunque en ocasiones se pasa por nuestro centro , para ver cómo le iba. La situación de Tomas ha cambiado , hace unas semanas , uno de los chicos murió y entraron a una pareja , que los han engañado , yendose sin pagar tres meses del piso , asi que han tenido que abandonar el piso , Tomas se ha visto solo y sin saber que hacer, no tiene capacidad para manejarse en estas situaciones y menos vivir solo. Hemos tenido que restructurar nuestras viviendas para ,poderlo entra en una de ellas , pero por un tiempo corto ,ya que la plaza , ya estaba comprometida. Yo he hablado con , si ha cambiado la idea de irse a cualquier pueblo o ciudad, donde tengais alguna plaza en vuestros pisos y ahora si estaria dispuesto , ya tiene miedo a verse solo. En la vivienda él se puede manejar , con nuestra supervisión , pero a nivel social no. Nos gustaria hablar contigo para ver qué podeis hacer. Sin mas . un saludo .Inés Inés García Jareño Área de Inclusión. Educadora en Centro Hermano, Caritas Diocesanas Mérida -Badajoz C/ Benito Mahedero Balsera N.º 75 Badajoz 924-24-00-47 igarcia.cdmeba@caritas.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2022-10-28','-Amalia : ha pasado a pisos supervisados en Almendralejo . Contacto : Buenos días Soy Alicia, la psicóloga de los pisos supervisados de Almendralejo. Me ponía en contacto contigo para informarme de una usuaria que está tutelada por la comisión. También, para hablar de su situación actual. Si puedes llamarme sería estupendo. Número de teléfono: 674355164 -------------------------- Tras hablar con la psicologa me informa que la adaptación es buena , ya no quiere cambiar de localidad. No se habla con la familia materna pero ha retomado relaciones con el padre y familia paterna. Está contenta. La madre cuando ella era pequeña denunció al padre por algún tipo de maltrato o negligencia con la niña , no tenemos más información al respecto. De momento queda con sus primos y tias paternas. Una de ellas es soltera y quiere que se vaya a vivir con ella . Se va a facilitar salidas de fines de semana para ver cómo evoluciona esa relación. El tema del móvil que quiere , se va a a valorar la necesidad del mismo y se le pide pto. nuevo para abonar en su caso con la extra de diciembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2022-06-13','Ana: Se autoriza presupuesto para el programa de vacaciones/turismo en la naturaleza del IMSERSO. ···· Recabo la firma en los documentos pertinentes y se los paso a Julio, Aux. Adtvo. CTAEX, para que le de registro de salida y remita los originales por correo certificado al CAMF.','2');
