insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2022-06-13','Ana: Llamada de Emilia Almodóvar, TS del CSS (24205) con Jairo. Emilia plantea de nuevo, que si no gasta el dinero en tabaco, si se le puede dar para otra cosa. *Tal y como expuse en el correo enviado en mayo, sería bueno que Jairo redujera el consumo de tabaco e incluso que lo dejara. Si le sirve de motivación contar con pequeñas cantidades de dinero para destinarlas a otro gatos, nos parece bien. Siempre que le dé un buen uso y no pida después tabaco a otros pacientes.','2');
