insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE JAVIER'and edp.apellido1='IGLESIAS'and apellido2='SANCHEZ'),'2022-06-13','TERESA SALIDA EXCURSION PLAYA CHIPIONA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO RODRIGO'and edp.apellido1='RIVERA'and apellido2='TORIO'),'2022-06-13','Ana: en relación a las vacaciones de la playa, a pesar de ir muy ajustado económicamente, se aprueba el presupuesto. ·········· *Al comprobar con Estrella, secc. ecca., los movimientos bancarios, me sorprendo pues sólo le ingresan de orfandad simple 178,75€. ············ Llamo al INSS-CC, hablo con Toni, Jefa de Secc. (927 62 00 57): no le han concedido los mínimos, no sabe el motivo. *Lo mirará y me llamará al respecto. ···················· Toni me devuelve la llamada: Cuando solicitaron la pensión en 2001 (aún no estaba a cargo por la CTAEX), no le correspondía los mínimos por la otra pensión que percibe. *Ahora sí le corresponde pero hay que solicitar la revisión, no la hacen de oficio. Por lo que no le concederán retroactividad. ············· Al abonar el 75% de la pensión a la plaza residencial, no le quedará mucho pero al menos incrementará unos 80€ más al año de las 2 extras. ···················· Redacto oficio-solicitud y se lo paso a Julio para que le dé registro y lo envíe al INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2022-06-13','Ana: Tras hablar con José Manuel y después con Pilar Martín, TS ESM, envío correo-e a Toni-Futuex: "Te escribo sobre todo para ver si vosotras podéis aclararme. Me ha llamado José Manuel Romero Mediavilla, dice que Pilar Martín, Trabajadora Social de Salud Mental, le ha dicho de hacer un curso, pero que no sabe de qué, ni cuántos días, ni horarios… Y que necesita se le autorice dinero para recargar la tarjeta abono mensual de transporte municipal. He mirado en la web y son 29€. Pero después he llamado a Pilar Martín, y me dice que ella no recuerda haberle dicho nada al respecto a José Manuel y que le pregunte mejor a Virginia, que ella estuvo presente… Cuando podáis informarme acerca de dicha cita y de si existe algún curso al que pueda acceder. Así mismo, hacednos, por favor, una valoración sobre la necesidad o no de adquirir el abono transporte mensual."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-06-13','Buenas tardes señor Miguel al final he decidido una vez que sea el juicio este miércoles 15 de junio osa pasado mañana cuando el piso se quede libre si la parte economica me lo permite le voy a alquilar el piso a mi prima por 400 euros ya que mi prima me lo va a cuidar bien y me llevo muy bien con ella.eso si cuando el piso se quede vacío según en las condiciones que lo deje el inquilino tengo que pagar una reforma al piso para que le pregunte a la parte economica y a través de la abogada hacerle una pequeña reforma al piso que lo pagaría yo de mi dinero.espero su contestación es importante éste tema gracias y le deseo que pase muy buena tarde recuerdos a ana matamoros de mi parte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='TORES'and apellido2='NUÑEZ'),'2022-06-13','Ana: Recibimos de PNC, el Cdo. de PNC actualizado: 421,40 €/mes x 12 + el complemento autonómico extraordinario de 250€ en el mes de abril de 2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2022-06-13','Buenas tardes señor Miguel al final he decidido una vez que sea el juicio este miércoles 15 de junio osa pasado mañana cuando el piso se quede libre si la parte economica me lo permite le voy a alquilar el piso a mi prima por 400 euros ya que mi prima me lo va a cuidar bien y me llevo muy bien con ella.eso si cuando el piso se quede vacío según en las condiciones que lo deje el inquilino tengo que pagar una reforma al piso para que le pregunte a la parte economica y a través de la abogada hacerle una pequeña reforma al piso que lo pagaría yo de mi dinero.espero su contestación es importante éste tema gracias y le deseo que pase muy buena tarde recuerdos a ana matamoros de mi parte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2022-06-13','Hola, los pacientes Sebastián Paredes Dicha y Almudena Correyero Parejo van a realizar un viaje a Lourdes del 22 al 27 de Junio de 2022,por lo que han hecho un abono de 285 euros que corresponde a la cuantía del viaje. Al margen de este dinero, llevarán dinero de bolsillo para sus gastos personales. Gracias. Un saludo. Manuela Domínguez Flores. Trabajadora Social. Centro Sociosanitario "Adolfo Díaz Ambrona". Ctra. Valverde, km. 2. 06800 Mérida. Tel.: 924 38 80 81. Ext.: 24012','2');
